    internal static class Program
    {
        internal const string AppTitle = "Forza Horizon 6 Luna";
        internal const string AppVersion = "1.5.0";
        private const string WebView2CoreAssemblyName = "Microsoft.Web.WebView2.Core";
        private const string WebView2WinFormsAssemblyName = "Microsoft.Web.WebView2.WinForms";
        private const string WebView2CoreResourceName = "bundled-webview2-core.dll";
        private const string WebView2WinFormsResourceName = "bundled-webview2-winforms.dll";
        private const string WebView2LoaderResourceName = "bundled-webview2-loader.dll";

        [STAThread]
        private static void Main()
        {
            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);

            if (!Native.IsAdministrator())
            {
                try
                {
                    var psi = new ProcessStartInfo(Application.ExecutablePath);
                    psi.Verb = "runas";
                    psi.WorkingDirectory = Path.GetDirectoryName(Application.ExecutablePath);
                    Process.Start(psi);
                    return;
                }
                catch
                {
                    MessageBox.Show("Administrator rights are needed to attach to the running game process.", AppTitle);
                }
            }

            InstallBundledWebView2Runtime();
            Native.EnableDebugPrivilege();
            Application.Run(new MainForm());
        }

        private static void InstallBundledWebView2Runtime()
        {
            AppDomain.CurrentDomain.AssemblyResolve -= ResolveBundledWebView2Assembly;
            AppDomain.CurrentDomain.AssemblyResolve += ResolveBundledWebView2Assembly;

            var appDir = AppDomain.CurrentDomain.BaseDirectory;
            var sideBySideLoader = Path.Combine(appDir, "WebView2Loader.dll");
            if (File.Exists(sideBySideLoader) || TryExtractBundledResource(WebView2LoaderResourceName, sideBySideLoader))
                Native.SetDllDirectory(appDir);
        }

        private static Assembly ResolveBundledWebView2Assembly(object sender, ResolveEventArgs args)
        {
            var requestedName = new AssemblyName(args.Name).Name;
            if (string.Equals(requestedName, WebView2CoreAssemblyName, StringComparison.OrdinalIgnoreCase))
                return LoadBundledAssembly(WebView2CoreResourceName);
            if (string.Equals(requestedName, WebView2WinFormsAssemblyName, StringComparison.OrdinalIgnoreCase))
                return LoadBundledAssembly(WebView2WinFormsResourceName);
            return null;
        }

        private static Assembly LoadBundledAssembly(string resourceName)
        {
            try
            {
                var assembly = Assembly.GetExecutingAssembly();
                using (var stream = assembly.GetManifestResourceStream(resourceName))
                {
                    if (stream == null)
                        return null;

                    var bytes = new byte[stream.Length];
                    var offset = 0;
                    while (offset < bytes.Length)
                    {
                        var read = stream.Read(bytes, offset, bytes.Length - offset);
                        if (read <= 0)
                            break;
                        offset += read;
                    }

                    return Assembly.Load(bytes);
                }
            }
            catch
            {
                return null;
            }
        }

        private static bool TryExtractBundledResource(string resourceName, string targetPath)
        {
            try
            {
                var assembly = Assembly.GetExecutingAssembly();
                using (var stream = assembly.GetManifestResourceStream(resourceName))
                {
                    if (stream == null)
                        return false;

                    var directory = Path.GetDirectoryName(targetPath);
                    if (!string.IsNullOrEmpty(directory))
                        Directory.CreateDirectory(directory);

                    if (File.Exists(targetPath))
                    {
                        var existing = new FileInfo(targetPath);
                        if (existing.Length == stream.Length)
                            return true;
                    }

                    var tempPath = targetPath + ".tmp";
                    using (var file = File.Create(tempPath))
                        stream.CopyTo(file);
                    File.Copy(tempPath, targetPath, true);
                    File.Delete(tempPath);
                    return true;
                }
            }
            catch
            {
                return File.Exists(targetPath);
            }
        }
    }

