                    _database.Dispose();
                    _database = null;
                }
            };

            Directory.CreateDirectory(_dumpDir);
            Directory.CreateDirectory(_reportDir);
            File.AppendAllText(_logPath, Environment.NewLine + "==== " + Program.AppTitle + " " + DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss") + " ====" + Environment.NewLine);

            Log("Ready. This tool does not edit the game folder until you attach and press an action.");
            Log("Stable unlock path: resolve the live game database, then update Autoshow visibility data.");
            Log("Autoshow query text patching is disabled; Features runtime hooks install only when Apply is pressed.");
            Log("Persistent log: " + Path.GetFileName(_logPath));
            WriteSqlReference();
            Shown += delegate
            {
                BeginInvoke((Action)TryAutoAttachOnOpen);
                RegisterTeleportSaveHotkey();
                RegisterTeleportPlaylistHotkey();
                RegisterFeatureOverlayHotkey();
                ShowOpenSourceNotice();
                if (_featureOverlayEnabled)
                    ShowFeatureOverlay();
                if (_consoleOverlayEnabled)
                    ShowConsoleOverlay();
            };
        }

        protected override void WndProc(ref Message m)
        {
            if (m.Msg == Native.WmHotkey && m.WParam.ToInt32() == TeleportSaveHotkeyId)
            {
                TriggerTeleportSaveHotkey();
                return;
            }

            if (m.Msg == Native.WmHotkey && m.WParam.ToInt32() == TeleportPlaylistHotkeyId)
            {
                TriggerTeleportPlaylistHotkey();
                return;
            }

            if (m.Msg == Native.WmHotkey && m.WParam.ToInt32() == AutoMasteryFinishRecordHotkeyId)
            {
                FinishAutoMasteryRecording();
                return;
            }

            if (m.Msg == Native.WmHotkey && m.WParam.ToInt32() == FeatureOverlayHotkeyId)
            {
                ToggleFeatureOverlayFromHotkey();
                return;
            }

            if (m.Msg == Native.WmHotkey && TryHandleRuntimeFeatureHotkey(m.WParam.ToInt32()))
                return;

            if (m.Msg == Native.WmSettingChange || m.Msg == Native.WmDwmColorizationColorChanged)
                ApplySystemTitleBarColor();

            base.WndProc(ref m);
        }

        protected override void OnHandleCreated(EventArgs e)
        {
            base.OnHandleCreated(e);
            ApplySystemTitleBarColor();
        }

        private Control _altTabScrollPage;
        private System.Drawing.Point _altTabScrollPos;

        protected override void OnDeactivate(EventArgs e)
        {
            base.OnDeactivate(e);
            try
            {
                var page = GetVisibleContentPage();
                var scrollable = page as ScrollableControl;
                if (scrollable != null)
                {
                    _altTabScrollPage = page;
                    var sp = scrollable.AutoScrollPosition;
                    _altTabScrollPos = new System.Drawing.Point(-sp.X, -sp.Y);
                }
            }
            catch
            {
            }
        }

        private Control GetVisibleContentPage()
        {
            if (_contentHost == null || _contentHost.IsDisposed)
                return null;
            foreach (Control child in _contentHost.Controls)
            {
                if (child != null && child.Visible)
                    return child;
            }
            return null;
        }

        protected override void OnActivated(EventArgs e)
        {
            base.OnActivated(e);
            if (IsDisposed || !IsHandleCreated)
                return;
            try
            {
                BeginInvoke((Action)delegate
                {
                    if (IsDisposed || !IsHandleCreated)
                        return;
                    var restore = _altTabScrollPage as ScrollableControl;
                    if (restore != null && !_altTabScrollPage.IsDisposed && _altTabScrollPage.Visible)
                        restore.AutoScrollPosition = _altTabScrollPos;
                    Invalidate(true);
                    if (_contentHost != null && !_contentHost.IsDisposed)
                        _contentHost.Invalidate(true);
                    Update();
                });
            }
            catch
            {
            }
        }

        private void ApplySystemTitleBarColor()
        {
            if (!IsHandleCreated)
                return;
            try
            {
                Native.ApplySystemTitleBarColor(Handle, AppBackground, TextPrimary);
            }
            catch
            {
            }
        }

        private void ShowOpenSourceNotice()
        {
            ApplyLunaUpdateInfo(new LunaUpdateInfo
            {
                Title = "Open Source Edition",
                Message = "This is the open-source build of Luna. Click here to visit the official website and see where it came from.",
                DownloadUrl = OpenSourceWebsiteUrl,
                LatestVersion = Program.AppVersion,
                FileName = string.Empty,
                Notes = string.Empty,
                UpdateAvailable = false,
                ForceShow = false,
            });
        }

        private void ApplyLunaUpdateInfo(LunaUpdateInfo info)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ApplyLunaUpdateInfo(info); }));
                return;
            }

            if (LunaUpdateInfoEquals(_lunaUpdateInfo, info))
                return;

            _lunaUpdateInfo = info;
            if (_hubUpdateCallout != null && !_hubUpdateCallout.IsDisposed)
            {
                _hubUpdateCallout.SetUpdate(info);
                _hubUpdateCallout.Visible = info != null;
                LayoutHub();
            }
        }

        private static bool LunaUpdateInfoEquals(LunaUpdateInfo a, LunaUpdateInfo b)
        {
            if (a == null && b == null)
                return true;
            if (a == null || b == null)
                return false;
            return string.Equals(a.LatestVersion, b.LatestVersion, StringComparison.Ordinal)
                && string.Equals(a.Title, b.Title, StringComparison.Ordinal)
                && string.Equals(a.Message, b.Message, StringComparison.Ordinal)
                && string.Equals(a.DownloadUrl, b.DownloadUrl, StringComparison.Ordinal)
                && string.Equals(a.FileName, b.FileName, StringComparison.Ordinal)
                && string.Equals(a.Notes, b.Notes, StringComparison.Ordinal)
                && a.UpdateAvailable == b.UpdateAvailable
                && a.ForceShow == b.ForceShow;
        }

        private void OpenLunaUpdateUrl(string url)
        {
            OpenExternalUrl(url);
        }

        private void OpenExternalUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
                return;
            try
            {
                Process.Start(new ProcessStartInfo(url) { UseShellExecute = true });
            }
            catch
            {
            }
        }

        private static bool JsonBool(string json, string key)
        {
            if (string.IsNullOrEmpty(json) || string.IsNullOrEmpty(key))
                return false;
            return Regex.IsMatch(json, "\"" + Regex.Escape(key) + "\"\\s*:\\s*true", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
        }

        private static string JsonString(string json, string key)
        {
            if (string.IsNullOrEmpty(json) || string.IsNullOrEmpty(key))
                return string.Empty;

            var match = Regex.Match(json, "\"" + Regex.Escape(key) + "\"\\s*:\\s*\"((?:\\\\.|[^\"])*)\"", RegexOptions.CultureInvariant);
            if (!match.Success)
                return string.Empty;
            return JsonUnescape(match.Groups[1].Value);
        }

        private static string JsonUnescape(string value)
        {
            if (string.IsNullOrEmpty(value))
                return string.Empty;
            try
            {
                return Regex.Unescape(value.Replace("\\/", "/"));
            }
            catch
            {
                return value.Replace("\\\"", "\"").Replace("\\\\", "\\").Replace("\\/", "/");
            }
        }

        private static int CompareVersionStrings(string left, string right)
        {
            var a = Regex.Matches(left ?? string.Empty, "\\d+").Cast<Match>().Select(m => int.Parse(m.Value)).Take(4).ToArray();
            var b = Regex.Matches(right ?? string.Empty, "\\d+").Cast<Match>().Select(m => int.Parse(m.Value)).Take(4).ToArray();
            var length = Math.Max(Math.Max(a.Length, b.Length), 3);
            for (var i = 0; i < length; i++)
            {
                var av = i < a.Length ? a[i] : 0;
                var bv = i < b.Length ? b[i] : 0;
                if (av != bv)
                    return av > bv ? 1 : -1;
            }
            return 0;
        }

