        private void RegisterCenteredPage(Panel page)
        {
            if (page == null || _centeredPages.Contains(page))
                return;

            _centeredPages.Add(page);
            var hasModernHeader = page.Controls
                .OfType<ModernPanel>()
                .Any(panel => object.Equals(panel.Tag, "PageHeaderSubtitlePanel"));
            if (hasModernHeader)
            {
                foreach (Control child in page.Controls)
                {
                    if (child.Top >= 72 &&
                        !object.Equals(child.Tag, "PageHeaderIcon") &&
                        !object.Equals(child.Tag, "PageHeaderTitle") &&
                        !object.Equals(child.Tag, "PageHeaderSubtitlePanel"))
                    {
                        child.Top += PageHeaderContentShift;
                    }
                }

                if (page.AutoScrollMinSize.Height > 0)
                {
                    page.AutoScrollMinSize = new Size(
                        page.AutoScrollMinSize.Width,
                        page.AutoScrollMinSize.Height + PageHeaderContentShift);
                }
            }

            var maxRight = 0;
            foreach (Control child in page.Controls)
            {
                if (!_centeredControlOrigins.ContainsKey(child))
                    _centeredControlOrigins[child] = child.Location;
                maxRight = Math.Max(maxRight, child.Left + child.Width);
            }

            _centeredPageLayoutWidths[page] = Math.Max(ContentWidth, maxRight);
            page.Resize += delegate { CenterPageContent(page); };
            CenterPageContent(page);
        }

        private void CenterPageContent(Panel page)
        {
            if (page == null || _centeringPages)
                return;

            int layoutWidth;
            if (!_centeredPageLayoutWidths.TryGetValue(page, out layoutWidth))
                layoutWidth = ContentWidth;

            var offset = Math.Max(0, (page.ClientSize.Width - layoutWidth) / 2);
            _centeringPages = true;
            try
            {
                foreach (Control child in page.Controls)
                {
                    Point origin;
                    if (!_centeredControlOrigins.TryGetValue(child, out origin))
                    {
                        origin = child.Location;
                        _centeredControlOrigins[child] = origin;
                    }
                    child.Location = new Point(origin.X + offset, origin.Y);
                }
            }
            finally
            {
                _centeringPages = false;
            }
        }

