        private void AddCarEditorTextField(Control parent, CarEditorField field, int index, int startY)
        {
            var column = index % 3;
            var row = index / 3;
            var x = 18 + (column * 286);
            var y = startY + (row * 50);

            var label = MakeLabel(field.Label, x, y);
            label.Width = 126;
            label.AutoSize = false;
            label.AutoEllipsis = true;
            parent.Controls.Add(label);
            SetTranslatedToolTip(label, field.Description);

            var box = new TextBox();
            box.Location = new Point(x, y + 22);
            box.Size = new Size(254, 28);
            box.TextAlign = HorizontalAlignment.Right;
            StyleTextBox(box);
            parent.Controls.Add(box);
            SetTranslatedToolTip(box, field.Description);
            _carEditorValueBoxes[field.Key] = box;
        }

