        private static void SetGridHeader(DataGridView grid, string columnName, string headerText)
        {
            if (grid == null || !grid.Columns.Contains(columnName) || string.IsNullOrWhiteSpace(headerText))
                return;
            grid.Columns[columnName].HeaderText = headerText;
        }

        private static void WireDatabaseCarSelectionLabel(DataGridView grid, Label label)
        {
            if (grid == null || label == null)
                return;

            grid.SelectionChanged += delegate { UpdateDatabaseCarSelectionLabel(grid, label); };
            grid.CellValueChanged += delegate(object sender, DataGridViewCellEventArgs e)
            {
                if (e.RowIndex >= 0 &&
                    e.ColumnIndex >= 0 &&
                    grid.Columns.Contains("Pick") &&
                    string.Equals(grid.Columns[e.ColumnIndex].Name, "Pick", StringComparison.Ordinal))
                    UpdateDatabaseCarSelectionLabel(grid, label);
            };
        }

        private void WireCarGrid(DataGridView grid)
        {
            grid.Enter += delegate { TrackCarGridSelection(grid); };
            grid.CellClick += delegate { TrackCarGridSelection(grid); };
            grid.SelectionChanged += delegate { TrackCarGridSelection(grid); };
            grid.ColumnHeaderMouseClick += delegate(object sender, DataGridViewCellMouseEventArgs e)
            {
                if (e.ColumnIndex >= 0 && string.Equals(grid.Columns[e.ColumnIndex].Name, "Pick", StringComparison.Ordinal))
                    ToggleVisibleCarChecks(grid);
            };
            grid.CellPainting += delegate(object sender, DataGridViewCellPaintingEventArgs e)
            {
                if (e.RowIndex == -1 &&
                    e.ColumnIndex >= 0 &&
                    string.Equals(grid.Columns[e.ColumnIndex].Name, "Pick", StringComparison.Ordinal))
                    PaintSelectAllHeader(e);
            };
            grid.CurrentCellDirtyStateChanged += delegate
            {
                if (grid.CurrentCell != null &&
                    grid.CurrentCell.OwningColumn != null &&
                    string.Equals(grid.CurrentCell.OwningColumn.Name, "Pick", StringComparison.Ordinal) &&
                    grid.IsCurrentCellDirty)
                    grid.CommitEdit(DataGridViewDataErrorContexts.Commit);
            };
            grid.CellValueChanged += delegate(object sender, DataGridViewCellEventArgs e)
            {
                if (e.RowIndex >= 0 &&
                    e.ColumnIndex >= 0 &&
                    string.Equals(grid.Columns[e.ColumnIndex].Name, "Pick", StringComparison.Ordinal))
                    UpdateCarCheckState(grid.Rows[e.RowIndex]);
            };
        }

        private static void PaintSelectAllHeader(DataGridViewCellPaintingEventArgs e)
        {
            e.Handled = true;
            using (var background = new SolidBrush(SurfaceAlt))
                e.Graphics.FillRectangle(background, e.CellBounds);

            var rect = new Rectangle(e.CellBounds.X + 5, e.CellBounds.Y + 6, Math.Max(1, e.CellBounds.Width - 10), Math.Max(1, e.CellBounds.Height - 12));
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            using (var path = CreateRoundedPath(rect, 7))
            using (var fill = new SolidBrush(Blend(SurfaceAlt, AccentBlue, 0.42F)))
            using (var border = new Pen(AccentBlue))
            {
                e.Graphics.FillPath(fill, path);
                e.Graphics.DrawPath(border, path);
            }

            using (var font = new Font("Segoe UI Semibold", 8F))
            {
                TextRenderer.DrawText(
                    e.Graphics,
                    "All",
                    font,
                    rect,
                    TextPrimary,
                    TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
            }
        }

        private static GraphicsPath CreateRoundedPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            radius = Math.Min(radius, Math.Min(rect.Width, rect.Height) / 2);
            var diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(rect.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }

