        private static IEnumerable<RarityOption> GetDefaultRarityOptions()
        {
            yield return new RarityOption("Common / normal garage car (0)", 0.0, 0);
            yield return new RarityOption("Common+ / slightly rarer (1)", 1.0, 1);
            yield return new RarityOption("Uncommon / low rarity (2)", 2.0, 2);
            yield return new RarityOption("Rare / reward-leaning (3)", 3.0, 3);
            yield return new RarityOption("Rare+ / collectible (4)", 4.0, 4);
            yield return new RarityOption("Epic / mid-high rarity (5)", 5.0, 5);
            yield return new RarityOption("Epic+ / harder to find (6)", 6.0, 6);
            yield return new RarityOption("Legendary / high rarity (7)", 7.0, 7);
            yield return new RarityOption("Legendary+ / very rare (8)", 8.0, 8);
            yield return new RarityOption("Exclusive / hard-to-find (9)", 9.0, 9);
            yield return new RarityOption("Ultra rare / max rarity (10)", 10.0, 10);
        }

        private void LayoutAutoshowActions(Control parent)
        {
            if (_allCars == null || _addAllCars == null)
                return;
            var gap = 16;
            var buttonWidth = Math.Max(180, (parent.ClientSize.Width - gap) / 2);
            var buttonHeight = Math.Min(82, parent.ClientSize.Height);
            _allCars.SetBounds(0, 0, buttonWidth, buttonHeight);
            _addAllCars.SetBounds(buttonWidth + gap, 0, buttonWidth, buttonHeight);
        }

