        private static void MakeLargeAutoshowButton(Button button, Color color, string glyph)
        {
            var modern = button as ModernButton;
            if (modern != null)
            {
                modern.FillColor = Blend(SurfaceAlt, color, 0.22F);
                modern.HoverColor = Blend(SurfaceAlt, color, 0.34F);
                modern.PressedColor = Blend(SurfaceAlt, color, 0.44F);
                modern.BorderColor = color;
                modern.Glyph = glyph;
                modern.GlyphColor = color;
                modern.CornerRadius = 12;
            }
            button.ForeColor = TextPrimary;
            button.TextAlign = ContentAlignment.MiddleCenter;
            button.Cursor = Cursors.Hand;
        }

        private static void MakeAccentButton(Button button, Color color)
        {
            var modern = button as ModernButton;
            if (modern != null)
            {
                modern.FillColor = color;
                modern.HoverColor = ControlPaint.Light(color, 0.08F);
                modern.PressedColor = ControlPaint.Dark(color, 0.08F);
                modern.BorderColor = color;
                modern.TracksTheme = false;
            }
            button.ForeColor = Color.White;
        }

        private static Button MakeNavButton(string text, string glyph, int y)
        {
            return MakeNavButton(text, glyph, y, AccentBlue);
        }

        private static Button MakeNavButton(string text, string glyph, int y, Color glyphColor)
        {
            var button = MakeButton(text, 12, y, 184, 36);
            var modern = button as ModernButton;
            if (modern != null)
            {
                modern.FillColor = Color.FromArgb(37, 47, 64);
                modern.HoverColor = Color.FromArgb(48, 61, 82);
                modern.PressedColor = Color.FromArgb(42, 86, 140);
                modern.SelectedFillColor = Color.FromArgb(42, 91, 148);
                modern.BorderColor = Color.FromArgb(72, 87, 112);
                modern.SelectedBorderColor = AccentBlue;
                modern.Glyph = glyph;
                modern.GlyphColor = glyphColor;
                modern.CenterContent = false;
                modern.TracksTheme = false;
            }
            button.TextAlign = ContentAlignment.MiddleLeft;
            button.Padding = new Padding(40, 0, 0, 0);
            return button;
        }

        private static Button MakeTopNavButton(string text, string glyph, Color glyphColor)
        {
            var font = new Font("Segoe UI Semibold", 7.8F);
            var measured = TextRenderer.MeasureText(text ?? string.Empty, font, new Size(320, 36), TextFormatFlags.SingleLine | TextFormatFlags.NoPadding).Width;
            var width = Math.Max(152, Math.Min(236, measured + 112));
            var button = MakeButton(text, 0, 0, width, 36);
            button.Margin = new Padding(0);
            button.AutoEllipsis = false;
            button.Font = font;
            var modern = button as ModernButton;
            if (modern != null)
            {
                modern.FillColor = Color.FromArgb(37, 47, 64);
                modern.HoverColor = Color.FromArgb(48, 61, 82);
                modern.PressedColor = Color.FromArgb(42, 86, 140);
                modern.SelectedFillColor = Color.FromArgb(42, 91, 148);
                modern.BorderColor = Color.FromArgb(72, 87, 112);
                modern.SelectedBorderColor = AccentBlue;
                modern.Glyph = glyph;
                modern.GlyphColor = glyphColor;
                modern.CenterContent = true;
                modern.TracksTheme = false;
            }
            button.TextAlign = ContentAlignment.MiddleCenter;
            button.Padding = new Padding(0);
            return button;
        }

        private static bool _layoutTopHeaderRunning;

        private static void LayoutTopHeader(Control header, Control banner, Panel navHost)
        {
            if (header == null || banner == null || navHost == null || header.ClientSize.Width <= 0)
                return;

            if (_layoutTopHeaderRunning)
                return;

            _layoutTopHeaderRunning = true;
            navHost.SuspendLayout();
            try
            {
                LayoutTopHeaderCore(header, banner, navHost);
            }
            finally
            {
                navHost.ResumeLayout(false);
                _layoutTopHeaderRunning = false;
            }
        }

        private static void LayoutTopHeaderCore(Control header, Control banner, Panel navHost)
        {
            const int sidePadding = 18;
            const int topPadding = 10;
            const int rowHeight = 36;
            const int horizontalGap = 10;
            const int verticalGap = 8;

            banner.Left = Math.Max(sidePadding, (header.ClientSize.Width - banner.Width) / 2);
            banner.Top = topPadding;

            var availableWidth = Math.Max(320, header.ClientSize.Width - (sidePadding * 2));
            var buttons = navHost.Controls.OfType<Button>().Where(button => button.Visible).ToList();
            var rows = new List<List<Button>>();
            var currentRow = new List<Button>();
            var currentWidth = 0;

            foreach (var button in buttons)
            {
                var nextWidth = currentRow.Count == 0 ? button.Width : currentWidth + horizontalGap + button.Width;
                if (currentRow.Count > 0 && nextWidth > availableWidth)
                {
                    rows.Add(currentRow);
                    currentRow = new List<Button>();
                    currentWidth = 0;
                }

                currentRow.Add(button);
                currentWidth = currentRow.Count == 1 ? button.Width : currentWidth + horizontalGap + button.Width;
            }

            if (currentRow.Count > 0)
                rows.Add(currentRow);
            if (rows.Count == 0)
                rows.Add(new List<Button>());

            var navTop = banner.Bottom + 10;
            var navHeight = (rows.Count * rowHeight) + (Math.Max(0, rows.Count - 1) * verticalGap);
            navHost.SetBounds(sidePadding, navTop, availableWidth, navHeight);

            var y = 0;
            foreach (var row in rows)
            {
                var rowWidth = row.Sum(button => button.Width) + (Math.Max(0, row.Count - 1) * horizontalGap);
                var x = Math.Max(0, (availableWidth - rowWidth) / 2);
                foreach (var button in row)
                {
                    button.Location = new Point(x, y);
                    x += button.Width + horizontalGap;
                }
                y += rowHeight + verticalGap;
            }

            var desiredHeaderHeight = navHost.Bottom + 12;
            var shell = header.Parent as TableLayoutPanel;
            if (shell != null && shell.RowStyles.Count > 0 && Math.Abs(shell.RowStyles[0].Height - desiredHeaderHeight) > 0.5F)
                shell.RowStyles[0].Height = desiredHeaderHeight;
        }

