        private static void SetNavImage(Button button, string fileName)
        {
            var modern = button as ModernButton;
            if (modern == null)
                return;

            var image = LoadLocalAssetIconImage(fileName, modern.GlyphColor);
            if (image == null)
                return;

            modern.IconImage = image;
            modern.Glyph = string.Empty;
            button.Padding = modern.CenterContent ? new Padding(0) : new Padding(40, 0, 0, 0);
            button.Invalidate();
        }

        private static void AddPageHeader(Control parent, string title, string subtitle)
        {
            var headerWidth = GetPageHeaderWidth(title);
            var iconFile = GetPageHeaderIconFileName(title);
            var iconColor = GetPageHeaderIconColor(title);
            var titleFont = new Font("Segoe UI Semibold", 19F);
            var titleWidth = TextRenderer.MeasureText(
                title ?? string.Empty,
                titleFont,
                new Size(headerWidth, 38),
                TextFormatFlags.SingleLine | TextFormatFlags.NoPadding).Width;
            const int iconSize = 38;
            const int titleGap = 12;
            var titleGroupWidth = iconSize + titleGap + titleWidth;
            var titleGroupLeft = Math.Max(0, (headerWidth - titleGroupWidth) / 2);

            var icon = new PictureBox();
            icon.Location = new Point(titleGroupLeft, 0);
            icon.Size = new Size(iconSize, iconSize);
            icon.Image = LoadLocalAssetIconImage(iconFile, iconColor);
            icon.SizeMode = PictureBoxSizeMode.Zoom;
            icon.BackColor = Color.Transparent;
            icon.Tag = "PageHeaderIcon";
            parent.Controls.Add(icon);

            var titleLabel = new Label();
            titleLabel.Text = title;
            titleLabel.UseMnemonic = false;
            titleLabel.Font = titleFont;
            titleLabel.ForeColor = TextPrimary;
            titleLabel.BackColor = AppBackground;
            titleLabel.Location = new Point(titleGroupLeft + iconSize + titleGap, 0);
            titleLabel.Size = new Size(titleWidth + 4, 38);
            titleLabel.TextAlign = ContentAlignment.MiddleLeft;
            titleLabel.Tag = "PageHeaderTitle";
            parent.Controls.Add(titleLabel);

            var subtitlePanel = new ModernPanel();
            subtitlePanel.Location = new Point(0, 46);
            subtitlePanel.Size = new Size(headerWidth, 42);
            subtitlePanel.FillColor = Surface;
            subtitlePanel.BorderColor = Border;
            subtitlePanel.CornerRadius = 10;
            subtitlePanel.BorderWidth = 1F;
            subtitlePanel.BackColor = Surface;
            subtitlePanel.Tag = "PageHeaderSubtitlePanel";
            parent.Controls.Add(subtitlePanel);

            var info = new PageInfoIcon();
            info.GlyphColor = TextMuted;
            info.Location = new Point(14, 6);
            info.Size = new Size(30, 30);
            subtitlePanel.Controls.Add(info);

            var subtitleLabel = new Label();
            subtitleLabel.Text = subtitle;
            subtitleLabel.UseMnemonic = false;
            subtitleLabel.UseCompatibleTextRendering = true;
            subtitleLabel.Font = new Font("Segoe UI", 9F);
            subtitleLabel.ForeColor = TextMuted;
            subtitleLabel.BackColor = Color.Transparent;
            subtitleLabel.Location = new Point(54, 7);
            subtitleLabel.Size = new Size(subtitlePanel.Width - 70, 28);
            subtitleLabel.TextAlign = ContentAlignment.MiddleLeft;
            subtitleLabel.AutoEllipsis = true;
            subtitleLabel.Tag = "PageHeaderSubtitle";
            subtitlePanel.Controls.Add(subtitleLabel);
        }

        private static void ResizePageHeader(Control parent, int headerWidth, Label status)
        {
            if (parent == null)
                return;

            var subtitlePanel = parent.Controls
                .OfType<ModernPanel>()
                .FirstOrDefault(panel => object.Equals(panel.Tag, "PageHeaderSubtitlePanel"));
            if (subtitlePanel != null)
            {
                subtitlePanel.Width = headerWidth;
                var subtitleLabel = subtitlePanel.Controls
                    .OfType<Label>()
                    .FirstOrDefault(label => object.Equals(label.Tag, "PageHeaderSubtitle"));
                if (subtitleLabel != null)
                    subtitleLabel.Width = Math.Max(80, headerWidth - 70);
            }

            var icon = parent.Controls
                .OfType<PictureBox>()
                .FirstOrDefault(control => object.Equals(control.Tag, "PageHeaderIcon"));
            var title = parent.Controls
                .OfType<Label>()
                .FirstOrDefault(control => object.Equals(control.Tag, "PageHeaderTitle"));
            if (icon != null && title != null)
            {
                const int titleGap = 12;
                var groupWidth = icon.Width + titleGap + title.Width;
                var left = Math.Max(0, (headerWidth - groupWidth) / 2);
                icon.Left = left;
                title.Left = left + icon.Width + titleGap;
            }

            if (status != null)
                status.Left = headerWidth - status.Width;
        }

        private static int GetPageHeaderWidth(string title)
        {
            if (string.Equals(title, "Features", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(title, "Database Tools", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(title, "Driving Editor", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(title, "Driving Tuning", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(title, "Teleport", StringComparison.OrdinalIgnoreCase))
                return ContentWidth + 96;

            return ContentWidth;
        }

        private static string GetPageHeaderIconFileName(string title)
        {
            var value = title ?? string.Empty;
            if (value.IndexOf("Feature", StringComparison.OrdinalIgnoreCase) >= 0)
                return "features (1).png";
            if (value.IndexOf("Autoshow", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Autoshow.png";
            if (value.IndexOf("Driving Tuning", StringComparison.OrdinalIgnoreCase) >= 0)
                return "service_846355.png";
            if (value.IndexOf("Driving", StringComparison.OrdinalIgnoreCase) >= 0)
                return "car-maintenance.png";
            if (value.IndexOf("Photo", StringComparison.OrdinalIgnoreCase) >= 0)
                return "photo-mode.png";
            if (value.IndexOf("Role", StringComparison.OrdinalIgnoreCase) >= 0)
                return "role-play.png";
            if (value.IndexOf("Teleport", StringComparison.OrdinalIgnoreCase) >= 0)
                return "teleport (1).png";
            if (value.IndexOf("Console", StringComparison.OrdinalIgnoreCase) >= 0)
                return "consoel.png";
            if (value.IndexOf("Tutorial", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Tutorial 2.png";
            if (value.IndexOf("Feedback", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("Bug", StringComparison.OrdinalIgnoreCase) >= 0)
                return "bug.png";
            if (value.IndexOf("Settings", StringComparison.OrdinalIgnoreCase) >= 0)
                return "setting.png";
            if (value.IndexOf("Donate", StringComparison.OrdinalIgnoreCase) >= 0)
                return "donate.png";
            if (value.IndexOf("Credits", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Credit.png";
            if (value.IndexOf("Connect", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Connection.png";
            if (value.IndexOf("Database Tuning", StringComparison.OrdinalIgnoreCase) >= 0)
                return "self-driving.png";

            return "database (1).png";
        }

        private static Color GetPageHeaderIconColor(string title)
        {
            var value = title ?? string.Empty;
            if (value.IndexOf("Feature", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(59, 130, 246);
            if (value.IndexOf("Autoshow", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(16, 185, 129);
            if (value.IndexOf("Driving Tuning", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(239, 68, 68);
            if (value.IndexOf("Driving", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(45, 212, 191);
            if (value.IndexOf("Photo", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(14, 165, 233);
            if (value.IndexOf("Role", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(168, 85, 247);
            if (value.IndexOf("Teleport", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(34, 197, 94);
            if (value.IndexOf("Console", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(161, 161, 170);
            if (value.IndexOf("Tutorial", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(99, 102, 241);
            if (value.IndexOf("Feedback", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("Bug", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(244, 63, 94);
            if (value.IndexOf("Settings", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(148, 163, 184);
            if (value.IndexOf("Donate", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(236, 72, 153);
            if (value.IndexOf("Credits", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(251, 191, 36);
            if (value.IndexOf("Connect", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(6, 182, 212);
            if (value.IndexOf("Database Tuning", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(245, 158, 11);

            return Color.FromArgb(249, 115, 22);
        }

        private static ModernPanel MakeCard(Control parent, int x, int y, int width, int height, string title, string subtitle)
        {
            var panel = new ModernPanel();
            panel.Location = new Point(x, y);
            panel.Size = new Size(width, height);
            panel.FillColor = Surface;
            panel.BorderColor = Border;
            panel.CornerRadius = 14;
            panel.BackColor = Surface;
            panel.Padding = new Padding(16);
            parent.Controls.Add(panel);

            if (!string.IsNullOrEmpty(title))
            {
                var titleLabel = new Label();
                titleLabel.Text = title;
                titleLabel.UseMnemonic = false;
                titleLabel.Font = new Font("Segoe UI Semibold", 11F);
                titleLabel.ForeColor = TextPrimary;
                titleLabel.BackColor = Surface;
                titleLabel.Location = new Point(18, 14);
                titleLabel.Size = new Size(Math.Max(120, width - 36), 22);
                titleLabel.Anchor = AnchorStyles.Left | AnchorStyles.Top | AnchorStyles.Right;
                panel.Controls.Add(titleLabel);
            }

            if (!string.IsNullOrEmpty(subtitle))
            {
                var subtitleLabel = new Label();
                subtitleLabel.Text = subtitle;
                subtitleLabel.UseMnemonic = false;
                subtitleLabel.Font = new Font("Segoe UI", 8.5F);
                subtitleLabel.ForeColor = TextMuted;
                subtitleLabel.BackColor = Surface;
                subtitleLabel.Location = new Point(18, 34);
                subtitleLabel.Size = new Size(Math.Max(120, width - 36), 20);
                subtitleLabel.Anchor = AnchorStyles.Left | AnchorStyles.Top | AnchorStyles.Right;
                panel.Controls.Add(subtitleLabel);
            }

            return panel;
        }

        private static Label MakeBodyLabel(string text, int x, int y, int width, int height)
        {
            var label = new Label();
            label.Text = text;
            label.UseMnemonic = false;
            label.Font = new Font("Segoe UI", 9F);
            label.ForeColor = TextMuted;
            label.BackColor = Surface;
            label.Location = new Point(x, y);
            label.Size = new Size(width, height);
            label.Anchor = AnchorStyles.Left | AnchorStyles.Top | AnchorStyles.Right;
            return label;
        }

        private static void StyleTextBox(TextBox box)
        {
            box.BorderStyle = BorderStyle.FixedSingle;
            box.BackColor = SurfaceAlt;
            box.ForeColor = TextPrimary;
            box.Font = new Font("Segoe UI", 9.5F);
        }

        private static TextBox MakeRoundedValueTextBox(Control parent, int x, int y, int width, int height, string text, HorizontalAlignment align)
        {
            var frame = new ModernPanel();
            frame.Location = new Point(x, y - 2);
            frame.Size = new Size(width, height);
            frame.FillColor = SurfaceAlt;
            frame.BorderColor = Blend(Border, AccentBlue, 0.32F);
            frame.CornerRadius = 10;
            frame.BackColor = Surface;
            parent.Controls.Add(frame);

            var box = new TextBox();
            box.BorderStyle = BorderStyle.None;
            box.BackColor = SurfaceAlt;
            box.ForeColor = TextPrimary;
            box.Font = new Font("Segoe UI Semibold", 9F);
            box.Text = text ?? string.Empty;
            box.TextAlign = align;
            box.Location = new Point(8, 7);
            box.Size = new Size(Math.Max(16, width - 16), Math.Max(18, height - 12));
            frame.Controls.Add(box);
            return box;
        }

        private static void StyleComboBox(ComboBox box)
        {
            box.BackColor = SurfaceAlt;
            box.ForeColor = TextPrimary;
            box.Font = new Font("Segoe UI", 9.5F);
            box.FlatStyle = FlatStyle.Flat;
        }

        private static void StyleLogBox(RichTextBox log)
        {
            var lightTheme = AppBackground.GetBrightness() > 0.62F;
            log.BackColor = lightTheme ? Color.FromArgb(248, 250, 252) : Color.FromArgb(17, 20, 26);
            log.ForeColor = lightTheme ? Color.FromArgb(30, 41, 59) : Color.FromArgb(226, 232, 240);
            log.BorderStyle = BorderStyle.None;
            log.ReadOnly = true;
            log.Font = new Font("Cascadia Mono", 9.25F);
            log.DetectUrls = false;
            log.WordWrap = false;
            log.Tag = "ConsoleLog";
        }

