        private void RunWorker(string actionName, Action action)
        {
            RunWorker(actionName, action, null);
        }

        private void RunWorker(string actionName, Action action, Button feedbackButton)
        {
            var isLoadCurrent = string.Equals(actionName, "Load Current", StringComparison.OrdinalIgnoreCase);
            var isAttach = actionName.IndexOf("Attach", StringComparison.OrdinalIgnoreCase) >= 0;
            SetButtons(false);
            if (isAttach)
                SetConnectionState(LunaConnectionState.Connecting);
            SetStatus(actionName + " running...");
            SetFeaturesStatus(actionName + " running...");
            SetProfileStatus(actionName + " running...");
            SetCarStatus(actionName + " running...");
            SetRarityStatus(actionName + " running...");
            SetSkillStatus(actionName + " running...");
            SetCarEditorStatus(actionName + " running...");
            SetDrivingStatus(actionName + " running...");
            if (isLoadCurrent)
                StartLoadCurrentTimer();
            ThreadPool.QueueUserWorkItem(delegate
            {
                var succeeded = false;
                try
                {
                    action();
                    succeeded = true;
                    SetStatus(actionName + " success");
                    SetFeaturesStatus(actionName + " success");
                    SetProfileStatus(actionName + " success");
                    SetCarStatus(actionName + " success");
                    SetRarityStatus(actionName + " success");
                    SetSkillStatus(actionName + " success");
                    SetCarEditorStatus(actionName + " success");
                    SetDrivingStatus(actionName + " success");
                }
                catch (Exception ex)
                {
                    if (isAttach)
                        SetConnectionState(LunaConnectionState.Disconnected);
                    Log("ERROR: " + ex.Message);
                    SetStatus(actionName + " failed");
                    SetFeaturesStatus(actionName + " failed");
                    SetProfileStatus(actionName + " failed");
                    SetCarStatus(actionName + " failed");
                    SetRarityStatus(actionName + " failed");
                    SetSkillStatus(actionName + " failed");
                    SetCarEditorStatus(actionName + " failed");
                    SetDrivingStatus(actionName + " failed");
                }
                finally
                {
                    if (isLoadCurrent)
                        StopLoadCurrentTimer(succeeded);
                    if (isAttach)
                    {
                        if (succeeded)
                        {
                            _startupAutoAttachRetryCount = 0;
                        }
                        else
                        {
                            _startupAutoAttachStarted = false;
                            if (string.Equals(actionName, "Startup Attach", StringComparison.OrdinalIgnoreCase) &&
                                _startupAutoAttachRetryCount < 2 && !IsDisposed)
                            {
                                _startupAutoAttachRetryCount++;
                                if (!IsDisposed && IsHandleCreated)
                                {
                                    try { BeginInvoke((Action)TryAutoAttachOnOpen); }
                                    catch { }
                                }
                            }
                        }
                    }
                    SetButtons(true);
                    if (succeeded)
                        FlashButtonSuccess(feedbackButton);
                }
            });
        }

        private void TryAutoAttachOnOpen()
        {
            if (_startupAutoAttachStarted || IsDisposed)
                return;
            if (_database != null && _database.IsAlive)
                return;

            Process process = null;
            try
            {
                process = FindForzaHorizonProcess();
            }
            catch
            {
            }

            if (process == null)
                return;

            _startupAutoAttachStarted = true;
            Log("FH6 is already running. Luna is auto-attaching now.");
            RunWorker("Startup Attach", Attach, _attach);
        }

        private void StartLoadCurrentTimer()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)StartLoadCurrentTimer);
                return;
            }

            _loadCurrentStartedUtc = DateTime.UtcNow;
            _loadCurrentUiTimer.Stop();
            _loadCurrentUiTimer.Start();
            SetFeaturesStatus("Load Current 00:00 / ~2:30 min", AccentBlue);
            Log("Load Current started. This should be done in around 2:30 minutes or less.");
        }

        private void UpdateLoadCurrentTimerStatus()
        {
            if (_loadCurrentStartedUtc == DateTime.MinValue)
                return;

            var elapsed = DateTime.UtcNow - _loadCurrentStartedUtc;
            SetFeaturesStatus("Load Current " + FormatElapsed(elapsed) + " / ~2:30 min", AccentBlue);
        }

        private void StopLoadCurrentTimer(bool succeeded)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { StopLoadCurrentTimer(succeeded); }));
                return;
            }

            _loadCurrentUiTimer.Stop();
            var elapsed = _loadCurrentStartedUtc == DateTime.MinValue ? TimeSpan.Zero : DateTime.UtcNow - _loadCurrentStartedUtc;
            _loadCurrentStartedUtc = DateTime.MinValue;
            if (succeeded)
                SetFeaturesStatus("Load Current Is Completed", AccentGreen);
            else
                SetFeaturesStatus("Load Current failed " + FormatElapsed(elapsed), AccentRed);
        }

        private static string FormatElapsed(TimeSpan elapsed)
        {
            if (elapsed < TimeSpan.Zero)
                elapsed = TimeSpan.Zero;
            var totalMinutes = (int)elapsed.TotalMinutes;
            return totalMinutes.ToString("00", CultureInfo.InvariantCulture) + ":" + elapsed.Seconds.ToString("00", CultureInfo.InvariantCulture);
        }

