        private void FlashButtonSuccess(Button button)
        {
            if (button == null || button.IsDisposed)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { FlashButtonSuccess(button); }));
                return;
            }

            var modern = button as ModernButton;
            if (modern == null)
                return;

            var fill = modern.FillColor;
            var hover = modern.HoverColor;
            var pressed = modern.PressedColor;
            var border = modern.BorderColor;
            var fore = button.ForeColor;
            var tracksTheme = modern.TracksTheme;
            var flashColor = object.Equals(button.Tag, "FeatureApply")
                ? Color.FromArgb(83, 177, 255)
                : AccentGreen;
            MakeAccentButton(button, flashColor);

            var timer = new System.Windows.Forms.Timer();
            timer.Interval = 850;
            timer.Tick += delegate
            {
                timer.Stop();
                timer.Dispose();
                if (button.IsDisposed)
                    return;
                modern.FillColor = fill;
                modern.HoverColor = hover;
                modern.PressedColor = pressed;
                modern.BorderColor = border;
                modern.TracksTheme = tracksTheme;
                button.ForeColor = fore;
                modern.Invalidate();
            };
            timer.Start();
        }

        private static void SetInteractiveControls(Control parent, bool enabled)
        {
            foreach (Control control in parent.Controls)
            {
                if (control is Button || control is TextBox || control is ComboBox || control is CheckBox || control is DataGridView)
                    control.Enabled = enabled;
                if (control.HasChildren)
                    SetInteractiveControls(control, enabled);
            }
        }

