        private void Log(string text)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { Log(text); }));
                return;
            }
            text = NormalizeConsoleLog(text);
            if (string.IsNullOrEmpty(text))
                return;
            var line = "[" + DateTime.Now.ToString("HH:mm:ss") + "] " + text + Environment.NewLine;
            AppendConsoleLine(line, text);
            try
            {
                File.AppendAllText(_logPath, line);
            }
            catch
            {
            }
        }

        private void AppendConsoleLine(string line, string message)
        {
            if (_log == null || _log.IsDisposed)
                return;

            var start = _log.TextLength;
            _log.AppendText(line);
            _log.Select(start, line.Length);
            var messageColor = GetConsoleMessageColor(message);
            _log.SelectionColor = messageColor;
            _log.SelectionLength = 0;
            if (_consoleAutoScroll)
            {
                _log.SelectionStart = _log.TextLength;
                _log.ScrollToCaret();
            }
            if (_consoleStatusLabel != null && !_consoleStatusLabel.IsDisposed)
            {
                var lineCount = _log.Lines.Count(item => !string.IsNullOrWhiteSpace(item));
                _consoleStatusLabel.Text = lineCount.ToString(CultureInfo.InvariantCulture) + " entries  |  " + Path.GetFileName(_logPath);
            }
            AppendConsoleOverlayLine(line, messageColor);
        }

        private static Color GetConsoleMessageColor(string message)
        {
            var value = message ?? string.Empty;
            if (value.IndexOf("ERROR", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("failed", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("could not", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(248, 113, 113);
            if (value.IndexOf("ready", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("success", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("finished", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("applied", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("connected", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(74, 222, 128);
            if (value.IndexOf("warning", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("waiting", StringComparison.OrdinalIgnoreCase) >= 0 ||
                value.IndexOf("skipped", StringComparison.OrdinalIgnoreCase) >= 0)
                return Color.FromArgb(250, 204, 21);
            return TextPrimary;
        }

        private static string NormalizeConsoleLog(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return string.Empty;

            var value = text.Trim();
            if (value.StartsWith("Candidate ", StringComparison.OrdinalIgnoreCase) && value.IndexOf(" db=0x", StringComparison.OrdinalIgnoreCase) >= 0)
                return string.Empty;
            if (value.StartsWith("SQL candidate exit ", StringComparison.OrdinalIgnoreCase))
                return string.Empty;
            if (value.StartsWith("SQL executed on FH6 CDatabase", StringComparison.OrdinalIgnoreCase) ||
                value.StartsWith("SQL query executed on FH6 CDatabase", StringComparison.OrdinalIgnoreCase))
                return string.Empty;
            if (value.StartsWith("Database object:", StringComparison.OrdinalIgnoreCase) ||
                value.StartsWith("SQL function:", StringComparison.OrdinalIgnoreCase) ||
                value.StartsWith("Database candidates armed:", StringComparison.OrdinalIgnoreCase))
                return string.Empty;

            if (value.StartsWith("Scanning main module:", StringComparison.OrdinalIgnoreCase))
                return "Scanning FH6 process.";
            if (value.StartsWith("Manual folder mode is ON.", StringComparison.OrdinalIgnoreCase))
                return "Manual folder mode is ON.";
            if (value.StartsWith("Detected game folder:", StringComparison.OrdinalIgnoreCase))
                return "Detected game folder.";
            if (value.StartsWith("Game folder changed.", StringComparison.OrdinalIgnoreCase))
                return "Game folder changed.";
            if (value.StartsWith("Opening donation page:", StringComparison.OrdinalIgnoreCase))
                return "Opening donation page.";

            var index = value.IndexOf(" hook is already installed at ", StringComparison.OrdinalIgnoreCase);
            if (index > 0)
                return value.Substring(0, index) + " already ready.";

            index = value.IndexOf(" hook verified at ", StringComparison.OrdinalIgnoreCase);
            if (index > 0)
                return value.Substring(0, index) + " checked.";

            index = value.IndexOf(" runtime detour installed.", StringComparison.OrdinalIgnoreCase);
            if (index > 0)
                return value.Substring(0, index) + " ready.";

            if (value.StartsWith("CRC check bypass armed.", StringComparison.OrdinalIgnoreCase))
                return "Runtime safety hook ready.";
            if (value.StartsWith("CRC check bypass restored.", StringComparison.OrdinalIgnoreCase))
                return "Runtime safety hook restored.";
            if (value.StartsWith("Jump armed at detour", StringComparison.OrdinalIgnoreCase))
                return "Jump ON. Hold the selected key for repeated controlled hops.";
            if (value.StartsWith("Gravity runtime hook enabled.", StringComparison.OrdinalIgnoreCase))
            {
                var requested = ExtractLogPart(value, "requested=", ",");
                return string.IsNullOrEmpty(requested) ? "Gravity ON." : "Gravity ON at " + requested + ".";
            }
            if (value.StartsWith("Best Spins patched ", StringComparison.OrdinalIgnoreCase))
                return "Best Spins patch applied.";
            if (value.StartsWith("Patched Autoshow query text", StringComparison.OrdinalIgnoreCase))
                return "Autoshow query patch applied.";

            index = value.IndexOf(" Signature:", StringComparison.OrdinalIgnoreCase);
            if (index >= 0)
                value = value.Substring(0, index);

            value = RedactHexNoise(value, " at 0x");
            value = RedactHexNoise(value, " pointer=0x");
            value = RedactHexNoise(value, " target=0x");
            value = RedactHexNoise(value, " detour=0x");
            value = RedactHexNoise(value, " db=0x");
            value = RedactHexNoise(value, " fn=0x");
            value = RedactHexNoise(value, " 0x");
            return value;
        }

        private static string ExtractLogPart(string text, string marker, string terminator)
        {
            var start = text.IndexOf(marker, StringComparison.OrdinalIgnoreCase);
            if (start < 0)
                return string.Empty;
            start += marker.Length;
            var end = text.IndexOf(terminator, start, StringComparison.OrdinalIgnoreCase);
            if (end < 0)
                end = text.Length;
            return text.Substring(start, end - start).Trim();
        }

        private static string RedactHexNoise(string text, string marker)
        {
            var index = text.IndexOf(marker, StringComparison.OrdinalIgnoreCase);
            if (index < 0)
                return text;

            var end = index + marker.Length;
            while (end < text.Length && Uri.IsHexDigit(text[end]))
                end++;

            return text.Substring(0, index) + text.Substring(end);
        }

        private void Attach()
        {
            if (_database != null)
            {
                _database.Dispose();
                _database = null;
            }
            SetConnectionState(LunaConnectionState.Connecting);

            Log("Smart attach scan: looking for the running Forza Horizon 6 game PID.");
            var process = FindForzaHorizonProcess();
            if (process == null)
                throw new InvalidOperationException("Forza Horizon 6 is not running. Start the game, load into the world, then press Attach.");

            SetTextBoxValue(_processName, process.ProcessName);
            var detectedPath = TryResolveProcessFolder(process);
            var platform = DetectForzaPlatform(process);
            Log("Selected " + platform + " FH6 process (PID " + process.Id.ToString(CultureInfo.InvariantCulture) + ").");
            var manualMode = IsManualAttachFolderEnabled();
            if (manualMode)
            {
                var manualPath = GetManualGamePath();
                if (!Directory.Exists(manualPath))
                    throw new InvalidOperationException("Manual folder mode is on, but that folder does not exist.");
                if (!ContainsForzaHorizonExecutable(manualPath))
                    throw new InvalidOperationException("Manual folder mode is on, but no supported FH6 executable was found in that folder.");
                Log("Manual folder mode is ON. Luna will use this folder for string tables: " + manualPath);
            }
            else if (!string.IsNullOrWhiteSpace(detectedPath))
            {
                SetTextBoxValue(_gamePath, detectedPath);
                Log("Detected game folder: " + detectedPath);
            }
            else
            {
                Log("Game folder auto-detect was unavailable. Luna will use the existing string-table path if needed.");
            }

            _database = new RemoteDatabase(process, Log);
            _database.Attach();
            _liveDrivingHooksVerified = false;
            _featuresAutoLoadDone = false;
            Log("Attached to PID " + process.Id + ".");
            Log("Database object: 0x" + _database.DatabaseObject.ToString("X"));
            Log("SQL function:    0x" + _database.QueryFunction.ToString("X"));
            Log("Database candidates armed: " + _database.CandidateCount);
            _database.VerifyFh6Schema();
            try
            {
                LoadCarTablesFromDatabase(_database);
            }
            catch (Exception ex)
            {
            Log("Autoshow car browser auto-load skipped: " + ex.Message);
            }
            TryAutoProbeLiveDrivingHooks();
            AutoLoadCurrentRuntimeValuesOnAttach();
        }

        private bool IsManualAttachFolderEnabled()
        {
            if (_manualAttachMode == null)
                return false;
            if (_manualAttachMode.InvokeRequired)
                return (bool)_manualAttachMode.Invoke(new Func<bool>(IsManualAttachFolderEnabled));
            return _manualAttachMode.Checked;
        }

        private string GetManualGamePath()
        {
            if (_gamePath == null)
                return DefaultGamePath;
            if (_gamePath.InvokeRequired)
                return (string)_gamePath.Invoke(new Func<string>(GetManualGamePath));
            return (_gamePath.Text ?? string.Empty).Trim();
        }

        private Process FindForzaHorizonProcess()
        {
            var candidates = new List<Process>();
            foreach (var name in new[] { "ForzaHorizon6", "forzahorizon6" })
            {
                try
                {
                    candidates.AddRange(Process.GetProcessesByName(name));
                }
                catch
                {
                }
            }

            try
            {
                candidates.AddRange(Process.GetProcesses().Where(process =>
                    IsForzaHorizonGameProcess(process)));
            }
            catch
            {
            }

            return candidates
                .GroupBy(process => process.Id)
                .Select(group => group.First())
                .Where(process => IsForzaHorizonGameProcess(process))
                .OrderByDescending(process => HasForzaMainWindow(process))
                .ThenByDescending(process => GetSafeProcessStartTime(process))
                .ThenByDescending(process => GetForzaPlatformPriority(process))
                .ThenByDescending(process => string.Equals(process.ProcessName, "ForzaHorizon6", StringComparison.OrdinalIgnoreCase))
                .ThenBy(process => process.ProcessName, StringComparer.OrdinalIgnoreCase)
                .FirstOrDefault();
        }

        private static bool HasForzaMainWindow(Process process)
        {
            try
            {
                return process != null && !process.HasExited && process.MainWindowHandle != IntPtr.Zero &&
                    (process.MainWindowTitle ?? string.Empty).IndexOf("Forza Horizon", StringComparison.OrdinalIgnoreCase) >= 0;
            }
            catch
            {
                return false;
            }
        }

        private static DateTime GetSafeProcessStartTime(Process process)
        {
            try { return process == null ? DateTime.MinValue : process.StartTime; }
            catch { return DateTime.MinValue; }
        }

        private static int GetForzaPlatformPriority(Process process)
        {
            var platform = DetectForzaPlatform(process);
            if (string.Equals(platform, "Steam", StringComparison.OrdinalIgnoreCase))
                return 3;
            if (string.Equals(platform, "Xbox", StringComparison.OrdinalIgnoreCase))
                return 2;
            if (string.Equals(platform, "Microsoft Store", StringComparison.OrdinalIgnoreCase))
                return 1;
            return 0;
        }

        private static string DetectForzaPlatform(Process process)
        {
            var path = TryResolveProcessExecutablePath(process);
            if (path.IndexOf("\\steamapps\\", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Steam";
            if (path.IndexOf("\\XboxGames\\", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Xbox";
            if (path.IndexOf("\\WindowsApps\\", StringComparison.OrdinalIgnoreCase) >= 0)
                return "Microsoft Store";
            return "unknown-platform";
        }

        private static string TryResolveProcessExecutablePath(Process process)
        {
            if (process == null)
                return string.Empty;
            try
            {
                var module = process.MainModule;
                return module == null ? string.Empty : module.FileName ?? string.Empty;
            }
            catch
            {
                return string.Empty;
            }
        }

        private static bool IsForzaHorizonGameProcess(Process process)
        {
            if (process == null || process.Id == Process.GetCurrentProcess().Id)
                return false;

            try
            {
                var module = process.MainModule;
                var path = module == null ? string.Empty : module.FileName;
                if (IsForzaHorizonExecutablePath(path))
                    return true;
            }
            catch
            {
            }

            var processName = process.ProcessName ?? string.Empty;
            return LooksLikeForzaHorizonText(processName) && !LooksLikeLunaText(processName);
        }

        private static bool ContainsForzaHorizonExecutable(string folder)
        {
            if (string.IsNullOrWhiteSpace(folder) || !Directory.Exists(folder))
                return false;

            try
            {
                foreach (var path in Directory.GetFiles(folder, "*.exe", SearchOption.TopDirectoryOnly))
                {
                    if (IsForzaHorizonExecutablePath(path))
                        return true;
                }
            }
            catch
            {
            }

            return false;
        }

        private static bool IsForzaHorizonExecutablePath(string path)
        {
            if (string.IsNullOrWhiteSpace(path) || !path.EndsWith(".exe", StringComparison.OrdinalIgnoreCase))
                return false;

            try
            {
                var current = Application.ExecutablePath;
                if (!string.IsNullOrWhiteSpace(current) && string.Equals(Path.GetFullPath(path), Path.GetFullPath(current), StringComparison.OrdinalIgnoreCase))
                    return false;
            }
            catch
            {
            }

            var fileName = Path.GetFileNameWithoutExtension(path) ?? string.Empty;
            var fullPath = path ?? string.Empty;
            if (LooksLikeLunaText(fileName) || LooksLikeLunaText(fullPath))
                return false;

            if (LooksLikeForzaHorizonText(fileName) || LooksLikeForzaHorizonText(fullPath))
                return true;

            try
            {
                var info = FileVersionInfo.GetVersionInfo(path);
                return LooksLikeForzaHorizonText(info.ProductName) ||
                    LooksLikeForzaHorizonText(info.FileDescription) ||
                    LooksLikeForzaHorizonText(info.OriginalFilename) ||
                    LooksLikeForzaHorizonText(info.InternalName);
            }
            catch
            {
                return false;
            }
        }

        private static bool LooksLikeForzaHorizonText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return false;

            var normalized = text.Replace("_", string.Empty).Replace("-", string.Empty).Replace(" ", string.Empty).ToLowerInvariant();
            return normalized.IndexOf("forzahorizon6", StringComparison.OrdinalIgnoreCase) >= 0 ||
                normalized.IndexOf("fh6", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static bool LooksLikeLunaText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return false;

            var normalized = text.ToLowerInvariant();
            return normalized.IndexOf("luna", StringComparison.OrdinalIgnoreCase) >= 0 ||
                normalized.IndexOf("autoshowunlocker", StringComparison.OrdinalIgnoreCase) >= 0 ||
                normalized.IndexOf("trainer", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static string TryResolveProcessFolder(Process process)
        {
            try
            {
                var path = TryResolveProcessExecutablePath(process);
                if (string.IsNullOrWhiteSpace(path))
                    return string.Empty;
                var folder = Path.GetDirectoryName(path);
                return Directory.Exists(folder) ? folder : string.Empty;
            }
            catch
            {
                return string.Empty;
            }
        }

        private RemoteDatabase RequireDatabase()
        {
            if (_database == null || !_database.IsAlive)
                Attach();
            return _database;
        }

        private void Dump()
        {
            Directory.CreateDirectory(_dumpDir);
            CopyStaticDatabaseCandidate();

            var db = RequireDatabase();
            var schemaReport = db.DumpSchemaReport(_dumpDir);
            Log("Wrote schema report: " + Path.GetFileName(schemaReport));
            var liveDump = db.DumpLiveDatabaseSqlite(_dumpDir);
            Log("Wrote live database dump: " + Path.GetFileName(liveDump));

            WriteSqlReference();
        }

        private void Persist()
        {
            var db = RequireDatabase();
            Log("Reapplying Autoshow unlock.");
            ApplyAutoshowUnlock(db);
            Log("Autoshow unlock reapplied.");
        }

        private void ToggleAllCars()
        {
            if (!_allCarsOn)
            {
                var db = RequireDatabase();
                Log("Applying All Cars Autoshow unlock.");
                ApplyAutoshowUnlock(db);
                _allCarsOn = true;
                UpdateAllCarsButton();
                Log("All Cars unlock sent. Apply before opening Autoshow, then enter Autoshow fresh.");
                ShowInfo("All cars are now showing in Autoshow. Enjoy!");
            }
