        }

        private void LoadCarTables()
        {
            var db = RequireDatabase();
            LoadCarTablesFromDatabase(db);
        }

        private void LoadCarTablesFromDatabase(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            ResolveActiveGarageTable(db);

            var owned = QueryOwnedCarRows(db);
            var addable = QueryAddableCarRows(db);
            SetCarTableRows(owned, addable);
            SetCarStatus("Garage " + owned.Count.ToString(CultureInfo.InvariantCulture) + " | Addable " + addable.Count.ToString(CultureInfo.InvariantCulture));
            Log("Autoshow car browser loaded. Garage rows: " + owned.Count.ToString(CultureInfo.InvariantCulture) + "; addable cars: " + addable.Count.ToString(CultureInfo.InvariantCulture) + ".");
        }

        private List<CarTableRow> QueryOwnedCarRows(RemoteDatabase db)
        {
            var garageTable = ResolveActiveGarageTable(db);
            var garageSql = EscapeIdentifierForSql(garageTable);
            var ownedState = "'Owned'";
            var ownedPiExpr = "COALESCE(MAX(garage.PerformanceIndex), MAX(data.PerformanceIndex), 0)";
            var ownedClassExpr = "COALESCE(MAX(garage.ClassID), MAX(data.ClassID), 0)";
            var sql =
                "SELECT garage.CarId AS CarId, " +
                "COALESCE(MAX(data.Year), '') AS Year, " +
                "COALESCE(MAX(data.MakeName), '') AS Make, " +
                "COALESCE(MAX(data.DisplayName), MAX(data.ModelShort), MAX(data.MediaName), '') AS Model, " +
                ownedPiExpr + " AS PI, " +
                ownedClassExpr + " AS ClassID, " +
                "COUNT(*) AS Copies, " +
                ownedState + " AS State " +
                "FROM " + garageSql + " garage " +
                "LEFT JOIN Data_Car data ON data.Id = garage.CarId " +
                "WHERE garage.CarId IS NOT NULL AND garage.CarId > 0 AND garage.CarId <> 3300 " +
                "GROUP BY garage.CarId " +
                "ORDER BY CAST(COALESCE(MAX(data.Year), 0) AS INTEGER), Make, Model, garage.CarId;";
            return QueryCarTableRowsWithLocalization(db, sql);
        }

        private List<CarTableRow> QueryAddableCarRows(RemoteDatabase db)
        {
            var garageTable = ResolveActiveGarageTable(db);
            var garageSql = EscapeIdentifierForSql(garageTable);
            var freeGrantState = "'Not Owned'";
            var addablePiExpr = "COALESCE(data.PerformanceIndex, 0)";
            var addableClassExpr = BuildPerformanceClassExpression(db, addablePiExpr, "COALESCE(data.ClassID, 0)");
            var sql =
                "SELECT data.Id AS CarId, " +
                "COALESCE(data.Year, '') AS Year, " +
                "COALESCE(data.MakeName, '') AS Make, " +
                "COALESCE(data.DisplayName, data.ModelShort, data.MediaName, '') AS Model, " +
                addablePiExpr + " AS PI, " +
                addableClassExpr + " AS ClassID, " +
                "COALESCE((SELECT COUNT(*) FROM " + garageSql + " garage WHERE garage.CarId = data.Id), 0) AS Copies, " +
                freeGrantState + " AS State " +
                "FROM Data_Car data " +
                "WHERE data.Id IS NOT NULL AND data.Id > 0 AND data.Id <> 3300 " +
                "AND NOT EXISTS (SELECT 1 FROM " + garageSql + " garage WHERE garage.CarId = data.Id) " +
                "ORDER BY CAST(COALESCE(data.Year, 0) AS INTEGER), Make, Model, data.Id;";
            return QueryCarTableRowsWithLocalization(db, sql);
        }

        private static List<CarTableRow> QueryCarTableRows(RemoteDatabase db, string sql)
        {
            var result = db.Query(sql);
            var rows = new List<CarTableRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 8)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;

                rows.Add(new CarTableRow(
                    carId,
                    ToDisplayString(row[1]),
                    CleanCarText(ToDisplayString(row[2])),
                    CleanCarText(ToDisplayString(row[3])),
                    FormatCarNumber(row[4]),
                    ToDisplayString(row[5]),
                    ToDisplayString(row[6]),
                    ToDisplayString(row[7])));
            }
            return rows;
        }

        private List<CarTableRow> QueryCarTableRowsWithLocalization(RemoteDatabase db, string sql)
        {
            EnsureCarStringTablesLoaded();

            var result = db.Query(sql);
            var rows = new List<CarTableRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 8)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;

                rows.Add(new CarTableRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    ToDisplayString(row[5]),
                    ToDisplayString(row[6]),
                    ToDisplayString(row[7])));
            }
            return rows;
        }

        private void EnsureCarStringTablesLoaded()
        {
            var zipPath = ResolveStringTableZipPath();
            if (string.Equals(_stringTableCachePath, zipPath, StringComparison.OrdinalIgnoreCase) &&
                _carNameStrings.Count > 0 &&
                _carMakeStrings.Count > 0)
                return;

            _stringTableCachePath = zipPath ?? string.Empty;
            _carNameStrings = new Dictionary<uint, string>();
            _carMakeStrings = new Dictionary<uint, string>();

            if (string.IsNullOrWhiteSpace(zipPath) || !File.Exists(zipPath))
            {
                Log("Autoshow car browser names: EN string table zip was not found. Showing raw localization keys.");
                return;
            }

            try
            {
                using (var archive = ZipFile.OpenRead(zipPath))
                {
                    _carNameStrings = LoadForzaStringTable(archive, "Data_Car.str");
                    _carMakeStrings = LoadForzaStringTable(archive, "List_CarMake.str");
                }

                Log("Autoshow car browser names loaded from " + Path.GetFileName(zipPath) + ": " +
                    _carMakeStrings.Count.ToString(CultureInfo.InvariantCulture) + " makes, " +
                    _carNameStrings.Count.ToString(CultureInfo.InvariantCulture) + " car names.");
            }
            catch (Exception ex)
            {
                _carNameStrings.Clear();
                _carMakeStrings.Clear();
                Log("Autoshow car browser names could not be loaded: " + ex.Message);
            }
        }

        private string ResolveStringTableZipPath()
        {
            var gamePath = _gamePath == null ? DefaultGamePath : _gamePath.Text.Trim();
            if (string.IsNullOrWhiteSpace(gamePath))
                gamePath = DefaultGamePath;

            var stringTableRoot = Path.Combine(gamePath, "media", "Stripped", "StringTables");
            var preferred = Path.Combine(stringTableRoot, "EN.zip");
            if (File.Exists(preferred))
                return preferred;

            var gb = Path.Combine(stringTableRoot, "GB.zip");
            if (File.Exists(gb))
                return gb;

            if (Directory.Exists(stringTableRoot))
            {
                var firstZip = Directory.GetFiles(stringTableRoot, "*.zip").OrderBy(path => path, StringComparer.OrdinalIgnoreCase).FirstOrDefault();
                if (!string.IsNullOrWhiteSpace(firstZip))
                    return firstZip;
            }

            return preferred;
        }

        private static Dictionary<uint, string> LoadForzaStringTable(ZipArchive archive, string entryName)
        {
            var entry = archive.Entries.FirstOrDefault(item => string.Equals(item.FullName, entryName, StringComparison.OrdinalIgnoreCase));
            if (entry == null)
                return new Dictionary<uint, string>();

            using (var stream = entry.Open())
            using (var memory = new MemoryStream())
            {
                stream.CopyTo(memory);
                return ParseForzaStringTable(memory.ToArray());
            }
        }

        private static Dictionary<uint, string> ParseForzaStringTable(byte[] bytes)
        {
            var values = new Dictionary<uint, string>();
            if (bytes == null || bytes.Length < 0x98)
                return values;

            var count = BitConverter.ToInt32(bytes, 0x94);
            if (count <= 0 || count > 200000)
                return values;

            var entriesOffset = 0x98;
            var stringDataOffset = entriesOffset + (count * 8);
            if (stringDataOffset <= entriesOffset || stringDataOffset >= bytes.Length)
                return values;

            for (var i = 0; i < count; i++)
            {
                var entryOffset = entriesOffset + (i * 8);
                if (entryOffset + 8 > bytes.Length)
                    break;

                var key = BitConverter.ToUInt32(bytes, entryOffset);
                var relativeOffset = BitConverter.ToUInt32(bytes, entryOffset + 4);
                var absoluteOffset = stringDataOffset + (int)relativeOffset;
                if (absoluteOffset < stringDataOffset || absoluteOffset >= bytes.Length)
                    continue;

                var end = absoluteOffset;
                while (end < bytes.Length && bytes[end] != 0)
                    end++;
                if (end <= absoluteOffset)
                    continue;

                var text = Encoding.UTF8.GetString(bytes, absoluteOffset, end - absoluteOffset).Trim();
                if (text.Length > 0 && !values.ContainsKey(key))
                    values.Add(key, text);
            }

            return values;
        }

        private static string TranslateCarText(string text, Dictionary<uint, string> lookup)
        {
            text = CleanCarText(text);
            if (lookup == null || lookup.Count == 0 || !text.StartsWith("_&", StringComparison.Ordinal))
                return text;

            ulong parsed;
            if (!ulong.TryParse(text.Substring(2), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
                return text;

            string translated;
            return lookup.TryGetValue((uint)(parsed & 0xFFFFFFFFUL), out translated) ? CleanCarText(translated) : text;
        }

        private void SetCarGridRows(DataGridView grid, List<CarTableRow> rows)
        {
            if (grid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetCarGridRows(grid, rows); }));
                return;
            }

            var wasSyncing = _syncingCarSelection;
            _syncingCarSelection = true;
            try
            {
                grid.Rows.Clear();
                foreach (var car in rows)
                {
                    var rowIndex = grid.Rows.Add(
                        _checkedCarIdsForAdd.Contains(car.CarId),
                        car.CarId.ToString(CultureInfo.InvariantCulture),
                        car.Year,
                        car.Make,
                        car.Model,
                        car.PerformanceIndex,
                        car.ClassId,
                        car.Copies,
                        car.State);
                    grid.Rows[rowIndex].Tag = car.CarId;
                }
                ClearCarGridSelection(grid);
            }
            finally
            {
                _syncingCarSelection = wasSyncing;
            }
        }

        private void SetCarTableRows(List<CarTableRow> owned, List<CarTableRow> addable)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetCarTableRows(owned, addable); }));
                return;
            }

            _ownedCarRows = owned ?? new List<CarTableRow>();
            _addableCarRows = addable ?? new List<CarTableRow>();
            _lastCarSelectionGrid = null;
            ApplyCarTableFilters();
        }

        private void TrackCarGridSelection(DataGridView activeGrid)
        {
            if (_syncingCarSelection || activeGrid == null || activeGrid.SelectedRows.Count == 0)
                return;

            _syncingCarSelection = true;
            try
            {
                _lastCarSelectionGrid = activeGrid;
                if (activeGrid == _ownedCarsGrid)
                    ClearCarGridSelection(_addableCarsGrid);
                else if (activeGrid == _addableCarsGrid)
                    ClearCarGridSelection(_ownedCarsGrid);
            }
            finally
            {
                _syncingCarSelection = false;
            }
        }

        private void ToggleVisibleCarChecks(DataGridView grid)
        {
            if (grid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ToggleVisibleCarChecks(grid); }));
                return;
            }

            var rows = grid.Rows.Cast<DataGridViewRow>()
                .Where(row => row != null && row.Visible && !row.IsNewRow)
                .ToList();
            var carIds = rows
                .Select(row =>
                {
                    int carId;
                    return TryGetCarIdFromGridRow(row, out carId) ? carId : 0;
                })
                .Where(carId => carId > 0)
                .Distinct()
                .ToList();
            if (carIds.Count == 0)
                return;

            var checkAll = carIds.Any(carId => !_checkedCarIdsForAdd.Contains(carId));
            var wasSyncing = _syncingCarSelection;
            _syncingCarSelection = true;
            try
            {
                foreach (var carId in carIds)
                {
                    if (checkAll)
                        _checkedCarIdsForAdd.Add(carId);
                    else
                        _checkedCarIdsForAdd.Remove(carId);
                }

                foreach (var row in rows)
                {
                    int carId;
                    if (TryGetCarIdFromGridRow(row, out carId))
                        row.Cells["Pick"].Value = _checkedCarIdsForAdd.Contains(carId);
                }
            }
            finally
            {
                _syncingCarSelection = wasSyncing;
            }

            SetCarStatus((checkAll ? "Checked " : "Unchecked ") +
                carIds.Count.ToString(CultureInfo.InvariantCulture) +
                " visible car(s). Selected " +
                _checkedCarIdsForAdd.Count.ToString(CultureInfo.InvariantCulture) + ".");
        }

        private static void ClearCarGridSelection(DataGridView grid)
        {
            if (grid == null)
                return;

            grid.ClearSelection();
            try
            {
                grid.CurrentCell = null;
            }
            catch
            {
            }
        }

        private void UpdateCarCheckState(DataGridViewRow row)
        {
            if (_syncingCarSelection || row == null)
                return;

            int carId;
            if (!TryGetCarIdFromGridRow(row, out carId))
                return;

            if (IsCarRowChecked(row))
                _checkedCarIdsForAdd.Add(carId);
            else
                _checkedCarIdsForAdd.Remove(carId);
        }

        private void ApplyCarTableFilters()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplyCarTableFilters);
                return;
            }

            var ownedFilter = _ownedCarSearch == null ? string.Empty : _ownedCarSearch.Text;
            var addableFilter = _addableCarSearch == null ? string.Empty : _addableCarSearch.Text;
            var owned = FilterCarRows(_ownedCarRows, ownedFilter);
            var addable = FilterCarRows(_addableCarRows, addableFilter);
            SetCarGridRows(_ownedCarsGrid, owned);
            SetCarGridRows(_addableCarsGrid, addable);
            UpdateCarTableTotalLabels(owned.Count, _ownedCarRows.Count, addable.Count, _addableCarRows.Count);
            SetCarStatus("Garage " + owned.Count.ToString(CultureInfo.InvariantCulture) + "/" + _ownedCarRows.Count.ToString(CultureInfo.InvariantCulture) +
                " | Addable " + addable.Count.ToString(CultureInfo.InvariantCulture) + "/" + _addableCarRows.Count.ToString(CultureInfo.InvariantCulture));
        }

        private void UpdateCarTableTotalLabels(int ownedVisible, int ownedTotal, int addableVisible, int addableTotal)
        {
            if (_ownedCarsTotal != null && !_ownedCarsTotal.IsDisposed)
                _ownedCarsTotal.Text = FormatCarTableTotal(ownedVisible, ownedTotal);
            if (_addableCarsTotal != null && !_addableCarsTotal.IsDisposed)
                _addableCarsTotal.Text = FormatCarTableTotal(addableVisible, addableTotal);
        }

        private static string FormatCarTableTotal(int visible, int total)
        {
            if (visible == total)
                return "Total " + total.ToString(CultureInfo.InvariantCulture);
            return "Total " + visible.ToString(CultureInfo.InvariantCulture) + " / " + total.ToString(CultureInfo.InvariantCulture);
        }

        private static List<CarTableRow> FilterCarRows(List<CarTableRow> rows, string filter)
        {
            if (rows == null)
                return new List<CarTableRow>();
            filter = (filter ?? string.Empty).Trim();
            if (filter.Length == 0)
                return rows.ToList();

            return rows.Where(row => row.Matches(filter)).ToList();
        }

        private List<CarTableSelection> GetSelectedCarsForAdd()
        {
            if (InvokeRequired)
                return (List<CarTableSelection>)Invoke(new Func<List<CarTableSelection>>(GetSelectedCarsForAdd));

            var checkedCars = GetCheckedCarSelectionsForAdd();
            if (checkedCars.Count > 0)
                return checkedCars;

            if (_lastCarSelectionGrid == _addableCarsGrid && _addableCarsGrid != null && _addableCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_addableCarsGrid, "Cars Not In Garage") };
            if (_lastCarSelectionGrid == _ownedCarsGrid && _ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_ownedCarsGrid, "Your Garage Cars") };
            if (_addableCarsGrid != null && _addableCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_addableCarsGrid, "Cars Not In Garage") };
            if (_ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_ownedCarsGrid, "Your Garage Cars") };

            throw new InvalidOperationException("Check one or more cars, or select a row in either table first.");
        }

        private List<CarTableSelection> GetSelectedOwnedCarsForRemove()
        {
            if (InvokeRequired)
                return (List<CarTableSelection>)Invoke(new Func<List<CarTableSelection>>(GetSelectedOwnedCarsForRemove));

            var selected = new List<CarTableSelection>();
            var seen = new HashSet<int>();
            foreach (var car in _ownedCarRows)
            {
                if (_checkedCarIdsForAdd.Contains(car.CarId) && seen.Add(car.CarId))
                    selected.Add(new CarTableSelection(car.CarId, FormatCarDisplayName(car)));
            }

            if (selected.Count > 0)
                return selected;

            if (_lastCarSelectionGrid == _ownedCarsGrid && _ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_ownedCarsGrid, "Your Garage Cars") };
            if (_ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return new List<CarTableSelection> { GetSelectedCarFromGrid(_ownedCarsGrid, "Your Garage Cars") };

            throw new InvalidOperationException("Check one or more cars in Your Garage Cars, or select a garage row first.");
        }

        private List<CarTableSelection> GetCheckedCarSelectionsForAdd()
        {
            var selected = new List<CarTableSelection>();
            var seen = new HashSet<int>();

            foreach (var car in _ownedCarRows.Concat(_addableCarRows))
            {
                if (_checkedCarIdsForAdd.Contains(car.CarId) && seen.Add(car.CarId))
                    selected.Add(new CarTableSelection(car.CarId, FormatCarDisplayName(car)));
            }

            foreach (var carId in _checkedCarIdsForAdd.OrderBy(id => id))
            {
                if (seen.Add(carId))
                    selected.Add(new CarTableSelection(carId, "CarId " + carId.ToString(CultureInfo.InvariantCulture)));
            }

            return selected;
        }

        private List<CarTableGrantRequest> PromptForSelectedCarGrantQuantities(List<CarTableSelection> cars)
        {
            if (InvokeRequired)
                return (List<CarTableGrantRequest>)Invoke(new Func<List<CarTableSelection>, List<CarTableGrantRequest>>(PromptForSelectedCarGrantQuantities), cars);

            var selected = (cars ?? new List<CarTableSelection>())
                .Where(car => car != null && car.CarId > 0)
                .GroupBy(car => car.CarId)
                .Select(group => group.First())
                .ToList();
            if (selected.Count == 0)
                throw new InvalidOperationException("Select a valid car first.");

            var result = new List<CarTableGrantRequest>();
            using (var dialog = new Form())
            {
                dialog.Text = "Add Selected Cars";
                dialog.StartPosition = FormStartPosition.CenterParent;
