                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(620, Math.Max(320, Math.Min(560, 182 + (selected.Count * 32))));

                var title = new Label();
                title.Text = "How many would you like to add?";
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = Color.Transparent;
                title.Location = new Point(18, 14);
                title.Size = new Size(584, 28);
                dialog.Controls.Add(title);

                var note = new Label();
                note.Text = "Review the selected cars, set a quantity for each one, then press Confirm.";
                note.Font = new Font("Segoe UI", 9F);
                note.ForeColor = TextMuted;
                note.BackColor = AppBackground;
                note.Location = new Point(18, 44);
                note.Size = new Size(584, 24);
                dialog.Controls.Add(note);

                var grid = new DataGridView();
                grid.Location = new Point(18, 76);
                grid.Size = new Size(584, Math.Max(112, dialog.ClientSize.Height - 136));
                grid.Anchor = AnchorStyles.Left | AnchorStyles.Top | AnchorStyles.Right | AnchorStyles.Bottom;
                grid.AllowUserToAddRows = false;
                grid.AllowUserToDeleteRows = false;
                grid.AllowUserToResizeRows = false;
                grid.RowHeadersVisible = false;
                grid.MultiSelect = false;
                grid.SelectionMode = DataGridViewSelectionMode.FullRowSelect;
                grid.BackgroundColor = Surface;
                grid.BorderStyle = BorderStyle.None;
                grid.GridColor = Border;
                grid.EnableHeadersVisualStyles = false;
                grid.ColumnHeadersDefaultCellStyle.BackColor = SurfaceAlt;
                grid.ColumnHeadersDefaultCellStyle.ForeColor = TextPrimary;
                grid.ColumnHeadersDefaultCellStyle.Font = new Font("Segoe UI Semibold", 9F);
                grid.DefaultCellStyle.BackColor = Surface;
                grid.DefaultCellStyle.ForeColor = TextPrimary;
                grid.DefaultCellStyle.SelectionBackColor = AccentBlueSoft;
                grid.DefaultCellStyle.SelectionForeColor = TextPrimary;
                grid.AutoSizeRowsMode = DataGridViewAutoSizeRowsMode.None;

                var idColumn = new DataGridViewTextBoxColumn();
                idColumn.Name = "CarId";
                idColumn.HeaderText = "ID";
                idColumn.Width = 74;
                idColumn.ReadOnly = true;
                grid.Columns.Add(idColumn);

                var carColumn = new DataGridViewTextBoxColumn();
                carColumn.Name = "Car";
                carColumn.HeaderText = "Selected Car";
                carColumn.Width = 394;
                carColumn.ReadOnly = true;
                grid.Columns.Add(carColumn);

                var quantityColumn = new DataGridViewTextBoxColumn();
                quantityColumn.Name = "Quantity";
                quantityColumn.HeaderText = "Quantity";
                quantityColumn.Width = 90;
                quantityColumn.ReadOnly = false;
                grid.Columns.Add(quantityColumn);

                foreach (var car in selected)
                    grid.Rows.Add(car.CarId.ToString(CultureInfo.InvariantCulture), car.DisplayName, "1");

                dialog.Controls.Add(grid);

                var cancel = MakeButton("Cancel", 386, dialog.ClientSize.Height - 48, 100, 32);
                cancel.Anchor = AnchorStyles.Right | AnchorStyles.Bottom;
                cancel.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(cancel);

                var confirm = MakeButton("Confirm", 502, dialog.ClientSize.Height - 48, 100, 32);
                confirm.Anchor = AnchorStyles.Right | AnchorStyles.Bottom;
                MakeAccentButton(confirm, AccentGreen);
                confirm.Click += delegate
                {
                    grid.EndEdit();
                    var parsed = new List<CarTableGrantRequest>();
                    foreach (DataGridViewRow row in grid.Rows)
                    {
                        if (row.IsNewRow)
                            continue;

                        int carId;
                        if (!int.TryParse(Convert.ToString(row.Cells["CarId"].Value, CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out carId))
                            continue;

                        int quantity;
                        if (!int.TryParse(Convert.ToString(row.Cells["Quantity"].Value, CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out quantity) ||
                            quantity < 1 || quantity > 999)
                        {
                            ShowTranslatedMessageBox(dialog, "Quantity must be a whole number from 1 to 999.", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                            return;
                        }

                        var displayName = Convert.ToString(row.Cells["Car"].Value, CultureInfo.InvariantCulture);
                        parsed.Add(new CarTableGrantRequest(carId, displayName, quantity));
                    }

                    result = parsed;
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(confirm);
                dialog.AcceptButton = confirm;
                dialog.CancelButton = cancel;

                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK ? result : new List<CarTableGrantRequest>();
            }
        }

        private int GetSelectedAddableCarId()
        {
            if (InvokeRequired)
                return (int)Invoke(new Func<int>(GetSelectedAddableCarId));
            if (_addableCarsGrid == null || _addableCarsGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a car in Cars Not In Garage first.");

            int carId;
            if (TryGetCarIdFromGridRow(_addableCarsGrid.SelectedRows[0], out carId))
                return carId;
            throw new InvalidOperationException("Could not read the selected car id.");
        }

        private int GetSelectedCarIdForAdd()
        {
            if (InvokeRequired)
                return (int)Invoke(new Func<int>(GetSelectedCarIdForAdd));

            if (_lastCarSelectionGrid == _addableCarsGrid && _addableCarsGrid != null && _addableCarsGrid.SelectedRows.Count > 0)
                return GetSelectedCarIdFromGrid(_addableCarsGrid, "Cars Not In Garage");
            if (_lastCarSelectionGrid == _ownedCarsGrid && _ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return GetSelectedCarIdFromGrid(_ownedCarsGrid, "Your Garage Cars");
            if (_addableCarsGrid != null && _addableCarsGrid.SelectedRows.Count > 0)
                return GetSelectedCarIdFromGrid(_addableCarsGrid, "Cars Not In Garage");
            if (_ownedCarsGrid != null && _ownedCarsGrid.SelectedRows.Count > 0)
                return GetSelectedCarIdFromGrid(_ownedCarsGrid, "Your Garage Cars");

            throw new InvalidOperationException("Select a car in either table first.");
        }

        private int GetSelectedOwnedCarId()
        {
            if (InvokeRequired)
                return (int)Invoke(new Func<int>(GetSelectedOwnedCarId));
            if (_ownedCarsGrid == null || _ownedCarsGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a car in Your Garage Cars first.");

            return GetSelectedCarIdFromGrid(_ownedCarsGrid, "Your Garage Cars");
