        private static int GetSelectedCarIdFromGrid(DataGridView grid, string tableName)
        {
            return GetSelectedCarFromGrid(grid, tableName).CarId;
        }

        private static CarTableSelection GetSelectedCarFromGrid(DataGridView grid, string tableName)
        {
            if (grid == null || grid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a car in " + tableName + " first.");

            var row = grid.SelectedRows[0];
            int carId;
            if (!TryGetCarIdFromGridRow(row, out carId))
                throw new InvalidOperationException("Could not read the selected car id from " + tableName + ".");

            return new CarTableSelection(carId, FormatCarDisplayName(
                carId,
                GetGridCellText(row, "Year"),
                GetGridCellText(row, "Make"),
                GetGridCellText(row, "Model")));
        }

        private static bool TryGetCarIdFromGridRow(DataGridViewRow row, out int carId)
        {
            carId = 0;
            if (row == null)
                return false;

            var tag = row.Tag;
            if (tag is int)
            {
                carId = (int)tag;
                return true;
            }

            int parsed;
            if (int.TryParse(GetGridCellText(row, "CarId"), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
            {
                carId = parsed;
                return true;
            }

            return false;
        }

        private static bool IsCarRowChecked(DataGridViewRow row)
        {
            var value = row == null ? null : row.Cells["Pick"].Value;
            return value is bool && (bool)value;
        }

        private static string GetGridCellText(DataGridViewRow row, string columnName)
        {
            if (row == null || row.DataGridView == null || !row.DataGridView.Columns.Contains(columnName))
                return string.Empty;

            var value = row.Cells[columnName].Value;
            return value == null ? string.Empty : Convert.ToString(value, CultureInfo.InvariantCulture);
        }

        private static string FormatCarDisplayName(CarTableRow car)
        {
            return car == null ? string.Empty : FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model);
        }

        private static string FormatCarDisplayName(int carId, string year, string make, string model)
        {
            var parts = new[] { year, make, model }
                .Where(part => !string.IsNullOrWhiteSpace(part))
                .Select(part => part.Trim())
                .ToArray();
            var name = string.Join(" ", parts);
            return name.Length == 0 ? "CarId " + carId.ToString(CultureInfo.InvariantCulture) : name;
        }

        private void AddSelectedCars(List<CarTableGrantRequest> cars)
        {
            if (cars == null || cars.Count == 0)
                throw new InvalidOperationException("Select a valid car first.");

            var selected = cars
                .Where(car => car != null && car.CarId > 0)
                .GroupBy(car => car.CarId)
                .Select(group =>
                {
                    var first = group.First();
                    var quantity = group.Sum(item => Math.Max(1, item.Quantity));
                    return new CarTableGrantRequest(first.CarId, first.DisplayName, Math.Min(999, quantity));
                })
                .ToList();
            if (selected.Count == 0)
                throw new InvalidOperationException("Select a valid car first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");

            foreach (var car in selected)
            {
                var exists = db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE Id = " + car.CarId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                if (exists <= 0)
                    throw new InvalidOperationException("Selected car was not found in Data_Car: " + car.DisplayName + ".");
            }

            Log("Preparing Autoshow visibility before selected car add.");
            ApplyAutoshowUnlock(db);
            var grants = ApplySelectedCarsAddAllGrantBatch(db, selected);
            foreach (var car in selected)
            {
                SelectedCarGrantResult grant;
                if (!grants.TryGetValue(car.CarId, out grant))
                    throw new InvalidOperationException("Selected car grant failed verification: missing result for " + car.DisplayName + ".");

                Log("Selected car " + car.CarId.ToString(CultureInfo.InvariantCulture) + " grant queued x" + car.Quantity.ToString(CultureInfo.InvariantCulture) +
                    ". Garage copies before grant: " + grant.OwnedBefore.ToString(CultureInfo.InvariantCulture) +
                    "; free grant count before: " + grant.FreeCountBefore.ToString(CultureInfo.InvariantCulture) +
                    "; after: " + grant.FreeCountAfter.ToString(CultureInfo.InvariantCulture) +
                    "; offer quantity: " + grant.OfferQuantityAfter.ToString(CultureInfo.InvariantCulture) +
                    "; auto-redeem mappings: " + grant.AutoRedeemMappings.ToString(CultureInfo.InvariantCulture) + ".");
            }

            ClearCheckedCarsForAdd();
            LoadCarTablesFromDatabase(db);
            ShowInfo(BuildSelectedCarsAddedMessage(selected));
        }

        private void SaveAutoshowCarList()
        {
            try
            {
                var cars = GetSelectedCarsForAdd();
                if (cars.Count == 0)
                    throw new InvalidOperationException("Check or select at least one car first.");

                var listDir = Path.Combine(_resultsDir, "car_lists");
                Directory.CreateDirectory(listDir);
                using (var dialog = new SaveFileDialog())
                {
                    dialog.Title = "Save Autoshow car list";
                    dialog.InitialDirectory = listDir;
                    dialog.Filter = "Luna car list (*.txt)|*.txt|All files (*.*)|*.*";
                    dialog.FileName = "autoshow_list_" + DateTime.Now.ToString("yyyyMMdd_HHmmss") + ".txt";
                    PrepareDialogForLanguage(dialog);
                if (dialog.ShowDialog(this) != DialogResult.OK)
                        return;

                    var lines = new List<string>();
                    lines.Add("# Forza Horizon 6 Luna Autoshow car list");
                    lines.Add("# CarId|Name");
                    foreach (var car in cars.OrderBy(car => car.CarId))
                        lines.Add(car.CarId.ToString(CultureInfo.InvariantCulture) + "|" + (car.DisplayName ?? string.Empty).Replace(Environment.NewLine, " "));
                    File.WriteAllLines(dialog.FileName, lines, Encoding.UTF8);
                    Log("Autoshow custom list saved: " + dialog.FileName + " (" + cars.Count.ToString(CultureInfo.InvariantCulture) + " car(s)).");
                    SetCarStatus("List saved");
                }
            }
            catch (Exception ex)
            {
                Log("Autoshow list save failed: " + ex.Message);
                ShowInfo(ex.Message);
            }
        }

        private void LoadAutoshowCarList()
        {
            try
            {
                var listDir = Path.Combine(_resultsDir, "car_lists");
                Directory.CreateDirectory(listDir);
                using (var dialog = new OpenFileDialog())
                {
                    dialog.Title = "Load Autoshow car list";
                    dialog.InitialDirectory = listDir;
                    dialog.Filter = "Luna car list (*.txt)|*.txt|All files (*.*)|*.*";
                    PrepareDialogForLanguage(dialog);
                if (dialog.ShowDialog(this) != DialogResult.OK)
                        return;

                    var ids = new HashSet<int>();
                    foreach (var line in File.ReadAllLines(dialog.FileName, Encoding.UTF8))
                    {
                        var trimmed = (line ?? string.Empty).Trim();
                        if (trimmed.Length == 0 || trimmed.StartsWith("#", StringComparison.Ordinal))
                            continue;
                        var first = trimmed.Split(new[] { '|', ',', '\t', ';' }, 2)[0].Trim();
                        int carId;
                        if (int.TryParse(first, NumberStyles.Integer, CultureInfo.InvariantCulture, out carId) && carId > 0)
                            ids.Add(carId);
                    }

                    if (ids.Count == 0)
                        throw new InvalidOperationException("That list did not contain any car IDs.");

                    foreach (var id in ids)
                        _checkedCarIdsForAdd.Add(id);

                    ApplyCarTableFilters();
                    Log("Autoshow custom list loaded: " + Path.GetFileName(dialog.FileName) + " (" + ids.Count.ToString(CultureInfo.InvariantCulture) + " car(s) checked).");
                    SetCarStatus("List loaded");
                }
            }
            catch (Exception ex)
            {
                Log("Autoshow list load failed: " + ex.Message);
                ShowInfo(ex.Message);
            }
        }

        private void ClearCheckedCarsForAdd()
        {
            if (InvokeRequired)
            {
                Invoke((Action)ClearCheckedCarsForAdd);
                return;
            }

            _checkedCarIdsForAdd.Clear();
        }

        private static string BuildSelectedCarsAddedMessage(List<CarTableGrantRequest> cars)
        {
            if (cars == null || cars.Count == 0)
                return "Selected car has been added! Enjoy!";

            if (cars.Count == 1)
                return "Selected car: " + cars[0].DisplayName + FormatQuantitySuffix(cars[0].Quantity) + " has been added! Enjoy!";

            var lines = new List<string>();
            lines.Add("Selected cars have been added! Enjoy!");
            lines.Add("");
            foreach (var car in cars.Take(9))
                lines.Add("- " + car.DisplayName + FormatQuantitySuffix(car.Quantity));
            if (cars.Count > 9)
                lines.Add("+ " + (cars.Count - 9).ToString(CultureInfo.InvariantCulture) + " more");
            return string.Join(Environment.NewLine, lines.ToArray());
        }

        private static string FormatQuantitySuffix(int quantity)
        {
            return quantity <= 1 ? string.Empty : " x" + quantity.ToString(CultureInfo.InvariantCulture);
        }

        private void RemoveSelectedCar(int carId)
        {
            if (carId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");
            RemoveSelectedCars(new List<CarTableSelection> { new CarTableSelection(carId, "CarId " + carId.ToString(CultureInfo.InvariantCulture)) });
        }

        private void RemoveSelectedCars(List<CarTableSelection> cars)
        {
            var selected = (cars ?? new List<CarTableSelection>())
                .Where(car => car != null && car.CarId > 0)
                .GroupBy(car => car.CarId)
                .Select(group => group.First())
                .ToList();
            if (selected.Count == 0)
                throw new InvalidOperationException("Select a valid garage car first.");

            var db = RequireDatabase();
            var garageTable = ResolveActiveGarageTable(db);
            var garageSql = EscapeIdentifierForSql(garageTable);
            var freeCarsTable = ResolveOptionalActiveFreeCarsTable(db);
            var freeCarsSql = string.IsNullOrEmpty(freeCarsTable) ? string.Empty : EscapeIdentifierForSql(freeCarsTable);
            var carIdsSql = string.Join(",", selected.Select(car => car.CarId.ToString(CultureInfo.InvariantCulture)).ToArray());

            var before = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId IN (" + carIdsSql + ")") ?? 0;
            if (before <= 0)
                throw new InvalidOperationException("Selected car is not currently in the garage table.");

            var rows = QueryGarageRemovalRows(db, garageTable, "g.CarId IN (" + carIdsSql + ")");
            foreach (var group in rows.GroupBy(row => row.CarId))
            {
                var count = group.Count();
                foreach (var row in group)
                    row.Copies = count;
            }
            var planned = rows
                .OrderBy(row => row.DisplayName, StringComparer.OrdinalIgnoreCase)
                .ThenBy(row => row.CarId)
                .ThenBy(row => row.RowId)
                .ToList();
            var approved = PromptForGarageRemovalCandidates(
                planned,
                selected.Count == 1 ? "Remove Selected Car" : "Remove Selected Cars",
                "Review the garage rows Luna will remove. Uncheck any car copies you want to keep.");
            if (approved.Count == 0)
            {
                Log("Remove Selected canceled before deleting any garage rows.");
                return;
            }

            db.Execute("CREATE TABLE IF NOT EXISTS _backup_Autoshow_RemoveSelectedCars AS SELECT rowid AS _rowid_, * FROM " + garageSql + ";");
            DeleteGarageRowsByRowId(db, garageTable, approved);

            var fullyRemovedIds = new List<int>();
            foreach (var carId in approved.Select(row => row.CarId).Distinct())
            {
                var afterForCar = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                if (afterForCar <= 0)
                    fullyRemovedIds.Add(carId);
            }

            if (fullyRemovedIds.Count > 0)
            {
                var removedIdsSql = string.Join(",", fullyRemovedIds.Select(id => id.ToString(CultureInfo.InvariantCulture)).ToArray());
                if (!string.IsNullOrEmpty(freeCarsTable))
                    ExecuteAutoshowSql(db, "DELETE FROM " + freeCarsSql + " WHERE CarId IN (" + removedIdsSql + ");");
                if (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "ContentId") && db.ColumnExists("ContentOffersMapping", "ContentType"))
                {
                    var removedContentIdsSql = db.TableExists("Data_Car")
                        ? BuildDataCarContentIdSubquery(db, "Data_Car.Id IN (" + removedIdsSql + ")")
                        : removedIdsSql;
                    var assignments = new List<string>();
                    if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                        assignments.Add("IsAutoRedeem = 0");
                    if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                        assignments.Add("Quantity = 0");
                    if (assignments.Count > 0)
                        ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET " + string.Join(", ", assignments.ToArray()) + " WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + removedContentIdsSql + ");");
                }
            }

            var after = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId IN (" + carIdsSql + ")") ?? 0;
            Log("Remove Selected removed " + approved.Count.ToString(CultureInfo.InvariantCulture) + " garage row(s). Copies before: " + before.ToString(CultureInfo.InvariantCulture) + "; after: " + after.ToString(CultureInfo.InvariantCulture) + ".");
            ClearCheckedCarsForAdd();
            LoadCarTablesFromDatabase(db);
            ShowInfo("Selected cars removed." + Environment.NewLine + Environment.NewLine +
                "Removed " + approved.Count.ToString(CultureInfo.InvariantCulture) + " garage row(s)." + Environment.NewLine +
                "Close and reopen the Garage screen so FH6 refreshes the list.");
        }

        private void LoadRarityGarage()
        {
            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var rows = QueryRarityGarageRows(db);
            SetRarityRows(rows);
            SetRarityStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture));
            Log("Car Rarity Editor loaded " + rows.Count.ToString(CultureInfo.InvariantCulture) + " owned car row(s).");
        }

        private List<RarityCarRow> QueryRarityGarageRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();

            var hasBaseRarity = db.ColumnExists("Data_Car", "BaseRarity");
            var hasCarRarityTable = db.TableExists("CarRarities") &&
                db.ColumnExists("CarRarities", "CarID") &&
                db.ColumnExists("CarRarities", "Rarity");
            var baseRarityExpr = hasBaseRarity ? "COALESCE(MAX(data.BaseRarity), 0)" : "''";
            var rarityExpr = hasCarRarityTable
                ? "COALESCE((SELECT CAST(MAX(rar.Rarity) AS TEXT) FROM CarRarities rar WHERE rar.CarID = garage.CarId), '')"
                : "''";

            var sql =
                "SELECT garage.CarId AS CarId, " +
                "COALESCE(MAX(data.Year), '') AS Year, " +
                "COALESCE(MAX(data.MakeName), '') AS Make, " +
                "COALESCE(MAX(data.DisplayName), MAX(data.ModelShort), MAX(data.MediaName), '') AS Model, " +
                "COALESCE(MAX(garage.PerformanceIndex), MAX(data.PerformanceIndex), 0) AS PI, " +
                "COALESCE(MAX(garage.ClassID), MAX(data.ClassID), 0) AS ClassID, " +
                "COUNT(*) AS Copies, " +
                baseRarityExpr + " AS BaseRarity, " +
                rarityExpr + " AS Rarity " +
                "FROM Profile0_Career_Garage garage " +
                "LEFT JOIN Data_Car data ON data.Id = garage.CarId " +
                "WHERE garage.CarId IS NOT NULL " +
                "GROUP BY garage.CarId " +
                "ORDER BY CAST(COALESCE(MAX(data.Year), 0) AS INTEGER), Make, Model, garage.CarId;";

            var result = db.Query(sql);
            var rows = new List<RarityCarRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 9)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;

                rows.Add(new RarityCarRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    ToDisplayString(row[5]),
                    ToDisplayString(row[6]),
                    FormatRarityBand(row[7]),
                    FormatRarityFlag(row[8])));
            }

            return rows;
        }

        private void SetRarityRows(List<RarityCarRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetRarityRows(rows); }));
                return;
            }

            _rarityRows = rows ?? new List<RarityCarRow>();
            ApplyRarityFilter();
        }

        private void ApplyRarityFilter()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplyRarityFilter);
                return;
            }

            var filter = _raritySearch == null ? string.Empty : _raritySearch.Text;
            var rows = FilterRarityRows(_rarityRows, filter);
            SetRarityGridRows(rows);
            SetRarityStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture) + "/" + _rarityRows.Count.ToString(CultureInfo.InvariantCulture));
        }

        private static List<RarityCarRow> FilterRarityRows(List<RarityCarRow> rows, string filter)
        {
            if (rows == null)
                return new List<RarityCarRow>();
            filter = (filter ?? string.Empty).Trim();
            if (filter.Length == 0)
                return rows.ToList();

            return rows.Where(row => row.Matches(filter)).ToList();
        }

        private void SetRarityGridRows(List<RarityCarRow> rows)
        {
            if (_rarityGrid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetRarityGridRows(rows); }));
                return;
            }

            _rarityGrid.Rows.Clear();
            foreach (var car in rows)
            {
                var rowIndex = _rarityGrid.Rows.Add(
                    car.CarId.ToString(CultureInfo.InvariantCulture),
                    car.Year,
                    car.Make,
                    car.Model,
                    car.PerformanceIndex,
                    car.ClassId,
                    car.Copies,
                    car.BaseRarity,
                    car.Rarity);
                _rarityGrid.Rows[rowIndex].Tag = car.CarId;
            }
            ClearCarGridSelection(_rarityGrid);
            UpdateRaritySelectionLabel();
        }

        private RarityCarRow GetSelectedRarityCar()
        {
            if (InvokeRequired)
                return (RarityCarRow)Invoke(new Func<RarityCarRow>(GetSelectedRarityCar));
            if (_rarityGrid == null || _rarityGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a garage car in the Car Rarity Editor first.");

            int carId;
            if (!TryGetCarIdFromGridRow(_rarityGrid.SelectedRows[0], out carId))
                throw new InvalidOperationException("Could not read the selected car id.");

            var row = _rarityRows.FirstOrDefault(car => car.CarId == carId);
            return row ?? new RarityCarRow(
                carId,
                GetGridCellText(_rarityGrid.SelectedRows[0], "Year"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "Make"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "Model"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "PI"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "Class"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "Copies"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "BaseRarity"),
                GetGridCellText(_rarityGrid.SelectedRows[0], "Rarity"));
        }

        private RarityOption GetSelectedRarityOption()
        {
            if (InvokeRequired)
                return (RarityOption)Invoke(new Func<RarityOption>(GetSelectedRarityOption));

            var selected = _rarityCombo == null ? null : _rarityCombo.SelectedItem as RarityOption;
            if (selected != null && string.Equals(_rarityCombo.Text, selected.ToString(), StringComparison.Ordinal))
                return selected;

            var text = _rarityCombo == null ? string.Empty : (_rarityCombo.Text ?? string.Empty).Trim();
            double value;
            if (!double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                throw new InvalidOperationException("Select a rarity preset, or type a number from 0 to 10.");
            if (double.IsNaN(value) || double.IsInfinity(value) || value < 0.0 || value > 10.0)
                throw new InvalidOperationException("Rarity must be between 0 and 10.");

            var rarityInt = Math.Max(0, Math.Min(10, (int)Math.Round(value, MidpointRounding.AwayFromZero)));
            return new RarityOption(FormatRarityBandName(value) + " custom (" + value.ToString("0.###", CultureInfo.InvariantCulture) + ")", value, rarityInt);
        }

        private void UpdateRaritySelectionLabel()
        {
            if (_raritySelected == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateRaritySelectionLabel);
                return;
            }

            if (_rarityGrid == null || _rarityGrid.SelectedRows.Count == 0)
            {
                _raritySelected.Text = "Select an owned car after loading the garage.";
                return;
            }

            var row = _rarityGrid.SelectedRows[0];
            var name = FormatCarDisplayName(
                ToInt(GetGridCellText(row, "CarId")),
                GetGridCellText(row, "Year"),
                GetGridCellText(row, "Make"),
                GetGridCellText(row, "Model"));
            _raritySelected.Text = "Selected: " + name + " | Current " + GetGridCellText(row, "BaseRarity") + " | Flag " + GetGridCellText(row, "Rarity");
        }

        private void ApplySelectedCarRarity(RarityCarRow car, RarityOption rarity)
        {
            if (car == null || car.CarId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");
            if (rarity == null)
                throw new InvalidOperationException("Select a rarity first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");

            var carIdSql = car.CarId.ToString(CultureInfo.InvariantCulture);
            var hasBaseRarity = db.ColumnExists("Data_Car", "BaseRarity");
            var hasCarRarityTable = db.TableExists("CarRarities") &&
                db.ColumnExists("CarRarities", "CarID") &&
                db.ColumnExists("CarRarities", "Rarity");
            if (!hasBaseRarity && !hasCarRarityTable)
                throw new InvalidOperationException("This FH6 database did not expose Data_Car.BaseRarity or CarRarities.Rarity.");

            var owned = db.TableExists("Profile0_Career_Garage") && db.ColumnExists("Profile0_Career_Garage", "CarId")
                ? (db.QueryScalarLong("SELECT count(*) FROM Profile0_Career_Garage WHERE CarId = " + carIdSql) ?? 0)
                : 0;
            if (owned <= 0)
                throw new InvalidOperationException("Selected car is not currently in the garage table.");

            if (hasBaseRarity)
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CarRarity_DataCar AS SELECT Id, BaseRarity FROM Data_Car;");
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET BaseRarity = " + rarity.BaseSql + " WHERE Id = " + carIdSql + ";");
            }

            if (hasCarRarityTable)
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CarRarity_CarRarities AS SELECT * FROM CarRarities;");
                ExecuteAutoshowSql(db, "INSERT INTO CarRarities (CarID, Rarity) SELECT " + carIdSql + ", " + rarity.RaritySql + " WHERE NOT EXISTS (SELECT 1 FROM CarRarities WHERE CarID = " + carIdSql + ");");
                ExecuteAutoshowSql(db, "UPDATE CarRarities SET Rarity = " + rarity.RaritySql + " WHERE CarID = " + carIdSql + ";");
            }

            var baseAfter = hasBaseRarity ? QueryScalarText(db, "SELECT CAST(BaseRarity AS TEXT) FROM Data_Car WHERE Id = " + carIdSql + " LIMIT 1") : "";
            var rarityAfter = hasCarRarityTable ? QueryScalarText(db, "SELECT CAST(MAX(Rarity) AS TEXT) FROM CarRarities WHERE CarID = " + carIdSql) : "";
            Log("Car rarity applied to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                ". Requested BaseRarity=" + rarity.BaseSql +
                ", Rarity=" + rarity.RaritySql +
                "; live BaseRarity=" + (baseAfter ?? "") +
                ", live Rarity=" + (rarityAfter ?? "") + ".");

            LoadRarityGarage();
            ShowInfo("Car rarity updated." + Environment.NewLine + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine +
                "New rarity: " + rarity.Label + Environment.NewLine + Environment.NewLine +
                "Reopen Garage or switch screens if FH6 cached the car list.");
        }

        private void LoadCarEditorGarage()
        {
            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var rows = QueryCarEditorRows(db);
            SetCarEditorRows(rows);
            SetCarEditorStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture));
            Log("Car Class Panel loaded " + rows.Count.ToString(CultureInfo.InvariantCulture) + " owned car row(s).");
        }

        private List<CarEditorRow> QueryCarEditorRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();

            var selectFields = new List<string>();
            selectFields.Add("garage.CarId AS CarId");
            selectFields.Add("COALESCE(MAX(data.Year), '') AS Year");
            selectFields.Add("COALESCE(MAX(data.MakeName), '') AS Make");
            selectFields.Add("COALESCE(MAX(data.DisplayName), MAX(data.ModelShort), MAX(data.MediaName), '') AS Model");
            selectFields.Add("COUNT(*) AS Copies");
            selectFields.Add(BuildCarEditorSelectExpression(db, CarEditorFields.First(field => field.Key == "performance_index")) + " AS PerformanceIndex");
            selectFields.Add(BuildCarEditorClassExpression(db) + " AS ClassId");
            selectFields.Add(BuildCarEditorSelectExpression(db, CarEditorFields.First(field => field.Key == "top_speed")) + " AS TopSpeed");
            selectFields.Add(BuildCarEditorSelectExpression(db, CarEditorFields.First(field => field.Key == "base_cost")) + " AS BaseCost");
            foreach (var field in CarEditorFields)
                selectFields.Add(BuildCarEditorSelectExpression(db, field) + " AS " + EscapeIdentifierForSql(field.Key));
            selectFields.Add(BuildCarEditorClassExpression(db) + " AS EditorClassId");
            selectFields.Add(BuildCarEditorDriveTypeExpression(db) + " AS DriveTypeId");
            selectFields.Add(db.ColumnExists("Data_Car", "EngineConfigID") ? "COALESCE(MAX(data.[EngineConfigID]), 0) AS EngineConfigId" : "0 AS EngineConfigId");
            selectFields.Add(BuildCarEditorAspirationExpression(db) + " AS AspirationTypeId");

            var sql =
                "SELECT " + string.Join(", ", selectFields.ToArray()) + " " +
                "FROM Profile0_Career_Garage garage " +
                "LEFT JOIN Data_Car data ON data.Id = garage.CarId " +
                "WHERE garage.CarId IS NOT NULL " +
                "GROUP BY garage.CarId " +
                "ORDER BY CAST(COALESCE(MAX(data.Year), 0) AS INTEGER), Make, Model, garage.CarId;";

            var result = db.Query(sql);
            var rows = new List<CarEditorRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 9 + CarEditorFields.Length + 4)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;

                var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                var index = 9;
                foreach (var field in CarEditorFields)
                    values[field.Key] = FormatCarNumber(row[index++]);

                rows.Add(new CarEditorRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    ToDisplayString(row[4]),
                    FormatCarNumber(row[5]),
                    ToInt(row[6]),
                    FormatCarNumber(row[7]),
                    FormatWholeNumber(row[8]),
                    values,
                    ToInt(row[index++]),
                    ToInt(row[index++]),
                    ToInt(row[index++]),
                    ToInt(row[index++])));
            }

            return rows;
        }

        private static string BuildCarEditorSelectExpression(RemoteDatabase db, CarEditorField field)
        {
            var expressions = new List<string>();
            foreach (var column in field.GarageColumns)
            {
                if (db.ColumnExists("Profile0_Career_Garage", column))
                    expressions.Add(BuildCarEditorColumnExpression("garage", column, field.ZeroMeansMissing));
            }
            foreach (var column in field.DataColumns)
            {
                if (db.ColumnExists("Data_Car", column))
                    expressions.Add(BuildCarEditorColumnExpression("data", column, field.ZeroMeansMissing));
            }

            return expressions.Count == 0 ? "''" : "COALESCE(" + string.Join(", ", expressions.ToArray()) + ", '')";
        }

        private static string BuildCarEditorColumnExpression(string alias, string column, bool zeroMeansMissing)
        {
            var expression = "MAX(" + alias + "." + EscapeIdentifierForSql(column) + ")";
            return zeroMeansMissing ? "CASE WHEN ABS(" + expression + ") > 0.01 THEN " + expression + " ELSE NULL END" : expression;
        }

        private static string BuildCarEditorClassExpression(RemoteDatabase db)
        {
            var expressions = new List<string>();
            if (db.ColumnExists("Profile0_Career_Garage", "ClassID"))
                expressions.Add("MAX(garage.[ClassID])");
            if (db.ColumnExists("Data_Car", "ClassID"))
                expressions.Add("MAX(data.[ClassID])");
            return expressions.Count == 0 ? "0" : "COALESCE(" + string.Join(", ", expressions.ToArray()) + ", 0)";
        }

        private static string BuildCarEditorAspirationExpression(RemoteDatabase db)
        {
            var expressions = new List<string>();
            if (db.ColumnExists("Profile0_Career_Garage", "AspirationTypeId"))
                expressions.Add("NULLIF(MAX(garage.[AspirationTypeId]), 0)");
            if (db.ColumnExists("Data_Car", "AspirationTypeId"))
                expressions.Add("MAX(data.[AspirationTypeId])");
            return expressions.Count == 0 ? "0" : "COALESCE(" + string.Join(", ", expressions.ToArray()) + ", 0)";
        }

        private static string BuildCarEditorDriveTypeExpression(RemoteDatabase db)
        {
            var expressions = new List<string>();
            if (db.ColumnExists("Profile0_Career_Garage", "Drivetrain") &&
                db.TableExists("List_UpgradeDrivetrain") &&
                db.ColumnExists("List_UpgradeDrivetrain", "Id") &&
                db.ColumnExists("List_UpgradeDrivetrain", "PowertrainId") &&
                db.TableExists("Powertrains") &&
                db.ColumnExists("Powertrains", "Id") &&
                db.ColumnExists("Powertrains", "DrivetrainId"))
            {
                expressions.Add("(SELECT p.DrivetrainId FROM Profile0_Career_Garage g2 JOIN List_UpgradeDrivetrain ud ON ud.Id = g2.[Drivetrain] JOIN Powertrains p ON p.Id = ud.PowertrainId WHERE g2.CarId = garage.CarId AND g2.[Drivetrain] IS NOT NULL ORDER BY g2.rowid LIMIT 1)");
            }
            if (db.ColumnExists("Profile0_Career_Garage", "Drivetrain") &&
                db.TableExists("List_UpgradeDrivetrain") &&
                db.ColumnExists("List_UpgradeDrivetrain", "Id") &&
                db.ColumnExists("List_UpgradeDrivetrain", "DrivetrainID") &&
                db.TableExists("Data_Drivetrain") &&
                db.ColumnExists("Data_Drivetrain", "DrivetrainID") &&
                db.ColumnExists("Data_Drivetrain", "DrivetypeID"))
            {
                expressions.Add("(SELECT drive.DrivetypeID FROM Profile0_Career_Garage g2 JOIN List_UpgradeDrivetrain ud ON ud.Id = g2.[Drivetrain] JOIN Data_Drivetrain drive ON drive.DrivetrainID = ud.DrivetrainID WHERE g2.CarId = garage.CarId AND g2.[Drivetrain] IS NOT NULL ORDER BY g2.rowid LIMIT 1)");
            }
            if (db.ColumnExists("Data_Car", "DriveTypeID"))
                expressions.Add("MAX(data.[DriveTypeID])");
            return expressions.Count == 0 ? "0" : "COALESCE(" + string.Join(", ", expressions.ToArray()) + ", 0)";
        }

        private void SetCarEditorRows(List<CarEditorRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetCarEditorRows(rows); }));
                return;
            }

            _carEditorRows = rows ?? new List<CarEditorRow>();
            ApplyCarEditorFilter();
        }

        private void ApplyCarEditorFilter()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplyCarEditorFilter);
                return;
            }

            var filter = _carEditorSearch == null ? string.Empty : _carEditorSearch.Text;
            var rows = FilterCarEditorRows(_carEditorRows, filter);
            SetCarEditorGridRows(rows);
            SetCarEditorStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture) + "/" + _carEditorRows.Count.ToString(CultureInfo.InvariantCulture));
        }

        private static List<CarEditorRow> FilterCarEditorRows(List<CarEditorRow> rows, string filter)
        {
            if (rows == null)
                return new List<CarEditorRow>();
            filter = (filter ?? string.Empty).Trim();
            if (filter.Length == 0)
                return rows.ToList();
            return rows.Where(row => row.Matches(filter)).ToList();
        }

        private void SetCarEditorGridRows(List<CarEditorRow> rows)
        {
            if (_carEditorGrid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetCarEditorGridRows(rows); }));
                return;
            }

            _carEditorGrid.Rows.Clear();
            foreach (var car in rows)
            {
                var rowIndex = _carEditorGrid.Rows.Add(
                    car.CarId.ToString(CultureInfo.InvariantCulture),
                    car.Year,
                    car.Make,
                    car.Model,
                    car.PerformanceIndex,
                    FormatCarClassId(car.ClassId),
                    car.Copies);
                _carEditorGrid.Rows[rowIndex].Tag = car.CarId;
            }
            ClearCarGridSelection(_carEditorGrid);
            UpdateCarEditorSelection();
        }

        private CarEditorRow GetSelectedCarEditorRow()
        {
            if (InvokeRequired)
                return (CarEditorRow)Invoke(new Func<CarEditorRow>(GetSelectedCarEditorRow));
            if (_carEditorGrid == null || _carEditorGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a garage car in the Car Class Panel first.");

            int carId;
            if (!TryGetCarIdFromGridRow(_carEditorGrid.SelectedRows[0], out carId))
                throw new InvalidOperationException("Could not read the selected car id.");

            var row = _carEditorRows.FirstOrDefault(car => car.CarId == carId);
            if (row != null)
                return row;

            return new CarEditorRow(
                carId,
                GetGridCellText(_carEditorGrid.SelectedRows[0], "Year"),
                GetGridCellText(_carEditorGrid.SelectedRows[0], "Make"),
                GetGridCellText(_carEditorGrid.SelectedRows[0], "Model"),
                GetGridCellText(_carEditorGrid.SelectedRows[0], "Copies"),
                GetGridCellText(_carEditorGrid.SelectedRows[0], "PI"),
                ParseClassIdFromDisplay(GetGridCellText(_carEditorGrid.SelectedRows[0], "Class")),
                string.Empty,
                string.Empty,
                new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase),
                ParseClassIdFromDisplay(GetGridCellText(_carEditorGrid.SelectedRows[0], "Class")),
                0,
                0,
                0);
        }

        private void UpdateCarEditorSelection()
        {
            if (_carEditorSelected == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateCarEditorSelection);
                return;
            }

            if (_carEditorGrid == null || _carEditorGrid.SelectedRows.Count == 0)
            {
                _carEditorSelected.Text = "Selected car: none";
                SetComboSelectedById(_carEditorClassCombo, 0);
                return;
            }

            var car = GetSelectedCarEditorRow();
            _carEditorSelected.Text = "Selected: " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                " | PI " + car.PerformanceIndex + " | " + FormatCarClassId(car.ClassId);
            SetComboSelectedById(_carEditorClassCombo, car.EditorClassId);
        }

        private Dictionary<string, string> CaptureCarEditorInputs()
        {
            if (InvokeRequired)
                return (Dictionary<string, string>)Invoke(new Func<Dictionary<string, string>>(CaptureCarEditorInputs));

            var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var field in CarEditorFields)
            {
                TextBox box;
                if (_carEditorValueBoxes.TryGetValue(field.Key, out box))
                    values[field.Key] = GetTextBoxValue(box);
            }
            return values;
        }

