        private static void SetComboSelectedById(ComboBox combo, int id)
        {
            if (combo == null)
                return;
            for (var i = 0; i < combo.Items.Count; i++)
            {
                var option = combo.Items[i] as NamedOption;
                if (option != null && option.Id == id)
                {
                    combo.SelectedIndex = i;
                    return;
                }
            }
            if (combo.Items.Count > 0)
                combo.SelectedIndex = 0;
        }

        private int GetSelectedNamedOptionId(ComboBox combo, string label)
        {
            if (combo == null)
                throw new InvalidOperationException(label + " selector was not built.");
            if (combo.InvokeRequired)
                return (int)combo.Invoke(new Func<ComboBox, string, int>(GetSelectedNamedOptionId), combo, label);
            var option = combo.SelectedItem as NamedOption;
            if (option == null)
                throw new InvalidOperationException("Select a " + label + " value first.");
            return option.Id;
        }

        private void ApplySelectedCarClass(CarEditorRow car, int classId)
        {
            if (car == null || car.CarId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var carIdSql = car.CarId.ToString(CultureInfo.InvariantCulture);
            var owned = db.QueryScalarLong("SELECT count(*) FROM Profile0_Career_Garage WHERE CarId = " + carIdSql) ?? 0;
            if (owned <= 0)
                throw new InvalidOperationException("Selected car is not currently in the garage table.");

            EnsureCarEditorBackups(db);

            var classSql = classId.ToString(CultureInfo.InvariantCulture);
            var dataSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var garageSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddColumnSetIfExists(db, "Data_Car", dataSets, "ClassID", classSql);
            AddColumnSetIfExists(db, "Data_Car", dataSets, "ClassId", classSql);
            AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "ClassID", classSql);
            AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "ClassId", classSql);

            if (dataSets.Count == 0 && garageSets.Count == 0)
                throw new InvalidOperationException("No supported class columns were found in this FH6 database.");

            if (dataSets.Count > 0)
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET " + string.Join(", ", dataSets.Values.ToArray()) + " WHERE Id = " + carIdSql + ";");
            if (garageSets.Count > 0)
                ExecuteAutoshowSql(db, "UPDATE Profile0_Career_Garage SET " + string.Join(", ", garageSets.Values.ToArray()) + " WHERE CarId = " + carIdSql + ";");

            var classAfter = QueryScalarText(db, "SELECT CAST(COALESCE(MAX(garage.ClassID), MAX(data.ClassID), 0) AS TEXT) FROM Profile0_Career_Garage garage LEFT JOIN Data_Car data ON data.Id = garage.CarId WHERE garage.CarId = " + carIdSql);
            Log("Car Class Panel applied to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                ". Data_Car fields=" + dataSets.Count.ToString(CultureInfo.InvariantCulture) +
                ", garage fields=" + garageSets.Count.ToString(CultureInfo.InvariantCulture) +
                "; live class=" + (classAfter ?? "") + ".");

            LoadCarEditorGarage();
            ShowInfo("Car class updated." + Environment.NewLine + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine +
                "New class: " + FormatCarClassId(classId) + Environment.NewLine + Environment.NewLine +
                "Switch garage screens if FH6 cached the old class.");
        }

        private void ApplySelectedCarEditorValues(CarEditorRow car, Dictionary<string, string> rawValues, int classId, int driveTypeId, int engineConfigId, int aspirationTypeId)
        {
            if (car == null || car.CarId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var carIdSql = car.CarId.ToString(CultureInfo.InvariantCulture);
            var owned = db.QueryScalarLong("SELECT count(*) FROM Profile0_Career_Garage WHERE CarId = " + carIdSql) ?? 0;
            if (owned <= 0)
                throw new InvalidOperationException("Selected car is not currently in the garage table.");

            EnsureCarEditorBackups(db);

            var dataSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var garageSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            foreach (var field in CarEditorFields)
            {
                string raw;
                if (rawValues == null || !rawValues.TryGetValue(field.Key, out raw) || string.IsNullOrWhiteSpace(raw))
                    continue;
                if (!IsCarEditorValueChanged(car, field, raw))
                    continue;

                if (string.Equals(field.Key, "top_speed", StringComparison.OrdinalIgnoreCase))
                {
                    var mph = ParseCarEditorDouble(raw, field);
                    var mphSql = FormatCarEditorReal(mph);
                    var metersPerSecondSql = FormatCarEditorReal(mph * 0.44704);
                    AddColumnSetIfExists(db, "Data_Car", dataSets, "TopSpeed-mph", mphSql);
                    AddColumnSetIfExists(db, "Data_Car", dataSets, "SimTopSpeed", metersPerSecondSql);
                    AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "TopSpeed", metersPerSecondSql);
                    continue;
                }

                if (string.Equals(field.Key, "sim_top_speed", StringComparison.OrdinalIgnoreCase))
                {
                    var simTopSpeed = ParseCarEditorDouble(raw, field);
                    var simSql = FormatCarEditorReal(simTopSpeed);
                    AddColumnSetIfExists(db, "Data_Car", dataSets, "SimTopSpeed", simSql);
                    AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "TopSpeed", simSql);
                    continue;
                }

                var sqlValue = ParseCarEditorSqlValue(raw, field);
                foreach (var column in field.DataColumns)
                    AddColumnSetIfExists(db, "Data_Car", dataSets, column, sqlValue);
                foreach (var column in field.GarageColumns)
                    AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, column, sqlValue);
            }

            var classSql = classId.ToString(CultureInfo.InvariantCulture);
            AddColumnSetIfExists(db, "Data_Car", dataSets, "ClassID", classSql);
            AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "ClassID", classSql);

            if (driveTypeId > 0)
            {
                var driveSql = driveTypeId.ToString(CultureInfo.InvariantCulture);
                AddColumnSetIfExists(db, "Data_Car", dataSets, "DriveTypeID", driveSql);
                var powertrainId = ResolvePowertrainIdForDriveType(db, car.CarId, driveTypeId);
                if (powertrainId.HasValue)
                    AddColumnSetIfExists(db, "Data_Car", dataSets, "PowertrainID", powertrainId.Value.ToString(CultureInfo.InvariantCulture));
                var drivetrainUpgradeId = ResolveUpgradeDrivetrainIdForDriveType(db, car.CarId, driveTypeId);
                if (drivetrainUpgradeId.HasValue)
                    AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "Drivetrain", drivetrainUpgradeId.Value.ToString(CultureInfo.InvariantCulture));
                else
                    Log("Car Editor drivetrain note: no matching List_UpgradeDrivetrain row was found for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + " and " + FormatDriveTypeId(driveTypeId) + ". Data_Car DriveTypeID was still updated.");
            }

            if (engineConfigId > 0)
                AddColumnSetIfExists(db, "Data_Car", dataSets, "EngineConfigID", engineConfigId.ToString(CultureInfo.InvariantCulture));

            if (aspirationTypeId > 0)
            {
                var aspirationSql = aspirationTypeId.ToString(CultureInfo.InvariantCulture);
                AddColumnSetIfExists(db, "Data_Car", dataSets, "AspirationTypeId", aspirationSql);
                AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, "AspirationTypeId", aspirationSql);
            }

            if (dataSets.Count == 0 && garageSets.Count == 0)
                throw new InvalidOperationException("No editable car columns were available in this FH6 database.");

            if (dataSets.Count > 0)
                db.Execute("UPDATE Data_Car SET " + string.Join(", ", dataSets.Values.ToArray()) + " WHERE Id = " + carIdSql + ";");
            if (garageSets.Count > 0)
                db.Execute("UPDATE Profile0_Career_Garage SET " + string.Join(", ", garageSets.Values.ToArray()) + " WHERE CarId = " + carIdSql + ";");

            var piAfter = QueryScalarText(db, "SELECT CAST(COALESCE(MAX(garage.PerformanceIndex), MAX(data.PerformanceIndex), 0) AS TEXT) FROM Profile0_Career_Garage garage LEFT JOIN Data_Car data ON data.Id = garage.CarId WHERE garage.CarId = " + carIdSql);
            var classAfter = QueryScalarText(db, "SELECT CAST(COALESCE(MAX(garage.ClassID), MAX(data.ClassID), 0) AS TEXT) FROM Profile0_Career_Garage garage LEFT JOIN Data_Car data ON data.Id = garage.CarId WHERE garage.CarId = " + carIdSql);
            Log("Car Editor applied to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                ". Data_Car fields=" + dataSets.Count.ToString(CultureInfo.InvariantCulture) +
                ", garage fields=" + garageSets.Count.ToString(CultureInfo.InvariantCulture) +
                "; live PI=" + (piAfter ?? "") +
                ", class=" + (classAfter ?? "") + ".");

            LoadCarEditorGarage();
            ShowInfo("Car editor values applied." + Environment.NewLine + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine +
                "Switch to another car, then switch back so FH6 reloads the active vehicle data.");
        }

        private void ApplySelectedCarMaxPerformanceRatings(CarEditorRow car)
        {
            if (car == null || car.CarId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var carIdSql = car.CarId.ToString(CultureInfo.InvariantCulture);
            var owned = db.QueryScalarLong("SELECT count(*) FROM Profile0_Career_Garage WHERE CarId = " + carIdSql) ?? 0;
            if (owned <= 0)
                throw new InvalidOperationException("Selected car is not currently in the garage table.");

            EnsureCarEditorBackups(db);

            var dataSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var garageSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var column in CarEditorRatingColumns())
            {
                AddColumnSetIfExists(db, "Data_Car", dataSets, column, "10");
                AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, column, "10");
            }
            foreach (var value in CarEditorMaxPerformanceDataValues())
                AddColumnSetIfExists(db, "Data_Car", dataSets, value.Key, value.Value);
            foreach (var value in CarEditorMaxPerformanceGarageValues())
                AddColumnSetIfExists(db, "Profile0_Career_Garage", garageSets, value.Key, value.Value);

            if (dataSets.Count == 0 && garageSets.Count == 0)
                throw new InvalidOperationException("No supported performance rating columns were found.");

            if (dataSets.Count > 0)
                db.Execute("UPDATE Data_Car SET " + string.Join(", ", dataSets.Values.ToArray()) + " WHERE Id = " + carIdSql + ";");
            if (garageSets.Count > 0)
                db.Execute("UPDATE Profile0_Career_Garage SET " + string.Join(", ", garageSets.Values.ToArray()) + " WHERE CarId = " + carIdSql + ";");

            var speedAfter = QueryScalarText(db, "SELECT CAST(COALESCE(MAX(garage.SpeedRating), MAX(data.SpeedRating), 0) AS TEXT) FROM Profile0_Career_Garage garage LEFT JOIN Data_Car data ON data.Id = garage.CarId WHERE garage.CarId = " + carIdSql);
            Log("Max performance ratings applied to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                ". Data_Car fields=" + dataSets.Count.ToString(CultureInfo.InvariantCulture) +
                ", garage fields=" + garageSets.Count.ToString(CultureInfo.InvariantCulture) +
                "; live SpeedRating=" + (speedAfter ?? "") + ".");

            LoadCarEditorGarage();
            ShowInfo("Max performance ratings applied." + Environment.NewLine + Environment.NewLine +
                "Speed, Handling, Acceleration, Launch, Braking, and Offroad were set to 10/10 with real helper values for:" + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine + Environment.NewLine +
                "Switch to another car, then switch back so FH6 refreshes the displayed ratings.");
        }

        private void ResetSelectedCarEditorValues(CarEditorRow car)
        {
            if (car == null || car.CarId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");

            var db = RequireDatabase();
            if (!db.TableExists("_backup_Database_CarEditor_DataCar") && !db.TableExists("_backup_Database_CarEditor_Garage"))
                throw new InvalidOperationException("No Car Editor default backup was found yet. Apply a Car Editor value first so Luna can capture defaults before changing the car.");

            var carIdSql = car.CarId.ToString(CultureInfo.InvariantCulture);
            var dataRestored = RestoreSelectedCarEditorColumnsFromBackup(
                db,
                "Data_Car",
                "_backup_Database_CarEditor_DataCar",
                "Id = " + carIdSql,
                "backup.[Id] = Data_Car.[Id]",
                GetCarEditorDataResetColumns());

            var garageRestored = RestoreSelectedCarEditorColumnsFromBackup(
                db,
                "Profile0_Career_Garage",
                "_backup_Database_CarEditor_Garage",
                "CarId = " + carIdSql,
                "backup.[_rowid_] = Profile0_Career_Garage.rowid",
                GetCarEditorGarageResetColumns());

            if (dataRestored + garageRestored == 0)
                throw new InvalidOperationException("The selected car was not found in the Car Editor backup tables.");

            Log("Car Editor reset " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) +
                ". Restored Data_Car columns=" + dataRestored.ToString(CultureInfo.InvariantCulture) +
                ", garage columns=" + garageRestored.ToString(CultureInfo.InvariantCulture) + ".");

            LoadCarEditorGarage();
            ShowInfo("Selected car values reset from Luna's Car Editor backup." + Environment.NewLine + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine +
                "Switch cars or reopen Garage so FH6 refreshes the visible values.");
        }

        private void EnsureCarEditorBackups(RemoteDatabase db)
        {
            db.Execute("CREATE TABLE IF NOT EXISTS _backup_Database_CarEditor_DataCar AS SELECT rowid AS _rowid_, * FROM Data_Car;");
            db.Execute("CREATE TABLE IF NOT EXISTS _backup_Database_CarEditor_Garage AS SELECT rowid AS _rowid_, * FROM Profile0_Career_Garage;");
        }

        private int RestoreSelectedCarEditorColumnsFromBackup(RemoteDatabase db, string tableName, string backupName, string targetWhere, string backupJoin, IEnumerable<string> columns)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName))
                return 0;

            var tableColumns = new HashSet<string>(GetTableColumns(db, tableName), StringComparer.OrdinalIgnoreCase);
            var backupColumns = new HashSet<string>(GetTableColumns(db, backupName), StringComparer.OrdinalIgnoreCase);
            var sets = new List<string>();
            foreach (var column in columns.Distinct(StringComparer.OrdinalIgnoreCase))
            {
                if (!tableColumns.Contains(column) || !backupColumns.Contains(column))
                    continue;
                var columnSql = EscapeIdentifierForSql(column);
                sets.Add(columnSql + " = (SELECT backup." + columnSql + " FROM " + EscapeIdentifierForSql(backupName) + " backup WHERE " + backupJoin + " LIMIT 1)");
            }

            if (sets.Count == 0)
                return 0;

            db.Execute(
                "UPDATE " + EscapeIdentifierForSql(tableName) + " SET " + string.Join(", ", sets.ToArray()) +
                " WHERE " + targetWhere +
                " AND EXISTS (SELECT 1 FROM " + EscapeIdentifierForSql(backupName) + " backup WHERE " + backupJoin + ");");
            return sets.Count;
        }

        private static IEnumerable<string> GetCarEditorDataResetColumns()
        {
            foreach (var field in CarEditorFields)
            {
                foreach (var column in field.DataColumns)
                    yield return column;
            }
            foreach (var column in new[] { "ClassID", "DriveTypeID", "PowertrainID", "EngineConfigID", "AspirationTypeId" })
                yield return column;
            foreach (var column in CarEditorRatingColumns())
                yield return column;
            foreach (var value in CarEditorMaxPerformanceDataValues())
                yield return value.Key;
        }

        private static IEnumerable<string> GetCarEditorGarageResetColumns()
        {
            foreach (var field in CarEditorFields)
