                foreach (var column in field.GarageColumns)
                    yield return column;
            }
            foreach (var column in new[] { "TopSpeed", "PerformanceIndex", "ClassID", "Drivetrain", "AspirationTypeId" })
                yield return column;
            foreach (var column in CarEditorRatingColumns())
                yield return column;
            foreach (var value in CarEditorMaxPerformanceGarageValues())
                yield return value.Key;
        }

