        private static void AddColumnSetIfExists(RemoteDatabase db, string tableName, List<string> sets, string columnName, string sqlValue)
        {
            if (db.ColumnExists(tableName, columnName))
                sets.Add(EscapeIdentifierForSql(columnName) + " = " + sqlValue);
        }

        private static void AddColumnSetIfExists(RemoteDatabase db, string tableName, Dictionary<string, string> sets, string columnName, string sqlValue)
        {
            if (db.ColumnExists(tableName, columnName))
            {
                var columnSql = EscapeIdentifierForSql(columnName);
                sets[columnName] = columnSql + " = " + sqlValue;
            }
        }

        private long? ResolvePowertrainIdForDriveType(RemoteDatabase db, int carId, int driveTypeId)
        {
            if (!db.TableExists("Powertrains") || !db.ColumnExists("Powertrains", "Id") || !db.ColumnExists("Powertrains", "DrivetrainId"))
                return null;

            var driveSql = driveTypeId.ToString(CultureInfo.InvariantCulture);
            var carSql = carId.ToString(CultureInfo.InvariantCulture);
            long? value = null;
            if (db.ColumnExists("Powertrains", "EnginePlacementId") && db.ColumnExists("Data_Car", "PowertrainID"))
            {
                value = db.QueryScalarLong(
                    "SELECT Id FROM Powertrains WHERE DrivetrainId = " + driveSql + " " +
                    "AND EnginePlacementId = COALESCE((SELECT current.EnginePlacementId FROM Powertrains current WHERE current.Id = (SELECT PowertrainID FROM Data_Car WHERE Id = " + carSql + ")), EnginePlacementId) " +
                    "ORDER BY Id LIMIT 1");
            }
            if (!value.HasValue)
                value = db.QueryScalarLong("SELECT Id FROM Powertrains WHERE DrivetrainId = " + driveSql + " ORDER BY Id LIMIT 1");
            return value;
        }

        private long? ResolveUpgradeDrivetrainIdForDriveType(RemoteDatabase db, int carId, int driveTypeId)
        {
            if (!db.TableExists("List_UpgradeDrivetrain") || !db.ColumnExists("List_UpgradeDrivetrain", "Id") || !db.ColumnExists("List_UpgradeDrivetrain", "Ordinal"))
                return null;

            var carSql = carId.ToString(CultureInfo.InvariantCulture);
            var driveSql = driveTypeId.ToString(CultureInfo.InvariantCulture);
            if (db.ColumnExists("List_UpgradeDrivetrain", "PowertrainId") &&
                db.TableExists("Powertrains") &&
                db.ColumnExists("Powertrains", "Id") &&
                db.ColumnExists("Powertrains", "DrivetrainId"))
            {
                var value = db.QueryScalarLong(
                    "SELECT ud.Id FROM List_UpgradeDrivetrain ud " +
                    "JOIN Powertrains p ON p.Id = ud.PowertrainId " +
                    "WHERE ud.Ordinal = " + carSql + " AND p.DrivetrainId = " + driveSql + " " +
                    "ORDER BY COALESCE(ud.IsStock, 0) DESC, ud.Id LIMIT 1");
                if (value.HasValue)
                    return value;
            }

            if (db.ColumnExists("List_UpgradeDrivetrain", "DrivetrainID") &&
                db.TableExists("Data_Drivetrain") &&
                db.ColumnExists("Data_Drivetrain", "DrivetrainID") &&
                db.ColumnExists("Data_Drivetrain", "DrivetypeID"))
            {
                return db.QueryScalarLong(
                    "SELECT ud.Id FROM List_UpgradeDrivetrain ud " +
                    "JOIN Data_Drivetrain drive ON drive.DrivetrainID = ud.DrivetrainID " +
                    "WHERE ud.Ordinal = " + carSql + " AND drive.DrivetypeID = " + driveSql + " " +
                    "ORDER BY COALESCE(ud.IsStock, 0) DESC, ud.Id LIMIT 1");
            }

            return null;
        }

        private static bool IsCarEditorValueChanged(CarEditorRow car, CarEditorField field, string raw)
        {
            if (car == null || car.Values == null)
                return true;

            string current;
            if (!car.Values.TryGetValue(field.Key, out current) || string.IsNullOrWhiteSpace(current))
                return true;

            double rawValue;
            double currentValue;
            if (double.TryParse((raw ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out rawValue) &&
                double.TryParse((current ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out currentValue))
                return Math.Abs(rawValue - currentValue) > 0.000001;

            return !string.Equals((raw ?? string.Empty).Trim(), (current ?? string.Empty).Trim(), StringComparison.OrdinalIgnoreCase);
        }

        private static string FormatCarEditorReal(double value)
        {
            return value.ToString("0.######", CultureInfo.InvariantCulture);
        }

        private static double ParseCarEditorDouble(string text, CarEditorField field)
        {
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (normalized.Length == 0)
                throw new InvalidOperationException(field.Label + " cannot be empty.");

            double value;
            if (!double.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || double.IsNaN(value) || double.IsInfinity(value))
                throw new InvalidOperationException(field.Label + " must be a finite number.");
            if (value < 0.0)
                throw new InvalidOperationException(field.Label + " must be zero or higher.");
            return value;
        }

        private static string ParseCarEditorSqlValue(string text, CarEditorField field)
        {
            var value = ParseCarEditorDouble(text, field);

            if (field.WholeNumber)
            {
                var rounded = Math.Round(value);
                if (Math.Abs(value - rounded) > 0.000001)
                    throw new InvalidOperationException(field.Label + " must be a whole number.");
                return ((long)rounded).ToString(CultureInfo.InvariantCulture);
            }

            return FormatCarEditorReal(value);
        }

        private void LoadSkillData()
        {
            var db = RequireDatabase();
            var garageTable = ResolveActiveGarageTable(db);
            if (!db.ColumnExists(garageTable, "Id") || !db.ColumnExists(garageTable, "CarId"))
                throw new InvalidOperationException(garageTable + ".Id/CarId was not found.");

            var garage = QuerySkillGarageRows(db);
            var profileStats = QueryProfileStatRows(db);
            SetSkillGarageRows(garage);
            SetProfileStatRows(profileStats);
            SetSkillStatus("Garage " + garage.Count.ToString(CultureInfo.InvariantCulture) + " | profile " + profileStats.Count.ToString(CultureInfo.InvariantCulture));
            Log("Stats Editor loaded " + garage.Count.ToString(CultureInfo.InvariantCulture) + " garage row(s) and " + profileStats.Count.ToString(CultureInfo.InvariantCulture) + " profile editable stat row(s).");
        }

        private void LoadProfileEditableStats()
        {
            var db = RequireDatabase();
            var profileStats = QueryProfileStatRows(db);
            SetProfileStatRows(profileStats);
            SetSkillStatus("Profile " + profileStats.Count.ToString(CultureInfo.InvariantCulture));
            Log("Profile Editable Stats loaded " + profileStats.Count.ToString(CultureInfo.InvariantCulture) + " supported profile row(s).");
        }

        private List<SkillGarageRow> QuerySkillGarageRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            var garageTable = ResolveActiveGarageTable(db);
            var garageSql = EscapeIdentifierForSql(garageTable);

            var select = new List<string>
            {
                "garage.Id AS GarageId",
                "garage.CarId AS CarId",
                "COALESCE(data.Year, '') AS Year",
                "COALESCE(data.MakeName, '') AS Make",
                "COALESCE(data.DisplayName, data.ModelShort, data.MediaName, '') AS Model",
                "COALESCE(garage.PerformanceIndex, data.PerformanceIndex, 0) AS PI",
                "COALESCE(garage.ClassID, data.ClassID, 0) AS ClassID"
            };
            foreach (var field in StatsEditorFields)
            {
                var column = EscapeIdentifierForSql(field.ColumnName);
                select.Add(db.ColumnExists(garageTable, field.ColumnName)
                    ? "COALESCE(garage." + column + ", '') AS " + column
                    : "'' AS " + column);
            }

            var sql =
                "SELECT " + string.Join(", ", select.ToArray()) + " " +
                "FROM " + garageSql + " garage " +
                "LEFT JOIN Data_Car data ON data.Id = garage.CarId " +
                "WHERE garage.CarId IS NOT NULL " +
                "ORDER BY Make, Model, garage.Id;";

            var result = db.Query(sql);
            var rows = new List<SkillGarageRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 7)
                    continue;
                var garageId = ToInt(row[0]);
                var carId = ToInt(row[1]);
                if (garageId <= 0 || carId <= 0)
                    continue;

                var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                for (var i = 0; i < StatsEditorFields.Length; i++)
                {
                    var valueIndex = 7 + i;
                    values[StatsEditorFields[i].ColumnName] = valueIndex < row.Count ? FormatCarNumber(row[valueIndex]) : string.Empty;
                }

                rows.Add(new SkillGarageRow(
                    garageId,
                    carId,
                    ToDisplayString(row[2]),
                    TranslateCarText(ToDisplayString(row[3]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[4]), _carNameStrings),
                    FormatCarNumber(row[5]),
                    ToDisplayString(row[6]),
                    values));
            }
            return rows;
        }

        private void SetSkillGarageRows(List<SkillGarageRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetSkillGarageRows(rows); }));
                return;
            }

            _skillGarageRows = rows ?? new List<SkillGarageRow>();
            ApplySkillGarageFilter();
        }

        private void ApplySkillGarageFilter()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplySkillGarageFilter);
                return;
            }

            var filter = _skillGarageSearch == null ? string.Empty : _skillGarageSearch.Text;
            var rows = FilterSkillGarageRows(_skillGarageRows, filter);
            SetSkillGarageGridRows(rows);
            SetSkillStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture) + "/" + _skillGarageRows.Count.ToString(CultureInfo.InvariantCulture));
        }

        private static List<SkillGarageRow> FilterSkillGarageRows(List<SkillGarageRow> rows, string filter)
        {
            if (rows == null)
                return new List<SkillGarageRow>();
            filter = (filter ?? string.Empty).Trim();
            if (filter.Length == 0)
                return rows.ToList();
            return rows.Where(row => row.Matches(filter)).ToList();
        }

        private void SetSkillGarageGridRows(List<SkillGarageRow> rows)
        {
            if (_skillGarageGrid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetSkillGarageGridRows(rows); }));
                return;
            }

            _skillGarageGrid.Rows.Clear();
            foreach (var car in rows)
            {
                var rowIndex = _skillGarageGrid.Rows.Add(
                    car.GarageId.ToString(CultureInfo.InvariantCulture),
                    car.CarId.ToString(CultureInfo.InvariantCulture),
                    car.Year,
                    car.Make,
                    car.Model,
                    car.PerformanceIndex,
                    car.ClassId,
                    car.GetValue("OriginalOwner"),
                    car.GetValue("NumOwners"),
                    car.GetValue("NumTimesSold"));
                _skillGarageGrid.Rows[rowIndex].Tag = car.GarageId;
            }
            ClearCarGridSelection(_skillGarageGrid);
            UpdateSkillGarageSelection();
        }

        private SkillGarageRow GetSelectedSkillGarageCar()
        {
            if (InvokeRequired)
                return (SkillGarageRow)Invoke(new Func<SkillGarageRow>(GetSelectedSkillGarageCar));
            if (_skillGarageGrid == null || _skillGarageGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Select a garage car in the Stats Editor first.");

            var garageId = ToInt(GetGridCellText(_skillGarageGrid.SelectedRows[0], "GarageId"));
            var row = _skillGarageRows.FirstOrDefault(car => car.GarageId == garageId);
            if (row == null)
                throw new InvalidOperationException("Could not read the selected garage row.");
            return row;
        }

        private void UpdateSkillGarageSelection()
        {
            if (_skillSelectedCar == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateSkillGarageSelection);
                return;
            }

            if (_skillGarageGrid == null || _skillGarageGrid.SelectedRows.Count == 0)
            {
                _skillSelectedCar.Text = "Selected car: none";
                PopulateStatsEditorGrid(null);
                return;
            }

            var row = _skillGarageGrid.SelectedRows[0];
            var garageId = ToInt(GetGridCellText(row, "GarageId"));
            var selected = _skillGarageRows.FirstOrDefault(car => car.GarageId == garageId);
            var name = FormatCarDisplayName(
                ToInt(GetGridCellText(row, "CarId")),
                GetGridCellText(row, "Year"),
                GetGridCellText(row, "Make"),
                GetGridCellText(row, "Model"));
            _skillSelectedCar.Text = "Selected car: " + name;
            PopulateStatsEditorGrid(selected);
        }

        private void PopulateStatsEditorGrid(SkillGarageRow selected)
        {
            if (_statsEditorGrid == null)
                return;
            if (_statsEditorGrid.InvokeRequired)
            {
                _statsEditorGrid.BeginInvoke((Action)(delegate { PopulateStatsEditorGrid(selected); }));
                return;
            }

            _statsEditorGrid.Rows.Clear();
            if (selected == null)
                return;

            foreach (var field in StatsEditorFields)
            {
                var rowIndex = _statsEditorGrid.Rows.Add(
                    field.ColumnName,
                    field.DisplayName,
                    field.Description,
                    selected.GetValue(field.ColumnName));
                _statsEditorGrid.Rows[rowIndex].Tag = field;
            }
            ClearCarGridSelection(_statsEditorGrid);
        }

        private Dictionary<string, string> CaptureStatsEditorValues()
        {
            if (_statsEditorGrid == null)
                throw new InvalidOperationException("Load a garage car in the Stats Editor first.");
            if (_statsEditorGrid.InvokeRequired)
                return (Dictionary<string, string>)_statsEditorGrid.Invoke(new Func<Dictionary<string, string>>(CaptureStatsEditorValues));

            if (_statsEditorGrid.IsCurrentCellDirty)
                _statsEditorGrid.CommitEdit(DataGridViewDataErrorContexts.Commit);
            if (_statsEditorGrid.IsCurrentCellInEditMode)
                _statsEditorGrid.EndEdit();

            var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (DataGridViewRow row in _statsEditorGrid.Rows)
            {
                if (row.IsNewRow)
                    continue;
                var column = Convert.ToString(row.Cells["Column"].Value, CultureInfo.InvariantCulture);
                var value = Convert.ToString(row.Cells["Value"].Value, CultureInfo.InvariantCulture);
                if (string.IsNullOrWhiteSpace(column))
                    continue;
                values[column.Trim()] = (value ?? string.Empty).Trim();
            }

            return values;
        }

        private void ApplySelectedCarStats(SkillGarageRow car, Dictionary<string, string> values)
        {
            if (car == null || car.GarageId <= 0)
                throw new InvalidOperationException("Select a valid garage car first.");
            if (values == null || values.Count == 0)
                throw new InvalidOperationException("Load current stats, select a car, then edit at least one value.");

            var db = RequireDatabase();
            var garageTable = ResolveActiveGarageTable(db);
            if (!db.ColumnExists(garageTable, "Id"))
                throw new InvalidOperationException(garageTable + ".Id was not found.");

            var preparedValues = new Dictionary<string, string>(values, StringComparer.OrdinalIgnoreCase);
            var currentOwnerRaceWasEdited = WasStatsValueEdited(preparedValues, "CurOwnerNumRaces", car.GetValue("CurOwnerNumRaces"));
            if (db.ColumnExists(garageTable, "NumRaces") &&
                db.ColumnExists(garageTable, "CurOwnerNumRaces") &&
                !currentOwnerRaceWasEdited &&
                preparedValues.ContainsKey("NumRaces"))
            {
                preparedValues["CurOwnerNumRaces"] = preparedValues["NumRaces"];
            }

            var sets = new List<string>();
            foreach (var field in StatsEditorFields)
            {
                string raw;
                if (!preparedValues.TryGetValue(field.ColumnName, out raw))
                    continue;
                if (!db.ColumnExists(garageTable, field.ColumnName))
                    continue;
                sets.Add(EscapeIdentifierForSql(field.ColumnName) + " = " + ParseStatsEditorFieldSqlValue(raw, field));
            }

            if (sets.Count == 0)
                throw new InvalidOperationException("None of the supported Stats Editor columns were found in this FH6 database.");

            var garageIdSql = car.GarageId.ToString(CultureInfo.InvariantCulture);
            var garageSql = EscapeIdentifierForSql(garageTable);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_StatsEditor_Garage AS SELECT rowid AS _rowid_, * FROM " + garageSql + ";");
            ExecuteAutoshowSql(db, "UPDATE " + garageSql + " SET " + string.Join(", ", sets.ToArray()) + " WHERE Id = " + garageIdSql + ";");
            NormalizeGarageRaceStats(db, garageTable, "Id = " + garageIdSql, !currentOwnerRaceWasEdited);

            Log("Stats Editor applied " + sets.Count.ToString(CultureInfo.InvariantCulture) + " value(s) to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ".");
            LogGarageRaceStatsVerification(db, garageTable, "Id = " + garageIdSql, "Selected car stats");
            LoadSkillData();
            ShowInfo("Stats updated." + Environment.NewLine + Environment.NewLine +
                FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + Environment.NewLine + Environment.NewLine +
                "Switch garage screens or restart FH6 if the menu cached the old values.");
        }

        private List<ProfileStatRow> QueryProfileStatRows(RemoteDatabase db)
        {
            var rows = new List<ProfileStatRow>();
            foreach (var field in ProfileStatFields)
            {
                var tableName = ResolveProfileStatFieldTable(db, field);
                if (string.IsNullOrEmpty(tableName) || !db.ColumnExists(tableName, field.ColumnName))
                    continue;

                var effectiveField = string.Equals(tableName, field.TableName, StringComparison.OrdinalIgnoreCase)
                    ? field
                    : new ProfileStatField(field.DisplayName, tableName, field.ColumnName, field.Description, field.AllowText);
                var tableSql = EscapeIdentifierForSql(tableName);
                var columnSql = EscapeIdentifierForSql(field.ColumnName);
                var rowCount = db.QueryScalarLong("SELECT count(*) FROM " + tableSql) ?? 0;
                var distinctCount = rowCount <= 0
                    ? 0
                    : (db.QueryScalarLong("SELECT count(*) FROM (SELECT DISTINCT " + columnSql + " FROM " + tableSql + " WHERE " + columnSql + " IS NOT NULL)") ?? 0);

                string current;
                string editable;
                if (rowCount <= 0)
                {
                    current = "no rows";
                    editable = string.Empty;
                }
                else if (distinctCount <= 0)
                {
                    current = "blank";
                    editable = string.Empty;
                }
                else if (distinctCount == 1)
                {
                    current = QueryScalarText(db, "SELECT CAST(" + columnSql + " AS TEXT) FROM " + tableSql + " WHERE " + columnSql + " IS NOT NULL LIMIT 1") ?? string.Empty;
                    editable = current;
                }
                else
                {
                    var min = QueryScalarText(db, "SELECT CAST(MIN(" + columnSql + ") AS TEXT) FROM " + tableSql + " WHERE " + columnSql + " IS NOT NULL") ?? "";
                    var max = QueryScalarText(db, "SELECT CAST(MAX(" + columnSql + ") AS TEXT) FROM " + tableSql + " WHERE " + columnSql + " IS NOT NULL") ?? "";
                    current = field.AllowText
                        ? "varies (" + distinctCount.ToString(CultureInfo.InvariantCulture) + " values)"
                        : "varies (" + distinctCount.ToString(CultureInfo.InvariantCulture) + ", " + min + " to " + max + ")";
                    editable = string.Empty;
                }

                rows.Add(new ProfileStatRow(effectiveField, current, editable, rowCount));
            }

            return rows;
        }

        private void SetProfileStatRows(List<ProfileStatRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetProfileStatRows(rows); }));
                return;
            }

            _profileStatRows = rows ?? new List<ProfileStatRow>();
            SetProfileStatsGridRows(_profileStatRows);
        }

        private void SetProfileStatsGridRows(List<ProfileStatRow> rows)
        {
            if (_profileStatsGrid == null)
                return;
            if (_profileStatsGrid.InvokeRequired)
            {
                _profileStatsGrid.BeginInvoke((Action)(delegate { SetProfileStatsGridRows(rows); }));
                return;
            }

            _profileStatsGrid.Rows.Clear();
            foreach (var stat in rows ?? new List<ProfileStatRow>())
            {
                var rowIndex = _profileStatsGrid.Rows.Add(
                    stat.Field.TableName,
                    stat.Field.ColumnName,
                    stat.Field.DisplayName,
                    stat.CurrentValue,
                    stat.EditValue,
                    stat.Field.Description);
                _profileStatsGrid.Rows[rowIndex].Tag = stat;
            }
            ClearCarGridSelection(_profileStatsGrid);
        }

        private List<ProfileStatEdit> CaptureProfileStatsValues()
        {
            if (_profileStatsGrid == null)
                throw new InvalidOperationException("Load Stats first so Profile Editable Stats can populate.");
            if (_profileStatsGrid.InvokeRequired)
                return (List<ProfileStatEdit>)_profileStatsGrid.Invoke(new Func<List<ProfileStatEdit>>(CaptureProfileStatsValues));

            if (_profileStatsGrid.IsCurrentCellDirty)
                _profileStatsGrid.CommitEdit(DataGridViewDataErrorContexts.Commit);
            if (_profileStatsGrid.IsCurrentCellInEditMode)
                _profileStatsGrid.EndEdit();

            var edits = new List<ProfileStatEdit>();
            foreach (DataGridViewRow row in _profileStatsGrid.Rows)
            {
                if (row.IsNewRow)
                    continue;
                var stat = row.Tag as ProfileStatRow;
                if (stat == null)
                    continue;
                var value = Convert.ToString(row.Cells["Value"].Value, CultureInfo.InvariantCulture);
                if (string.IsNullOrWhiteSpace(value))
                    continue;
                value = value.Trim();
                if (IsProfileStatValueUnchanged(stat, value))
                    continue;
                edits.Add(new ProfileStatEdit(stat, value));
            }

            return edits;
        }

        private void ApplyProfileStats(List<ProfileStatEdit> edits)
        {
            if (edits == null || edits.Count == 0)
                throw new InvalidOperationException("Enter at least one Profile Editable Stats value before applying.");

            var db = RequireDatabase();
            var backedUpTables = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var touched = 0;
            var garageTablesTouched = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var garageTablesMirrorCurrentOwnerRaces = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var touchedGarageRaceColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var edit in edits)
            {
                var field = edit.Row == null ? null : edit.Row.Field;
                if (field == null)
                    continue;
                var tableName = ResolveProfileStatFieldTable(db, field);
                if (string.IsNullOrEmpty(tableName) || !db.ColumnExists(tableName, field.ColumnName))
                    continue;

                var effectiveField = string.Equals(tableName, field.TableName, StringComparison.OrdinalIgnoreCase)
                    ? field
                    : new ProfileStatField(field.DisplayName, tableName, field.ColumnName, field.Description, field.AllowText);
                var tableSql = EscapeIdentifierForSql(tableName);
                var columnSql = EscapeIdentifierForSql(field.ColumnName);
                if (backedUpTables.Add(tableName))
                {
                    ExecuteAutoshowSql(db,
                        "CREATE TABLE IF NOT EXISTS _backup_Database_ProfileEditableStats_" + MakeSqlBackupSuffix(tableName) +
                        " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
                }

                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + columnSql + " = " + ParseProfileStatSqlValue(edit.Value, effectiveField) + ";");
                if (IsGarageStatsTable(db, tableName))
                {
                    if (IsGarageRaceStatColumn(field.ColumnName))
                    {
                        garageTablesTouched.Add(tableName);
                        touchedGarageRaceColumns.Add(tableName + "\n" + field.ColumnName);
                    }
                    if (string.Equals(field.ColumnName, "NumRaces", StringComparison.OrdinalIgnoreCase))
                        garageTablesMirrorCurrentOwnerRaces.Add(tableName);
                }
                touched++;
            }

            if (touched == 0)
                throw new InvalidOperationException("None of the selected Profile Editable Stats columns were found in this FH6 database.");

            foreach (var tableName in garageTablesTouched)
            {
                var explicitCurrentOwnerRace = touchedGarageRaceColumns.Contains(tableName + "\nCurOwnerNumRaces");
                var shouldMirrorCurrentOwnerRace = garageTablesMirrorCurrentOwnerRaces.Contains(tableName) && !explicitCurrentOwnerRace;
                NormalizeGarageRaceStats(db, tableName, null, shouldMirrorCurrentOwnerRace);
                LogGarageRaceStatsVerification(db, tableName, null, "Profile editable garage stats");
            }

            Log("Profile Editable Stats applied " + touched.ToString(CultureInfo.InvariantCulture) + " profile/table value(s).");
            LoadSkillData();
            ShowInfo("Profile editable stats updated." + Environment.NewLine + Environment.NewLine +
                "Switch screens or restart FH6 if a menu cached the old values.");
        }

        private static string ParseProfileStatSqlValue(string text, ProfileStatField field)
        {
            var normalized = (text ?? string.Empty).Trim();
            if (field != null && field.AllowText)
            {
                if (normalized.Length > 128)
                    throw new InvalidOperationException(field.DisplayName + " text must be 128 characters or fewer.");
                return ToSqlText(normalized);
            }

            return ParseStatsEditorSqlValue(normalized, field == null ? "Profile stat" : field.DisplayName);
        }

        private static string ParseStatsEditorFieldSqlValue(string text, StatsEditorField field)
        {
            var normalized = (text ?? string.Empty).Trim();
            if (field != null && field.AllowText)
            {
                if (normalized.Length > 128)
                    throw new InvalidOperationException(field.DisplayName + " text must be 128 characters or fewer.");
                return ToSqlText(normalized);
            }

            return ParseStatsEditorSqlValue(normalized, field == null ? "Stats Editor value" : field.DisplayName);
        }

        private static string MakeSqlBackupSuffix(string tableName)
        {
            var builder = new StringBuilder();
            foreach (var ch in tableName ?? string.Empty)
            {
                if (char.IsLetterOrDigit(ch))
                    builder.Append(ch);
                else
                    builder.Append('_');
            }
            return builder.Length == 0 ? "Table" : builder.ToString();
        }

        private static bool WasStatsValueEdited(Dictionary<string, string> values, string columnName, string originalValue)
        {
            if (values == null)
                return false;

            string editedValue;
            if (!values.TryGetValue(columnName, out editedValue))
                return false;

            return !string.Equals(NormalizeStatsCompareText(editedValue), NormalizeStatsCompareText(originalValue), StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsProfileStatValueUnchanged(ProfileStatRow stat, string value)
        {
            if (stat == null)
                return false;
            if (string.IsNullOrWhiteSpace(stat.EditValue))
                return false;

            var field = stat.Field;
            if (field != null && field.AllowText)
                return string.Equals((value ?? string.Empty).Trim(), (stat.EditValue ?? string.Empty).Trim(), StringComparison.Ordinal);

            return string.Equals(NormalizeStatsCompareText(value), NormalizeStatsCompareText(stat.EditValue), StringComparison.OrdinalIgnoreCase);
        }

        private static string NormalizeStatsCompareText(string value)
        {
            var text = (value ?? string.Empty).Replace(",", string.Empty).Trim();
            double numeric;
            if (double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out numeric))
                return numeric.ToString("0.######", CultureInfo.InvariantCulture);
            return text;
        }

        private static bool IsGarageRaceStatColumn(string columnName)
        {
            return string.Equals(columnName, "NumRaces", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "CurOwnerNumRaces", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "NumVictories", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "NumPodiums", StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsGarageStatsTable(RemoteDatabase db, string tableName)
        {
            return HasRequiredColumns(db, tableName, "CarId") &&
                db.ColumnExists(tableName, "NumRaces") &&
                db.ColumnExists(tableName, "NumVictories") &&
                db.ColumnExists(tableName, "NumPodiums");
        }

        private void NormalizeGarageRaceStats(RemoteDatabase db, string tableName, string whereClause, bool mirrorCurrentOwnerRaces)
        {
            if (!IsGarageStatsTable(db, tableName))
                return;

            var tableSql = EscapeIdentifierForSql(tableName);
            var whereSql = string.IsNullOrWhiteSpace(whereClause) ? string.Empty : " WHERE " + whereClause;
            ExecuteAutoshowSql(db,
                "UPDATE " + tableSql + " SET [NumPodiums] = [NumVictories]" +
                " WHERE COALESCE([NumPodiums], 0) < COALESCE([NumVictories], 0)" +
                (string.IsNullOrWhiteSpace(whereClause) ? string.Empty : " AND " + whereClause) + ";");
            ExecuteAutoshowSql(db,
                "UPDATE " + tableSql + " SET [NumRaces] = [NumPodiums]" +
                " WHERE COALESCE([NumRaces], 0) < COALESCE([NumPodiums], 0)" +
                (string.IsNullOrWhiteSpace(whereClause) ? string.Empty : " AND " + whereClause) + ";");

            if (mirrorCurrentOwnerRaces && db.ColumnExists(tableName, "CurOwnerNumRaces"))
            {
                ExecuteAutoshowSql(db,
                    "UPDATE " + tableSql + " SET [CurOwnerNumRaces] = [NumRaces]" + whereSql + ";");
            }
        }

        private void LogGarageRaceStatsVerification(RemoteDatabase db, string tableName, string whereClause, string label)
        {
            if (!IsGarageStatsTable(db, tableName))
                return;

            var tableSql = EscapeIdentifierForSql(tableName);
            var whereSql = string.IsNullOrWhiteSpace(whereClause) ? string.Empty : " WHERE " + whereClause;
            var races = QueryScalarText(db, "SELECT CAST(COALESCE(SUM([NumRaces]), 0) AS TEXT) FROM " + tableSql + whereSql) ?? "0";
            var currentOwnerRaces = db.ColumnExists(tableName, "CurOwnerNumRaces")
                ? (QueryScalarText(db, "SELECT CAST(COALESCE(SUM([CurOwnerNumRaces]), 0) AS TEXT) FROM " + tableSql + whereSql) ?? "0")
                : "n/a";
            var wins = QueryScalarText(db, "SELECT CAST(COALESCE(SUM([NumVictories]), 0) AS TEXT) FROM " + tableSql + whereSql) ?? "0";
            var podiums = QueryScalarText(db, "SELECT CAST(COALESCE(SUM([NumPodiums]), 0) AS TEXT) FROM " + tableSql + whereSql) ?? "0";
            Log(label + " verified: races=" + races + ", current-owner races=" + currentOwnerRaces + ", wins=" + wins + ", podiums=" + podiums + ".");
        }

        private static string ParseStatsEditorSqlValue(string text, string label)
        {
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (normalized.Length == 0)
                normalized = "0";

            double value;
            if (!double.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                throw new InvalidOperationException(label + " must be a finite number.");
            if (double.IsNaN(value) || double.IsInfinity(value))
                throw new InvalidOperationException(label + " must be a finite number.");
            if (value < 0 || value > 999999999999.0)
                throw new InvalidOperationException(label + " must be between 0 and 999999999999.");

            return value.ToString("0.######", CultureInfo.InvariantCulture);
        }

        private void ApplySingleCarGrant(RemoteDatabase db, int carId)
        {
            if (db.TableExists("Data_Car_Buckets") && db.ColumnExists("Data_Car_Buckets", "CarId"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_DataCarBuckets AS SELECT * FROM Data_Car_Buckets;");
                ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO Data_Car_Buckets(CarId) SELECT Id FROM Data_Car WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + " AND NOT EXISTS (SELECT 1 FROM Data_Car_Buckets buckets WHERE buckets.CarId = Data_Car.Id);");
                if (db.ColumnExists("Data_Car_Buckets", "CarBucket") && db.ColumnExists("Data_Car_Buckets", "BucketHero"))
                    ExecuteAutoshowSql(db, "UPDATE Data_Car_Buckets SET CarBucket=0, BucketHero=0 WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture) + " AND CarBucket IS NULL;");
            }

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_DataCarRow AS SELECT * FROM Data_Car WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (db.ColumnExists("Data_Car", "NotAvailableInAutoshow"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET NotAvailableInAutoshow = 0 WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (db.ColumnExists("Data_Car", "VisibleOnlyIfOwned"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET VisibleOnlyIfOwned = 0 WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (db.ColumnExists("Data_Car", "IsInstalled"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET IsInstalled = 1 WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (db.ColumnExists("Data_Car", "IsPurchased"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET IsPurchased = 1 WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (db.ColumnExists("Data_Car", "IsDrivable"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET IsDrivable = 1 WHERE Id = " + carId.ToString(CultureInfo.InvariantCulture) + ";");

            var freeCarsTable = ResolveOptionalActiveFreeCarsTable(db);
            if (!string.IsNullOrEmpty(freeCarsTable))
            {
                var freeCarsSql = EscapeIdentifierForSql(freeCarsTable);
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_Profile_FreeCars AS SELECT * FROM " + freeCarsSql + ";");
                ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO " + freeCarsSql + " (CarId, FreeCount) VALUES (" + carId.ToString(CultureInfo.InvariantCulture) + ", 1);");
                ExecuteAutoshowSql(db, "UPDATE " + freeCarsSql + " SET FreeCount = 1 WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture) + " AND (FreeCount IS NULL OR FreeCount < 1);");
            }

            if (db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentId") &&
                db.ColumnExists("ContentOffersMapping", "ContentType"))
            {
                var carContentSubquery = BuildDataCarContentIdSubquery(db, "Data_Car.Id = " + carId.ToString(CultureInfo.InvariantCulture));
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                InsertSingleCarContentOfferMapping(db, carId);
                if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 1 WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + carContentSubquery + ");");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + carContentSubquery + ") AND (Quantity IS NULL OR Quantity < 1);");
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + carContentSubquery + ") AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");
            }

            if (db.TableExists("OnDiscContent") && db.ColumnExists("OnDiscContent", "ContentId") && db.ColumnExists("OnDiscContent", "ContentType"))
                InsertSingleCarOnDiscContent(db, carId);
        }

        private void InsertSingleCarContentOfferMapping(RemoteDatabase db, int carId)
        {
            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "OfferId", BuildCarOfferIdExpression(db));
            AddInsertColumn(columns, values, "ContentId", "CAST(" + BuildDataCarContentIdExpression(db, "Data_Car") + " AS TEXT)");
            AddInsertColumn(columns, values, "ContentType", "1");
            if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                AddInsertColumn(columns, values, "IsPromo", "0");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                AddInsertColumn(columns, values, "IsAutoRedeem", "1");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                AddInsertColumn(columns, values, "ReleaseDateUTC", "'1969-04-20 00:00'");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                AddInsertColumn(columns, values, "Quantity", "1");

            ExecuteAutoshowSql(db,
                "INSERT OR IGNORE INTO ContentOffersMapping (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE Data_Car.Id = " + carId.ToString(CultureInfo.InvariantCulture) + " " +
                "AND NOT EXISTS (SELECT 1 FROM ContentOffersMapping WHERE ContentType = 1 AND " + BuildContentMappingDataCarMatch(db, "ContentOffersMapping", "Data_Car") + ");");
        }

        private void InsertSingleCarOnDiscContent(RemoteDatabase db, int carId)
        {
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_OnDiscContent AS SELECT * FROM OnDiscContent;");
            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "ContentId", BuildDataCarContentIdExpression(db, "Data_Car"));
            AddInsertColumn(columns, values, "ContentType", "1");
            if (db.ColumnExists("OnDiscContent", "ReleaseOrder"))
                AddInsertColumn(columns, values, "ReleaseOrder", "COALESCE((SELECT MAX(ReleaseOrder) FROM OnDiscContent WHERE ContentType = 1), 0)");

            ExecuteAutoshowSql(db,
                "INSERT OR IGNORE INTO OnDiscContent (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE Data_Car.Id = " + carId.ToString(CultureInfo.InvariantCulture) + " " +
                "AND NOT EXISTS (SELECT 1 FROM OnDiscContent WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) = " + BuildDataCarContentIdExpression(db, "Data_Car") + ");");
        }

        private bool TryInsertSingleGarageCar(RemoteDatabase db, int carId)
        {
            var garageTable = ResolveActiveGarageTable(db);
            if (!db.TableExists(garageTable) || !db.ColumnExists(garageTable, "CarId"))
                return false;

            var garageSql = EscapeIdentifierForSql(garageTable);
            var carIdSql = carId.ToString(CultureInfo.InvariantCulture);
            var before = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + carIdSql) ?? 0;
            if (before > 0)
                return false;

            var garageColumns = GetTableColumns(db, garageTable);
            var dataColumns = new HashSet<string>(GetTableColumns(db, "Data_Car"), StringComparer.OrdinalIgnoreCase);
            var stockExpressions = BuildStockGarageExpressions(db);
            var insertColumns = new List<string>();
            var selectValues = new List<string>();

            foreach (var column in garageColumns)
            {
                if (string.Equals(column, "Id", StringComparison.OrdinalIgnoreCase))
                    continue;

                string expression;
                if (!TryBuildGarageInsertExpression(db, garageTable, column, dataColumns, stockExpressions, out expression))
                    continue;

                insertColumns.Add(EscapeIdentifierForSql(column));
                selectValues.Add(expression);
            }

            if (!insertColumns.Any(c => string.Equals(c, EscapeIdentifierForSql("CarId"), StringComparison.OrdinalIgnoreCase)))
                throw new InvalidOperationException(garageTable + ".CarId was not available for direct insert.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_DirectGarageInsert_" + EscapeIdentifierForSql(garageTable).Replace("[", string.Empty).Replace("]", string.Empty) + " AS SELECT rowid AS _rowid_, * FROM " + garageSql + ";");
            ExecuteAutoshowSql(
                db,
                "INSERT INTO " + garageSql + " (" + string.Join(", ", insertColumns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", selectValues.ToArray()) + " FROM Data_Car " +
                "WHERE Data_Car.Id = " + carIdSql + " " +
                "AND NOT EXISTS (SELECT 1 FROM " + garageSql + " WHERE CarId = Data_Car.Id);");

            var after = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + carIdSql) ?? 0;
            return after > before;
        }

        private static List<string> GetTableColumns(RemoteDatabase db, string tableName)
        {
            var result = db.Query("PRAGMA table_info(" + EscapeIdentifierForSql(tableName) + ")");
            var columns = new List<string>();
            foreach (var row in result.Rows)
            {
                if (row.Count > 1)
                {
                    var name = Convert.ToString(row[1], CultureInfo.InvariantCulture);
                    if (!string.IsNullOrWhiteSpace(name))
                        columns.Add(name);
                }
            }
            return columns;
        }

