        private static void AddOrdinalStockExpression(RemoteDatabase db, Dictionary<string, string> expressions, string garageColumn, string tableName, string fallback)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "Id") || !db.ColumnExists(tableName, "Ordinal"))
                return;

            var stockFilter = db.ColumnExists(tableName, "IsStock") ? " AND COALESCE([IsStock], 0) = 1" : string.Empty;
            expressions[garageColumn] = "COALESCE((SELECT [Id] FROM " + EscapeIdentifierForSql(tableName) + " WHERE [Ordinal] = Data_Car.[Id]" + stockFilter + " ORDER BY [Id] LIMIT 1), " + fallback + ")";
        }

        private static void AddEngineStockExpression(RemoteDatabase db, Dictionary<string, string> expressions, string garageColumn, string tableName, string fallback)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "Id") || !db.ColumnExists(tableName, "EngineID") ||
                !db.TableExists("List_UpgradeEngine") || !db.ColumnExists("List_UpgradeEngine", "EngineID") || !db.ColumnExists("List_UpgradeEngine", "Ordinal"))
                return;

            var stockFilter = db.ColumnExists(tableName, "IsStock") ? " AND COALESCE(part.[IsStock], 0) = 1" : string.Empty;
            var engineStockFilter = db.ColumnExists("List_UpgradeEngine", "IsStock") ? " AND COALESCE(engine.[IsStock], 0) = 1" : string.Empty;
            var engineFallback = db.ColumnExists("Data_Car", "EngineConfigID") ? "Data_Car.[EngineConfigID]" : "0";
            var engineId =
                "COALESCE((SELECT engine.[EngineID] FROM [List_UpgradeEngine] engine WHERE engine.[Ordinal] = Data_Car.[Id]" + engineStockFilter + " ORDER BY engine.[Id] LIMIT 1), " + engineFallback + ")";
            expressions[garageColumn] =
                "COALESCE((SELECT part.[Id] FROM " + EscapeIdentifierForSql(tableName) + " part WHERE part.[EngineID] = " + engineId + stockFilter + " ORDER BY part.[Id] LIMIT 1), " + fallback + ")";
        }

        private static void AddDrivetrainStockExpression(RemoteDatabase db, Dictionary<string, string> expressions, string garageColumn, string tableName, string fallback)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "Id") || !db.ColumnExists(tableName, "DrivetrainID") ||
                !db.TableExists("List_UpgradeDrivetrain") || !db.ColumnExists("List_UpgradeDrivetrain", "DrivetrainID") || !db.ColumnExists("List_UpgradeDrivetrain", "Ordinal"))
                return;

            var stockFilter = db.ColumnExists(tableName, "IsStock") ? " AND COALESCE(part.[IsStock], 0) = 1" : string.Empty;
            var drivetrainStockFilter = db.ColumnExists("List_UpgradeDrivetrain", "IsStock") ? " AND COALESCE(drivetrain.[IsStock], 0) = 1" : string.Empty;
            var drivetrainFallback = db.ColumnExists("Data_Car", "DriveTypeID") ? "Data_Car.[DriveTypeID]" : "0";
            var drivetrainId =
                "COALESCE((SELECT drivetrain.[DrivetrainID] FROM [List_UpgradeDrivetrain] drivetrain WHERE drivetrain.[Ordinal] = Data_Car.[Id]" + drivetrainStockFilter + " ORDER BY drivetrain.[Id] LIMIT 1), " + drivetrainFallback + ")";
            expressions[garageColumn] =
                "COALESCE((SELECT part.[Id] FROM " + EscapeIdentifierForSql(tableName) + " part WHERE part.[DrivetrainID] = " + drivetrainId + stockFilter + " ORDER BY part.[Id] LIMIT 1), " + fallback + ")";
        }

        private static bool TryBuildGarageInsertExpression(RemoteDatabase db, string garageTable, string column, HashSet<string> dataColumns, Dictionary<string, string> stockExpressions, out string expression)
        {
            expression = null;
            if (string.Equals(column, "CarId", StringComparison.OrdinalIgnoreCase))
            {
                expression = "Data_Car.Id";
                return true;
            }

            if (stockExpressions != null && stockExpressions.TryGetValue(column, out expression))
                return true;

            if (string.Equals(column, "ClassID", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "ClassId", StringComparison.OrdinalIgnoreCase))
            {
                var piExpr = dataColumns.Contains("PerformanceIndex") ? "Data_Car." + EscapeIdentifierForSql("PerformanceIndex") : "0";
                var fallback = dataColumns.Contains("ClassID") ? "Data_Car." + EscapeIdentifierForSql("ClassID") : "0";
                expression = BuildPerformanceClassExpression(db, piExpr, fallback);
                return true;
            }

            if (dataColumns.Contains(column))
            {
                expression = "Data_Car." + EscapeIdentifierForSql(column);
                return true;
            }

            if (string.Equals(column, "TopSpeed", StringComparison.OrdinalIgnoreCase))
            {
                var candidates = new List<string>();
                if (dataColumns.Contains("SimTopSpeed"))
                    candidates.Add("Data_Car." + EscapeIdentifierForSql("SimTopSpeed"));
                if (dataColumns.Contains("TopSpeed-mph"))
                    candidates.Add("Data_Car." + EscapeIdentifierForSql("TopSpeed-mph"));
                candidates.Add("0");
                expression = "COALESCE(" + string.Join(", ", candidates.ToArray()) + ")";
                return true;
            }

            if (string.Equals(column, "Guid", StringComparison.OrdinalIgnoreCase))
            {
                expression = "lower(hex(randomblob(4))) || '-' || lower(hex(randomblob(2))) || '-' || lower(hex(randomblob(2))) || '-' || lower(hex(randomblob(2))) || '-' || lower(hex(randomblob(6)))";
                return true;
            }

            if (string.Equals(column, "OriginalOwner", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "LiveryFileName", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "TuneFileName", StringComparison.OrdinalIgnoreCase))
            {
                expression = "''";
                return true;
            }

            if (string.Equals(column, "VersionedTuneId", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "VersionedLiveryId", StringComparison.OrdinalIgnoreCase))
            {
                expression = "'00000000-0000-0000-0000-000000000000'";
                return true;
            }

            if (string.Equals(column, "HasCurrentOwnerViewedCar", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "NumOwners", StringComparison.OrdinalIgnoreCase))
            {
                expression = "1";
                return true;
            }

            if (string.Equals(column, "FrontTireAspectRatioOffset", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(column, "RearTireAspectRatioOffset", StringComparison.OrdinalIgnoreCase))
            {
                expression = "-1";
                return true;
            }

            if (IsZeroGarageColumn(column))
            {
                expression = "0";
                return true;
            }

            expression = "(SELECT " + EscapeIdentifierForSql(column) + " FROM " + EscapeIdentifierForSql(garageTable) + " WHERE " + EscapeIdentifierForSql(column) + " IS NOT NULL ORDER BY rowid LIMIT 1)";
            return true;
        }

        private static bool IsZeroGarageColumn(string column)
        {
            switch (column)
            {
                case "PartsValue":
                case "PeakIntakePSI":
                case "DistanceDriven":
                case "TimeDriven":
                case "TotalWinnings":
                case "TotalRepairs":
                case "NumVictories":
                case "NumPodiums":
                case "NumRaces":
                case "NumTimesSold":
                case "TimeDrivenInRoadTrips":
                case "CurOwnerNumRaces":
                case "CurOwnerWinnings":
                case "NumSkillPointsEarned":
                case "HighestSkillScore":
                case "Flags":
                case "DefaultManufacturerColorIndex":
                case "VersionedTuneXUID":
                case "SharedID":
                case "IsFavorite":
                    return true;
                default:
                    return false;
            }
        }

        private static int ToInt(object value)
        {
            if (value == null)
                return 0;
            if (value is int)
                return (int)value;
            if (value is long)
                return (int)(long)value;
            if (value is double)
                return (int)(double)value;
            int parsed;
            return int.TryParse(Convert.ToString(value, CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : 0;
        }

        private static long ToLong(object value)
        {
            if (value == null)
                return 0;
            if (value is long)
                return (long)value;
            if (value is int)
                return (int)value;
            if (value is double)
                return (long)(double)value;
            long parsed;
            return long.TryParse(Convert.ToString(value, CultureInfo.InvariantCulture), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : 0;
        }

        private static string ToDisplayString(object value)
        {
            if (value == null)
                return string.Empty;
            var formattable = value as IFormattable;
            if (formattable != null)
                return formattable.ToString(null, CultureInfo.InvariantCulture);
            return Convert.ToString(value, CultureInfo.InvariantCulture) ?? string.Empty;
        }

        private static string FormatCarNumber(object value)
        {
            if (value == null)
                return string.Empty;
            if (value is double)
                return ((double)value).ToString("0.###", CultureInfo.InvariantCulture);
            if (value is float)
                return ((float)value).ToString("0.###", CultureInfo.InvariantCulture);
            return ToDisplayString(value);
        }

        private static string FormatWholeNumber(object value)
        {
            if (value == null)
                return "0";
            if (value is double)
                return ((long)(double)value).ToString(CultureInfo.InvariantCulture);
            if (value is float)
                return ((long)(float)value).ToString(CultureInfo.InvariantCulture);
            if (value is int)
                return ((int)value).ToString(CultureInfo.InvariantCulture);
            if (value is long)
                return ((long)value).ToString(CultureInfo.InvariantCulture);
            long parsed;
            return long.TryParse(ToDisplayString(value), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed.ToString(CultureInfo.InvariantCulture) : "0";
        }

        private static string FormatRarityBand(object value)
        {
            double rarity;
            if (!TryToDouble(value, out rarity))
                return string.Empty;
            return FormatRarityBandName(rarity) + " (" + rarity.ToString("0.###", CultureInfo.InvariantCulture) + ")";
        }

        private static string FormatRarityBandName(double rarity)
        {
            if (rarity <= 0.49)
                return "Common / normal garage car";
            if (rarity < 1.5)
                return "Common+ / slightly rarer";
            if (rarity < 2.5)
                return "Uncommon / low rarity";
            if (rarity < 3.5)
                return "Rare / reward-leaning";
            if (rarity < 4.5)
                return "Rare+ / collectible";
            if (rarity < 5.5)
                return "Epic / mid-high rarity";
            if (rarity < 6.5)
                return "Epic+ / harder to find";
            if (rarity < 7.5)
                return "Legendary / high rarity";
            if (rarity < 8.5)
                return "Legendary+ / very rare";
            if (rarity < 9.5)
                return "Exclusive / hard-to-find";
            return "Ultra rare / max rarity";
        }

        private static string FormatRarityFlag(object value)
        {
            var text = ToDisplayString(value).Trim();
            if (text.Length == 0)
                return "Not set";
            return string.Equals(text, "0", StringComparison.OrdinalIgnoreCase) ? "Default flag (0)" : "Flag " + text;
        }

        private static string FormatCarClassId(int classId)
        {
            switch (classId)
            {
                case 0: return "D (0)";
                case 1: return "C (1)";
                case 2: return "B (2)";
                case 3: return "A (3)";
                case 4: return "S1 (4)";
                case 5: return "S2 (5)";
                case 6: return "R (6)";
                case 7: return "X (7)";
                default: return "Class " + classId.ToString(CultureInfo.InvariantCulture);
            }
        }

        private static int ParseClassIdFromDisplay(string text)
        {
            text = (text ?? string.Empty).Trim();
            if (text.Length == 0)
                return 0;
            if (text.StartsWith("D", StringComparison.OrdinalIgnoreCase))
                return 0;
            if (text.StartsWith("C", StringComparison.OrdinalIgnoreCase))
                return 1;
            if (text.StartsWith("B", StringComparison.OrdinalIgnoreCase))
                return 2;
            if (text.StartsWith("A", StringComparison.OrdinalIgnoreCase))
                return 3;
            if (text.StartsWith("S1", StringComparison.OrdinalIgnoreCase))
                return 4;
            if (text.StartsWith("S2", StringComparison.OrdinalIgnoreCase))
                return 5;
            if (text.StartsWith("R", StringComparison.OrdinalIgnoreCase))
                return 6;
            if (text.StartsWith("X", StringComparison.OrdinalIgnoreCase))
                return 7;
            var digits = new string(text.Where(char.IsDigit).ToArray());
            int parsed;
            return int.TryParse(digits, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : 0;
        }

        private static string FormatDriveTypeId(int driveTypeId)
        {
            switch (driveTypeId)
            {
                case 1: return "FWD";
                case 2: return "RWD";
                case 3: return "AWD";
                default: return "DriveType " + driveTypeId.ToString(CultureInfo.InvariantCulture);
            }
        }

        private static bool TryToDouble(object value, out double parsed)
        {
            if (value is double)
            {
                parsed = (double)value;
                return true;
            }
            if (value is float)
            {
                parsed = (float)value;
                return true;
            }
            if (value is int)
            {
                parsed = (int)value;
                return true;
            }
            if (value is long)
            {
                parsed = (long)value;
                return true;
            }
            return double.TryParse(ToDisplayString(value), NumberStyles.Float, CultureInfo.InvariantCulture, out parsed);
        }

        private string GetTextBoxValue(TextBox box)
        {
            if (box == null)
                return string.Empty;
            if (box.InvokeRequired)
                return (string)box.Invoke(new Func<TextBox, string>(GetTextBoxValue), box);
            return box.Text ?? string.Empty;
        }

        private void SetTextBoxValue(TextBox box, string value)
        {
            if (box == null)
                return;
            if (box.InvokeRequired)
            {
                box.BeginInvoke((Action)(delegate { SetTextBoxValue(box, value); }));
                return;
            }
            box.Text = value ?? string.Empty;
        }

        private static string CleanCarText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return "";
            text = text.Trim();
            if (text.Length > 96)
                return text.Substring(0, 96);
            return text;
        }

        private void ApplyProfileRuntimeHook(RuntimeProfileFeature feature, string label, string text, bool enabled)
        {
            if (feature == RuntimeProfileFeature.RoadWetnessPuddleControl)
            {
                ApplyRoadWetnessPuddleControl(label, text, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.SuperGrip)
            {
                ApplySuperGripHook(text, enabled);
                return;
            }


            if (feature == RuntimeProfileFeature.PhaseDash)
            {
                ApplyPhaseDashRuntimeHook(enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.Rewind)
            {
                ApplyRewindRuntimeHook(enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.GrapplingHook)
            {
                ApplyGrapplingHookRuntimeHook(enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.XpGain)
            {
                ApplyXpGainHook(label, text, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.CruiseControl)
            {
                ApplyCruiseControlHook(label, text, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.AccelerationRamp)
            {
                ApplyAccelerationRampHook(label, text, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.TopSpeedCap)
            {
                ApplyTopSpeedCapHook(label, text, enabled);
                return;
            }

            var value = 0;
            var displayValue = string.Empty;
            var parsedMultiplier = 0F;
            if (enabled && RuntimeFeatureRequiresValue(feature))
            {
                if (IsFloatRuntimeFeature(feature))
                {
            if (feature == RuntimeProfileFeature.Acceleration)
            {
                var requestedMultiplier = ParsePositiveFloat(text, label);
                parsedMultiplier = _accelerationUsePercentage
                    ? Math.Max(1F, Math.Min(MaxAccelerationPercentMultiplier, requestedMultiplier))
                    : NormalizeAccelerationMultiplier(requestedMultiplier);
                displayValue = "x" + FormatFloat(parsedMultiplier);
                if (!_accelerationUsePercentage && Math.Abs(requestedMultiplier - parsedMultiplier) > 0.0001F)
                    displayValue += " from requested x" + FormatFloat(requestedMultiplier);
            }
                    else
                    {
                        parsedMultiplier = ParseRuntimeFloatValue(feature, text, label);
                        displayValue = FormatRuntimeValueForLog(feature, parsedMultiplier);
                    }
                    value = BitConverter.ToInt32(BitConverter.GetBytes(parsedMultiplier), 0);
                }
                else
                {
                    var parsed = ParseNonNegativeLong(text, label);
                    if (parsed > int.MaxValue)
                        throw new InvalidOperationException(label + " must be " + int.MaxValue + " or lower for the runtime hook.");
                    value = (int)parsed;
                    displayValue = value.ToString(CultureInfo.InvariantCulture);
                }
            }

            var db = RequireDatabase();
            if (feature == RuntimeProfileFeature.SuperBrake || feature == RuntimeProfileFeature.AdaptiveBrake)
                db.SetBrakeVirtualKey(_brakeVirtualKey);
            db.ApplyProfileRuntimeHook(feature, value, enabled);
            Log(label + " runtime hook " + (enabled ? (RuntimeFeatureRequiresValue(feature) ? "ON with value " + displayValue : "ON") : "OFF") + ".");
        }

        private void ApplySuperGripHook(string text, bool enabled)
        {
            var strength = "100";
            if (enabled && !string.IsNullOrWhiteSpace(text))
                strength = text.Trim();

            ApplyProfileRuntimeHook(RuntimeProfileFeature.NoWaterDrag, "No Water Drag", string.Empty, enabled);
            ApplyProfileRuntimeHook(RuntimeProfileFeature.SuperHandling, "Super Handling", strength, enabled);
            ApplyProfileRuntimeHook(RuntimeProfileFeature.LandingStabilizer, "Landing Stabilizer", strength, enabled);
            ApplyProfileRuntimeHook(RuntimeProfileFeature.SlideCalmer, "Slide Calmer", strength, enabled);

            Log("Super Grip " + (enabled ? "ON (No Water Drag + Super Handling + Landing Stabilizer + Slide Calmer at " + strength + "%)" : "OFF") + ".");
        }

        private void ApplyTrailblazerTimer(string label, string text, bool enabled)
        {
            var db = RequireDatabase();
            if (!enabled)
            {
                db.ApplyTrailblazerTimerScale(1F, false);
                Log(label + " OFF. Live countdown control stopped.");
                return;
            }

            var scale = ParseRuntimeFloatValue(RuntimeProfileFeature.TrailblazerMultiplier, text, label);
            if (float.IsNaN(scale) || float.IsInfinity(scale) || scale < -10F || scale > 10F)
                throw new InvalidOperationException(label + " expects a value from -10 to 10. Negative values slow the countdown; 1 is normal.");

            var count = db.ApplyTrailblazerTimerScale(scale, true);
            Log(label + " ON with value " + FormatFloat(scale) + ". Live countdown field(s) found: " + count.ToString(CultureInfo.InvariantCulture) + ".");
        }

        private void ApplyRoadWetnessPuddleControl(string label, string text, bool enabled)
        {
            var db = RequireDatabase();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id") || !db.ColumnExists("Data_Car", "PuddleScale"))
                throw new InvalidOperationException("Data_Car.PuddleScale was not found in this FH6 database.");

            const string backupName = "_backup_Database_RoadWetness_DataCar";
            if (!enabled)
            {
                RestoreDataCarColumnBackup(db, "PuddleScale", backupName);
                Log(label + " restored Data_Car.PuddleScale from backup.");
                return;
            }

            var value = ParseRuntimeFloatValue(RuntimeProfileFeature.RoadWetnessPuddleControl, text, label);
            if (value < 0F)
                throw new InvalidOperationException(label + " must be 0 or higher.");
            var valueSql = value.ToString("0.######", CultureInfo.InvariantCulture);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backupName + " AS SELECT Id, PuddleScale FROM Data_Car;");
            ExecuteAutoshowSql(db, "UPDATE Data_Car SET PuddleScale = " + valueSql + " WHERE Id IS NOT NULL AND PuddleScale IS NOT NULL;");
            LogCount(db, label + " puddle rows", "SELECT count(*) FROM Data_Car WHERE PuddleScale IS NOT NULL AND ABS(CAST(PuddleScale AS REAL) - " + valueSql + ") < 0.0001");
            Log(label + " database control ON with PuddleScale " + valueSql + ". Switch cars or reload the world if FH6 has cached the current car/environment.");
        }

        private void ApplyBackfireFlameControl(string label, string text, bool enabled)
        {
            var db = RequireDatabase();
            if (!enabled)
            {
                RestoreGenericFullTableBackup(db, "Data_Engine", "_backup_Database_Backfire_DataEngine");
                RestoreGenericFullTableBackup(db, "BackfireLevels", "_backup_Database_Backfire_Levels");
                Log(label + " restored backfire tables from backup.");
                return;
            }

            var value = ParseRuntimeFloatValue(RuntimeProfileFeature.BackfireFlameControl, text, label);
            if (value < 0F)
                throw new InvalidOperationException(label + " must be 0 or higher.");
            var valueSql = value.ToString("0.######", CultureInfo.InvariantCulture);
            var touched = 0;

            if (db.TableExists("Data_Engine"))
            {
                var setParts = new List<string>();
                AddSetIfColumnExists(db, "Data_Engine", setParts, "BackfireIntensityScalar", valueSql);
                AddSetIfColumnExists(db, "Data_Engine", setParts, "BackfireSootToFireRatioScalar", valueSql);
                if (setParts.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_Backfire_DataEngine AS SELECT rowid AS _rowid_, * FROM Data_Engine;");
                    ExecuteAutoshowSql(db, "UPDATE Data_Engine SET " + string.Join(", ", setParts.ToArray()) + ";");
                    touched++;
                }
            }

            if (db.TableExists("BackfireLevels") && db.ColumnExists("BackfireLevels", "BackfireLevel"))
            {
                var level = Math.Max(0, Math.Min(10, (int)Math.Round(value)));
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_Backfire_Levels AS SELECT rowid AS _rowid_, * FROM BackfireLevels;");
                ExecuteAutoshowSql(db, "UPDATE BackfireLevels SET BackfireLevel = " + level.ToString(CultureInfo.InvariantCulture) + ";");
                touched++;
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported Backfire tables/columns were found.");

            Log(label + " database control ON with scalar " + valueSql + ". Switch cars or reload the car if FH6 has cached exhaust effects.");
        }

        private static void AddSetIfColumnExists(RemoteDatabase db, string tableName, List<string> setParts, string columnName, string valueSql)
        {
            if (db.ColumnExists(tableName, columnName))
                setParts.Add(EscapeIdentifierForSql(columnName) + " = " + valueSql);
        }

        private void RestoreGenericFullTableBackup(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName))
                return;

            var columns = GetTableColumns(db, tableName);
            if (columns.Count == 0)
                return;

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var columnList = string.Join(", ", columns.Select(EscapeIdentifierForSql).ToArray());
            ExecuteAutoshowSql(db, "DELETE FROM " + tableSql + ";");
            ExecuteAutoshowSql(db, "INSERT INTO " + tableSql + " (" + columnList + ") SELECT " + columnList + " FROM " + backupSql + ";");
            ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS " + backupSql + ";");
        }

        private static string SanitizeSqlName(string value)
        {
            var source = value ?? string.Empty;
            var sb = new StringBuilder(source.Length);
            foreach (var ch in source)
                sb.Append(char.IsLetterOrDigit(ch) || ch == '_' ? ch : '_');
            return sb.Length == 0 ? "Table" : sb.ToString();
        }

