        private void UpdateChargeJumpOverlayPercent(float percent)
        {
            if (InvokeRequired)
            {
                try
                {
                    BeginInvoke(new Action<float>(UpdateChargeJumpOverlayPercent), percent);
                }
                catch
                {
                }
                return;
            }

            var clamped = percent;
            if (!IsFiniteFloat(clamped))
                clamped = 0F;
            if (clamped < 0F) clamped = 0F;
            if (clamped > 100F) clamped = 100F;
            var whole = (int)Math.Round(clamped);
            if (System.Threading.Interlocked.Exchange(ref _chargeJumpOverlayPercent, whole) != whole)
                RequestFeatureOverlayRefresh();

            if (whole > 0)
                ShowChargeJumpMeter(whole);
            else
                HideChargeJumpMeter();
        }

        private void ShowChargeJumpMeter(int percent)
        {
            if (_chargeJumpMeterForm == null || _chargeJumpMeterForm.IsDisposed)
            {
                _chargeJumpMeterForm = new ChargeJumpMeterForm(AppBackground, Surface, SurfaceAlt, Border, TextPrimary, TextMuted, AccentBlue, AccentPurple, AccentGreen);
                _chargeJumpMeterForm.StartPosition = FormStartPosition.Manual;
                _chargeJumpMeterForm.Location = new Point(
                    Math.Max(0, Left + (Width - _chargeJumpMeterForm.Width) / 2),
                    Math.Max(0, Top + 120));
            }

            _chargeJumpMeterForm.SetPercent(percent);
            if (!_chargeJumpMeterForm.Visible)
                _chargeJumpMeterForm.Show(this);
            else
                _chargeJumpMeterForm.BringToFront();
        }

        private void HideChargeJumpMeter()
        {
            if (_chargeJumpMeterForm != null && !_chargeJumpMeterForm.IsDisposed)
                _chargeJumpMeterForm.Hide();
        }

        private void ApplyXpGainHook(string label, string text, bool enabled)
        {
            var db = RequireDatabase();
            if (!enabled)
            {
                db.SetXpGainRuntimeHook(false, 0, 1000, true);
                Log(label + " OFF.");
                return;
            }

            int amount;
            int speedMs;
            int fireCount;
            int xpAmount;
            bool whilePlaying;
            ParseXpGainConfig(text, out amount, out speedMs, out whilePlaying, out fireCount, out xpAmount);
            if (amount < 0)
                throw new InvalidOperationException(label + " needs a whole number of skill points 0 or greater.");

            db.SetXpGainRuntimeHook(true, amount, speedMs, whilePlaying, fireCount);
            Log(label + " ON: " + xpAmount.ToString(CultureInfo.InvariantCulture) + " XP (" +
                amount.ToString(CultureInfo.InvariantCulture) + " skill point(s)) every " +
                speedMs.ToString(CultureInfo.InvariantCulture) + " ms, " +
                (fireCount > 0 ? fireCount.ToString(CultureInfo.InvariantCulture) + " fire(s)" : "continuous") +
                " (" + (whilePlaying ? "auto while playing" : "on pause/resume") +
                "). Spend one skill point in the perk menu once to arm it.");
        }

        private static void ParseXpGainConfig(string text, out int amount, out int speedMs, out bool whilePlaying)
        {
            int fireCount;
            int xpAmount;
            bool useSkillPointMode;
            ParseXpGainConfig(text, out amount, out speedMs, out whilePlaying, out fireCount, out xpAmount, out useSkillPointMode);
        }

        private static void ParseXpGainConfig(string text, out int amount, out int speedMs, out bool whilePlaying, out int fireCount, out int xpAmount)
        {
            bool useSkillPointMode;
            ParseXpGainConfig(text, out amount, out speedMs, out whilePlaying, out fireCount, out xpAmount, out useSkillPointMode);
        }

        private static void ParseXpGainConfig(string text, out int amount, out int speedMs, out bool whilePlaying, out int fireCount, out int xpAmount, out bool useSkillPointMode)
        {
            amount = 50;
            speedMs = 1000;
            whilePlaying = true;
            fireCount = 0;
            xpAmount = amount * XpGainXpPerSkillPoint;
            useSkillPointMode = false;
            var parts = (text ?? string.Empty).Split('/');
            if (parts.Length >= 1)
            {
                int a;
                if (int.TryParse(parts[0].Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out a) && a >= 0)
                    amount = a;
            }
            xpAmount = amount * XpGainXpPerSkillPoint;
            if (parts.Length >= 2)
            {
                int s;
                if (int.TryParse(parts[1].Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out s))
                    speedMs = Math.Max(100, Math.Min(10000, s));
            }
            if (parts.Length >= 3)
                whilePlaying = parts[2].Trim() != "0";
            if (parts.Length >= 4)
            {
                int f;
                if (int.TryParse(parts[3].Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out f))
                    fireCount = Math.Max(0, Math.Min(100000, f));
            }
            if (parts.Length >= 5)
            {
                int x;
                if (int.TryParse(parts[4].Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out x) && x >= 0)
                    xpAmount = x;
            }
            if (xpAmount > 0 && xpAmount % XpGainXpPerSkillPoint == 0)
                amount = xpAmount / XpGainXpPerSkillPoint;
            else
                xpAmount = amount * XpGainXpPerSkillPoint;
            if (parts.Length >= 6)
            {
                var mode = (parts[5] ?? string.Empty).Trim();
                useSkillPointMode =
                    string.Equals(mode, "sp", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(mode, "skill", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(mode, "skillpoints", StringComparison.OrdinalIgnoreCase);
            }
        }

