        private void NormalizeRewindConfig()
        {
            if (!IsFiniteFloat(_rewindBufferSeconds) || _rewindBufferSeconds < 2F || _rewindBufferSeconds > 30F)
                _rewindBufferSeconds = DefaultRewindBufferSeconds;
            if (!IsFiniteFloat(_rewindScrubSpeed) || _rewindScrubSpeed < 0.25F || _rewindScrubSpeed > 5F)
                _rewindScrubSpeed = DefaultRewindScrubSpeed;
        }

        private void NormalizeGrapplingHookConfig()
        {
            if (!IsFiniteFloat(_grapplingHookTargetDistance) || _grapplingHookTargetDistance < 10F || _grapplingHookTargetDistance > 1000F)
                _grapplingHookTargetDistance = DefaultGrapplingHookTargetDistance;
            if (!IsFiniteFloat(_grapplingHookMinimumSpeed) || _grapplingHookMinimumSpeed < 1F || _grapplingHookMinimumSpeed > 500F)
                _grapplingHookMinimumSpeed = DefaultGrapplingHookMinimumSpeed;
            if (!IsFiniteFloat(_grapplingHookMaximumSpeed) || _grapplingHookMaximumSpeed < 1F || _grapplingHookMaximumSpeed > 700F)
                _grapplingHookMaximumSpeed = DefaultGrapplingHookMaximumSpeed;
            if (!IsFiniteFloat(_grapplingHookRampPerSecond) || _grapplingHookRampPerSecond < 0F || _grapplingHookRampPerSecond > 1000F)
                _grapplingHookRampPerSecond = DefaultGrapplingHookRampPerSecond;
            if (!IsFiniteFloat(_grapplingHookVerticalScale) || _grapplingHookVerticalScale < 0F || _grapplingHookVerticalScale > 1.5F)
                _grapplingHookVerticalScale = DefaultGrapplingHookVerticalScale;

            if (_grapplingHookMaximumSpeed < _grapplingHookMinimumSpeed)
                _grapplingHookMaximumSpeed = _grapplingHookMinimumSpeed;
        }

        private void NormalizeChargeJumpConfig()
        {
            if (!IsFiniteFloat(_chargeJumpMaxSeconds) || _chargeJumpMaxSeconds < 0.25F || _chargeJumpMaxSeconds > 6F)
                _chargeJumpMaxSeconds = DefaultChargeJumpMaxSeconds;
            if (!IsFiniteFloat(_chargeJumpVerticalForce) || _chargeJumpVerticalForce < 1F || _chargeJumpVerticalForce > 250F)
                _chargeJumpVerticalForce = DefaultChargeJumpVerticalForce;
            if (!IsFiniteFloat(_chargeJumpForwardForce) || _chargeJumpForwardForce < 0F || _chargeJumpForwardForce > 500F)
                _chargeJumpForwardForce = DefaultChargeJumpForwardForce;
        }

