        private static bool TryParseFovDegrees(string text, out float degrees)
        {
            degrees = DefaultFovDegrees;
            float parsed;
            if (!float.TryParse((text ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out parsed))
                return false;
            if (!IsFiniteFloat(parsed) || parsed < MinimumFovDegrees || parsed > MaximumFovDegrees)
                return false;
            degrees = parsed;
            return true;
        }

        private static float NormalizeFovDegrees(float degrees)
        {
            if (!IsFiniteFloat(degrees))
                return DefaultFovDegrees;
            if (degrees < MinimumFovDegrees)
                return MinimumFovDegrees;
            if (degrees > MaximumFovDegrees)
                return MaximumFovDegrees;
            return degrees;
        }

        private void NormalizeFovConfig()
        {
            _fovAllDegrees = NormalizeFovDegrees(_fovAllDegrees);
            _fovDashboardDegrees = NormalizeFovDegrees(_fovDashboardDegrees);
            _fovChaseDegrees = NormalizeFovDegrees(_fovChaseDegrees);
            _fovFarChaseDegrees = NormalizeFovDegrees(_fovFarChaseDegrees);
            _fovHoodDegrees = NormalizeFovDegrees(_fovHoodDegrees);
            _fovBumperDegrees = NormalizeFovDegrees(_fovBumperDegrees);
        }

        private string BuildFovConfigSummary()
        {
            NormalizeFovConfig();
            if (_fovControlAll)
                return "all cameras " + FormatFloat(_fovAllDegrees) + " degrees";

            return "Dashboard " + FormatFloat(_fovDashboardDegrees) +
                ", Chase " + FormatFloat(_fovChaseDegrees) +
                ", Far Chase " + FormatFloat(_fovFarChaseDegrees) +
                ", Hood " + FormatFloat(_fovHoodDegrees) +
                ", Bumper " + FormatFloat(_fovBumperDegrees);
        }

