        private void NormalizeSuperStrengthConfig()
        {
            if (!IsFiniteFloat(_superStrengthShoveSpeed) || _superStrengthShoveSpeed <= 0F || _superStrengthShoveSpeed > 500F)
                _superStrengthShoveSpeed = DefaultSuperStrengthShoveSpeed;
            if (!IsFiniteFloat(_superStrengthMinSpeed) || _superStrengthMinSpeed <= 0F || _superStrengthMinSpeed > 500F)
                _superStrengthMinSpeed = DefaultSuperStrengthMinSpeed;
            if (!IsFiniteFloat(_superStrengthMaxSpeed) || _superStrengthMaxSpeed <= 0F || _superStrengthMaxSpeed > 500F)
                _superStrengthMaxSpeed = DefaultSuperStrengthMaxSpeed;
            if (!IsFiniteFloat(_superStrengthAccelerationPerSecond) || _superStrengthAccelerationPerSecond < 0F || _superStrengthAccelerationPerSecond > 500F)
                _superStrengthAccelerationPerSecond = DefaultSuperStrengthAccelerationPerSecond;
            if (!IsFiniteFloat(_superStrengthVerticalDamping) || _superStrengthVerticalDamping < 0F || _superStrengthVerticalDamping > 1F)
                _superStrengthVerticalDamping = DefaultSuperStrengthVerticalDamping;
            if (!IsFiniteFloat(_superStrengthVerticalClamp) || _superStrengthVerticalClamp < 0F || _superStrengthVerticalClamp > 100F)
                _superStrengthVerticalClamp = DefaultSuperStrengthVerticalClamp;

            var requiredMax = Math.Max(_superStrengthShoveSpeed, _superStrengthMinSpeed);
            if (_superStrengthMaxSpeed < requiredMax)
                _superStrengthMaxSpeed = requiredMax;
        }

