            var db = RequireDatabase();
            PushAutoRaceConfig(db);
            db.SetTeleportToCheckpointRuntimeHook(enabled, _teleportCheckpointVirtualKey);
            Log("Auto Race runtime hook " + (enabled ? "ON with key " + GetTeleportCheckpointKeyText() : "OFF") + ".");
        }

        private void ApplyCheckpointRecoveryRuntimeHook(bool enabled)
        {
            var db = RequireDatabase();
            db.SetCheckpointRecoveryRuntimeHook(enabled, _checkpointRecoveryVirtualKey);
            Log("Recovery Path runtime hook " + (enabled ? "ON with key " + GetCheckpointRecoveryKeyText() : "OFF") + ".");
        }

        private void ApplyAutoRaceDriveRuntimeHook(bool enabled)
        {
            var db = RequireDatabase();
            if (enabled)
            {
                PushAutoRaceDriveConfig(db);
                db.SetBrakeVirtualKey(_brakeVirtualKey);
                ArmAutoRaceDrivePerformanceHooks(db, true);
            }

            db.SetAutoRaceDriveRuntimeHook(enabled, _autoRaceDriveVirtualKey);

            if (!enabled)
                ArmAutoRaceDrivePerformanceHooks(db, false);

            Log("Auto Race (Drive) " + (enabled
                ? "ON with key " + GetAutoRaceDriveKeyText() + " (cruise " + _autoRaceDriveCruiseKmh.ToString(CultureInfo.InvariantCulture) + " km/h; Acceleration x" + FormatFloat(_autoRaceDriveAccelMultiplier) + ", Adaptive Brake, Super Handling, Landing Stabilizer, Slide Calmer" + (_autoRaceDriveNoWaterDrag ? ", No Water Drag" : "") + "). Press the key in-game to start/stop."
                : "OFF") + ".");
        }

        private void PushAutoRaceDriveConfig(RemoteDatabase db)
        {
            if (db == null)
                return;
            var cruiseKmh = _autoRaceDriveCruiseEnabled ? _autoRaceDriveCruiseKmh : DefaultAutoRaceDriveCruiseKmh;
            var topKmh = _autoRaceDriveTopSpeedEnabled ? _autoRaceDriveTopSpeedKmh : DefaultAutoRaceDriveTopKmh;
            var accel = _autoRaceDriveAccelStrengthEnabled ? _autoRaceDriveAccelStrength : DefaultAutoRaceDriveAccel;
            var accelMultiplier = _autoRaceDriveAccelMultEnabled ? Math.Max(0.1F, _autoRaceDriveAccelMultiplier) : 1F;
            var steer = _autoRaceDriveSteerEnabled ? _autoRaceDriveSteerStrength : DefaultAutoRaceDriveSteer;
            db.AutoRaceDriveCruiseSpeed = Math.Max(1F, cruiseKmh / 3.6F);
            db.AutoRaceDriveMaxSpeed = Math.Max(db.AutoRaceDriveCruiseSpeed, topKmh / 3.6F);
            db.AutoRaceDriveAccelPerSecond = Math.Max(1F, accel * accelMultiplier);
            db.AutoRaceDriveTurnRate = Math.Max(0.1F, steer);
            db.AutoRaceDriveScanIntervalMs = _autoRaceDriveScanEnabled ? _autoRaceDriveScanIntervalMs : DefaultAutoRaceDriveScanMs;
            db.AutoRaceDriveOffWaypointMeters = _autoRaceDriveOffWaypointEnabled ? Math.Max(0F, _autoRaceDriveOffWaypointMeters) : 0F;
        }

        private void ArmAutoRaceDrivePerformanceHooks(RemoteDatabase db, bool enabled)
        {
            if (db == null)
                return;
            ArmAutoRaceDriveFeature(db, RuntimeProfileFeature.NoWaterDrag, 0F, enabled && _autoRaceDriveNoWaterDrag);
            ArmAutoRaceDriveFeature(db, RuntimeProfileFeature.SuperHandling, _autoRaceDriveSuperHandling, enabled && _autoRaceDriveSuperHandlingEnabled);
            ArmAutoRaceDriveFeature(db, RuntimeProfileFeature.LandingStabilizer, _autoRaceDriveLandingStabilizer, enabled && _autoRaceDriveLandingStabilizerEnabled);
            ArmAutoRaceDriveFeature(db, RuntimeProfileFeature.SlideCalmer, _autoRaceDriveSlideCalmer, enabled && _autoRaceDriveSlideCalmerEnabled);
            ArmAutoRaceDriveFeature(db, RuntimeProfileFeature.AdaptiveBrake, _autoRaceDriveAdaptiveBrake, enabled && _autoRaceDriveAdaptiveBrakeEnabled);
        }

        private void ArmAutoRaceDriveFeature(RemoteDatabase db, RuntimeProfileFeature feature, float value, bool enabled)
        {
            try
            {
                var encoded = BitConverter.ToInt32(BitConverter.GetBytes(value), 0);
                db.ApplyProfileRuntimeHook(feature, encoded, enabled);
            }
            catch (Exception ex)
            {
                Log("Auto Race (Drive) could not " + (enabled ? "arm " : "clear ") + GetRuntimeFeatureLabel(feature) + ": " + ex.Message);
            }
        }

        private void PushAutoRaceConfig(RemoteDatabase db)
        {
            if (db == null)
                return;
            db.AutoRaceIntervalMs = _autoRaceIntervalMs;
            db.AutoRaceHoldMs = _autoRaceHoldMs;
            db.AutoRaceResetSpeed = _autoRaceResetSpeed;
        }

        private void ApplyDriftModeRuntimeHook(bool enabled)
        {
            var db = RequireDatabase();
            db.SetDriftModeRuntimeHook(enabled, _driftModeVirtualKey, _driftModeForce);
            Log("Drift Mode runtime hook " + (enabled ? "ON. Hold " + GetDriftModeKeyText() + " and steer (A/D, arrows, or stick) to drift; max strength " + FormatFloat(_driftModeForce) : "OFF") + ".");
        }

        private void ApplyProfileBoostPack(bool enabled)
        {
            if (enabled)
            {
                var xpSkillPoints = Math.Max(1, _profilePackXpGainXp / XpGainXpPerSkillPoint);
                var xpConfig = xpSkillPoints.ToString(CultureInfo.InvariantCulture) + "/1000/1/" +
                    _profilePackXpGainFireCount.ToString(CultureInfo.InvariantCulture) + "/" +
                    _profilePackXpGainXp.ToString(CultureInfo.InvariantCulture) + "/xp";
                ApplyProfileRuntimeHook(RuntimeProfileFeature.Credits, "Credits", _profilePackCredits.ToString(CultureInfo.InvariantCulture), true);
                ApplyProfileRuntimeHook(RuntimeProfileFeature.Wheelspins, "Both Wheelspins", _profilePackWheelspins.ToString(CultureInfo.InvariantCulture), true);
                ApplyProfileRuntimeHook(RuntimeProfileFeature.SkillPoints, "Skill Points", _profilePackSkillPoints.ToString(CultureInfo.InvariantCulture), true);
                ApplyXpGainHook("XP Gain", xpConfig, true);
                Log("Profile Boost Pack ON. Refresh Credits, Both Wheelspins, and Skill Points in-game so FH6 reads the new values. XP Gain is armed for " +
                    _profilePackXpGainXp.ToString(CultureInfo.InvariantCulture) + " XP (" +
                    xpSkillPoints.ToString(CultureInfo.InvariantCulture) + " skill point(s)) " +
                    (_profilePackXpGainFireCount > 0 ? _profilePackXpGainFireCount.ToString(CultureInfo.InvariantCulture) + " fire(s)" : "continuously") +
                    "; spend one skill point once to start it.");
                return;
            }

            ApplyProfileRuntimeHook(RuntimeProfileFeature.Credits, "Credits", string.Empty, false);
            ApplyProfileRuntimeHook(RuntimeProfileFeature.Wheelspins, "Both Wheelspins", string.Empty, false);
            ApplyProfileRuntimeHook(RuntimeProfileFeature.SkillPoints, "Skill Points", string.Empty, false);
            ApplyXpGainHook("XP Gain", string.Empty, false);
            Log("Profile Boost Pack OFF.");
        }

        private void StartAutoMasteryRecordingWorkflow()
        {
            if (!ShowAutoMasteryRecordStartPrompt())
                return;

            CancellationTokenSource source;
            lock (_autoMasteryLock)
            {
                if (_autoMasteryCancel != null)
                {
                    ShowInfo("Auto Mastery is already running.");
                    return;
                }

                source = new CancellationTokenSource();
                _autoMasteryCancel = source;
            }

            SetAutoMasteryButtons(true);
            SetFeaturesStatus("Auto Mastery recording...", AccentPurple);
            Log("Auto Mastery recording starting.");

            ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    ExecuteAutoMasteryRecordingWorkflow(source.Token);
                    SetFeaturesStatus("Auto Mastery recording saved", AccentGreen);
                }
                catch (OperationCanceledException)
                {
                    SetFeaturesStatus("Auto Mastery recording canceled", AccentRed);
                    Log("Auto Mastery recording canceled.");
                }
                catch (Exception ex)
                {
                    SetFeaturesStatus("Auto Mastery recording failed", AccentRed);
                    Log("ERROR: Auto Mastery recording failed: " + ex.Message);
                }
                finally
                {
                    FinishAutoMasteryRecording();
                    lock (_autoMasteryLock)
                    {
                        if (ReferenceEquals(_autoMasteryCancel, source))
                        {
                            _autoMasteryCancel.Dispose();
                            _autoMasteryCancel = null;
                        }
                    }
                    SetAutoMasteryButtons(false);
                }
            });
        }

        private bool ShowAutoMasteryRecordStartPrompt()
        {
