                "Luna will add 10 BMW M2 FE cars first." + Environment.NewLine +
                "When the ready popup appears, click OK, select FH6, then use your mouse to do one full mastery path." + Environment.NewLine + Environment.NewLine +
                "Every left click inside FH6 will be saved. Press F8 when the path is done.";

            return ShowTranslatedMessageBox(this, text, MessageBoxButtons.OKCancel, MessageBoxIcon.Information) == DialogResult.OK;
        }

