        private int? ShowAutoMasteryRunsPrompt(int currentValue)
        {
            if (InvokeRequired)
                return (int?)Invoke(new Func<int, int?>(ShowAutoMasteryRunsPrompt), currentValue);

            using (var dialog = new Form())
            {
                dialog.Text = "Auto Mastery Runs";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(360, 160);

                var title = new Label();
                title.Text = "How many times should Luna replay the macro?";
                title.Font = new Font("Segoe UI Semibold", 10F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                title.Location = new Point(18, 18);
                title.Size = new Size(324, 26);
                dialog.Controls.Add(title);

                var note = new Label();
                note.Text = "Luna adds 10 BMWs per batch, then removes that batch.";
                note.Font = new Font("Segoe UI", 9F);
                note.ForeColor = TextMuted;
                note.BackColor = AppBackground;
                note.Location = new Point(18, 48);
                note.Size = new Size(324, 24);
                dialog.Controls.Add(note);

                var value = new NumericUpDown();
                value.Minimum = 1;
                value.Maximum = 999;
                value.Value = Math.Max(1, Math.Min(999, currentValue));
                value.Location = new Point(18, 82);
                value.Width = 110;
                value.BackColor = SurfaceAlt;
                value.ForeColor = TextPrimary;
                dialog.Controls.Add(value);

                var cancel = MakeButton("Cancel", 134, 112, 96, 32);
                cancel.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(cancel);

                var save = MakeButton("Save", 246, 112, 96, 32);
                MakeAccentButton(save, AccentGreen);
                save.Click += delegate
                {
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(save);
                dialog.AcceptButton = save;
                dialog.CancelButton = cancel;

                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK ? (int?)Convert.ToInt32(value.Value) : null;
            }
        }

