        private static bool IsRuntimeFeatureHotkeySupported(RuntimeProfileFeature feature)
        {
            return feature == RuntimeProfileFeature.FreezeAI ||
                   feature == RuntimeProfileFeature.MissionTimerScale ||
                   feature == RuntimeProfileFeature.RaceTimerScale ||
                   feature == RuntimeProfileFeature.Hover ||
                   feature == RuntimeProfileFeature.Acceleration ||
                   feature == RuntimeProfileFeature.CruiseControl ||
                   feature == RuntimeProfileFeature.AccelerationRamp;
        }

        private int GetRuntimeFeatureHotkeyId(RuntimeProfileFeature feature)
        {
            switch (feature)
            {
                case RuntimeProfileFeature.FreezeAI:
                    return RuntimeHotkeyFreezeAiId;
                case RuntimeProfileFeature.MissionTimerScale:
                    return RuntimeHotkeyMissionTimerId;
                case RuntimeProfileFeature.RaceTimerScale:
                    return RuntimeHotkeyRaceTimerId;
                case RuntimeProfileFeature.Hover:
                    return RuntimeHotkeyFlyId;
                case RuntimeProfileFeature.Acceleration:
                    return RuntimeHotkeyAccelerationId;
                case RuntimeProfileFeature.CruiseControl:
                    return RuntimeHotkeyCruiseControlId;
                case RuntimeProfileFeature.AccelerationRamp:
                    return RuntimeHotkeyAccelRampId;
                default:
                    throw new InvalidOperationException("Unsupported runtime hotkey feature.");
            }
        }

        private RuntimeProfileFeature? GetRuntimeFeatureFromHotkeyId(int hotkeyId)
        {
            switch (hotkeyId)
            {
                case RuntimeHotkeyFreezeAiId:
                    return RuntimeProfileFeature.FreezeAI;
                case RuntimeHotkeyMissionTimerId:
                    return RuntimeProfileFeature.MissionTimerScale;
                case RuntimeHotkeyRaceTimerId:
                    return RuntimeProfileFeature.RaceTimerScale;
                case RuntimeHotkeyFlyId:
                    return RuntimeProfileFeature.Hover;
                case RuntimeHotkeyAccelerationId:
                    return RuntimeProfileFeature.Acceleration;
                case RuntimeHotkeyCruiseControlId:
                    return RuntimeProfileFeature.CruiseControl;
                case RuntimeHotkeyAccelRampId:
                    return RuntimeProfileFeature.AccelerationRamp;
                default:
                    return null;
            }
        }

        private int GetRuntimeFeatureHotkey(RuntimeProfileFeature feature)
        {
            switch (feature)
            {
                case RuntimeProfileFeature.FreezeAI:
                    return _freezeAiHotkeyVirtualKey;
                case RuntimeProfileFeature.MissionTimerScale:
                    return _missionTimerHotkeyVirtualKey;
                case RuntimeProfileFeature.RaceTimerScale:
                    return _raceTimerHotkeyVirtualKey;
                case RuntimeProfileFeature.Hover:
                    return _flyHotkeyVirtualKey;
                case RuntimeProfileFeature.Acceleration:
                    return _accelerationHotkeyVirtualKey;
                case RuntimeProfileFeature.CruiseControl:
                    return _cruiseControlHotkeyVirtualKey;
                case RuntimeProfileFeature.AccelerationRamp:
                    return _accelRampHotkeyVirtualKey;
                default:
                    return 0;
            }
        }

        private void SetRuntimeFeatureHotkey(RuntimeProfileFeature feature, int virtualKey)
        {
            if (virtualKey <= 0 || virtualKey > 0xFE)
                return;

            switch (feature)
            {
                case RuntimeProfileFeature.FreezeAI:
                    _freezeAiHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.MissionTimerScale:
                    _missionTimerHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.RaceTimerScale:
                    _raceTimerHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.Hover:
                    _flyHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.Acceleration:
                    _accelerationHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.CruiseControl:
                    _cruiseControlHotkeyVirtualKey = virtualKey;
                    break;
                case RuntimeProfileFeature.AccelerationRamp:
                    _accelRampHotkeyVirtualKey = virtualKey;
                    break;
            }
        }

        private string GetRuntimeFeatureHotkeyText(RuntimeProfileFeature feature)
        {
            return FormatVirtualKeyText(GetRuntimeFeatureHotkey(feature));
        }

        private static string FormatVirtualKeyText(int virtualKey)
        {
            if (virtualKey <= 0)
                return "None";

            var key = (Keys)virtualKey;
            return key == Keys.Space ? "Space" : key.ToString();
        }

        private void ToggleRuntimeFeatureHotkeyArm(RuntimeProfileFeature feature)
        {
            if (!IsRuntimeFeatureHotkeySupported(feature))
                return;

            if (_runtimeFeatureHotkeysRegistered.Contains(feature))
            {
                UnregisterRuntimeFeatureHotkey(feature);
                SetFeaturesStatus(GetRuntimeFeatureLabel(feature) + " hotkey off", AccentRed);
                return;
            }

            if (RegisterRuntimeFeatureHotkey(feature))
                SetFeaturesStatus(GetRuntimeFeatureLabel(feature) + " hotkey on", AccentGreen);
        }

        private bool RegisterRuntimeFeatureHotkey(RuntimeProfileFeature feature)
        {
            if (!IsRuntimeFeatureHotkeySupported(feature) || IsDisposed)
                return false;
            if (_runtimeFeatureHotkeysRegistered.Contains(feature))
                return true;

            var key = GetRuntimeFeatureHotkey(feature);

            if (key <= 0 || key > 0xFE)
            {
                Log("ERROR: " + GetRuntimeFeatureLabel(feature) + " hotkey has no valid key.");
                return false;
            }

            if (Native.RegisterHotKey(Handle, GetRuntimeFeatureHotkeyId(feature), 0, key))
            {
                _runtimeFeatureHotkeysRegistered.Add(feature);
                _runtimeFeatureHotkeysArmed.Add(feature);
                UpdateRuntimeFeatureHotkeyButtons(feature);
                Log(GetRuntimeFeatureLabel(feature) + " hotkey ready: press " + GetRuntimeFeatureHotkeyText(feature) + " to toggle.");
                return true;
            }

            _runtimeFeatureHotkeysArmed.Remove(feature);
            UpdateRuntimeFeatureHotkeyButtons(feature);
            Log("ERROR: " + GetRuntimeFeatureLabel(feature) + " hotkey " + GetRuntimeFeatureHotkeyText(feature) + " could not be registered.");
            ShowInfo(GetRuntimeFeatureLabel(feature) + " hotkey could not be registered." + Environment.NewLine + Environment.NewLine + "Pick another key or close the other app using it.");
            return false;
        }

        private void UnregisterRuntimeFeatureHotkey(RuntimeProfileFeature feature)
        {
            if (!_runtimeFeatureHotkeysRegistered.Contains(feature))
            {
                _runtimeFeatureHotkeysArmed.Remove(feature);
                UpdateRuntimeFeatureHotkeyButtons(feature);
                return;
            }

            Native.UnregisterHotKey(Handle, GetRuntimeFeatureHotkeyId(feature));
            _runtimeFeatureHotkeysRegistered.Remove(feature);
            _runtimeFeatureHotkeysArmed.Remove(feature);
            UpdateRuntimeFeatureHotkeyButtons(feature);
            Log(GetRuntimeFeatureLabel(feature) + " hotkey off.");
        }

        private void ReRegisterRuntimeFeatureHotkey(RuntimeProfileFeature feature)
        {
            var wasArmed = _runtimeFeatureHotkeysArmed.Contains(feature) || _runtimeFeatureHotkeysRegistered.Contains(feature);
            UnregisterRuntimeFeatureHotkey(feature);
            if (wasArmed)
                RegisterRuntimeFeatureHotkey(feature);
        }

        private void UnregisterAllRuntimeFeatureHotkeys()
        {
            foreach (var feature in _runtimeFeatureHotkeysRegistered.ToArray())
                UnregisterRuntimeFeatureHotkey(feature);
        }

        private bool TryHandleRuntimeFeatureHotkey(int hotkeyId)
        {
            var feature = GetRuntimeFeatureFromHotkeyId(hotkeyId);
            if (!feature.HasValue || !IsRuntimeFeatureHotkeySupported(feature.Value))
                return false;

            TriggerRuntimeFeatureHotkey(feature.Value);
            return true;
        }

        private void TriggerRuntimeFeatureHotkey(RuntimeProfileFeature feature)
        {
            if (!IsRuntimeFeatureHotkeySupported(feature))
                return;

            var label = GetRuntimeFeatureLabel(feature);
            StatusDotToggle toggle;
            _runtimeFeatureToggles.TryGetValue(feature, out toggle);
            var nextEnabled = toggle == null || !toggle.Checked;
            if (toggle != null && !toggle.IsDisposed)
                toggle.Checked = nextEnabled;

            if (feature == RuntimeProfileFeature.Hover && toggle != null && !toggle.IsDisposed)
            {
                SetFeaturesStatus(label + " hotkey toggled " + (nextEnabled ? "on" : "off"), nextEnabled ? AccentGreen : AccentRed);
                return;
            }

            if (!nextEnabled)
            {
                SetFeaturesStatus(label + " hotkey toggled off", AccentRed);
                return;
            }

            TextBox valueBox;
            _profileValueBoxes.TryGetValue(feature, out valueBox);
            var value = feature == RuntimeProfileFeature.Acceleration
                ? FormatFloat(GetAccelerationRequestedMultiplier())
                : valueBox == null ? string.Empty : GetTextBoxValue(valueBox);
            RunWorker(label + " Hotkey", delegate { ApplyProfileRuntimeHook(feature, label, value, true); });
        }

        private void UpdateRuntimeFeatureHotkeyButtons(RuntimeProfileFeature feature)
        {
            Button keyButton;
            if (_runtimeFeatureHotkeyButtons.TryGetValue(feature, out keyButton) && keyButton != null && !keyButton.IsDisposed)
                keyButton.Text = GetRuntimeFeatureHotkeyText(feature);

            Button armButton;
            if (_runtimeFeatureHotkeyArmButtons.TryGetValue(feature, out armButton) && armButton != null && !armButton.IsDisposed)
            {
                var armed = _runtimeFeatureHotkeysRegistered.Contains(feature);
                armButton.Text = armed ? "Key ON" : "Key OFF";
                MakeAccentButton(armButton, armed ? AccentGreen : AccentRed);
            }
        }

        private void StartAutoMasteryWorkflow()
        {
            StartAutoMasteryWorkflow(true);
        }

        private void StartAutoMasteryWorkflow(bool showPrompt)
        {
            if (GetAutoMasteryMacroSnapshot().Count == 0)
            {
                if (showPrompt)
                {
                    ShowInfo("Record an Auto Mastery mouse macro first.");
                    return;
                }

                StartAutoMasteryRecordingWorkflow();
                return;
            }

            if (showPrompt && !ShowAutoMasteryStartPrompt())
                return;

            CancellationTokenSource source;
            lock (_autoMasteryLock)
            {
                if (_autoMasteryCancel != null)
                {
                    ShowInfo("Auto Mastery is already running.");
                    return;
                }

                source = new CancellationTokenSource();
                _autoMasteryCancel = source;
            }

            SetAutoMasteryButtons(true);
            SetFeaturesStatus("Auto Mastery starting...", AccentPurple);
            Log("Auto Mastery starting. Keep FH6 on the Garage/Cars menus and do not touch the keyboard until it finishes or you press Stop.");

            ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    ExecuteAutoMasteryWorkflow(source.Token);
                    SetFeaturesStatus("Auto Mastery success", AccentGreen);
                    Log("Auto Mastery finished.");
                }
                catch (OperationCanceledException)
                {
                    SetFeaturesStatus("Auto Mastery canceled", AccentRed);
                    Log("Auto Mastery canceled.");
                }
                catch (Exception ex)
                {
                    SetFeaturesStatus("Auto Mastery failed", AccentRed);
                    Log("ERROR: Auto Mastery failed: " + ex.Message);
                }
                finally
                {
                    lock (_autoMasteryLock)
                    {
                        if (ReferenceEquals(_autoMasteryCancel, source))
                        {
                            _autoMasteryCancel.Dispose();
                            _autoMasteryCancel = null;
                        }
                    }
                    SetAutoMasteryButtons(false);
                }
            });
        }

        private void CancelAutoMasteryWorkflow()
        {
            lock (_autoMasteryLock)
            {
                if (_autoMasteryCancel == null)
                    return;

                _autoMasteryCancel.Cancel();
            }

            SetFeaturesStatus("Auto Mastery stopping...", AccentRed);
            Log("Auto Mastery stop requested.");
        }

        private bool ShowAutoMasteryStartPrompt()
        {
            if (InvokeRequired)
                return (bool)Invoke(new Func<bool>(ShowAutoMasteryStartPrompt));

            var text =
                "Start Auto Mastery now?" + Environment.NewLine + Environment.NewLine +
                "Before pressing OK:" + Environment.NewLine +
                "- FH6 must be open and loaded." + Environment.NewLine +
                "- Put the game on the Garage/Festival menu where Cars is available." + Environment.NewLine +
                "- Record a mouse macro first if this is your first run." + Environment.NewLine +
                "- Do not use the mouse or keyboard while Luna replays the macro." + Environment.NewLine + Environment.NewLine +
                "Luna will queue 10 BMW M2 Forza Edition copies per batch, clear the new-car popup, replay your recorded mouse macro " + _autoMasteryRuns.ToString(CultureInfo.InvariantCulture) + " time(s), then remove each batch when done." + Environment.NewLine + Environment.NewLine +
                "If FH6 loses focus, Auto Mastery pauses and resumes after you select the FH6 window again.";

            return ShowTranslatedMessageBox(this, text, MessageBoxButtons.OKCancel, MessageBoxIcon.Warning) == DialogResult.OK;
        }

        private void SetAutoMasteryButtons(bool running)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetAutoMasteryButtons(running); }));
                return;
            }

            if (_autoMasteryStartButton != null && !_autoMasteryStartButton.IsDisposed)
                _autoMasteryStartButton.Enabled = !running;
            if (_autoMasteryRecordButton != null && !_autoMasteryRecordButton.IsDisposed)
                _autoMasteryRecordButton.Enabled = !running;
            if (_autoMasteryRunsButton != null && !_autoMasteryRunsButton.IsDisposed)
                _autoMasteryRunsButton.Enabled = !running;
            if (_autoMasteryStopButton != null && !_autoMasteryStopButton.IsDisposed)
                _autoMasteryStopButton.Enabled = running;
        }

        private void ExecuteAutoMasteryWorkflow(CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            var db = RequireDatabase();
            var target = ResolveAutoMasteryTargetCar(db);
            var macro = GetAutoMasteryMacroSnapshot();
            if (macro.Count == 0)
                throw new InvalidOperationException("Record an Auto Mastery mouse macro first.");

            var garageTable = ResolveOptionalGarageTable(db);
            var totalRuns = Math.Max(1, _autoMasteryRuns);
            var completed = 0;
            Log("Auto Mastery target: " + target.DisplayName + " (CarId " + target.CarId.ToString(CultureInfo.InvariantCulture) + "). Runs=" + totalRuns.ToString(CultureInfo.InvariantCulture) + ", macro clicks=" + macro.Count.ToString(CultureInfo.InvariantCulture) + ".");

            while (completed < totalRuns)
            {
                token.ThrowIfCancellationRequested();
                var beforeRows = string.IsNullOrEmpty(garageTable)
                    ? new HashSet<long>()
                    : QueryGarageRowIdsForCar(db, garageTable, target.CarId);
                var beforeCount = beforeRows.Count;
                var batchRuns = Math.Min(10, totalRuns - completed);

                SetFeaturesStatus("Auto Mastery: queueing BMW M2 FE cars", AccentPurple);
                Log("Auto Mastery batch starting. BMW M2 FE garage copies before: " + beforeCount.ToString(CultureInfo.InvariantCulture) + ". Batch runs=" + batchRuns.ToString(CultureInfo.InvariantCulture) + ".");

                var cleanupNeeded = false;
                try
                {
                    ApplyAutoshowUnlock(db);
                    var request = new List<CarTableGrantRequest>
                    {
                        new CarTableGrantRequest(target.CarId, target.DisplayName, 10)
                    };
                    ApplySelectedCarsAddAllGrantBatch(db, request);
                    cleanupNeeded = true;
                    token.ThrowIfCancellationRequested();

                    ClearAutoMasteryNewCarPopup(db, garageTable, target.CarId, beforeCount + 10, token);

                    for (var i = 0; i < batchRuns; i++)
                    {
                        token.ThrowIfCancellationRequested();
                        SetFeaturesStatus("Auto Mastery: replay " + (completed + 1).ToString(CultureInfo.InvariantCulture) + " / " + totalRuns.ToString(CultureInfo.InvariantCulture), AccentPurple);
                        Log("Auto Mastery replay " + (completed + 1).ToString(CultureInfo.InvariantCulture) + "/" + totalRuns.ToString(CultureInfo.InvariantCulture) + ".");
                        ReplayAutoMasteryMacro(macro, token);
                        completed++;
                    }
                }
                finally
                {
                    if (cleanupNeeded)
                    {
                        try
                        {
                            RemoveAutoMasteryBatchCars(db, garageTable, target.CarId, beforeRows);
                        }
                        catch (Exception ex)
                        {
                            Log("ERROR: Auto Mastery cleanup failed: " + ex.Message);
                        }
                    }
                }
            }
        }

        private void ExecuteAutoMasteryRecordingWorkflow(CancellationToken token)
        {
            token.ThrowIfCancellationRequested();

            var db = RequireDatabase();
            var target = ResolveAutoMasteryTargetCar(db);
            var garageTable = ResolveOptionalGarageTable(db);
            var beforeRows = string.IsNullOrEmpty(garageTable)
                ? new HashSet<long>()
                : QueryGarageRowIdsForCar(db, garageTable, target.CarId);
            var beforeCount = beforeRows.Count;
            var cleanupNeeded = false;

            try
            {
                SetFeaturesStatus("Auto Mastery: adding record cars", AccentPurple);
                ApplyAutoshowUnlock(db);
                ApplySelectedCarsAddAllGrantBatch(db, new List<CarTableGrantRequest>
                {
                    new CarTableGrantRequest(target.CarId, target.DisplayName, 10)
                });
                cleanupNeeded = true;
                token.ThrowIfCancellationRequested();

                ClearAutoMasteryNewCarPopup(db, garageTable, target.CarId, beforeCount + 10, token);
                if (!ShowAutoMasteryRecordingReadyPrompt())
                    throw new OperationCanceledException();

                StartAutoMasteryClickCapture(token);
                FocusForzaForAutoMastery(token);
                SetFeaturesStatus("Auto Mastery recording. Press F8 when done.", AccentPurple);
                Log("Auto Mastery mouse recording active. Click through FH6, then press F8.");

                while (!_autoMasteryRecordingDone.Wait(120))
                    token.ThrowIfCancellationRequested();

                FinishAutoMasteryRecording();
                var snapshot = GetAutoMasteryMacroSnapshot();
                if (snapshot.Count == 0)
                    throw new InvalidOperationException("No FH6 mouse clicks were recorded.");

                SaveAutoMasteryMacro(snapshot);
                Log("Auto Mastery macro saved with " + snapshot.Count.ToString(CultureInfo.InvariantCulture) + " click(s).");
                ShowInfo("Confirmed. Auto Mastery macro saved with " + snapshot.Count.ToString(CultureInfo.InvariantCulture) + " click(s).");
            }
            finally
            {
                FinishAutoMasteryRecording();
                if (cleanupNeeded)
                {
                    try
                    {
                        RemoveAutoMasteryBatchCars(db, garageTable, target.CarId, beforeRows);
                    }
                    catch (Exception ex)
                    {
                        Log("ERROR: Auto Mastery recording cleanup failed: " + ex.Message);
                    }
                }
            }
        }

        private void StartAutoMasteryClickCapture(CancellationToken token)
        {
            token.ThrowIfCancellationRequested();
            FinishAutoMasteryRecording();
            lock (_autoMasteryMacroLock)
                _autoMasteryMacroSteps.Clear();

            RegisterAutoMasteryFinishHotkey();
            _autoMasteryRecordingDone = new ManualResetEventSlim(false);
            _autoMasteryRecordingClock = Stopwatch.StartNew();
            _autoMasteryMouseProc = AutoMasteryMouseHookCallback;
            _autoMasteryMouseHook = Native.SetWindowsHookEx(Native.WhMouseLl, _autoMasteryMouseProc, Native.GetModuleHandle(null), 0);
            if (_autoMasteryMouseHook == IntPtr.Zero)
            {
                UnregisterAutoMasteryFinishHotkey();
                throw new InvalidOperationException("Could not start the Auto Mastery mouse recorder.");
            }

            _autoMasteryRecordingActive = true;
        }

        private void FinishAutoMasteryRecording()
        {
            _autoMasteryRecordingActive = false;
            if (_autoMasteryMouseHook != IntPtr.Zero)
            {
                Native.UnhookWindowsHookEx(_autoMasteryMouseHook);
                _autoMasteryMouseHook = IntPtr.Zero;
            }

            UnregisterAutoMasteryFinishHotkey();
            if (_autoMasteryRecordingClock != null)
            {
                _autoMasteryRecordingClock.Stop();
                _autoMasteryRecordingClock = null;
            }

            var done = _autoMasteryRecordingDone;
            if (done != null)
                done.Set();
        }

        private IntPtr AutoMasteryMouseHookCallback(int nCode, IntPtr wParam, IntPtr lParam)
        {
            if (nCode >= 0 && _autoMasteryRecordingActive && wParam.ToInt32() == Native.WmLButtonDown)
            {
                try
                {
                    if (IsForzaForegroundForAutoMastery())
                    {
                        var info = (Native.Msllhookstruct)Marshal.PtrToStructure(lParam, typeof(Native.Msllhookstruct));
                        var handle = GetForzaWindowHandleForAutoMastery();
                        Native.Rect rect;
                        if (handle != IntPtr.Zero && Native.GetWindowRect(handle, out rect))
                        {
                            var delay = 120;
                            if (_autoMasteryRecordingClock != null)
                            {
                                delay = (int)Math.Max(60, Math.Min(5000, _autoMasteryRecordingClock.ElapsedMilliseconds));
                                _autoMasteryRecordingClock.Restart();
                            }

                            var step = new AutoMasteryMacroStep(info.pt.x - rect.Left, info.pt.y - rect.Top, delay);
                            lock (_autoMasteryMacroLock)
                                _autoMasteryMacroSteps.Add(step);
                            SetFeaturesStatus("Auto Mastery recording clicks: " + GetAutoMasteryMacroSnapshot().Count.ToString(CultureInfo.InvariantCulture), AccentPurple);
                        }
                    }
                }
                catch
                {
                }
            }

            return Native.CallNextHookEx(_autoMasteryMouseHook, nCode, wParam, lParam);
        }

        private void ReplayAutoMasteryMacro(List<AutoMasteryMacroStep> steps, CancellationToken token)
        {
            if (steps == null || steps.Count == 0)
                throw new InvalidOperationException("Record an Auto Mastery mouse macro first.");

            var handle = GetForzaWindowHandleForAutoMastery();
            if (handle == IntPtr.Zero)
                throw new InvalidOperationException("FH6 main window was not found.");

            WaitForzaForegroundForAutoMastery(token, true);
            foreach (var step in steps)
            {
                token.ThrowIfCancellationRequested();
                WaitForzaForegroundForAutoMastery(token, false);
                AutoMasteryDelay(Math.Max(40, Math.Min(5000, step.DelayMs)), token);
                Native.Rect rect;
                if (!Native.GetWindowRect(handle, out rect))
                    throw new InvalidOperationException("FH6 window position could not be read.");

                Native.SendMouseLeftClick(rect.Left + step.X, rect.Top + step.Y);
            }
        }

        private IntPtr GetForzaWindowHandleForAutoMastery()
        {
            var process = FindForzaHorizonProcess();
            if (process == null || process.HasExited)
                return IntPtr.Zero;
            return process.MainWindowHandle;
        }

        private List<AutoMasteryMacroStep> GetAutoMasteryMacroSnapshot()
        {
            lock (_autoMasteryMacroLock)
                return _autoMasteryMacroSteps.Select(step => new AutoMasteryMacroStep(step.X, step.Y, step.DelayMs)).ToList();
        }

        private void SaveAutoMasteryMacro(List<AutoMasteryMacroStep> steps)
        {
            try
            {
                lock (_autoMasteryMacroLock)
                {
                    _autoMasteryMacroSteps.Clear();
                    _autoMasteryMacroSteps.AddRange(steps.Select(step => new AutoMasteryMacroStep(step.X, step.Y, step.DelayMs)));
                }

                var lines = steps.Select(step =>
                    step.X.ToString(CultureInfo.InvariantCulture) + "," +
                    step.Y.ToString(CultureInfo.InvariantCulture) + "," +
                    step.DelayMs.ToString(CultureInfo.InvariantCulture)).ToArray();
                File.WriteAllLines(_autoMasteryMacroPath, lines);
            }
            catch (Exception ex)
            {
                Log("Auto Mastery macro could not be saved: " + ex.Message);
            }
        }

        private void LoadAutoMasteryMacro()
        {
            try
            {
                if (string.IsNullOrEmpty(_autoMasteryMacroPath) || !File.Exists(_autoMasteryMacroPath))
                    return;

                var loaded = new List<AutoMasteryMacroStep>();
                foreach (var line in File.ReadAllLines(_autoMasteryMacroPath))
                {
                    var parts = (line ?? string.Empty).Split(',');
                    if (parts.Length < 3)
                        continue;
                    int x;
                    int y;
                    int delay;
                    if (int.TryParse(parts[0], NumberStyles.Integer, CultureInfo.InvariantCulture, out x) &&
                        int.TryParse(parts[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out y) &&
                        int.TryParse(parts[2], NumberStyles.Integer, CultureInfo.InvariantCulture, out delay))
                        loaded.Add(new AutoMasteryMacroStep(x, y, Math.Max(40, Math.Min(5000, delay))));
                }

                lock (_autoMasteryMacroLock)
                {
                    _autoMasteryMacroSteps.Clear();
                    _autoMasteryMacroSteps.AddRange(loaded);
                }
            }
            catch
            {
            }
        }

        private AutoMasteryTargetCar ResolveAutoMasteryTargetCar(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found, so Auto Mastery cannot find the BMW M2 Forza Edition.");

            EnsureCarStringTablesLoaded();

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE([Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE([MakeName], '')" : "''";
            var displayExpr = db.ColumnExists("Data_Car", "DisplayName") ? "COALESCE([DisplayName], '')" : "''";
            var modelExpr = db.ColumnExists("Data_Car", "ModelShort") ? "COALESCE([ModelShort], '')" : "''";
            var mediaExpr = db.ColumnExists("Data_Car", "MediaName") ? "COALESCE([MediaName], '')" : "''";

            var result = db.Query(
                "SELECT [Id], " + yearExpr + ", " + makeExpr + ", " + displayExpr + ", " + modelExpr + ", " + mediaExpr + " " +
                "FROM Data_Car WHERE [Id] IS NOT NULL AND [Id] <> 3300;");

            AutoMasteryTargetCar best = null;
            var bestScore = 0;

            foreach (var row in result.Rows)
            {
                if (row.Count < 6)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;

                var year = ToDisplayString(row[1]);
                var make = TranslateCarText(ToDisplayString(row[2]), _carMakeStrings);
                var display = TranslateCarText(ToDisplayString(row[3]), _carNameStrings);
                var model = TranslateCarText(ToDisplayString(row[4]), _carNameStrings);
                var media = TranslateCarText(ToDisplayString(row[5]), _carNameStrings);
                var combined = (year + " " + make + " " + display + " " + model + " " + media + " " +
                    ToDisplayString(row[2]) + " " + ToDisplayString(row[3]) + " " + ToDisplayString(row[4]) + " " + ToDisplayString(row[5])).ToUpperInvariant();

                var score = 0;
                if (combined.Contains("BMW")) score += 40;
                if (combined.Contains("M2")) score += 35;
                if (combined.Contains("2023") || string.Equals(year.Trim(), "2023", StringComparison.OrdinalIgnoreCase)) score += 15;
                if (combined.Contains("FORZA EDITION")) score += 80;
                else if (combined.Contains("FORZA")) score += 35;
                else if (combined.Contains(" FE ") ||
                         combined.Contains("FE_") ||
                         combined.Contains("_FE") ||
                         combined.Contains("M2FE") ||
                         combined.EndsWith(" FE", StringComparison.OrdinalIgnoreCase)) score += 45;

                if (score > bestScore)
                {
                    bestScore = score;
                    best = new AutoMasteryTargetCar(carId, FormatCarDisplayName(carId, year, make, string.IsNullOrWhiteSpace(display) ? model : display));
                }
            }

            if (best != null && bestScore >= 100)
                return best;

            var knownExists = db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE Id = " + AutoMasteryBmwM2FeCarId.ToString(CultureInfo.InvariantCulture)) ?? 0;
            if (knownExists > 0)
                return new AutoMasteryTargetCar(AutoMasteryBmwM2FeCarId, "2023 BMW M2 Forza Edition");

            if (best == null || bestScore < 100)
                throw new InvalidOperationException("Auto Mastery could not confidently find the 2023 BMW M2 Forza Edition in Data_Car.");

            return best;
        }

        private HashSet<long> QueryGarageRowIdsForCar(RemoteDatabase db, string garageTable, int carId)
        {
            var ids = new HashSet<long>();
            if (string.IsNullOrEmpty(garageTable))
                return ids;

            var result = db.Query(
                "SELECT rowid FROM " + EscapeIdentifierForSql(garageTable) +
                " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            foreach (var row in result.Rows)
            {
                if (row.Count > 0)
                    ids.Add(ToLong(row[0]));
            }
            return ids;
        }

        private void ClearAutoMasteryNewCarPopup(RemoteDatabase db, string garageTable, int carId, int targetCount, CancellationToken token)
        {
            FocusForzaForAutoMastery(token);
            SetFeaturesStatus("Auto Mastery: clearing new-car popup", AccentPurple);
            Log("Auto Mastery queued 10 BMW M2 FE copies. Starting macro now.");

            for (var i = 0; i < 4; i++)
            {
                token.ThrowIfCancellationRequested();
                WaitForzaForegroundForAutoMastery(token, i == 0);
                Native.SendKeyboardKey((ushort)Keys.Enter);
                AutoMasteryDelay(350, token);
            }

            if (!string.IsNullOrEmpty(garageTable))
            {
                var count = db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(garageTable) + " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                Log("Auto Mastery BMW M2 FE garage copies now: " + count.ToString(CultureInfo.InvariantCulture) + "/" + targetCount.ToString(CultureInfo.InvariantCulture) + ".");
            }

            AutoMasteryDelay(450, token);
        }

        private void WaitForAutoMasteryGarageCopies(RemoteDatabase db, string garageTable, int carId, int targetCount, CancellationToken token)
        {
            var tableSql = EscapeIdentifierForSql(garageTable);
            var deadline = DateTime.UtcNow.AddSeconds(90);
            var lastEnter = DateTime.MinValue;
            var enterLogged = false;
            while (DateTime.UtcNow < deadline)
            {
                token.ThrowIfCancellationRequested();
                var count = db.QueryScalarLong("SELECT count(*) FROM " + tableSql + " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                if (count >= targetCount)
                {
                    if (!enterLogged && IsForzaForegroundForAutoMastery())
                    {
                        Native.SendKeyboardKey((ushort)Keys.Enter);
                        AutoMasteryDelay(500, token);
                        Log("Auto Mastery pressed Enter for the FH6 new-car popup.");
                    }

                    Log("Auto Mastery confirmed garage copies: " + count.ToString(CultureInfo.InvariantCulture) + ".");
                    return;
                }

                SetFeaturesStatus("Auto Mastery: waiting for FH6 to claim cars " + count.ToString(CultureInfo.InvariantCulture) + "/" + targetCount.ToString(CultureInfo.InvariantCulture), AccentPurple);
                if (IsForzaForegroundForAutoMastery())
                {
                    if ((DateTime.UtcNow - lastEnter).TotalMilliseconds >= 900)
                    {
                        Native.SendKeyboardKey((ushort)Keys.Enter);
                        lastEnter = DateTime.UtcNow;
                        if (!enterLogged)
                        {
                            Log("Auto Mastery is pressing Enter to clear the FH6 new-car popup.");
                            enterLogged = true;
                        }
                    }

                    AutoMasteryDelay(500, token);
                    continue;
                }

                WaitForzaForegroundForAutoMastery(token, true);
                deadline = DateTime.UtcNow.AddSeconds(90);
            }

            Log("Auto Mastery note: garage copy count did not reach " + targetCount.ToString(CultureInfo.InvariantCulture) + " within 90 seconds. Continuing with queued grants.");
        }

        private void FocusForzaForAutoMastery(CancellationToken token)
        {
            WaitForzaForegroundForAutoMastery(token, true);
        }

        private void WaitForzaForegroundForAutoMastery(CancellationToken token, bool requestFocus)
        {
            var process = FindForzaHorizonProcess();
            if (process == null || process.HasExited)
                throw new InvalidOperationException("FH6 process was not found.");
            if (process.MainWindowHandle == IntPtr.Zero)
                throw new InvalidOperationException("FH6 main window was not found.");

            if (requestFocus)
            {
                Native.ShowWindow(process.MainWindowHandle, Native.SwRestore);
                Native.SetForegroundWindow(process.MainWindowHandle);
                AutoMasteryDelay(650, token);
            }

            var paused = false;
            while (true)
            {
                token.ThrowIfCancellationRequested();
                process.Refresh();
                if (process.HasExited)
                    throw new InvalidOperationException("FH6 process closed while Auto Mastery was running.");

                int foregroundPid;
                Native.GetWindowThreadProcessId(Native.GetForegroundWindow(), out foregroundPid);
                if (foregroundPid == process.Id)
                {
                    if (paused)
                    {
                        SetFeaturesStatus("Auto Mastery resumed", AccentGreen);
                        Log("Auto Mastery resumed after FH6 was selected again.");
                    }
                    return;
                }

                if (!paused)
                {
                    SetFeaturesStatus("Auto Mastery paused. Select FH6 to resume.", AccentPurple);
                    Log("Auto Mastery paused. Select the FH6 window to continue.");
                    paused = true;
                }

                AutoMasteryDelay(350, token);
            }
        }

        private bool IsForzaForegroundForAutoMastery()
        {
            var process = FindForzaHorizonProcess();
            if (process == null || process.HasExited)
                return false;

            int foregroundPid;
            Native.GetWindowThreadProcessId(Native.GetForegroundWindow(), out foregroundPid);
            return foregroundPid == process.Id;
        }

        private void RunAutoMasteryCarMenuCycle(int index, CancellationToken token)
        {
            FocusForzaForAutoMastery(token);

            Log("Auto Mastery macro running car " + (index + 1).ToString(CultureInfo.InvariantCulture) + "/10.");
            if (index == 0)
                AutoMasteryPress(Keys.E, 360, token);

            AutoMasteryPress(Keys.Enter, 800, token);
            AutoMasteryPress(Keys.Home, 220, token);
            for (var i = 0; i < index; i++)
                AutoMasteryPress(Keys.Down, 85, token);

            AutoMasteryPress(Keys.Enter, 420, token);
            AutoMasteryPress(Keys.Enter, 3800, token);
            AutoMasteryPress(Keys.E, 360, token);
            AutoMasteryPress(Keys.Down, 160, token);
            AutoMasteryPress(Keys.Enter, 520, token);
            AutoMasteryPress(Keys.Down, 160, token);
            AutoMasteryPress(Keys.Enter, 750, token);
            AutoMasteryPress(Keys.Y, 360, token);
            AutoMasteryPress(Keys.Enter, 520, token);
            AutoMasteryPress(Keys.Escape, 420, token);
            AutoMasteryPress(Keys.Escape, 620, token);
        }

        private void RemoveAutoMasteryBatchCars(RemoteDatabase db, string garageTable, int carId, HashSet<long> baselineRows)
        {
            if (string.IsNullOrEmpty(garageTable))
            {
                Log("Auto Mastery cleanup skipped: no garage table was available.");
                return;
            }

            var rows = QueryGarageRemovalRows(db, garageTable, "g.CarId = " + carId.ToString(CultureInfo.InvariantCulture));
            var removeRows = rows
                .Where(row => baselineRows == null || !baselineRows.Contains(row.RowId))
                .OrderByDescending(row => row.RowId)
                .Take(10)
                .ToList();

            if (removeRows.Count == 0)
            {
                Log("Auto Mastery cleanup found no newly added BMW M2 FE garage rows to remove.");
                return;
            }

            db.Execute("CREATE TABLE IF NOT EXISTS _backup_AutoMastery_RemoveCars AS SELECT rowid AS _rowid_, * FROM " + EscapeIdentifierForSql(garageTable) + ";");
            DeleteGarageRowsByRowId(db, garageTable, removeRows);
            Log("Auto Mastery cleanup removed " + removeRows.Count.ToString(CultureInfo.InvariantCulture) + " BMW M2 FE garage row(s).");
        }

        private void AutoMasteryPress(Keys key, int delayMs, CancellationToken token)
        {
            token.ThrowIfCancellationRequested();
            WaitForzaForegroundForAutoMastery(token, false);
            Native.SendKeyboardKey((ushort)key);
            AutoMasteryDelay(delayMs, token);
        }

        private static void AutoMasteryDelay(int milliseconds, CancellationToken token)
        {
            var remaining = Math.Max(0, milliseconds);
            while (remaining > 0)
            {
                token.ThrowIfCancellationRequested();
                var slice = Math.Min(100, remaining);
                Thread.Sleep(slice);
                remaining -= slice;
            }
        }

        private void LoadCurrentRuntimeValues()
        {
            var db = RequireDatabase();
            var loaded = new Dictionary<RuntimeProfileFeature, string>();

            var captureTargets = new List<RuntimeProfileFeature>
            {
                RuntimeProfileFeature.Credits,
                RuntimeProfileFeature.Wheelspins,
                RuntimeProfileFeature.SkillPoints
            };

            var armed = db.ArmProfileRuntimeValueCapture(captureTargets);
            var captured = db.ReadProfileRuntimeCaptureValues(armed, true);
            AddCapturedRuntimeValues(loaded, captured);

            if (loaded.Count > 0)
                SetProfileValueBoxValues(loaded);

            SetPendingRuntimeCaptures(armed.Where(feature => !loaded.ContainsKey(feature)).ToList());
            Log("Load Current armed runtime capture for " + armed.Count + " value(s); loaded " + loaded.Count + " value(s) immediately.");
            if (armed.Any(feature => !loaded.ContainsKey(feature)))
                Log("Open the in-game garage/profile/pause screens so FH6 refreshes Credits, Wheelspins, or Skill Points. The boxes will fill automatically when captured.");
        }

        private static void AddCapturedRuntimeValues(Dictionary<RuntimeProfileFeature, string> loaded, Dictionary<RuntimeProfileFeature, int> captured)
        {
            foreach (var item in captured)
            {
                if (IsFloatRuntimeFeature(item.Key))
                {
                    var value = BitConverter.ToSingle(BitConverter.GetBytes(item.Value), 0);
                    if (!float.IsNaN(value) && !float.IsInfinity(value))
                        loaded[item.Key] = FormatRuntimeValueForBox(item.Key, value);
                }
                else if (item.Value >= 0)
                {
                    loaded[item.Key] = item.Value.ToString(CultureInfo.InvariantCulture);
                }
            }
        }

        private void SetPendingRuntimeCaptures(List<RuntimeProfileFeature> pending)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetPendingRuntimeCaptures(pending); }));
                return;
            }

            _pendingRuntimeCaptures.Clear();
            foreach (var feature in pending)
                _pendingRuntimeCaptures.Add(feature);

            if (_pendingRuntimeCaptures.Count > 0)
            {
                _runtimeCaptureTimer.Start();
                SetProfileStatus("Waiting for current values");
            }
            else
            {
                _runtimeCaptureTimer.Stop();
                SetProfileStatus("Current values loaded");
            }
        }

        private void PollPendingRuntimeCaptures()
        {
            if (_database == null || !_database.IsAlive || _pendingRuntimeCaptures.Count == 0)
            {
                _runtimeCaptureTimer.Stop();
                _pendingRuntimeCaptures.Clear();
                return;
            }

            try
            {
                var pending = _pendingRuntimeCaptures.ToList();
                var captured = _database.ReadProfileRuntimeCaptureValues(pending, false);
                if (captured.Count == 0)
                    return;

                var loaded = new Dictionary<RuntimeProfileFeature, string>();
                AddCapturedRuntimeValues(loaded, captured);
                if (loaded.Count == 0)
                    return;

                SetProfileValueBoxValues(loaded);
                foreach (var item in loaded)
                {
                    _pendingRuntimeCaptures.Remove(item.Key);
                    Log("Current " + GetRuntimeFeatureLabel(item.Key) + " captured: " + item.Value);
                }

                if (_pendingRuntimeCaptures.Count == 0)
                {
                    _runtimeCaptureTimer.Stop();
                    SetProfileStatus("Current values loaded");
                }
            }
            catch (Exception ex)
            {
                _runtimeCaptureTimer.Stop();
                _pendingRuntimeCaptures.Clear();
                Log("Runtime value capture stopped: " + ex.Message);
            }
        }

        private void SetProfileValueBoxValues(Dictionary<RuntimeProfileFeature, string> values)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetProfileValueBoxValues(values); }));
                return;
            }

            foreach (var item in values)
            {
                TextBox box;
                if (_profileValueBoxes.TryGetValue(item.Key, out box) && box != null && !box.IsDisposed)
                {
                    if (item.Key == RuntimeProfileFeature.FovSlider)
                    {
                        int fovLevel;
                        if (int.TryParse((item.Value ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out fovLevel))
                        {
                            box.Text = Math.Max(1, Math.Min(360, fovLevel)).ToString(CultureInfo.InvariantCulture);
                            _fovControlAll = true;
                            _fovAllDegrees = Math.Max(MinimumFovDegrees, Math.Min(MaximumFovDegrees, fovLevel));
                            _fovDashboardDegrees = _fovAllDegrees;
                            _fovChaseDegrees = _fovAllDegrees;
                            _fovFarChaseDegrees = _fovAllDegrees;
                            _fovHoodDegrees = _fovAllDegrees;
                            _fovBumperDegrees = _fovAllDegrees;
                            UpdateFovValueButton();
                        }
                    }
                    else
                    {
                        box.Text = item.Value;
                    }
                }
            }
        }

