        private static bool RuntimeFeatureRequiresValue(RuntimeProfileFeature feature)
        {
            return feature != RuntimeProfileFeature.NoSkillBreak &&
                   feature != RuntimeProfileFeature.SuperBrake &&
                   feature != RuntimeProfileFeature.Jump &&
                   feature != RuntimeProfileFeature.NoWaterDrag &&
                   feature != RuntimeProfileFeature.NoBuildLimit &&
                   feature != RuntimeProfileFeature.FreezeAI &&
                   feature != RuntimeProfileFeature.NoClip &&
                   feature != RuntimeProfileFeature.DisableCameraCollision &&
                   feature != RuntimeProfileFeature.SuperStrength &&
                   feature != RuntimeProfileFeature.PhaseDash &&
                   feature != RuntimeProfileFeature.Rewind &&
                   feature != RuntimeProfileFeature.GrapplingHook &&
                   feature != RuntimeProfileFeature.ChargeJump &&
                   feature != RuntimeProfileFeature.TeleportToWaypoint &&
                   feature != RuntimeProfileFeature.SideLock &&
                   feature != RuntimeProfileFeature.ForwardLock &&
                   feature != RuntimeProfileFeature.VerticalHold &&
                   feature != RuntimeProfileFeature.MotionFreeze;
        }

