        }

        private static bool IsLiveDrivingMultiplierScale(RuntimeProfileFeature feature)
        {
            return feature == RuntimeProfileFeature.LandingStabilizer ||
                   feature == RuntimeProfileFeature.SpeedTamer ||
                   feature == RuntimeProfileFeature.BounceCushion ||
                   feature == RuntimeProfileFeature.MomentumControl ||
                   feature == RuntimeProfileFeature.LeftRightCalm ||
                   feature == RuntimeProfileFeature.ForwardBackCalm ||
                   feature == RuntimeProfileFeature.AirBrake ||
                   feature == RuntimeProfileFeature.ForwardGrip ||
                   feature == RuntimeProfileFeature.RailGrip ||
                   feature == RuntimeProfileFeature.StabilityRail;
        }

        private static float ParseLiveDrivingStrengthValue(RuntimeProfileFeature feature, string text, string label)
        {
            var strength = ParseFloat(text, label + " strength");
            return ConvertLiveDrivingStrengthToRaw(feature, strength);
        }

        private static float ConvertLiveDrivingStrengthToRaw(RuntimeProfileFeature feature, float strength)
        {
            float defaultRaw;
            if (!TryGetLiveDrivingDefaultRawValue(feature, out defaultRaw))
                return strength;

            var scale = strength / 100F;
            if (IsLiveDrivingMultiplierScale(feature) && Math.Abs(defaultRaw - 1F) >= 0.000001F)
                return 1F + ((defaultRaw - 1F) * scale);

            return defaultRaw * scale;
        }

        private static float ConvertLiveDrivingRawToStrength(RuntimeProfileFeature feature, float raw)
        {
            float defaultRaw;
            if (!TryGetLiveDrivingDefaultRawValue(feature, out defaultRaw))
                return raw;

            if (IsLiveDrivingMultiplierScale(feature) && Math.Abs(defaultRaw - 1F) >= 0.000001F)
            {
                var delta = defaultRaw - 1F;
                return ((raw - 1F) / delta) * 100F;
            }

            if (Math.Abs(defaultRaw) < 0.000001F)
                return 0F;
            return (raw / defaultRaw) * 100F;
        }

        private static float ParseRuntimeFloatValue(RuntimeProfileFeature feature, string text, string label)
        {
            if (IsLiveDrivingEditorFloatFeature(feature))
                return ParseLiveDrivingStrengthValue(feature, text, label);

            if (feature == RuntimeProfileFeature.Acceleration)
                return NormalizeAccelerationMultiplier(ParsePositiveFloat(text, label));

            if (feature == RuntimeProfileFeature.MissionTimerScale ||
                feature == RuntimeProfileFeature.RaceTimerScale)
            {
                var value = ParseFloat(text, label);
                if (value < 0F || value > 10F)
                    throw new InvalidOperationException(label + " should be between 0 and 10. Use 0 to freeze or 1 for normal speed.");
                return value;
            }

            if (feature == RuntimeProfileFeature.TrailblazerMultiplier)
            {
                var value = ParseFloat(text, label);
                if (value < -10F || value > 10F)
                    throw new InvalidOperationException(label + " should be between -10 and 10. Negative values slow the countdown; 1 is normal speed.");
                return value;
            }

            if (feature == RuntimeProfileFeature.TimeOfDay)
            {
                var value = ParseFloat(text, label);
                if (value < 0F || value > 24F)
                    throw new InvalidOperationException(label + " should be between 0 and 24. 0 is midnight, 12 is noon, 18 is evening.");
                if (value >= 24F)
                    return 0F;
                return value * 3600F;
            }

            if (feature == RuntimeProfileFeature.FovSlider)
            {
                var degrees = ParseFloat(text, label);
                if (degrees < 1F || degrees > 360F)
                    throw new InvalidOperationException(label + " should be between 1 and 360.");
                return degrees;
            }

            if (feature == RuntimeProfileFeature.FastSlowTime)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.01F || value > 20F)
                    throw new InvalidOperationException(label + " should be between 0.01 and 20. Use 1 for normal time.");
                return value;
            }

            if (feature == RuntimeProfileFeature.BackfireFlameControl)
            {
                return ParseNonNegativeFloat(text, label);
            }

            if (feature == RuntimeProfileFeature.CruiseControl)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 1F || value > 1500F)
                    throw new InvalidOperationException(label + " should be between 1 and 1500 km/h.");
                return value;
            }

            if (feature == RuntimeProfileFeature.AccelerationRamp)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 1F || value > 2000F)
                    throw new InvalidOperationException(label + " should be between 1 and 2000 (m/s^2 acceleration boost). Try 30-100.");
                return value;
            }

            if (feature == RuntimeProfileFeature.TopSpeedCap)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 1F || value > 5000F)
                    throw new InvalidOperationException(label + " should be between 1 and 5000 km/h.");
                return value;
            }

            if (feature == RuntimeProfileFeature.WallClimber)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.1F || value > 10F)
                    throw new InvalidOperationException(label + " should be between 0.1 and 10. Start with 1.");
                return value;
            }

            if (feature == RuntimeProfileFeature.Hover)
            {
                var value = ParsePositiveFloat(text, label + " speed");
                if (value < 1F || value > 250F)
                    throw new InvalidOperationException(label + " speed should be between 1 and 250. Default is " + FormatFloat(DefaultFlySpeed) + ".");
                return value;
            }

            if (feature == RuntimeProfileFeature.SpeedZoneSpeed)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.01F || value > 1000F)
                    throw new InvalidOperationException(label + " should be between 0.01 and 1000. Use 1 for normal.");
                return value;
            }

            if (feature == RuntimeProfileFeature.GroundClamp)
            {
                var value = ParseNonNegativeFloat(text, label);
                if (value > 2F)
                    throw new InvalidOperationException(label + " should be between 0 and 2. Start around 0.035.");
                return value;
            }

            if (feature == RuntimeProfileFeature.SlideCalmer)
            {
                var value = ParseNonNegativeFloat(text, label);
                if (value > 3F)
                    throw new InvalidOperationException(label + " should be between 0 and 3. Start around 0.18; higher adds stronger slide control.");
                return value;
            }

            if (IsLiveDrivingEditorFloatFeature(feature))
                return ParseFloat(text, label);

            if (feature == RuntimeProfileFeature.Gravity)
            {
                var percent = ParseFloat(text, label + " percent");
                if (percent < GravityMinPercent || percent > GravityMaxPercent)
                    throw new InvalidOperationException(label + " must be between " + GravityMinPercent.ToString(CultureInfo.InvariantCulture) + "% and " + GravityMaxPercent.ToString(CultureInfo.InvariantCulture) + "% for stable physics.");
                return percent / 100F;
            }
            if (feature == RuntimeProfileFeature.SuperHandling)
            {
                var value = ParsePositiveFloat(text, label);
                if (value > 3F)
                    throw new InvalidOperationException(label + " should stay at 3.0 or lower. Start around 0.24.");
                return value;
            }
            if (feature == RuntimeProfileFeature.SuperGrip)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 10F || value > 1000F)
                    throw new InvalidOperationException(label + " strength should be between 10 and 1000 (100 = normal grip; higher = grippier).");
                return value;
            }
            if (feature == RuntimeProfileFeature.LandingStabilizer)
            {
                var value = ParsePositiveFloat(text, label);
                if (value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.01 and 1.0. Default is 1.");
                return value;
            }
            if (feature == RuntimeProfileFeature.RoadMagnet)
            {
                var value = ParsePositiveFloat(text, label);
                if (value > 5F)
                    throw new InvalidOperationException(label + " should stay at 5.0 or lower. Start around 0.35.");
                return value;
            }
            if (feature == RuntimeProfileFeature.TireBite)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.05F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.05 and 1.0. Lower gives stronger side grip.");
                return value;
            }
            if (feature == RuntimeProfileFeature.GripLock)
            {
                var value = ParsePositiveFloat(text, label);
                if (value > 5F)
                    throw new InvalidOperationException(label + " should stay at 5.0 or lower. Start around 0.12.");
                return value;
            }
            if (feature == RuntimeProfileFeature.SpeedTamer)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.5F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.5 and 1.0. Start around 0.985. Lower calms speed more.");
                return value;
            }
            if (feature == RuntimeProfileFeature.AirLift)
            {
                var value = ParseFloat(text, label);
                if (value < 0F || value > 2F)
                    throw new InvalidOperationException(label + " should be between 0 and 2.0. Start around 0.08.");
                return value;
            }
            if (feature == RuntimeProfileFeature.BounceCushion)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.1F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.1 and 1.0. Start around 0.85. Lower is softer.");
                return value;
            }
            if (feature == RuntimeProfileFeature.MomentumControl ||
                feature == RuntimeProfileFeature.LeftRightCalm ||
                feature == RuntimeProfileFeature.ForwardBackCalm)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.5F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.5 and 1.0. Start around 0.98. Lower calms movement more.");
                return value;
            }
            if (feature == RuntimeProfileFeature.SidePush ||
                feature == RuntimeProfileFeature.ForwardPush ||
                feature == RuntimeProfileFeature.VerticalTrim ||
                feature == RuntimeProfileFeature.WheelieBoost ||
                feature == RuntimeProfileFeature.DriftKick ||
                feature == RuntimeProfileFeature.PlantedBoost ||
                feature == RuntimeProfileFeature.ForwardLaunch ||
                feature == RuntimeProfileFeature.StraightLaunch ||
                feature == RuntimeProfileFeature.DragLaunchAssist)
            {
                var value = ParseFloat(text, label);
                if (value < -2F || value > 2F)
                    throw new InvalidOperationException(label + " should be between -2.0 and 2.0. Use small changes like 0.05 first.");
                return value;
            }
            if (feature == RuntimeProfileFeature.Boost)
            {
                var value = ParseFloat(text, label);
                if (value < -0.95F || value > 20F)
                    throw new InvalidOperationException(label + " should be between -0.95 and 20. Default is 0.02.");
                return value;
            }
            if (feature == RuntimeProfileFeature.DriftMode)
            {
                var value = ParseFloat(text, label);
                if (value < 0F || value > 1F)
                    throw new InvalidOperationException(label + " intensity should be between 0 and 1. Start around 0.5; higher slides harder.");
                return value;
            }
            if (feature == RuntimeProfileFeature.HoverGlide)
            {
                var value = ParsePositiveFloat(text, label);
                if (value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.01 and 1.0. Start around 0.08.");
                return value;
            }
            if (feature == RuntimeProfileFeature.AirBrake)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.05F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.05 and 1.0. Lower slows motion more.");
                return value;
            }
            if (feature == RuntimeProfileFeature.CornerStabilizer)
            {
                var value = ParsePositiveFloat(text, label);
                if (value < 0.5F || value > 1F)
                    throw new InvalidOperationException(label + " should be between 0.5 and 1.0. Start around 0.92. Lower steadies corners more.");
                return value;
            }
            if (feature == RuntimeProfileFeature.AdaptiveBrake)
            {
                return ParseFloat(text, label);
            }
            return ParsePositiveFloat(text, label);
        }

        private static float NormalizeAccelerationMultiplier(float requestedMultiplier)
        {
            if (requestedMultiplier <= SafeAccelerationMultiplier)
                return requestedMultiplier;

            var softened = SafeAccelerationMultiplier + ((requestedMultiplier - SafeAccelerationMultiplier) * AccelerationInputSoftScale);
            if (softened > MaxAccelerationRawMultiplier)
                return MaxAccelerationRawMultiplier;
            return softened;
        }

        private static float AccelerationPercentToMultiplier(int percent)
        {
            percent = Math.Max(0, Math.Min(MaxAccelerationPercent, percent));
            return 1F + ((MaxAccelerationPercentMultiplier - 1F) * (percent / (float)MaxAccelerationPercent));
        }

        private static float NormalizeBoostForce(float requestedForce)
        {
            if (requestedForce <= DefaultBoostForce)
                return requestedForce;

            var softened = DefaultBoostForce + ((requestedForce - DefaultBoostForce) * BoostInputSoftScale);
            if (softened > MaxBoostRawForce)
                return MaxBoostRawForce;
            return softened;
        }

        private static string FormatRuntimeValueForBox(RuntimeProfileFeature feature, float value)
        {
            if (IsLiveDrivingEditorFloatFeature(feature))
                return FormatFloat(ConvertLiveDrivingRawToStrength(feature, value));
            if (feature == RuntimeProfileFeature.Gravity)
                return FormatFloat(value * 100F);
            if (feature == RuntimeProfileFeature.TimeOfDay)
                return FormatFloat(value / 3600F);
            if (feature == RuntimeProfileFeature.FovSlider)
                return FormatFloat(value);
            return FormatFloat(value);
        }

        private static string FormatRuntimeValueForLog(RuntimeProfileFeature feature, float value)
        {
            if (IsLiveDrivingEditorFloatFeature(feature))
                return FormatFloat(ConvertLiveDrivingRawToStrength(feature, value)) + " strength";
            if (feature == RuntimeProfileFeature.Gravity)
                return FormatFloat(value * 100F) + "% (x" + FormatFloat(value) + ")";
            if (feature == RuntimeProfileFeature.TimeOfDay)
                return FormatFloat(value / 3600F) + ":00";
            if (feature == RuntimeProfileFeature.FovSlider)
                return FormatFloat(value) + " degrees";
            if (feature == RuntimeProfileFeature.Hover)
                return FormatFloat(value) + " speed";
            return "x" + FormatFloat(value);
        }

