        private void ApplyBarnFindUnlocks(RemoteDatabase db)
        {
            var touched = 0;
            touched += ApplyBarnFindProfileTable(db, "Profile0_BarnFinds", "_backup_Database_BarnFindUnlock_Profile0");
            touched += ApplyBarnFindProfileTable(db, "NewProfile_BarnFinds", "_backup_Database_BarnFindUnlock_NewProfile");
            var granted = GrantBarnFindCars(db);
            SyncBarnFindVinsToGarage(db, "Profile0_BarnFinds", "Profile0_Career_Garage");
            SyncBarnFindVinsToGarage(db, "NewProfile_BarnFinds", "NewProfile_Career_Garage");

            if (db.TableExists("BarnfindCars"))
                LogCount(db, "BarnfindCars metadata rows", "SELECT count(*) FROM BarnfindCars");
            if (granted > 0)
                Log("Barn Find Unlocker added free-car/profile grant support for " + granted.ToString(CultureInfo.InvariantCulture) + " barn-find car(s).");

            var missingGrants = CountBarnFindCarsMissingStableGrant(db);
            if (missingGrants > 0)
                throw new InvalidOperationException("Barn Find verification failed: " + missingGrants.ToString(CultureInfo.InvariantCulture) + " barn-find car(s) are still missing the stable grant row.");

            var missingGarage = CountBarnFindCarsMissingFromGarage(db);
            if (missingGarage > 0)
                Log("Barn Find note: " + missingGarage.ToString(CultureInfo.InvariantCulture) + " barn-find car(s) may appear after FH6 redeems the queued grant.");

            if (touched == 0)
                throw new InvalidOperationException("No supported barn-find profile table was found.");
        }

        private int ApplyBarnFindProfileTable(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName) ||
                !db.ColumnExists(tableName, "CarOrdinal") ||
                !db.ColumnExists(tableName, "State"))
            {
                return 0;
            }

            var tableSql = EscapeIdentifierForSql(tableName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT * FROM " + tableSql + ";");

            if (db.TableExists("BarnfindCars") && db.ColumnExists("BarnfindCars", "CarId"))
            {
                var columns = new List<string>();
                var values = new List<string>();
                AddInsertColumn(columns, values, "CarOrdinal", "barn.CarId");
                AddInsertColumn(columns, values, "State", "5");
                if (db.ColumnExists(tableName, "VIN"))
                    AddInsertColumn(columns, values, "VIN", "lower(printf('%08X-0000-4000-8000-%012X', barn.CarId, barn.CarId))");

                ExecuteAutoshowSql(db,
                    "INSERT OR IGNORE INTO " + tableSql + " (" + string.Join(", ", columns.ToArray()) + ") " +
                    "SELECT " + string.Join(", ", values.ToArray()) + " FROM BarnfindCars barn " +
                    "WHERE barn.CarId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM " + tableSql + " existing WHERE existing.CarOrdinal = barn.CarId);");
            }

            ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET State = 5 WHERE State IS NULL OR State < 5;");
            if (db.ColumnExists(tableName, "VIN"))
            {
                var garageTable = tableName.StartsWith("NewProfile", StringComparison.OrdinalIgnoreCase)
                    ? "NewProfile_Career_Garage"
                    : "Profile0_Career_Garage";
                SyncBarnFindVinsToGarage(db, tableName, garageTable);
                ExecuteAutoshowSql(db,
                    "UPDATE " + tableSql + " SET VIN = lower(printf('%08X-0000-4000-8000-%012X', CarOrdinal, CarOrdinal)) " +
                    "WHERE VIN IS NULL OR VIN = '' OR VIN = '00000000-0000-0000-0000-000000000000';");
            }

            LogCount(db, tableName + " rows not restored", "SELECT count(*) FROM " + tableSql + " WHERE State IS NULL OR State < 5");
            LogCount(db, tableName + " total rows", "SELECT count(*) FROM " + tableSql);
            return 1;
        }

        private void SyncBarnFindVinsToGarage(RemoteDatabase db, string barnTableName, string garageTableName)
        {
            if (!db.TableExists(barnTableName) ||
                !db.ColumnExists(barnTableName, "CarOrdinal") ||
                !db.ColumnExists(barnTableName, "VIN") ||
                !db.TableExists(garageTableName) ||
                !db.ColumnExists(garageTableName, "CarId") ||
                !db.ColumnExists(garageTableName, "Guid"))
            {
                return;
            }

            var barnSql = EscapeIdentifierForSql(barnTableName);
            var garageSql = EscapeIdentifierForSql(garageTableName);
            ExecuteAutoshowSql(db,
                "UPDATE " + barnSql + " SET VIN = (" +
                "SELECT g.Guid FROM " + garageSql + " g WHERE g.CarId = " + barnSql + ".CarOrdinal AND g.Guid IS NOT NULL AND g.Guid <> '' ORDER BY g.rowid LIMIT 1) " +
                "WHERE EXISTS (SELECT 1 FROM " + garageSql + " g WHERE g.CarId = " + barnSql + ".CarOrdinal AND g.Guid IS NOT NULL AND g.Guid <> '') " +
                "AND (VIN IS NULL OR VIN = '' OR VIN <> (SELECT g.Guid FROM " + garageSql + " g WHERE g.CarId = " + barnSql + ".CarOrdinal AND g.Guid IS NOT NULL AND g.Guid <> '' ORDER BY g.rowid LIMIT 1));");
        }

        private int GrantBarnFindCars(RemoteDatabase db)
        {
            var idSql = BuildBarnFindIdSourceSql(db);
            if (string.IsNullOrWhiteSpace(idSql))
                return 0;

            var result = db.Query(idSql);
            var requests = new List<CarTableGrantRequest>();
            var seen = new HashSet<int>();
            foreach (var row in result.Rows)
            {
                if (row.Count == 0)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0 || !seen.Add(carId))
                    continue;
                requests.Add(new CarTableGrantRequest(carId, "Barn Find CarId " + carId.ToString(CultureInfo.InvariantCulture), 1));
            }

            if (requests.Count == 0)
                return 0;

            ApplyAutoshowUnlock(db);
            var grants = ApplySelectedCarsAddAllGrantBatch(db, requests);
            Log("Barn-find cars queued through Add All style grants: " + grants.Count.ToString(CultureInfo.InvariantCulture) + ".");
            Log("Barn-find cars missing from garage after queue: " + CountBarnFindCarsMissingFromGarage(db).ToString(CultureInfo.InvariantCulture));
            return grants.Count;
        }

        private long CountBarnFindCarsMissingStableGrant(RemoteDatabase db)
        {
            var idSql = BuildBarnFindIdSourceSql(db);
            if (string.IsNullOrWhiteSpace(idSql) ||
                !db.TableExists("Profile0_FreeCars") ||
                !db.ColumnExists("Profile0_FreeCars", "CarId") ||
                !db.ColumnExists("Profile0_FreeCars", "FreeCount"))
            {
                return 0;
            }

            long missing = 0;
            foreach (var row in db.Query(idSql).Rows)
            {
                if (row.Count == 0)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                var queued = db.QueryScalarLong("SELECT COALESCE(MAX(FreeCount), 0) FROM Profile0_FreeCars WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                if (queued <= 0)
                    missing++;
            }
            return missing;
        }

        private long CountBarnFindCarsMissingFromGarage(RemoteDatabase db)
        {
            var idSql = BuildBarnFindIdSourceSql(db);
            if (string.IsNullOrWhiteSpace(idSql))
                return 0;
            var garageTable = ResolveActiveGarageTable(db);
            var garageSql = EscapeIdentifierForSql(garageTable);
            long missing = 0;
            foreach (var row in db.Query(idSql).Rows)
            {
                if (row.Count == 0)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                var owned = db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0;
                if (owned <= 0)
                    missing++;
            }
            return missing;
        }

