        private void ApplyCreativePaintLiveryUnlocks(RemoteDatabase db)
        {
            var touched = 0;

            if (db.TableExists("CarExceptions"))
            {
                var columns = new[]
                    {
                        "NoMirrors",
                        "NoWindows",
                        "NoHoodStock",
                        "NoHoodAftermarket",
                        "NoPaintableWingStock",
                        "NoPaintableWingAftermarket",
                        "NoDecalsWingStock",
                        "NoDecalsWingAftermarket"
                    }
                    .Where(column => db.ColumnExists("CarExceptions", column))
                    .ToList();
                if (columns.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_CarExceptions AS SELECT * FROM CarExceptions;");
                    ExecuteAutoshowSql(db, "UPDATE CarExceptions SET " + string.Join(", ", columns.Select(column => EscapeIdentifierForSql(column) + " = 0").ToArray()) +
                        " WHERE " + string.Join(" OR ", columns.Select(column => EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 0").ToArray()) + ";");
                    touched++;
                    LogCount(db, "Customization car exception rows still gated", "SELECT count(*) FROM CarExceptions WHERE " + string.Join(" OR ", columns.Select(column => EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 0").ToArray()));
                }
            }

            if (db.TableExists("CarUpgradeExceptions"))
            {
                var columns = new[] { "NoRimStyles" }
                    .Where(column => db.ColumnExists("CarUpgradeExceptions", column))
                    .ToList();
                if (columns.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_CarUpgradeExceptions AS SELECT * FROM CarUpgradeExceptions;");
                    ExecuteAutoshowSql(db, "UPDATE CarUpgradeExceptions SET " + string.Join(", ", columns.Select(column => EscapeIdentifierForSql(column) + " = 0").ToArray()) +
                        " WHERE " + string.Join(" OR ", columns.Select(column => EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 0").ToArray()) + ";");
                    touched++;
                    LogCount(db, "Rim/custom upgrade exception rows still gated", "SELECT count(*) FROM CarUpgradeExceptions WHERE " + string.Join(" OR ", columns.Select(column => EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 0").ToArray()));
                }
            }

            if (db.TableExists("CarColorTypeExceptions"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "CarColorTypeExceptions", sets, "HideNormalColors", "0");
                AddColumnSetIfExists(db, "CarColorTypeExceptions", sets, "HideManufacturerColors", "0");
                AddColumnSetIfExists(db, "CarColorTypeExceptions", sets, "HideSpecialColors", "0");
                AddColumnSetIfExists(db, "CarColorTypeExceptions", sets, "AllowStockManufacturerColorsForWheels", "1");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_CarColorTypeExceptions AS SELECT * FROM CarColorTypeExceptions;");
                    ExecuteAutoshowSql(db, "UPDATE CarColorTypeExceptions SET " + string.Join(", ", sets.Values.ToArray()) + ";");
                    touched++;
                }
            }

            ApplyCreativeReleaseOrderOpen(db, "List_LiveryMaterials", "_backup_Database_CreativeUnlock_LiveryMaterials");
            ApplyCreativeReleaseOrderOpen(db, "PaintableGroups", "_backup_Database_CreativeUnlock_PaintableGroups");
            ApplyCreativeReleaseOrderOpen(db, "LiveryStripes", "_backup_Database_CreativeUnlock_LiveryStripes");

            if (db.TableExists("Livery_VinylsDecals") && db.ColumnExists("Livery_VinylsDecals", "SortOrder"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_LiveryVinylsDecals AS SELECT * FROM Livery_VinylsDecals;");
                ExecuteAutoshowSql(db, "UPDATE Livery_VinylsDecals SET SortOrder = COALESCE(NULLIF(SortOrder, 0), ID * 10) WHERE SortOrder IS NULL OR SortOrder = 0;");
                touched++;
            }

            if (db.TableExists("Livery_Categories") && db.ColumnExists("Livery_Categories", "sortOrder"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_LiveryCategories AS SELECT * FROM Livery_Categories;");
                ExecuteAutoshowSql(db, "UPDATE Livery_Categories SET sortOrder = COALESCE(NULLIF(sortOrder, 0), ID * 1000) WHERE sortOrder IS NULL OR sortOrder = 0;");
                touched++;
            }

            if (db.TableExists("Livery_DecalsSortOrder") &&
                db.TableExists("Livery_Decals") &&
                db.TableExists("Data_Car") &&
                db.ColumnExists("Livery_DecalsSortOrder", "MakeID") &&
                db.ColumnExists("Livery_DecalsSortOrder", "Sequence") &&
                db.ColumnExists("Livery_DecalsSortOrder", "Livery_DecalID") &&
                db.ColumnExists("Livery_Decals", "ID") &&
                db.ColumnExists("Data_Car", "MakeID"))
            {
                var missingBefore = db.QueryScalarLong(
                    "SELECT count(*) FROM (SELECT DISTINCT MakeID FROM Data_Car WHERE MakeID IS NOT NULL) makes CROSS JOIN Livery_Decals decals " +
                    "WHERE NOT EXISTS (SELECT 1 FROM Livery_DecalsSortOrder sort WHERE sort.MakeID = makes.MakeID AND sort.Livery_DecalID = decals.ID)") ?? 0;
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_CreativeUnlock_DecalsSortOrder AS SELECT * FROM Livery_DecalsSortOrder;");
                ExecuteAutoshowSql(db,
                    "INSERT INTO Livery_DecalsSortOrder (MakeID, Sequence, Livery_DecalID) " +
                    "SELECT makes.MakeID, COALESCE((SELECT MAX(existing.Sequence) FROM Livery_DecalsSortOrder existing WHERE existing.MakeID = makes.MakeID), 0) + decals.ID, decals.ID " +
                    "FROM (SELECT DISTINCT MakeID FROM Data_Car WHERE MakeID IS NOT NULL) makes CROSS JOIN Livery_Decals decals " +
                    "WHERE NOT EXISTS (SELECT 1 FROM Livery_DecalsSortOrder sort WHERE sort.MakeID = makes.MakeID AND sort.Livery_DecalID = decals.ID);");
                var missingAfter = db.QueryScalarLong(
                    "SELECT count(*) FROM (SELECT DISTINCT MakeID FROM Data_Car WHERE MakeID IS NOT NULL) makes CROSS JOIN Livery_Decals decals " +
                    "WHERE NOT EXISTS (SELECT 1 FROM Livery_DecalsSortOrder sort WHERE sort.MakeID = makes.MakeID AND sort.Livery_DecalID = decals.ID)") ?? 0;
                Log("Livery decal make mappings added: " + Math.Max(0L, missingBefore - missingAfter).ToString(CultureInfo.InvariantCulture) + ".");
                touched++;
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported customization exception, paint, livery, decal, or vinyl tables were found.");
        }

        private void ApplyCreativeReleaseOrderOpen(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName))
                return;

            var tableSql = EscapeIdentifierForSql(tableName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT * FROM " + tableSql + ";");
            if (db.ColumnExists(tableName, "releaseOrder"))
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET releaseOrder = 0 WHERE releaseOrder IS NULL OR releaseOrder <> 0;");
            if (db.ColumnExists(tableName, "SortOrder") && db.ColumnExists(tableName, "ID"))
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET SortOrder = COALESCE(NULLIF(SortOrder, 0), ID * 1000) WHERE SortOrder IS NULL OR SortOrder = 0;");
        }

