        private void ApplyContentOfferUnlocks(RemoteDatabase db)
        {
            if (!db.TableExists("ContentOffers"))
                throw new InvalidOperationException("ContentOffers table was not found.");

            var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddColumnSetIfExists(db, "ContentOffers", sets, "Visible", "1");
            AddColumnSetIfExists(db, "ContentOffers", sets, "IsPurchased", "1");
            AddColumnSetIfExists(db, "ContentOffers", sets, "IsFree", "1");
            AddColumnSetIfExists(db, "ContentOffers", sets, "IsNew", "1");
            AddColumnSetIfExists(db, "ContentOffers", sets, "ShouldUpsell", "0");
            if (sets.Count == 0)
                throw new InvalidOperationException("ContentOffers did not expose visible/purchased/free/new/upsell columns.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_ContentOfferUnlock_ContentOffers AS SELECT * FROM ContentOffers;");
            ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", sets.Values.ToArray()) + ";");

            if (db.TableExists("ContentOffersMapping"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_ContentOfferUnlock_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00';");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE Quantity IS NULL OR Quantity < 1;");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE IsPromo IS NULL OR IsPromo <> 0;");
            }

            LogCount(db, "Content offers still hidden/not purchased/not free", "SELECT count(*) FROM ContentOffers WHERE (Visible IS NULL OR Visible <> 1) OR (IsPurchased IS NULL OR IsPurchased <> 1) OR (IsFree IS NULL OR IsFree <> 1)");
        }

