        private void ApplyLicensePlateHiddenCharacters(RemoteDatabase db)
        {
            if (!db.TableExists("LicensePlateCharacters") || !db.ColumnExists("LicensePlateCharacters", "Hidden"))
                throw new InvalidOperationException("LicensePlateCharacters.Hidden was not found.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_LicensePlateCharacters AS SELECT * FROM LicensePlateCharacters;");
            var hiddenBefore = db.QueryScalarLong("SELECT count(*) FROM LicensePlateCharacters WHERE Hidden IS NOT NULL AND Hidden <> 0") ?? 0;
            ExecuteAutoshowSql(db, "UPDATE LicensePlateCharacters SET Hidden = 0 WHERE Hidden IS NULL OR Hidden <> 0;");
            var hiddenAfter = db.QueryScalarLong("SELECT count(*) FROM LicensePlateCharacters WHERE Hidden IS NOT NULL AND Hidden <> 0") ?? 0;
            Log("License plate hidden characters before=" + hiddenBefore.ToString(CultureInfo.InvariantCulture) +
                "; after=" + hiddenAfter.ToString(CultureInfo.InvariantCulture) + ".");
        }

