        private void RestoreWholeTableBackup(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName))
                return;
            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            db.Execute("DELETE FROM " + tableSql + ";");
            db.Execute("INSERT INTO " + tableSql + " SELECT * FROM " + backupSql + ";");
            db.Execute("DROP TABLE IF EXISTS " + backupSql + ";");
            Log("Restored " + tableName + " from " + backupName + ".");
        }

        private void ClearNewCarTags()
