            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_ProfileEditor_NewTags AS SELECT CarId, HasCurrentOwnerViewedCar FROM " + garageSql + ";");
            ExecuteAutoshowSql(db, "UPDATE " + garageSql + " SET HasCurrentOwnerViewedCar = 1 WHERE HasCurrentOwnerViewedCar IS NULL OR HasCurrentOwnerViewedCar <> 1;");
            LogCount(db, "Cars still marked new", "SELECT count(*) FROM " + garageSql + " WHERE HasCurrentOwnerViewedCar IS NULL OR HasCurrentOwnerViewedCar <> 1");
