        private void RemoveDuplicateGarageCars()
        {
            var db = RequireDatabase();
            var garageTable = ResolveActiveGarageTable(db);
            var tableSql = EscapeIdentifierForSql(garageTable);

            var before = db.QueryScalarLong(GarageDuplicateExtraRowsSql(garageTable)) ?? 0;
            Log("Remove Dupe Cars starting. Duplicate extra garage rows before cleanup: " + before.ToString(CultureInfo.InvariantCulture));
            if (before <= 0)
            {
                Log("Remove Dupe Cars found no duplicate garage rows.");
                SetProfileStatus("No duplicates found");
                ShowInfo("No duplicate garage cars were found.");
                return;
            }

            var candidates = BuildDuplicateGarageRemovalCandidates(db, garageTable);
            if (candidates.Count == 0)
            {
                Log("Remove Dupe Cars found no safe rows to remove.");
                SetProfileStatus("No duplicate rows selected");
                ShowInfo("No duplicate garage rows were selected for removal.");
                return;
            }

            var approved = PromptForGarageRemovalCandidates(
                candidates,
                "Remove Duplicate Cars",
                "Review the duplicate garage rows Luna plans to remove. Uncheck anything you want to keep, then press Remove.");
            if (approved.Count == 0)
            {
                Log("Remove Dupe Cars canceled before deleting any garage rows.");
                SetProfileStatus("Remove duplicates canceled");
                return;
            }

            db.Execute("CREATE TABLE IF NOT EXISTS _backup_Database_RemoveDupeCars AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
            DeleteGarageRowsByRowId(db, garageTable, approved);

            var after = db.QueryScalarLong(GarageDuplicateExtraRowsSql(garageTable)) ?? 0;
            var removed = before - after;
            if (removed < 0)
                removed = approved.Count;

            Log("Remove Dupe Cars finished. Removed " + approved.Count.ToString(CultureInfo.InvariantCulture) + " selected duplicate garage row(s).");
            LogCount(db, "Garage duplicate extra rows remaining", GarageDuplicateExtraRowsSql(garageTable));
            LogCount(db, "Garage total rows", "SELECT count(*) FROM " + tableSql);
            LogCount(db, "Garage distinct cars", "SELECT count(DISTINCT CarId) FROM " + tableSql + " WHERE CarId IS NOT NULL");
            SetProfileStatus("Duplicate garage cars removed");
        }

        private List<GarageRemovalCandidate> BuildDuplicateGarageRemovalCandidates(RemoteDatabase db, string garageTable)
        {
            var rows = QueryGarageRemovalRows(db, garageTable, string.Empty);
            var candidates = new List<GarageRemovalCandidate>();

            foreach (var group in rows.Where(row => row.CarId > 0).GroupBy(row => row.CarId))
            {
                var ordered = group
                    .OrderByDescending(row => row.IsFavorite)
                    .ThenByDescending(row => row.DistanceDriven)
                    .ThenBy(row => row.SortId)
                    .ToList();
                if (ordered.Count <= 1)
                    continue;

                foreach (var row in ordered)
                    row.Copies = ordered.Count;

                candidates.AddRange(ordered.Skip(1));
            }

            return candidates
                .OrderBy(row => row.DisplayName, StringComparer.OrdinalIgnoreCase)
                .ThenBy(row => row.CarId)
                .ThenBy(row => row.RowId)
                .ToList();
        }

        private List<GarageRemovalCandidate> QueryGarageRemovalRows(RemoteDatabase db, string garageTable, string whereSql)
        {
            EnsureCarStringTablesLoaded();

            var tableSql = EscapeIdentifierForSql(garageTable);
            var hasDataCar = db.TableExists("Data_Car");
            var dataJoin = hasDataCar && db.ColumnExists("Data_Car", "Id")
                ? " LEFT JOIN Data_Car data ON data.Id = g.CarId "
                : string.Empty;
            var yearExpr = hasDataCar && db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = hasDataCar && db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelParts = new List<string>();
            if (hasDataCar && db.ColumnExists("Data_Car", "DisplayName"))
                modelParts.Add("data.[DisplayName]");
            if (hasDataCar && db.ColumnExists("Data_Car", "ModelShort"))
                modelParts.Add("data.[ModelShort]");
            if (hasDataCar && db.ColumnExists("Data_Car", "MediaName"))
                modelParts.Add("data.[MediaName]");
            modelParts.Add("''");
            var modelExpr = "COALESCE(" + string.Join(", ", modelParts.ToArray()) + ")";
            var sortIdExpr = db.ColumnExists(garageTable, "Id") ? "COALESCE(g.[Id], g.rowid)" : "g.rowid";
            var garageIdExpr = db.ColumnExists(garageTable, "Id") ? "COALESCE(g.[Id], g.rowid)" : "g.rowid";
            var favoriteExpr = db.ColumnExists(garageTable, "IsFavorite") ? "COALESCE(g.[IsFavorite], 0)" : "0";
            var distanceExpr = db.ColumnExists(garageTable, "DistanceDriven") ? "COALESCE(g.[DistanceDriven], 0)" : "0";

            var sql =
                "SELECT g.rowid, g.CarId, " + garageIdExpr + ", " + favoriteExpr + ", " + distanceExpr + ", " +
                yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + sortIdExpr + " " +
                "FROM " + tableSql + " g " + dataJoin +
                "WHERE g.CarId IS NOT NULL " + (string.IsNullOrWhiteSpace(whereSql) ? string.Empty : "AND (" + whereSql + ") ") +
                "ORDER BY g.CarId, g.rowid;";

            var result = db.Query(sql);
            var rows = new List<GarageRemovalCandidate>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 9)
                    continue;

                var carId = ToInt(row[1]);
                if (carId <= 0)
                    continue;

                var year = ToDisplayString(row[5]);
                var make = TranslateCarText(ToDisplayString(row[6]), _carMakeStrings);
                var model = TranslateCarText(ToDisplayString(row[7]), _carNameStrings);
                double distance;
                TryToDouble(row[4], out distance);

                rows.Add(new GarageRemovalCandidate(
                    ToLong(row[0]),
                    carId,
                    ToLong(row[2]),
                    ToLong(row[3]),
                    distance,
                    FormatCarDisplayName(carId, year, make, model),
                    ToLong(row[8])));
            }

            return rows;
        }

