        private void DeleteGarageRowsByRowId(RemoteDatabase db, string garageTable, List<GarageRemovalCandidate> candidates)
        {
            var ids = (candidates ?? new List<GarageRemovalCandidate>())
                .Where(candidate => candidate != null && candidate.RowId > 0)
                .Select(candidate => candidate.RowId)
                .Distinct()
                .ToList();
            if (ids.Count == 0)
                return;

            var tableSql = EscapeIdentifierForSql(garageTable);
            for (var i = 0; i < ids.Count; i += 400)
            {
                var chunk = ids.Skip(i).Take(400).Select(id => id.ToString(CultureInfo.InvariantCulture)).ToArray();
                db.Execute("DELETE FROM " + tableSql + " WHERE rowid IN (" + string.Join(",", chunk) + ");");
            }
        }

        private void FixGarageThumbnails()
        {
