            var garageTable = ResolveProfileTable(db, "Profile0_Career_Garage", "NewProfile_Career_Garage", "CarId", "Thumbnail");
            var garageSql = EscapeIdentifierForSql(garageTable);
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Garage or Data_Car table was not found.");
            if (!db.ColumnExists("Data_Car", "Id") ||
                !db.ColumnExists("Data_Car", "Thumbnail"))
                throw new InvalidOperationException("Thumbnail columns were not found.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_ProfileEditor_Thumbnails AS SELECT CarId, Thumbnail FROM " + garageSql + ";");
            ExecuteAutoshowSql(db, "UPDATE " + garageSql + " SET Thumbnail = (SELECT Data_Car.Thumbnail FROM Data_Car WHERE Data_Car.Id = " + garageSql + ".CarId) WHERE EXISTS (SELECT 1 FROM Data_Car WHERE Data_Car.Id = " + garageSql + ".CarId AND Data_Car.Thumbnail IS NOT NULL);");
            Log("Garage thumbnails refreshed from Data_Car.");
        }

