        private void StartAuctionHouseAllCars(Button feedbackButton)
        {
            try
            {
                var db = RequireDatabase();
                var rows = QueryAuctionHouseCandidateRows(db);
                if (rows.Count == 0)
                {
                    ShowInfo("All supported cars are already auctionable.");
                    return;
                }

                var selectedIds = ShowAuctionHouseAllCarsPreviewDialog(rows);
                if (selectedIds == null || selectedIds.Count == 0)
                {
                    ShowInfo("No auction house cars were selected.");
                    return;
                }

                RunWorker("Auction All Cars", delegate { ApplyAuctionHouseSelectedCars(selectedIds); }, feedbackButton);
            }
            catch (Exception ex)
            {
                ShowInfo(ex.Message);
            }
        }

        private List<DatabaseCarRow> QueryAuctionHouseCandidateRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");

            var positiveColumns = GetSupportedAuctionPositiveColumns(db);
            var negativeColumns = GetSupportedAuctionNegativeColumns(db);
            if (positiveColumns.Count == 0 && negativeColumns.Count == 0)
                throw new InvalidOperationException("No supported auction-house column was found. Expected Data_Car.IsAuctionable or Data_Car.NotAvailableInAuctionHouse.");

            var needsWhere = BuildAuctionHouseNeedsWhere(positiveColumns, negativeColumns);
            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var hasPerformanceIndex = db.ColumnExists("Data_Car", "PerformanceIndex");
            var hasPi = db.ColumnExists("Data_Car", "PI");
            var piExpr = hasPerformanceIndex && hasPi
                ? "COALESCE(data.[PerformanceIndex], data.[PI], 0)"
                : (hasPerformanceIndex ? "COALESCE(data.[PerformanceIndex], 0)" : (hasPi ? "COALESCE(data.[PI], 0)" : "0"));
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";
            var garageTable = ResolveOptionalGarageTable(db);
            var copiesExpr = string.IsNullOrEmpty(garageTable)
                ? "0"
                : "(SELECT count(*) FROM " + EscapeIdentifierForSql(garageTable) + " garage WHERE garage.[CarId] = data.[Id])";
            var sql =
                "SELECT data.[Id], " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", " + copiesExpr + " " +
                "FROM Data_Car data WHERE data.[Id] IS NOT NULL AND data.[Id] > 0 AND (" + needsWhere + ") ORDER BY data.[Id];";

            var result = db.Query(sql);
            var rows = new List<DatabaseCarRow>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 7)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                rows.Add(new DatabaseCarRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    FormatCarNumber(row[6]),
                    "Will enable"));
            }

            return rows;
        }

