        private void ApplyAuctionHouseSelectedCars(List<int> carIds)
        {
            if (carIds == null || carIds.Count == 0)
                throw new InvalidOperationException("No auction house cars were selected.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");

            var positiveColumns = GetSupportedAuctionPositiveColumns(db);
            var negativeColumns = GetSupportedAuctionNegativeColumns(db);
            if (positiveColumns.Count == 0 && negativeColumns.Count == 0)
                throw new InvalidOperationException("No supported auction-house column was found. Expected Data_Car.IsAuctionable or Data_Car.NotAvailableInAuctionHouse.");

            var backupColumns = positiveColumns.Concat(negativeColumns).Distinct(StringComparer.OrdinalIgnoreCase).ToArray();
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_AuctionHouse_DataCar AS SELECT Id, " + string.Join(", ", backupColumns.Select(EscapeIdentifierForSql).ToArray()) + " FROM Data_Car;");

            var sets = positiveColumns.Select(column => EscapeIdentifierForSql(column) + " = 1")
                .Concat(negativeColumns.Select(column => EscapeIdentifierForSql(column) + " = 0"))
                .ToArray();

            var distinctIds = carIds.Where(id => id > 0).Distinct().ToList();
            for (var i = 0; i < distinctIds.Count; i += 400)
            {
                var idsSql = BuildIntegerInList(distinctIds.Skip(i).Take(400));
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET " + string.Join(", ", sets) + " WHERE Id IN (" + idsSql + ");");
            }

            var selectedWhere = "Id IN (" + BuildIntegerInList(distinctIds) + ")";
            LogCount(db, "Selected cars still blocked from auction", "SELECT count(*) FROM Data_Car WHERE " + selectedWhere + " AND (" + BuildAuctionHouseNeedsWhere(positiveColumns, negativeColumns) + ")");
            SetProfileStatus("Auction cars applied");
            Log("Auction House All Cars applied to " + distinctIds.Count.ToString(CultureInfo.InvariantCulture) + " selected car(s).");
            ShowInfo("Auction House cars applied." + Environment.NewLine + Environment.NewLine + "Reload the garage or Auction House screens so FH6 refreshes the car list.");
        }

