        private static string BuildAuctionHouseNeedsWhere(IEnumerable<string> positiveColumns, IEnumerable<string> negativeColumns)
        {
            var checks = new List<string>();
            foreach (var column in positiveColumns ?? new string[0])
                checks.Add("COALESCE(" + EscapeIdentifierForSql(column) + ", 0) <> 1");
            foreach (var column in negativeColumns ?? new string[0])
                checks.Add("COALESCE(" + EscapeIdentifierForSql(column) + ", 0) <> 0");
            return checks.Count == 0 ? "0=1" : string.Join(" OR ", checks.ToArray());
        }

        private bool IsDisableDamageActive(RemoteDatabase db)
        {
            if (db == null)
                return _disableDamageSwitchOn;

            if (db.TableExists("List_DamageModDef"))
            {
                var damageColumns = GetSupportedDamageDefinitionColumns(db);
                if (damageColumns.Count > 0)
                {
                    var checks = damageColumns
                        .Select(column => "ABS(COALESCE(" + EscapeIdentifierForSql(column) + ", 0)) > 0.000001")
                        .ToArray();
                    var nonZero = db.QueryScalarLong("SELECT count(*) FROM List_DamageModDef WHERE " + string.Join(" OR ", checks)) ?? 0;
                    if (nonZero == 0)
                        return true;
                }
            }

            foreach (var table in GetSupportedDamageGarageTables(db))
            {
                var flagColumns = GetSupportedDamageGarageFlagColumns(db, table);
                if (flagColumns.Count == 0)
                    continue;

                var checks = flagColumns
                    .Select(column => "COALESCE(" + EscapeIdentifierForSql(column) + ", 0) <> 1")
                    .ToArray();
                var offRows = db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(table) + " WHERE " + string.Join(" OR ", checks)) ?? 0;
                if (offRows == 0)
                    return true;
            }

            return false;
        }

        private int ApplyDisableDamageToggle(RemoteDatabase db, bool enable)
        {
            var touched = 0;
            touched += ApplyGarageDamageDisableFlags(db, enable);
            touched += ApplyDamageDefinitionDisable(db, enable);
            return touched;
        }

        private int ApplyGarageDamageDisableFlags(RemoteDatabase db, bool enable)
        {
            var touched = 0;
            foreach (var table in GetSupportedDamageGarageTables(db))
            {
                var flagColumns = GetSupportedDamageGarageFlagColumns(db, table);
                if (flagColumns.Count == 0)
                    continue;

                var tableSql = EscapeIdentifierForSql(table);
                var backupName = "_backup_Database_DisableDamage_" + table;
                var backupSql = EscapeIdentifierForSql(backupName);
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backupSql + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");

                if (enable)
                {
                    var sets = flagColumns.Select(column => EscapeIdentifierForSql(column) + " = 1").ToArray();
                    ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + string.Join(", ", sets) + ";");
                }
                else
                {
                    var restored = RestoreNumericColumnSet(db, table, backupName, flagColumns);
                    if (restored <= 0)
                    {
                        var sets = flagColumns.Select(column => EscapeIdentifierForSql(column) + " = 0").ToArray();
                        ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + string.Join(", ", sets) + ";");
                    }
                }

                touched++;
            }

            return touched;
        }

        private int ApplyDamageDefinitionDisable(RemoteDatabase db, bool enable)
        {
            if (!db.TableExists("List_DamageModDef"))
                return 0;

            var columns = GetSupportedDamageDefinitionColumns(db);
            if (columns.Count == 0)
                return 0;

            const string tableName = "List_DamageModDef";
            const string backupName = "_backup_Database_DisableDamage_ListDamageModDef";
            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);

            if (enable)
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backupSql + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
                var sets = columns.Select(column => EscapeIdentifierForSql(column) + " = 0").ToArray();
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + string.Join(", ", sets) + ";");
                LogCount(db, "Damage modifier rows still active", "SELECT count(*) FROM " + tableSql + " WHERE " + string.Join(" OR ", columns.Select(column => "ABS(COALESCE(" + EscapeIdentifierForSql(column) + ", 0)) > 0.000001").ToArray()));
                return 1;
            }

            var restored = RestoreNumericColumnSet(db, tableName, backupName, columns);
            if (restored <= 0)
                throw new InvalidOperationException("Disable Damage backup was not found yet. Turn it ON once before using OFF restore.");
            return 1;
        }

