        private void ApplyDlcGateUnlocks(RemoteDatabase db, IEnumerable<int> offerIds, bool applyGlobalInstallFlags, bool verifyAfterApply)
        {
            var touched = 0;
            var selectedOfferIds = (offerIds ?? Enumerable.Empty<int>())
                .Where(id => id > 0)
                .Distinct()
                .ToList();
            var hasSelectedOffers = selectedOfferIds.Count > 0;
            var selectedOfferSql = hasSelectedOffers ? BuildIntegerInList(selectedOfferIds) : string.Empty;

            if (db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentId") &&
                db.ColumnExists("ContentOffersMapping", "ContentType") &&
                db.TableExists("Data_Car"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_DlcGates_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                if (!hasSelectedOffers)
                    InsertMissingContentOfferMappings(db);
            }

            var offerWhere = hasSelectedOffers
                ? " WHERE Id IN (" + selectedOfferSql + ")"
                : (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "OfferId") && db.ColumnExists("ContentOffersMapping", "ContentType")
                    ? " WHERE Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE ContentType = 1)"
                    : string.Empty);

            if (db.TableExists("ContentOffers"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "ContentOffers", sets, "Visible", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsPurchased", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsFree", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsNew", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "ShouldUpsell", "0");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_DlcGates_ContentOffers AS SELECT * FROM ContentOffers;");
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", sets.Values.ToArray()) + offerWhere + ";");
                    touched++;
                }
            }

            if (db.TableExists("ContentOffersMapping"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_DlcGates_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                var mappingWhere = hasSelectedOffers
                    ? "OfferId IN (" + selectedOfferSql + ") AND "
                    : (db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType = 1 AND " : string.Empty);
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE " + mappingWhere + "(ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE " + mappingWhere + "(Quantity IS NULL OR Quantity < 1);");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE " + mappingWhere + "(IsPromo IS NULL OR IsPromo <> 0);");
                if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem") && db.ColumnExists("ContentOffersMapping", "ContentType"))
                {
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 1 WHERE " + mappingWhere + "(IsAutoRedeem IS NULL OR IsAutoRedeem <> 1);");
                    var nonCarMappingWhere = hasSelectedOffers
                        ? "OfferId IN (" + selectedOfferSql + ") AND ContentType <> 1"
                        : "ContentType <> 1";
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 0 WHERE " + nonCarMappingWhere + " AND (IsAutoRedeem IS NULL OR IsAutoRedeem <> 0);");
                }
                touched++;
            }

            ApplyDlcGateDataCarFlagsForOffers(db, selectedOfferSql, hasSelectedOffers);
            if (applyGlobalInstallFlags)
                ApplyAllIeCarInstallFlags(db);

            if (hasSelectedOffers)
                ApplyOnDiscContentBridgeForOffers(db, selectedOfferSql);
            else
                ApplyOnDiscContentBridge(db);

            if (touched == 0)
                throw new InvalidOperationException("No supported DLC/content offer tables were found.");

            if (verifyAfterApply && db.TableExists("ContentOffers"))
            {
                var checks = new List<string>();
                if (db.ColumnExists("ContentOffers", "Visible"))
                    checks.Add("Visible IS NULL OR Visible <> 1");
                if (db.ColumnExists("ContentOffers", "IsPurchased"))
                    checks.Add("IsPurchased IS NULL OR IsPurchased <> 1");
                if (db.ColumnExists("ContentOffers", "IsFree"))
                    checks.Add("IsFree IS NULL OR IsFree <> 1");
                if (checks.Count > 0)
                    LogCount(db, hasSelectedOffers ? "Selected content offers still gated" : "Car content offers still gated", "SELECT count(*) FROM ContentOffers" + offerWhere + (offerWhere.Length == 0 ? " WHERE " : " AND ") + "(" + string.Join(" OR ", checks.ToArray()) + ")");
            }
        }

        private void ApplyDlcGateDataCarFlagsForOffers(RemoteDatabase db, string selectedOfferSql, bool hasSelectedOffers)
        {
            if (db == null ||
                !db.TableExists("Data_Car") ||
                !db.ColumnExists("Data_Car", "Id") ||
                !db.TableExists("ContentOffersMapping") ||
                !db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId"))
                return;

            var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddColumnSetIfExists(db, "Data_Car", sets, "IsInstalled", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsPurchased", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsDrivable", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "NotAvailableInAutoshow", "0");
            AddColumnSetIfExists(db, "Data_Car", sets, "VisibleOnlyIfOwned", "0");
            if (sets.Count == 0)
                return;

            var mapFilter = new List<string>();
            if (hasSelectedOffers)
                mapFilter.Add("map.OfferId IN (" + selectedOfferSql + ")");
            if (db.ColumnExists("ContentOffersMapping", "ContentType"))
                mapFilter.Add("map.ContentType = 1");
            var mapWhere = mapFilter.Count == 0 ? "1 = 1" : string.Join(" AND ", mapFilter.ToArray());

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_DlcGates_DataCar AS SELECT * FROM Data_Car;");
            ExecuteAutoshowSql(
                db,
                "UPDATE Data_Car SET " + string.Join(", ", sets.Values.ToArray()) + " " +
                "WHERE EXISTS (SELECT 1 FROM ContentOffersMapping map WHERE " + mapWhere + " AND " + BuildContentMappingDataCarMatch(db, "map", "Data_Car") + ");");
        }

