        private void ApplyFreeAutoshowPrices()
        {
            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");

            var touched = new List<string>();
            ApplyFreePriceColumnSet(db, "Data_Car", "_backup_Database_FreeCarPrices_DataCar", null, new[]
            {
                "BaseCost",
                "BasePrice",
                "BuyPrice",
                "AutoshowPrice",
                "AutoShowPrice",
                "Price",
                "Cost",
                "CreditCost",
                "CreditsCost"
            }, touched);

            if (db.TableExists("ContentOffersMapping"))
            {
                var mappingWhere = db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType = 1" : null;
                ApplyFreePriceColumnSet(db, "ContentOffersMapping", "_backup_Database_FreeCarPrices_ContentOffersMapping", mappingWhere, new[]
                {
                    "BaseCost",
                    "BasePrice",
                    "BuyPrice",
                    "AutoshowPrice",
                    "AutoShowPrice",
                    "Price",
                    "Cost",
                    "CreditCost",
                    "CreditsCost"
                }, touched);
            }

            if (db.TableExists("ContentOffers") &&
                db.ColumnExists("ContentOffers", "OfferId") &&
                db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentType"))
            {
                ApplyFreePriceColumnSet(db, "ContentOffers", "_backup_Database_FreeCarPrices_ContentOffers", "OfferId IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE ContentType = 1)", new[]
                {
                    "BaseCost",
                    "BasePrice",
                    "BuyPrice",
                    "AutoshowPrice",
                    "AutoShowPrice",
                    "Price",
                    "Cost",
                    "CreditCost",
                    "CreditsCost"
                }, touched);
            }

            if (touched.Count == 0)
                throw new InvalidOperationException("No supported car price columns were found.");

            if (db.ColumnExists("Data_Car", "BaseCost"))
                LogCount(db, "Cars with non-zero BaseCost", "SELECT count(*) FROM Data_Car WHERE BaseCost IS NOT NULL AND CAST(BaseCost AS REAL) <> 0");
            Log("Free car prices applied to " + touched.Count.ToString(CultureInfo.InvariantCulture) + " price column(s): " + string.Join(", ", touched.ToArray()) + ".");
            try { LoadFreePriceRows(); }
            catch { }
            SetProfileStatus("All prices free");
            ShowInfo("Free car prices applied." + Environment.NewLine + Environment.NewLine +
                "Updated price column(s): " + touched.Count.ToString(CultureInfo.InvariantCulture));
        }

        private int ApplyFreePriceColumnSet(RemoteDatabase db, string tableName, string backupName, string rowFilter, IEnumerable<string> candidateColumns, List<string> touched)
        {
            if (!db.TableExists(tableName))
                return 0;

            var columns = candidateColumns
                .Where(column => db.ColumnExists(tableName, column))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
            if (columns.Count == 0)
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");

            foreach (var column in columns)
            {
                var columnSql = EscapeIdentifierForSql(column);
                var where = "(" + columnSql + " IS NULL OR CAST(" + columnSql + " AS REAL) <> 0)";
                if (!string.IsNullOrWhiteSpace(rowFilter))
                    where = "(" + rowFilter + ") AND " + where;

                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + columnSql + " = 0 WHERE " + where + ";");
                if (touched != null)
                    touched.Add(tableName + "." + column);
            }

            return columns.Count;
        }

