        private void ApplySelectedInstallFlags(RemoteDatabase db, List<int> carIds)
        {
            if (db == null || !db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");

            var idsSql = BuildIntegerInList(carIds);
            var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddColumnSetIfExists(db, "Data_Car", sets, "IsInstalled", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsPurchased", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsDrivable", "1");
            if (sets.Count == 0)
                throw new InvalidOperationException("No supported install flag columns were found.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_SelectedInstallFlags_DataCar AS SELECT * FROM Data_Car;");
            ExecuteAutoshowSql(db, "UPDATE Data_Car SET " + string.Join(", ", sets.Values.ToArray()) + " WHERE Id IN (" + idsSql + ");");

            if (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_SelectedInstallFlags_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                var carContentSubquery = BuildDataCarContentIdSubquery(db, "Id IN (" + idsSql + ")");
                var mappingWhere = (db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType = 1 AND " : string.Empty) +
                    "CAST(ContentId AS INTEGER) IN (" + carContentSubquery + ")";
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE " + mappingWhere + " AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE " + mappingWhere + " AND (Quantity IS NULL OR Quantity < 1);");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE " + mappingWhere + " AND (IsPromo IS NULL OR IsPromo <> 0);");

                if (db.TableExists("ContentOffers") && db.ColumnExists("ContentOffers", "Id") && db.ColumnExists("ContentOffersMapping", "OfferId"))
                {
                    var offerSets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                    AddColumnSetIfExists(db, "ContentOffers", offerSets, "Visible", "1");
                    AddColumnSetIfExists(db, "ContentOffers", offerSets, "IsPurchased", "1");
                    AddColumnSetIfExists(db, "ContentOffers", offerSets, "IsFree", "1");
                    AddColumnSetIfExists(db, "ContentOffers", offerSets, "ShouldUpsell", "0");
                    if (offerSets.Count > 0)
                    {
                        ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_SelectedInstallFlags_ContentOffers AS SELECT * FROM ContentOffers;");
                        ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", offerSets.Values.ToArray()) + " WHERE Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE " + mappingWhere + ");");
                    }
                }
            }

            Log("Selected install/purchased/drivable flags applied to " + carIds.Distinct().Count().ToString(CultureInfo.InvariantCulture) + " car(s).");
        }

