        private void RefreshVehicleTunerCurrentValues()
        {
            if (_vehicleTunerOptionsGrid == null || _vehicleTunerOptionsGrid.IsDisposed)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)RefreshVehicleTunerCurrentValues);
                return;
            }

            int? selectedCarId = null;
            if (_vehicleTunerGarageGrid != null && _vehicleTunerGarageGrid.SelectedRows.Count > 0)
            {
                int carId;
                if (TryGetCarIdFromGridRow(_vehicleTunerGarageGrid.SelectedRows[0], out carId) && carId > 0)
                    selectedCarId = carId;
            }

            var db = _database != null && _database.IsAlive ? _database : null;
            foreach (DataGridViewRow row in _vehicleTunerOptionsGrid.Rows)
            {
                var option = row.Tag as VehicleTunerOption;
                if (option == null)
                    continue;

                row.Cells["Default"].Value = option.DefaultValue;
                row.Cells["Current"].Value = db == null ? "Attach first" : QueryVehicleTunerCurrentValue(db, option, selectedCarId);
            }
        }

        private string QueryVehicleTunerCurrentValue(RemoteDatabase db, VehicleTunerOption option, int? selectedCarId)
        {
            if (db == null || option == null)
                return "-";

            try
            {
                if (string.Equals(option.Key, "drift", StringComparison.OrdinalIgnoreCase))
                    return FormatVehicleTunerCurrentMultiplier(TryQueryAverageMultiplier(db, "Tracks", "_backup_Database_VehicleTuner_Tracks", "DriftScoreScalar", false));

                if (!selectedCarId.HasValue)
                    return "Select car";

                if (string.Equals(option.Key, "traction", StringComparison.OrdinalIgnoreCase))
                {
                    var values = new List<double>();
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "Traction_Road", false, selectedCarId));
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "Traction_OffRoad", false, selectedCarId));
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "Traction_Snow", false, selectedCarId));
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Profile0_Career_Garage", "_backup_Database_VehicleTuner_ProfileGarage", "Traction_Road", false, selectedCarId));
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Profile0_Career_Garage", "_backup_Database_VehicleTuner_ProfileGarage", "Traction_OffRoad", false, selectedCarId));
                    AddVehicleTunerMultiplier(values, TryQueryAverageMultiplier(db, "Profile0_Career_Garage", "_backup_Database_VehicleTuner_ProfileGarage", "Traction_Snow", false, selectedCarId));
                    return values.Count == 0 ? "x1" : "x" + FormatDrivingMultiplier(values.Average());
                }

                if (string.Equals(option.Key, "torque", StringComparison.OrdinalIgnoreCase))
                    return FormatVehicleTunerCurrentMultiplier(TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "GameTorqueScale", false, selectedCarId));

                if (string.Equals(option.Key, "drag", StringComparison.OrdinalIgnoreCase))
                {
                    var value = TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "GameDragScale", false, selectedCarId);
                    if (!value.HasValue)
                        value = TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", "BodyAeroLongitudinalDrag", false, selectedCarId);
                    return FormatVehicleTunerCurrentMultiplier(value);
                }
            }
            catch
            {
                return "Check DB";
            }

            return "-";
        }

        private static void AddVehicleTunerMultiplier(List<double> values, double? value)
        {
            if (!value.HasValue || value.Value <= 0.0 || double.IsNaN(value.Value) || double.IsInfinity(value.Value))
                return;
            values.Add(value.Value);
        }

        private static string FormatVehicleTunerCurrentMultiplier(double? value)
        {
            if (!value.HasValue || value.Value <= 0.0 || double.IsNaN(value.Value) || double.IsInfinity(value.Value))
                return "x1";
            return "x" + FormatDrivingMultiplier(value.Value);
        }

        private List<VehicleTunerInput> CaptureVehicleTunerInputs()
        {
            if (InvokeRequired)
                return (List<VehicleTunerInput>)Invoke(new Func<List<VehicleTunerInput>>(CaptureVehicleTunerInputs));

            if (_vehicleTunerOptionsGrid == null)
                return new List<VehicleTunerInput>();

            _vehicleTunerOptionsGrid.EndEdit();
            var inputs = new List<VehicleTunerInput>();
            foreach (DataGridViewRow row in _vehicleTunerOptionsGrid.Rows)
            {
                var option = row.Tag as VehicleTunerOption;
                if (option == null)
                    continue;

                var raw = Convert.ToString(row.Cells["Value"].Value, CultureInfo.InvariantCulture) ?? option.DefaultValue;
                var enabled = row.Cells["Enabled"].Value is bool && (bool)row.Cells["Enabled"].Value;
                inputs.Add(new VehicleTunerInput(option, raw, enabled));
            }

            return inputs;
        }

        private void ApplyVehicleTunerValues(List<VehicleTunerInput> inputs)
        {
            if (inputs == null || inputs.Count == 0)
                throw new InvalidOperationException("Vehicle Tuner rows were not found.");

            var db = RequireDatabase();
            var needsCar = inputs.Any(input => input.Enabled && !string.Equals(input.Option.Key, "drift", StringComparison.OrdinalIgnoreCase));
            CarEditorRow car = null;
            if (needsCar)
                car = GetSelectedVehicleTunerCar();
            else if (_vehicleTunerGarageGrid != null && _vehicleTunerGarageGrid.SelectedRows.Count > 0)
            {
                try { car = GetSelectedVehicleTunerCar(); }
                catch { car = null; }
            }

            var touched = 0;
            foreach (var input in inputs)
            {
                var key = input.Option.Key;
                if (string.Equals(key, "drift", StringComparison.OrdinalIgnoreCase))
                {
                    touched += input.Enabled
                        ? ApplyVehicleTunerDriftScore(db, ParseVehicleTunerMultiplier(input.RawValue, input.Option.DisplayName))
                        : RestoreVehicleTunerColumnSet(db, "Tracks", "_backup_Database_VehicleTuner_Tracks", new[] { "DriftScoreScalar" }, null);
                }
                else if (string.Equals(key, "traction", StringComparison.OrdinalIgnoreCase))
                {
                    touched += input.Enabled
                        ? ApplyVehicleTunerTraction(db, car.CarId, ParseVehicleTunerMultiplier(input.RawValue, input.Option.DisplayName))
                        : (car == null ? 0 : RestoreVehicleTunerCarTraction(db, car.CarId));
                }
                else if (string.Equals(key, "torque", StringComparison.OrdinalIgnoreCase))
                {
                    touched += input.Enabled
                        ? ApplyVehicleTunerTorque(db, car.CarId, ParseVehicleTunerMultiplier(input.RawValue, input.Option.DisplayName))
                        : (car == null ? 0 : RestoreVehicleTunerColumnSet(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", new[] { "GameTorqueScale" }, car.CarId));
                }
                else if (string.Equals(key, "drag", StringComparison.OrdinalIgnoreCase))
                {
                    touched += input.Enabled
                        ? ApplyVehicleTunerDrag(db, car.CarId, ParseVehicleTunerMultiplier(input.RawValue, input.Option.DisplayName))
                        : (car == null ? 0 : RestoreVehicleTunerColumnSet(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", new[] { "GameDragScale", "BodyAeroLongitudinalDrag" }, car.CarId));
                }
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported Vehicle Tuner columns were found on this database.");

            var target = car == null ? "global drift rows" : FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model);
            Log("Vehicle Tuner finished. Supported column groups touched: " + touched.ToString(CultureInfo.InvariantCulture) + " for " + target + ".");
            RefreshVehicleTunerCurrentValues();
            ShowInfo("Vehicle Tuner applied." + Environment.NewLine + Environment.NewLine + "Switch cars or reload the garage screen so FH6 refreshes the selected vehicle values.");
        }

        private void RestoreVehicleTunerDefaults()
        {
            var db = RequireDatabase();
            var restored = 0;
            restored += RestoreVehicleTunerColumnSet(db, "Tracks", "_backup_Database_VehicleTuner_Tracks", new[] { "DriftScoreScalar" }, null);
            restored += RestoreVehicleTunerColumnSet(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", new[] { "GameTorqueScale", "GameDragScale", "BodyAeroLongitudinalDrag", "Traction_Road", "Traction_OffRoad", "Traction_Snow" }, null);
            restored += RestoreVehicleTunerColumnSet(db, "Profile0_Career_Garage", "_backup_Database_VehicleTuner_ProfileGarage", new[] { "Traction_Road", "Traction_OffRoad", "Traction_Snow" }, null);

            if (restored == 0)
                throw new InvalidOperationException("No Vehicle Tuner backups were found yet.");

            Log("Vehicle Tuner defaults restored. Column groups restored: " + restored.ToString(CultureInfo.InvariantCulture) + ".");
            RefreshVehicleTunerCurrentValues();
            ShowInfo("Vehicle Tuner defaults restored.");
        }

        private void LoadDatabaseTuningGarage()
        {
            Interlocked.Increment(ref _databaseTuningLoadGeneration);
            List<CarEditorRow> rows;
            lock (_databaseTuningDbLock)
            {
                var db = RequireDatabase();
                if (!db.TableExists("Data_Car"))
                    throw new InvalidOperationException("Data_Car table was not found.");
                if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                    throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

                rows = QueryCarEditorRows(db);
            }
            SetDatabaseTuningGarageRows(rows);
            SetProfileStatus("Database Tuning " + rows.Count.ToString(CultureInfo.InvariantCulture));
            Log("Database Tuning loaded " + rows.Count.ToString(CultureInfo.InvariantCulture) + " owned car row(s).");
        }

