        private void UpdateDatabaseTuningSelection()
        {
            if (_databaseTuningSelectionLoading)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateDatabaseTuningSelection);
                return;
            }

            if (_databaseTuningGarageGrid == null || _databaseTuningGarageGrid.SelectedRows.Count == 0)
            {
                Interlocked.Increment(ref _databaseTuningLoadGeneration);
                if (_databaseTuningSelected != null)
                    _databaseTuningSelected.Text = "Selected car: none";
                SetDatabaseTuningRows(new List<DatabaseTuningRow>());
                return;
            }

            try
            {
                var car = GetSelectedDatabaseTuningCar();
                if (_databaseTuningSelected != null)
                    _databaseTuningSelected.Text = "Selected car: " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model);
                LoadDatabaseTuningFields(car);
            }
            catch (Exception ex)
            {
                Log("Database Tuning selection failed: " + ex.Message);
                if (_databaseTuningSummary != null)
                    _databaseTuningSummary.Text = "Fields: selection failed";
            }
        }

        private void LoadDatabaseTuningFields(CarEditorRow car)
        {
            if (car == null || car.CarId <= 0)
            {
                Interlocked.Increment(ref _databaseTuningLoadGeneration);
                SetDatabaseTuningRows(new List<DatabaseTuningRow>());
                return;
            }

            var generation = Interlocked.Increment(ref _databaseTuningLoadGeneration);
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate
                {
                    if (generation == _databaseTuningLoadGeneration && _databaseTuningSummary != null)
                        _databaseTuningSummary.Text = "Fields: loading selected car...";
                }));
            }
            else if (_databaseTuningSummary != null)
            {
                _databaseTuningSummary.Text = "Fields: loading selected car...";
            }

            ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    if (generation != _databaseTuningLoadGeneration)
                        return;

                    List<DatabaseTuningRow> rows;
                    lock (_databaseTuningDbLock)
                    {
                        if (generation != _databaseTuningLoadGeneration)
                            return;
                        var db = RequireDatabase();
                        rows = BuildDatabaseTuningRows(db, car);
                    }
                    if (generation != _databaseTuningLoadGeneration)
                        return;
                    if (IsDisposed || !IsHandleCreated)
                        return;

                    BeginInvoke((Action)(delegate
                    {
                        if (generation != _databaseTuningLoadGeneration)
                            return;
                        SetDatabaseTuningRows(rows);
                        Log("Database Tuning loaded " + rows.Count.ToString(CultureInfo.InvariantCulture) + " editable field(s) for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ".");
                    }));
                }
                catch (Exception ex)
                {
                    if (generation != _databaseTuningLoadGeneration)
                        return;
                    if (IsDisposed || !IsHandleCreated)
                        return;
                    BeginInvoke((Action)(delegate
                    {
                        if (generation != _databaseTuningLoadGeneration)
                            return;
                        SetDatabaseTuningRows(new List<DatabaseTuningRow>());
                        if (_databaseTuningSummary != null)
                            _databaseTuningSummary.Text = "Fields: load failed";
                        Log("Database Tuning field load failed: " + ex.Message);
                    }));
                }
            });
        }

        private void SetDatabaseTuningRows(List<DatabaseTuningRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetDatabaseTuningRows(rows); }));
                return;
            }

            _databaseTuningRows = rows ?? new List<DatabaseTuningRow>();
            ApplyDatabaseTuningFieldFilter();
        }

        private void ApplyDatabaseTuningFieldFilter()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplyDatabaseTuningFieldFilter);
                return;
            }

            SyncDatabaseTuningGridEdits();
            var filter = _databaseTuningFieldSearch == null ? string.Empty : _databaseTuningFieldSearch.Text;
            var rows = (_databaseTuningRows ?? new List<DatabaseTuningRow>())
                .Where(row => row.Matches(filter))
                .Where(row => _databaseTuningActivePreset == null || _databaseTuningActivePreset.Matches(row))
                .OrderBy(row => row.Section, StringComparer.OrdinalIgnoreCase)
                .ThenBy(row => row.DisplayName, StringComparer.OrdinalIgnoreCase)
                .ToList();
            SetDatabaseTuningGridRows(rows);
            UpdateDatabaseTuningFilterLabel();
            if (_databaseTuningSummary != null)
            {
                var presetText = _databaseTuningActivePreset == null ? string.Empty : " | " + _databaseTuningActivePreset.Name;
                _databaseTuningSummary.Text = "Fields: " + rows.Count.ToString(CultureInfo.InvariantCulture) + "/" +
                    (_databaseTuningRows == null ? 0 : _databaseTuningRows.Count).ToString(CultureInfo.InvariantCulture) + presetText;
            }
        }

        private void ShowDatabaseTuningSortOptions()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ShowDatabaseTuningSortOptions);
                return;
            }

            using (var dialog = new Form())
            {
                dialog.Text = "Sort Options";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(720, 520);

                var title = new Label();
                title.Text = "Selected Car Editor Filters";
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                title.Location = new Point(18, 14);
                title.Size = new Size(684, 28);
                dialog.Controls.Add(title);

                var sub = new Label();
                sub.Text = "Pick a workflow to hide unrelated rows. This only filters the table; it does not change values.";
                sub.Font = new Font("Segoe UI", 8.5F);
                sub.ForeColor = TextMuted;
                sub.BackColor = AppBackground;
                sub.Location = new Point(18, 42);
                sub.Size = new Size(684, 24);
                dialog.Controls.Add(sub);

                var list = new ListBox();
                list.Location = new Point(18, 78);
                list.Size = new Size(250, 368);
                list.BackColor = Surface;
                list.ForeColor = TextPrimary;
                list.BorderStyle = BorderStyle.FixedSingle;
                list.Font = new Font("Segoe UI", 9F);
                foreach (var preset in DatabaseTuningFilterPresets)
                    list.Items.Add(preset);
                if (_databaseTuningActivePreset != null)
                {
                    for (var i = 0; i < list.Items.Count; i++)
                    {
                        var preset = list.Items[i] as DatabaseTuningFilterPreset;
                        if (preset != null && string.Equals(preset.Name, _databaseTuningActivePreset.Name, StringComparison.OrdinalIgnoreCase))
                        {
                            list.SelectedIndex = i;
                            break;
                        }
                    }
                }
                if (list.SelectedIndex < 0 && list.Items.Count > 0)
                    list.SelectedIndex = 0;
                dialog.Controls.Add(list);

                var description = new Label();
                description.Location = new Point(288, 78);
                description.Size = new Size(414, 88);
                description.BackColor = AppBackground;
                description.ForeColor = TextMuted;
                description.Font = new Font("Segoe UI", 9.5F);
                dialog.Controls.Add(description);

                var terms = new Label();
                terms.Location = new Point(288, 178);
                terms.Size = new Size(414, 268);
                terms.BackColor = Surface;
                terms.ForeColor = TextPrimary;
                terms.Font = new Font("Segoe UI", 9F);
                terms.Padding = new Padding(12);
                dialog.Controls.Add(terms);

                Action refresh = delegate
                {
                    var preset = list.SelectedItem as DatabaseTuningFilterPreset;
                    if (preset == null)
                    {
                        description.Text = string.Empty;
                        terms.Text = string.Empty;
                        return;
                    }

                    var count = (_databaseTuningRows ?? new List<DatabaseTuningRow>()).Count(row => preset.Matches(row));
                    description.Text = preset.Description + Environment.NewLine + Environment.NewLine +
                        "Matching loaded rows: " + count.ToString(CultureInfo.InvariantCulture);
                    terms.Text = "Looks for:" + Environment.NewLine + string.Join(", ", preset.Terms);
                };
                list.SelectedIndexChanged += delegate { refresh(); };
                list.DoubleClick += delegate
                {
                    var preset = list.SelectedItem as DatabaseTuningFilterPreset;
                    if (preset == null)
                        return;
                    SetDatabaseTuningFilterPreset(preset);
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };

                var remove = MakeButton("Remove Filter", 370, 468, 120, 32);
                remove.Click += delegate
                {
                    SetDatabaseTuningFilterPreset(null);
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(remove);

                var cancel = MakeButton("Cancel", 502, 468, 86, 32);
                cancel.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(cancel);

                var apply = MakeButton("Apply Filter", 600, 468, 102, 32);
                MakeAccentButton(apply, AccentBlue);
                apply.Click += delegate
                {
                    var preset = list.SelectedItem as DatabaseTuningFilterPreset;
                    if (preset == null)
                        return;
                    SetDatabaseTuningFilterPreset(preset);
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(apply);

                refresh();
                PrepareDialogForLanguage(dialog);
                dialog.ShowDialog(this);
            }
        }

        private void SetDatabaseTuningFilterPreset(DatabaseTuningFilterPreset preset)
        {
            _databaseTuningActivePreset = preset;
            ApplyDatabaseTuningFieldFilter();
        }

        private void ClearDatabaseTuningFilterPreset()
        {
            SetDatabaseTuningFilterPreset(null);
        }

        private void UpdateDatabaseTuningFilterLabel()
        {
            if (_databaseTuningFilterLabel == null)
                return;

            if (_databaseTuningActivePreset == null)
            {
                _databaseTuningFilterLabel.Text = TranslateDynamicUi("Filter: All options");
                _databaseTuningFilterLabel.ForeColor = TextMuted;
            }
            else
            {
                _databaseTuningFilterLabel.Text = TranslateDynamicUi("Filter:") + " " + TranslateDynamicUi(_databaseTuningActivePreset.Name);
                _databaseTuningFilterLabel.ForeColor = AccentBlue;
            }
        }

        private void SetDatabaseTuningGridRows(List<DatabaseTuningRow> rows)
        {
            if (_databaseTuningGrid == null)
                return;

            _databaseTuningGrid.Rows.Clear();
            foreach (var item in rows ?? new List<DatabaseTuningRow>())
            {
                var rowIndex = _databaseTuningGrid.Rows.Add(
                    item.Enabled,
                    TranslateDynamicUi(item.Section),
                    TranslateDynamicUi(item.DisplayName),
                    item.CurrentDisplay,
                    item.NewValue,
                    item.DefaultDisplay,
                    item.TableName,
                    TranslateDynamicUi(item.Description));
                var gridRow = _databaseTuningGrid.Rows[rowIndex];
                gridRow.Tag = item;
                gridRow.Cells["NewValue"].ToolTipText = string.Equals(item.ValueType, "part", StringComparison.OrdinalIgnoreCase)
                    ? TranslateDynamicUi("Click to open the safe part picker.")
                    : TranslateDynamicUi("Click to use an existing FH6 value or enter any positive or negative finite number.");
                gridRow.Cells["Current"].ToolTipText = item.CurrentRaw;
                gridRow.Cells["Default"].ToolTipText = item.DefaultRaw;
            }
        }

        private void SyncDatabaseTuningGridEdits()
        {
            if (_databaseTuningGrid == null || _databaseTuningGrid.IsDisposed)
                return;
            try { _databaseTuningGrid.EndEdit(); }
            catch { }

            foreach (DataGridViewRow gridRow in _databaseTuningGrid.Rows)
            {
                var item = gridRow.Tag as DatabaseTuningRow;
                if (item == null)
                    continue;
                item.Enabled = gridRow.Cells["Apply"].Value is bool && (bool)gridRow.Cells["Apply"].Value;
                item.NewValue = Convert.ToString(gridRow.Cells["NewValue"].Value, CultureInfo.InvariantCulture) ?? string.Empty;
            }
        }

        private List<DatabaseTuningRow> BuildDatabaseTuningRows(RemoteDatabase db, CarEditorRow car)
        {
            var rows = new List<DatabaseTuningRow>();
            var partMap = QueryDatabaseTuningPartMap(db);
            var partLabelCache = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddDatabaseTuningRowsForTable(db, car, "Data_Car", "_backup_DatabaseTuning_DataCar", partMap, partLabelCache, rows);
            AddDatabaseTuningRowsForTable(db, car, "Profile0_Career_Garage", "_backup_DatabaseTuning_ProfileGarage", partMap, partLabelCache, rows);
            AddDatabaseTuningRowsForTable(db, car, "List_AeroStaticSystem", GetDatabaseTuningBackupName("List_AeroStaticSystem"), partMap, partLabelCache, rows);
            AddDatabaseTuningRowsForTable(db, car, "List_DragWallSettingsOverride", GetDatabaseTuningBackupName("List_DragWallSettingsOverride"), partMap, partLabelCache, rows);
            AddDatabaseTuningInstalledPartAttributeRows(db, car, partMap, rows);
            AddDatabaseTuningReferencedPhysicsRows(db, car, partMap, rows);
            return rows;
        }

        private void AddDatabaseTuningRowsForTable(RemoteDatabase db, CarEditorRow car, string tableName, string backupName, Dictionary<string, DatabaseTuningPartMap> partMap, Dictionary<string, string> partLabelCache, List<DatabaseTuningRow> rows)
        {
            if (!db.TableExists(tableName))
                return;

            var columns = QueryDatabaseTuningColumns(db, tableName);
            var currentValues = QueryDatabaseTuningRowValueMap(db, tableName, car.CarId);
            if (currentValues.Count == 0)
                return;
            var backupValues = db.TableExists(backupName) ? QueryDatabaseTuningRowValueMap(db, backupName, car.CarId) : new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
            foreach (var column in columns)
            {
                if (!IsDatabaseTuningSupportedColumn(tableName, column.Name, column.Type, partMap))
                    continue;

                object current;
                currentValues.TryGetValue(column.Name, out current);
                object original;
                if (!backupValues.TryGetValue(column.Name, out original))
                    original = current;
                var currentRaw = FormatDatabaseTuningRawValue(current);
                var defaultRaw = FormatDatabaseTuningRawValue(original);
                DatabaseTuningPartMap map;
                partMap.TryGetValue(column.Name, out map);
                var valueType = map != null ? "part" : (IsIntegerColumnType(column.Type) ? "int" : "real");
                var partTable = map == null ? string.Empty : map.TableName;
                rows.Add(new DatabaseTuningRow(
                    tableName,
                    column.Name,
                    GetDatabaseTuningSection(tableName, column.Name, map),
                    GetDatabaseTuningDisplayName(column.Name, map),
                    GetDatabaseTuningDescription(tableName, column.Name, map),
                    FormatDatabaseTuningDisplayValue(db, car.CarId, current, map, partLabelCache),
                    currentRaw,
                    FormatDatabaseTuningDisplayValue(db, car.CarId, original, map, partLabelCache),
                    defaultRaw,
                    valueType,
                    partTable));
            }
        }

        private void AddDatabaseTuningInstalledPartAttributeRows(RemoteDatabase db, CarEditorRow car, Dictionary<string, DatabaseTuningPartMap> partMap, List<DatabaseTuningRow> rows)
        {
            if (db == null || car == null || partMap == null || rows == null || !db.TableExists("Profile0_Career_Garage"))
                return;

            var garageValues = QueryDatabaseTuningRowValueMap(db, "Profile0_Career_Garage", car.CarId);
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var map in partMap.Values.OrderBy(item => item.ColumnName, StringComparer.OrdinalIgnoreCase))
            {
                if (map == null || string.IsNullOrWhiteSpace(map.TableName) || !db.TableExists(map.TableName))
                    continue;

                object installedRaw;
                if (!garageValues.TryGetValue(map.ColumnName, out installedRaw))
                    continue;

                var partId = ToLong(installedRaw);
                if (partId <= 0)
                    continue;

                var idColumn = ResolveDatabaseTuningPartIdColumn(db, map.TableName);
                if (string.IsNullOrWhiteSpace(idColumn))
                    continue;

                var currentValues = QueryDatabaseTuningRecordValueMap(db, map.TableName, idColumn, partId);
                if (currentValues.Count == 0)
                    continue;

                var backupName = GetDatabaseTuningBackupName(map.TableName);
                var backupValues = db.TableExists(backupName)
                    ? QueryDatabaseTuningRecordValueMap(db, backupName, idColumn, partId)
                    : new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
                foreach (var column in QueryDatabaseTuningColumns(db, map.TableName))
                {
                    if (!IsDatabaseTuningInstalledPartValueColumn(map.TableName, column.Name))
                        continue;

                    var unique = map.TableName + "." + partId.ToString(CultureInfo.InvariantCulture) + "." + column.Name;
                    if (!seen.Add(unique))
                        continue;

                    object current;
                    if (!currentValues.TryGetValue(column.Name, out current))
                        continue;

                    object original;
                    if (!backupValues.TryGetValue(column.Name, out original))
                        original = current;

                    var currentRaw = FormatDatabaseTuningRawValue(current);
                    var defaultRaw = FormatDatabaseTuningRawValue(original);
                    var valueType = IsIntegerColumnType(column.Type) ? "int" : "real";
                    var sourceName = MakeReadableIdentifier(map.ColumnName);
                    rows.Add(new DatabaseTuningRow(
                        map.TableName,
                        column.Name,
                        "Installed Part Values - " + sourceName,
                        sourceName + " - " + GetDatabaseTuningDisplayName(column.Name, null),
                        "Edits the selected car's currently installed " + sourceName + " part row.",
                        currentRaw.Length == 0 ? "-" : currentRaw,
                        currentRaw,
                        defaultRaw.Length == 0 ? "-" : defaultRaw,
                        defaultRaw,
                        valueType,
                        string.Empty,
                        idColumn,
                        partId,
                        sourceName + " part " + partId.ToString(CultureInfo.InvariantCulture)));
                }
            }
        }

        private void AddDatabaseTuningReferencedPhysicsRows(RemoteDatabase db, CarEditorRow car, Dictionary<string, DatabaseTuningPartMap> partMap, List<DatabaseTuningRow> rows)
        {
            if (db == null || car == null || partMap == null || rows == null || !db.TableExists("Profile0_Career_Garage"))
                return;

            var seen = new HashSet<string>((rows ?? new List<DatabaseTuningRow>()).Select(row => row.Key), StringComparer.OrdinalIgnoreCase);
            AddDatabaseTuningDrivingModeRows(db, car.CarId, rows, seen);

            var carValues = QueryDatabaseTuningRowValueMap(db, "Data_Car", car.CarId);
            AddDatabaseTuningReferencedRecordFromValue(db, carValues, "BrakeProfile", "List_BrakeProfile", "BrakesProfileID", "Referenced Physics - Brakes", "Car Brake Profile", rows, seen);
            AddDatabaseTuningReferencedRecordFromValue(db, carValues, "AutoSteerOverrideID", "AutoSteerOverrides", "Id", "Referenced Physics - Steering", "Auto-Steer Override", rows, seen);

            var garageValues = QueryDatabaseTuningRowValueMap(db, "Profile0_Career_Garage", car.CarId);
            foreach (var map in partMap.Values.OrderBy(item => item.ColumnName, StringComparer.OrdinalIgnoreCase))
            {
                if (map == null || string.IsNullOrWhiteSpace(map.TableName) || !db.TableExists(map.TableName))
                    continue;

                object installedRaw;
                if (!garageValues.TryGetValue(map.ColumnName, out installedRaw))
                    continue;

                var partId = ToLong(installedRaw);
                if (partId <= 0)
                    continue;

                var idColumn = ResolveDatabaseTuningPartIdColumn(db, map.TableName);
                if (string.IsNullOrWhiteSpace(idColumn))
                    continue;

                var partValues = QueryDatabaseTuningRecordValueMap(db, map.TableName, idColumn, partId);
                if (partValues.Count == 0)
                    continue;

                var sourceName = MakeReadableIdentifier(map.ColumnName);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "AeroPhysicsID", "List_AeroPhysics", "AeroPhysicsID", "Referenced Physics - Aero", sourceName + " Aero", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "AntiSwayPhysicsID", "List_AntiSwayPhysics", "AntiSwayPhysicsID", "Referenced Physics - Anti-Roll Bars", sourceName + " Anti-Roll Physics", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "BrakesProfileID", "List_BrakeProfile", "BrakesProfileID", "Referenced Physics - Brakes", sourceName + " Brake Profile", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "TCProfileID", "List_TractionControl", "TC_ProfileID", "Referenced Physics - Traction Control", sourceName + " Traction Control", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "FrontSpringDamperPhysicsID", "List_SpringDamperPhysics", "SpringDamperPhysicsID", "Referenced Physics - Springs", sourceName + " Front Spring Physics", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "RearSpringDamperPhysicsID", "List_SpringDamperPhysics", "SpringDamperPhysicsID", "Referenced Physics - Springs", sourceName + " Rear Spring Physics", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "SteeringSettingsProfileID", "List_SteeringSettings", "SteeringSettingsID", "Referenced Physics - Steering", sourceName + " Steering Settings", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "RearSteeringSettingsID", "List_RearSteeringSettings", "Id", "Referenced Physics - Steering", sourceName + " Rear Steering Settings", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "FrontThirdSpringID", "List_ThirdSpringElement", "ThirdSpringID", "Referenced Physics - Springs", sourceName + " Front Third Spring", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "RearThirdSpringID", "List_ThirdSpringElement", "ThirdSpringID", "Referenced Physics - Springs", sourceName + " Rear Third Spring", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "PreloadAndDroopDamperID", "List_PreloadAndDroopDamper", "PreloadAndDroopDamperID", "Referenced Physics - Springs", sourceName + " Preload & Droop", rows, seen);

                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "TorqueCurveFullThrottleID", "List_TorqueCurve", "TorqueCurveID", "Referenced Physics - Torque Curve", sourceName + " Torque Curve", rows, seen);
                var engineValues = AddDatabaseTuningReferencedRecordFromValue(db, partValues, "EngineID", "Data_Engine", "EngineID", "Referenced Physics - Engine", sourceName + " Engine Data", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, engineValues, "TorqueCurveFullThrottleID", "List_TorqueCurve", "TorqueCurveID", "Referenced Physics - Torque Curve", sourceName + " Engine Torque Curve", rows, seen);
                var motorValues = AddDatabaseTuningReferencedRecordFromValue(db, partValues, "MotorID", "Data_Motor", "MotorID", "Referenced Physics - Motor", sourceName + " Motor Data", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, motorValues, "TorqueCurveFullThrottleID", "List_TorqueCurve", "TorqueCurveID", "Referenced Physics - Torque Curve", sourceName + " Motor Torque Curve", rows, seen);

                var tireValues = AddDatabaseTuningReferencedRecordFromValue(db, partValues, "TireCompoundID", "List_TireCompound", "TireCompoundID", "Referenced Physics - Tire Grip", sourceName + " Tire Compound Physics", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, partValues, "TireCompoundID", "List_TyreCurveDB", "TireCompoundID", "Referenced Physics - Tire Curves", sourceName + " Tire Curve DB", rows, seen);
                AddDatabaseTuningTireCompoundReferencedRows(db, tireValues, sourceName, rows, seen);

                if (string.Equals(map.TableName, "List_UpgradeTireCompound", StringComparison.OrdinalIgnoreCase))
                    AddDatabaseTuningReferencedRecordRows(db, "List_UpgradeTireCompoundFictionModOverride", "PartId", partId, "Referenced Physics - Tire Grip", sourceName + " Friction Override", rows, seen);
            }
        }

        private void AddDatabaseTuningTireCompoundReferencedRows(RemoteDatabase db, Dictionary<string, object> tireValues, string sourceName, List<DatabaseTuningRow> rows, HashSet<string> seen)
        {
            if (db == null || tireValues == null || tireValues.Count == 0)
                return;

            var multiCurves = new[]
            {
                new[] { "FrictionMultiCurveLateralID", "Lateral Road" },
                new[] { "FrictionMultiCurveLateralID_Offroad", "Lateral Offroad" },
                new[] { "FrictionMultiCurveLateralID_Snow", "Lateral Snow" },
                new[] { "FrictionMultiCurveLongitudinalAccelID", "Acceleration Road" },
                new[] { "FrictionMultiCurveLongitudinalAccelID_Offroad", "Acceleration Offroad" },
                new[] { "FrictionMultiCurveLongitudinalAccelID_Snow", "Acceleration Snow" },
                new[] { "FrictionMultiCurveLongitudinalBrakeID", "Braking Road" },
                new[] { "FrictionMultiCurveLongitudinalBrakeID_Offroad", "Braking Offroad" },
                new[] { "FrictionMultiCurveLongitudinalBrakeID_Snow", "Braking Snow" }
            };
            foreach (var item in multiCurves)
            {
                var label = sourceName + " " + item[1] + " Multi Curve";
                var multiValues = AddDatabaseTuningReferencedRecordFromValue(db, tireValues, item[0], "List_TireFrictionMultiCurve", "FrictionMultiCurveID", "Referenced Physics - Tire Curves", label, rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, multiValues, "TireFrictionCurveID0", "List_TireFrictionCurve", "FrictionCurveID", "Referenced Physics - Tire Curves", label + " Low Load", rows, seen);
                AddDatabaseTuningReferencedRecordFromValue(db, multiValues, "TireFrictionCurveID1", "List_TireFrictionCurve", "FrictionCurveID", "Referenced Physics - Tire Curves", label + " High Load", rows, seen);
            }

            var affectCurves = new[]
            {
                new[] { "AffectCurveTempAffectFrictionID", "Temperature Friction" },
                new[] { "AffectCurveTempAffectWearID", "Temperature Wear" },
                new[] { "AffectCurvePressureAffectFrictionID", "Pressure Friction" },
                new[] { "AffectCurvePressureAffectFrictionID_Offroad", "Pressure Friction Offroad" },
                new[] { "AffectCurvePressureAffectFrictionID_Snow", "Pressure Friction Snow" },
                new[] { "AffectCurvePressureAffectWearID", "Pressure Wear" },
                new[] { "AffectCurveStartPressureAffectPeakSASRID", "Start Pressure Peak" },
                new[] { "AffectCurveCamberAffectLatFrictionID", "Camber Lateral Friction" },
                new[] { "AffectCurveCamberAffectLongFrictionID", "Camber Longitudinal Friction" },
                new[] { "AffectCurveWearAffectFrictionID", "Wear Friction" },
                new[] { "AffectCurveSpeedAffectFrictionID", "Speed Friction" },
                new[] { "AffectCurveNormSlipAngleAffectPneumaticTrailAtLightestLoadID", "Slip Trail Light Load" },
                new[] { "AffectCurveNormSlipAngleAffectPneumaticTrailAtHeaviestLoadID", "Slip Trail Heavy Load" }
            };
            foreach (var item in affectCurves)
                AddDatabaseTuningReferencedRecordFromValue(db, tireValues, item[0], "List_TireAffectCurve", "AffectCurveID", "Referenced Physics - Tire Affect Curves", sourceName + " " + item[1], rows, seen);
        }

        private Dictionary<string, object> AddDatabaseTuningReferencedRecordFromValue(RemoteDatabase db, Dictionary<string, object> sourceValues, string sourceColumn, string targetTable, string targetKeyColumn, string section, string sourceName, List<DatabaseTuningRow> rows, HashSet<string> seen)
        {
            var empty = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
            object raw;
            if (sourceValues == null || !sourceValues.TryGetValue(sourceColumn, out raw))
                return empty;

            var keyValue = ToLong(raw);
            if (keyValue <= 0)
                return empty;

            return AddDatabaseTuningReferencedRecordRows(db, targetTable, targetKeyColumn, keyValue, section, sourceName, rows, seen);
        }

        private Dictionary<string, object> AddDatabaseTuningReferencedRecordRows(RemoteDatabase db, string tableName, string keyColumn, long keyValue, string section, string sourceName, List<DatabaseTuningRow> rows, HashSet<string> seen)
        {
            var empty = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
            if (db == null || string.IsNullOrWhiteSpace(tableName) || string.IsNullOrWhiteSpace(keyColumn) ||
                !db.TableExists(tableName) || !db.ColumnExists(tableName, keyColumn))
            {
                return empty;
            }

            var currentValues = QueryDatabaseTuningRecordValueMap(db, tableName, keyColumn, keyValue);
            if (currentValues.Count == 0)
                return empty;

            var backupName = GetDatabaseTuningBackupName(tableName);
            var backupValues = db.TableExists(backupName)
                ? QueryDatabaseTuningRecordValueMap(db, backupName, keyColumn, keyValue)
                : new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);

            foreach (var column in QueryDatabaseTuningColumns(db, tableName))
            {
                if (!IsDatabaseTuningReferencedPhysicsValueColumn(tableName, column.Name))
                    continue;

                object current;
                if (!currentValues.TryGetValue(column.Name, out current))
                    continue;

                var unique = tableName + "." + keyValue.ToString(CultureInfo.InvariantCulture) + "." + column.Name;
                if (seen != null && !seen.Add(unique))
                    continue;

                object original;
                if (!backupValues.TryGetValue(column.Name, out original))
                    original = current;

                var currentRaw = FormatDatabaseTuningRawValue(current);
                var defaultRaw = FormatDatabaseTuningRawValue(original);
                rows.Add(new DatabaseTuningRow(
                    tableName,
                    column.Name,
                    section,
                    sourceName + " - " + GetDatabaseTuningDisplayName(column.Name, null),
                    "Edits a physics row referenced by the selected car's installed setup.",
                    currentRaw.Length == 0 ? "-" : currentRaw,
                    currentRaw,
                    defaultRaw.Length == 0 ? "-" : defaultRaw,
                    defaultRaw,
                    IsIntegerColumnType(column.Type) ? "int" : "real",
                    string.Empty,
                        keyColumn,
                        keyValue,
                        sourceName + " " + keyValue.ToString(CultureInfo.InvariantCulture)));
            }

            return currentValues;
        }

        private void AddDatabaseTuningDrivingModeRows(RemoteDatabase db, int carId, List<DatabaseTuningRow> rows, HashSet<string> seen)
        {
            const string tableName = "List_DrivingMode";
            if (db == null || !db.TableExists(tableName) || !db.ColumnExists(tableName, "Ordinal"))
                return;

            var result = db.Query("SELECT rowid, * FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE [Ordinal] = " + carId.ToString(CultureInfo.InvariantCulture) + ";");
            if (result.Rows.Count == 0)
                return;

            var rowidIndex = FindColumnIndex(result.Columns, "rowid");
            if (rowidIndex < 0)
                return;

            foreach (var resultRow in result.Rows)
            {
                if (resultRow.Count <= rowidIndex)
                    continue;

                var rowid = ToLong(resultRow[rowidIndex]);
                if (rowid <= 0)
                    continue;

                var currentValues = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
                for (var i = 0; i < result.Columns.Count && i < resultRow.Count; i++)
                    currentValues[result.Columns[i]] = resultRow[i];

                var backupName = GetDatabaseTuningBackupName(tableName);
                var backupValues = db.TableExists(backupName)
                    ? QueryDatabaseTuningRecordValueMap(db, backupName, "_rowid_", rowid)
                    : new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
                var mode = currentValues.ContainsKey("DrivingModeID") ? FormatDatabaseTuningRawValue(currentValues["DrivingModeID"]) : rowid.ToString(CultureInfo.InvariantCulture);
                var sourceName = "Driving Mode " + mode;

                foreach (var column in QueryDatabaseTuningColumns(db, tableName))
                {
                    if (!IsDatabaseTuningReferencedPhysicsValueColumn(tableName, column.Name))
                        continue;

                    object current;
                    if (!currentValues.TryGetValue(column.Name, out current))
                        continue;

                    var unique = tableName + "." + rowid.ToString(CultureInfo.InvariantCulture) + "." + column.Name;
                    if (seen != null && !seen.Add(unique))
                        continue;

                    object original;
                    if (!backupValues.TryGetValue(column.Name, out original))
                        original = current;

                    var currentRaw = FormatDatabaseTuningRawValue(current);
                    var defaultRaw = FormatDatabaseTuningRawValue(original);
                    rows.Add(new DatabaseTuningRow(
                        tableName,
                        column.Name,
                        "Referenced Physics - Driving Mode",
                        sourceName + " - " + GetDatabaseTuningDisplayName(column.Name, null),
                        "Edits a car-specific driving mode physics row for the selected car.",
                        currentRaw.Length == 0 ? "-" : currentRaw,
                        currentRaw,
                        defaultRaw.Length == 0 ? "-" : defaultRaw,
                        defaultRaw,
                        IsIntegerColumnType(column.Type) ? "int" : "real",
                        string.Empty,
                        "rowid",
                        rowid,
                        sourceName));
                }
            }
        }

        private List<DatabaseTuningColumnInfo> QueryDatabaseTuningColumns(RemoteDatabase db, string tableName)
        {
            var result = db.Query("PRAGMA table_info(" + EscapeIdentifierForSql(tableName) + ")");
            var columns = new List<DatabaseTuningColumnInfo>();
            foreach (var row in result.Rows)
            {
                if (row.Count < 3)
                    continue;
                columns.Add(new DatabaseTuningColumnInfo(ToDisplayString(row[1]), ToDisplayString(row[2])));
            }
            return columns;
        }

        private Dictionary<string, object> QueryDatabaseTuningRecordValueMap(RemoteDatabase db, string tableName, string keyColumn, long keyValue)
        {
            var values = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
            if (db == null || string.IsNullOrWhiteSpace(tableName) || string.IsNullOrWhiteSpace(keyColumn) ||
                !db.TableExists(tableName) || !db.ColumnExists(tableName, keyColumn))
            {
                return values;
            }

            var result = db.Query("SELECT * FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(keyColumn) + " = " + keyValue.ToString(CultureInfo.InvariantCulture) +
                " LIMIT 1;");
            if (result.Rows.Count == 0)
                return values;

            var row = result.Rows[0];
            for (var i = 0; i < result.Columns.Count && i < row.Count; i++)
                values[result.Columns[i]] = row[i];
            return values;
        }

        private Dictionary<string, DatabaseTuningPartMap> QueryDatabaseTuningPartMap(RemoteDatabase db)
        {
            var map = new Dictionary<string, DatabaseTuningPartMap>(StringComparer.OrdinalIgnoreCase);
            if (!db.TableExists("Data_UpgradePart") ||
                !db.ColumnExists("Data_UpgradePart", "PartName") ||
                !db.ColumnExists("Data_UpgradePart", "TableName"))
                return map;

            var hasCategory = db.ColumnExists("Data_UpgradePart", "CategoryName");
            var result = db.Query("SELECT PartName, TableName" + (hasCategory ? ", CategoryName" : ", ''") + " FROM Data_UpgradePart WHERE PartName IS NOT NULL AND PartName <> '';");
            foreach (var row in result.Rows)
            {
                if (row.Count < 2)
                    continue;
                var column = ToDisplayString(row[0]).Trim();
                var table = ToDisplayString(row[1]).Trim();
                if (column.Length == 0 || table.Length == 0 || !db.TableExists(table))
                    continue;
                if (!map.ContainsKey(column))
                    map[column] = new DatabaseTuningPartMap(column, table, row.Count > 2 ? ToDisplayString(row[2]) : string.Empty);
            }
            return map;
        }

        private static bool IsDatabaseTuningSupportedColumn(string tableName, string columnName, string typeName, Dictionary<string, DatabaseTuningPartMap> partMap)
        {
            if (string.IsNullOrWhiteSpace(columnName))
                return false;
            if (IsDatabaseTuningBlockedColumn(tableName, columnName))
                return false;
            if (partMap != null && partMap.ContainsKey(columnName))
                return true;
            if (!IsNumericColumnType(typeName))
                return false;
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
            return IsDatabaseTuningSafeValueColumn(tableName, columnName);
        }

        private static bool IsDatabaseTuningSafeValueColumn(string tableName, string columnName)
        {
            if (string.Equals(tableName, "List_AeroStaticSystem", StringComparison.OrdinalIgnoreCase))
            {
                switch (columnName ?? string.Empty)
                {
                    case "StaticDragReduction":
