        private static bool IsDatabaseTuningInstalledPartValueColumn(string tableName, string columnName)
        {
            if (string.IsNullOrWhiteSpace(tableName) || string.IsNullOrWhiteSpace(columnName))
                return false;
            if (!tableName.StartsWith("List_Upgrade", StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(tableName, "List_Wheels", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (string.Equals(columnName, "RequiresClutchWhenShifting", StringComparison.OrdinalIgnoreCase))
                return true;

            if (ContainsAny(columnName,
                "MassDiff", "WeightDistDiff", "DragScale", "WindInstabilityScale",
                "TorqueScale", "PowerMaxScale", "PowerMinScale", "TorqueDropOffRPM", "TorqueDropOffScale",
                "RedlineRPM", "RedlineWearSpeed", "TorqueCurveMaxRPM", "MomentInertia", "OffThrottleMomentInertia",
                "ClutchFriction", "ClutchInTime", "ClutchOutTime",
                "GearShiftTime", "FinalDriveRatio", "GearRatio", "CVTShiftTime",
                "FrontLimitedSlip", "RearLimitedSlip", "CenterLimitedSlip", "RearToqueSplit",
                "OneOverSpringConstant", "MultipleOfEngineTorqueForSpring", "Flex",
                "GameFrictionScaleBraking", "BrakeTorqueSlider", "BrakeBiasSlider", "BiasHandbrake",
                "ReleasePointABS", "BrakeTorqueClamp", "BrakeSize", "BrakeRotorThicknessMM",
                "BrakeDrumDepthMM", "BrakeNonSpinningMass", "CaliperPistons",
                "FrontTirePressure", "RearTirePressure", "TrackSpacerOffset",
                "FrontWheelDiameter", "RearWheelDiameter", "FrontTireWidth", "RearTireWidth",
                "FrontTireAspectRatioOffset", "RearTireAspectRatioOffset",
                "CMHeight", "CMBackFront", "CMLeftRight", "BlockDim", "YawOverride",
                "SteerMaxAngle", "SteerMaxAngleFiltered", "BrakeDrawOffset"))
            {
                return true;
            }

            return false;
        }

