        private static bool IsDatabaseTuningTyreCurveDbColumn(string columnName)
        {
            if (string.IsNullOrWhiteSpace(columnName))
                return false;
            if (!columnName.StartsWith("Asph_", StringComparison.OrdinalIgnoreCase) &&
                !columnName.StartsWith("Off_", StringComparison.OrdinalIgnoreCase) &&
                !columnName.StartsWith("Snow_", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            return ContainsAny(columnName, "SlipPeak", "CurveShape", "End", "Pre", "Flat");
        }

