        private static bool IsDatabaseTuningBlockedColumn(string tableName, string columnName)
        {
            var blocked = new[]
            {
                "Id", "CarId", "Guid", "SharedID", "VersionedTuneXUID", "VersionedTuneId", "VersionedLiveryId",
                "VersionedLiveryXUID", "LiveryFileName", "TuneFileName", "Thumbnail", "OriginalOwner",
                "DistanceDriven", "TimeDriven", "TotalWinnings", "TotalRepairs", "NumVictories", "NumPodiums",
                "NumRaces", "NumOwners", "NumTimesSold", "TimeDrivenInRoadTrips", "CurOwnerNumRaces",
                "CurOwnerWinnings", "NumSkillPointsEarned", "HighestSkillScore"
            };
            if (blocked.Any(item => string.Equals(item, columnName, StringComparison.OrdinalIgnoreCase)))
                return true;
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) &&
                ContainsAny(columnName, "MakeID", "FamilyModelID", "FamilyBodyID", "MaterialTypeID", "AIPlayerID", "ContentId", "RegionID", "CountryID", "ModelId"))
                return true;
            return false;
        }

        private static bool IsNumericColumnType(string typeName)
        {
            if (string.IsNullOrWhiteSpace(typeName))
                return true;
            return ContainsAny(typeName, "INT", "REAL", "NUM", "FLOAT", "DOUBLE", "DECIMAL", "BIGINT");
        }

        private static bool IsIntegerColumnType(string typeName)
        {
            return !string.IsNullOrWhiteSpace(typeName) && ContainsAny(typeName, "INT", "BIGINT");
        }

        private static bool ContainsAny(string value, params string[] needles)
        {
            value = value ?? string.Empty;
            foreach (var needle in needles ?? new string[0])
            {
                if (value.IndexOf(needle, StringComparison.OrdinalIgnoreCase) >= 0)
                    return true;
            }
            return false;
        }

        private object QueryDatabaseTuningCell(RemoteDatabase db, string tableName, string columnName, int carId, bool backupTable)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, columnName))
                return null;

            var tableSql = EscapeIdentifierForSql(tableName);
            var columnSql = EscapeIdentifierForSql(columnName);
            string where;
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "_backup_DatabaseTuning_DataCar", StringComparison.OrdinalIgnoreCase))
            {
                where = db.ColumnExists(tableName, "Id") ? " WHERE [Id] = " + carId.ToString(CultureInfo.InvariantCulture) : string.Empty;
            }
            else
            {
                where = db.ColumnExists(tableName, "CarId") ? " WHERE [CarId] = " + carId.ToString(CultureInfo.InvariantCulture) : string.Empty;
            }

            var result = db.Query("SELECT " + columnSql + " FROM " + tableSql + where + " LIMIT 1;");
            return result.Rows.Count == 0 || result.Rows[0].Count == 0 ? null : result.Rows[0][0];
        }

        private Dictionary<string, object> QueryDatabaseTuningRowValueMap(RemoteDatabase db, string tableName, int carId)
        {
            var values = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);
            if (!db.TableExists(tableName))
                return values;

            string keyColumn;
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "_backup_DatabaseTuning_DataCar", StringComparison.OrdinalIgnoreCase))
            {
                keyColumn = db.ColumnExists(tableName, "Id") ? "Id" : string.Empty;
            }
            else
            {
                keyColumn = db.ColumnExists(tableName, "CarId") ? "CarId" : string.Empty;
            }

            if (string.IsNullOrEmpty(keyColumn))
                return values;

            var result = db.Query("SELECT * FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(keyColumn) + " = " + carId.ToString(CultureInfo.InvariantCulture) +
                " LIMIT 1;");
            if (result.Rows.Count == 0)
                return values;

            var row = result.Rows[0];
            for (var i = 0; i < result.Columns.Count && i < row.Count; i++)
                values[result.Columns[i]] = row[i];
            return values;
        }

        private static string FormatDatabaseTuningRawValue(object value)
        {
            if (value == null)
                return string.Empty;
            if (value is double)
                return ((double)value).ToString("0.########", CultureInfo.InvariantCulture);
            if (value is float)
                return ((float)value).ToString("0.########", CultureInfo.InvariantCulture);
            if (value is decimal)
                return ((decimal)value).ToString("0.########", CultureInfo.InvariantCulture);
            if (value is long || value is int || value is short || value is byte)
                return Convert.ToInt64(value, CultureInfo.InvariantCulture).ToString(CultureInfo.InvariantCulture);
            return Convert.ToString(value, CultureInfo.InvariantCulture) ?? string.Empty;
        }

        private string FormatDatabaseTuningDisplayValue(RemoteDatabase db, int carId, object value, DatabaseTuningPartMap partMap)
        {
            return FormatDatabaseTuningDisplayValue(db, carId, value, partMap, null);
        }

        private string FormatDatabaseTuningDisplayValue(RemoteDatabase db, int carId, object value, DatabaseTuningPartMap partMap, Dictionary<string, string> partLabelCache)
        {
            var raw = FormatDatabaseTuningRawValue(value);
            if (partMap == null || raw.Length == 0)
                return raw.Length == 0 ? "-" : raw;

            long id;
            if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out id))
                return raw;
            var cacheKey = partMap.TableName + "|" + id.ToString(CultureInfo.InvariantCulture);
            string label;
            if (partLabelCache == null || !partLabelCache.TryGetValue(cacheKey, out label))
            {
                label = QueryDatabaseTuningPartLabel(db, partMap.TableName, id, carId);
                if (partLabelCache != null)
                    partLabelCache[cacheKey] = label ?? string.Empty;
            }
            return id.ToString(CultureInfo.InvariantCulture) + (string.IsNullOrWhiteSpace(label) ? string.Empty : " - " + label);
        }

        private string QueryDatabaseTuningPartLabel(RemoteDatabase db, string partTableName, long id, int carId)
        {
            if (string.IsNullOrWhiteSpace(partTableName) || !db.TableExists(partTableName))
                return string.Empty;

            var idColumn = ResolveDatabaseTuningPartIdColumn(db, partTableName);
            if (string.IsNullOrEmpty(idColumn))
                return string.Empty;

            var tableSql = EscapeIdentifierForSql(partTableName);
            var idSql = EscapeIdentifierForSql(idColumn);
            var result = db.Query("SELECT * FROM " + tableSql + " WHERE " + idSql + " = " + id.ToString(CultureInfo.InvariantCulture) + " LIMIT 1;");
            if (result.Rows.Count == 0)
                return string.Empty;
            return BuildDatabaseTuningPartLabel(result.Columns, result.Rows[0], BuildDatabaseTuningPartLabelLookups(db));
        }

        private static string BuildDatabaseTuningValueSourceLabel(DatabaseTuningRow row)
        {
            if (row == null)
                return string.Empty;
            var label = row.TableName + "." + row.ColumnName;
            if (!string.IsNullOrWhiteSpace(row.TargetLabel))
                label += " (" + row.TargetLabel + ")";
            return label;
        }

        private static string GetDatabaseTuningSection(string tableName, string columnName, DatabaseTuningPartMap map)
        {
            if (map != null)
            {
                var category = string.IsNullOrWhiteSpace(map.CategoryName) ? "Parts" : map.CategoryName.Trim();
                return "Parts - " + MakeReadableIdentifier(category);
            }
            if (columnName.StartsWith("Tuning_", StringComparison.OrdinalIgnoreCase))
            {
                if (ContainsAny(columnName, "TirePressure")) return "Tune - Tires";
                if (ContainsAny(columnName, "Gear", "DriveRatio")) return "Tune - Gearing";
                if (ContainsAny(columnName, "Camber", "Toe", "Caster")) return "Tune - Alignment";
                if (ContainsAny(columnName, "Swaybar")) return "Tune - Anti-Roll Bars";
                if (ContainsAny(columnName, "Spring", "RideHeight", "Damping", "Bump")) return "Tune - Springs & Damping";
                if (ContainsAny(columnName, "Downforce")) return "Tune - Aero";
                if (ContainsAny(columnName, "Brake")) return "Tune - Brakes";
                if (ContainsAny(columnName, "Accel", "Decel", "Torque")) return "Tune - Differential";
                return "Tune Values";
            }
            if (ContainsAny(columnName, "RigidBodies", "Raycast", "SprungForces", "ForceProp", "RaceMode", "AutoSteer", "TCS", "BrakeProfile")) return "Advanced Physics";
            if (ContainsAny(columnName, "Traction", "Tire", "Slip", "Fric")) return "Tires & Grip";
            if (ContainsAny(columnName, "Engine", "Torque", "Power", "Redline", "Gear", "DriveType", "Drivetrain", "Aspiration", "Displacement")) return "Engine & Drivetrain";
            if (ContainsAny(columnName, "Aero", "Drag", "Downforce", "Wing")) return "Aero";
            if (ContainsAny(columnName, "Brake")) return "Brakes";
            if (ContainsAny(columnName, "Weight", "Mass", "Body", "Chassis")) return "Body & Weight";
            if (ContainsAny(columnName, "Rating", "Performance", "Class", "PI")) return "Ratings";
            if (ContainsAny(columnName, "Year", "Generation", "Series")) return "Identity & Details";
            if (ContainsAny(columnName, "Is", "NotAvailable", "Visible", "Purchased", "Installed", "Drivable", "Flags")) return "Flags";
            return string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ? "Data Car" : "Garage";
        }

