            if (string.Equals(name, "UseForcePropLongTorque", StringComparison.OrdinalIgnoreCase)) return "Force Prop Longitudinal Torque";
            if (string.Equals(name, "BrakeProfile", StringComparison.OrdinalIgnoreCase)) return "Brake Profile";
