        private static string MakeReadableIdentifier(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return string.Empty;
            var source = text.Replace("_", " ").Replace("-", " ").Replace(":", " ");
            var sb = new StringBuilder();
            for (var i = 0; i < source.Length; i++)
            {
                var c = source[i];
                if (i > 0 && char.IsUpper(c) && !char.IsWhiteSpace(source[i - 1]) && !char.IsUpper(source[i - 1]))
                    sb.Append(' ');
                sb.Append(c);
            }
            return CultureInfo.CurrentCulture.TextInfo.ToTitleCase(sb.ToString().Trim().ToLowerInvariant())
                .Replace("Mph", "MPH")
                .Replace("Pi", "PI")
                .Replace("Tcs", "TCS")
                .Replace("Abs", "ABS")
                .Replace("Rgb", "RGB")
                .Replace("Id", "ID");
        }

        private void ApplyDatabaseTuningSelected()
        {
            var car = GetSelectedDatabaseTuningCar();
            var inputs = CaptureDatabaseTuningInputs(true);
            if (inputs.Count == 0)
                throw new InvalidOperationException("Check at least one row or edit a New Value first.");

            Interlocked.Increment(ref _databaseTuningLoadGeneration);
            var touched = 0;
            var mirrored = 0;
            var verified = 0;
            var autoSupportNotes = new List<string>();
            lock (_databaseTuningDbLock)
            {
                var db = RequireDatabase();
                inputs = ValidateDatabaseTuningInputs(db, car, inputs, autoSupportNotes);
                var mirrorRows = new List<DatabaseTuningRow>();
                mirrored = BuildDatabaseTuningMirrors(db, car.CarId, inputs, mirrorRows);
                var writeRows = inputs.Concat(mirrorRows)
                    .GroupBy(row => row.Key, StringComparer.OrdinalIgnoreCase)
                    .Select(group => group.First())
                    .ToList();
                RunDatabaseTuningAtomic(db, "database_tuning_apply", delegate
                {
                    touched = ApplyDatabaseTuningBatchedWrites(db, car.CarId, writeRows);
                    if (touched == 0)
                        throw new InvalidOperationException("No Database Tuning rows could be applied.");
                    verified = VerifyDatabaseTuningApplied(db, car.CarId, writeRows);
                });
            }

            if (touched == 0)
                throw new InvalidOperationException("No Database Tuning rows could be applied.");

            Log("Database Tuning applied and verified " + verified.ToString(CultureInfo.InvariantCulture) + " field(s) for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ".");
            if (mirrored > 0)
                Log("Database Tuning synchronized " + mirrored.ToString(CultureInfo.InvariantCulture) + " linked performance/cache field(s).");
            if (autoSupportNotes.Count > 0)
                Log("Database Tuning auto-installed " + autoSupportNotes.Count.ToString(CultureInfo.InvariantCulture) + " support part(s): " + string.Join(", ", autoSupportNotes.ToArray()) + ".");
            LoadDatabaseTuningFields(car);
            var supportText = autoSupportNotes.Count == 0
                ? string.Empty
                : Environment.NewLine + Environment.NewLine + "Luna also installed " + autoSupportNotes.Count.ToString(CultureInfo.InvariantCulture) + " required support part(s) so the car loads safely.";
            var mirrorText = mirrored == 0
                ? string.Empty
                : Environment.NewLine + Environment.NewLine + "Luna also synced " + mirrored.ToString(CultureInfo.InvariantCulture) + " linked car cache field(s) so FH6 reads the same values from garage and car data.";
            ShowInfo("Database Tuning applied and verified." + supportText + mirrorText + Environment.NewLine + Environment.NewLine +
                "Please switch cars and switch back to see changes.");
        }

        private int BuildDatabaseTuningMirrors(RemoteDatabase db, int carId, List<DatabaseTuningRow> inputs, List<DatabaseTuningRow> mirrorRows)
        {
            var mirrors = new Dictionary<string, DatabaseTuningRow>(StringComparer.OrdinalIgnoreCase);
            var explicitKeys = new HashSet<string>((inputs ?? new List<DatabaseTuningRow>()).Select(row => row.Key), StringComparer.OrdinalIgnoreCase);
            foreach (var item in inputs ?? new List<DatabaseTuningRow>())
            {
                if (item == null || string.IsNullOrWhiteSpace(item.ColumnName))
                    continue;

                var raw = (item.NewValue ?? string.Empty).Trim();
                double value;
                if (string.Equals(item.ColumnName, "TopSpeed-mph", StringComparison.OrdinalIgnoreCase) &&
                    string.Equals(item.TableName, "Data_Car", StringComparison.OrdinalIgnoreCase) &&
                    double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                {
                    var sim = value * 0.44704D;
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "SimTopSpeed", sim.ToString("0.########", CultureInfo.InvariantCulture), "real", "Top Speed simulation cache");
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Profile0_Career_Garage", "TopSpeed", sim.ToString("0.########", CultureInfo.InvariantCulture), "real", "Garage top-speed cache");
                    continue;
                }

                if (string.Equals(item.ColumnName, "SimTopSpeed", StringComparison.OrdinalIgnoreCase) &&
                    string.Equals(item.TableName, "Data_Car", StringComparison.OrdinalIgnoreCase) &&
                    double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                {
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Profile0_Career_Garage", "TopSpeed", value.ToString("0.########", CultureInfo.InvariantCulture), "real", "Garage top-speed cache");
                    if (Math.Abs(0.44704D) > double.Epsilon)
                        AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "TopSpeed-mph", (value / 0.44704D).ToString("0.########", CultureInfo.InvariantCulture), "real", "Top Speed MPH cache");
                    continue;
                }

                if (string.Equals(item.ColumnName, "TopSpeed", StringComparison.OrdinalIgnoreCase) &&
                    string.Equals(item.TableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase) &&
                    double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                {
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "SimTopSpeed", value.ToString("0.########", CultureInfo.InvariantCulture), "real", "Top Speed simulation cache");
                    if (Math.Abs(0.44704D) > double.Epsilon)
                        AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "TopSpeed-mph", (value / 0.44704D).ToString("0.########", CultureInfo.InvariantCulture), "real", "Top Speed MPH cache");
                    continue;
                }

                if (string.Equals(item.ColumnName, "PI", StringComparison.OrdinalIgnoreCase))
                {
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "PerformanceIndex", raw, item.ValueType, "Performance index cache");
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Profile0_Career_Garage", "PerformanceIndex", raw, item.ValueType, "Garage PI cache");
                    continue;
                }

                if (string.Equals(item.ColumnName, "PerformanceIndex", StringComparison.OrdinalIgnoreCase))
                {
                    var otherTable = string.Equals(item.TableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ? "Profile0_Career_Garage" : "Data_Car";
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, otherTable, "PerformanceIndex", raw, item.ValueType, "Performance index cache");
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", "PI", raw, item.ValueType, "PI cache");
                    continue;
                }

                if (!IsDatabaseTuningExactMirrorColumn(item.ColumnName))
                    continue;

                if (string.Equals(item.TableName, "Data_Car", StringComparison.OrdinalIgnoreCase))
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Profile0_Career_Garage", item.ColumnName, raw, item.ValueType, item.DisplayName + " garage cache");
                else if (string.Equals(item.TableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase))
                    AddDatabaseTuningMirror(db, carId, explicitKeys, mirrors, "Data_Car", item.ColumnName, raw, item.ValueType, item.DisplayName + " car data cache");
            }

            if (mirrorRows != null)
                mirrorRows.AddRange(mirrors.Values);
            return mirrors.Count;
        }

        private int ApplyDatabaseTuningBatchedWrites(RemoteDatabase db, int carId, List<DatabaseTuningRow> rows)
        {
            var touched = 0;
            foreach (var group in (rows ?? new List<DatabaseTuningRow>()).GroupBy(row =>
                row.TableName + "\n" + BuildDatabaseTuningRowWhere(row, carId), StringComparer.OrdinalIgnoreCase))
            {
                var first = group.FirstOrDefault();
                if (first == null)
                    continue;

                var tableName = first.TableName;
                if (!db.TableExists(tableName))
                    continue;

                var backupName = GetDatabaseTuningBackupName(tableName);
                var tableSql = EscapeIdentifierForSql(tableName);
                db.Execute("CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");

                var sets = new List<string>();
                foreach (var item in group)
                {
                    if (!db.ColumnExists(tableName, item.ColumnName))
                        continue;
                    sets.Add(EscapeIdentifierForSql(item.ColumnName) + " = " + BuildDatabaseTuningSqlValue(item));
                }

                if (sets.Count == 0)
                    continue;

                db.Execute("UPDATE " + tableSql + " SET " + string.Join(", ", sets.ToArray()) + BuildDatabaseTuningRowWhere(first, carId) + ";");
                touched += sets.Count;
            }
            return touched;
        }

        private void RunDatabaseTuningAtomic(RemoteDatabase db, string operationName, Action action)
        {
            if (db == null)
                throw new InvalidOperationException("Attach and load the database first.");
            if (action == null)
                return;

            var savepoint = EscapeIdentifierForSql(string.IsNullOrWhiteSpace(operationName) ? "luna_database_tuning" : operationName);
            var active = false;
            try
            {
                db.Execute("SAVEPOINT " + savepoint + ";");
                active = true;
                action();
                db.Execute("RELEASE SAVEPOINT " + savepoint + ";");
                active = false;
            }
            catch
            {
                if (active)
                {
                    try
                    {
                        db.Execute("ROLLBACK TO SAVEPOINT " + savepoint + ";");
                    }
                    catch (Exception ex)
                    {
                        Log("Database Tuning rollback warning: " + ex.Message);
                    }

                    try
                    {
                        db.Execute("RELEASE SAVEPOINT " + savepoint + ";");
                    }
                    catch (Exception ex)
                    {
                        Log("Database Tuning rollback cleanup warning: " + ex.Message);
                    }
                }
                throw;
            }
        }

        private static void AddDatabaseTuningMirror(RemoteDatabase db, int carId, HashSet<string> explicitKeys, Dictionary<string, DatabaseTuningRow> mirrors, string tableName, string columnName, string rawValue, string valueType, string description)
        {
            if (db == null || string.IsNullOrWhiteSpace(tableName) || string.IsNullOrWhiteSpace(columnName))
                return;
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, columnName))
                return;

            var key = tableName + "." + columnName;
            if (explicitKeys != null && explicitKeys.Contains(key))
                return;

            mirrors[key] = new DatabaseTuningRow(
                tableName,
                columnName,
                "Linked Caches",
                MakeReadableIdentifier(columnName),
                description,
                string.Empty,
                string.Empty,
                string.Empty,
                string.Empty,
                string.IsNullOrWhiteSpace(valueType) ? "real" : valueType,
                string.Empty)
            {
                Enabled = true,
                NewValue = rawValue ?? string.Empty
            };
        }

        private static bool IsDatabaseTuningExactMirrorColumn(string columnName)
        {
            switch (columnName ?? string.Empty)
            {
                case "PerformanceIndex":
                case "ClassID":
                case "ClassId":
                case "SpeedRating":
                case "OffroadRating":
                case "AccelerationRating":
                case "LaunchRating":
                case "BrakingRating":
                case "HandlingRating":
                case "CurbWeight":
                case "WeightDistribution":
                case "AspirationTypeId":
                case "SimPeakPower":
                case "SimPeakAngVel":
                case "SimPeakTorque":
                case "SimPeakTorqueAngVel":
                case "SimRedlineAngVel":
                case "PeakIntakePSI":
                case "Traction_Road":
                case "Traction_OffRoad":
                case "Traction_Snow":
                    return true;
                default:
                    return false;
            }
        }

        private int VerifyDatabaseTuningApplied(RemoteDatabase db, int carId, List<DatabaseTuningRow> rows)
        {
            var failures = new List<string>();
            var verified = 0;
            foreach (var item in rows ?? new List<DatabaseTuningRow>())
            {
                if (item == null || !db.TableExists(item.TableName) || !db.ColumnExists(item.TableName, item.ColumnName))
                    continue;

                var targetRows = CountDatabaseTuningTargetRows(db, item, carId);
                if (targetRows <= 0)
                {
                    failures.Add(item.DisplayName + " had no target row");
                    continue;
                }

                var mismatched = CountDatabaseTuningMismatchedRows(db, item, carId);
                if (mismatched > 0)
                    failures.Add(item.DisplayName + " did not stick");
                else
                    verified++;
            }

            if (failures.Count > 0)
            {
                var shown = string.Join(", ", failures.Take(8).ToArray());
                if (failures.Count > 8)
                    shown += ", +" + (failures.Count - 8).ToString(CultureInfo.InvariantCulture) + " more";
                throw new InvalidOperationException("Database Tuning verification failed: " + shown + ".");
            }

            return verified;
        }

        private long CountDatabaseTuningTargetRows(RemoteDatabase db, string tableName, int carId)
        {
            var where = BuildDatabaseTuningCarWhere(tableName, carId);
            return db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(tableName) + where + ";") ?? 0;
        }

        private long CountDatabaseTuningTargetRows(RemoteDatabase db, DatabaseTuningRow row, int carId)
        {
            if (row == null)
                return 0;
            var where = BuildDatabaseTuningRowWhere(row, carId);
            return db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(row.TableName) + where + ";") ?? 0;
        }

        private long CountDatabaseTuningMismatchedRows(RemoteDatabase db, DatabaseTuningRow row, int carId)
        {
            var tableSql = EscapeIdentifierForSql(row.TableName);
            var columnSql = EscapeIdentifierForSql(row.ColumnName);
            var where = BuildDatabaseTuningRowWhere(row, carId);
            var raw = (row.NewValue ?? string.Empty).Trim();
            string mismatch;
            if (raw.Length == 0)
            {
                mismatch = columnSql + " IS NOT NULL";
            }
            else if (string.Equals(row.ValueType, "part", StringComparison.OrdinalIgnoreCase) ||
                     string.Equals(row.ValueType, "int", StringComparison.OrdinalIgnoreCase))
            {
                long parsed;
                if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
                    throw new InvalidOperationException(row.DisplayName + " must be a whole number.");
                mismatch = columnSql + " IS NULL OR CAST(" + columnSql + " AS INTEGER) <> " + parsed.ToString(CultureInfo.InvariantCulture);
            }
            else
            {
                double parsed;
                if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out parsed) || double.IsNaN(parsed) || double.IsInfinity(parsed))
                    throw new InvalidOperationException(row.DisplayName + " must be a finite number.");
                var epsilon = Math.Max(0.00001D, Math.Abs(parsed) * 0.0000001D);
                mismatch = columnSql + " IS NULL OR ABS(CAST(" + columnSql + " AS REAL) - " + parsed.ToString("0.########", CultureInfo.InvariantCulture) + ") > " + epsilon.ToString("0.########", CultureInfo.InvariantCulture);
            }

            return db.QueryScalarLong("SELECT count(*) FROM " + tableSql + where + " AND (" + mismatch + ");") ?? 0;
        }

        private List<DatabaseTuningRow> ValidateDatabaseTuningInputs(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> inputs, List<string> autoSupportNotes)
        {
            var safeInputs = new List<DatabaseTuningRow>(inputs ?? new List<DatabaseTuningRow>());
            ValidateDatabaseTuningValueInputs(db, safeInputs);
            var explicitKeys = new HashSet<string>(safeInputs.Select(row => row.Key), StringComparer.OrdinalIgnoreCase);
            var requirements = new Dictionary<string, DatabaseTuningPartDependency>(StringComparer.OrdinalIgnoreCase);

            foreach (var item in safeInputs.ToList())
            {
                if (!IsDatabaseTuningPartRow(item))
                    continue;

                var partId = ParseDatabaseTuningPartId(item);
                var part = QueryDatabaseTuningPartRecord(db, item.PartTableName, partId);
                if (part == null)
                    throw new InvalidOperationException(item.DisplayName + " part ID " + partId.ToString(CultureInfo.InvariantCulture) + " was not found in " + item.PartTableName + ".");

                var dependency = ResolveDatabaseTuningPartDependency(db, item, part, car.CarId);
                if (dependency == null)
                    continue;

                if (dependency.IsOrdinal)
                {
                    if (dependency.RequiredValue > 0 && dependency.RequiredValue != car.CarId)
                    {
                        throw new InvalidOperationException(item.DisplayName + " is built for car ID " + dependency.RequiredValue.ToString(CultureInfo.InvariantCulture) +
                            ", not the selected car ID " + car.CarId.ToString(CultureInfo.InvariantCulture) + ". Pick a part made for this car or use a compatible parent/child part family.");
                    }
                    continue;
                }

                var parentKey = "Profile0_Career_Garage." + dependency.ParentColumn;
                DatabaseTuningPartDependency existing;
                if (requirements.TryGetValue(parentKey, out existing) && existing.RequiredValue != dependency.RequiredValue)
                {
                    throw new InvalidOperationException("Selected parts require different " + MakeReadableIdentifier(dependency.ParentColumn) +
                        " support values. Pick parts from the same family before applying.");
                }
                requirements[parentKey] = dependency;
            }

            foreach (var requirement in requirements.Values)
                EnsureDatabaseTuningSupportPart(db, car, safeInputs, explicitKeys, requirement, autoSupportNotes);
            EnsureDatabaseTuningCurrentOrdinalPartsSupported(db, car, safeInputs, explicitKeys, autoSupportNotes);
            EnsureDatabaseTuningChildrenForSelectedParents(db, car, safeInputs, explicitKeys, autoSupportNotes);

            return safeInputs;
        }

        private static void ValidateDatabaseTuningValueInputs(RemoteDatabase db, List<DatabaseTuningRow> inputs)
        {
            foreach (var item in inputs ?? new List<DatabaseTuningRow>())
            {
                if (item == null || IsDatabaseTuningPartRow(item))
                    continue;
                if (!IsDatabaseTuningSafeValueColumn(item.TableName, item.ColumnName))
                {
                    throw new InvalidOperationException(item.DisplayName +
                        " is a structural FH6 value and cannot be edited safely by itself. Use Pick Part or a dedicated Luna editor instead.");
                }

                var raw = (item.NewValue ?? string.Empty).Trim();
                if (raw.Length == 0)
                    throw new InvalidOperationException(item.DisplayName + " cannot be blank. Use Restore Selected to return to the backed-up value.");

                if (string.Equals(item.ValueType, "int", StringComparison.OrdinalIgnoreCase))
                {
                    long parsedInt;
                    if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsedInt))
                        throw new InvalidOperationException(item.DisplayName + " must be a whole number.");
                    continue;
                }

                double value;
                if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value) ||
                    double.IsNaN(value) ||
                    double.IsInfinity(value))
                {
                    throw new InvalidOperationException(item.DisplayName + " must be a finite number.");
                }
            }
        }

        private static void ValidateDatabaseTuningKnownValue(RemoteDatabase db, DatabaseTuningRow item, double value)
        {
            if (db == null || item == null || !IsDatabaseTuningKnownValueColumn(item.TableName, item.ColumnName))
                return;

            var whole = Math.Round(value);
            if (Math.Abs(value - whole) > 0.000001D)
                throw new InvalidOperationException(item.DisplayName + " must use a whole FH6 profile value.");

            var parsed = Convert.ToInt64(whole, CultureInfo.InvariantCulture);
            if (!db.TableExists(item.TableName) || !db.ColumnExists(item.TableName, item.ColumnName))
                throw new InvalidOperationException(item.DisplayName + " is not available in the current live database.");

            var count = db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(item.TableName) +
                " WHERE " + EscapeIdentifierForSql(item.ColumnName) + " = " + parsed.ToString(CultureInfo.InvariantCulture) + ";") ?? 0;
            if (count <= 0)
            {
                throw new InvalidOperationException(item.DisplayName + " must use a value that exists in this FH6 database. " +
                    "Use a value copied from another car if you want to swap this profile safely.");
            }
        }

        private static bool IsDatabaseTuningKnownValueColumn(string tableName, string columnName)
        {
            if (!string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase))
                return false;

            return string.Equals(columnName, "BrakeProfile", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "AutoSteerOverrideID", StringComparison.OrdinalIgnoreCase);
        }

        private static bool TryGetDatabaseTuningSafeRange(string tableName, string columnName, out double min, out double max, out string rangeText)
        {
            min = 0D;
            max = 0D;
            rangeText = string.Empty;

            if (string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase) &&
                columnName.StartsWith("Tuning_", StringComparison.OrdinalIgnoreCase))
            {
                min = 0D;
                max = 1D;
                rangeText = "-1 for stock or between 0 and 1";
                return true;
            }

            if (IsDatabaseTuningBooleanPhysicsColumn(columnName))
            {
                min = 0D; max = 1D; rangeText = "0 or 1"; return true;
            }

            if (string.Equals(tableName, "List_TyreCurveDB", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningTyreCurveDbColumn(columnName))
            {
                min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
            }

            if (string.Equals(tableName, "List_TractionControl", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                if (ContainsAny(columnName, "Speed"))
                {
                    min = 0D; max = 300D; rangeText = "between 0 and 300"; return true;
                }
                min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
            }

            if (string.Equals(tableName, "List_BrakeProfile", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                min = 0D; max = 10D; rangeText = "between 0 and 10"; return true;
            }

            if (string.Equals(tableName, "List_SpringDamperPhysics", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                if (ContainsAny(columnName, "Toe", "Camber", "Caster", "RideHeight", "Stretch", "RollCentre", "AntiGeometry"))
                {
                    min = -45D; max = 45D; rangeText = "between -45 and 45"; return true;
                }
                min = 0D; max = 1000000D; rangeText = "between 0 and 1000000"; return true;
            }

            if (string.Equals(tableName, "List_TireCompound", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                if (ContainsAny(columnName, "Pressure"))
                {
                    min = 0D; max = 100D; rangeText = "between 0 and 100"; return true;
                }
                if (ContainsAny(columnName, "Spring", "Stiffness", "Trail", "Compression", "BumpD", "ReboundD", "Resistance", "Inertia", "Downforce", "Load", "Width", "Diameter"))
                {
                    min = 0D; max = 1000000D; rangeText = "between 0 and 1000000"; return true;
                }
                min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
            }

            if ((string.Equals(tableName, "List_SteeringSettings", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_RearSteeringSettings", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "AutoSteerOverrides", StringComparison.OrdinalIgnoreCase)) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                min = -360D; max = 360D; rangeText = "between -360 and 360"; return true;
            }

            if (string.Equals(tableName, "Data_Engine", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                if (ContainsAny(columnName, "Mass"))
                {
                    min = 0.001D; max = 5000D; rangeText = "between 0.001 and 5000"; return true;
                }
                if (ContainsAny(columnName, "Boost"))
                {
                    min = 0D; max = 20D; rangeText = "between 0 and 20"; return true;
                }
                if (ContainsAny(columnName, "Torque", "Power"))
                {
                    min = 0D; max = 100000D; rangeText = "between 0 and 100000"; return true;
                }
                min = 0D; max = 10000D; rangeText = "between 0 and 10000"; return true;
            }

            if (string.Equals(tableName, "Data_Motor", StringComparison.OrdinalIgnoreCase) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                if (ContainsAny(columnName, "Mass"))
                {
                    min = 0.001D; max = 5000D; rangeText = "between 0.001 and 5000"; return true;
                }
                if (ContainsAny(columnName, "Torque", "Power", "Redline"))
                {
                    min = 0D; max = 100000D; rangeText = "between 0 and 100000"; return true;
                }
                min = 0D; max = 10000D; rangeText = "between 0 and 10000"; return true;
            }

            if ((string.Equals(tableName, "List_AntiSwayPhysics", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_PreloadAndDroopDamper", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_ThirdSpringElement", StringComparison.OrdinalIgnoreCase)) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                min = 0D; max = 1000000D; rangeText = "between 0 and 1000000"; return true;
            }

            if ((string.Equals(tableName, "List_TireFrictionCurve", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_TireFrictionMultiCurve", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_TireAffectCurve", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "List_UpgradeTireCompoundFictionModOverride", StringComparison.OrdinalIgnoreCase)) &&
                IsDatabaseTuningReferencedPhysicsValueColumn(tableName, columnName))
            {
                min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
            }

            switch (columnName ?? string.Empty)
            {
                case "TopSpeed-mph":
                    min = 1D; max = 500D; rangeText = "between 1 and 500 MPH"; return true;
                case "NumGears":
                    min = 1D; max = 11D; rangeText = "between 1 and 11"; return true;
                case "RequiresClutchWhenShifting":
                    min = 0D; max = 1D; rangeText = "0 or 1"; return true;
                case "FrontTireWidthMM":
                case "RearTireWidthMM":
                case "FrontTireWidth":
                case "RearTireWidth":
                    min = 50D; max = 700D; rangeText = "between 50 and 700 mm"; return true;
                case "FrontTireAspect":
                case "RearTireAspect":
                    min = 10D; max = 150D; rangeText = "between 10 and 150"; return true;
                case "FrontWheelDiameterIN":
                case "RearWheelDiameterIN":
                case "FrontWheelDiameter":
                case "RearWheelDiameter":
                    min = 5D; max = 30D; rangeText = "between 5 and 30 inches"; return true;
                case "FrontTireAspectRatioOffset":
                case "RearTireAspectRatioOffset":
                    min = -100D; max = 100D; rangeText = "between -100 and 100"; return true;
                case "GearShiftTime":
                case "CVTShiftTime":
                case "ClutchInTime":
                case "ClutchOutTime":
                    min = -1D; max = 10D; rangeText = "between -1 and 10 seconds"; return true;
                case "FinalDriveRatio":
                    min = 0.01D; max = 30D; rangeText = "between 0.01 and 30"; return true;
                case "GearRatio0":
                case "GearRatio1":
                case "GearRatio2":
                case "GearRatio3":
                case "GearRatio4":
                case "GearRatio5":
                case "GearRatio6":
                case "GearRatio7":
                case "GearRatio8":
                case "GearRatio9":
                case "GearRatio10":
                    min = -20D; max = 20D; rangeText = "between -20 and 20"; return true;
                case "SimTopSpeed":
