                    min = 0.1D; max = 250D; rangeText = "between 0.1 and 250 simulation speed units"; return true;
                case "Time:0-60-sec":
                case "Time:0-100-sec":
                case "QuarterMileTime-sec":
                case "SimTimeTo60MPH":
                case "SimTimeTo100MPH":
                case "SimTimeQuarterMile":
                    min = 0D; max = 600D; rangeText = "between 0 and 600 seconds"; return true;
                case "QuarterMileSpeed-mph":
