                case "DefRideHeight":
                case "MinRideHeight":
                case "MaxRideHeight":
                case "BumpStopLength":
                case "RollCentreHeight":
                case "AntiGeometryPercent":
                    min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
                case "DefSpringRate":
                case "MinSpringRate":
                case "MaxSpringRate":
                case "BumpStopSpringK":
                case "BumpStopSpringKMax":
                    min = 0D; max = 1000000D; rangeText = "between 0 and 1000000"; return true;
                case "PuddleScale":
                    min = 0D; max = 10D; rangeText = "between 0 and 10"; return true;
                case "PerformanceIndex":
                case "PI":
                    min = 0D; max = 999D; rangeText = "between 0 and 999"; return true;
                case "ClassID":
                    min = 0D; max = 7D; rangeText = "between 0 and 7"; return true;
                case "CarClassModifier":
                    min = -10D; max = 10D; rangeText = "between -10 and 10"; return true;
                case "SpeedRating":
                case "OffroadRating":
                case "AccelerationRating":
                case "LaunchRating":
                case "BrakingRating":
                case "HandlingRating":
                case "MinOffRoadPerfRating":
                case "MaxUpgradeWizardPerfRating":
                    min = 0D; max = 10D; rangeText = "between 0 and 10"; return true;
                case "CurbWeight":
                    min = 0.001D; max = 1000D; rangeText = "between 0.001 and 1000"; return true;
                case "WeightDistribution":
                    min = 0D; max = 1D; rangeText = "between 0 and 1"; return true;
                case "SimPeakPower":
                case "SimPeakAngVel":
                case "SimPeakTorque":
                case "SimPeakTorqueAngVel":
                case "SimRedlineAngVel":
                case "PeakIntakePSI":
                    min = 0D; max = 100000D; rangeText = "between 0 and 100000"; return true;
                case "BaseRarity":
                    min = 0D; max = 10D; rangeText = "between 0 and 10"; return true;
                case "BaseCost":
                case "RebuildModTorque":
                case "RebuildModGrip":
                case "RebuildModBraking":
                case "RebuildModWeight":
                case "RebuildScore":
                    min = 0D; max = 100000000D; rangeText = "between 0 and 100000000"; return true;
                case "FrontStockRideHeight":
                case "RearStockRideHeight":
                    min = 0D; max = 10D; rangeText = "between 0 and 10"; return true;
                default:
                    return false;
            }
        }

        private void EnsureDatabaseTuningCurrentOrdinalPartsSupported(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> safeInputs, HashSet<string> explicitKeys, List<string> autoSupportNotes)
        {
            var partMap = QueryDatabaseTuningPartMap(db);
            foreach (var map in partMap.Values)
            {
                if (map == null ||
                    !db.ColumnExists("Profile0_Career_Garage", map.ColumnName) ||
                    !db.TableExists(map.TableName) ||
                    !db.ColumnExists(map.TableName, "Ordinal"))
                    continue;

                var item = FindDatabaseTuningInput(safeInputs, "Profile0_Career_Garage", map.ColumnName);
                var explicitInput = item != null && explicitKeys.Contains(item.Key);
                var partId = item != null
                    ? ParseDatabaseTuningPartId(item)
                    : ToLong(QueryDatabaseTuningCell(db, "Profile0_Career_Garage", map.ColumnName, car.CarId, false));
                if (partId <= 0)
                    continue;

                var part = QueryDatabaseTuningPartRecord(db, map.TableName, partId);
                var ordinal = part == null ? 0 : part.GetLong("Ordinal");
                if (ordinal == car.CarId)
                    continue;

                if (explicitInput)
                {
                    throw new InvalidOperationException(GetDatabaseTuningDisplayName(map.ColumnName, map) +
                        " belongs to car ID " + ordinal.ToString(CultureInfo.InvariantCulture) +
                        ". Pick a part made for the selected car to avoid a crash.");
                }

                var repairPartId = FindDatabaseTuningOrdinalSupportPart(db, map.TableName, car.CarId);
                if (!repairPartId.HasValue)
                {
                    throw new InvalidOperationException(GetDatabaseTuningDisplayName(map.ColumnName, map) +
                        " is currently unsupported for the selected car, and Luna could not find a safe stock replacement.");
                }

                UpsertDatabaseTuningDependentSupportInput(db, car, safeInputs, item, map, repairPartId.Value, autoSupportNotes);
            }
        }

        private void EnsureDatabaseTuningChildrenForSelectedParents(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> safeInputs, HashSet<string> explicitKeys, List<string> autoSupportNotes)
        {
            var partMap = QueryDatabaseTuningPartMap(db);
            EnsureDatabaseTuningChildrenForParent(db, car, safeInputs, explicitKeys, autoSupportNotes, partMap, "Engine", "List_UpgradeEngine", "EngineID", "EngineID");
            EnsureDatabaseTuningChildrenForParent(db, car, safeInputs, explicitKeys, autoSupportNotes, partMap, "Drivetrain", "List_UpgradeDrivetrain", "DrivetrainID", "DrivetrainID", "DrivetrainId");
            EnsureDatabaseTuningChildrenForParent(db, car, safeInputs, explicitKeys, autoSupportNotes, partMap, "CarBody", "List_UpgradeCarBody", "CarBodyID", "CarBodyID", "CarBodyId", "CarbodyId");
            EnsureDatabaseTuningChildrenForParent(db, car, safeInputs, explicitKeys, autoSupportNotes, partMap, "Motor", "List_UpgradeMotor", "MotorID", "MotorID");
        }

        private void EnsureDatabaseTuningChildrenForParent(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> safeInputs, HashSet<string> explicitKeys, List<string> autoSupportNotes, Dictionary<string, DatabaseTuningPartMap> partMap, string parentColumn, string parentTable, string parentProperty, params string[] childDependencyColumns)
        {
            var parentRow = FindDatabaseTuningInput(safeInputs, "Profile0_Career_Garage", parentColumn);
            if (parentRow == null)
                return;

            var parentPartId = ParseDatabaseTuningPartId(parentRow);
            var parentPart = QueryDatabaseTuningPartRecord(db, parentTable, parentPartId);
            if (parentPart == null)
                throw new InvalidOperationException(MakeReadableIdentifier(parentColumn) + " part ID " + parentPartId.ToString(CultureInfo.InvariantCulture) + " was not found.");

            var parentPropertyColumn = ResolveExistingColumn(db, parentTable, parentProperty);
            var requiredValue = string.IsNullOrEmpty(parentPropertyColumn) ? 0 : parentPart.GetLong(parentPropertyColumn);
            if (requiredValue <= 0)
                return;

            foreach (var map in partMap.Values)
            {
                if (map == null ||
                    string.Equals(map.ColumnName, parentColumn, StringComparison.OrdinalIgnoreCase) ||
                    !db.ColumnExists("Profile0_Career_Garage", map.ColumnName) ||
                    !db.TableExists(map.TableName))
                    continue;

                var dependencyColumn = ResolveExistingColumn(db, map.TableName, childDependencyColumns);
                if (string.IsNullOrEmpty(dependencyColumn))
                    continue;

                var childRow = FindDatabaseTuningInput(safeInputs, "Profile0_Career_Garage", map.ColumnName);
                var childExplicit = childRow != null && explicitKeys.Contains(childRow.Key);
                var childPartId = childRow != null
                    ? ParseDatabaseTuningPartId(childRow)
                    : ToLong(QueryDatabaseTuningCell(db, "Profile0_Career_Garage", map.ColumnName, car.CarId, false));
                if (childPartId <= 0)
                    continue;

                var childPart = QueryDatabaseTuningPartRecord(db, map.TableName, childPartId);
                if (childPart != null && childPart.GetLong(dependencyColumn) == requiredValue)
                    continue;

                if (childExplicit)
                {
                    throw new InvalidOperationException(GetDatabaseTuningDisplayName(map.ColumnName, map) + " does not match the selected " +
                        MakeReadableIdentifier(parentColumn) + ". Pick a compatible part from the same family.");
                }

                var supportPartId = FindDatabaseTuningPartByProperty(db, map.TableName, dependencyColumn, requiredValue, car.CarId);
                if (!supportPartId.HasValue)
                    supportPartId = CreateDatabaseTuningClonedDependentPart(db, map.TableName, dependencyColumn, requiredValue, map.ColumnName, childPartId, car.CarId, autoSupportNotes);

                if (!supportPartId.HasValue)
                    throw new InvalidOperationException(GetDatabaseTuningDisplayName(map.ColumnName, map) + " needs " +
                        MakeReadableIdentifier(parentColumn) + " support value " + requiredValue.ToString(CultureInfo.InvariantCulture) +
                        ", but Luna could not create a safe replacement part.");

                UpsertDatabaseTuningDependentSupportInput(db, car, safeInputs, childRow, map, supportPartId.Value, autoSupportNotes);
            }
        }

        private static DatabaseTuningRow FindDatabaseTuningInput(List<DatabaseTuningRow> inputs, string tableName, string columnName)
        {
            return (inputs ?? new List<DatabaseTuningRow>()).FirstOrDefault(row =>
                string.Equals(row.TableName, tableName, StringComparison.OrdinalIgnoreCase) &&
                string.Equals(row.ColumnName, columnName, StringComparison.OrdinalIgnoreCase));
        }

        private void UpsertDatabaseTuningDependentSupportInput(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> safeInputs, DatabaseTuningRow existingRow, DatabaseTuningPartMap map, long supportPartId, List<string> autoSupportNotes)
        {
            if (existingRow != null)
            {
                existingRow.NewValue = supportPartId.ToString(CultureInfo.InvariantCulture);
                existingRow.Enabled = true;
            }
            else
            {
                var current = QueryDatabaseTuningCell(db, "Profile0_Career_Garage", map.ColumnName, car.CarId, false);
                var currentRaw = FormatDatabaseTuningRawValue(current);
                var currentDisplay = FormatDatabaseTuningDisplayValue(db, car.CarId, current, map);
                var row = new DatabaseTuningRow(
                    "Profile0_Career_Garage",
                    map.ColumnName,
                    "Parts - Required Support",
                    GetDatabaseTuningDisplayName(map.ColumnName, map),
                    "Required support part added so selected custom parts load safely.",
                    currentDisplay,
                    currentRaw,
                    currentDisplay,
                    currentRaw,
                    "part",
                    map.TableName);
                row.NewValue = supportPartId.ToString(CultureInfo.InvariantCulture);
                row.Enabled = true;
                safeInputs.Add(row);
            }

            var note = GetDatabaseTuningDisplayName(map.ColumnName, map) + " " + supportPartId.ToString(CultureInfo.InvariantCulture);
            if (autoSupportNotes != null && !autoSupportNotes.Contains(note))
                autoSupportNotes.Add(note);
        }

        private void EnsureDatabaseTuningSupportPart(RemoteDatabase db, CarEditorRow car, List<DatabaseTuningRow> safeInputs, HashSet<string> explicitKeys, DatabaseTuningPartDependency requirement, List<string> autoSupportNotes)
        {
            var parentRow = safeInputs.FirstOrDefault(row =>
                string.Equals(row.TableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase) &&
                string.Equals(row.ColumnName, requirement.ParentColumn, StringComparison.OrdinalIgnoreCase));
            var parentExplicit = parentRow != null && explicitKeys.Contains(parentRow.Key);

            long parentPartId = 0;
            if (parentRow != null)
                parentPartId = ParseDatabaseTuningPartId(parentRow);
            else
                parentPartId = ToLong(QueryDatabaseTuningCell(db, "Profile0_Career_Garage", requirement.ParentColumn, car.CarId, false));

            if (DatabaseTuningParentMatches(db, requirement.ParentTable, requirement.ParentProperty, parentPartId, requirement.RequiredValue))
                return;

            if (parentExplicit)
            {
                throw new InvalidOperationException(requirement.SourceDisplayName + " requires " + MakeReadableIdentifier(requirement.ParentColumn) +
                    " support value " + requirement.RequiredValue.ToString(CultureInfo.InvariantCulture) + ", but the selected " +
                    MakeReadableIdentifier(requirement.ParentColumn) + " does not match.");
            }

            var supportPartId = FindDatabaseTuningSupportPart(db, requirement.ParentTable, requirement.ParentProperty, requirement.RequiredValue, car.CarId);
            if (!supportPartId.HasValue)
            {
                supportPartId = CreateDatabaseTuningClonedSupportPart(db, requirement.ParentTable, requirement.ParentProperty, requirement.RequiredValue, car.CarId, autoSupportNotes);
                if (!supportPartId.HasValue)
                {
                    throw new InvalidOperationException(requirement.SourceDisplayName + " requires " + MakeReadableIdentifier(requirement.ParentColumn) +
                        " support value " + requirement.RequiredValue.ToString(CultureInfo.InvariantCulture) + ", but Luna could not find a safe support part.");
                }
            }

            if (parentRow == null)
            {
                parentRow = CreateDatabaseTuningSupportRow(db, car, requirement, supportPartId.Value);
                safeInputs.Add(parentRow);
            }
            else
            {
                parentRow.NewValue = supportPartId.Value.ToString(CultureInfo.InvariantCulture);
                parentRow.Enabled = true;
            }

            var note = MakeReadableIdentifier(requirement.ParentColumn) + " " + supportPartId.Value.ToString(CultureInfo.InvariantCulture);
            if (autoSupportNotes != null && !autoSupportNotes.Contains(note))
                autoSupportNotes.Add(note);
        }

        private DatabaseTuningRow CreateDatabaseTuningSupportRow(RemoteDatabase db, CarEditorRow car, DatabaseTuningPartDependency requirement, long supportPartId)
        {
            var map = new DatabaseTuningPartMap(requirement.ParentColumn, requirement.ParentTable, "Required Support");
            var current = QueryDatabaseTuningCell(db, "Profile0_Career_Garage", requirement.ParentColumn, car.CarId, false);
            var currentRaw = FormatDatabaseTuningRawValue(current);
            var currentDisplay = FormatDatabaseTuningDisplayValue(db, car.CarId, current, map);
            var row = new DatabaseTuningRow(
                "Profile0_Career_Garage",
                requirement.ParentColumn,
                "Parts - Required Support",
                GetDatabaseTuningDisplayName(requirement.ParentColumn, map),
                "Required support part added so selected custom parts load safely.",
                currentDisplay,
                currentRaw,
                currentDisplay,
                currentRaw,
                "part",
                requirement.ParentTable);
            row.NewValue = supportPartId.ToString(CultureInfo.InvariantCulture);
            row.Enabled = true;
            return row;
        }

        private static bool IsDatabaseTuningPartRow(DatabaseTuningRow row)
        {
            return row != null &&
                string.Equals(row.ValueType, "part", StringComparison.OrdinalIgnoreCase) &&
                !string.IsNullOrWhiteSpace(row.PartTableName);
        }

        private static long ParseDatabaseTuningPartId(DatabaseTuningRow row)
        {
            var raw = (row == null ? string.Empty : row.NewValue ?? string.Empty).Trim();
            long parsed;
            if (raw.Length == 0 || !long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) || parsed <= 0)
                throw new InvalidOperationException((row == null ? "Part" : row.DisplayName) + " must use a valid positive part ID.");
            return parsed;
        }

        private DatabaseTuningPartDependency ResolveDatabaseTuningPartDependency(RemoteDatabase db, DatabaseTuningRow row, DatabaseTuningPartRecord part, int carId)
        {
            if (row == null || part == null)
                return null;
            if (string.Equals(row.PartTableName, "List_Wheels", StringComparison.OrdinalIgnoreCase))
                return null;

            var ordinalColumn = part.FindColumn("Ordinal");
            if (IsDatabaseTuningParentInstallColumn(row.ColumnName))
            {
                var ordinal = string.IsNullOrEmpty(ordinalColumn) ? 0 : part.GetLong(ordinalColumn);
                if (ordinal > 0 && ordinal != carId)
                    return DatabaseTuningPartDependency.ForOrdinal(row.DisplayName, ordinal);
                return null;
            }

            var engineColumn = part.FindColumn("EngineID");
            if (!string.IsNullOrEmpty(engineColumn))
                return CreateDatabaseTuningParentDependency(db, row, part, engineColumn, "Engine", "List_UpgradeEngine", "EngineID");

            var drivetrainColumn = part.FindColumn("DrivetrainID", "DrivetrainId");
            if (!string.IsNullOrEmpty(drivetrainColumn))
                return CreateDatabaseTuningParentDependency(db, row, part, drivetrainColumn, "Drivetrain", "List_UpgradeDrivetrain", "DrivetrainID");

            var carBodyColumn = part.FindColumn("CarBodyID", "CarBodyId", "CarbodyId");
            if (!string.IsNullOrEmpty(carBodyColumn))
                return CreateDatabaseTuningParentDependency(db, row, part, carBodyColumn, "CarBody", "List_UpgradeCarBody", "CarBodyID");

            var motorColumn = part.FindColumn("MotorID");
            if (!string.IsNullOrEmpty(motorColumn))
                return CreateDatabaseTuningParentDependency(db, row, part, motorColumn, "Motor", "List_UpgradeMotor", "MotorID");

            if (!string.IsNullOrEmpty(ordinalColumn) && !IsDatabaseTuningParentInstallColumn(row.ColumnName))
                return DatabaseTuningPartDependency.ForOrdinal(row.DisplayName, part.GetLong(ordinalColumn));

            return null;
        }

        private DatabaseTuningPartDependency CreateDatabaseTuningParentDependency(RemoteDatabase db, DatabaseTuningRow row, DatabaseTuningPartRecord part, string dependencyColumn, string parentColumn, string parentTable, string parentProperty)
        {
            var requiredValue = part.GetLong(dependencyColumn);
            if (requiredValue <= 0)
                return null;

            var resolvedParentProperty = ResolveExistingColumn(db, parentTable, parentProperty);
            if (string.IsNullOrEmpty(resolvedParentProperty))
            {
                throw new InvalidOperationException(row.DisplayName + " requires " + MakeReadableIdentifier(parentColumn) +
                    " support, but " + parentTable + "." + parentProperty + " was not found.");
            }

            return DatabaseTuningPartDependency.ForParent(row.DisplayName, dependencyColumn, requiredValue, parentColumn, parentTable, resolvedParentProperty);
        }

        private static bool IsDatabaseTuningParentInstallColumn(string columnName)
        {
            return string.Equals(columnName, "Engine", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "Drivetrain", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "CarBody", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "Motor", StringComparison.OrdinalIgnoreCase);
        }

        private bool DatabaseTuningParentMatches(RemoteDatabase db, string parentTable, string parentProperty, long parentPartId, long requiredValue)
        {
            if (parentPartId <= 0)
                return false;
            var parent = QueryDatabaseTuningPartRecord(db, parentTable, parentPartId);
            return parent != null && parent.GetLong(parentProperty) == requiredValue;
        }

        private long? FindDatabaseTuningSupportPart(RemoteDatabase db, string parentTable, string parentProperty, long requiredValue, int carId)
        {
            return FindDatabaseTuningPartByProperty(db, parentTable, parentProperty, requiredValue, carId, true);
        }

        private long? CreateDatabaseTuningClonedSupportPart(RemoteDatabase db, string parentTable, string parentProperty, long requiredValue, int carId, List<string> autoSupportNotes)
        {
            if (!IsDatabaseTuningCloneableSupportTable(parentTable) ||
                !db.TableExists(parentTable) ||
                !db.ColumnExists(parentTable, "Ordinal"))
                return null;

            var idColumn = ResolveDatabaseTuningPartIdColumn(db, parentTable);
            var propertyColumn = ResolveExistingColumn(db, parentTable, parentProperty);
            if (string.IsNullOrEmpty(idColumn) || string.IsNullOrEmpty(propertyColumn))
                return null;

            var existing = FindDatabaseTuningPartByProperty(db, parentTable, propertyColumn, requiredValue, carId, true);
            if (existing.HasValue)
                return existing.Value;

            var source = db.Query("SELECT * FROM " + EscapeIdentifierForSql(parentTable) +
                " WHERE " + EscapeIdentifierForSql(propertyColumn) + " = " + requiredValue.ToString(CultureInfo.InvariantCulture) +
                " AND " + EscapeIdentifierForSql(idColumn) + " > 0" +
                " ORDER BY " +
                (db.ColumnExists(parentTable, "IsStock") ? "[IsStock] DESC, " : string.Empty) +
                (db.ColumnExists(parentTable, "Level") ? "[Level], " : string.Empty) +
                EscapeIdentifierForSql(idColumn) +
                " LIMIT 1;");
            if (source.Rows.Count == 0)
            {
                var garageColumn = GetDatabaseTuningParentGarageColumn(parentTable);
                var currentPartId = string.IsNullOrEmpty(garageColumn) || !db.ColumnExists("Profile0_Career_Garage", garageColumn)
                    ? 0
                    : (db.QueryScalarLong("SELECT " + EscapeIdentifierForSql(garageColumn) + " FROM Profile0_Career_Garage WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture) + " LIMIT 1;") ?? 0);
                if (currentPartId > 0)
                {
                    source = db.Query("SELECT * FROM " + EscapeIdentifierForSql(parentTable) +
                        " WHERE " + EscapeIdentifierForSql(idColumn) + " = " + currentPartId.ToString(CultureInfo.InvariantCulture) +
                        " LIMIT 1;");
                }
            }
            if (source.Rows.Count == 0)
                return null;

            var newId = QueryDatabaseTuningNextPartId(db, parentTable, idColumn);
            if (newId <= 0)
                return null;

            var columns = source.Columns;
            var values = source.Rows[0];
            var insertColumns = new List<string>();
            var insertValues = new List<string>();
            for (var i = 0; i < columns.Count; i++)
            {
                var column = columns[i];
                insertColumns.Add(EscapeIdentifierForSql(column));
                if (string.Equals(column, idColumn, StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(newId.ToString(CultureInfo.InvariantCulture));
                else if (string.Equals(column, "Ordinal", StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(carId.ToString(CultureInfo.InvariantCulture));
                else if (string.Equals(column, propertyColumn, StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(requiredValue.ToString(CultureInfo.InvariantCulture));
                else if (i < values.Count)
                    insertValues.Add(ToDatabaseTuningSqlLiteral(values[i]));
                else
                    insertValues.Add("NULL");
            }

            var tableSql = EscapeIdentifierForSql(parentTable);
            var backupName = "_backup_DatabaseTuning_" + parentTable;
            db.Execute("CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
            db.Execute("INSERT INTO " + tableSql + " (" + string.Join(", ", insertColumns.ToArray()) + ") VALUES (" + string.Join(", ", insertValues.ToArray()) + ");");

            var note = MakeReadableIdentifier(parentTable.Replace("List_Upgrade", string.Empty)) + " support clone " + newId.ToString(CultureInfo.InvariantCulture);
            if (autoSupportNotes != null && !autoSupportNotes.Contains(note))
                autoSupportNotes.Add(note);
            Log("Database Tuning created safe local support part " + newId.ToString(CultureInfo.InvariantCulture) + " in " + parentTable + " for selected car " + carId.ToString(CultureInfo.InvariantCulture) + ".");
            return newId;
        }

        private long? CreateDatabaseTuningClonedDependentPart(RemoteDatabase db, string tableName, string dependencyColumn, long requiredValue, string garageColumn, long currentPartId, int carId, List<string> autoSupportNotes)
        {
            if (!db.TableExists(tableName) || string.IsNullOrWhiteSpace(dependencyColumn) || !db.ColumnExists(tableName, dependencyColumn))
                return null;

            var idColumn = ResolveDatabaseTuningPartIdColumn(db, tableName);
            if (string.IsNullOrEmpty(idColumn))
                return null;

            var source = db.Query("SELECT * FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(dependencyColumn) + " = " + requiredValue.ToString(CultureInfo.InvariantCulture) +
                " AND " + EscapeIdentifierForSql(idColumn) + " > 0" +
                " ORDER BY " +
                (db.ColumnExists(tableName, "IsStock") ? "[IsStock] DESC, " : string.Empty) +
                (db.ColumnExists(tableName, "Level") ? "[Level], " : string.Empty) +
                EscapeIdentifierForSql(idColumn) +
                " LIMIT 1;");
            if (source.Rows.Count == 0 && currentPartId > 0)
            {
                source = db.Query("SELECT * FROM " + EscapeIdentifierForSql(tableName) +
                    " WHERE " + EscapeIdentifierForSql(idColumn) + " = " + currentPartId.ToString(CultureInfo.InvariantCulture) +
                    " LIMIT 1;");
            }
            if (source.Rows.Count == 0)
                return null;

            var newId = QueryDatabaseTuningNextPartId(db, tableName, idColumn);
            if (newId <= 0)
                return null;

            var columns = source.Columns;
            var values = source.Rows[0];
            var insertColumns = new List<string>();
            var insertValues = new List<string>();
            for (var i = 0; i < columns.Count; i++)
            {
                var column = columns[i];
                insertColumns.Add(EscapeIdentifierForSql(column));
                if (string.Equals(column, idColumn, StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(newId.ToString(CultureInfo.InvariantCulture));
                else if (string.Equals(column, "Ordinal", StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(carId.ToString(CultureInfo.InvariantCulture));
                else if (string.Equals(column, dependencyColumn, StringComparison.OrdinalIgnoreCase))
                    insertValues.Add(requiredValue.ToString(CultureInfo.InvariantCulture));
                else if (i < values.Count)
                    insertValues.Add(ToDatabaseTuningSqlLiteral(values[i]));
                else
                    insertValues.Add("NULL");
            }

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupName = GetDatabaseTuningBackupName(tableName);
            db.Execute("CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
            db.Execute("INSERT INTO " + tableSql + " (" + string.Join(", ", insertColumns.ToArray()) + ") VALUES (" + string.Join(", ", insertValues.ToArray()) + ");");

            var note = MakeReadableIdentifier(garageColumn) + " support clone " + newId.ToString(CultureInfo.InvariantCulture);
            if (autoSupportNotes != null && !autoSupportNotes.Contains(note))
                autoSupportNotes.Add(note);
            Log("Database Tuning created safe dependent part " + newId.ToString(CultureInfo.InvariantCulture) + " in " + tableName + " for selected car " + carId.ToString(CultureInfo.InvariantCulture) + ".");
            return newId;
        }

        private static bool IsDatabaseTuningCloneableSupportTable(string tableName)
        {
            return string.Equals(tableName, "List_UpgradeEngine", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "List_UpgradeDrivetrain", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "List_UpgradeCarBody", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(tableName, "List_UpgradeMotor", StringComparison.OrdinalIgnoreCase);
        }

        private static string GetDatabaseTuningParentGarageColumn(string parentTable)
        {
            if (string.Equals(parentTable, "List_UpgradeEngine", StringComparison.OrdinalIgnoreCase))
                return "Engine";
            if (string.Equals(parentTable, "List_UpgradeDrivetrain", StringComparison.OrdinalIgnoreCase))
                return "Drivetrain";
            if (string.Equals(parentTable, "List_UpgradeCarBody", StringComparison.OrdinalIgnoreCase))
                return "CarBody";
            if (string.Equals(parentTable, "List_UpgradeMotor", StringComparison.OrdinalIgnoreCase))
                return "Motor";
            return string.Empty;
        }

        private long QueryDatabaseTuningNextPartId(RemoteDatabase db, string tableName, string idColumn)
        {
            var next = db.QueryScalarLong("SELECT COALESCE(MAX(" + EscapeIdentifierForSql(idColumn) + "), 0) + 1 FROM " + EscapeIdentifierForSql(tableName) + ";") ?? 0;
            while (next > 0)
            {
                var exists = db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(tableName) +
                    " WHERE " + EscapeIdentifierForSql(idColumn) + " = " + next.ToString(CultureInfo.InvariantCulture) + ";") ?? 0;
                if (exists == 0)
                    return next;
                next++;
            }
            return 0;
        }

        private static string ToDatabaseTuningSqlLiteral(object value)
        {
            if (value == null || value == DBNull.Value)
                return "NULL";
            if (value is byte[])
                return "NULL";
            if (value is bool)
                return (bool)value ? "1" : "0";
            var formattable = value as IFormattable;
            if (value is sbyte || value is byte || value is short || value is ushort || value is int || value is uint ||
                value is long || value is ulong || value is float || value is double || value is decimal)
                return formattable.ToString(null, CultureInfo.InvariantCulture);
            return ToSqlText(Convert.ToString(value, CultureInfo.InvariantCulture));
        }

        private long? FindDatabaseTuningPartByProperty(RemoteDatabase db, string tableName, string propertyColumn, long requiredValue, int carId)
        {
            return FindDatabaseTuningPartByProperty(db, tableName, propertyColumn, requiredValue, carId, false);
        }

        private long? FindDatabaseTuningPartByProperty(RemoteDatabase db, string tableName, string propertyColumn, long requiredValue, int carId, bool requireSelectedCarOrdinal)
        {
            if (!db.TableExists(tableName))
                return null;
            var idColumn = ResolveDatabaseTuningPartIdColumn(db, tableName);
            var resolvedPropertyColumn = ResolveExistingColumn(db, tableName, propertyColumn);
            if (string.IsNullOrEmpty(idColumn) || string.IsNullOrEmpty(resolvedPropertyColumn))
                return null;

            var order = new List<string>();
            if (db.ColumnExists(tableName, "Ordinal"))
                order.Add("CASE WHEN [Ordinal] = " + carId.ToString(CultureInfo.InvariantCulture) + " THEN 0 ELSE 1 END");
            if (db.ColumnExists(tableName, "IsStock"))
                order.Add("[IsStock] DESC");
            if (db.ColumnExists(tableName, "Level"))
                order.Add("[Level]");
            order.Add(EscapeIdentifierForSql(idColumn));

            var sql =
                "SELECT " + EscapeIdentifierForSql(idColumn) +
                " FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(resolvedPropertyColumn) + " = " + requiredValue.ToString(CultureInfo.InvariantCulture) +
                " AND " + EscapeIdentifierForSql(idColumn) + " > 0" +
                (requireSelectedCarOrdinal && db.ColumnExists(tableName, "Ordinal") ? " AND [Ordinal] = " + carId.ToString(CultureInfo.InvariantCulture) : string.Empty) +
                " ORDER BY " + string.Join(", ", order.ToArray()) +
                " LIMIT 1;";
            return db.QueryScalarLong(sql);
        }

        private long? FindDatabaseTuningOrdinalSupportPart(RemoteDatabase db, string tableName, int carId)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "Ordinal"))
                return null;

            var idColumn = ResolveDatabaseTuningPartIdColumn(db, tableName);
            if (string.IsNullOrEmpty(idColumn))
                return null;

            var order = new List<string>();
            if (db.ColumnExists(tableName, "IsStock"))
                order.Add("[IsStock] DESC");
            if (db.ColumnExists(tableName, "Level"))
                order.Add("[Level]");
            order.Add(EscapeIdentifierForSql(idColumn));

            return db.QueryScalarLong(
                "SELECT " + EscapeIdentifierForSql(idColumn) +
                " FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE [Ordinal] = " + carId.ToString(CultureInfo.InvariantCulture) +
                " AND " + EscapeIdentifierForSql(idColumn) + " > 0" +
                " ORDER BY " + string.Join(", ", order.ToArray()) +
                " LIMIT 1;");
        }

        private DatabaseTuningPartRecord QueryDatabaseTuningPartRecord(RemoteDatabase db, string tableName, long partId)
        {
            if (string.IsNullOrWhiteSpace(tableName) || !db.TableExists(tableName) || partId <= 0)
                return null;
            var idColumn = ResolveDatabaseTuningPartIdColumn(db, tableName);
            if (string.IsNullOrEmpty(idColumn))
                return null;

            var result = db.Query("SELECT * FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(idColumn) + " = " + partId.ToString(CultureInfo.InvariantCulture) +
                " LIMIT 1;");
            if (result.Rows.Count == 0)
                return null;
            return new DatabaseTuningPartRecord(result.Columns, result.Rows[0]);
        }

        private static string ResolveExistingColumn(RemoteDatabase db, string tableName, params string[] candidates)
        {
            foreach (var candidate in candidates ?? new string[0])
            {
                if (db.ColumnExists(tableName, candidate))
                    return candidate;
            }
            return string.Empty;
        }

        private void RestoreDatabaseTuningSelectedCar()
        {
            var car = GetSelectedDatabaseTuningCar();
            var rows = CaptureDatabaseTuningInputs(false);
            if (rows.Count == 0)
                throw new InvalidOperationException("Select a car and load Database Tuning rows first.");

            Interlocked.Increment(ref _databaseTuningLoadGeneration);
            var restored = 0;
            lock (_databaseTuningDbLock)
            {
                var db = RequireDatabase();
                RunDatabaseTuningAtomic(db, "database_tuning_restore", delegate
                {
                    foreach (var group in rows.GroupBy(row => row.TableName + "\n" + BuildDatabaseTuningRowWhere(row, car.CarId), StringComparer.OrdinalIgnoreCase))
                        restored += RestoreDatabaseTuningRows(db, car.CarId, group.ToList());
                    if (restored == 0)
                        throw new InvalidOperationException("No Database Tuning backup rows were found for the selected car yet.");
                });
            }
            if (restored == 0)
                throw new InvalidOperationException("No Database Tuning backup rows were found for the selected car yet.");

            Log("Database Tuning restored " + restored.ToString(CultureInfo.InvariantCulture) + " field(s) for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ".");
            LoadDatabaseTuningFields(car);
            ShowInfo("Database Tuning restored the selected car.");
        }

        private int RestoreDatabaseTuningTable(RemoteDatabase db, string tableName, string backupName, int carId, IEnumerable<string> columns)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName) || !db.ColumnExists(backupName, "_rowid_"))
                return 0;
            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var carWhere = BuildDatabaseTuningCarWhere(tableName, carId);
            var restored = 0;
            foreach (var column in (columns ?? new string[0]).Distinct(StringComparer.OrdinalIgnoreCase))
            {
                if (!db.ColumnExists(tableName, column) || !db.ColumnExists(backupName, column))
                    continue;
                var columnSql = EscapeIdentifierForSql(column);
                db.Execute("UPDATE " + tableSql + " SET " + columnSql + " = (SELECT " + backupSql + "." + columnSql + " FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid)" + carWhere.Replace(" WHERE ", " AND ") + ";");
                restored++;
            }
            return restored;
        }

        private int RestoreDatabaseTuningRows(RemoteDatabase db, int carId, List<DatabaseTuningRow> rows)
        {
            var first = (rows ?? new List<DatabaseTuningRow>()).FirstOrDefault();
            if (first == null)
                return 0;

            var tableName = first.TableName;
            var backupName = GetDatabaseTuningBackupName(tableName);
            if (!db.TableExists(tableName) || !db.TableExists(backupName) || !db.ColumnExists(backupName, "_rowid_"))
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var where = BuildDatabaseTuningRowWhere(first, carId);
            var restored = 0;
            foreach (var column in rows.Select(row => row.ColumnName).Distinct(StringComparer.OrdinalIgnoreCase))
            {
                if (!db.ColumnExists(tableName, column) || !db.ColumnExists(backupName, column))
                    continue;

                var columnSql = EscapeIdentifierForSql(column);
                db.Execute("UPDATE " + tableSql + " SET " + columnSql + " = (SELECT " + backupSql + "." + columnSql + " FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid)" + where.Replace(" WHERE ", " AND ") + ";");
                restored++;
            }
            return restored;
        }

        private List<DatabaseTuningRow> CaptureDatabaseTuningInputs(bool onlyChanged)
        {
            if (InvokeRequired)
                return (List<DatabaseTuningRow>)Invoke(new Func<bool, List<DatabaseTuningRow>>(CaptureDatabaseTuningInputs), onlyChanged);

            SyncDatabaseTuningGridEdits();
            var rows = _databaseTuningRows ?? new List<DatabaseTuningRow>();
            if (!onlyChanged)
                return rows.ToList();
            return rows.Where(row => row.Enabled || !string.Equals((row.NewValue ?? string.Empty).Trim(), (row.CurrentRaw ?? string.Empty).Trim(), StringComparison.OrdinalIgnoreCase)).ToList();
        }

        private void SaveDatabaseTuningConfig()
        {
            try
            {
                var car = GetSelectedDatabaseTuningCar();
                var rows = CaptureDatabaseTuningInputs(false);
                if (rows.Count == 0)
                    throw new InvalidOperationException("Load Database Tuning rows for the selected car first.");

                var presetDir = Path.Combine(_resultsDir, "database_tuning_configs", car.CarId.ToString(CultureInfo.InvariantCulture));
                Directory.CreateDirectory(presetDir);
                using (var dialog = new SaveFileDialog())
                {
                    dialog.Title = "Save Database Tuning config";
                    dialog.InitialDirectory = presetDir;
                    dialog.Filter = "Luna database tuning config (*.txt)|*.txt|All files (*.*)|*.*";
                    dialog.FileName = MakeDatabaseTuningConfigFileName(car);
                    PrepareDialogForLanguage(dialog);
                    if (dialog.ShowDialog(this) != DialogResult.OK)
                        return;

                    var lines = new List<string>();
                    lines.Add("# Forza Horizon 6 Luna Database Tuning config");
                    lines.Add("CarId=" + car.CarId.ToString(CultureInfo.InvariantCulture));
                    lines.Add("CarName=" + EncodeDatabaseTuningPresetValue(FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model)));
                    lines.Add("SavedUtc=" + DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ssZ", CultureInfo.InvariantCulture));
                    lines.Add("# RowKey|ValueBase64");
                    foreach (var row in rows.OrderBy(row => row.TableName, StringComparer.OrdinalIgnoreCase).ThenBy(row => row.ColumnName, StringComparer.OrdinalIgnoreCase))
                    {
                        var value = string.IsNullOrWhiteSpace(row.NewValue) ? row.CurrentRaw : row.NewValue;
                        lines.Add(row.Key + "|" + EncodeDatabaseTuningPresetValue(value ?? string.Empty));
                    }

                    File.WriteAllLines(dialog.FileName, lines.ToArray(), Encoding.UTF8);
                    Log("Database Tuning config saved: " + dialog.FileName + ".");
                    ShowInfo("Database Tuning config saved for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ".");
                }
            }
            catch (Exception ex)
            {
                Log("Database Tuning config save failed: " + ex.Message);
                ShowInfo(ex.Message);
            }
        }

        private void LoadDatabaseTuningConfig()
        {
            try
            {
                var presetDir = Path.Combine(_resultsDir, "database_tuning_configs");
                Directory.CreateDirectory(presetDir);
                using (var dialog = new OpenFileDialog())
                {
                    dialog.Title = "Load Database Tuning config";
                    dialog.InitialDirectory = presetDir;
                    dialog.Filter = "Luna database tuning config (*.txt)|*.txt|All files (*.*)|*.*";
                    PrepareDialogForLanguage(dialog);
                    if (dialog.ShowDialog(this) != DialogResult.OK)
                        return;

                    LoadDatabaseTuningConfigFile(dialog.FileName);
                }
            }
            catch (Exception ex)
            {
                Log("Database Tuning config load failed: " + ex.Message);
                ShowInfo(ex.Message);
            }
        }

        private void LoadDatabaseTuningConfigFile(string fileName)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { LoadDatabaseTuningConfigFile(fileName); }));
                return;
            }

            var config = ParseDatabaseTuningConfigFile(fileName);
            if (config.CarId <= 0)
                throw new InvalidOperationException("That Database Tuning config is missing a linked car ID.");

            if (!IsDatabaseTuningCarOwned(config.CarId))
                throw new InvalidOperationException("This config is linked to CarId " + config.CarId.ToString(CultureInfo.InvariantCulture) + ", but that car is not owned in the loaded garage.");

            var selected = GetSelectedDatabaseTuningCar();
            if (selected.CarId != config.CarId)
                throw new InvalidOperationException("This config is linked to " + (string.IsNullOrWhiteSpace(config.CarName) ? "CarId " + config.CarId.ToString(CultureInfo.InvariantCulture) : config.CarName) + "." + Environment.NewLine + Environment.NewLine +
                    "Select that owned car in Database Tuning before loading this config.");

            if (_databaseTuningRows == null || _databaseTuningRows.Count == 0)
                throw new InvalidOperationException("Load the selected car's Database Tuning rows before loading a config.");

            SyncDatabaseTuningGridEdits();
            var loaded = 0;
            foreach (var row in _databaseTuningRows)
            {
                string value;
                if (!config.Values.TryGetValue(row.Key, out value))
                    continue;
                row.NewValue = value ?? string.Empty;
                row.Enabled = !string.Equals((row.NewValue ?? string.Empty).Trim(), (row.CurrentRaw ?? string.Empty).Trim(), StringComparison.OrdinalIgnoreCase);
                loaded++;
            }

            if (loaded == 0)
                throw new InvalidOperationException("That config did not contain rows that match this Database Tuning page.");

            ApplyDatabaseTuningFieldFilter();
            Log("Database Tuning config loaded: " + Path.GetFileName(fileName) + " (" + loaded.ToString(CultureInfo.InvariantCulture) + " row(s)). Press Apply Selected to use it.");
            ShowInfo("Database Tuning config loaded." + Environment.NewLine + Environment.NewLine + "Review the checked rows, then press Apply Selected.");
        }

        private DatabaseTuningConfig ParseDatabaseTuningConfigFile(string fileName)
        {
            var config = new DatabaseTuningConfig();
            foreach (var line in File.ReadAllLines(fileName, Encoding.UTF8))
            {
                var trimmed = (line ?? string.Empty).Trim();
                if (trimmed.Length == 0 || trimmed.StartsWith("#", StringComparison.Ordinal))
                    continue;

                if (trimmed.StartsWith("CarId=", StringComparison.OrdinalIgnoreCase))
                {
                    int carId;
                    if (int.TryParse(trimmed.Substring("CarId=".Length).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out carId))
                        config.CarId = carId;
                    continue;
                }
                if (trimmed.StartsWith("CarName=", StringComparison.OrdinalIgnoreCase))
                {
                    config.CarName = DecodeDatabaseTuningPresetValue(trimmed.Substring("CarName=".Length).Trim());
                    continue;
                }

                var parts = trimmed.Split(new[] { '|' }, 3);
                if (parts.Length == 2)
                {
                    var key = parts[0].Trim();
                    if (key.Length > 0)
                        config.Values[key] = DecodeDatabaseTuningPresetValue(parts[1].Trim());
                    continue;
                }
                if (parts.Length != 3)
                    continue;
                var tableName = parts[0].Trim();
                var columnName = parts[1].Trim();
                if (tableName.Length > 0 && columnName.Length > 0)
                    config.Values[tableName + "." + columnName] = DecodeDatabaseTuningPresetValue(parts[2].Trim());
            }
            return config;
        }

        private bool IsDatabaseTuningCarOwned(int carId)
        {
            if ((_databaseTuningGarageRows ?? new List<CarEditorRow>()).Any(car => car.CarId == carId))
                return true;

            var db = _database != null && _database.IsAlive ? _database : null;
            if (db == null || !db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                return false;

            var count = db.QueryScalarLong("SELECT count(*) FROM Profile0_Career_Garage WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture) + ";") ?? 0;
            return count > 0;
        }

        private static string EncodeDatabaseTuningPresetValue(string value)
        {
            return Convert.ToBase64String(Encoding.UTF8.GetBytes(value ?? string.Empty));
        }

        private static string DecodeDatabaseTuningPresetValue(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return string.Empty;
            try
            {
                return Encoding.UTF8.GetString(Convert.FromBase64String(value.Trim()));
            }
            catch
            {
                return value;
            }
        }

        private static string MakeDatabaseTuningConfigFileName(CarEditorRow car)
        {
            var name = FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model);
            foreach (var c in Path.GetInvalidFileNameChars())
                name = name.Replace(c, '_');
            name = string.Join(" ", name.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries));
            if (name.Length > 64)
                name = name.Substring(0, 64).Trim();
            return car.CarId.ToString(CultureInfo.InvariantCulture) + " - " + name + " - " + DateTime.Now.ToString("yyyyMMdd_HHmmss", CultureInfo.InvariantCulture) + ".txt";
        }

        private static string BuildDatabaseTuningSqlValue(DatabaseTuningRow row)
        {
            var raw = (row.NewValue ?? string.Empty).Trim();
            if (raw.Length == 0)
                return "NULL";
            if (string.Equals(row.ValueType, "part", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(row.ValueType, "int", StringComparison.OrdinalIgnoreCase))
            {
                long parsed;
                if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
                    throw new InvalidOperationException(row.DisplayName + " must be a whole number.");
                return parsed.ToString(CultureInfo.InvariantCulture);
            }

            double value;
            if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || double.IsNaN(value) || double.IsInfinity(value))
                throw new InvalidOperationException(row.DisplayName + " must be a finite number.");
            return value.ToString("0.########", CultureInfo.InvariantCulture);
        }

        private static string BuildDatabaseTuningCarWhere(string tableName, int carId)
        {
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase))
                return " WHERE [Id] = " + carId.ToString(CultureInfo.InvariantCulture);
            return " WHERE [CarId] = " + carId.ToString(CultureInfo.InvariantCulture);
        }

        private static string BuildDatabaseTuningRowWhere(DatabaseTuningRow row, int carId)
        {
            if (row != null && !string.IsNullOrWhiteSpace(row.TargetKeyColumn) && row.TargetKeyValue > 0)
                return " WHERE " + EscapeIdentifierForSql(row.TargetKeyColumn) + " = " + row.TargetKeyValue.ToString(CultureInfo.InvariantCulture);
            return BuildDatabaseTuningCarWhere(row == null ? string.Empty : row.TableName, carId);
        }

        private static string GetDatabaseTuningBackupName(string tableName)
        {
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase))
                return "_backup_DatabaseTuning_DataCar";
            if (string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase))
                return "_backup_DatabaseTuning_ProfileGarage";

            var safe = new string((tableName ?? string.Empty).Select(c => char.IsLetterOrDigit(c) || c == '_' ? c : '_').ToArray());
            if (safe.Length == 0)
                safe = "Table";
            return "_backup_DatabaseTuning_" + safe;
        }

        private void ShowSelectedDatabaseTuningValueOrPartPicker()
        {
            var item = GetSelectedDatabaseTuningGridRow();
            if (item == null)
            {
                ShowInfo("Select a Database Tuning row first.");
                return;
            }

            if (IsDatabaseTuningPartRow(item))
                ShowSelectedDatabaseTuningPartPicker();
            else
                ShowSelectedDatabaseTuningValuePicker(item);
        }

        private DatabaseTuningRow GetSelectedDatabaseTuningGridRow()
        {
            if (_databaseTuningGrid == null)
                return null;
            DataGridViewRow row = null;
            if (_databaseTuningGrid.CurrentRow != null && !_databaseTuningGrid.CurrentRow.IsNewRow)
                row = _databaseTuningGrid.CurrentRow;
            else if (_databaseTuningGrid.SelectedRows.Count > 0)
                row = _databaseTuningGrid.SelectedRows[0];
            return row == null ? null : row.Tag as DatabaseTuningRow;
        }

        private void SetSelectedDatabaseTuningGridRowValue(DatabaseTuningRow item, string value)
        {
            if (item == null)
                return;

            item.NewValue = value ?? string.Empty;
            item.Enabled = true;
            if (_databaseTuningGrid == null)
                return;

            foreach (DataGridViewRow row in _databaseTuningGrid.Rows)
            {
                if (!ReferenceEquals(row.Tag, item))
                    continue;
                row.Cells["NewValue"].Value = item.NewValue;
                row.Cells["Apply"].Value = true;
                break;
            }
        }

        private bool TryEnterDatabaseTuningDbLock(string busyMessage)
        {
            if (Monitor.TryEnter(_databaseTuningDbLock, 750))
                return true;

            ShowInfo(string.IsNullOrWhiteSpace(busyMessage)
                ? "Database Tuning is busy. Try again in a moment."
                : busyMessage);
            return false;
        }

        private void ShowSelectedDatabaseTuningValuePicker(DatabaseTuningRow tuningRow)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ShowSelectedDatabaseTuningValuePicker(tuningRow); }));
                return;
            }

            if (tuningRow == null || IsDatabaseTuningPartRow(tuningRow))
                return;

            RemoteDatabase db;
            List<DatabaseTuningValueOption> options;
            if (!TryEnterDatabaseTuningDbLock("Database Tuning is busy applying, restoring, or loading. Try again in a moment."))
                return;
            try
            {
                db = _database != null && _database.IsAlive ? _database : null;
                if (db == null)
                {
                    ShowInfo("Attach and load the database before picking values.");
                    return;
                }

                options = QueryDatabaseTuningValueOptions(db, tuningRow);
            }
            finally
            {
                Monitor.Exit(_databaseTuningDbLock);
            }

            var customRuleText = string.Equals(tuningRow.ValueType, "int", StringComparison.OrdinalIgnoreCase)
                ? "Allowed custom value: any positive or negative whole number."
                : "Allowed custom value: any positive or negative finite number.";

            using (var dialog = new Form())
            {
                dialog.Text = "Pick Value";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(760, 560);

                var title = new Label();
                title.Text = tuningRow.DisplayName;
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                title.Location = new Point(18, 14);
                title.Size = new Size(724, 28);
                dialog.Controls.Add(title);

                var meta = new Label();
                meta.Text = BuildDatabaseTuningValueSourceLabel(tuningRow);
                meta.Font = new Font("Segoe UI", 8.5F);
                meta.ForeColor = TextMuted;
                meta.BackColor = AppBackground;
                meta.Location = new Point(18, 42);
                meta.Size = new Size(724, 22);
                dialog.Controls.Add(meta);

                var rule = new Label();
                rule.Text = customRuleText;
                rule.Font = new Font("Segoe UI Semibold", 9F);
                rule.ForeColor = AccentBlue;
                rule.BackColor = AppBackground;
                rule.Location = new Point(18, 68);
                rule.Size = new Size(724, 24);
                dialog.Controls.Add(rule);

                var current = new Label();
                current.Text = "Current: " + (string.IsNullOrWhiteSpace(tuningRow.CurrentRaw) ? "-" : tuningRow.CurrentRaw) +
                    "    Default: " + (string.IsNullOrWhiteSpace(tuningRow.DefaultRaw) ? "-" : tuningRow.DefaultRaw);
                current.Font = new Font("Segoe UI", 8.5F);
                current.ForeColor = TextMuted;
                current.BackColor = AppBackground;
                current.Location = new Point(18, 94);
                current.Size = new Size(724, 22);
                dialog.Controls.Add(current);

                var custom = new TextBox();
                custom.Location = new Point(18, 124);
                custom.Size = new Size(232, 28);
                custom.Text = string.IsNullOrWhiteSpace(tuningRow.NewValue) ? tuningRow.CurrentRaw : tuningRow.NewValue;
                StyleTextBox(custom);
                dialog.Controls.Add(custom);

                var useCustom = MakeButton("Use Custom", 262, 122, 116, 32);
                MakeAccentButton(useCustom, AccentBlue);
                dialog.Controls.Add(useCustom);

                var search = new TextBox();
                search.Location = new Point(394, 124);
                search.Size = new Size(348, 28);
                StyleTextBox(search);
                dialog.Controls.Add(search);

                var grid = BuildReadOnlyGrid();
                grid.Location = new Point(18, 166);
                grid.Size = new Size(724, 334);
                grid.Columns.Add("Value", "Existing Value");
                grid.Columns.Add("Uses", "Uses");
                grid.Columns.Add("State", "State");
                grid.Columns["Value"].FillWeight = 70F;
                grid.Columns["Uses"].Width = 90;
                grid.Columns["Uses"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Uses"].ToolTipText = "Click to see cars using this value.";
                grid.Columns["State"].Width = 160;
                grid.Columns["State"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                dialog.Controls.Add(grid);

                Action refresh = delegate
                {
                    var filter = search.Text ?? string.Empty;
                    grid.Rows.Clear();
                    foreach (var option in options
                        .Where(option => string.IsNullOrWhiteSpace(filter) || option.RawValue.IndexOf(filter, StringComparison.OrdinalIgnoreCase) >= 0)
                        .OrderByDescending(option => option.IsCurrent)
                        .ThenByDescending(option => option.IsDefault)
                        .ThenByDescending(option => option.UseCount)
                        .ThenBy(option => option.SortValue)
                        .Take(1000))
                    {
                        var state = option.IsCurrent ? "Current" : option.IsDefault ? "Default" : "Existing";
                        var rowIndex = grid.Rows.Add(option.RawValue, option.UseCount.ToString(CultureInfo.InvariantCulture), state);
                        var row = grid.Rows[rowIndex];
                        row.Tag = option;
                        if (option.IsCurrent)
                        {
                            row.DefaultCellStyle.BackColor = Color.FromArgb(24, 94, 64);
                            row.DefaultCellStyle.SelectionBackColor = Color.FromArgb(36, 137, 87);
                        }
                        else if (option.InRange)
                        {
                            row.DefaultCellStyle.BackColor = Color.FromArgb(104, 82, 20);
                            row.DefaultCellStyle.SelectionBackColor = Color.FromArgb(142, 108, 26);
                        }
                        else
                        {
                            row.DefaultCellStyle.BackColor = Color.FromArgb(66, 66, 72);
                            row.DefaultCellStyle.SelectionBackColor = Color.FromArgb(86, 86, 96);
                        }
                        row.DefaultCellStyle.ForeColor = TextPrimary;
                        row.DefaultCellStyle.SelectionForeColor = TextPrimary;
                        row.Cells["Uses"].Style.ForeColor = AccentBlue;
                        row.Cells["Uses"].ToolTipText = "Click to see cars using this value.";
                    }
                };

                Func<string, bool> acceptValue = delegate(string raw)
                {
                    raw = (raw ?? string.Empty).Trim();
                    try
                    {
                        if (!TryEnterDatabaseTuningDbLock("Database Tuning is busy applying, restoring, or loading. Try again in a moment."))
                            return false;
                        try
                        {
                            var liveDb = _database != null && _database.IsAlive ? _database : null;
                            if (liveDb == null)
                                throw new InvalidOperationException("Attach and load the database before picking values.");
                            ValidateDatabaseTuningValueChoice(liveDb, tuningRow, raw);
                        }
                        finally
                        {
                            Monitor.Exit(_databaseTuningDbLock);
                        }

                        SetSelectedDatabaseTuningGridRowValue(tuningRow, raw);
                        dialog.DialogResult = DialogResult.OK;
                        dialog.Close();
                        return true;
                    }
                    catch (Exception ex)
                    {
                        ShowInfo(ex.Message);
                        return false;
                    }
                };

                grid.CellDoubleClick += delegate
                {
                    if (grid.SelectedRows.Count == 0)
                        return;
                    var option = grid.SelectedRows[0].Tag as DatabaseTuningValueOption;
                    if (option != null)
                        acceptValue(option.RawValue);
                };
                grid.CellClick += delegate(object sender, DataGridViewCellEventArgs e)
                {
                    if (e.RowIndex < 0 || e.ColumnIndex < 0 || grid.Columns[e.ColumnIndex].Name != "Uses")
                        return;
                    var option = grid.Rows[e.RowIndex].Tag as DatabaseTuningValueOption;
                    if (option == null)
                        return;
                    if (ShowDatabaseTuningValueUsers(db, tuningRow, option))
                        acceptValue(option.RawValue);
                };
                search.TextChanged += delegate { refresh(); };
                useCustom.Click += delegate { acceptValue(custom.Text); };

                var useDefault = MakeButton("Use Default", 390, 516, 110, 32);
                useDefault.Click += delegate { acceptValue(tuningRow.DefaultRaw); };
                dialog.Controls.Add(useDefault);

                var cancel = MakeButton("Cancel", 514, 516, 100, 32);
                cancel.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(cancel);

                var confirm = MakeButton("Use Selected", 628, 516, 114, 32);
                MakeAccentButton(confirm, AccentGreen);
                confirm.Click += delegate
                {
                    if (grid.SelectedRows.Count == 0)
                        return;
                    var option = grid.SelectedRows[0].Tag as DatabaseTuningValueOption;
                    if (option != null)
                        acceptValue(option.RawValue);
                };
                dialog.Controls.Add(confirm);

                refresh();
                PrepareDialogForLanguage(dialog);
                dialog.ShowDialog(this);
            }
        }

        private void ValidateDatabaseTuningValueChoice(RemoteDatabase db, DatabaseTuningRow row, string raw)
        {
            if (row == null)
                throw new InvalidOperationException("No Database Tuning row is selected.");
            if (raw.Length == 0)
                throw new InvalidOperationException(row.DisplayName + " cannot be blank.");

            double value;
            if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out value) ||
                double.IsNaN(value) ||
                double.IsInfinity(value))
            {
                throw new InvalidOperationException(row.DisplayName + " must be a finite number.");
            }

            if (string.Equals(row.ValueType, "int", StringComparison.OrdinalIgnoreCase))
            {
                long parsedInt;
                if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsedInt))
                    throw new InvalidOperationException(row.DisplayName + " must be a whole number.");
            }
        }

        private List<DatabaseTuningValueOption> QueryDatabaseTuningValueOptions(RemoteDatabase db, DatabaseTuningRow row)
        {
            var options = new List<DatabaseTuningValueOption>();
            if (db == null || row == null || !db.TableExists(row.TableName) || !db.ColumnExists(row.TableName, row.ColumnName))
                return options;

            double min;
            double max;
            string rangeText;
            var hasRange = TryGetDatabaseTuningSafeRange(row.TableName, row.ColumnName, out min, out max, out rangeText);
            var sql = "SELECT " + EscapeIdentifierForSql(row.ColumnName) + " AS Value, COUNT(*) AS Uses FROM " +
                EscapeIdentifierForSql(row.TableName) + " WHERE " + EscapeIdentifierForSql(row.ColumnName) +
                " IS NOT NULL GROUP BY " + EscapeIdentifierForSql(row.ColumnName) +
                " ORDER BY Uses DESC LIMIT 2500;";
            foreach (var dbRow in db.Query(sql).Rows)
            {
                if (dbRow.Count == 0)
                    continue;
                var raw = FormatDatabaseTuningRawValue(dbRow[0]);
                if (raw.Length == 0)
                    continue;
                var uses = dbRow.Count > 1 ? ToLong(dbRow[1]) : 0;
                double parsed;
                var sort = double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out parsed) ? parsed : 0D;
                var inRange = true;
                if (hasRange && double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out parsed))
                {
                    var isStockTuneValue = row.ColumnName.StartsWith("Tuning_", StringComparison.OrdinalIgnoreCase) &&
                        Math.Abs(parsed + 1D) <= 0.000001D;
                    inRange = isStockTuneValue || (parsed >= min && parsed <= max);
                }
                options.Add(new DatabaseTuningValueOption(
                    raw,
                    uses,
                    string.Equals(raw, row.CurrentRaw, StringComparison.OrdinalIgnoreCase),
                    string.Equals(raw, row.DefaultRaw, StringComparison.OrdinalIgnoreCase),
                    inRange,
                    sort));
            }

            AddDatabaseTuningValueOption(options, row.CurrentRaw, 0, true, false, true);
            AddDatabaseTuningValueOption(options, row.DefaultRaw, 0, false, true, true);
            return options
                .GroupBy(option => option.RawValue, StringComparer.OrdinalIgnoreCase)
                .Select(group => group.OrderByDescending(option => option.IsCurrent).ThenByDescending(option => option.IsDefault).First())
                .ToList();
        }

        private static void AddDatabaseTuningValueOption(List<DatabaseTuningValueOption> options, string raw, long uses, bool current, bool def, bool inRange)
        {
            raw = (raw ?? string.Empty).Trim();
            if (raw.Length == 0 || options == null)
                return;
            double sort;
            if (!double.TryParse(raw, NumberStyles.Float, CultureInfo.InvariantCulture, out sort))
                sort = 0D;
            options.Add(new DatabaseTuningValueOption(raw, uses, current, def, inRange, sort));
        }

        private bool ShowDatabaseTuningValueUsers(RemoteDatabase db, DatabaseTuningRow tuningRow, DatabaseTuningValueOption option)
        {
            if (db == null || tuningRow == null || option == null)
                return false;

            List<DatabaseTuningValueUser> users;
            if (!TryEnterDatabaseTuningDbLock("Database Tuning is busy applying, restoring, or loading. Try again in a moment."))
                return false;
            try
            {
                db = _database != null && _database.IsAlive ? _database : null;
                if (db == null)
                {
                    ShowInfo("Attach and load the database before viewing car usage.");
                    return false;
                }

                users = QueryDatabaseTuningValueUsers(db, tuningRow, option.RawValue);
            }
            finally
            {
                Monitor.Exit(_databaseTuningDbLock);
            }

            var useValue = false;
            using (var dialog = new Form())
            {
                dialog.Text = "Cars Using Value";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(860, 540);

                var title = new Label();
                title.Text = tuningRow.DisplayName + " = " + option.RawValue;
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                title.Location = new Point(18, 14);
                title.Size = new Size(824, 28);
                dialog.Controls.Add(title);

                var meta = new Label();
                meta.Text = users.Count.ToString(CultureInfo.InvariantCulture) + " car link(s) found. Sources show how the value reaches the car.";
                meta.Font = new Font("Segoe UI", 8.5F);
                meta.ForeColor = TextMuted;
                meta.BackColor = AppBackground;
                meta.Location = new Point(18, 42);
                meta.Size = new Size(824, 22);
                dialog.Controls.Add(meta);

                var search = new TextBox();
                search.Location = new Point(18, 74);
                search.Size = new Size(824, 28);
                StyleTextBox(search);
                dialog.Controls.Add(search);

                var grid = BuildReadOnlyGrid();
                grid.Location = new Point(18, 114);
                grid.Size = new Size(824, 368);
                grid.Columns.Add("CarId", "Car ID");
                grid.Columns.Add("Year", "Year");
                grid.Columns.Add("Make", "Make");
                grid.Columns.Add("Model", "Model");
                grid.Columns.Add("PI", "PI");
                grid.Columns.Add("Class", "Class");
                grid.Columns.Add("Copies", "Copies");
                grid.Columns.Add("Source", "Source");
                grid.Columns["CarId"].Width = 78;
                grid.Columns["CarId"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Year"].Width = 66;
                grid.Columns["Year"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["PI"].Width = 62;
                grid.Columns["PI"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Class"].Width = 70;
                grid.Columns["Class"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Copies"].Width = 78;
                grid.Columns["Copies"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Make"].FillWeight = 18F;
                grid.Columns["Model"].FillWeight = 30F;
                grid.Columns["Source"].FillWeight = 32F;
                dialog.Controls.Add(grid);

                Action refresh = delegate
                {
                    var filter = search.Text ?? string.Empty;
                    grid.Rows.Clear();
                    foreach (var user in users
                        .Where(user => user.Matches(filter))
                        .OrderBy(user => user.Make, StringComparer.OrdinalIgnoreCase)
                        .ThenBy(user => user.Model, StringComparer.OrdinalIgnoreCase)
                        .ThenBy(user => user.CarId)
                        .ThenBy(user => user.Source, StringComparer.OrdinalIgnoreCase)
                        .Take(1200))
                    {
                        var rowIndex = grid.Rows.Add(
                            user.CarId.ToString(CultureInfo.InvariantCulture),
                            user.Year,
                            user.Make,
                            user.Model,
                            user.PerformanceIndex,
                            FormatCarClassId(user.ClassId),
                            user.Copies.ToString(CultureInfo.InvariantCulture),
                            user.Source);
                        var gridRow = grid.Rows[rowIndex];
                        gridRow.Tag = user;
                        gridRow.DefaultCellStyle.BackColor = user.Copies > 0 ? Color.FromArgb(24, 94, 64) : Color.FromArgb(66, 66, 72);
                        gridRow.DefaultCellStyle.SelectionBackColor = user.Copies > 0 ? Color.FromArgb(36, 137, 87) : Color.FromArgb(86, 86, 96);
                        gridRow.DefaultCellStyle.ForeColor = TextPrimary;
                        gridRow.DefaultCellStyle.SelectionForeColor = TextPrimary;
                    }
                };

                search.TextChanged += delegate { refresh(); };

                var close = MakeButton("Close", 606, 498, 100, 32);
                close.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(close);

                var use = MakeButton("Use This Value", 722, 498, 120, 32);
                MakeAccentButton(use, AccentGreen);
                use.Click += delegate
                {
                    useValue = true;
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(use);

                refresh();
                PrepareDialogForLanguage(dialog);
                dialog.ShowDialog(this);
            }

            return useValue;
        }

        private List<DatabaseTuningValueUser> QueryDatabaseTuningValueUsers(RemoteDatabase db, DatabaseTuningRow row, string rawValue)
        {
            var users = new List<DatabaseTuningValueUser>();
            if (db == null || row == null || string.IsNullOrWhiteSpace(rawValue) ||
                !db.TableExists(row.TableName) || !db.ColumnExists(row.TableName, row.ColumnName))
            {
                return users;
            }

            AddDatabaseTuningDirectValueUsers(db, users, row, rawValue);
            AddDatabaseTuningInstalledPartValueUsers(db, users, row, rawValue);
            AddDatabaseTuningReferencedPartValueUsers(db, users, row, rawValue);
            AddDatabaseTuningTireCurveValueUsers(db, users, row, rawValue);

            return users
                .GroupBy(user => user.CarId.ToString(CultureInfo.InvariantCulture) + "|" + user.Source, StringComparer.OrdinalIgnoreCase)
                .Select(group => group.First())
                .ToList();
        }

        private void AddDatabaseTuningDirectValueUsers(RemoteDatabase db, List<DatabaseTuningValueUser> users, DatabaseTuningRow row, string rawValue)
        {
            var comparison = BuildDatabaseTuningValueComparison(row.TableName, "source", row.ColumnName, rawValue);
            if (string.Equals(row.TableName, "Data_Car", StringComparison.OrdinalIgnoreCase) && db.ColumnExists("Data_Car", "Id"))
            {
                var sql = BuildDatabaseTuningValueUserSelectSql(db, "source.[Id]", "COUNT(DISTINCT garage.rowid)", "Data Car") +
                    "FROM Data_Car source " +
                    "LEFT JOIN Profile0_Career_Garage garage ON garage.CarId = source.[Id] " +
                    "LEFT JOIN Data_Car data ON data.Id = source.[Id] " +
                    "WHERE " + comparison + " " +
                    "GROUP BY source.[Id];";
                AddDatabaseTuningValueUsersFromSql(db, users, sql);
                return;
            }

            if (string.Equals(row.TableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase) && db.ColumnExists("Profile0_Career_Garage", "CarId"))
            {
                var sql = BuildDatabaseTuningValueUserSelectSql(db, "source.[CarId]", "COUNT(DISTINCT source.rowid)", "Garage") +
                    "FROM Profile0_Career_Garage source " +
                    "LEFT JOIN Data_Car data ON data.Id = source.[CarId] " +
                    "WHERE " + comparison + " " +
                    "GROUP BY source.[CarId];";
                AddDatabaseTuningValueUsersFromSql(db, users, sql);
                return;
            }

            var directColumn = db.ColumnExists(row.TableName, "CarId") ? "CarId" : db.ColumnExists(row.TableName, "Ordinal") ? "Ordinal" : string.Empty;
            if (directColumn.Length == 0)
                return;

            var sourceCar = "source." + EscapeIdentifierForSql(directColumn);
            var sqlDirect = BuildDatabaseTuningValueUserSelectSql(db, sourceCar, "COUNT(DISTINCT garage.rowid)", MakeReadableIdentifier(row.TableName)) +
                "FROM " + EscapeIdentifierForSql(row.TableName) + " source " +
                "LEFT JOIN Profile0_Career_Garage garage ON garage.CarId = " + sourceCar + " " +
                "LEFT JOIN Data_Car data ON data.Id = " + sourceCar + " " +
                "WHERE " + comparison + " " +
                "GROUP BY " + sourceCar + ";";
            AddDatabaseTuningValueUsersFromSql(db, users, sqlDirect);
        }

        private void AddDatabaseTuningInstalledPartValueUsers(RemoteDatabase db, List<DatabaseTuningValueUser> users, DatabaseTuningRow row, string rawValue)
        {
            if (!db.TableExists("Profile0_Career_Garage") || !db.TableExists("Data_UpgradePart"))
                return;

            if (string.Equals(row.TableName, "List_UpgradeTireCompoundFictionModOverride", StringComparison.OrdinalIgnoreCase) &&
                db.ColumnExists("Profile0_Career_Garage", "TireCompound") &&
                db.ColumnExists(row.TableName, "PartId"))
            {
                var sqlOverride = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", "Tire Compound Friction Override") +
                    "FROM " + EscapeIdentifierForSql(row.TableName) + " source " +
                    "JOIN Profile0_Career_Garage garage ON garage.[TireCompound] = source.[PartId] " +
                    "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                    "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "source", row.ColumnName, rawValue) + " " +
                    "GROUP BY garage.[CarId];";
                AddDatabaseTuningValueUsersFromSql(db, users, sqlOverride);
            }

            var partMap = QueryDatabaseTuningPartMap(db);
            foreach (var map in partMap.Values.Where(map => string.Equals(map.TableName, row.TableName, StringComparison.OrdinalIgnoreCase)))
            {
                if (!db.ColumnExists("Profile0_Career_Garage", map.ColumnName))
                    continue;
                var idColumn = ResolveDatabaseTuningPartIdColumn(db, map.TableName);
                if (string.IsNullOrEmpty(idColumn))
                    continue;

                var source = MakeReadableIdentifier(map.ColumnName) + " Part";
                var sql = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", source) +
                    "FROM " + EscapeIdentifierForSql(map.TableName) + " source " +
                    "JOIN Profile0_Career_Garage garage ON garage." + EscapeIdentifierForSql(map.ColumnName) + " = source." + EscapeIdentifierForSql(idColumn) + " " +
                    "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                    "WHERE " + BuildDatabaseTuningValueComparison(map.TableName, "source", row.ColumnName, rawValue) + " " +
                    "GROUP BY garage.[CarId];";
                AddDatabaseTuningValueUsersFromSql(db, users, sql);
            }
        }

        private void AddDatabaseTuningReferencedPartValueUsers(RemoteDatabase db, List<DatabaseTuningValueUser> users, DatabaseTuningRow row, string rawValue)
        {
            var targetKey = GetDatabaseTuningReferencedTargetKeyColumn(row.TableName);
            if (string.IsNullOrEmpty(targetKey) || !db.ColumnExists(row.TableName, targetKey))
                return;

            AddDatabaseTuningDataCarReferenceValueUsers(db, users, row, rawValue, targetKey);

            var referenceColumns = GetDatabaseTuningReferenceColumnsForTarget(row.TableName);
            if (referenceColumns.Length == 0 || !db.TableExists("Profile0_Career_Garage"))
                return;

            var partMap = QueryDatabaseTuningPartMap(db);
            foreach (var map in partMap.Values)
            {
                if (map == null || string.IsNullOrWhiteSpace(map.TableName) || !db.TableExists(map.TableName) ||
                    !db.ColumnExists("Profile0_Career_Garage", map.ColumnName))
                {
                    continue;
                }

                var idColumn = ResolveDatabaseTuningPartIdColumn(db, map.TableName);
                if (string.IsNullOrEmpty(idColumn))
                    continue;

                foreach (var referenceColumn in referenceColumns)
                {
                    if (!db.ColumnExists(map.TableName, referenceColumn))
                        continue;

                    var source = MakeReadableIdentifier(map.ColumnName) + " -> " + MakeReadableIdentifier(row.TableName);
                    var sql = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", source) +
                        "FROM " + EscapeIdentifierForSql(row.TableName) + " target " +
                        "JOIN " + EscapeIdentifierForSql(map.TableName) + " part ON part." + EscapeIdentifierForSql(referenceColumn) + " = target." + EscapeIdentifierForSql(targetKey) + " " +
                        "JOIN Profile0_Career_Garage garage ON garage." + EscapeIdentifierForSql(map.ColumnName) + " = part." + EscapeIdentifierForSql(idColumn) + " " +
                        "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                        "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "target", row.ColumnName, rawValue) + " " +
                        "GROUP BY garage.[CarId];";
                    AddDatabaseTuningValueUsersFromSql(db, users, sql);
                }
            }
        }

        private void AddDatabaseTuningDataCarReferenceValueUsers(RemoteDatabase db, List<DatabaseTuningValueUser> users, DatabaseTuningRow row, string rawValue, string targetKey)
        {
            var dataColumn = string.Empty;
            if (string.Equals(row.TableName, "List_BrakeProfile", StringComparison.OrdinalIgnoreCase) && db.ColumnExists("Data_Car", "BrakeProfile"))
                dataColumn = "BrakeProfile";
            else if (string.Equals(row.TableName, "AutoSteerOverrides", StringComparison.OrdinalIgnoreCase) && db.ColumnExists("Data_Car", "AutoSteerOverrideID"))
                dataColumn = "AutoSteerOverrideID";
            if (dataColumn.Length == 0)
                return;

            var sql = BuildDatabaseTuningValueUserSelectSql(db, "source.[Id]", "COUNT(DISTINCT garage.rowid)", "Data Car Reference") +
                "FROM " + EscapeIdentifierForSql(row.TableName) + " target " +
                "JOIN Data_Car source ON source." + EscapeIdentifierForSql(dataColumn) + " = target." + EscapeIdentifierForSql(targetKey) + " " +
                "LEFT JOIN Profile0_Career_Garage garage ON garage.CarId = source.[Id] " +
                "LEFT JOIN Data_Car data ON data.Id = source.[Id] " +
                "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "target", row.ColumnName, rawValue) + " " +
                "GROUP BY source.[Id];";
            AddDatabaseTuningValueUsersFromSql(db, users, sql);
        }

        private void AddDatabaseTuningTireCurveValueUsers(RemoteDatabase db, List<DatabaseTuningValueUser> users, DatabaseTuningRow row, string rawValue)
        {
            if (!db.TableExists("Profile0_Career_Garage") ||
                !db.ColumnExists("Profile0_Career_Garage", "TireCompound") ||
                !db.TableExists("List_UpgradeTireCompound") ||
                !db.ColumnExists("List_UpgradeTireCompound", "Id") ||
                !db.ColumnExists("List_UpgradeTireCompound", "TireCompoundID"))
            {
                return;
            }

            if (string.Equals(row.TableName, "List_TireFrictionMultiCurve", StringComparison.OrdinalIgnoreCase))
            {
                foreach (var compoundColumn in GetDatabaseTuningTireCompoundMultiCurveColumns())
                {
                    if (!db.ColumnExists("List_TireCompound", compoundColumn))
                        continue;
                    var sql = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", "Tire Compound -> Multi Curve") +
                        "FROM List_TireFrictionMultiCurve target " +
                        "JOIN List_TireCompound compound ON compound." + EscapeIdentifierForSql(compoundColumn) + " = target.[FrictionMultiCurveID] " +
                        "JOIN List_UpgradeTireCompound part ON part.[TireCompoundID] = compound.[TireCompoundID] " +
                        "JOIN Profile0_Career_Garage garage ON garage.[TireCompound] = part.[Id] " +
                        "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                        "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "target", row.ColumnName, rawValue) + " " +
                        "GROUP BY garage.[CarId];";
                    AddDatabaseTuningValueUsersFromSql(db, users, sql);
                }
            }

            if (string.Equals(row.TableName, "List_TireFrictionCurve", StringComparison.OrdinalIgnoreCase))
            {
                foreach (var multiColumn in new[] { "TireFrictionCurveID0", "TireFrictionCurveID1" })
                {
                    if (!db.ColumnExists("List_TireFrictionMultiCurve", multiColumn))
                        continue;
                    foreach (var compoundColumn in GetDatabaseTuningTireCompoundMultiCurveColumns())
                    {
                        if (!db.ColumnExists("List_TireCompound", compoundColumn))
                            continue;
                        var sql = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", "Tire Compound -> Friction Curve") +
                            "FROM List_TireFrictionCurve target " +
                            "JOIN List_TireFrictionMultiCurve multi ON multi." + EscapeIdentifierForSql(multiColumn) + " = target.[FrictionCurveID] " +
                            "JOIN List_TireCompound compound ON compound." + EscapeIdentifierForSql(compoundColumn) + " = multi.[FrictionMultiCurveID] " +
                            "JOIN List_UpgradeTireCompound part ON part.[TireCompoundID] = compound.[TireCompoundID] " +
                            "JOIN Profile0_Career_Garage garage ON garage.[TireCompound] = part.[Id] " +
                            "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                            "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "target", row.ColumnName, rawValue) + " " +
                            "GROUP BY garage.[CarId];";
                        AddDatabaseTuningValueUsersFromSql(db, users, sql);
                    }
                }
            }

            if (string.Equals(row.TableName, "List_TireAffectCurve", StringComparison.OrdinalIgnoreCase))
            {
                foreach (var compoundColumn in GetDatabaseTuningTireCompoundAffectCurveColumns())
                {
                    if (!db.ColumnExists("List_TireCompound", compoundColumn))
                        continue;
                    var sql = BuildDatabaseTuningValueUserSelectSql(db, "garage.[CarId]", "COUNT(DISTINCT garage.rowid)", "Tire Compound -> Affect Curve") +
                        "FROM List_TireAffectCurve target " +
                        "JOIN List_TireCompound compound ON compound." + EscapeIdentifierForSql(compoundColumn) + " = target.[AffectCurveID] " +
                        "JOIN List_UpgradeTireCompound part ON part.[TireCompoundID] = compound.[TireCompoundID] " +
                        "JOIN Profile0_Career_Garage garage ON garage.[TireCompound] = part.[Id] " +
                        "LEFT JOIN Data_Car data ON data.Id = garage.[CarId] " +
                        "WHERE " + BuildDatabaseTuningValueComparison(row.TableName, "target", row.ColumnName, rawValue) + " " +
                        "GROUP BY garage.[CarId];";
                    AddDatabaseTuningValueUsersFromSql(db, users, sql);
                }
            }
        }

        private void AddDatabaseTuningValueUsersFromSql(RemoteDatabase db, List<DatabaseTuningValueUser> users, string sql)
        {
            if (db == null || users == null || string.IsNullOrWhiteSpace(sql))
                return;

            try
            {
                var result = db.Query(sql);
                foreach (var row in result.Rows)
                {
                    if (row.Count < 8)
                        continue;
                    var carId = ToInt(row[0]);
                    if (carId <= 0)
                        continue;
                    users.Add(new DatabaseTuningValueUser(
                        carId,
                        ToDisplayString(row[1]),
                        TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                        TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                        FormatWholeNumber(row[4]),
                        ToInt(row[5]),
                        ToLong(row[6]),
                        ToDisplayString(row[7])));
                }
            }
            catch
            {
            }
        }

        private string BuildDatabaseTuningValueUserSelectSql(RemoteDatabase db, string carIdExpression, string copiesExpression, string source)
        {
            return "SELECT " + carIdExpression + " AS CarId, " +
                BuildDatabaseTuningUserDataText(db, "Year") + " AS Year, " +
                BuildDatabaseTuningUserDataText(db, "MakeName") + " AS Make, " +
                BuildDatabaseTuningUserModelText(db) + " AS Model, " +
                BuildDatabaseTuningUserPerformanceIndex(db) + " AS PerformanceIndex, " +
                BuildDatabaseTuningUserClassId(db) + " AS ClassId, " +
                copiesExpression + " AS Copies, " +
                ToSqlText(source) + " AS Source ";
        }

        private static string BuildDatabaseTuningUserDataText(RemoteDatabase db, string columnName)
        {
            return db != null && db.TableExists("Data_Car") && db.ColumnExists("Data_Car", columnName)
                ? "COALESCE(MAX(data." + EscapeIdentifierForSql(columnName) + "), '')"
                : "''";
        }

        private static string BuildDatabaseTuningUserModelText(RemoteDatabase db)
        {
            var columns = new[] { "DisplayName", "ModelShort", "MediaName" }
                .Where(column => db != null && db.TableExists("Data_Car") && db.ColumnExists("Data_Car", column))
                .Select(column => "MAX(data." + EscapeIdentifierForSql(column) + ")")
                .ToArray();
            return columns.Length == 0 ? "''" : "COALESCE(" + string.Join(", ", columns) + ", '')";
        }

        private static string BuildDatabaseTuningUserPerformanceIndex(RemoteDatabase db)
        {
            var columns = new[] { "PerformanceIndex", "PI" }
                .Where(column => db != null && db.TableExists("Data_Car") && db.ColumnExists("Data_Car", column))
                .Select(column => "MAX(data." + EscapeIdentifierForSql(column) + ")")
                .ToArray();
            return columns.Length == 0 ? "0" : "COALESCE(" + string.Join(", ", columns) + ", 0)";
        }

        private static string BuildDatabaseTuningUserClassId(RemoteDatabase db)
        {
            return db != null && db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "ClassID")
                ? "COALESCE(MAX(data.[ClassID]), 0)"
                : "0";
        }

        private static string BuildDatabaseTuningValueComparison(string tableName, string alias, string columnName, string rawValue)
        {
            var columnSql = (string.IsNullOrWhiteSpace(alias) ? string.Empty : alias + ".") + EscapeIdentifierForSql(columnName);
            double parsed;
            if (double.TryParse((rawValue ?? string.Empty).Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out parsed) &&
                !double.IsNaN(parsed) && !double.IsInfinity(parsed))
            {
                var epsilon = Math.Max(0.00001D, Math.Abs(parsed) * 0.0000001D);
                return columnSql + " IS NOT NULL AND ABS(CAST(" + columnSql + " AS REAL) - " +
                    parsed.ToString("0.########", CultureInfo.InvariantCulture) + ") <= " +
                    epsilon.ToString("0.########", CultureInfo.InvariantCulture);
            }

            return columnSql + " = " + ToSqlText(rawValue);
        }

