        private void ShowSelectedDatabaseTuningPartPicker()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ShowSelectedDatabaseTuningPartPicker);
                return;
            }

            var item = GetSelectedDatabaseTuningGridRow();
            if (_databaseTuningGrid == null || item == null)
            {
                ShowInfo("Select an installed-part row first.");
                return;
            }

            if (item == null || !string.Equals(item.ValueType, "part", StringComparison.OrdinalIgnoreCase) || string.IsNullOrWhiteSpace(item.PartTableName))
            {
                ShowInfo("Pick Part is only for installed-part rows.");
                return;
            }

            var car = GetSelectedDatabaseTuningCar();
            var selected = ShowDatabaseTuningPartPicker(item, car.CarId);
            if (!selected.HasValue)
                return;

            SetSelectedDatabaseTuningGridRowValue(item, selected.Value.ToString(CultureInfo.InvariantCulture));
        }

        private long? ShowDatabaseTuningPartPicker(DatabaseTuningRow tuningRow, int carId)
        {
            List<DatabaseTuningPartOption> options;
            lock (_databaseTuningDbLock)
            {
                var db = RequireDatabase();
                options = QueryDatabaseTuningPartOptions(db, tuningRow, carId);
            }
            if (options.Count == 0)
            {
                ShowInfo("No part options were found for " + tuningRow.DisplayName + ".");
                return null;
            }

            long? selected = null;
            using (var dialog = new Form())
            {
                dialog.Text = "Pick Part";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(720, 520);

                var title = new Label();
                title.Text = tuningRow.DisplayName;
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                title.Location = new Point(18, 14);
                title.Size = new Size(684, 28);
                dialog.Controls.Add(title);

                long installedId;
                var hasInstalledId = long.TryParse((tuningRow.CurrentRaw ?? string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out installedId);

                var search = new TextBox();
                search.Location = new Point(18, 52);
                search.Size = new Size(684, 28);
                StyleTextBox(search);
                dialog.Controls.Add(search);

                var grid = BuildReadOnlyGrid();
                grid.Location = new Point(18, 92);
                grid.Size = new Size(684, 368);
                grid.Columns.Add("Status", "Status");
                grid.Columns.Add("Id", "ID");
                grid.Columns.Add("Part", "Part");
                grid.Columns["Status"].Width = 126;
                grid.Columns["Status"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Id"].Width = 110;
                grid.Columns["Id"].AutoSizeMode = DataGridViewAutoSizeColumnMode.None;
                grid.Columns["Part"].FillWeight = 100F;
                dialog.Controls.Add(grid);

                Func<DatabaseTuningPartOption, bool> acceptOption = delegate(DatabaseTuningPartOption option)
                {
                    if (option == null)
                        return false;
                    if (!option.CanInstall)
                    {
                        var reason = string.IsNullOrWhiteSpace(option.Reason)
                            ? "This part is not compatible with the selected car."
                            : option.Reason;
                        ShowInfo("Part can't be installed due to the selected car." + Environment.NewLine + Environment.NewLine + reason);
                        return false;
                    }

                    selected = option.Id;
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                    return true;
                };

                Action refresh = delegate
                {
                    var filter = search.Text ?? string.Empty;
                    grid.Rows.Clear();
                    foreach (var option in options
                        .Where(option => string.IsNullOrWhiteSpace(filter) || option.SearchText.IndexOf(filter, StringComparison.OrdinalIgnoreCase) >= 0)
                        .OrderByDescending(option => hasInstalledId && option.Id == installedId)
                        .ThenBy(option => option.CanInstall ? 0 : 1)
                        .ThenBy(option => option.SortRank)
                        .ThenBy(option => option.Id)
                        .Take(900))
                    {
                        var installed = hasInstalledId && option.Id == installedId;
                        var status = installed ? "Installed" : option.StatusText;
                        var rowIndex = grid.Rows.Add(status, option.Id.ToString(CultureInfo.InvariantCulture), option.DisplayName);
                        var gridRow = grid.Rows[rowIndex];
                        gridRow.Tag = option;
                        gridRow.Cells["Status"].ToolTipText = option.Reason;
                        gridRow.Cells["Part"].ToolTipText = option.Reason;
                        if (installed)
                        {
                            var fill = Color.FromArgb(24, 94, 64);
                            var selectedFill = Color.FromArgb(36, 137, 87);
                            gridRow.DefaultCellStyle.BackColor = fill;
                            gridRow.DefaultCellStyle.SelectionBackColor = selectedFill;
                            gridRow.DefaultCellStyle.ForeColor = TextPrimary;
                            gridRow.DefaultCellStyle.SelectionForeColor = TextPrimary;
                        }
                        else if (option.CanInstall)
                        {
                            var fill = Color.FromArgb(104, 82, 20);
                            var selectedFill = Color.FromArgb(142, 108, 26);
                            gridRow.DefaultCellStyle.BackColor = fill;
                            gridRow.DefaultCellStyle.SelectionBackColor = selectedFill;
                            gridRow.DefaultCellStyle.ForeColor = TextPrimary;
                            gridRow.DefaultCellStyle.SelectionForeColor = TextPrimary;
                        }
                        else
                        {
                            var fill = Color.FromArgb(83, 36, 42);
                            var selectedFill = Color.FromArgb(118, 47, 55);
                            gridRow.DefaultCellStyle.BackColor = fill;
                            gridRow.DefaultCellStyle.SelectionBackColor = selectedFill;
                            gridRow.DefaultCellStyle.ForeColor = Color.FromArgb(234, 184, 190);
                            gridRow.DefaultCellStyle.SelectionForeColor = TextPrimary;
                        }
                    }
                };
                search.TextChanged += delegate { refresh(); };
                grid.CellDoubleClick += delegate
                {
                    if (grid.SelectedRows.Count == 0)
                        return;
                    var option = grid.SelectedRows[0].Tag as DatabaseTuningPartOption;
                    if (option == null)
                        return;
                    acceptOption(option);
                };

                var cancel = MakeButton("Cancel", 486, 476, 100, 32);
                cancel.Click += delegate { dialog.Close(); };
                dialog.Controls.Add(cancel);

                var confirm = MakeButton("Confirm", 602, 476, 100, 32);
                MakeAccentButton(confirm, AccentGreen);
                confirm.Click += delegate
                {
                    if (grid.SelectedRows.Count == 0)
                        return;
                    var option = grid.SelectedRows[0].Tag as DatabaseTuningPartOption;
                    if (option == null)
                        return;
                    acceptOption(option);
                };
                dialog.Controls.Add(confirm);

                refresh();
                PrepareDialogForLanguage(dialog);
                dialog.ShowDialog(this);
            }

            return selected;
        }

        private List<DatabaseTuningPartOption> QueryDatabaseTuningPartOptions(RemoteDatabase db, DatabaseTuningRow tuningRow, int carId)
        {
            var tableName = tuningRow.PartTableName;
            var idColumn = ResolveDatabaseTuningPartIdColumn(db, tableName);
            if (string.IsNullOrEmpty(idColumn))
                return new List<DatabaseTuningPartOption>();

            var tableSql = EscapeIdentifierForSql(tableName);
            var idSql = EscapeIdentifierForSql(idColumn);
            long installedId;
            var hasInstalledId = long.TryParse((tuningRow.CurrentRaw ?? string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out installedId);
            var installedOrder = hasInstalledId
                ? "CASE WHEN " + idSql + " = " + installedId.ToString(CultureInfo.InvariantCulture) + " THEN 0 ELSE 1 END, "
                : string.Empty;
            var sql = "SELECT * FROM " + tableSql + " ORDER BY " +
                installedOrder +
                (db.ColumnExists(tableName, "IsStock") ? "[IsStock] DESC, " : string.Empty) +
                (db.ColumnExists(tableName, "Level") ? "[Level], " : string.Empty) +
                idSql + " LIMIT 6000;";
            var options = ConvertDatabaseTuningPartOptions(db, db.Query(sql), idColumn, tuningRow, carId);

            return options
                .GroupBy(option => option.Id)
                .Select(group => group.First())
                .OrderBy(option => option.SortRank)
                .ThenBy(option => option.Id)
                .ToList();
        }

        private List<string> BuildDatabaseTuningPartFilters(RemoteDatabase db, DatabaseTuningRow tuningRow, int carId)
        {
            var filters = new List<string>();
            var tableName = tuningRow.PartTableName;
            var carIdSql = carId.ToString(CultureInfo.InvariantCulture);
            if (db.ColumnExists(tableName, "Ordinal"))
                filters.Add(" WHERE [Ordinal] = " + carIdSql);

            if (db.ColumnExists(tableName, "EngineID"))
            {
                var engineId = QueryDatabaseTuningInstalledPartProperty(db, "Engine", "List_UpgradeEngine", "EngineID", carId);
                if (engineId.HasValue)
                    filters.Add(" WHERE [EngineID] = " + engineId.Value.ToString(CultureInfo.InvariantCulture));
            }
            if (db.ColumnExists(tableName, "DrivetrainID"))
            {
                var drivetrainId = QueryDatabaseTuningInstalledPartProperty(db, "Drivetrain", "List_UpgradeDrivetrain", "DrivetrainID", carId);
                if (drivetrainId.HasValue)
                    filters.Add(" WHERE [DrivetrainID] = " + drivetrainId.Value.ToString(CultureInfo.InvariantCulture));
            }
            if (db.ColumnExists(tableName, "CarBodyId"))
            {
                var carBodyId = QueryDatabaseTuningInstalledPartProperty(db, "CarBody", "List_UpgradeCarBody", "CarBodyID", carId);
                if (carBodyId.HasValue)
                    filters.Add(" WHERE [CarBodyId] = " + carBodyId.Value.ToString(CultureInfo.InvariantCulture));
            }
            if (db.ColumnExists(tableName, "CarBodyID"))
            {
                var carBodyId = QueryDatabaseTuningInstalledPartProperty(db, "CarBody", "List_UpgradeCarBody", "CarBodyID", carId);
                if (carBodyId.HasValue)
                    filters.Add(" WHERE [CarBodyID] = " + carBodyId.Value.ToString(CultureInfo.InvariantCulture));
            }
            if (db.ColumnExists(tableName, "MotorID"))
            {
                var motorId = QueryDatabaseTuningInstalledPartProperty(db, "Motor", "List_UpgradeMotor", "MotorID", carId);
                if (motorId.HasValue)
                    filters.Add(" WHERE [MotorID] = " + motorId.Value.ToString(CultureInfo.InvariantCulture));
            }

            filters.Add(string.Empty);
            return filters.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
        }

        private long? QueryDatabaseTuningInstalledPartProperty(RemoteDatabase db, string garageColumn, string partTable, string partProperty, int carId)
        {
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", garageColumn) ||
                !db.TableExists(partTable) || !db.ColumnExists(partTable, partProperty))
                return null;

            var idColumn = ResolveDatabaseTuningPartIdColumn(db, partTable);
            if (string.IsNullOrEmpty(idColumn))
                return null;

            var sql =
                "SELECT part." + EscapeIdentifierForSql(partProperty) + " " +
                "FROM Profile0_Career_Garage garage " +
                "JOIN " + EscapeIdentifierForSql(partTable) + " part ON part." + EscapeIdentifierForSql(idColumn) + " = garage." + EscapeIdentifierForSql(garageColumn) + " " +
                "WHERE garage.CarId = " + carId.ToString(CultureInfo.InvariantCulture) + " LIMIT 1;";
            return db.QueryScalarLong(sql);
        }

        private List<DatabaseTuningPartOption> ConvertDatabaseTuningPartOptions(RemoteDatabase db, RemoteDatabase.QueryResult result, string idColumn, DatabaseTuningRow tuningRow, int carId)
        {
            var options = new List<DatabaseTuningPartOption>();
            var idIndex = FindColumnIndex(result.Columns, idColumn);
            if (idIndex < 0)
                return options;

            var supportIndex = BuildDatabaseTuningPartSupportIndex(db, carId);
            var currentSupport = QueryDatabaseTuningCurrentSupportValues(db, carId);
            var labelLookups = BuildDatabaseTuningPartLabelLookups(db);
            foreach (var row in result.Rows)
            {
                if (row.Count <= idIndex)
                    continue;
                var id = ToLong(row[idIndex]);
                if (id <= 0)
                    continue;
                var label = BuildDatabaseTuningPartLabel(result.Columns, row, labelLookups);
                var display = id.ToString(CultureInfo.InvariantCulture) + (string.IsNullOrWhiteSpace(label) ? string.Empty : " - " + label);
                options.Add(ClassifyDatabaseTuningPartOption(db, tuningRow, carId, id, display, result.Columns, row, supportIndex, currentSupport));
            }
            return options;
        }

        private DatabaseTuningPartOption ClassifyDatabaseTuningPartOption(RemoteDatabase db, DatabaseTuningRow tuningRow, int carId, long id, string display, List<string> columns, List<object> row, DatabaseTuningPartSupportIndex supportIndex, Dictionary<string, long> currentSupport)
        {
            if (tuningRow == null)
                return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3, "No tuning row is selected.");
            if (string.Equals(tuningRow.PartTableName, "List_Wheels", StringComparison.OrdinalIgnoreCase))
                return new DatabaseTuningPartOption(id, display, display, "Can Install", true, 0, "Wheel style can be installed.");

            var part = new DatabaseTuningPartRecord(columns, row);
            if (IsDatabaseTuningParentInstallColumn(tuningRow.ColumnName))
            {
                var parentOrdinalColumn = part.FindColumn("Ordinal");
                if (string.IsNullOrEmpty(parentOrdinalColumn))
                    return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3, "This support part does not expose a car support marker.");

                var parentOrdinal = part.GetLong(parentOrdinalColumn);
                if (parentOrdinal == carId)
                    return new DatabaseTuningPartOption(id, display, display, "Can Install", true, 0, "Supported parent part for this selected car.");

                return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3,
                    "This support part belongs to car ID " + parentOrdinal.ToString(CultureInfo.InvariantCulture) +
                    ". FH6 only loads supported parent parts for the selected car.");
            }

            var engineColumn = part.FindColumn("EngineID");
            if (!string.IsNullOrEmpty(engineColumn))
                return ClassifyDatabaseTuningFamilyPartOption(id, display, part.GetLong(engineColumn), "Engine", supportIndex.EngineIds, supportIndex, currentSupport);

            var drivetrainColumn = part.FindColumn("DrivetrainID", "DrivetrainId");
            if (!string.IsNullOrEmpty(drivetrainColumn))
                return ClassifyDatabaseTuningFamilyPartOption(id, display, part.GetLong(drivetrainColumn), "Drivetrain", supportIndex.DrivetrainIds, supportIndex, currentSupport);

            var carBodyColumn = part.FindColumn("CarBodyID", "CarBodyId", "CarbodyId");
            if (!string.IsNullOrEmpty(carBodyColumn))
                return ClassifyDatabaseTuningFamilyPartOption(id, display, part.GetLong(carBodyColumn), "Car Body", supportIndex.CarBodyIds, supportIndex, currentSupport);

            var motorColumn = part.FindColumn("MotorID");
            if (!string.IsNullOrEmpty(motorColumn))
                return ClassifyDatabaseTuningFamilyPartOption(id, display, part.GetLong(motorColumn), "Motor", supportIndex.MotorIds, supportIndex, currentSupport);

            var ordinalColumn = part.FindColumn("Ordinal");
            if (!string.IsNullOrEmpty(ordinalColumn))
            {
                var ordinal = part.GetLong(ordinalColumn);
                if (ordinal == carId)
                    return new DatabaseTuningPartOption(id, display, display, "Can Install", true, 0, "Native part for this car.");
                return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3,
                    "This part is built for car ID " + ordinal.ToString(CultureInfo.InvariantCulture) +
                    ", not selected car ID " + carId.ToString(CultureInfo.InvariantCulture) + ".");
            }

            return new DatabaseTuningPartOption(id, display, display, "Can Install", true, 0, "No car-specific dependency was found.");
        }

        private static DatabaseTuningPartOption ClassifyDatabaseTuningFamilyPartOption(long id, string display, long requiredValue, string familyName, HashSet<long> supportedValues, DatabaseTuningPartSupportIndex supportIndex, Dictionary<string, long> currentSupport)
        {
            if (requiredValue <= 0)
                return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3, familyName + " dependency was missing.");

            long currentValue;
            if (currentSupport != null && currentSupport.TryGetValue(familyName, out currentValue) && currentValue == requiredValue)
                return new DatabaseTuningPartOption(id, display, display, "Can Install", true, 0, "Matches the currently installed " + familyName + " family.");

            if (supportedValues != null && supportedValues.Contains(requiredValue))
                return new DatabaseTuningPartOption(id, display, display, "With Support", true, 1, "Luna can install the matching " + familyName + " support part on Apply.");

            if (supportIndex != null && supportIndex.CanCloneSupport(familyName, requiredValue))
                return new DatabaseTuningPartOption(id, display, display, "Create Support", true, 2, "Luna can create a selected-car support row for this non-visual " + familyName + " family on Apply.");

            return new DatabaseTuningPartOption(id, display, display, "Unavailable", false, 3, "No matching " + familyName + " support part was found.");
        }

        private DatabaseTuningPartSupportIndex BuildDatabaseTuningPartSupportIndex(RemoteDatabase db, int carId)
        {
            return new DatabaseTuningPartSupportIndex(
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeEngine", "EngineID", carId),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeDrivetrain", "DrivetrainID", carId),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeCarBody", "CarBodyID", carId),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeMotor", "MotorID", carId),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeEngine", "EngineID", null),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeDrivetrain", "DrivetrainID", null),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeCarBody", "CarBodyID", null),
                QueryDatabaseTuningSupportValueSet(db, "List_UpgradeMotor", "MotorID", null));
        }

        private HashSet<long> QueryDatabaseTuningSupportValueSet(RemoteDatabase db, string tableName, string columnName, int? carId)
        {
            var values = new HashSet<long>();
            if (!db.TableExists(tableName))
                return values;
            var resolvedColumn = ResolveExistingColumn(db, tableName, columnName);
            if (string.IsNullOrEmpty(resolvedColumn))
                return values;

            var result = db.Query("SELECT DISTINCT " + EscapeIdentifierForSql(resolvedColumn) +
                " FROM " + EscapeIdentifierForSql(tableName) +
                " WHERE " + EscapeIdentifierForSql(resolvedColumn) + " IS NOT NULL AND " + EscapeIdentifierForSql(resolvedColumn) + " > 0" +
                (carId.HasValue && db.ColumnExists(tableName, "Ordinal") ? " AND [Ordinal] = " + carId.Value.ToString(CultureInfo.InvariantCulture) : string.Empty) + ";");
            foreach (var row in result.Rows)
            {
                if (row.Count == 0)
                    continue;
                var value = ToLong(row[0]);
                if (value > 0)
                    values.Add(value);
            }
            return values;
        }

        private Dictionary<string, long> QueryDatabaseTuningCurrentSupportValues(RemoteDatabase db, int carId)
        {
            var values = new Dictionary<string, long>(StringComparer.OrdinalIgnoreCase);
            AddDatabaseTuningCurrentSupportValue(db, values, "Engine", "Engine", "List_UpgradeEngine", "EngineID", carId);
            AddDatabaseTuningCurrentSupportValue(db, values, "Drivetrain", "Drivetrain", "List_UpgradeDrivetrain", "DrivetrainID", carId);
            AddDatabaseTuningCurrentSupportValue(db, values, "Car Body", "CarBody", "List_UpgradeCarBody", "CarBodyID", carId);
            AddDatabaseTuningCurrentSupportValue(db, values, "Motor", "Motor", "List_UpgradeMotor", "MotorID", carId);
            return values;
        }

        private void AddDatabaseTuningCurrentSupportValue(RemoteDatabase db, Dictionary<string, long> values, string familyName, string garageColumn, string partTable, string partProperty, int carId)
        {
            var value = QueryDatabaseTuningInstalledPartProperty(db, garageColumn, partTable, partProperty, carId);
            if (value.HasValue && value.Value > 0)
                values[familyName] = value.Value;
        }

        private DatabaseTuningPartLabelLookups BuildDatabaseTuningPartLabelLookups(RemoteDatabase db)
        {
            return new DatabaseTuningPartLabelLookups(
                QueryDatabaseTuningTextLookup(db, "List_PartsStrings", "Id", "PartsString"),
                QueryDatabaseTuningTextLookup(db, "CarPartNames", "ID", "PartName"),
                QueryDatabaseTuningTextLookup(db, "List_PartManufacturer", "Id", "PartManufacturer"));
        }

        private Dictionary<long, string> QueryDatabaseTuningTextLookup(RemoteDatabase db, string tableName, string idColumn, string textColumn)
        {
            var values = new Dictionary<long, string>();
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, idColumn) || !db.ColumnExists(tableName, textColumn))
                return values;

            var result = db.Query("SELECT " + EscapeIdentifierForSql(idColumn) + ", " + EscapeIdentifierForSql(textColumn) + " FROM " + EscapeIdentifierForSql(tableName) + ";");
            foreach (var row in result.Rows)
            {
                if (row.Count < 2)
                    continue;
                var id = ToLong(row[0]);
                var text = CleanDatabaseTuningPartLabelText(ToDisplayString(row[1]));
                if (id > 0 && !string.IsNullOrWhiteSpace(text) && !values.ContainsKey(id))
                    values.Add(id, text);
            }
            return values;
        }

        private static string BuildDatabaseTuningPartLabel(List<string> columns, List<object> row, DatabaseTuningPartLabelLookups lookups)
        {
            var pieces = new List<string>();
            AddPartLabelPiece(pieces, columns, row, "DisplayName");
            AddPartLabelPiece(pieces, columns, row, "MediaName");
            AddPartLabelPiece(pieces, columns, row, "Name");
            AddPartLabelPiece(pieces, columns, row, "TireModelName");
            AddPartStringLabelPiece(pieces, columns, row, lookups, "PartsStringID", "PartsStringId");
            AddManufacturerLabelPiece(pieces, columns, row, lookups, "ManufacturerID", "ManufacturerId", "PartManufacturerID");
            AddFamilyLabelPiece(pieces, columns, row, "EngineID", "Engine");
            AddFamilyLabelPiece(pieces, columns, row, "DrivetrainID", "Drivetrain");
            AddFamilyLabelPiece(pieces, columns, row, "DrivetrainId", "Drivetrain");
            AddFamilyLabelPiece(pieces, columns, row, "CarBodyID", "Body");
            AddFamilyLabelPiece(pieces, columns, row, "CarBodyId", "Body");
            AddFamilyLabelPiece(pieces, columns, row, "CarbodyId", "Body");
            AddFamilyLabelPiece(pieces, columns, row, "MotorID", "Motor");
            AddFamilyLabelPiece(pieces, columns, row, "Ordinal", "Car");
            var level = GetColumnValue(columns, row, "Level");
            if (!string.IsNullOrWhiteSpace(level))
                pieces.Add("Level " + level);
            var stock = GetColumnValue(columns, row, "IsStock");
            if (stock == "1")
                pieces.Add("Stock");
            var price = GetColumnValue(columns, row, "Price");
            if (!string.IsNullOrWhiteSpace(price))
                pieces.Add(price + " CR");
            return string.Join(" | ", pieces.Where(piece => !string.IsNullOrWhiteSpace(piece)).Distinct(StringComparer.OrdinalIgnoreCase).ToArray());
        }

        private static void AddPartLabelPiece(List<string> pieces, List<string> columns, List<object> row, string columnName)
        {
            var value = GetColumnValue(columns, row, columnName);
            value = CleanDatabaseTuningPartLabelText(value);
            if (!string.IsNullOrWhiteSpace(value) && value != "0")
                pieces.Add(value);
        }

        private static void AddPartStringLabelPiece(List<string> pieces, List<string> columns, List<object> row, DatabaseTuningPartLabelLookups lookups, params string[] columnNames)
        {
            foreach (var columnName in columnNames ?? new string[0])
            {
                var raw = GetColumnValue(columns, row, columnName);
                long id;
                if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out id) || id <= 0)
                    continue;

                string text;
                if (lookups != null && lookups.CarPartNames.TryGetValue(id, out text))
                    pieces.Add(text);
                if (lookups != null && lookups.PartStrings.TryGetValue(id, out text))
                    pieces.Add(text);
                pieces.Add("Part string " + id.ToString(CultureInfo.InvariantCulture));
                return;
            }
        }

        private static void AddManufacturerLabelPiece(List<string> pieces, List<string> columns, List<object> row, DatabaseTuningPartLabelLookups lookups, params string[] columnNames)
        {
            foreach (var columnName in columnNames ?? new string[0])
            {
                var raw = GetColumnValue(columns, row, columnName);
                long id;
                if (!long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out id) || id <= 0)
                    continue;

                string text;
                if (lookups != null && lookups.Manufacturers.TryGetValue(id, out text) && !string.IsNullOrWhiteSpace(text))
                    pieces.Add(text);
                else
                    pieces.Add("Manufacturer " + id.ToString(CultureInfo.InvariantCulture));
                return;
            }
        }

        private static void AddFamilyLabelPiece(List<string> pieces, List<string> columns, List<object> row, string columnName, string label)
        {
            var raw = GetColumnValue(columns, row, columnName);
            long id;
            if (long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out id) && id > 0)
                pieces.Add(label + " " + id.ToString(CultureInfo.InvariantCulture));
        }

        private static string CleanDatabaseTuningPartLabelText(string text)
        {
            text = (text ?? string.Empty).Trim();
            if (text.Length == 0 || string.Equals(text, "NULL", StringComparison.OrdinalIgnoreCase))
                return string.Empty;
            if (text.StartsWith("_&", StringComparison.Ordinal))
                return string.Empty;
            return MakeReadableIdentifier(text);
        }

        private static string GetColumnValue(List<string> columns, List<object> row, string columnName)
        {
            var index = FindColumnIndex(columns, columnName);
            if (index < 0 || row == null || row.Count <= index || row[index] == null)
                return string.Empty;
            return Convert.ToString(row[index], CultureInfo.InvariantCulture) ?? string.Empty;
        }

        private static int FindColumnIndex(List<string> columns, string columnName)
        {
            if (columns == null)
                return -1;
            for (var i = 0; i < columns.Count; i++)
            {
                if (string.Equals(columns[i], columnName, StringComparison.OrdinalIgnoreCase))
                    return i;
            }
            return -1;
        }

        private string ResolveDatabaseTuningPartIdColumn(RemoteDatabase db, string tableName)
        {
            if (string.IsNullOrWhiteSpace(tableName) || !db.TableExists(tableName))
                return string.Empty;
            if (db.ColumnExists(tableName, "Id"))
                return "Id";
            if (db.ColumnExists(tableName, "ID"))
                return "ID";
            return string.Empty;
        }

        private void ScanLiveTuning()
        {
            var db = RequireDatabase();
            var report = db.ScanLiveTuningPointers(true);
            Log("Driving Tuning scan updated: " + report.Summary + ".");
            SetTuningSelection(report.Summary + ".");
            RefreshLiveTuningCurrentValues();
        }

        private void ToggleTuningLiveScan(Button button)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ToggleTuningLiveScan(button); }));
                return;
            }

            if (_tuningLiveScanTimer != null && _tuningLiveScanTimer.Enabled)
            {
                StopTuningLiveScan(true);
                return;
            }

            StartTuningLiveScan(button);
        }

        private void StartTuningLiveScan(Button button)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { StartTuningLiveScan(button); }));
                return;
            }

            _tuningLiveScanButton = button ?? _tuningLiveScanButton;
            if (_tuningLiveScanTimer == null)
            {
                _tuningLiveScanTimer = new System.Windows.Forms.Timer();
                _tuningLiveScanTimer.Interval = TuningLiveScanIntervalMs;
                _tuningLiveScanTimer.Tick += delegate { RunTuningLiveScanTick(); };
            }

            _tuningLiveScanTimer.Start();
            _tuningLiveScanLastSummary = string.Empty;
            if (_tuningLiveScanButton != null)
            {
                _tuningLiveScanButton.Text = "Stop Live Scan";
                MakeAccentButton(_tuningLiveScanButton, AccentRed);
            }

            Log("Driving Tuning live scan started.");
            SetTuningSelection("Live scan running. Move or open the tuning menu so FH6 updates the values.");
            RunTuningLiveScanTick();
        }

        private void StopTuningLiveScan(bool updateUi)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { StopTuningLiveScan(updateUi); }));
                return;
            }

            if (_tuningLiveScanTimer != null)
                _tuningLiveScanTimer.Stop();

            if (!updateUi)
                return;

            if (_tuningLiveScanButton != null)
            {
                _tuningLiveScanButton.Text = "Start Live Scan";
                MakeAccentButton(_tuningLiveScanButton, AccentBlue);
            }

            Log("Driving Tuning live scan stopped.");
            SetTuningSelection("Live scan stopped.");
        }

        private void RunTuningLiveScanTick()
        {
            if (Interlocked.CompareExchange(ref _tuningOperationBusy, 0, 0) != 0)
            {
                SetTuningSelection("Live scan paused while a tuning operation is running.");
                return;
            }

            if (Interlocked.Exchange(ref _tuningLiveScanBusy, 1) != 0)
                return;

            ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    var db = _database != null && _database.IsAlive ? _database : null;
                    if (db == null)
                    {
                        const string waitingSummary = "waiting:attach";
                        if (!string.Equals(waitingSummary, _tuningLiveScanLastSummary, StringComparison.OrdinalIgnoreCase))
                        {
                            _tuningLiveScanLastSummary = waitingSummary;
                            Log("Driving Tuning scan waiting for FH6 attach.");
                        }
                        RefreshLiveTuningCurrentValues();
                        SetTuningSelection("Live scan waiting for FH6 attach.");
                        return;
                    }

                    var report = db.ScanLiveTuningPointers(true);
                    if (!string.Equals(report.Summary, _tuningLiveScanLastSummary, StringComparison.OrdinalIgnoreCase))
                    {
                        _tuningLiveScanLastSummary = report.Summary;
                        Log("Driving Tuning scan updated: " + report.Summary + ".");
                    }

                    RefreshLiveTuningCurrentValues();
                    SetTuningSelection("Live scan running. " + report.Summary + ".");
                }
                catch (Exception ex)
                {
                    var errorSummary = "error:" + ex.Message;
                    if (!string.Equals(errorSummary, _tuningLiveScanLastSummary, StringComparison.OrdinalIgnoreCase))
                    {
                        _tuningLiveScanLastSummary = errorSummary;
                        Log("Driving Tuning scan waiting: " + ex.Message);
                    }
                    RefreshLiveTuningCurrentValues();
                    SetTuningSelection("Live scan waiting: " + ex.Message);
                }
                finally
                {
                    Interlocked.Exchange(ref _tuningLiveScanBusy, 0);
                }
            });
        }

        private void LoadLiveTuningCurrent()
        {
            EnterLiveTuningOperation("Driving Tuning is already loading, applying, or restoring.");
            try
            {
                var db = RequireDatabase();
                db.ScanLiveTuningPointers(true);
                RefreshLiveTuningCurrentValues();
                SetTuningSelection("Current tuning values loaded.");
            }
            finally
            {
                ExitLiveTuningOperation();
            }
        }

        private void RefreshLiveTuningCurrentValues()
        {
            if (_tuningGrid == null || _tuningGrid.IsDisposed)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)RefreshLiveTuningCurrentValues);
                return;
            }

            var db = _database != null && _database.IsAlive ? _database : null;
            foreach (DataGridViewRow row in _tuningGrid.Rows)
            {
                var field = row.Tag as LiveTuningField;
                if (field == null)
                    continue;

                if (db == null)
                {
                    row.Cells["Address"].Value = "Not Found";
                    row.Cells["Address"].ToolTipText = "Attach to FH6 first.";
                    row.Cells["Current"].Value = "Attach first";
                    StyleLiveTuningRow(row, "Not scanned");
                    continue;
                }

                try
                {
                    var readback = db.ReadLiveTuningFloat(field.Key, field.Source, field.Offset, field.SaneMin, field.SaneMax);
                    row.Cells["Address"].Value = FormatLiveTuningAddressStatus(readback);
                    row.Cells["Address"].ToolTipText = FormatLiveTuningAddressToolTip(readback);
                    row.Cells["Current"].Value = readback.Address == 0 ? readback.Status : FormatFloat(readback.Value);
                    if (string.IsNullOrWhiteSpace(Convert.ToString(row.Cells["Value"].Value, CultureInfo.InvariantCulture)) && readback.Address != 0 && !IsBadLiveTuningStatus(readback.Status))
                        row.Cells["Value"].Value = FormatFloat(readback.Value);
                    row.Cells["Current"].ToolTipText = readback.Status;
                    StyleLiveTuningRow(row, readback.Status);
                }
                catch (Exception ex)
                {
                    row.Cells["Address"].Value = "Not Found";
                    row.Cells["Address"].ToolTipText = ex.Message;
                    row.Cells["Current"].Value = ex.Message;
                    StyleLiveTuningRow(row, "Check");
                }
            }
        }

        private List<LiveTuningInput> CaptureLiveTuningInputs()
        {
            if (InvokeRequired)
                return (List<LiveTuningInput>)Invoke(new Func<List<LiveTuningInput>>(CaptureLiveTuningInputs));
            if (_tuningGrid == null)
                return new List<LiveTuningInput>();

            _tuningGrid.EndEdit();
            var inputs = new List<LiveTuningInput>();
            foreach (DataGridViewRow row in _tuningGrid.Rows)
            {
                var field = row.Tag as LiveTuningField;
                if (field == null)
                    continue;

                var enabled = row.Cells["Enabled"].Value is bool && (bool)row.Cells["Enabled"].Value;
                if (!enabled)
                    continue;

                var raw = Convert.ToString(row.Cells["Value"].Value, CultureInfo.InvariantCulture) ?? string.Empty;
                var value = ParseFloat(raw, field.DisplayName);
                ValidateLiveTuningInputValue(field, value);
                inputs.Add(new LiveTuningInput(field, value, true));
            }

            return inputs;
        }

        private void ApplyLiveTuningInputs(List<LiveTuningInput> inputs)
        {
            if (inputs == null || inputs.Count == 0)
                throw new InvalidOperationException("Turn at least one Tuning row green before applying.");

            EnterLiveTuningOperation("Driving Tuning is already loading, applying, or restoring.");
            try
            {
                foreach (var input in inputs)
                    ValidateLiveTuningInputValue(input.Field, input.Value);

                var db = RequireDatabase();
                db.ScanLiveTuningPointers(true);
                var applied = 0;
                var skipped = 0;
                foreach (var input in inputs)
                {
                    var field = input.Field;
                    try
                    {
                        var before = db.ReadLiveTuningFloat(field.Key, field.Source, field.Offset, field.SaneMin, field.SaneMax);
                        if (IsBadLiveTuningStatus(before.Status))
                        {
                            skipped++;
                            UpdateLiveTuningRow(field.Key, before);
                            Log("Driving Tuning skipped " + field.DisplayName + ": " + before.Status + ".");
                            continue;
                        }

                        var readback = db.WriteLiveTuningFloat(
                            field.Key,
                            field.Source,
                            field.Offset,
                            input.Value,
                            field.SaneMin,
                            field.SaneMax,
                            field.MirrorSource,
                            field.MirrorOffset);
                        if (IsBadLiveTuningStatus(readback.Status))
                        {
                            skipped++;
                            UpdateLiveTuningRow(field.Key, readback);
                            Log("Driving Tuning write did not verify for " + field.DisplayName + ": " + readback.Status + ".");
                            continue;
                        }

                        applied++;
                        UpdateLiveTuningRow(field.Key, readback);
                    }
                    catch (Exception ex)
                    {
                        skipped++;
                        UpdateLiveTuningRow(field.Key, new LiveTuningReadback(field.Key, 0, 0F, "Check"));
                        Log("Driving Tuning skipped " + field.DisplayName + ": " + ex.Message);
                    }
                }

                if (applied == 0)
                    throw new InvalidOperationException("No selected Driving Tuning rows are ready yet. Red rows need to be found before Luna can write them.");

                var skippedText = skipped > 0 ? " Skipped " + skipped.ToString(CultureInfo.InvariantCulture) + " unresolved/red row(s)." : string.Empty;
                Log("Driving Tuning applied " + applied.ToString(CultureInfo.InvariantCulture) + " row(s)." + skippedText);
                SetTuningSelection("Applied " + applied.ToString(CultureInfo.InvariantCulture) + " tuning row(s)." + skippedText);
                ShowInfo("Tuning applied to the live game process." + (skipped > 0 ? Environment.NewLine + Environment.NewLine + skippedText.Trim() : string.Empty));
            }
            finally
            {
                ExitLiveTuningOperation();
            }
        }

        private void RestoreLiveTuningSnapshot()
        {
            EnterLiveTuningOperation("Driving Tuning is already loading, applying, or restoring.");
            try
            {
                var db = RequireDatabase();
                var restored = db.RestoreLiveTuningSnapshots();
                RefreshLiveTuningCurrentValues();
                Log("Driving Tuning restored " + restored.ToString(CultureInfo.InvariantCulture) + " snapshot value(s).");
                SetTuningSelection(restored > 0 ? "Restored " + restored.ToString(CultureInfo.InvariantCulture) + " snapshot value(s)." : "No tuning snapshots to restore.");
                ShowInfo(restored > 0 ? "Tuning snapshot restored." : "No tuning snapshots were captured yet.");
            }
            finally
            {
                ExitLiveTuningOperation();
            }
        }

        private void EnterLiveTuningOperation(string busyMessage)
        {
            if (Interlocked.CompareExchange(ref _tuningOperationBusy, 1, 0) != 0)
                throw new InvalidOperationException(string.IsNullOrWhiteSpace(busyMessage)
                    ? "Driving Tuning is busy. Try again in a moment."
                    : busyMessage);
        }

        private void ExitLiveTuningOperation()
        {
            Interlocked.Exchange(ref _tuningOperationBusy, 0);
        }

        private static void ValidateLiveTuningInputValue(LiveTuningField field, float value)
        {
            if (field == null)
                throw new InvalidOperationException("Tuning row is missing.");
            if (float.IsNaN(value) || float.IsInfinity(value))
                throw new InvalidOperationException(field.DisplayName + " must be a finite number.");
            if (value < field.SaneMin || value > field.SaneMax)
            {
                throw new InvalidOperationException(field.DisplayName + " must be between " +
                    FormatFloat(field.SaneMin) + " and " + FormatFloat(field.SaneMax) +
                    " so FH6 can load the live tuning value safely.");
            }
        }

        private void UpdateLiveTuningRow(string key, LiveTuningReadback readback)
        {
            if (_tuningGrid == null || _tuningGrid.IsDisposed)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { UpdateLiveTuningRow(key, readback); }));
                return;
            }

            foreach (DataGridViewRow row in _tuningGrid.Rows)
            {
                var field = row.Tag as LiveTuningField;
                if (field == null || !string.Equals(field.Key, key, StringComparison.OrdinalIgnoreCase))
                    continue;

                row.Cells["Address"].Value = FormatLiveTuningAddressStatus(readback);
                row.Cells["Address"].ToolTipText = FormatLiveTuningAddressToolTip(readback);
                row.Cells["Current"].Value = readback.Address == 0 ? readback.Status : FormatFloat(readback.Value);
                row.Cells["Current"].ToolTipText = readback.Status;
                StyleLiveTuningRow(row, readback.Status);
                return;
            }
        }

        private static string FormatLiveTuningAddressStatus(LiveTuningReadback readback)
        {
            if (readback == null || readback.Address == 0)
                return "Not Found";

            return "Found";
        }

        private static string FormatLiveTuningAddressToolTip(LiveTuningReadback readback)
        {
            if (readback == null)
                return "No live tuning readback.";

            if (readback.Address == 0)
                return readback.Status;

            return readback.Status;
        }

        private void StyleLiveTuningRow(DataGridViewRow row, string status)
        {
            if (row == null)
                return;

            var bad = IsBadLiveTuningStatus(status);
            var good = string.Equals(status, "OK", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(status, "Applied", StringComparison.OrdinalIgnoreCase);

            foreach (DataGridViewCell cell in row.Cells)
            {
                if (bad)
                {
                    cell.Style.ForeColor = AccentRed;
                    cell.Style.SelectionForeColor = AccentRed;
                }
                else if (good)
                {
                    cell.Style.ForeColor = TextPrimary;
                    cell.Style.SelectionForeColor = TextPrimary;
                }
                else
                {
                    cell.Style.ForeColor = TextMuted;
                    cell.Style.SelectionForeColor = TextMuted;
                }
            }

            if (row.DataGridView != null && row.DataGridView.Columns.Contains("Address"))
            {
                var statusCell = row.Cells["Address"];
                var addressFound = string.Equals(Convert.ToString(statusCell.Value, CultureInfo.InvariantCulture), "Found", StringComparison.OrdinalIgnoreCase);
                statusCell.Style.ForeColor = addressFound ? AccentGreen : AccentRed;
                statusCell.Style.SelectionForeColor = statusCell.Style.ForeColor;
                statusCell.Style.Font = new Font("Segoe UI Semibold", 9F, FontStyle.Bold);
            }

            SyncLiveTuningRowControl(row);
        }

        private static bool IsBadLiveTuningStatus(string status)
        {
            if (string.IsNullOrWhiteSpace(status))
                return true;

            return string.Equals(status, "Not scanned", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(status, "Not Found", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(status, "Unreadable", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(status, "Waiting", StringComparison.OrdinalIgnoreCase);
        }

        private void SetTuningSelection(string text)
        {
            if (_tuningSelected == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetTuningSelection(text); }));
                return;
            }

            _tuningSelected.Text = text ?? string.Empty;
            SetTuningPageStatus(string.IsNullOrWhiteSpace(text) ? "Tuning" : text);
            SetProfileStatus(string.IsNullOrWhiteSpace(text) ? "Tuning" : text);
        }

        private void SetTuningPageStatus(string text)
        {
            if (_tuningPage == null || _tuningPage.Tag == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetTuningPageStatus(text); }));
                return;
            }

            var label = _tuningPage.Tag as Label;
            if (label != null)
                label.Text = TranslateStatusText(text);
        }

        private int ApplyVehicleTunerDriftScore(RemoteDatabase db, float multiplier)
        {
            if (!db.TableExists("Tracks") || !db.ColumnExists("Tracks", "DriftScoreScalar"))
                return 0;

            var table = EscapeIdentifierForSql("Tracks");
            var backup = EscapeIdentifierForSql("_backup_Database_VehicleTuner_Tracks");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
            return ApplyBaselineRealMultiplier(db, table, backup, "DriftScoreScalar", FormatDrivingMultiplier(multiplier), false, 0.001);
        }

        private int ApplyVehicleTunerTraction(RemoteDatabase db, int carId, float multiplier)
        {
            var applied = 0;
            var multiplierSql = FormatDrivingMultiplier(multiplier);
            if (db.TableExists("Data_Car"))
            {
                var table = EscapeIdentifierForSql("Data_Car");
                var backup = EscapeIdentifierForSql("_backup_Database_VehicleTuner_DataCar");
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
                var where = BuildDrivingCarFilterForQuery(db, "Data_Car", table, carId);
                if (string.IsNullOrEmpty(where))
                    return applied;
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_Road", multiplierSql, false, 0.001, where);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_OffRoad", multiplierSql, false, 0.001, where);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_Snow", multiplierSql, false, 0.001, where);
            }

            if (db.TableExists("Profile0_Career_Garage"))
            {
                var table = EscapeIdentifierForSql("Profile0_Career_Garage");
                var backup = EscapeIdentifierForSql("_backup_Database_VehicleTuner_ProfileGarage");
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
                var where = BuildDrivingCarFilterForQuery(db, "Profile0_Career_Garage", table, carId);
                if (string.IsNullOrEmpty(where))
                    return applied;
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_Road", multiplierSql, false, 0.001, where);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_OffRoad", multiplierSql, false, 0.001, where);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "Traction_Snow", multiplierSql, false, 0.001, where);
            }

            return applied;
        }

        private int ApplyVehicleTunerTorque(RemoteDatabase db, int carId, float multiplier)
        {
            if (!db.TableExists("Data_Car"))
                return 0;

            var table = EscapeIdentifierForSql("Data_Car");
            var backup = EscapeIdentifierForSql("_backup_Database_VehicleTuner_DataCar");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
            var where = BuildDrivingCarFilterForQuery(db, "Data_Car", table, carId);
            if (string.IsNullOrEmpty(where))
                return 0;
            return ApplyBaselineRealMultiplier(db, table, backup, "GameTorqueScale", FormatDrivingMultiplier(multiplier), false, 0.001, where);
        }

        private int ApplyVehicleTunerDrag(RemoteDatabase db, int carId, float multiplier)
        {
            if (!db.TableExists("Data_Car"))
                return 0;

            var table = EscapeIdentifierForSql("Data_Car");
            var backup = EscapeIdentifierForSql("_backup_Database_VehicleTuner_DataCar");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
            var where = BuildDrivingCarFilterForQuery(db, "Data_Car", table, carId);
            if (string.IsNullOrEmpty(where))
                return 0;
            var multiplierSql = FormatDrivingMultiplier(multiplier);
            var applied = 0;
            applied += ApplyBaselineRealMultiplier(db, table, backup, "GameDragScale", multiplierSql, false, 0.001, where);
            applied += ApplyBaselineRealMultiplier(db, table, backup, "BodyAeroLongitudinalDrag", multiplierSql, false, 0.001, where);
            return applied;
        }

        private int RestoreVehicleTunerCarTraction(RemoteDatabase db, int carId)
        {
            var columns = new[] { "Traction_Road", "Traction_OffRoad", "Traction_Snow" };
            return RestoreVehicleTunerColumnSet(db, "Data_Car", "_backup_Database_VehicleTuner_DataCar", columns, carId) +
                   RestoreVehicleTunerColumnSet(db, "Profile0_Career_Garage", "_backup_Database_VehicleTuner_ProfileGarage", columns, carId);
        }

        private int RestoreVehicleTunerColumnSet(RemoteDatabase db, string tableName, string backupName, IEnumerable<string> columns, int? carId)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName) || !db.ColumnExists(backupName, "_rowid_"))
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var carFilter = BuildDrivingCarFilterForQuery(db, tableName, tableSql, carId);
            if (carId.HasValue && string.IsNullOrEmpty(carFilter) &&
                (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase)))
            {
                return 0;
            }
            var restored = 0;
            foreach (var column in columns)
            {
                if (!db.ColumnExists(tableName, column) || !db.ColumnExists(backupName, column))
                    continue;

                var columnSql = EscapeIdentifierForSql(column);
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + columnSql + " = (SELECT " + backupSql + "." + columnSql + " FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid)" + carFilter + ";");
                restored++;
            }

            return restored;
        }

        private static float ParseVehicleTunerMultiplier(string text, string label)
        {
            var value = ParsePositiveFloat(text, label);
            if (value < 0.001F || value > 1000F)
                throw new InvalidOperationException(label + " should be between 0.001 and 1000.");
            return value;
        }

