        private List<DatabaseCarRow> QueryGarageFavoriteRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            var garageTable = ResolveActiveGarageTable(db);
            if (!db.ColumnExists(garageTable, "IsFavorite"))
                throw new InvalidOperationException(garageTable + ".IsFavorite was not found.");

            var garageSql = EscapeIdentifierForSql(garageTable);
            var hasDataCar = db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id");
            var dataJoin = hasDataCar ? " LEFT JOIN Data_Car data ON data.Id = g.CarId " : string.Empty;
            var yearExpr = hasDataCar && db.ColumnExists("Data_Car", "Year") ? "COALESCE(MAX(data.[Year]), '')" : "''";
            var makeExpr = hasDataCar && db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(MAX(data.[MakeName]), '')" : "''";
            var modelParts = new List<string>();
            if (hasDataCar && db.ColumnExists("Data_Car", "DisplayName"))
                modelParts.Add("MAX(data.[DisplayName])");
            if (hasDataCar && db.ColumnExists("Data_Car", "ModelShort"))
                modelParts.Add("MAX(data.[ModelShort])");
            if (hasDataCar && db.ColumnExists("Data_Car", "MediaName"))
                modelParts.Add("MAX(data.[MediaName])");
            modelParts.Add("''");
            var modelExpr = "COALESCE(" + string.Join(", ", modelParts.ToArray()) + ")";
            var piExpr = db.ColumnExists(garageTable, "PerformanceIndex")
                ? "COALESCE(MAX(g.[PerformanceIndex]), " + (hasDataCar && db.ColumnExists("Data_Car", "PerformanceIndex") ? "MAX(data.[PerformanceIndex])" : "0") + ", 0)"
                : (hasDataCar && db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(MAX(data.[PerformanceIndex]), 0)" : "0");
            var classExpr = db.ColumnExists(garageTable, "ClassID")
                ? "COALESCE(MAX(g.[ClassID]), " + (hasDataCar && db.ColumnExists("Data_Car", "ClassID") ? "MAX(data.[ClassID])" : "0") + ", 0)"
                : (hasDataCar && db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(MAX(data.[ClassID]), 0)" : "0");

            var sql =
                "SELECT g.CarId, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", COUNT(*), COALESCE(MAX(g.[IsFavorite]), 0) " +
                "FROM " + garageSql + " g " + dataJoin +
                "WHERE g.CarId IS NOT NULL GROUP BY g.CarId ORDER BY COALESCE(MAX(g.[IsFavorite]), 0) DESC, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ";";

            var rows = new List<DatabaseCarRow>();
            var result = db.Query(sql);
            foreach (var row in result.Rows)
            {
                if (row.Count < 8)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                var year = ToDisplayString(row[1]);
                var make = TranslateCarText(ToDisplayString(row[2]), _carMakeStrings);
                var model = TranslateCarText(ToDisplayString(row[3]), _carNameStrings);
                rows.Add(new DatabaseCarRow(
                    carId,
                    year,
                    make,
                    model,
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    ToDisplayString(row[6]),
                    ToLong(row[7]) > 0 ? "Favorite" : "Normal"));
            }
            return rows;
        }

