        private List<DatabaseCarRow> QueryTrafficEditorRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");
            if (!db.TableExists("TrafficCars") || !db.ColumnExists("TrafficCars", "CarId"))
                throw new InvalidOperationException("TrafficCars.CarId was not found.");

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelParts = new List<string>();
            if (db.ColumnExists("Data_Car", "DisplayName"))
                modelParts.Add("data.[DisplayName]");
            if (db.ColumnExists("Data_Car", "ModelShort"))
                modelParts.Add("data.[ModelShort]");
            if (db.ColumnExists("Data_Car", "MediaName"))
                modelParts.Add("data.[MediaName]");
            modelParts.Add("''");
            var modelExpr = "COALESCE(" + string.Join(", ", modelParts.ToArray()) + ")";
            var piExpr = db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(data.[PerformanceIndex], 0)" : (db.ColumnExists("Data_Car", "PI") ? "COALESCE(data.[PI], 0)" : "0");
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";

