                "SELECT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", " +
                "CASE WHEN traffic.CarId IS NULL THEN 0 ELSE 1 END " +
                "FROM Data_Car data LEFT JOIN TrafficCars traffic ON traffic.CarId = data.Id " +
                "WHERE data.Id IS NOT NULL ORDER BY CASE WHEN traffic.CarId IS NULL THEN 0 ELSE 1 END DESC, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ";";

