        private List<DatabaseCarRow> QueryWheelspinOddsRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");

            var hasBaseRarity = db.ColumnExists("Data_Car", "BaseRarity");
            var hasCarRarity = db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity");
            if (!hasBaseRarity && !hasCarRarity)
                throw new InvalidOperationException("No Data_Car.BaseRarity or CarRarities.Rarity table was found.");

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var piExpr = db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(data.[PerformanceIndex], 0)" : (db.ColumnExists("Data_Car", "PI") ? "COALESCE(data.[PI], 0)" : "0");
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";
            var baseExpr = hasBaseRarity ? "data.[BaseRarity]" : "NULL";
            var rarityExpr = hasCarRarity ? "rarity.[Rarity]" : "NULL";
            var join = hasCarRarity ? " LEFT JOIN CarRarities rarity ON rarity.CarID = data.Id " : string.Empty;
            var sql =
                "SELECT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", " + baseExpr + ", " + rarityExpr + " " +
                "FROM Data_Car data " + join +
                "WHERE data.Id IS NOT NULL ORDER BY data.Id;";

            var rows = new List<DatabaseCarRow>();
            var result = db.Query(sql);
            foreach (var row in result.Rows)
            {
                if (row.Count < 8)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                var baseCommon = !hasBaseRarity || IsCommonRarity(row[6]);
                var rarityCommon = !hasCarRarity || (!IsNullDatabaseValue(row[7]) && IsCommonRarity(row[7]));
                var state = baseCommon && rarityCommon ? "Common" : BuildWheelspinOddsState(hasBaseRarity ? row[6] : null, hasCarRarity ? row[7] : null);
                rows.Add(new DatabaseCarRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    string.Empty,
                    state));
            }
            return rows;
        }

