        private void UpdateWheelspinOddsSwitchButton()
        {
            if (_wheelspinOddsSwitchButton == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateWheelspinOddsSwitchButton);
                return;
            }

            if (_database != null && _database.IsAlive)
            {
                try { _wheelspinOddsOn = HasBestWheelspinBackup(_database) && CountWheelspinOddsMismatch(_database) == 0; }
                catch { }
            }

            _wheelspinOddsSwitchButton.Text = _wheelspinOddsOn ? "Odds ON" : "Odds OFF";
            var modern = _wheelspinOddsSwitchButton as ModernButton;
            if (modern != null)
            {
                if (_wheelspinOddsOn)
                {
                    MakeAccentButton(_wheelspinOddsSwitchButton, AccentGreen);
                }
                else
                {
                    modern.FillColor = SurfaceAlt;
                    modern.HoverColor = Color.FromArgb(38, 47, 63);
                    modern.PressedColor = Color.FromArgb(45, 55, 73);
                    modern.BorderColor = Border;
                    _wheelspinOddsSwitchButton.ForeColor = TextPrimary;
                    modern.Invalidate();
                }
            }
        }

        private void SetSelectedWheelspinOddsCommon(List<int> carIds)
        {
            if (carIds == null || carIds.Count == 0)
                throw new InvalidOperationException("Select one or more rarity rows first.");

            var db = RequireDatabase();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");
            var idsSql = BuildIntegerInList(carIds);
            var mismatchBefore = CountSelectedWheelspinOddsMismatch(db, carIds);
            var touched = 0;

            if (db.ColumnExists("Data_Car", "BaseRarity"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_BestWheelspin_DataCar AS SELECT Id, BaseRarity FROM Data_Car;");
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET BaseRarity = 0 WHERE Id IN (" + idsSql + ") AND (BaseRarity IS NULL OR CAST(BaseRarity AS REAL) <> 0);");
                touched++;
            }

            if (db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_BestWheelspin_CarRarities AS SELECT * FROM CarRarities;");
                ExecuteAutoshowSql(db, "INSERT INTO CarRarities (CarID, Rarity) SELECT Id, 0 FROM Data_Car WHERE Id IN (" + idsSql + ") AND NOT EXISTS (SELECT 1 FROM CarRarities WHERE CarRarities.CarID = Data_Car.Id);");
                ExecuteAutoshowSql(db, "UPDATE CarRarities SET Rarity = 0 WHERE CarID IN (" + idsSql + ") AND (Rarity IS NULL OR Rarity <> 0);");
                touched++;
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported wheelspin rarity columns were found.");

            var mismatchAfter = CountSelectedWheelspinOddsMismatch(db, carIds);
            if (mismatchAfter > 0)
                throw new InvalidOperationException("Selected Wheelspin Odds verification failed: " + mismatchAfter.ToString(CultureInfo.InvariantCulture) + " selected row(s) are still not common.");

            _wheelspinOddsOn = HasBestWheelspinBackup(db) && CountWheelspinOddsMismatch(db) == 0;
            UpdateWheelspinOddsSwitchButton();
            LoadWheelspinOddsRows();
            ShowInfo("Selected wheelspin odds set to common." + Environment.NewLine + Environment.NewLine +
                "Selected non-common before: " + mismatchBefore.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Selected non-common after: " + mismatchAfter.ToString(CultureInfo.InvariantCulture));
        }

