        private List<WheelspinAddPreviewRow> BuildWheelspinAddPreviewRows()
        {
            var db = RequireDatabase();
            var rows = _wheelspinOddsRows != null && _wheelspinOddsRows.Count > 0
                ? _wheelspinOddsRows
                : QueryWheelspinOddsRows(db);
            var garageTable = ResolveOptionalGarageTable(db);
            var garageSql = string.IsNullOrEmpty(garageTable) ? string.Empty : EscapeIdentifierForSql(garageTable);
            var result = new List<WheelspinAddPreviewRow>();
            foreach (var row in rows.Where(row => row != null && row.CarId > 0).GroupBy(row => row.CarId).Select(group => group.First()))
            {
                var owned = string.IsNullOrEmpty(garageSql)
                    ? 0
                    : (db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + row.CarId.ToString(CultureInfo.InvariantCulture)) ?? 0);
                result.Add(new WheelspinAddPreviewRow(row.CarId, FormatCarDisplayName(row.CarId, row.Year, row.Make, row.Model), owned));
            }
            return result.OrderBy(row => row.WouldDuplicate ? 0 : 1).ThenBy(row => row.DisplayName).ToList();
        }

        private bool ShowWheelspinAddPreviewDialog(List<WheelspinAddPreviewRow> rows)
        {
            if (InvokeRequired)
                return (bool)Invoke(new Func<List<WheelspinAddPreviewRow>, bool>(ShowWheelspinAddPreviewDialog), rows);

            rows = rows ?? new List<WheelspinAddPreviewRow>();
            var duplicateCount = rows.Count(row => row.WouldDuplicate);
            using (var dialog = new Form())
            {
                dialog.Text = "Add Wheelspin Cars";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.ClientSize = new Size(720, 520);

                var title = new Label();
                title.Text = "Review before adding";
                title.Location = new Point(18, 14);
                title.Size = new Size(684, 26);
                title.Font = new Font("Segoe UI Semibold", 12F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                dialog.Controls.Add(title);

                var note = new Label();
                note.Text = duplicateCount.ToString(CultureInfo.InvariantCulture) + " car(s) are already in your garage and may become duplicates. Red = duplicate, green = safe add.";
                note.Location = new Point(18, 44);
                note.Size = new Size(684, 34);
                note.Font = new Font("Segoe UI", 9F);
                note.ForeColor = duplicateCount > 0 ? AccentRed : AccentGreen;
                note.BackColor = AppBackground;
                dialog.Controls.Add(note);

                var grid = BuildReadOnlyGrid();
                grid.Location = new Point(18, 86);
                grid.Size = new Size(684, 378);
                grid.Anchor = AnchorStyles.Left | AnchorStyles.Top | AnchorStyles.Right | AnchorStyles.Bottom;
                grid.Columns.Add("CarId", "Car ID");
                grid.Columns.Add("Car", "Wheelspin Car");
                grid.Columns.Add("Owned", "Owned");
                grid.Columns.Add("Result", "Result");
                grid.Columns["CarId"].FillWeight = 12F;
                grid.Columns["Car"].FillWeight = 52F;
                grid.Columns["Owned"].FillWeight = 12F;
                grid.Columns["Result"].FillWeight = 24F;
                foreach (var row in rows)
                {
                    var index = grid.Rows.Add(
                        row.CarId.ToString(CultureInfo.InvariantCulture),
                        row.DisplayName,
                        row.OwnedCopies.ToString(CultureInfo.InvariantCulture),
                        row.WouldDuplicate ? "Duplicate warning" : "Safe add");
                    grid.Rows[index].DefaultCellStyle.ForeColor = row.WouldDuplicate ? AccentRed : AccentGreen;
                    grid.Rows[index].DefaultCellStyle.SelectionForeColor = grid.Rows[index].DefaultCellStyle.ForeColor;
                }
                dialog.Controls.Add(grid);

                var cancel = MakeButton("Cancel", 488, 478, 96, 32);
                cancel.Anchor = AnchorStyles.Right | AnchorStyles.Bottom;
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                var confirm = MakeButton("Add Cars", 600, 478, 102, 32);
                confirm.Anchor = AnchorStyles.Right | AnchorStyles.Bottom;
                MakeAccentButton(confirm, duplicateCount > 0 ? AccentRed : AccentGreen);
                confirm.DialogResult = DialogResult.OK;
                dialog.Controls.Add(confirm);
                dialog.AcceptButton = confirm;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

        private void AddWheelspinOddsCars(List<WheelspinAddPreviewRow> preview)
        {
            preview = preview ?? new List<WheelspinAddPreviewRow>();
            if (preview.Count == 0)
                throw new InvalidOperationException("No wheelspin odds cars were found.");

            var db = RequireDatabase();
            ApplyAutoshowUnlock(db);
            var requests = preview
                .Where(row => row != null && row.CarId > 0)
                .Select(row => new CarTableGrantRequest(row.CarId, row.DisplayName, 1))
                .ToList();
            var grants = ApplySelectedCarsAddAllGrantBatch(db, requests);
            var duplicateCount = preview.Count(row => row.WouldDuplicate);
            Log("Wheelspin cars queued through Add All style grants: " + grants.Count.ToString(CultureInfo.InvariantCulture) + "; duplicate warnings: " + duplicateCount.ToString(CultureInfo.InvariantCulture) + ".");
            try { LoadCarTablesFromDatabase(db); }
            catch { }
            SetProfileStatus("Wheelspin cars queued");
            ShowInfo("Wheelspin cars queued." + Environment.NewLine + Environment.NewLine +
                "Cars queued: " + grants.Count.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Duplicate warnings: " + duplicateCount.ToString(CultureInfo.InvariantCulture));
        }

        private long CountSelectedWheelspinOddsMismatch(RemoteDatabase db, IEnumerable<int> carIds)
        {
            var idsSql = BuildIntegerInList(carIds);
            long total = 0;
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "BaseRarity"))
                total += db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE Id IN (" + idsSql + ") AND (BaseRarity IS NULL OR CAST(BaseRarity AS REAL) <> 0)") ?? 0;
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id") &&
                db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity"))
            {
                total += db.QueryScalarLong(
                    "SELECT count(*) FROM Data_Car WHERE Id IN (" + idsSql + ") AND (" +
                    "Id NOT IN (SELECT CarID FROM CarRarities WHERE CarID IS NOT NULL) OR " +
                    "Id IN (SELECT CarID FROM CarRarities WHERE Rarity IS NULL OR Rarity <> 0))") ?? 0;
            }
            else if (db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity"))
            {
                total += db.QueryScalarLong("SELECT count(*) FROM CarRarities WHERE CarID IN (" + idsSql + ") AND (Rarity IS NULL OR Rarity <> 0)") ?? 0;
            }
            return total;
        }

