        private List<DatabaseCarRow> QueryRouteRows(RemoteDatabase db)
        {
            if (!db.TableExists("Tracks") || !db.ColumnExists("Tracks", "id"))
                throw new InvalidOperationException("Tracks.id was not found.");

            var nameExpr = BuildTrackNameExpression(db, "track");
            var mediaExpr = db.ColumnExists("Tracks", "MediaName") ? "COALESCE(track.[MediaName], '')" : "''";
            var lengthExpr = db.ColumnExists("Tracks", "Length") ? "COALESCE(track.[Length], 0)" : "0";
            var environmentExpr = db.ColumnExists("Tracks", "EnvironmentId") ? "COALESCE(track.[EnvironmentId], 0)" : "0";
            var environmentJoin = db.ColumnExists("Tracks", "EnvironmentId") && db.TableExists("Environments") && db.ColumnExists("Environments", "Id")
                ? " LEFT JOIN Environments env ON env.Id = track.EnvironmentId "
                : string.Empty;
            var openExpr = BuildTrackOpenExpression(db, "track", string.IsNullOrEmpty(environmentJoin) ? null : "env");
            var sql =
                "SELECT track.id, " + nameExpr + ", " + mediaExpr + ", " + lengthExpr + ", " + environmentExpr + ", CASE WHEN " + openExpr + " THEN 1 ELSE 0 END " +
                "FROM Tracks track " + environmentJoin +
                "WHERE track.id IS NOT NULL ORDER BY CASE WHEN " + openExpr + " THEN 0 ELSE 1 END, track.id;";

            var rows = new List<DatabaseCarRow>();
            var result = db.Query(sql);
            foreach (var row in result.Rows)
            {
                if (row.Count < 6)
                    continue;
                var id = ToInt(row[0]);
                if (id <= 0)
                    continue;
                var routeName = CleanRouteName(ToDisplayString(row[1]), ToDisplayString(row[2]), id);
                rows.Add(new DatabaseCarRow(
                    id,
                    "Route " + id.ToString(CultureInfo.InvariantCulture),
                    "Route",
                    routeName,
                    FormatCarNumber(row[3]),
                    "Env " + ToDisplayString(row[4]),
                    CleanCarText(ToDisplayString(row[2])),
                    ToLong(row[5]) > 0 ? "Open" : "Locked"));
            }
            return rows;
        }

