        private void UnlockSelectedRoutes(List<int> routeIds)
        {
            if (routeIds == null || routeIds.Count == 0)
                throw new InvalidOperationException("Select one or more locked routes first.");

            var db = RequireDatabase();
            var lockedBefore = CountSelectedLockedRoutesAndTracks(db, routeIds);
            var touched = ApplySelectedRouteAndTrackUnlocks(db, routeIds);
            if (touched == 0)
                throw new InvalidOperationException("No supported route columns were found.");
            var lockedAfter = CountSelectedLockedRoutesAndTracks(db, routeIds);
            if (lockedAfter > 0)
                throw new InvalidOperationException("Selected Route verification failed: " + lockedAfter.ToString(CultureInfo.InvariantCulture) + " selected route row(s) are still locked.");
            LoadRouteRows();
            SetProfileStatus("Selected routes unlocked");
            ShowInfo("Selected routes unlocked." + Environment.NewLine + Environment.NewLine +
                "Locked before: " + lockedBefore.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Locked after: " + lockedAfter.ToString(CultureInfo.InvariantCulture));
        }

        private int ApplySelectedRouteAndTrackUnlocks(RemoteDatabase db, IEnumerable<int> routeIds)
        {
            var idsSql = BuildIntegerInList(routeIds);
            var touched = 0;
            if (db.TableExists("Tracks") && db.ColumnExists("Tracks", "id"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "Tracks", sets, "Active", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "Renderable", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "IsInstalled", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "IsPurchased", "1");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_Tracks AS SELECT * FROM Tracks;");
                    ExecuteAutoshowSql(db, "UPDATE Tracks SET " + string.Join(", ", sets.Values.ToArray()) + " WHERE id IN (" + idsSql + ");");
                    touched++;
                }
            }

            if (db.TableExists("Environments") && db.ColumnExists("Environments", "ShowOnMap") &&
                db.TableExists("Tracks") && db.ColumnExists("Tracks", "EnvironmentId"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_Environments AS SELECT * FROM Environments;");
                ExecuteAutoshowSql(db, "UPDATE Environments SET ShowOnMap = 1 WHERE Id IN (SELECT EnvironmentId FROM Tracks WHERE id IN (" + idsSql + ") AND EnvironmentId IS NOT NULL);");
                touched++;
            }

            ApplySelectedRouteContentGates(db, idsSql);
            return touched;
        }

        private void ApplySelectedRouteContentGates(RemoteDatabase db, string idsSql)
        {
            if (string.IsNullOrWhiteSpace(idsSql) || !db.TableExists("Tracks") || !db.ColumnExists("Tracks", "ContentId"))
                return;

            var contentFilter = "CAST(ContentId AS INTEGER) IN (SELECT ContentId FROM Tracks WHERE id IN (" + idsSql + ") AND ContentId IS NOT NULL)";
            if (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE " + contentFilter + " AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE " + contentFilter + " AND (Quantity IS NULL OR Quantity < 1);");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE " + contentFilter + " AND (IsPromo IS NULL OR IsPromo <> 0);");
            }

            if (db.TableExists("ContentOffers") &&
                db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffers", "Id") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "ContentOffers", sets, "Visible", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsPurchased", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsFree", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsNew", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "ShouldUpsell", "0");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_ContentOffers AS SELECT * FROM ContentOffers;");
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", sets.Values.ToArray()) + " WHERE Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE " + contentFilter + ");");
                }
            }
        }

        private long CountSelectedLockedRoutesAndTracks(RemoteDatabase db, IEnumerable<int> routeIds)
        {
            var idsSql = BuildIntegerInList(routeIds);
            long total = 0;
            if (db.TableExists("Tracks") && db.ColumnExists("Tracks", "id"))
            {
                var flags = new[] { "Active", "Renderable", "IsInstalled", "IsPurchased" }
                    .Where(column => db.ColumnExists("Tracks", column))
                    .ToList();
                if (flags.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM Tracks WHERE id IN (" + idsSql + ") AND (" + BuildNotOneWhere(flags) + ")") ?? 0;
            }

            if (db.TableExists("Environments") && db.ColumnExists("Environments", "ShowOnMap") &&
                db.TableExists("Tracks") && db.ColumnExists("Tracks", "EnvironmentId"))
            {
                total += db.QueryScalarLong("SELECT count(*) FROM Environments WHERE Id IN (SELECT EnvironmentId FROM Tracks WHERE id IN (" + idsSql + ") AND EnvironmentId IS NOT NULL) AND (ShowOnMap IS NULL OR ShowOnMap <> 1)") ?? 0;
            }
            return total;
        }

