        private void CompleteSelectedRaceRows(List<int> raceRouteIds)
        {
            if (raceRouteIds == null || raceRouteIds.Count == 0)
                throw new InvalidOperationException("Select one or more race rows first.");

            var db = RequireDatabase();
            var lockedBefore = CountSelectedLockedRoutesAndTracks(db, raceRouteIds);
            var touched = ApplySelectedRouteAndTrackUnlocks(db, raceRouteIds);
            touched += ApplyClassRestrictionUnlocks(db);
            if (touched == 0)
                throw new InvalidOperationException("No supported race route columns were found.");
