        private List<DatabaseCarRow> QueryFreePriceRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");
            var priceColumns = GetSupportedPriceColumns(db, "Data_Car");
            if (priceColumns.Count == 0)
                throw new InvalidOperationException("No supported Data_Car price column was found.");

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var piExpr = db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(data.[PerformanceIndex], 0)" : (db.ColumnExists("Data_Car", "PI") ? "COALESCE(data.[PI], 0)" : "0");
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";
            var priceExpr = BuildPriceDisplayExpression(priceColumns, "data");
            var nonFreeWhere = BuildPriceNonZeroWhere(priceColumns, "data");
            var sql =
                "SELECT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", " + priceExpr + ", CASE WHEN " + nonFreeWhere + " THEN 1 ELSE 0 END " +
                "FROM Data_Car data WHERE data.Id IS NOT NULL ORDER BY CASE WHEN " + nonFreeWhere + " THEN 0 ELSE 1 END, data.Id;";

            var rows = new List<DatabaseCarRow>();
            var result = db.Query(sql);
            foreach (var row in result.Rows)
            {
                if (row.Count < 8)
                    continue;
                var carId = ToInt(row[0]);
                if (carId <= 0)
                    continue;
                rows.Add(new DatabaseCarRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    FormatCarNumber(row[6]),
                    ToLong(row[7]) > 0 ? "Priced" : "Free"));
            }
            return rows;
        }

