        private void ApplySelectedFreeCarPrices(List<int> carIds)
        {
            if (carIds == null || carIds.Count == 0)
                throw new InvalidOperationException("Select one or more priced cars first.");

            var db = RequireDatabase();
            var idsSql = BuildIntegerInList(carIds);
            var before = CountSelectedNonFreePrices(db, carIds);
            var touched = new List<string>();

            ApplyFreePriceColumnSet(db, "Data_Car", "_backup_Database_FreeCarPrices_DataCar", "Id IN (" + idsSql + ")", GetPriceColumnCandidates(), touched);
            if (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                var mappingWhere = (db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType = 1 AND " : string.Empty) + "CAST(ContentId AS INTEGER) IN (" + idsSql + ")";
                ApplyFreePriceColumnSet(db, "ContentOffersMapping", "_backup_Database_FreeCarPrices_ContentOffersMapping", mappingWhere, GetPriceColumnCandidates(), touched);
            }
            if (db.TableExists("ContentOffers") &&
                db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffers", "Id") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                var offerWhere = "Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE CAST(ContentId AS INTEGER) IN (" + idsSql + ")" +
                    (db.ColumnExists("ContentOffersMapping", "ContentType") ? " AND ContentType = 1" : string.Empty) + ")";
                ApplyFreePriceColumnSet(db, "ContentOffers", "_backup_Database_FreeCarPrices_ContentOffers", offerWhere, GetPriceColumnCandidates(), touched);
            }

            if (touched.Count == 0)
                throw new InvalidOperationException("No supported selected car price columns were found.");
            var after = CountSelectedNonFreePrices(db, carIds);
            if (after > 0)
                throw new InvalidOperationException("Selected Free Price verification failed: " + after.ToString(CultureInfo.InvariantCulture) + " selected price row(s) are still not free.");

            LoadFreePriceRows();
            SetProfileStatus("Selected prices free");
            ShowInfo("Selected car prices are free." + Environment.NewLine + Environment.NewLine +
                "Priced before: " + before.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Priced after: " + after.ToString(CultureInfo.InvariantCulture));
        }

        private long CountSelectedNonFreePrices(RemoteDatabase db, IEnumerable<int> carIds)
        {
            var idsSql = BuildIntegerInList(carIds);
            long total = 0;
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id"))
            {
                var columns = GetSupportedPriceColumns(db, "Data_Car");
                if (columns.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE Id IN (" + idsSql + ") AND (" + BuildPriceNonZeroWhere(columns, null) + ")") ?? 0;
            }

            if (db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "ContentId"))
            {
                var columns = GetSupportedPriceColumns(db, "ContentOffersMapping");
                if (columns.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM ContentOffersMapping WHERE CAST(ContentId AS INTEGER) IN (" + idsSql + ")" +
                        (db.ColumnExists("ContentOffersMapping", "ContentType") ? " AND ContentType = 1" : string.Empty) +
                        " AND (" + BuildPriceNonZeroWhere(columns, null) + ")") ?? 0;
            }

            return total;
        }

