        private List<DatabaseCarRow> QueryDriveTrafficRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            EnsureTrafficCarsTable(db);
            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var piExpr = db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(data.[PerformanceIndex], 0)" : "0";
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";
            var installedExpr = db.ColumnExists("Data_Car", "IsInstalled") ? "COALESCE(data.[IsInstalled], 0)" : "1";
            var purchasedExpr = db.ColumnExists("Data_Car", "IsPurchased") ? "COALESCE(data.[IsPurchased], 0)" : "1";
            var drivableExpr = db.ColumnExists("Data_Car", "IsDrivable") ? "COALESCE(data.[IsDrivable], 0)" : "1";
            var hiddenExpr = db.ColumnExists("Data_Car", "NotAvailableInAutoshow") ? "COALESCE(data.[NotAvailableInAutoshow], 0)" : "0";
            var ownedOnlyExpr = db.ColumnExists("Data_Car", "VisibleOnlyIfOwned") ? "COALESCE(data.[VisibleOnlyIfOwned], 0)" : "0";
            var sql =
                "SELECT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", " +
                installedExpr + ", " + purchasedExpr + ", " + drivableExpr + ", " + hiddenExpr + ", " + ownedOnlyExpr + " " +
                "FROM TrafficCars traffic JOIN Data_Car data ON data.Id = traffic.CarId WHERE traffic.CarId IS NOT NULL ORDER BY data.Id;";
            var rows = new List<DatabaseCarRow>();
            foreach (var row in db.Query(sql).Rows)
            {
                if (row.Count < 11)
                    continue;
                var carId = ToInt(row[0]);
                var installed = ToLong(row[6]) == 1;
                var purchased = ToLong(row[7]) == 1;
                var drivable = ToLong(row[8]) == 1;
                var visible = ToLong(row[9]) == 0 && ToLong(row[10]) == 0;
                var ready = installed && purchased && drivable && visible;
                rows.Add(new DatabaseCarRow(
                    carId,
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    "Traffic",
                    ready ? "Drivable" : BuildFlagSummary(installed, purchased, drivable, visible)));
            }
            return rows;
        }

