        private List<DatabaseCarRow> QueryBarnFindRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            var idSql = BuildBarnFindIdSourceSql(db);
            if (string.IsNullOrWhiteSpace(idSql))
                throw new InvalidOperationException("No supported barn-find table was found.");

            var hasDataCar = db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id");
            var garageTable = ResolveOptionalGarageTable(db);
            var rows = new List<DatabaseCarRow>();
            foreach (var source in db.Query(idSql).Rows)
            {
                if (source.Count == 0)
                    continue;
                var carId = ToInt(source[0]);
                if (carId <= 0)
                    continue;

                var car = hasDataCar ? QuerySingleDataCarRow(db, carId) : null;
                var state = QueryBarnFindState(db, carId);
                var vin = QueryBarnFindVin(db, carId);
                var garageCount = string.IsNullOrEmpty(garageTable)
                    ? 0
                    : (db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(garageTable) + " WHERE CarId = " + carId.ToString(CultureInfo.InvariantCulture)) ?? 0);
                var complete = state >= 5 && garageCount > 0;
                rows.Add(new DatabaseCarRow(
                    carId,
                    car == null ? string.Empty : car.Year,
                    car == null ? string.Empty : car.Make,
                    car == null ? "Barn Find " + carId.ToString(CultureInfo.InvariantCulture) : car.Model,
                    "State " + state.ToString(CultureInfo.InvariantCulture),
                    "Garage " + garageCount.ToString(CultureInfo.InvariantCulture),
                    string.IsNullOrWhiteSpace(vin) ? "No VIN" : "VIN OK",
                    complete ? "Completed" : "Needs Completion"));
            }
            return rows;
        }

