        private List<DatabaseCarRow> QueryDlcGateRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("ContentOffers") || !db.ColumnExists("ContentOffers", "Id"))
                throw new InvalidOperationException("ContentOffers.Id was not found.");

            var displayExpr = db.ColumnExists("ContentOffers", "DisplayName") ? "COALESCE([DisplayName], '')" : "''";
            var subtitleExpr = db.ColumnExists("ContentOffers", "DisplaySubtitle") ? "COALESCE([DisplaySubtitle], '')" : "''";
            var packageExpr = db.ColumnExists("ContentOffers", "PackageName") ? "COALESCE([PackageName], '')" : "''";
            var styleExpr = db.ColumnExists("ContentOffers", "Style") ? "COALESCE([Style], '')" : "''";
            var devCenterExpr = db.ColumnExists("ContentOffers", "DevCenterId") ? "COALESCE([DevCenterId], '')" : "''";
            var imageExpr = db.ColumnExists("ContentOffers", "ImagePath") ? "COALESCE([ImagePath], '')" : "''";
            var visibleExpr = db.ColumnExists("ContentOffers", "Visible") ? "COALESCE([Visible], 0)" : "1";
            var purchasedExpr = db.ColumnExists("ContentOffers", "IsPurchased") ? "COALESCE([IsPurchased], 0)" : "1";
            var freeExpr = db.ColumnExists("ContentOffers", "IsFree") ? "COALESCE([IsFree], 0)" : "1";
            var upsellExpr = db.ColumnExists("ContentOffers", "ShouldUpsell") ? "COALESCE([ShouldUpsell], 0)" : "0";
            var sql = "SELECT [Id], " + displayExpr + ", " + subtitleExpr + ", " + packageExpr + ", " + styleExpr + ", " + devCenterExpr + ", " + imageExpr + ", " + visibleExpr + ", " + purchasedExpr + ", " + freeExpr + ", " + upsellExpr + " FROM ContentOffers ORDER BY [Id];";
            var rows = new List<DatabaseCarRow>();
            foreach (var row in db.Query(sql).Rows)
            {
                if (row.Count < 11)
                    continue;
                var id = ToInt(row[0]);
                var display = ToDisplayString(row[1]);
                var subtitle = ToDisplayString(row[2]);
                var package = ToDisplayString(row[3]);
                var style = ToDisplayString(row[4]);
                var devCenter = ToDisplayString(row[5]);
                var image = ToDisplayString(row[6]);
                var visible = ToLong(row[7]) == 1;
                var purchased = ToLong(row[8]) == 1;
                var free = ToLong(row[9]) == 1;
                var noUpsell = ToLong(row[10]) == 0;
                var blockedMappings = CountBlockedContentMappings(db, id);
                var carSummary = QueryDlcGateMappedCarSummary(db, id, 4);
                var contentName = BuildDlcGateReadableName(id, display, subtitle, package, style, devCenter, image, carSummary);
                var typeName = string.IsNullOrWhiteSpace(carSummary) ? BuildDlcGateTypeName(style) : "Cars";
                var packageName = BuildDlcGatePackageText(package, style, devCenter);
                var open = visible && purchased && free && noUpsell && blockedMappings == 0;
                rows.Add(new DatabaseCarRow(
                    id,
                    typeName,
                    contentName,
                    packageName,
                    "V" + FlagDigit(visible) + " P" + FlagDigit(purchased) + " F" + FlagDigit(free),
                    blockedMappings == 0 ? "Ready" : blockedMappings.ToString(CultureInfo.InvariantCulture) + " gated",
                    noUpsell ? "Released" : "Upsell",
                    open ? "Open" : "Blocked"));
            }
            return rows;
        }

        private string QueryDlcGateMappedCarSummary(RemoteDatabase db, int offerId, int maxNames)
        {
            if (db == null ||
                offerId < 0 ||
                !db.TableExists("ContentOffersMapping") ||
                !db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType") ||
                !db.TableExists("Data_Car") ||
                !db.ColumnExists("Data_Car", "Id"))
                return string.Empty;

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var match = "CAST(map.[ContentId] AS INTEGER) = data.[Id]";
            if (db.ColumnExists("Data_Car", "ContentId"))
                match += " OR (data.[ContentId] IS NOT NULL AND CAST(data.[ContentId] AS INTEGER) > 0 AND CAST(data.[ContentId] AS INTEGER) <> 99 AND CAST(map.[ContentId] AS INTEGER) = CAST(data.[ContentId] AS INTEGER))";

            var offerSql = offerId.ToString(CultureInfo.InvariantCulture);
            var names = new List<string>();
            var sql =
                "SELECT DISTINCT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + " " +
                "FROM ContentOffersMapping map JOIN Data_Car data ON (" + match + ") " +
                "WHERE map.OfferId = " + offerSql + " AND map.ContentType = 1 " +
                "ORDER BY data.[Id] LIMIT " + Math.Max(1, maxNames).ToString(CultureInfo.InvariantCulture) + ";";
            foreach (var row in db.Query(sql).Rows)
            {
                if (row.Count < 4)
                    continue;

                var year = ToDisplayString(row[1]);
                var make = TranslateCarText(ToDisplayString(row[2]), _carMakeStrings);
                var model = TranslateCarText(ToDisplayString(row[3]), _carNameStrings);
                var name = (year + " " + make + " " + model).Trim();
                if (!string.IsNullOrWhiteSpace(name) && !names.Contains(name))
                    names.Add(name);
            }

            if (names.Count == 0)
                return string.Empty;

            var countSql =
                "SELECT COUNT(DISTINCT data.Id) " +
                "FROM ContentOffersMapping map JOIN Data_Car data ON (" + match + ") " +
                "WHERE map.OfferId = " + offerSql + " AND map.ContentType = 1;";
            var total = db.QueryScalarLong(countSql) ?? names.Count;
            var summary = string.Join(", ", names.ToArray());
            if (total > names.Count)
                summary += " +" + (total - names.Count).ToString(CultureInfo.InvariantCulture) + " more";
            return summary;
        }

        private static string BuildDlcGateReadableName(int id, string display, string subtitle, string package, string style, string devCenter, string image, string carSummary)
        {
            if (!string.IsNullOrWhiteSpace(carSummary))
                return carSummary;

            foreach (var candidate in new[] { display, subtitle, package, style, image, devCenter })
            {
                var readable = CleanReadableText(candidate);
                if (!string.IsNullOrWhiteSpace(readable))
                    return readable;
            }

            return "Content Offer " + id.ToString(CultureInfo.InvariantCulture);
        }

        private static string BuildDlcGateTypeName(string style)
        {
            var readable = CleanReadableText(style);
            return string.IsNullOrWhiteSpace(readable) ? "Content" : SplitReadableToken(readable);
        }

        private static string BuildDlcGatePackageText(string package, string style, string devCenter)
        {
            foreach (var candidate in new[] { package, style, devCenter })
            {
                var readable = CleanReadableText(candidate);
                if (!string.IsNullOrWhiteSpace(readable))
                    return SplitReadableToken(readable);
            }

            return "Content Offer";
        }

        private static string CleanReadableText(string text)
        {
            var cleaned = CleanCarText(text);
            if (string.IsNullOrWhiteSpace(cleaned) || cleaned.StartsWith("_&", StringComparison.Ordinal))
                return string.Empty;

            try
            {
                if (cleaned.IndexOf('\\') >= 0 || cleaned.IndexOf('/') >= 0)
                    cleaned = Path.GetFileNameWithoutExtension(cleaned);
            }
            catch
            {
            }

            cleaned = cleaned.Replace('_', ' ').Replace('-', ' ').Trim();
            foreach (var suffix in new[] { " Large", " Small", " Feature" })
            {
                if (cleaned.EndsWith(suffix, StringComparison.OrdinalIgnoreCase))
                    cleaned = cleaned.Substring(0, cleaned.Length - suffix.Length).Trim();
            }
            return cleaned;
        }

        private static string SplitReadableToken(string text)
        {
            text = CleanReadableText(text);
            if (string.IsNullOrWhiteSpace(text))
                return string.Empty;

            var builder = new StringBuilder();
            for (var i = 0; i < text.Length; i++)
            {
                var ch = text[i];
                if (i > 0 && char.IsUpper(ch) && !char.IsWhiteSpace(text[i - 1]) && !char.IsUpper(text[i - 1]))
                    builder.Append(' ');
                builder.Append(ch);
            }
            return builder.ToString().Trim();
        }

