        private List<DatabaseCarRow> QueryUnobtainableRows(RemoteDatabase db)
        {
            EnsureCarStringTablesLoaded();
            if (!db.TableExists("UnobtainableCars") || !db.ColumnExists("UnobtainableCars", "Ordinal"))
                throw new InvalidOperationException("UnobtainableCars.Ordinal was not found.");

            var rows = new List<DatabaseCarRow>();
            foreach (var row in db.Query("SELECT Ordinal FROM UnobtainableCars ORDER BY Ordinal;").Rows)
            {
                if (row.Count == 0)
                    continue;
                var ordinal = ToLong(row[0]);
                var carIdLong = ordinal >= 0 ? ordinal : (-1000000000L - ordinal);
                var carId = carIdLong > 0 && carIdLong <= int.MaxValue ? (int)carIdLong : 0;
                var car = carId > 0 ? QuerySingleDataCarRow(db, carId) : null;
                rows.Add(new DatabaseCarRow(
                    carId,
                    ordinal < 0 ? "Moved" : "Gate",
                    car == null ? string.Empty : car.Make,
                    car == null ? "Ordinal " + ordinal.ToString(CultureInfo.InvariantCulture) : car.Model,
                    car == null ? string.Empty : car.PerformanceIndex,
                    car == null ? string.Empty : car.ClassId,
                    ordinal.ToString(CultureInfo.InvariantCulture),
                    ordinal < 0 ? "Open" : "Blocked"));
            }
            return rows;
        }

