        private void ApplyDatabaseStatusPageFilter(Panel page)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ApplyDatabaseStatusPageFilter(page); }));
                return;
            }

            if (page == _driveTrafficPage)
            {
                ApplyTwoGridFilter(_driveTrafficRows, _driveTrafficSearch, _driveTrafficReadyGrid, _driveTrafficNeedsGrid, "Drivable");
                return;
            }
            if (page == _barnFindsPage)
            {
                ApplyTwoGridFilter(_barnFindRows, _barnFindsSearch, _barnFindsCompleteGrid, _barnFindsNeedsGrid, "Completed");
                return;
            }
            if (page == _dlcGatesPage)
            {
                ApplyTwoGridFilter(_dlcGateRows, _dlcGatesSearch, _dlcGatesOpenGrid, _dlcGatesBlockedGrid, "Open");
                return;
            }
            if (page == _unobtainablePage)
            {
                ApplyTwoGridFilter(_unobtainableRows, _unobtainableSearch, _unobtainableOpenGrid, _unobtainableBlockedGrid, "Open");
                return;
            }
            if (page == _unlockPresetsPage)
            {
                ApplyTwoGridFilter(_unlockPresetRows, _unlockPresetsSearch, _unlockPresetsOpenGrid, _unlockPresetsLockedGrid, "Purchasable");
                return;
            }
            if (page == _newTagsPage)
            {
                ApplyTwoGridFilter(_newTagRows, _newTagsSearch, _newTagsClearGrid, _newTagsTaggedGrid, "Clear");
                return;
            }
            if (page == _installFlagsPage)
                ApplyTwoGridFilter(_installFlagRows, _installFlagsSearch, _installFlagsReadyGrid, _installFlagsNeedsGrid, "Ready");
        }

        private void SetDatabaseStatusRows(Panel page, List<DatabaseCarRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetDatabaseStatusRows(page, rows); }));
                return;
            }

            if (page == _driveTrafficPage)
                _driveTrafficRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _barnFindsPage)
                _barnFindRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _dlcGatesPage)
                _dlcGateRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _unobtainablePage)
                _unobtainableRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _unlockPresetsPage)
                _unlockPresetRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _newTagsPage)
                _newTagRows = rows ?? new List<DatabaseCarRow>();
            else if (page == _installFlagsPage)
                _installFlagRows = rows ?? new List<DatabaseCarRow>();

            ApplyDatabaseStatusPageFilter(page);
        }

        private void ApplyTwoGridFilter(List<DatabaseCarRow> rows, TextBox search, DataGridView readyGrid, DataGridView needsGrid, string readyState)
        {
            var source = rows ?? new List<DatabaseCarRow>();
            var filter = search == null ? string.Empty : search.Text;
            var filtered = FilterDatabaseCarRows(source, filter);
            SetDatabaseCarGridRows(readyGrid, filtered.Where(row => string.Equals(row.State, readyState, StringComparison.OrdinalIgnoreCase)).ToList());
            SetDatabaseCarGridRows(needsGrid, filtered.Where(row => !string.Equals(row.State, readyState, StringComparison.OrdinalIgnoreCase)).ToList());
            SetProfileStatus(filtered.Count.ToString(CultureInfo.InvariantCulture) + "/" + source.Count.ToString(CultureInfo.InvariantCulture) + " rows");
        }

