        private void ApplySelectedDlcGatesFromPage()
        {
            var ids = GetSelectedDatabaseCarIds(_dlcGatesBlockedGrid);
            if (ids.Count == 0)
                throw new InvalidOperationException("Select one or more blocked DLC/content rows first.");

            try
            {
                ApplySelectedDlcGateIds(ids, "selected");
            }
            catch (Exception ex)
            {
                if (!IsRemoteSqlThreadTimeout(ex))
                    throw;
                LogDlcGateTimeoutAsApplied("selected apply", ex);
                MarkDlcGateRowsOpenLocally(ids);
            }
            TryReloadDlcGateRowsAfterApply();
        }

        private void ApplyAllDlcGatesFromPage()
        {
            var ids = (_dlcGateRows ?? new List<DatabaseCarRow>())
                .Where(row => row != null && !string.Equals(row.State, "Open", StringComparison.OrdinalIgnoreCase) && row.CarId > 0)
                .Select(row => row.CarId)
                .Distinct()
                .ToList();

            if (ids.Count == 0)
            {
                var db = RequireDatabase();
                ids = QueryDlcGateRows(db)
                    .Where(row => row != null && !string.Equals(row.State, "Open", StringComparison.OrdinalIgnoreCase) && row.CarId > 0)
                    .Select(row => row.CarId)
                    .Distinct()
                    .ToList();
            }

            if (ids.Count == 0)
                throw new InvalidOperationException("No blocked DLC/content rows were found.");

            try
            {
                ApplyDlcGateIdsInBatches(ids, "all blocked");
            }
            catch (Exception ex)
            {
                if (!IsRemoteSqlThreadTimeout(ex))
                    throw;
                LogDlcGateTimeoutAsApplied("add all", ex);
            }
            MarkDlcGateRowsOpenLocally(ids);
        }

        private void ApplySelectedDlcGateIds(List<int> ids, string label)
        {
            if (ids == null || ids.Count == 0)
                throw new InvalidOperationException("Select one or more blocked DLC/content rows first.");

            var db = RequireDatabase();
            var distinct = ids.Where(id => id > 0).Distinct().ToList();
            if (distinct.Count == 0)
                throw new InvalidOperationException("The selected DLC/content rows did not have valid offer IDs.");

            Log("Adding " + label + " DLC/content gate row(s): " + distinct.Count.ToString(CultureInfo.InvariantCulture) + ".");
            if (distinct.Count > DlcGateBatchSize)
                ApplyDlcGateIdsInBatches(db, distinct, label);
            else
                ApplyDlcGateUnlocks(db, distinct);
            Log("DLC/content gates added: " + distinct.Count.ToString(CultureInfo.InvariantCulture) + ".");
            SetStatus("DLC Gates applied");
            SetProfileStatus("DLC Gates applied");
        }

        private void ApplyDlcGateIdsInBatches(List<int> ids, string label)
        {
            var db = RequireDatabase();
            ApplyDlcGateIdsInBatches(db, ids, label);
        }

        private void ApplyDlcGateIdsInBatches(RemoteDatabase db, List<int> ids, string label)
        {
            if (db == null)
                throw new InvalidOperationException("Not attached.");

            var distinct = (ids ?? new List<int>())
                .Where(id => id > 0)
                .Distinct()
                .ToList();
            if (distinct.Count == 0)
                throw new InvalidOperationException("The selected DLC/content rows did not have valid offer IDs.");

            var batchCount = (distinct.Count + DlcGateBatchSize - 1) / DlcGateBatchSize;
            Log("Adding " + label + " DLC/content gates in " + batchCount.ToString(CultureInfo.InvariantCulture) + " safe batch(es).");
            for (var offset = 0; offset < distinct.Count; offset += DlcGateBatchSize)
            {
                var chunk = distinct.Skip(offset).Take(DlcGateBatchSize).ToList();
                var batchIndex = (offset / DlcGateBatchSize) + 1;
                SetProfileStatus("DLC Gates batch " + batchIndex.ToString(CultureInfo.InvariantCulture) + "/" + batchCount.ToString(CultureInfo.InvariantCulture));
                ApplyDlcGateUnlocks(db, chunk, false, false);
                Log("DLC Gates batch " + batchIndex.ToString(CultureInfo.InvariantCulture) + "/" + batchCount.ToString(CultureInfo.InvariantCulture) +
                    " applied (" + Math.Min(offset + chunk.Count, distinct.Count).ToString(CultureInfo.InvariantCulture) + "/" +
                    distinct.Count.ToString(CultureInfo.InvariantCulture) + ").");
                if (offset + DlcGateBatchSize < distinct.Count)
                    Thread.Sleep(DlcGateBatchPauseMs);
            }

            ApplyAllIeCarInstallFlags(db);
            Log("DLC/content gates added: " + distinct.Count.ToString(CultureInfo.InvariantCulture) + ".");
            SetStatus("DLC Gates applied");
            SetProfileStatus("DLC Gates applied");
        }

        private void MarkDlcGateRowsOpenLocally(IEnumerable<int> ids)
        {
            var idSet = new HashSet<int>((ids ?? Enumerable.Empty<int>()).Where(id => id > 0));
            if (idSet.Count == 0 || _dlcGateRows == null || _dlcGateRows.Count == 0)
                return;

            var rows = _dlcGateRows
                .Select(row => row != null && idSet.Contains(row.CarId)
                    ? new DatabaseCarRow(row.CarId, row.Year, row.Make, row.Model, "V1 P1 F1", "Ready", "Released", "Open")
                    : row)
                .Where(row => row != null)
                .ToList();
            SetDatabaseStatusRows(_dlcGatesPage, rows);
        }

        private void LogDlcGateTimeoutAsApplied(string context, Exception ex)
        {
            Log("DLC Gates " + context + " warning: FH6 remote SQL timed out after the write was sent. Keeping the action marked applied. Details: " + ex.Message);
            SetStatus("DLC Gates applied");
            SetProfileStatus("DLC Gates applied");
        }

        private static bool IsRemoteSqlThreadTimeout(Exception ex)
        {
            while (ex != null)
            {
                if ((ex.Message ?? string.Empty).IndexOf("Remote SQL thread timed out", StringComparison.OrdinalIgnoreCase) >= 0)
                    return true;
                ex = ex.InnerException;
            }
            return false;
        }

        private void TryReloadDlcGateRowsAfterApply()
        {
            try
            {
                LoadDlcGateRows();
            }
            catch (Exception ex)
            {
                Log("DLC Gates applied, but the table refresh was skipped: " + ex.Message);
            }
        }

