        private static string BuildDataCarModelExpression(RemoteDatabase db, string alias)
        {
            var prefix = string.IsNullOrWhiteSpace(alias) ? string.Empty : alias + ".";
            var parts = new List<string>();
            if (db.ColumnExists("Data_Car", "DisplayName"))
                parts.Add(prefix + "[DisplayName]");
            if (db.ColumnExists("Data_Car", "ModelShort"))
                parts.Add(prefix + "[ModelShort]");
            if (db.ColumnExists("Data_Car", "MediaName"))
                parts.Add(prefix + "[MediaName]");
            parts.Add("''");
            return "COALESCE(" + string.Join(", ", parts.ToArray()) + ")";
        }

        private DatabaseCarRow QuerySingleDataCarRow(RemoteDatabase db, int carId)
        {
            if (db == null || !db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id") || carId <= 0)
                return null;

            var yearExpr = db.ColumnExists("Data_Car", "Year") ? "COALESCE(data.[Year], '')" : "''";
            var makeExpr = db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(data.[MakeName], '')" : "''";
            var modelExpr = BuildDataCarModelExpression(db, "data");
            var piExpr = db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(data.[PerformanceIndex], 0)" : "0";
            var classExpr = db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(data.[ClassID], 0)" : "0";
            var result = db.Query("SELECT data.Id, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + " FROM Data_Car data WHERE data.Id = " + carId.ToString(CultureInfo.InvariantCulture) + " LIMIT 1;");
            if (result.Rows.Count == 0 || result.Rows[0].Count < 6)
                return null;

            var row = result.Rows[0];
            return new DatabaseCarRow(
                ToInt(row[0]),
                ToDisplayString(row[1]),
                TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                FormatCarNumber(row[4]),
                FormatCarClassId(ToInt(row[5])),
                string.Empty,
                string.Empty);
        }

        private List<DatabaseCarRow> QueryGarageStatusRows(RemoteDatabase db, string garageTable, string flagColumn, string readyState, string needsState, bool readyWhenOne)
        {
            EnsureCarStringTablesLoaded();
            if (string.IsNullOrWhiteSpace(garageTable) || !db.TableExists(garageTable) || !db.ColumnExists(garageTable, "CarId") || !db.ColumnExists(garageTable, flagColumn))
                throw new InvalidOperationException("Garage table or " + flagColumn + " was not found.");

            var garageSql = EscapeIdentifierForSql(garageTable);
            var hasDataCar = db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id");
            var join = hasDataCar ? " LEFT JOIN Data_Car data ON data.Id = g.CarId " : string.Empty;
            var yearExpr = hasDataCar && db.ColumnExists("Data_Car", "Year") ? "COALESCE(MAX(data.[Year]), '')" : "''";
            var makeExpr = hasDataCar && db.ColumnExists("Data_Car", "MakeName") ? "COALESCE(MAX(data.[MakeName]), '')" : "''";
            var modelExpr = hasDataCar ? BuildGarageDataCarModelExpression(db) : "''";
            var piExpr = db.ColumnExists(garageTable, "PerformanceIndex")
                ? "COALESCE(MAX(g.[PerformanceIndex]), " + (hasDataCar && db.ColumnExists("Data_Car", "PerformanceIndex") ? "MAX(data.[PerformanceIndex])" : "0") + ", 0)"
                : (hasDataCar && db.ColumnExists("Data_Car", "PerformanceIndex") ? "COALESCE(MAX(data.[PerformanceIndex]), 0)" : "0");
            var classExpr = db.ColumnExists(garageTable, "ClassID")
                ? "COALESCE(MAX(g.[ClassID]), " + (hasDataCar && db.ColumnExists("Data_Car", "ClassID") ? "MAX(data.[ClassID])" : "0") + ", 0)"
                : (hasDataCar && db.ColumnExists("Data_Car", "ClassID") ? "COALESCE(MAX(data.[ClassID]), 0)" : "0");
            var flagSql = EscapeIdentifierForSql(flagColumn);
            var sql =
                "SELECT g.CarId, " + yearExpr + ", " + makeExpr + ", " + modelExpr + ", " + piExpr + ", " + classExpr + ", COUNT(*), COALESCE(MAX(g." + flagSql + "), 0) " +
                "FROM " + garageSql + " g " + join + "WHERE g.CarId IS NOT NULL GROUP BY g.CarId ORDER BY COALESCE(MAX(g." + flagSql + "), 0), " + yearExpr + ";";
            var rows = new List<DatabaseCarRow>();
            foreach (var row in db.Query(sql).Rows)
            {
                if (row.Count < 8)
                    continue;
                var ready = readyWhenOne ? ToLong(row[7]) == 1 : ToLong(row[7]) != 1;
                rows.Add(new DatabaseCarRow(
                    ToInt(row[0]),
                    ToDisplayString(row[1]),
                    TranslateCarText(ToDisplayString(row[2]), _carMakeStrings),
                    TranslateCarText(ToDisplayString(row[3]), _carNameStrings),
                    FormatCarNumber(row[4]),
                    FormatCarClassId(ToInt(row[5])),
                    ToDisplayString(row[6]),
                    ready ? readyState : needsState));
            }
            return rows;
        }

        private static string BuildGarageDataCarModelExpression(RemoteDatabase db)
        {
            var parts = new List<string>();
            if (db.ColumnExists("Data_Car", "DisplayName"))
                parts.Add("MAX(data.[DisplayName])");
            if (db.ColumnExists("Data_Car", "ModelShort"))
                parts.Add("MAX(data.[ModelShort])");
            if (db.ColumnExists("Data_Car", "MediaName"))
                parts.Add("MAX(data.[MediaName])");
            parts.Add("''");
            return "COALESCE(" + string.Join(", ", parts.ToArray()) + ")";
        }

        private static string BuildFlagSummary(bool installed, bool purchased, bool drivable, bool visible)
        {
            return "I" + FlagDigit(installed) + " P" + FlagDigit(purchased) + " D" + FlagDigit(drivable) + " V" + FlagDigit(visible);
        }

        private static string CleanRouteName(string displayName, string mediaName, int id)
        {
            var display = CleanCarText(displayName);
            var media = CleanCarText(mediaName);
            if (!string.IsNullOrWhiteSpace(display) && !display.StartsWith("_&", StringComparison.Ordinal))
                return display;
            if (!string.IsNullOrWhiteSpace(media))
                return media.Replace('_', ' ').Trim();
            return "Route " + id.ToString(CultureInfo.InvariantCulture);
        }

        private static string CleanHashedText(string text, string fallback)
        {
            var cleaned = CleanCarText(text);
            if (!string.IsNullOrWhiteSpace(cleaned) && !cleaned.StartsWith("_&", StringComparison.Ordinal))
                return cleaned;
            return string.IsNullOrWhiteSpace(fallback) ? cleaned : fallback;
        }

        private static string BuildPresetFallbackName(string thumbnail, int id)
        {
            var text = CleanCarText(thumbnail);
            if (!string.IsNullOrWhiteSpace(text))
            {
                var slash = Math.Max(text.LastIndexOf('\\'), text.LastIndexOf('/'));
                if (slash >= 0 && slash + 1 < text.Length)
                    text = text.Substring(slash + 1);
                if (text.EndsWith(".png", StringComparison.OrdinalIgnoreCase))
                    text = text.Substring(0, text.Length - 4);
                if (text.StartsWith("preset_", StringComparison.OrdinalIgnoreCase))
                    text = text.Substring("preset_".Length);
                text = text.Replace('_', ' ').Trim();
                if (text.Length > 0)
                    return CultureInfo.InvariantCulture.TextInfo.ToTitleCase(text.ToLowerInvariant()) + " Preset";
            }
            return "Preset " + id.ToString(CultureInfo.InvariantCulture);
        }

        private static string FlagDigit(bool value)
        {
            return value ? "1" : "0";
        }

        private static string BuildBarnFindIdSourceSql(RemoteDatabase db)
        {
            var sources = new List<string>();
            if (db.TableExists("BarnfindCars") && db.ColumnExists("BarnfindCars", "CarId"))
                sources.Add("SELECT CarId AS CarId FROM BarnfindCars WHERE CarId IS NOT NULL");
            if (db.TableExists("Profile0_BarnFinds") && db.ColumnExists("Profile0_BarnFinds", "CarOrdinal"))
                sources.Add("SELECT CarOrdinal AS CarId FROM Profile0_BarnFinds WHERE CarOrdinal IS NOT NULL");
            if (db.TableExists("NewProfile_BarnFinds") && db.ColumnExists("NewProfile_BarnFinds", "CarOrdinal"))
                sources.Add("SELECT CarOrdinal AS CarId FROM NewProfile_BarnFinds WHERE CarOrdinal IS NOT NULL");
            return sources.Count == 0 ? string.Empty : "SELECT DISTINCT CarId FROM (" + string.Join(" UNION ALL ", sources.ToArray()) + ") ORDER BY CarId;";
        }

        private int QueryBarnFindState(RemoteDatabase db, int carId)
        {
            var states = new List<long>();
            foreach (var table in new[] { "Profile0_BarnFinds", "NewProfile_BarnFinds" })
            {
                if (!db.TableExists(table) || !db.ColumnExists(table, "CarOrdinal") || !db.ColumnExists(table, "State"))
                    continue;
                var value = db.QueryScalarLong("SELECT COALESCE(MAX(State), 0) FROM " + EscapeIdentifierForSql(table) + " WHERE CarOrdinal = " + carId.ToString(CultureInfo.InvariantCulture));
                if (value.HasValue)
                    states.Add(value.Value);
            }
            return states.Count == 0 ? 0 : (int)states.Max();
        }

        private string QueryBarnFindVin(RemoteDatabase db, int carId)
        {
            foreach (var table in new[] { "Profile0_BarnFinds", "NewProfile_BarnFinds" })
            {
                if (!db.TableExists(table) || !db.ColumnExists(table, "CarOrdinal") || !db.ColumnExists(table, "VIN"))
                    continue;
                var text = QueryScalarText(db, "SELECT VIN FROM " + EscapeIdentifierForSql(table) + " WHERE CarOrdinal = " + carId.ToString(CultureInfo.InvariantCulture) + " AND VIN IS NOT NULL AND VIN <> '' ORDER BY rowid LIMIT 1");
                if (!string.IsNullOrWhiteSpace(text) && text != "00000000-0000-0000-0000-000000000000")
                    return text;
            }
            return string.Empty;
        }

        private long CountBlockedContentMappings(RemoteDatabase db, int offerId)
        {
            if (!db.TableExists("ContentOffersMapping") || !db.ColumnExists("ContentOffersMapping", "OfferId"))
                return 0;

            var checks = new List<string>();
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                checks.Add("ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00'");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                checks.Add("Quantity IS NULL OR Quantity < 1");
            if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                checks.Add("IsPromo IS NULL OR IsPromo <> 0");
            if (checks.Count == 0)
                return 0;
            return db.QueryScalarLong("SELECT count(*) FROM ContentOffersMapping WHERE OfferId = " + offerId.ToString(CultureInfo.InvariantCulture) + " AND (" + string.Join(" OR ", checks.ToArray()) + ")") ?? 0;
        }

        private static string BuildTrackNameExpression(RemoteDatabase db, string alias)
        {
            var prefix = string.IsNullOrWhiteSpace(alias) ? string.Empty : alias + ".";
            var parts = new List<string>();
            if (db.ColumnExists("Tracks", "DisplayName"))
                parts.Add(prefix + "[DisplayName]");
            if (db.ColumnExists("Tracks", "ShortDisplayName"))
                parts.Add(prefix + "[ShortDisplayName]");
            if (db.ColumnExists("Tracks", "MediaName"))
                parts.Add(prefix + "[MediaName]");
            if (db.ColumnExists("Tracks", "Route"))
                parts.Add(prefix + "[Route]");
            parts.Add("''");
            return "COALESCE(" + string.Join(", ", parts.ToArray()) + ")";
        }

        private static string BuildTrackOpenExpression(RemoteDatabase db, string trackAlias, string environmentAlias)
        {
            var trackPrefix = string.IsNullOrWhiteSpace(trackAlias) ? string.Empty : trackAlias + ".";
            var checks = new List<string>();
            foreach (var column in new[] { "Active", "Renderable", "IsInstalled", "IsPurchased" })
            {
                if (db.ColumnExists("Tracks", column))
                    checks.Add("COALESCE(" + trackPrefix + EscapeIdentifierForSql(column) + ", 0) = 1");
            }

            if (!string.IsNullOrWhiteSpace(environmentAlias) &&
                db.TableExists("Environments") &&
                db.ColumnExists("Environments", "ShowOnMap"))
            {
                checks.Add("COALESCE(" + environmentAlias + ".[ShowOnMap], 1) = 1");
            }

            return checks.Count == 0 ? "1=1" : string.Join(" AND ", checks.ToArray());
        }

        private static bool IsNullDatabaseValue(object value)
        {
            return value == null || value == DBNull.Value || string.IsNullOrWhiteSpace(ToDisplayString(value));
        }

        private static bool IsCommonRarity(object value)
        {
            if (IsNullDatabaseValue(value))
                return false;
            double rarity;
            return TryToDouble(value, out rarity) && rarity <= 0.49D;
        }

        private static string BuildWheelspinOddsState(object baseRarity, object wheelspinRarity)
        {
            return "Base " + FormatRarityShort(baseRarity) + " / Odds " + FormatRarityShort(wheelspinRarity);
        }

        private static string FormatRarityShort(object value)
        {
            if (IsNullDatabaseValue(value))
                return "missing";
            double rarity;
            if (!TryToDouble(value, out rarity))
                return "unknown";
            var name = FormatRarityBandName(rarity);
            var slash = name.IndexOf('/');
            if (slash >= 0)
                name = name.Substring(0, slash).Trim();
            var space = name.IndexOf(' ');
            if (space > 0)
                name = name.Substring(0, space).Trim();
            return name + " " + rarity.ToString("0.#", CultureInfo.InvariantCulture);
        }

        private static string[] GetPriceColumnCandidates()
        {
            return new[]
            {
                "BaseCost",
                "BasePrice",
                "BuyPrice",
                "AutoshowPrice",
                "AutoShowPrice",
                "Price",
                "Cost",
                "CreditCost",
                "CreditsCost"
            };
        }

        private static List<string> GetSupportedPriceColumns(RemoteDatabase db, string tableName)
        {
            return GetPriceColumnCandidates()
                .Where(column => db.TableExists(tableName) && db.ColumnExists(tableName, column))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static string BuildPriceDisplayExpression(IEnumerable<string> columns, string alias)
        {
            var parts = (columns ?? new string[0])
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Select(column => "NULLIF(CAST(" + BuildSqlColumnReference(alias, column) + " AS REAL), 0)")
                .ToList();
            parts.Add("0");
            return "COALESCE(" + string.Join(", ", parts.ToArray()) + ")";
        }

        private static string BuildPriceNonZeroWhere(IEnumerable<string> columns, string alias)
        {
            var checks = (columns ?? new string[0])
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Select(column => "COALESCE(CAST(" + BuildSqlColumnReference(alias, column) + " AS REAL), 0) <> 0")
                .ToList();
            return checks.Count == 0 ? "0=1" : string.Join(" OR ", checks.ToArray());
        }

        private static string BuildSqlColumnReference(string alias, string column)
        {
            return string.IsNullOrWhiteSpace(alias)
                ? EscapeIdentifierForSql(column)
                : alias + "." + EscapeIdentifierForSql(column);
        }

