        private static void SetDatabaseCarGridRows(DataGridView grid, List<DatabaseCarRow> rows)
        {
            if (grid == null)
                return;

            grid.Rows.Clear();
            foreach (var car in rows ?? new List<DatabaseCarRow>())
            {
                var rowIndex = grid.Rows.Add(
                    false,
                    car.CarId.ToString(CultureInfo.InvariantCulture),
                    car.Year,
                    car.Make,
                    car.Model,
                    car.PerformanceIndex,
                    car.ClassId,
                    car.Copies,
                    car.State);
                grid.Rows[rowIndex].Tag = car.CarId;
            }
            ClearCarGridSelection(grid);
        }

        private static List<int> GetSelectedDatabaseCarIds(DataGridView grid)
        {
            var ids = new List<int>();
            if (grid == null)
                return ids;

            if (grid.Columns.Contains("Pick"))
            {
                foreach (DataGridViewRow row in grid.Rows)
                {
                    if (row == null || row.IsNewRow)
                        continue;
                    var value = row.Cells["Pick"].Value;
                    if (!(value is bool) || !(bool)value)
                        continue;
                    int checkedCarId;
                    if (TryGetCarIdFromGridRow(row, out checkedCarId) && checkedCarId > 0 && !ids.Contains(checkedCarId))
                        ids.Add(checkedCarId);
                }
            }

            foreach (DataGridViewRow row in grid.SelectedRows)
            {
                int carId;
                if (TryGetCarIdFromGridRow(row, out carId) && carId > 0 && !ids.Contains(carId))
                    ids.Add(carId);
            }

            if (ids.Count == 0 && grid.CurrentRow != null)
            {
                int carId;
                if (TryGetCarIdFromGridRow(grid.CurrentRow, out carId) && carId > 0)
                    ids.Add(carId);
            }

            return ids;
        }

        private static void ToggleVisibleDatabaseGridChecks(DataGridView grid)
        {
            if (grid == null || !grid.Columns.Contains("Pick"))
                return;

            var rows = grid.Rows.Cast<DataGridViewRow>()
                .Where(row => row != null && row.Visible && !row.IsNewRow)
                .ToList();
            var checkAll = rows.Any(row => !(row.Cells["Pick"].Value is bool) || !(bool)row.Cells["Pick"].Value);
            foreach (var row in rows)
                row.Cells["Pick"].Value = checkAll;
        }

        private static void UpdateDatabaseCarSelectionLabel(DataGridView grid, Label label)
        {
            if (label == null)
                return;

            var ids = GetSelectedDatabaseCarIds(grid);
            label.Text = ids.Count == 0
                ? "Selected: none"
                : "Selected: " + ids.Count.ToString(CultureInfo.InvariantCulture) + " row(s)";
        }

        private void SetSelectedTrafficCars(List<int> carIds, bool inTraffic)
        {
            if (carIds == null || carIds.Count == 0)
                throw new InvalidOperationException("Select one or more cars first.");

            var db = RequireDatabase();
            EnsureTrafficCarsTable(db);
            var idsSql = BuildIntegerInList(carIds);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_TrafficCars AS SELECT * FROM TrafficCars;");
            if (inTraffic)
            {
                ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO TrafficCars (CarId, IsLaunchChunkCar) SELECT Id, 0 FROM Data_Car WHERE Id IN (" + idsSql + ");");
                ApplyTrafficDataCarFlags(db, "Id IN (" + idsSql + ")");
            }
            else
            {
                ExecuteAutoshowSql(db, "DELETE FROM TrafficCars WHERE CarId IN (" + idsSql + ");");
            }

            LogCount(db, "TrafficCars rows", "SELECT count(*) FROM TrafficCars");
            LoadTrafficEditorCars();
        }

        private void ClearTrafficCars()
        {
            var db = RequireDatabase();
            EnsureTrafficCarsTable(db);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_TrafficCars AS SELECT * FROM TrafficCars;");
            ExecuteAutoshowSql(db, "DELETE FROM TrafficCars;");
            LogCount(db, "TrafficCars rows", "SELECT count(*) FROM TrafficCars");
            LoadTrafficEditorCars();
        }

