        private void SetRemoveTrafficSwitchState(bool turnOn)
        {
            var db = RequireDatabase();
            EnsureTrafficCarsTable(db);
            if (turnOn)
            {
                db.SetLiveTrafficRemoved(true);
                try
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RemoveTraffic_TrafficCars AS SELECT * FROM TrafficCars;");
                    ExecuteAutoshowSql(db, "DELETE FROM TrafficCars;");
                    var raceTables = SetRaceTrafficFlags(db, false);
                    var remaining = db.QueryScalarLong("SELECT count(*) FROM TrafficCars") ?? 0;
                    if (remaining != 0)
                        throw new InvalidOperationException("TrafficCars still has " + remaining.ToString(CultureInfo.InvariantCulture) + " row(s).");
                    _removeTrafficSwitchOn = true;
                    Log("Remove Traffic ON. Active traffic was unloaded, new traffic spawning was disabled, and database traffic was backed up and cleared" +
                        (raceTables > 0 ? "; race HasTraffic flags were also disabled in " + raceTables.ToString(CultureInfo.InvariantCulture) + " table(s)." : "."));
                }
                catch
                {
                    try { db.SetLiveTrafficRemoved(false); }
                    catch { }
                    throw;
                }
            }
            else
            {
                if (!db.TableExists("_backup_Database_RemoveTraffic_TrafficCars"))
                    throw new InvalidOperationException("No Remove Traffic backup was found to restore.");
                RestoreTableBackup(db, "TrafficCars", "_backup_Database_RemoveTraffic_TrafficCars");
                var raceTables = SetRaceTrafficFlags(db, true);
                db.SetLiveTrafficRemoved(false);
                _removeTrafficSwitchOn = false;
                LogCount(db, "TrafficCars restored rows", "SELECT count(*) FROM TrafficCars");
                if (raceTables > 0)
                    Log("Remove Traffic OFF. Race HasTraffic flags restored in " + raceTables.ToString(CultureInfo.InvariantCulture) + " table(s).");
            }

            UpdateRemoveTrafficSwitchButton();
            if (_trafficEditorRows != null && _trafficEditorRows.Count > 0)
                LoadTrafficEditorCars();
        }

        private void UpdateRemoveTrafficSwitchButton()
        {
            UpdateRemoveTrafficSwitchButton(_removeTrafficSwitchOn);
        }

        private void UpdateRemoveTrafficSwitchButton(bool on)
        {
            if (_removeTrafficSwitchButton == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { UpdateRemoveTrafficSwitchButton(on); }));
                return;
            }

            _removeTrafficSwitchOn = on;
            _removeTrafficSwitchButton.Text = TranslateDynamicUi(on ? "Remove Traffic: ON" : "Remove Traffic: OFF");
            MakeAccentButton(_removeTrafficSwitchButton, on ? AccentGreen : AccentRed);
        }

