        private int SetRaceTrafficFlags(RemoteDatabase db, bool restore)
        {
            var touched = 0;
            foreach (var table in new[] { "Profile0_CareerRaces", "NewProfile_CareerRaces" })
            {
                if (!db.TableExists(table) || !db.ColumnExists(table, "HasTraffic"))
                    continue;

                var tableSql = EscapeIdentifierForSql(table);
                var backupName = "_backup_Database_RemoveTraffic_" + SanitizeSqlName(table);
                if (restore)
                {
                    if (!db.TableExists(backupName))
                        continue;
                    RestoreGenericFullTableBackup(db, table, backupName);
                    touched++;
                    continue;
                }

                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET HasTraffic = 0 WHERE COALESCE(HasTraffic, 1) <> 0;");
                touched++;
            }

            return touched;
        }

        private void ApplyTrafficPreset(string presetName, string presetKey)
        {
            var db = RequireDatabase();
            EnsureTrafficCarsTable(db);
            var whereSql = BuildTrafficPresetWhere(db, presetKey);
            if (string.IsNullOrWhiteSpace(whereSql))
                throw new InvalidOperationException("Traffic preset is missing a filter.");

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_TrafficCars AS SELECT * FROM TrafficCars;");
            ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO TrafficCars (CarId, IsLaunchChunkCar) SELECT Id, 0 FROM Data_Car WHERE " + whereSql + ";");
            ApplyTrafficDataCarFlags(db, "(" + whereSql + ")");
            LogCount(db, presetName + " traffic preset rows", "SELECT count(*) FROM TrafficCars WHERE CarId IN (SELECT Id FROM Data_Car WHERE " + whereSql + ")");
            LoadTrafficEditorCars();
        }

        private static string BuildTrafficPresetWhere(RemoteDatabase db, string presetKey)
        {
            var key = presetKey ?? string.Empty;
            if (string.Equals(key, "hyper", StringComparison.OrdinalIgnoreCase))
            {
                var parts = new List<string>();
                if (db.ColumnExists("Data_Car", "PerformanceIndex"))
                    parts.Add("COALESCE([PerformanceIndex], 0) >= 800");
                if (db.ColumnExists("Data_Car", "PI"))
                    parts.Add("COALESCE([PI], 0) >= 800");
                if (db.ColumnExists("Data_Car", "ClassID"))
                    parts.Add("COALESCE([ClassID], 0) >= 5");
                return parts.Count == 0 ? string.Empty : "(" + string.Join(" OR ", parts.ToArray()) + ")";
            }

            if (string.Equals(key, "jdm", StringComparison.OrdinalIgnoreCase))
            {
                var parts = new List<string>();
                if (db.ColumnExists("Data_Car", "CountryID"))
                    parts.Add("COALESCE([CountryID], 0) = 5");
                if (db.ColumnExists("Data_Car", "MakeID") &&
                    db.TableExists("List_CarMake") &&
                    db.ColumnExists("List_CarMake", "ID") &&
                    db.ColumnExists("List_CarMake", "CountryID"))
                    parts.Add("[MakeID] IN (SELECT [ID] FROM [List_CarMake] WHERE COALESCE([CountryID], 0) = 5)");
                return parts.Count == 0 ? string.Empty : "(" + string.Join(" OR ", parts.ToArray()) + ")";
            }

            if (string.Equals(key, "offroad", StringComparison.OrdinalIgnoreCase))
            {
                var parts = new List<string>();
                if (db.ColumnExists("Data_Car", "OffroadRating"))
                    parts.Add("COALESCE([OffroadRating], 0) >= 7");
                if (db.ColumnExists("Data_Car", "MinOffRoadPerfRating"))
                    parts.Add("COALESCE([MinOffRoadPerfRating], 0) >= 7");
                return parts.Count == 0 ? string.Empty : "(" + string.Join(" OR ", parts.ToArray()) + ")";
            }

            return string.Empty;
        }

        private static void EnsureTrafficCarsTable(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                throw new InvalidOperationException("Data_Car.Id was not found.");
            if (!db.TableExists("TrafficCars") || !db.ColumnExists("TrafficCars", "CarId"))
                throw new InvalidOperationException("TrafficCars.CarId was not found.");
        }

        private int ApplyTrafficDataCarFlags(RemoteDatabase db, string dataCarWhere)
        {
            if (!db.TableExists("Data_Car") || string.IsNullOrWhiteSpace(dataCarWhere))
                return 0;

            var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            AddColumnSetIfExists(db, "Data_Car", sets, "IsDrivable", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsInstalled", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "IsPurchased", "1");
            AddColumnSetIfExists(db, "Data_Car", sets, "NotAvailableInAutoshow", "0");
            AddColumnSetIfExists(db, "Data_Car", sets, "VisibleOnlyIfOwned", "0");
            if (sets.Count == 0)
                return 0;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_TrafficDataCar AS SELECT * FROM Data_Car;");
            ExecuteAutoshowSql(db, "UPDATE Data_Car SET " + string.Join(", ", sets.Values.ToArray()) + " WHERE " + dataCarWhere + ";");
            return sets.Count;
        }

        private void PhotoCaptureAllCars()
        {
            var db = RequireDatabase();
            var beforeMissing = CountMissingPhotoCaptures(db);
            var touched = 0;
            touched += ApplyPhotoCaptureTable(db, "Profile0_PhotoCaptures", "_backup_Database_PhotoCaptures_Profile0");
            touched += ApplyPhotoCaptureTable(db, "NewProfile_PhotoCaptures", "_backup_Database_PhotoCaptures_NewProfile");
            if (touched == 0)
                throw new InvalidOperationException("No supported PhotoCaptures profile table was found.");

            var afterMissing = CountMissingPhotoCaptures(db);
            var tableMissing = CountMissingPhotoCaptureRowsInSupportedTables(db);
            if (afterMissing > 0 || tableMissing > 0)
                throw new InvalidOperationException("Photo Capture verification failed: " + Math.Max(afterMissing, tableMissing).ToString(CultureInfo.InvariantCulture) + " car(s) are still missing.");

            try { LoadPhotoCaptureRows(); }
            catch { }

            SetProfileStatus("Photo captures complete");
            ShowInfo("Photo Capture complete." + Environment.NewLine + Environment.NewLine +
                "Missing before: " + beforeMissing.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Missing after: " + afterMissing.ToString(CultureInfo.InvariantCulture));
        }

        private int ApplyPhotoCaptureTable(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "CarOrdinal"))
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT * FROM " + tableSql + ";");

            ExecuteAutoshowSql(db, "DELETE FROM " + tableSql + " WHERE CarOrdinal IS NULL;");
            ExecuteAutoshowSql(db, "DELETE FROM " + tableSql + " WHERE rowid NOT IN (SELECT MIN(rowid) FROM " + tableSql + " GROUP BY CarOrdinal);");

            var sourceSql = BuildPhotoCaptureIdSourceSql(db);
            if (string.IsNullOrWhiteSpace(sourceSql))
                throw new InvalidOperationException("No Data_Car or garage car source was found for Photo Capture.");

            ExecuteAutoshowSql(db,
                "INSERT INTO " + tableSql + " (CarOrdinal) " +
                "SELECT source.CarId FROM (" + sourceSql + ") source " +
                "WHERE source.CarId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM " + tableSql + " existing WHERE existing.CarOrdinal = source.CarId);");
            LogCount(db, tableName + " captured cars", "SELECT count(DISTINCT CarOrdinal) FROM " + tableSql);
            return 1;
        }

        private static string ResolvePhotoCaptureTable(RemoteDatabase db)
        {
            return ResolveActiveProfileTable(db, "Profile0_PhotoCaptures", "NewProfile_PhotoCaptures", "CarOrdinal");
        }

        private static string BuildPhotoCaptureIdSourceSql(RemoteDatabase db)
        {
            var sources = new List<string>();
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id"))
                sources.Add("SELECT Id AS CarId FROM Data_Car WHERE Id IS NOT NULL AND Id > 0 AND Id <> 3300");
            if (db.TableExists("Profile0_PhotoCaptures") && db.ColumnExists("Profile0_PhotoCaptures", "CarOrdinal"))
                sources.Add("SELECT CarOrdinal AS CarId FROM Profile0_PhotoCaptures WHERE CarOrdinal IS NOT NULL AND CarOrdinal > 0 AND CarOrdinal <> 3300");
            if (db.TableExists("NewProfile_PhotoCaptures") && db.ColumnExists("NewProfile_PhotoCaptures", "CarOrdinal"))
                sources.Add("SELECT CarOrdinal AS CarId FROM NewProfile_PhotoCaptures WHERE CarOrdinal IS NOT NULL AND CarOrdinal > 0 AND CarOrdinal <> 3300");
            if (sources.Count == 0)
            {
                var garageTable = ResolveOptionalGarageTable(db);
                if (!string.IsNullOrEmpty(garageTable))
                    sources.Add("SELECT DISTINCT CarId AS CarId FROM " + EscapeIdentifierForSql(garageTable) + " WHERE CarId IS NOT NULL AND CarId > 0 AND CarId <> 3300");
            }

            return sources.Count == 0 ? string.Empty : "SELECT DISTINCT CarId FROM (" + string.Join(" UNION ALL ", sources.ToArray()) + ") ORDER BY CarId";
        }

        private long CountMissingPhotoCaptures(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                return 0;
            var tableName = ResolvePhotoCaptureTable(db);
            return db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE Id IS NOT NULL AND Id <> 3300 AND Id NOT IN (SELECT CarOrdinal FROM " + EscapeIdentifierForSql(tableName) + " WHERE CarOrdinal IS NOT NULL)") ?? 0;
        }

        private long CountMissingPhotoCaptureRowsInSupportedTables(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                return 0;

            long missing = 0;
            foreach (var tableName in new[] { "Profile0_PhotoCaptures", "NewProfile_PhotoCaptures" })
            {
                if (!db.TableExists(tableName) || !db.ColumnExists(tableName, "CarOrdinal"))
                    continue;

                missing += db.QueryScalarLong(
                    "SELECT count(*) FROM Data_Car WHERE Id IS NOT NULL AND Id <> 3300 " +
                    "AND Id NOT IN (SELECT CarOrdinal FROM " + EscapeIdentifierForSql(tableName) + " WHERE CarOrdinal IS NOT NULL)") ?? 0;
            }

            return missing;
        }

        private void DriveTrafficCars()
        {
            var db = RequireDatabase();
            EnsureTrafficCarsTable(db);
            ApplyTrafficDataCarFlags(db, "Id IN (SELECT CarId FROM TrafficCars WHERE CarId IS NOT NULL)");
            if (db.ColumnExists("Data_Car", "IsDrivable"))
                LogCount(db, "Traffic cars not drivable", "SELECT count(*) FROM TrafficCars traffic JOIN Data_Car data ON data.Id = traffic.CarId WHERE COALESCE(data.IsDrivable, 0) <> 1");
            SetProfileStatus("Traffic drivable");
            ShowInfo("Traffic cars are marked drivable." + Environment.NewLine + Environment.NewLine + "Reload garage/autoshow screens if FH6 cached the list.");
        }

        private void ToggleBestWheelspinOdds()
        {
            var db = RequireDatabase();
            var mismatchBefore = CountWheelspinOddsMismatch(db);
            if (mismatchBefore == 0 && HasBestWheelspinBackup(db))
            {
                RestoreBestWheelspinOdds(db);
                var mismatchAfterRestore = CountWheelspinOddsMismatch(db);
                _wheelspinOddsOn = false;
                UpdateWheelspinOddsSwitchButton();
                try { LoadWheelspinOddsRows(); }
                catch { }
                SetProfileStatus("Wheelspin odds restored");
                ShowInfo("Wheelspin Odds turned off." + Environment.NewLine + Environment.NewLine +
                    "Restored from Luna backup. Non-common rows now: " + mismatchAfterRestore.ToString(CultureInfo.InvariantCulture));
                return;
            }

            ApplyBestWheelspinOdds(db, mismatchBefore);
        }

        private void ApplyBestWheelspinOdds(RemoteDatabase db, long mismatchBefore)
        {
            var touched = 0;

            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "BaseRarity"))
            {
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_Database_BestWheelspin_DataCar;");
                ExecuteAutoshowSql(db, "CREATE TABLE _backup_Database_BestWheelspin_DataCar AS SELECT Id, BaseRarity FROM Data_Car;");
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET BaseRarity = 0 WHERE BaseRarity IS NULL OR CAST(BaseRarity AS REAL) <> 0;");
                touched++;
            }

            if (db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity"))
            {
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_Database_BestWheelspin_CarRarities;");
                ExecuteAutoshowSql(db, "CREATE TABLE _backup_Database_BestWheelspin_CarRarities AS SELECT * FROM CarRarities;");
                if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id"))
                    ExecuteAutoshowSql(db, "INSERT INTO CarRarities (CarID, Rarity) SELECT Id, 0 FROM Data_Car WHERE Id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM CarRarities WHERE CarRarities.CarID = Data_Car.Id);");
                ExecuteAutoshowSql(db, "UPDATE CarRarities SET Rarity = 0 WHERE Rarity IS NULL OR Rarity <> 0;");
                LogCount(db, "Cars with non-common wheelspin rarity", "SELECT count(*) FROM CarRarities WHERE Rarity IS NULL OR Rarity <> 0");
                touched++;
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported car rarity columns were found.");
            var mismatchAfter = CountWheelspinOddsMismatch(db);
            if (mismatchAfter > 0)
                throw new InvalidOperationException("Wheelspin Odds verification failed: " + mismatchAfter.ToString(CultureInfo.InvariantCulture) + " rarity row(s) are still not common.");
            _wheelspinOddsOn = HasBestWheelspinBackup(db);
            UpdateWheelspinOddsSwitchButton();
            try { LoadWheelspinOddsRows(); }
            catch { }
            SetProfileStatus("Wheelspin odds applied");
            ShowInfo("Wheelspin Odds turned on." + Environment.NewLine + Environment.NewLine +
                "Non-common rows before: " + mismatchBefore.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Non-common rows after: " + mismatchAfter.ToString(CultureInfo.InvariantCulture));
        }

        private void RestoreBestWheelspinOdds(RemoteDatabase db)
        {
            var restored = 0;
            if (db.TableExists("_backup_Database_BestWheelspin_DataCar") &&
                db.TableExists("Data_Car") &&
                db.ColumnExists("_backup_Database_BestWheelspin_DataCar", "Id") &&
                db.ColumnExists("_backup_Database_BestWheelspin_DataCar", "BaseRarity") &&
                db.ColumnExists("Data_Car", "BaseRarity"))
            {
                ExecuteAutoshowSql(db,
                    "UPDATE Data_Car SET BaseRarity = (SELECT backup.BaseRarity FROM _backup_Database_BestWheelspin_DataCar backup WHERE backup.Id = Data_Car.Id) " +
                    "WHERE EXISTS (SELECT 1 FROM _backup_Database_BestWheelspin_DataCar backup WHERE backup.Id = Data_Car.Id);");
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_Database_BestWheelspin_DataCar;");
                restored++;
            }

            if (db.TableExists("_backup_Database_BestWheelspin_CarRarities") &&
                db.TableExists("CarRarities"))
            {
                ExecuteAutoshowSql(db, "DELETE FROM CarRarities;");
                ExecuteAutoshowSql(db, "INSERT INTO CarRarities SELECT * FROM _backup_Database_BestWheelspin_CarRarities;");
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_Database_BestWheelspin_CarRarities;");
                restored++;
            }

            if (restored == 0)
                throw new InvalidOperationException("Wheelspin Odds is already common, but Luna did not find a backup to restore.");
        }

        private static bool HasBestWheelspinBackup(RemoteDatabase db)
        {
            return db.TableExists("_backup_Database_BestWheelspin_DataCar") ||
                db.TableExists("_backup_Database_BestWheelspin_CarRarities");
        }

        private long CountWheelspinOddsMismatch(RemoteDatabase db)
        {
            long total = 0;
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "BaseRarity"))
                total += db.QueryScalarLong("SELECT count(*) FROM Data_Car WHERE BaseRarity IS NULL OR CAST(BaseRarity AS REAL) <> 0") ?? 0;
            if (db.TableExists("Data_Car") && db.ColumnExists("Data_Car", "Id") &&
                db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "CarID") && db.ColumnExists("CarRarities", "Rarity"))
            {
                total += db.QueryScalarLong(
                    "SELECT count(*) FROM Data_Car WHERE Id IS NOT NULL AND (" +
                    "Id NOT IN (SELECT CarID FROM CarRarities WHERE CarID IS NOT NULL) OR " +
                    "Id IN (SELECT CarID FROM CarRarities WHERE Rarity IS NULL OR Rarity <> 0))") ?? 0;
            }
            else if (db.TableExists("CarRarities") && db.ColumnExists("CarRarities", "Rarity"))
            {
                total += db.QueryScalarLong("SELECT count(*) FROM CarRarities WHERE Rarity IS NULL OR Rarity <> 0") ?? 0;
            }
            return total;
        }

        private void UnlockRoutesAndTracks()
        {
            var db = RequireDatabase();
            var lockedBefore = CountLockedRoutesAndTracks(db);
            var touched = ApplyRouteAndTrackUnlocks(db);
            if (touched == 0)
                throw new InvalidOperationException("No supported route/track columns were found.");
            var lockedAfter = CountLockedRoutesAndTracks(db);
            if (lockedAfter > 0)
                throw new InvalidOperationException("Unlock Routes verification failed: " + lockedAfter.ToString(CultureInfo.InvariantCulture) + " supported route/map row(s) are still locked.");
            SetProfileStatus("Routes unlocked");
            ShowInfo("Routes and tracks unlocked." + Environment.NewLine + Environment.NewLine +
                "Locked before: " + lockedBefore.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                "Locked after: " + lockedAfter.ToString(CultureInfo.InvariantCulture) + Environment.NewLine + Environment.NewLine +
                "Reopen the map/event screen if FH6 cached route visibility.");
        }

        private int ApplyRouteAndTrackUnlocks(RemoteDatabase db)
        {
            var touched = 0;
            if (db.TableExists("Tracks"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "Tracks", sets, "Active", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "Renderable", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "IsInstalled", "1");
                AddColumnSetIfExists(db, "Tracks", sets, "IsPurchased", "1");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_Tracks AS SELECT * FROM Tracks;");
                    ExecuteAutoshowSql(db, "UPDATE Tracks SET " + string.Join(", ", sets.Values.ToArray()) + ";");
                    touched++;
                    LogRoutesStillLocked(db);
                }
            }

            if (db.TableExists("Environments") && db.ColumnExists("Environments", "ShowOnMap"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_Environments AS SELECT * FROM Environments;");
                ExecuteAutoshowSql(db, "UPDATE Environments SET ShowOnMap = 1 WHERE ShowOnMap IS NULL OR ShowOnMap <> 1;");
                touched++;
                LogCount(db, "Environments still hidden from map", "SELECT count(*) FROM Environments WHERE ShowOnMap IS NULL OR ShowOnMap <> 1");
            }

            if (db.TableExists("ContentOffers"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "ContentOffers", sets, "Visible", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsPurchased", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsFree", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsNew", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "ShouldUpsell", "0");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_ContentOffers AS SELECT * FROM ContentOffers;");
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", sets.Values.ToArray()) + ";");
                    touched++;
                }
            }

            if (db.TableExists("ContentOffersMapping"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_RoutesTracks_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00';");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE Quantity IS NULL OR Quantity < 1;");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE IsPromo IS NULL OR IsPromo <> 0;");
                touched++;
            }
            return touched;
        }

        private long CountLockedRoutesAndTracks(RemoteDatabase db)
        {
            long total = 0;
            if (db.TableExists("Tracks"))
            {
                var flagColumns = new[] { "Active", "Renderable", "IsInstalled", "IsPurchased" }
                    .Where(column => db.ColumnExists("Tracks", column))
                    .ToList();
                if (flagColumns.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM Tracks WHERE " + BuildNotOneWhere(flagColumns)) ?? 0;
            }

            if (db.TableExists("Environments") && db.ColumnExists("Environments", "ShowOnMap"))
                total += db.QueryScalarLong("SELECT count(*) FROM Environments WHERE ShowOnMap IS NULL OR ShowOnMap <> 1") ?? 0;

            if (db.TableExists("ContentOffers"))
            {
                var checks = new List<string>();
                foreach (var column in new[] { "Visible", "IsPurchased", "IsFree", "IsNew" })
                {
                    if (db.ColumnExists("ContentOffers", column))
                        checks.Add(EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 1");
                }
                if (db.ColumnExists("ContentOffers", "ShouldUpsell"))
                    checks.Add("ShouldUpsell IS NULL OR ShouldUpsell <> 0");
                if (checks.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM ContentOffers WHERE " + string.Join(" OR ", checks.ToArray())) ?? 0;
            }

            if (db.TableExists("ContentOffersMapping"))
            {
                var checks = new List<string>();
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    checks.Add("ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00'");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    checks.Add("Quantity IS NULL OR Quantity < 1");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    checks.Add("IsPromo IS NULL OR IsPromo <> 0");
                if (checks.Count > 0)
                    total += db.QueryScalarLong("SELECT count(*) FROM ContentOffersMapping WHERE " + string.Join(" OR ", checks.ToArray())) ?? 0;
            }

            return total;
        }

        private void CompleteAllCareerRaces()
        {
            var db = RequireDatabase();
            var touched = 0;
            touched += ApplyCareerRaceCompletionTable(db, "Profile0_CareerRaces", "_backup_Database_CompleteCareerRaces_Profile0Races");
            touched += ApplyCareerRaceCompletionTable(db, "NewProfile_CareerRaces", "_backup_Database_CompleteCareerRaces_NewProfileRaces");
            touched += ApplyCareerRaceCompletionTable(db, "Profile0_CareerRaceCollections", "_backup_Database_CompleteCareerRaces_Profile0Collections");
            touched += ApplyCareerRaceCompletionTable(db, "NewProfile_CareerRaceCollections", "_backup_Database_CompleteCareerRaces_NewProfileCollections");

            if (touched == 0)
            {
                var lockedBefore = CountLockedRoutesAndTracks(db);
                touched += ApplyRouteAndTrackUnlocks(db);
                touched += ApplyClassRestrictionUnlocks(db);
                var lockedAfter = CountLockedRoutesAndTracks(db);
                if (lockedAfter > 0)
                    throw new InvalidOperationException("Race route verification failed: " + lockedAfter.ToString(CultureInfo.InvariantCulture) + " supported route/map row(s) are still locked.");
                Log("Complete Races did not find dedicated completion columns on this database, so Luna applied route unlocks and race restriction cleanup instead.");
                if (touched > 0)
                {
                    SetProfileStatus("Race routes unlocked");
                    ShowInfo("Race route unlock applied." + Environment.NewLine + Environment.NewLine +
                        "This FH6 database exposes race definitions, but no SQL completion-save columns. Luna unlocked routes/map visibility instead." + Environment.NewLine + Environment.NewLine +
                        "Locked before: " + lockedBefore.ToString(CultureInfo.InvariantCulture) + Environment.NewLine +
                        "Locked after: " + lockedAfter.ToString(CultureInfo.InvariantCulture));
                    return;
                }
            }

            if (touched == 0)
                throw new InvalidOperationException("No supported career race tables or route unlock columns were found.");
            SetProfileStatus("Career race helper applied");
            ShowInfo("Career race completion fields applied." + Environment.NewLine + Environment.NewLine + "Reload the map or race menu so FH6 refreshes the route state.");
        }

        private int ApplyCareerRaceCompletionTable(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(tableName))
                return 0;

            var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var column in new[] { "Completed", "Complete", "IsCompleted", "HasCompleted", "HasBeenCompleted", "Unlocked", "IsUnlocked", "Finished", "Passed", "IsVisible", "Visible" })
                AddColumnSetIfExists(db, tableName, sets, column, "1");
            foreach (var column in new[] { "BestPosition", "BestFinishPosition", "BestPlacement" })
                AddColumnSetIfExists(db, tableName, sets, column, "1");
            foreach (var column in new[] { "NumCompletions", "Completions", "TimesCompleted", "TimesWon", "Wins", "StarCount", "StarsEarned" })
                AddColumnSetIfExists(db, tableName, sets, column, "CASE WHEN " + EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " < 1 THEN 1 ELSE " + EscapeIdentifierForSql(column) + " END");
            if (sets.Count == 0)
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
            ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + string.Join(", ", sets.Values.ToArray()) + ";");
            Log(tableName + " completion columns applied: " + string.Join(", ", sets.Keys.ToArray()) + ".");
            return 1;
        }

        private static string BuildIntegerInList(IEnumerable<int> values)
        {
            var ids = (values ?? new int[0])
                .Where(value => value > 0)
                .Distinct()
                .Select(value => value.ToString(CultureInfo.InvariantCulture))
                .ToArray();
            if (ids.Length == 0)
                throw new InvalidOperationException("No valid car ids were selected.");
            return string.Join(", ", ids);
        }

        private void LoadDrivingGarage()
        {
            var db = RequireDatabase();
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("Profile0_Career_Garage") || !db.ColumnExists("Profile0_Career_Garage", "CarId"))
                throw new InvalidOperationException("Profile0_Career_Garage.CarId was not found.");

            var rows = QueryCarEditorRows(db);
            SetDrivingGarageRows(rows);
            SetDrivingStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture));
            Log("Driving Editor loaded " + rows.Count.ToString(CultureInfo.InvariantCulture) + " owned car row(s). Select a car, then press Load Selected Car Values.");
        }

        private void SetDrivingGarageRows(List<CarEditorRow> rows)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetDrivingGarageRows(rows); }));
                return;
            }

            _drivingGarageRows = rows ?? new List<CarEditorRow>();
            ApplyDrivingGarageFilter();
        }

        private void ApplyDrivingGarageFilter()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)ApplyDrivingGarageFilter);
                return;
            }

            var filter = _drivingGarageSearch == null ? string.Empty : _drivingGarageSearch.Text;
            var rows = FilterCarEditorRows(_drivingGarageRows, filter);
            SetDrivingGarageGridRows(rows);
            SetDrivingStatus("Garage " + rows.Count.ToString(CultureInfo.InvariantCulture) + "/" + _drivingGarageRows.Count.ToString(CultureInfo.InvariantCulture));
        }

        private void SetDrivingGarageGridRows(List<CarEditorRow> rows)
        {
            if (_drivingGarageGrid == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetDrivingGarageGridRows(rows); }));
                return;
            }

            _drivingGarageGrid.Rows.Clear();
            foreach (var car in rows ?? new List<CarEditorRow>())
            {
                var rowIndex = _drivingGarageGrid.Rows.Add(
                    car.CarId.ToString(CultureInfo.InvariantCulture),
                    car.Year,
                    car.Make,
                    car.Model,
                    car.PerformanceIndex,
                    FormatCarClassId(car.ClassId),
                    car.Copies);
                _drivingGarageGrid.Rows[rowIndex].Tag = car.CarId;
            }
            ClearCarGridSelection(_drivingGarageGrid);
            UpdateDrivingGarageSelection();
        }

        private CarEditorRow GetSelectedDrivingCar()
        {
            if (InvokeRequired)
                return (CarEditorRow)Invoke(new Func<CarEditorRow>(GetSelectedDrivingCar));
            if (_drivingGarageGrid == null || _drivingGarageGrid.SelectedRows.Count == 0)
                throw new InvalidOperationException("Load Garage and select a car in the Driving Editor first.");

            int carId;
            if (!TryGetCarIdFromGridRow(_drivingGarageGrid.SelectedRows[0], out carId))
                throw new InvalidOperationException("Could not read the selected driving car id.");

            var row = _drivingGarageRows.FirstOrDefault(car => car.CarId == carId);
            if (row != null)
                return row;

            return new CarEditorRow(
                carId,
                GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Year"),
                GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Make"),
                GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Model"),
                GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Copies"),
                GetGridCellText(_drivingGarageGrid.SelectedRows[0], "PI"),
                ParseClassIdFromDisplay(GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Class")),
                string.Empty,
                string.Empty,
                new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase),
                ParseClassIdFromDisplay(GetGridCellText(_drivingGarageGrid.SelectedRows[0], "Class")),
                0,
                0,
                0);
        }

        private void UpdateDrivingGarageSelection()
        {
            if (_drivingSelectedCar == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateDrivingGarageSelection);
                return;
            }

            if (_drivingGarageGrid == null || _drivingGarageGrid.SelectedRows.Count == 0)
            {
                _drivingSelectedCar.Text = "Your current car selected: none";
                return;
            }

            var row = _drivingGarageGrid.SelectedRows[0];
            var name = FormatCarDisplayName(
                ToInt(GetGridCellText(row, "CarId")),
                GetGridCellText(row, "Year"),
                GetGridCellText(row, "Make"),
                GetGridCellText(row, "Model"));
            _drivingSelectedCar.Text = "Your current car selected: " + name;
        }

        private List<DrivingEditorInput> CaptureDrivingEditorInputs()
        {
            if (InvokeRequired)
                return (List<DrivingEditorInput>)Invoke(new Func<List<DrivingEditorInput>>(CaptureDrivingEditorInputs));

            _drivingGrid.EndEdit();
            var inputs = new List<DrivingEditorInput>();
            foreach (DataGridViewRow row in _drivingGrid.Rows)
            {
                var field = row.Tag as DrivingEditorField;
                if (field == null)
                    continue;

                var raw = Convert.ToString(row.Cells[2].Value);
                if (string.IsNullOrWhiteSpace(raw))
                    continue;

                inputs.Add(new DrivingEditorInput(field, raw));
            }

            return inputs;
        }

        private void LoadDrivingEditorValues()
        {
            var car = GetSelectedDrivingCar();
            var db = RequireDatabase();
            var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var missing = new List<string>();

            foreach (var field in DrivingEditorFields)
            {
                if (field.IsSpeedPack)
                {
                    if (SpeedEditorPackSupported(db))
                        values[field.Key] = QuerySpeedEditorCurrentMultiplier(db, car.CarId);
                    else
                        missing.Add(field.Key);
                    continue;
                }

                if (!db.TableExists(field.TableName) || !db.ColumnExists(field.TableName, field.ColumnName))
                {
                    missing.Add(field.Key);
                    continue;
                }

                var tableSql = EscapeIdentifierForSql(field.TableName);
                var columnSql = EscapeIdentifierForSql(field.ColumnName);
                if (field.UseBaselineMultiplier)
                {
                    values[field.Key] = QueryDrivingEditorCurrentMultiplier(db, field, car.CarId);
                }
                else
                {
                    var current = QueryScalarText(db, "SELECT CAST(" + columnSql + " AS TEXT) FROM " + tableSql + " WHERE " + columnSql + " IS NOT NULL LIMIT 1");
                    values[field.Key] = current ?? string.Empty;
                }
            }

            SetDrivingEditorValues(values, missing);
            Log("Driving Editor loaded " + values.Count + " supported value(s) for " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ". Multiplier rows show the selected car's ratio against Luna's backup baseline when available.");
            if (missing.Count > 0)
                Log("Driving Editor missing column(s): " + string.Join(", ", missing.ToArray()));
        }

        private string QueryDrivingEditorCurrentMultiplier(RemoteDatabase db, DrivingEditorField field, int carId)
        {
            var multiplier = TryQueryAverageMultiplier(db, field.TableName, field.BackupName, field.ColumnName, false, carId);
            if (!multiplier.HasValue || multiplier.Value <= 0.0 || double.IsNaN(multiplier.Value) || double.IsInfinity(multiplier.Value))
                return "1";

            return FormatDrivingMultiplier(multiplier.Value);
        }

        private void ApplyDrivingEditorValues(List<DrivingEditorInput> inputs)
        {
            if (inputs == null || inputs.Count == 0)
                throw new InvalidOperationException("Enter at least one Driving Editor value before pressing Apply Values.");

            var car = GetSelectedDrivingCar();
            var db = RequireDatabase();
            var groupedValues = new Dictionary<string, List<DrivingEditorSqlInput>>(StringComparer.OrdinalIgnoreCase);
            var backupNames = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            var touched = 0;

            foreach (var input in inputs)
            {
                var field = input.Field;
                var sqlValue = ParseDrivingEditorSqlValue(input.RawValue, field);
                if (field.IsSpeedPack)
                {
                    touched += ApplySpeedEditorPack(db, sqlValue, car.CarId);
                    continue;
                }

                AddDrivingEditorGroupedInput(groupedValues, backupNames, field, sqlValue);
                if (IsGripDrivingColumn(field.ColumnName))
                {
                    var garageField = new DrivingEditorField(
                        field.DisplayName,
                        field.Description,
                        "Profile0_Career_Garage",
                        field.ColumnName,
                        "_backup_Database_ProfileGarageGripPack",
                        field.WholeNumber,
                        field.AllowText,
                        field.UseBaselineMultiplier);
                    AddDrivingEditorGroupedInput(groupedValues, backupNames, garageField, sqlValue);
                }
            }

            foreach (var tableValues in groupedValues)
                touched += ApplyDrivingColumnSet(db, tableValues.Key, backupNames[tableValues.Key], tableValues.Value, car.CarId);

            if (touched == 0)
                throw new InvalidOperationException("None of the Driving Editor tables/columns were found.");

            Log("Driving Editor applied " + touched + " supported column value(s) to " + FormatCarDisplayName(car.CarId, car.Year, car.Make, car.Model) + ". Switch to another car and back so FH6 reloads the selected vehicle data.");
        }

        private static void AddDrivingEditorGroupedInput(Dictionary<string, List<DrivingEditorSqlInput>> groupedValues, Dictionary<string, string> backupNames, DrivingEditorField field, string sqlValue)
        {
            List<DrivingEditorSqlInput> tableValues;
            if (!groupedValues.TryGetValue(field.TableName, out tableValues))
            {
                tableValues = new List<DrivingEditorSqlInput>();
                groupedValues.Add(field.TableName, tableValues);
                backupNames[field.TableName] = field.BackupName;
            }
            tableValues.Add(new DrivingEditorSqlInput(field, sqlValue));
        }

        private static bool IsGripDrivingColumn(string columnName)
        {
            return string.Equals(columnName, "Traction_Road", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "Traction_OffRoad", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(columnName, "Traction_Snow", StringComparison.OrdinalIgnoreCase);
        }

        private bool SpeedEditorPackSupported(RemoteDatabase db)
        {
            return (db.TableExists("Data_Car") &&
                    (db.ColumnExists("Data_Car", "TopSpeed-mph") ||
                     db.ColumnExists("Data_Car", "SimTopSpeed") ||
                     db.ColumnExists("Data_Car", "BodyAeroLongitudinalDrag"))) ||
                   (db.TableExists("Profile0_Career_Garage") && db.ColumnExists("Profile0_Career_Garage", "TopSpeed")) ||
                   (db.TableExists("List_DragWallSettingsOverride") &&
                    (db.ColumnExists("List_DragWallSettingsOverride", "MinSpeedForDragWall") ||
                     db.ColumnExists("List_DragWallSettingsOverride", "MedSpeedForDragWall") ||
                     db.ColumnExists("List_DragWallSettingsOverride", "MaxSpeedForDragWall")));
        }

        private int ApplySpeedEditorPack(RemoteDatabase db, string multiplierSql, int carId)
        {
            double multiplier;
            if (!double.TryParse(multiplierSql, NumberStyles.Float, CultureInfo.InvariantCulture, out multiplier) || multiplier <= 0.0 || double.IsNaN(multiplier) || double.IsInfinity(multiplier))
                throw new InvalidOperationException("Top Speed multiplier must be a positive finite number.");

            var applied = 0;
            var carIdSql = carId.ToString(CultureInfo.InvariantCulture);
            if (db.TableExists("Data_Car"))
            {
                var table = EscapeIdentifierForSql("Data_Car");
                var backup = EscapeIdentifierForSql("_backup_Database_DataCarSpeedPack");
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
                var dataCarWhere = db.ColumnExists("Data_Car", "Id") ? " AND " + table + ".[Id] = " + carIdSql : string.Empty;

                applied += ApplyBaselineRealMultiplier(db, table, backup, "TopSpeed-mph", multiplierSql, false, 0.001, dataCarWhere);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "SimTopSpeed", multiplierSql, false, 0.001, dataCarWhere);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "BodyAeroLongitudinalDrag", multiplierSql, true, 0.001, dataCarWhere);
            }

            if (db.TableExists("Profile0_Career_Garage"))
            {
                var table = EscapeIdentifierForSql("Profile0_Career_Garage");
                var backup = EscapeIdentifierForSql("_backup_Database_ProfileGarageSpeedPack");
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
                var garageWhere = db.ColumnExists("Profile0_Career_Garage", "CarId") ? " AND " + table + ".[CarId] = " + carIdSql : string.Empty;
                applied += ApplyBaselineRealMultiplier(db, table, backup, "TopSpeed", multiplierSql, false, 0.001, garageWhere);

                if (multiplier > 1.000001 &&
                    db.ColumnExists("Profile0_Career_Garage", "CarId") &&
                    db.TableExists("Data_Car") &&
                    db.ColumnExists("Data_Car", "Id") &&
                    db.ColumnExists("Data_Car", "SimTopSpeed"))
                {
                    ExecuteAutoshowSql(db,
                        "UPDATE " + table + " SET [TopSpeed] = (" +
                        "SELECT dataCar.[SimTopSpeed] * (" + multiplierSql + ") FROM [Data_Car] dataCar WHERE dataCar.[Id] = " + table + ".[CarId] AND dataCar.[SimTopSpeed] IS NOT NULL AND dataCar.[SimTopSpeed] > 0 LIMIT 1) " +
                        "WHERE [TopSpeed] IS NOT NULL AND [TopSpeed] <= 0 AND " + table + ".[CarId] = " + carIdSql + " AND EXISTS (SELECT 1 FROM [Data_Car] dataCar WHERE dataCar.[Id] = " + table + ".[CarId] AND dataCar.[SimTopSpeed] IS NOT NULL AND dataCar.[SimTopSpeed] > 0);");
                }
            }

            if (db.TableExists("List_DragWallSettingsOverride"))
            {
                var table = EscapeIdentifierForSql("List_DragWallSettingsOverride");
                var backup = EscapeIdentifierForSql("_backup_Database_DragWallSpeedPack");
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backup + " AS SELECT rowid AS _rowid_, * FROM " + table + ";");
                applied += ApplyBaselineRealMultiplier(db, table, backup, "MinSpeedForDragWall", multiplierSql, false, 0.001);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "MedSpeedForDragWall", multiplierSql, false, 0.001);
                applied += ApplyBaselineRealMultiplier(db, table, backup, "MaxSpeedForDragWall", multiplierSql, false, 0.001);
            }

            if (applied == 0)
                throw new InvalidOperationException("No supported speed editor columns were found.");

            Log("Top Speed multiplier applied at x" + FormatDrivingMultiplier(multiplier) +
                ". It raises top-speed targets and reduces baseline body drag; switch to another car and back so FH6 reloads speed data.");
            return applied;
        }

        private string QuerySpeedEditorCurrentMultiplier(RemoteDatabase db, int carId)
        {
            double? multiplier = TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_DataCarSpeedPack", "SimTopSpeed", false, carId);
            if (!multiplier.HasValue)
                multiplier = TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_DataCarSpeedPack", "TopSpeed-mph", false, carId);
            if (!multiplier.HasValue)
                multiplier = TryQueryAverageMultiplier(db, "Profile0_Career_Garage", "_backup_Database_ProfileGarageSpeedPack", "TopSpeed", false, carId);
            if (!multiplier.HasValue)
                multiplier = TryQueryAverageMultiplier(db, "List_DragWallSettingsOverride", "_backup_Database_DragWallSpeedPack", "MaxSpeedForDragWall", false);
            if (!multiplier.HasValue)
                multiplier = TryQueryAverageMultiplier(db, "Data_Car", "_backup_Database_DataCarSpeedPack", "BodyAeroLongitudinalDrag", true, carId);

            if (!multiplier.HasValue || multiplier.Value <= 0.0 || double.IsNaN(multiplier.Value) || double.IsInfinity(multiplier.Value))
                return "1";

            return FormatDrivingMultiplier(multiplier.Value);
        }

        private double? TryQueryAverageMultiplier(RemoteDatabase db, string tableName, string backupName, string columnName, bool inverse, int? carId = null)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName) ||
                !db.ColumnExists(tableName, columnName) ||
                !db.ColumnExists(backupName, columnName) ||
                !db.ColumnExists(backupName, "_rowid_"))
                return null;

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var columnSql = EscapeIdentifierForSql(columnName);
            var numerator = inverse ? backupSql + "." + columnSql : tableSql + "." + columnSql;
            var denominator = inverse ? tableSql + "." + columnSql : backupSql + "." + columnSql;
            var filter = BuildDrivingCarFilterForQuery(db, tableName, tableSql, carId);
            var text = QueryScalarText(
                db,
                "SELECT AVG(CAST(" + numerator + " AS REAL) / CAST(" + denominator + " AS REAL)) " +
                "FROM " + tableSql + " JOIN " + backupSql + " ON " + backupSql + ".[_rowid_] = " + tableSql + ".rowid " +
                "WHERE " + numerator + " IS NOT NULL AND " + denominator + " IS NOT NULL " +
                "AND CAST(" + numerator + " AS REAL) > 0 AND CAST(" + denominator + " AS REAL) > 0" + filter + ";");

            double value;
            if (!double.TryParse(text, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
                return null;
            if (value <= 0.0 || double.IsNaN(value) || double.IsInfinity(value))
                return null;
            return value;
        }

        private static string BuildDrivingCarFilterForQuery(RemoteDatabase db, string tableName, string tableSql, int? carId)
        {
            if (!carId.HasValue)
                return string.Empty;

            var carIdSql = carId.Value.ToString(CultureInfo.InvariantCulture);
            if (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) && db.ColumnExists(tableName, "Id"))
                return " AND " + tableSql + ".[Id] = " + carIdSql;
            if (string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase) && db.ColumnExists(tableName, "CarId"))
                return " AND " + tableSql + ".[CarId] = " + carIdSql;
            return string.Empty;
        }

        private int ApplyBaselineRealMultiplier(RemoteDatabase db, string tableSql, string backupSql, string columnName, string multiplierSql, bool inverse, double minValue, string extraWhere = "")
        {
            var plainTable = tableSql.Trim('[', ']').Replace("]]", "]");
            var plainBackup = backupSql.Trim('[', ']').Replace("]]", "]");
            if (!db.ColumnExists(plainTable, columnName) || !db.ColumnExists(plainBackup, columnName) || !db.ColumnExists(plainBackup, "_rowid_"))
                return 0;

            var columnSql = EscapeIdentifierForSql(columnName);
            var expression = inverse
                ? "CAST(" + backupSql + "." + columnSql + " AS REAL) / (" + multiplierSql + ")"
                : "CAST(" + backupSql + "." + columnSql + " AS REAL) * (" + multiplierSql + ")";

            ExecuteAutoshowSql(
                db,
                "UPDATE " + tableSql + " SET " + columnSql + " = " +
                "(SELECT CASE WHEN " + backupSql + "." + columnSql + " IS NULL THEN " + tableSql + "." + columnSql + " " +
                "WHEN " + expression + " < " + minValue.ToString("0.######", CultureInfo.InvariantCulture) + " THEN " + minValue.ToString("0.######", CultureInfo.InvariantCulture) + " " +
                "ELSE " + expression + " END FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) " +
                "WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) AND " + columnSql + " IS NOT NULL" + (extraWhere ?? string.Empty) + ";");
            return 1;
        }

        private void SetDrivingEditorValues(Dictionary<string, string> values, List<string> missing)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { SetDrivingEditorValues(values, missing); }));
                return;
            }

            var missingSet = new HashSet<string>(missing ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
            foreach (DataGridViewRow row in _drivingGrid.Rows)
            {
                var field = row.Tag as DrivingEditorField;
                if (field == null)
                    continue;

                string value;
                if (values != null && values.TryGetValue(field.Key, out value))
                {
                    row.Cells[2].Value = value;
                    row.DefaultCellStyle.ForeColor = Color.FromArgb(223, 232, 245);
                    row.Cells[2].ToolTipText = field.UseBaselineMultiplier ? "Loaded live multiplier ratio. Edit it, then press Apply Values." : "Current sample loaded. Edit this value, then press Apply Values.";
                }
                else if (missingSet.Contains(field.Key))
                {
                    row.Cells[2].Value = string.Empty;
                    row.DefaultCellStyle.ForeColor = Color.FromArgb(132, 143, 160);
                    row.Cells[2].ToolTipText = "This FH6 build did not expose " + field.Path + ".";
                }
            }
        }

        private static string QueryScalarText(RemoteDatabase db, string sql)
        {
            var result = db.Query(sql);
            if (result.Rows.Count == 0 || result.Rows[0].Count == 0)
                return null;

            var value = result.Rows[0][0];
            if (value == null)
                return null;

            var formattable = value as IFormattable;
            if (formattable != null)
                return formattable.ToString(null, CultureInfo.InvariantCulture);
            return Convert.ToString(value, CultureInfo.InvariantCulture);
        }

        private static string ParseDrivingEditorSqlValue(string text, DrivingEditorField field)
        {
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (field.AllowText && normalized.Length == 0)
                throw new InvalidOperationException(field.DisplayName + " cannot be empty.");

            double value;
            if (!double.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value))
            {
                if (!field.AllowText)
                    throw new InvalidOperationException(field.DisplayName + " must be a finite number.");
                if (normalized.Length > 128)
                    throw new InvalidOperationException(field.DisplayName + " text must be 128 characters or fewer.");
                return "'" + normalized.Replace("'", "''") + "'";
            }

            if (double.IsNaN(value) || double.IsInfinity(value))
                throw new InvalidOperationException(field.DisplayName + " must be a finite number.");

            if (field.UseBaselineMultiplier)
            {
                if (value <= 0.0)
                    throw new InvalidOperationException(field.DisplayName + " must be a positive number.");
                return FormatDrivingMultiplier(value);
            }

            if (value < 0 || value > 1000000)
                throw new InvalidOperationException(field.DisplayName + " must be between 0 and 1000000.");

            if (field.WholeNumber)
            {
                var rounded = Math.Round(value);
                if (Math.Abs(value - rounded) > 0.000001)
                    throw new InvalidOperationException(field.DisplayName + " must be a whole number.");
                return ((long)rounded).ToString(CultureInfo.InvariantCulture);
            }

            return value.ToString("0.######", CultureInfo.InvariantCulture);
        }

