            public DatabaseTuningFilterPreset(string name, string description, params string[] terms)
            {
                Name = name ?? string.Empty;
                Description = description ?? string.Empty;
                Terms = terms ?? new string[0];
            }

            public bool Matches(DatabaseTuningRow row)
            {
                if (row == null)
                    return false;
                if (Terms.Length == 0)
                    return true;

                return Terms.Any(term => row.Matches(term));
            }

            public override string ToString()
            {
                return Name;
            }
        }

        private sealed class DatabaseTuningRow
        {
            public readonly string Key;
            public readonly string TableName;
            public readonly string ColumnName;
            public readonly string TargetKeyColumn;
            public readonly long TargetKeyValue;
            public readonly string TargetLabel;
            public readonly string Section;
            public readonly string DisplayName;
            public readonly string Description;
            public readonly string CurrentDisplay;
            public readonly string CurrentRaw;
            public readonly string DefaultDisplay;
            public readonly string DefaultRaw;
            public readonly string ValueType;
            public readonly string PartTableName;
            public bool Enabled;
            public string NewValue;

            public DatabaseTuningRow(
                string tableName,
                string columnName,
                string section,
                string displayName,
                string description,
                string currentDisplay,
                string currentRaw,
                string defaultDisplay,
                string defaultRaw,
                string valueType,
                string partTableName,
                string targetKeyColumn = "",
                long targetKeyValue = 0,
                string targetLabel = "")
            {
                TableName = tableName ?? string.Empty;
                ColumnName = columnName ?? string.Empty;
                TargetKeyColumn = targetKeyColumn ?? string.Empty;
                TargetKeyValue = targetKeyValue;
                TargetLabel = targetLabel ?? string.Empty;
                Key = TableName + "." + ColumnName +
                    (string.IsNullOrWhiteSpace(TargetKeyColumn) ? string.Empty : "#" + TargetKeyColumn + "=" + TargetKeyValue.ToString(CultureInfo.InvariantCulture));
                Section = section ?? string.Empty;
                DisplayName = displayName ?? string.Empty;
                Description = description ?? string.Empty;
                CurrentDisplay = currentDisplay ?? string.Empty;
                CurrentRaw = currentRaw ?? string.Empty;
                DefaultDisplay = defaultDisplay ?? string.Empty;
                DefaultRaw = defaultRaw ?? string.Empty;
                ValueType = valueType ?? string.Empty;
                PartTableName = partTableName ?? string.Empty;
                NewValue = CurrentRaw;
            }

            public bool Matches(string filter)
            {
                if (string.IsNullOrWhiteSpace(filter))
                    return true;

                return Contains(Section, filter) ||
                    Contains(DisplayName, filter) ||
                    Contains(Description, filter) ||
                    Contains(TableName, filter) ||
                    Contains(ColumnName, filter) ||
                    Contains(CurrentDisplay, filter) ||
                    Contains(DefaultDisplay, filter);
            }

            private static bool Contains(string value, string filter)
            {
                return (value ?? string.Empty).IndexOf(filter, StringComparison.OrdinalIgnoreCase) >= 0;
            }
        }

