        {
            public readonly HashSet<long> EngineIds;
            public readonly HashSet<long> DrivetrainIds;
            public readonly HashSet<long> CarBodyIds;
            public readonly HashSet<long> MotorIds;
            public readonly HashSet<long> CloneableEngineIds;
            public readonly HashSet<long> CloneableDrivetrainIds;
            public readonly HashSet<long> CloneableCarBodyIds;
            public readonly HashSet<long> CloneableMotorIds;

            public DatabaseTuningPartSupportIndex(HashSet<long> engineIds, HashSet<long> drivetrainIds, HashSet<long> carBodyIds, HashSet<long> motorIds, HashSet<long> cloneableEngineIds, HashSet<long> cloneableDrivetrainIds, HashSet<long> cloneableCarBodyIds, HashSet<long> cloneableMotorIds)
            {
                EngineIds = engineIds ?? new HashSet<long>();
                DrivetrainIds = drivetrainIds ?? new HashSet<long>();
                CarBodyIds = carBodyIds ?? new HashSet<long>();
                MotorIds = motorIds ?? new HashSet<long>();
                CloneableEngineIds = cloneableEngineIds ?? new HashSet<long>();
                CloneableDrivetrainIds = cloneableDrivetrainIds ?? new HashSet<long>();
                CloneableCarBodyIds = cloneableCarBodyIds ?? new HashSet<long>();
                CloneableMotorIds = cloneableMotorIds ?? new HashSet<long>();
            }

            public bool CanCloneSupport(string familyName, long requiredValue)
            {
                if (requiredValue <= 0)
                    return false;
                if (string.Equals(familyName, "Engine", StringComparison.OrdinalIgnoreCase))
                    return true;
                if (string.Equals(familyName, "Drivetrain", StringComparison.OrdinalIgnoreCase))
                    return true;
                if (string.Equals(familyName, "Car Body", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(familyName, "CarBody", StringComparison.OrdinalIgnoreCase))
                    return true;
                if (string.Equals(familyName, "Motor", StringComparison.OrdinalIgnoreCase))
                    return true;
                return false;
            }
        }

        private sealed class DatabaseTuningPartRecord
        {
            private readonly List<string> _columns;
            private readonly List<object> _row;

            public DatabaseTuningPartRecord(List<string> columns, List<object> row)
            {
                _columns = columns ?? new List<string>();
                _row = row ?? new List<object>();
            }

            public string FindColumn(params string[] names)
            {
                foreach (var name in names ?? new string[0])
                {
                    for (var i = 0; i < _columns.Count; i++)
                    {
                        if (string.Equals(_columns[i], name, StringComparison.OrdinalIgnoreCase))
                            return _columns[i];
                    }
                }
                return string.Empty;
            }

            public long GetLong(string columnName)
            {
                var index = FindColumnIndex(_columns, columnName);
                if (index < 0 || index >= _row.Count)
                    return 0;
                return ToLong(_row[index]);
            }
        }

