        private sealed class TeleportLocationRow
        {
            public string Name;
            public readonly byte[] RawPosition;

            public TeleportLocationRow(string name, byte[] rawPosition)
            {
                Name = CleanTeleportLocationName(name);
                RawPosition = new byte[16];
                if (rawPosition != null)
                    Buffer.BlockCopy(rawPosition, 0, RawPosition, 0, Math.Min(16, rawPosition.Length));
            }

            public float X
            {
                get { return RawPosition.Length >= 4 ? BitConverter.ToSingle(RawPosition, 0) : 0F; }
            }

            public float Y
            {
                get { return RawPosition.Length >= 8 ? BitConverter.ToSingle(RawPosition, 4) : 0F; }
            }

            public float Z
            {
                get { return RawPosition.Length >= 12 ? BitConverter.ToSingle(RawPosition, 8) : 0F; }
            }
        }

