        private void RestoreDrivingDatabasePack()
        {
            var db = RequireDatabase();
            var restored = 0;

            restored += RestoreNumericColumnSet(db, "Data_Car", "_backup_Database_DataCarDrivingPack", new[]
            {
                "GameTorqueScale",
                "GameDragScale",
                "Traction_Road",
                "Traction_OffRoad",
                "Traction_Snow",
                "LongAccelFrontScalarMax",
                "LongAccelRearScalarMax",
                "PuddleScale"
            });

            restored += RestoreNumericColumnSet(db, "Profile0_Career_Garage", "_backup_Database_ProfileGarageGripPack", new[]
            {
                "Traction_Road",
                "Traction_OffRoad",
                "Traction_Snow"
            });

            restored += RestoreNumericColumnSet(db, "Data_Car", "_backup_Database_DataCarSpeedPack", new[]
            {
                "TopSpeed-mph",
                "SimTopSpeed",
                "BodyAeroLongitudinalDrag"
            });

            restored += RestoreNumericColumnSet(db, "List_DrivingMode", "_backup_Database_ListDrivingModePack", new[]
            {
                "GameTorqueScale_Override"
            });

            restored += RestoreNumericColumnSet(db, "List_TireCompound", "_backup_Database_ListTireCompoundPack", new[]
            {
                "WetFrictionModFrictionScale",
                "WetFrictionModSlipScale",
                "WetOffroadFrictionScale",
                "WetOffroadSlipScale"
            });

            restored += RestoreNumericColumnSet(db, "Tracks", "_backup_Database_TracksDriftScore", new[]
            {
                "DriftScoreScalar"
            });

            restored += RestoreNumericColumnSet(db, "Profile0_Career_Garage", "_backup_Database_ProfileGarageOriginalOwner", new[]
            {
                "OriginalOwner"
            });

            restored += RestoreNumericColumnSet(db, "Profile0_Career_Garage", "_backup_Database_ProfileGarageSpeedPack", new[]
            {
                "TopSpeed"
            });

            restored += RestoreNumericColumnSet(db, "List_DragWallSettingsOverride", "_backup_Database_DragWallSpeedPack", new[]
            {
                "MinSpeedForDragWall",
                "MedSpeedForDragWall",
                "MaxSpeedForDragWall"
            });

            if (restored == 0)
                Log("No Driving Editor backups were found to restore.");
            else
                Log("Driving Editor restored " + restored + " supported column(s). Restart the game if a value was cached.");
        }

        private void RestoreAutoshow()
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)RestoreAutoshow);
                return;
            }

            _allCarsOn = false;
            UpdateAllCarsButton();
            SetStatus("Restore instructions shown");
            Log("Restore requested. Close Luna and the game, then reopen the game for Autoshow to restore.");
            ShowTranslatedMessageBox(
                this,
                "Please close Luna and the game." + Environment.NewLine + Environment.NewLine +
                "Then Reopen game for autoshow to restore.",
                MessageBoxButtons.OK,
                MessageBoxIcon.Information);
        }

        private void ShowInfo(string message)
        {
            if (InvokeRequired)
            {
                BeginInvoke((Action)(delegate { ShowInfo(message); }));
                return;
