            ShowLunaMessageDialog(this, TranslateMessageText(message), MessageBoxButtons.OK, MessageBoxIcon.Information);
        }

        private void ShowInfoBlocking(string message)
        {
            if (InvokeRequired)
            {
                Invoke((Action)(delegate { ShowInfo(message); }));
