            ShowInfo(message);
        }

        private bool ShowProceedDialog(string titleText, string messageText)
        {
            if (InvokeRequired)
                return (bool)Invoke(new Func<string, string, bool>(ShowProceedDialog), titleText, messageText);

            using (var dialog = new Form())
            {
                var displayTitle = TranslateMessageText(titleText);
                var displayMessage = TranslateMessageText(messageText);
                dialog.Text = string.IsNullOrWhiteSpace(displayTitle) ? Program.AppTitle : displayTitle;
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                Size bodySize;
                using (var measureFont = new Font("Segoe UI", 9.5F))
                {
                    bodySize = TextRenderer.MeasureText(displayMessage ?? string.Empty, measureFont, new Size(408, 1000), TextFormatFlags.WordBreak);
                }

                var bodyHeight = Math.Max(78, Math.Min(210, bodySize.Height + 18));
                var dialogHeight = 154 + bodyHeight;
                dialog.ClientSize = new Size(472, dialogHeight);

                var card = new ModernPanel();
                card.Location = new Point(14, 14);
                card.Size = new Size(444, dialogHeight - 28);
                card.FillColor = Surface;
                card.BorderColor = Border;
                card.CornerRadius = 14;
                dialog.Controls.Add(card);

                var title = new Label();
                title.Text = string.IsNullOrWhiteSpace(displayTitle) ? "Luna" : displayTitle;
                title.Font = new Font("Segoe UI Semibold", 13F);
                title.ForeColor = TextPrimary;
                title.BackColor = Surface;
                title.Location = new Point(18, 14);
                title.Size = new Size(408, 28);
                title.AutoEllipsis = true;
                card.Controls.Add(title);

                var body = new Label();
                body.Text = displayMessage;
                body.Font = new Font("Segoe UI", 9.5F);
                body.ForeColor = TextMuted;
                body.BackColor = Surface;
                body.Location = new Point(18, 52);
                body.Size = new Size(408, bodyHeight);
                card.Controls.Add(body);

                var cancel = MakeButton("Cancel", 206, card.Height - 44, 104, 30);
                cancel.Click += delegate
                {
                    dialog.DialogResult = DialogResult.Cancel;
                    dialog.Close();
                };
                card.Controls.Add(cancel);

                var proceed = MakeButton("Proceed", 318, card.Height - 44, 108, 30);
                MakeAccentButton(proceed, AccentGreen);
                proceed.Click += delegate
                {
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                card.Controls.Add(proceed);
                dialog.AcceptButton = proceed;
                dialog.CancelButton = cancel;

                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

        private string ShowLiveDrivingValuePrompt(LiveDrivingField field, string currentValue)
        {
            if (InvokeRequired)
            {
                return (string)Invoke(new Func<LiveDrivingField, string, string>(ShowLiveDrivingValuePrompt), field, currentValue);
            }

            using (var dialog = new Form())
            {
                dialog.Text = field.DisplayName + " Value";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.ClientSize = new Size(560, 252);
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                var title = new Label();
                title.Text = field.DisplayName;
                title.Location = new Point(18, 16);
                title.Size = new Size(520, 26);
                title.Font = new Font("Segoe UI Semibold", 11F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                dialog.Controls.Add(title);

                var body = new Label();
                body.Text = field.Description;
                body.Location = new Point(18, 48);
                body.Size = new Size(520, 60);
                body.ForeColor = TextMuted;
                body.BackColor = Color.Transparent;
                dialog.Controls.Add(body);

                var valueLabel = new Label();
                valueLabel.Text = field.Feature == RuntimeProfileFeature.Hover ? "Lift" : "Strength";
                valueLabel.Location = new Point(18, 128);
                valueLabel.Size = new Size(120, 24);
                valueLabel.ForeColor = TextPrimary;
                valueLabel.BackColor = AppBackground;
                valueLabel.Font = new Font("Segoe UI Semibold", 9F);
                dialog.Controls.Add(valueLabel);

                var valueBox = new TextBox();
                valueBox.Text = string.IsNullOrWhiteSpace(currentValue) ? GetLiveDrivingDefaultDisplayValue(field) : currentValue;
                valueBox.Location = new Point(144, 126);
                valueBox.Size = new Size(130, 28);
                valueBox.TextAlign = HorizontalAlignment.Right;
                StyleTextBox(valueBox);
                dialog.Controls.Add(valueBox);

                var hint = new Label();
                hint.Text = field.Feature == RuntimeProfileFeature.Hover
                    ? "Hover lift is uncapped. 0 holds height, positive rises, negative sinks. Start around 0.02 or -0.02."
                    : "Strength is uncapped. 100 is Luna's tuned default, 0 is neutral where supported.";
                hint.Location = new Point(18, 174);
                hint.Size = new Size(520, 24);
                hint.ForeColor = TextMuted;
                hint.BackColor = AppBackground;
                dialog.Controls.Add(hint);

                string result = null;
                var apply = MakeButton("Use Value", 350, 206, 96, 30);
                MakeAccentButton(apply, AccentBlue);
                apply.Click += delegate
                {
                    try
                    {
                        var parsed = ParseRuntimeFloatValue(field.Feature, valueBox.Text, field.DisplayName);
                        result = FormatRuntimeValueForBox(field.Feature, parsed);
                        dialog.DialogResult = DialogResult.OK;
                        dialog.Close();
                    }
                    catch (Exception ex)
                    {
