                string result = null;
                var apply = MakeButton("Use Value", 350, 176, 96, 30);
                MakeAccentButton(apply, AccentBlue);
                apply.Click += delegate
                {
                    try
                    {
                        if (IsFloatRuntimeFeature(feature))
                        {
                            var parsed = ParseRuntimeFloatValue(feature, valueBox.Text, labelText);
                            result = FormatRuntimeValueForBox(feature, parsed);
                        }
                        else
                        {
                            var parsed = ParseNonNegativeLong(valueBox.Text, labelText);
                            if (parsed > int.MaxValue)
                                throw new InvalidOperationException(labelText + " must be " + int.MaxValue.ToString(CultureInfo.InvariantCulture) + " or lower for the runtime hook.");
                            result = parsed.ToString(CultureInfo.InvariantCulture);
                        }
                        dialog.DialogResult = DialogResult.OK;
                        dialog.Close();
                    }
                    catch (Exception ex)
                    {
                        ShowTranslatedMessageBox(dialog, ex.Message, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    }
                };
                dialog.Controls.Add(apply);

                var cancel = MakeButton("Cancel", 456, 176, 82, 30);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = apply;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK ? result : null;
            }
        }

