        }

        private AccelerationConfigResult ShowAccelerationConfigPrompt()
        {
            if (InvokeRequired)
            {
                return (AccelerationConfigResult)Invoke(new Func<AccelerationConfigResult>(ShowAccelerationConfigPrompt));
            }

            NormalizeAccelerationConfigState();

            using (var dialog = new Form())
            {
                dialog.Text = "Acceleration";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.ClientSize = new Size(660, 290);
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                var body = new Label();
                body.Text = "Choose one acceleration mode. Custom Speed uses the typed multiplier; Percentage uses micro adjustment.";
                body.Location = new Point(24, 16);
                body.Size = new Size(612, 36);
                body.ForeColor = TextMuted;
                body.BackColor = Color.Transparent;
                body.TextAlign = ContentAlignment.MiddleCenter;
                dialog.Controls.Add(body);

                var customCard = new ModernPanel();
                customCard.SetBounds(24, 62, 612, 58);
                customCard.FillColor = SurfaceAlt;
                customCard.BorderColor = Border;
                customCard.CornerRadius = 10;
                customCard.BackColor = SurfaceAlt;
                dialog.Controls.Add(customCard);

                var customToggle = new StatusDotToggle();
                customToggle.Location = new Point(16, 17);
                customToggle.Size = new Size(44, 24);
                customToggle.BackColor = SurfaceAlt;
                customToggle.Checked = !_accelerationUsePercentage;
                customCard.Controls.Add(customToggle);

                var speedLabel = new Label();
                speedLabel.Text = "Custom Speed";
                speedLabel.Location = new Point(74, 17);
                speedLabel.Size = new Size(150, 24);
                speedLabel.ForeColor = TextPrimary;
                speedLabel.BackColor = Color.Transparent;
                speedLabel.Font = new Font("Segoe UI Semibold", 9.5F);
                customCard.Controls.Add(speedLabel);

                var speedBox = MakeRoundedValueTextBox(customCard, 280, 12, 150, 34,
                    FormatFloat(Math.Max(_accelerationToggleMultiplier, SafeAccelerationMultiplier)), HorizontalAlignment.Center);

                var customDefault = new ModernCheckBox();
                customDefault.Location = new Point(458, 17);
                customDefault.Size = new Size(24, 24);
                customDefault.Checked = !_accelerationDefaultUsePercentage;
                customCard.Controls.Add(customDefault);

                var customDefaultLabel = new Label();
                customDefaultLabel.Text = "Make Default";
                customDefaultLabel.Location = new Point(488, 17);
                customDefaultLabel.Size = new Size(112, 24);
                customDefaultLabel.ForeColor = TextMuted;
                customDefaultLabel.BackColor = Color.Transparent;
                customDefaultLabel.Cursor = Cursors.Hand;
                customDefaultLabel.Click += delegate { if (customDefault.Enabled) customDefault.Checked = !customDefault.Checked; };
                customCard.Controls.Add(customDefaultLabel);

                var percentCard = new ModernPanel();
                percentCard.SetBounds(24, 128, 612, 84);
                percentCard.FillColor = SurfaceAlt;
                percentCard.BorderColor = Border;
                percentCard.CornerRadius = 10;
                percentCard.BackColor = SurfaceAlt;
                dialog.Controls.Add(percentCard);

                var percentToggle = new StatusDotToggle();
                percentToggle.Location = new Point(16, 14);
                percentToggle.Size = new Size(44, 24);
                percentToggle.BackColor = SurfaceAlt;
                percentToggle.Checked = _accelerationUsePercentage;
                percentCard.Controls.Add(percentToggle);

                var percentLabel = new Label();
                percentLabel.Text = "Percentage";
                percentLabel.Location = new Point(74, 15);
                percentLabel.Size = new Size(150, 24);
                percentLabel.ForeColor = TextPrimary;
                percentLabel.BackColor = Color.Transparent;
                percentLabel.Font = new Font("Segoe UI Semibold", 9.5F);
                percentCard.Controls.Add(percentLabel);

                var percentDefault = new ModernCheckBox();
                percentDefault.Location = new Point(458, 46);
                percentDefault.Size = new Size(24, 24);
                percentDefault.Checked = _accelerationDefaultUsePercentage;
                percentCard.Controls.Add(percentDefault);

                var percentDefaultLabel = new Label();
                percentDefaultLabel.Text = "Make Default";
                percentDefaultLabel.Location = new Point(488, 46);
                percentDefaultLabel.Size = new Size(112, 24);
                percentDefaultLabel.ForeColor = TextMuted;
                percentDefaultLabel.BackColor = Color.Transparent;
                percentDefaultLabel.Cursor = Cursors.Hand;
                percentDefaultLabel.Click += delegate { if (percentDefault.Enabled) percentDefault.Checked = !percentDefault.Checked; };
                percentCard.Controls.Add(percentDefaultLabel);

                var percentSlider = new ModernSlider();
                percentSlider.Location = new Point(74, 48);
                percentSlider.Size = new Size(240, 28);
                percentSlider.Minimum = 0;
                percentSlider.Maximum = MaxAccelerationPercent;
                percentSlider.Value = Math.Max(0, Math.Min(MaxAccelerationPercent, _accelerationPercentage));
                percentSlider.TrackColor = Border;
                percentSlider.FillColor = AccentBlue;
                percentSlider.ThumbColor = Color.White;
                percentSlider.ThumbBorderColor = Blend(AccentBlue, Color.White, 0.24F);
                percentSlider.BackColor = Color.Transparent;
                percentCard.Controls.Add(percentSlider);

                var percentBox = MakeRoundedValueTextBox(percentCard, 324, 44, 54, 34,
                    percentSlider.Value.ToString(CultureInfo.InvariantCulture), HorizontalAlignment.Center);

                var percentSuffix = new Label();
                percentSuffix.Text = "%";
                percentSuffix.Location = new Point(384, 50);
                percentSuffix.Size = new Size(20, 24);
                percentSuffix.ForeColor = TextMuted;
                percentSuffix.Font = new Font("Segoe UI Semibold", 10F);
                percentSuffix.BackColor = Color.Transparent;
                percentCard.Controls.Add(percentSuffix);

                var syncing = false;
                Action updateEnabled = delegate
                {
                    speedBox.Enabled = customToggle.Checked;
                    customDefault.Enabled = customToggle.Checked;
                    customDefaultLabel.ForeColor = customToggle.Checked ? TextPrimary : TextMuted;
                    percentSlider.Enabled = percentToggle.Checked;
                    percentBox.Enabled = percentToggle.Checked;
                    percentDefault.Enabled = percentToggle.Checked;
                    percentDefaultLabel.ForeColor = percentToggle.Checked ? TextPrimary : TextMuted;
                    speedLabel.ForeColor = customToggle.Checked ? TextPrimary : TextMuted;
                    percentLabel.ForeColor = percentToggle.Checked ? TextPrimary : TextMuted;
                };

                customToggle.CheckedChanged += delegate
                {
                    if (syncing)
                        return;
                    syncing = true;
                    if (customToggle.Checked)
                    {
                        percentToggle.Checked = false;
                        percentDefault.Checked = false;
                    }
                    else if (!percentToggle.Checked)
                    {
                        customToggle.Checked = true;
                    }
                    syncing = false;
                    updateEnabled();
                };

                percentToggle.CheckedChanged += delegate
                {
                    if (syncing)
                        return;
                    syncing = true;
                    if (percentToggle.Checked)
                    {
                        customToggle.Checked = false;
                        customDefault.Checked = false;
                    }
                    else if (!customToggle.Checked)
                    {
                        percentToggle.Checked = true;
                    }
                    syncing = false;
                    updateEnabled();
                };

                customDefault.CheckedChanged += delegate
                {
                    if (customDefault.Checked)
                        percentDefault.Checked = false;
                };

                percentDefault.CheckedChanged += delegate
                {
                    if (percentDefault.Checked)
                        customDefault.Checked = false;
                };

                percentSlider.ValueChanged += delegate
                {
                    if (syncing)
                        return;
                    percentBox.Text = percentSlider.Value.ToString(CultureInfo.InvariantCulture);
                };

                percentBox.TextChanged += delegate
                {
                    if (syncing)
                        return;
                    int parsed;
                    if (!int.TryParse((percentBox.Text ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
                        return;
                    parsed = Math.Max(0, Math.Min(MaxAccelerationPercent, parsed));
                    if (percentSlider.Value == parsed)
                        return;
                    syncing = true;
                    percentSlider.Value = parsed;
                    syncing = false;
                };

                updateEnabled();

                AccelerationConfigResult result = null;
                var apply = MakeButton("Use Settings", 424, 236, 116, 32);
                MakeAccentButton(apply, AccentBlue);
                apply.Click += delegate
                {
                    try
                    {
                        var customValue = _accelerationToggleMultiplier;
                        if (customToggle.Checked)
                            customValue = ParsePositiveFloat(speedBox.Text, "Custom acceleration speed");
                        int percent;
                        if (!int.TryParse((percentBox.Text ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out percent))
                        {
                            if (percentToggle.Checked)
                                throw new InvalidOperationException("Acceleration percentage must be a whole number from 0 to 100.");
                            percent = _accelerationPercentage;
                        }
                        percent = Math.Max(0, Math.Min(MaxAccelerationPercent, percent));
                        result = new AccelerationConfigResult
                        {
                            UsePercentage = percentToggle.Checked,
                            CustomMultiplier = customValue,
                            Percentage = percent,
                            MakeDefaultCustom = customToggle.Checked && customDefault.Checked,
                            MakeDefaultPercentage = percentToggle.Checked && percentDefault.Checked
                        };
                        dialog.DialogResult = DialogResult.OK;
                        dialog.Close();
                    }
                    catch (Exception ex)
                    {
                        ShowTranslatedMessageBox(dialog, ex.Message, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    }
                };
                dialog.Controls.Add(apply);

                var cancel = MakeButton("Cancel", 550, 236, 86, 32);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = apply;
                dialog.CancelButton = cancel;

                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK ? result : null;
            }
        }

