                updateEnabled();

                var reset = MakeButton("Reset Defaults", 18, 480, 130, 32);
                reset.Click += delegate
                {
                    SetFovCameraSliderValue(allSlider, allBox, DefaultFovDegrees);
                    SetFovCameraSliderValue(dashboardSlider, dashboardBox, DefaultFovDegrees);
                    SetFovCameraSliderValue(chaseSlider, chaseBox, DefaultFovDegrees);
                    SetFovCameraSliderValue(farChaseSlider, farChaseBox, DefaultFovDegrees);
                    SetFovCameraSliderValue(hoodSlider, hoodBox, DefaultFovDegrees);
                    SetFovCameraSliderValue(bumperSlider, bumperBox, DefaultFovDegrees);
                };
                dialog.Controls.Add(reset);

                var save = MakeButton("Save FOV", 560, 480, 100, 32);
                MakeAccentButton(save, AccentBlue);
                save.Click += delegate
                {
                    float all;
                    float dashboard;
                    float chase;
                    float farChase;
                    float hood;
                    float bumper;
                    if (!TryReadFovCameraValue(dialog, allBox, "All Cameras", out all) ||
                        !TryReadFovCameraValue(dialog, dashboardBox, "Dashboard", out dashboard) ||
                        !TryReadFovCameraValue(dialog, chaseBox, "Chase", out chase) ||
                        !TryReadFovCameraValue(dialog, farChaseBox, "Far Chase", out farChase) ||
                        !TryReadFovCameraValue(dialog, hoodBox, "Hood", out hood) ||
                        !TryReadFovCameraValue(dialog, bumperBox, "Bumper", out bumper))
                    {
                        return;
                    }

                    _fovControlAll = controlAll.Checked;
                    _fovAllDegrees = all;
                    if (_fovControlAll)
                    {
                        _fovDashboardDegrees = all;
                        _fovChaseDegrees = all;
                        _fovFarChaseDegrees = all;
                        _fovHoodDegrees = all;
                        _fovBumperDegrees = all;
                    }
                    else
                    {
                        _fovDashboardDegrees = dashboard;
                        _fovChaseDegrees = chase;
                        _fovFarChaseDegrees = farChase;
                        _fovHoodDegrees = hood;
                        _fovBumperDegrees = bumper;
                    }
                    NormalizeFovConfig();

                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(save);

                var cancel = MakeButton("Cancel", 674, 480, 84, 32);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = save;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

        private ModernSlider AddFovCameraSlider(Form dialog, string labelText, int y, float currentValue, out TextBox valueBox, out Label valueLabel)
        {
            var label = new Label();
            label.Text = labelText;
            label.Location = new Point(18, y + 8);
            label.Size = new Size(112, 22);
            label.Font = new Font("Segoe UI Semibold", 9F);
            label.ForeColor = TextPrimary;
            label.BackColor = AppBackground;
            dialog.Controls.Add(label);

            var localValueBox = MakeRoundedValueTextBox(dialog, 134, y + 2, 64, 32,
                ((int)Math.Round(NormalizeFovDegrees(currentValue))).ToString(CultureInfo.InvariantCulture), HorizontalAlignment.Right);
            SetTranslatedToolTip(localValueBox, "Type a FOV number from 1 to 360.");

            var localValueLabel = new Label();
            localValueLabel.Text = localValueBox.Text + " degrees";
            localValueLabel.Location = new Point(208, y + 5);
            localValueLabel.Size = new Size(98, 28);
            localValueLabel.TextAlign = ContentAlignment.MiddleCenter;
            localValueLabel.Font = new Font("Segoe UI Semibold", 9F);
            localValueLabel.ForeColor = TextPrimary;
            localValueLabel.BackColor = SurfaceAlt;
            dialog.Controls.Add(localValueLabel);

            var slider = new ModernSlider();
            slider.Location = new Point(318, y + 4);
            slider.Size = new Size(430, 30);
            slider.Minimum = MinimumFovDegrees;
            slider.Maximum = MaximumFovDegrees;
            slider.Value = Math.Max(slider.Minimum, Math.Min(slider.Maximum, (int)Math.Round(NormalizeFovDegrees(currentValue))));
            slider.TrackColor = Border;
            slider.FillColor = AccentBlue;
            slider.ThumbColor = Color.White;
            slider.ThumbBorderColor = Blend(AccentBlue, Color.White, 0.24F);
            slider.BackColor = Color.Transparent;
            dialog.Controls.Add(slider);

            var syncing = false;
            slider.ValueChanged += delegate
            {
                if (syncing)
                    return;
                localValueBox.Text = slider.Value.ToString(CultureInfo.InvariantCulture);
                localValueLabel.Text = slider.Value.ToString(CultureInfo.InvariantCulture) + " degrees";
            };
            localValueBox.TextChanged += delegate
            {
                int parsed;
                if (!int.TryParse((localValueBox.Text ?? string.Empty).Replace(",", string.Empty).Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
                    return;
                if (parsed < slider.Minimum || parsed > slider.Maximum)
                    return;

                syncing = true;
                try
                {
                    slider.Value = parsed;
                    localValueLabel.Text = parsed.ToString(CultureInfo.InvariantCulture) + " degrees";
                }
                finally
                {
                    syncing = false;
                }
            };

            valueBox = localValueBox;
            valueLabel = localValueLabel;
            return slider;
        }

        private static void SetFovCameraSliderValue(ModernSlider slider, TextBox valueBox, float value)
        {
            var normalized = (int)Math.Round(NormalizeFovDegrees(value));
            if (slider != null)
                slider.Value = Math.Max(slider.Minimum, Math.Min(slider.Maximum, normalized));
            if (valueBox != null)
                valueBox.Text = normalized.ToString(CultureInfo.InvariantCulture);
        }

        private void SetFovCameraSliderEnabled(ModernSlider slider, TextBox valueBox, Label valueLabel, bool enabled)
        {
            if (slider != null)
            {
                slider.Enabled = enabled;
                slider.BackColor = Color.Transparent;
            }
            if (valueBox != null)
            {
                valueBox.Enabled = enabled;
                valueBox.ForeColor = enabled ? TextPrimary : TextMuted;
            }
            if (valueLabel != null)
            {
                valueLabel.ForeColor = enabled ? TextPrimary : TextMuted;
                valueLabel.BackColor = enabled ? SurfaceAlt : Surface;
            }
        }

        private bool TryReadFovCameraValue(IWin32Window owner, TextBox valueBox, string labelText, out float value)
        {
            value = DefaultFovDegrees;
            if (TryParseFovDegrees(valueBox == null ? string.Empty : valueBox.Text, out value))
                return true;

            ShowTranslatedMessageBox(owner, labelText + " FOV must be a number from " + MinimumFovDegrees.ToString(CultureInfo.InvariantCulture) + " to " + MaximumFovDegrees.ToString(CultureInfo.InvariantCulture) + ".", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return false;
        }

