                value.Increment = 1M;
                value.Value = ToClampedDecimal(currentValue, value.Minimum, value.Maximum);
                value.TextAlign = HorizontalAlignment.Right;
                value.BackColor = SurfaceAlt;
                value.ForeColor = TextPrimary;
                value.Font = new Font("Segoe UI Semibold", 9F);
