        private bool ShowGrapplingHookConfigPrompt()
        {
            if (InvokeRequired)
                return (bool)Invoke(new Func<bool>(ShowGrapplingHookConfigPrompt));

            NormalizeGrapplingHookConfig();

            using (var dialog = new Form())
            {
                dialog.Text = "Grappling Hook Configuration";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.ClientSize = new Size(760, 398);
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                var title = new Label();
                title.Text = "Grappling Hook Configuration";
                title.Location = new Point(18, 16);
                title.Size = new Size(720, 26);
                title.Font = new Font("Segoe UI Semibold", 11F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                dialog.Controls.Add(title);

                var body = new Label();
                body.Text = "Aim with the camera, hold the Grappling Hook key to pull toward that point, and release to keep the exit momentum.";
                body.Location = new Point(18, 48);
                body.Size = new Size(720, 38);
                body.ForeColor = TextMuted;
                body.BackColor = AppBackground;
                dialog.Controls.Add(body);

                AddSuperStrengthHeaderLabel(dialog, "Value", 212, 94, 106);
                AddSuperStrengthHeaderLabel(dialog, "Default", 334, 94, 82);
                AddSuperStrengthHeaderLabel(dialog, "What it does", 432, 94, 292);

                var distance = AddSuperStrengthConfigNumber(dialog, 124, "Target distance", _grapplingHookTargetDistance, DefaultGrapplingHookTargetDistance, 10M, 1000M, 5M, 1, "How far ahead the camera aim point is placed.");
                var minimum = AddSuperStrengthConfigNumber(dialog, 164, "Minimum speed", _grapplingHookMinimumSpeed, DefaultGrapplingHookMinimumSpeed, 1M, 500M, 1M, 1, "Lowest pull speed when the hook engages.");
                var maximum = AddSuperStrengthConfigNumber(dialog, 204, "Maximum speed", _grapplingHookMaximumSpeed, DefaultGrapplingHookMaximumSpeed, 1M, 700M, 1M, 1, "Highest velocity the pull is allowed to retarget.");
                var ramp = AddSuperStrengthConfigNumber(dialog, 244, "Ramp per second", _grapplingHookRampPerSecond, DefaultGrapplingHookRampPerSecond, 0M, 1000M, 5M, 1, "How quickly the pull grows while held.");
                var lift = AddSuperStrengthConfigNumber(dialog, 284, "Vertical scale", _grapplingHookVerticalScale, DefaultGrapplingHookVerticalScale, 0M, 1.5M, 0.05M, 2, "How much camera up/down aim affects the pull.");

                var reset = MakeButton("Reset Defaults", 18, 348, 128, 32);
                reset.Click += delegate
                {
                    distance.Value = ToClampedDecimal(DefaultGrapplingHookTargetDistance, distance.Minimum, distance.Maximum);
                    minimum.Value = ToClampedDecimal(DefaultGrapplingHookMinimumSpeed, minimum.Minimum, minimum.Maximum);
                    maximum.Value = ToClampedDecimal(DefaultGrapplingHookMaximumSpeed, maximum.Minimum, maximum.Maximum);
                    ramp.Value = ToClampedDecimal(DefaultGrapplingHookRampPerSecond, ramp.Minimum, ramp.Maximum);
                    lift.Value = ToClampedDecimal(DefaultGrapplingHookVerticalScale, lift.Minimum, lift.Maximum);
                };
                dialog.Controls.Add(reset);

                var save = MakeButton("Save Config", 522, 348, 118, 32);
                MakeAccentButton(save, AccentBlue);
                save.Click += delegate
                {
                    var newMinimum = (float)minimum.Value;
                    var newMaximum = (float)maximum.Value;
                    if (newMaximum < newMinimum)
                    {
                        ShowTranslatedMessageBox(dialog, "Maximum speed must be at least the minimum speed.", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        return;
                    }

                    _grapplingHookTargetDistance = (float)distance.Value;
                    _grapplingHookMinimumSpeed = newMinimum;
                    _grapplingHookMaximumSpeed = newMaximum;
                    _grapplingHookRampPerSecond = (float)ramp.Value;
                    _grapplingHookVerticalScale = (float)lift.Value;
                    NormalizeGrapplingHookConfig();

                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(save);

                var cancel = MakeButton("Cancel", 652, 348, 86, 32);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = save;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

