                AddSuperStrengthHeaderLabel(dialog, "What it does", 432, 94, 292);

                var shove = AddSuperStrengthConfigNumber(dialog, 124, "Shove speed", _superStrengthShoveSpeed, DefaultSuperStrengthShoveSpeed, 1M, 500M, 1M, 1, "Main target speed as soon as the key is held.");
                var minimum = AddSuperStrengthConfigNumber(dialog, 164, "Minimum speed", _superStrengthMinSpeed, DefaultSuperStrengthMinSpeed, 1M, 500M, 1M, 1, "Lowest assisted speed Super Strength will enforce.");
                var maximum = AddSuperStrengthConfigNumber(dialog, 204, "Maximum speed", _superStrengthMaxSpeed, DefaultSuperStrengthMaxSpeed, 1M, 500M, 1M, 1, "Safety cap so the shove stays controllable.");
                var ramp = AddSuperStrengthConfigNumber(dialog, 244, "Acceleration ramp", _superStrengthAccelerationPerSecond, DefaultSuperStrengthAccelerationPerSecond, 0M, 500M, 1M, 1, "Speed gained per second while the key is held.");
                var damping = AddSuperStrengthConfigNumber(dialog, 284, "Vertical damping", _superStrengthVerticalDamping, DefaultSuperStrengthVerticalDamping, 0M, 1M, 0.05M, 2, "How much up/down motion remains. Lower feels flatter.");
                var clamp = AddSuperStrengthConfigNumber(dialog, 324, "Vertical clamp", _superStrengthVerticalClamp, DefaultSuperStrengthVerticalClamp, 0M, 100M, 0.5M, 1, "Maximum up/down velocity allowed while boosting.");

                var reset = MakeButton("Reset Defaults", 18, 388, 128, 32);
                reset.Click += delegate
                {
                    shove.Value = ToClampedDecimal(DefaultSuperStrengthShoveSpeed, shove.Minimum, shove.Maximum);
                    minimum.Value = ToClampedDecimal(DefaultSuperStrengthMinSpeed, minimum.Minimum, minimum.Maximum);
                    maximum.Value = ToClampedDecimal(DefaultSuperStrengthMaxSpeed, maximum.Minimum, maximum.Maximum);
                    ramp.Value = ToClampedDecimal(DefaultSuperStrengthAccelerationPerSecond, ramp.Minimum, ramp.Maximum);
                    damping.Value = ToClampedDecimal(DefaultSuperStrengthVerticalDamping, damping.Minimum, damping.Maximum);
                    clamp.Value = ToClampedDecimal(DefaultSuperStrengthVerticalClamp, clamp.Minimum, clamp.Maximum);
                };
                dialog.Controls.Add(reset);

                var save = MakeButton("Save Config", 522, 388, 118, 32);
                MakeAccentButton(save, AccentBlue);
                save.Click += delegate
                {
                    var newShove = (float)shove.Value;
                    var newMinimum = (float)minimum.Value;
                    var newMaximum = (float)maximum.Value;
                    var requiredMax = Math.Max(newShove, newMinimum);
                    if (newMaximum < requiredMax)
                    {
                        ShowTranslatedMessageBox(dialog, "Maximum speed must be at least the shove speed and minimum speed.", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                        return;
                    }

                    _superStrengthShoveSpeed = newShove;
                    _superStrengthMinSpeed = newMinimum;
                    _superStrengthMaxSpeed = newMaximum;
                    _superStrengthAccelerationPerSecond = (float)ramp.Value;
                    _superStrengthVerticalDamping = (float)damping.Value;
                    _superStrengthVerticalClamp = (float)clamp.Value;
                    NormalizeSuperStrengthConfig();

                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };
                dialog.Controls.Add(save);

                var cancel = MakeButton("Cancel", 652, 388, 86, 32);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = save;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

        private NumericUpDown AddSuperStrengthConfigNumber(
            Form dialog,
            int y,
            string labelText,
            float currentValue,
            float defaultValue,
            decimal minimum,
            decimal maximum,
            decimal increment,
            int decimals,
            string description)
        {
            var label = new Label();
            label.Text = labelText;
            label.Location = new Point(18, y + 4);
            label.Size = new Size(178, 22);
            label.Font = new Font("Segoe UI Semibold", 9F);
            label.ForeColor = TextPrimary;
            label.BackColor = AppBackground;
            dialog.Controls.Add(label);

            var value = new NumericUpDown();
            value.Location = new Point(212, y);
            value.Size = new Size(106, 26);
            value.Minimum = minimum;
            value.Maximum = maximum;
            value.Increment = increment;
            value.DecimalPlaces = decimals;
            value.Value = ToClampedDecimal(currentValue, minimum, maximum);
            value.TextAlign = HorizontalAlignment.Right;
            value.BackColor = SurfaceAlt;
            value.ForeColor = TextPrimary;
            value.Font = new Font("Segoe UI Semibold", 9F);
            dialog.Controls.Add(value);

            var defaultLabel = new Label();
            defaultLabel.Text = FormatFloat(defaultValue);
            defaultLabel.Location = new Point(334, y + 4);
            defaultLabel.Size = new Size(82, 22);
            defaultLabel.ForeColor = TextMuted;
            defaultLabel.BackColor = AppBackground;
            defaultLabel.TextAlign = ContentAlignment.MiddleRight;
            dialog.Controls.Add(defaultLabel);

            var detail = new Label();
            detail.Text = description;
            detail.Location = new Point(432, y + 4);
            detail.Size = new Size(292, 22);
            detail.ForeColor = TextMuted;
            detail.BackColor = AppBackground;
            detail.AutoEllipsis = true;
            dialog.Controls.Add(detail);

            return value;
        }

        private void AddSuperStrengthHeaderLabel(Form dialog, string text, int x, int y, int width)
        {
            var label = new Label();
            label.Text = text;
            label.Location = new Point(x, y);
            label.Size = new Size(width, 22);
            label.ForeColor = TextPrimary;
            label.BackColor = AppBackground;
            label.Font = new Font("Segoe UI Semibold", 8.7F);
            label.TextAlign = x == 334 ? ContentAlignment.MiddleRight : ContentAlignment.MiddleLeft;
            dialog.Controls.Add(label);
        }

        private static decimal ToClampedDecimal(float value, decimal minimum, decimal maximum)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
                return minimum;

            var decimalValue = (decimal)value;
            if (decimalValue < minimum)
                return minimum;
            if (decimalValue > maximum)
                return maximum;
            return decimalValue;
        }

