        private int? ShowKeybindPrompt(string dialogTitle, string promptText)
        {
            if (InvokeRequired)
            {
                return (int?)Invoke(new Func<string, string, int?>(ShowKeybindPrompt), dialogTitle, promptText);
            }

            using (var dialog = new Form())
            {
                dialog.Text = dialogTitle;
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.KeyPreview = true;
                dialog.ClientSize = new Size(420, 142);
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                var title = new Label();
                title.Text = promptText;
                title.Location = new Point(18, 16);
                title.Size = new Size(384, 24);
                title.Font = new Font("Segoe UI Semibold", 11F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                dialog.Controls.Add(title);

                var body = new Label();
                body.Text = "Press a keyboard key. Escape cancels.";
                body.Location = new Point(18, 48);
                body.Size = new Size(384, 38);
                body.ForeColor = TextMuted;
                body.BackColor = AppBackground;
                dialog.Controls.Add(body);

                int? result = null;
                dialog.KeyDown += delegate(object sender, KeyEventArgs e)
                {
                    if (e.KeyCode == Keys.Escape)
                    {
                        dialog.DialogResult = DialogResult.Cancel;
                        dialog.Close();
                        return;
                    }

                    if (e.KeyCode == Keys.ShiftKey || e.KeyCode == Keys.ControlKey || e.KeyCode == Keys.Menu)
                        return;

                    result = (int)e.KeyCode;
                    e.SuppressKeyPress = true;
                    dialog.DialogResult = DialogResult.OK;
                    dialog.Close();
                };

                var cancel = MakeButton("Cancel", 318, 96, 84, 30);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);
                dialog.CancelButton = cancel;

                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK ? result : null;
            }
        }

