        private bool ShowProfileBoostPackPrompt()
        {
            if (InvokeRequired)
            {
                return (bool)Invoke(new Func<bool>(ShowProfileBoostPackPrompt));
            }

            using (var dialog = new Form())
            {
                dialog.Text = "Profile Boost Pack";
                dialog.StartPosition = FormStartPosition.CenterParent;
                dialog.FormBorderStyle = FormBorderStyle.FixedDialog;
                dialog.MaximizeBox = false;
                dialog.MinimizeBox = false;
                dialog.ShowInTaskbar = false;
                dialog.ClientSize = new Size(600, 408);
                dialog.BackColor = AppBackground;
                dialog.ForeColor = TextPrimary;
                dialog.Font = new Font("Segoe UI", 9F);

                var title = new Label();
                title.Text = "Profile Boost Pack values";
                title.Location = new Point(18, 16);
                title.Size = new Size(560, 24);
                title.Font = new Font("Segoe UI Semibold", 11F);
                title.ForeColor = TextPrimary;
                title.BackColor = AppBackground;
                dialog.Controls.Add(title);

                var body = new Label();
                body.Text = "Edit the pack values, then press Apply on the row. XP Gain uses the skill-point reward path: 1 skill point = 200 XP.";
                body.Location = new Point(18, 48);
                body.Size = new Size(560, 42);
                body.ForeColor = TextMuted;
                body.BackColor = AppBackground;
                dialog.Controls.Add(body);

                var creditsBox = AddPackValueBox(dialog, "Credits", _profilePackCredits.ToString(CultureInfo.InvariantCulture), 104);
                var spinsBox = AddPackValueBox(dialog, "Both Wheelspins", _profilePackWheelspins.ToString(CultureInfo.InvariantCulture), 138);
                var skillBox = AddPackValueBox(dialog, "Skill Points", _profilePackSkillPoints.ToString(CultureInfo.InvariantCulture), 172);
                var xpBox = AddPackValueBox(dialog, "XP Gain", _profilePackXpGainXp.ToString(CultureInfo.InvariantCulture), 218);
                var firesBox = AddPackValueBox(dialog, "XP fires", _profilePackXpGainFireCount.ToString(CultureInfo.InvariantCulture), 252);

                var xpHint = new Label();
                xpHint.Text = "Example: 10000 XP = 50 skill points. Use 0 fires for continuous; 1 fires once.";
                xpHint.Location = new Point(180, 286);
                xpHint.Size = new Size(380, 22);
                xpHint.ForeColor = TextMuted;
                xpHint.BackColor = AppBackground;
                dialog.Controls.Add(xpHint);

                var xpSummary = new Label();
                xpSummary.Location = new Point(18, 314);
                xpSummary.Size = new Size(560, 42);
                xpSummary.ForeColor = AccentGreen;
                xpSummary.BackColor = AppBackground;
                xpSummary.Font = new Font("Segoe UI Semibold", 9F);
                dialog.Controls.Add(xpSummary);

                Action updateXpSummary = delegate
                {
                    int xp;
                    if (!int.TryParse(xpBox.Text.Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out xp) || xp <= 0)
                    {
                        xpSummary.Text = "XP Gain must be a whole XP number greater than zero.";
                        xpSummary.ForeColor = AccentRed;
                        return;
                    }

                    int fires;
                    if (!int.TryParse(firesBox.Text.Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out fires) || fires < 0)
                    {
                        xpSummary.Text = "XP fires must be a whole number 0 or greater.";
                        xpSummary.ForeColor = AccentRed;
                        return;
                    }

                    var roundedXp = RoundXpToSkillPointEvent(xp);
                    var skillPoints = roundedXp / XpGainXpPerSkillPoint;
                    if (roundedXp == xp)
                    {
                        xpSummary.Text = "XP Gain: " + xp.ToString(CultureInfo.InvariantCulture) + " XP = " +
                            skillPoints.ToString(CultureInfo.InvariantCulture) + " skill point(s) per fire" +
                            (fires > 0 ? "; total " + ((long)xp * fires).ToString(CultureInfo.InvariantCulture) + " XP." : "; continuous until turned off.");
                        xpSummary.ForeColor = AccentGreen;
                    }
                    else
                    {
                        xpSummary.Text = "XP Gain will round to " + roundedXp.ToString(CultureInfo.InvariantCulture) + " XP = " +
                            skillPoints.ToString(CultureInfo.InvariantCulture) + " skill point(s) per fire.";
                        xpSummary.ForeColor = AccentOrange;
                    }
                };
                xpBox.TextChanged += delegate { updateXpSummary(); };
                firesBox.TextChanged += delegate { updateXpSummary(); };
                updateXpSummary();

                var apply = MakeButton("Use Values", 392, 362, 96, 30);
                MakeAccentButton(apply, AccentBlue);
                apply.Click += delegate
                {
                    try
                    {
                        var credits = ParseNonNegativeLong(creditsBox.Text, "Credits");
                        var spins = ParseNonNegativeLong(spinsBox.Text, "Both Wheelspins");
                        var skills = ParseNonNegativeLong(skillBox.Text, "Skill Points");
                        if (credits > int.MaxValue || spins > int.MaxValue || skills > int.MaxValue)
                            throw new InvalidOperationException("Profile Boost Pack values must be " + int.MaxValue.ToString(CultureInfo.InvariantCulture) + " or lower.");

                        int xp;
                        if (!int.TryParse(xpBox.Text.Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out xp) || xp <= 0)
                            throw new InvalidOperationException("XP Gain must be a whole XP number greater than zero.");

                        var roundedXp = RoundXpToSkillPointEvent(xp);
                        if (roundedXp != xp)
                        {
                            if (!ShowXpRoundedChoice(xp, roundedXp))
                            {
                                xpBox.Focus();
                                xpBox.SelectAll();
                                updateXpSummary();
                                return;
                            }

                            xp = roundedXp;
                            xpBox.Text = xp.ToString(CultureInfo.InvariantCulture);
                        }

                        int fires;
                        if (!int.TryParse(firesBox.Text.Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out fires) || fires < 0)
                            throw new InvalidOperationException("XP fires must be a whole number 0 or greater. Use 0 for continuous.");
                        fires = Math.Min(100000, fires);

                        _profilePackCredits = credits;
                        _profilePackWheelspins = (int)spins;
                        _profilePackSkillPoints = (int)skills;
                        _profilePackXpGainXp = xp;
                        _profilePackXpGainFireCount = fires;
                        dialog.DialogResult = DialogResult.OK;
                        dialog.Close();
                    }
                    catch (Exception ex)
                    {
                        ShowTranslatedMessageBox(dialog, ex.Message, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                    }
                };
                dialog.Controls.Add(apply);

                var cancel = MakeButton("Cancel", 496, 362, 84, 30);
                cancel.DialogResult = DialogResult.Cancel;
                dialog.Controls.Add(cancel);

                dialog.AcceptButton = apply;
                dialog.CancelButton = cancel;
                PrepareDialogForLanguage(dialog);
                return dialog.ShowDialog(this) == DialogResult.OK;
            }
        }

