        private static long ParseNonNegativeLong(string text, string label)
        {
            long value;
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (!long.TryParse(normalized, out value) || value < 0)
                throw new InvalidOperationException(label + " must be a whole number greater than or equal to zero.");
            return value;
        }

        private static float ParsePositiveFloat(string text, string label)
        {
            float value;
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (!float.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || value <= 0 || float.IsNaN(value) || float.IsInfinity(value))
                throw new InvalidOperationException(label + " must be a positive number. Example: 5 or 10.");
            return value;
        }

        private static float ParseFloat(string text, string label)
        {
            float value;
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (!float.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || float.IsNaN(value) || float.IsInfinity(value))
                throw new InvalidOperationException(label + " must be a number. Example: -100, 0, 100, or 10000.");
            return value;
        }

        private static float ParseNonNegativeFloat(string text, string label)
        {
            float value;
            var normalized = (text ?? string.Empty).Replace(",", string.Empty).Trim();
            if (!float.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || value < 0 || float.IsNaN(value) || float.IsInfinity(value))
                throw new InvalidOperationException(label + " must be zero or higher. Example: 0, 1, 5, or 10.");
            return value;
        }

        private static bool IsFiniteFloat(float value)
        {
            return !float.IsNaN(value) && !float.IsInfinity(value);
        }

        private static string FormatFloat(float value)
        {
            return value.ToString("0.###", CultureInfo.InvariantCulture);
        }

        private static int FloatBits(float value)
        {
            return BitConverter.ToInt32(BitConverter.GetBytes(value), 0);
        }

        private static string FormatDrivingMultiplier(double value)
        {
            return value.ToString("0.######", CultureInfo.InvariantCulture);
        }

