        private sealed class CarEditorRow
        {
            public readonly int CarId;
            public readonly string Year;
            public readonly string Make;
            public readonly string Model;
            public readonly string Copies;
            public readonly string PerformanceIndex;
            public readonly int ClassId;
            public readonly string TopSpeed;
            public readonly string BaseCost;
            public readonly Dictionary<string, string> Values;
            public readonly int EditorClassId;
            public readonly int DriveTypeId;
            public readonly int EngineConfigId;
            public readonly int AspirationTypeId;

            public CarEditorRow(int carId, string year, string make, string model, string copies, string performanceIndex, int classId, string topSpeed, string baseCost, Dictionary<string, string> values, int editorClassId, int driveTypeId, int engineConfigId, int aspirationTypeId)
            {
                CarId = carId;
                Year = year ?? string.Empty;
                Make = make ?? string.Empty;
                Model = model ?? string.Empty;
                Copies = copies ?? string.Empty;
                PerformanceIndex = performanceIndex ?? string.Empty;
                ClassId = classId;
                TopSpeed = topSpeed ?? string.Empty;
                BaseCost = baseCost ?? string.Empty;
                Values = values ?? new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                EditorClassId = editorClassId;
                DriveTypeId = driveTypeId;
                EngineConfigId = engineConfigId;
                AspirationTypeId = aspirationTypeId;
            }

            public bool Matches(string filter)
            {
                if (string.IsNullOrWhiteSpace(filter))
                    return true;

                return Contains(CarId.ToString(CultureInfo.InvariantCulture), filter) ||
                    Contains(Year, filter) ||
                    Contains(Make, filter) ||
                    Contains(Model, filter) ||
                    Contains(Copies, filter) ||
                    Contains(PerformanceIndex, filter) ||
                    Contains(FormatCarClassId(ClassId), filter) ||
                    Contains(TopSpeed, filter) ||
                    Contains(BaseCost, filter) ||
                    Values.Any(item => Contains(item.Value, filter));
            }

            private static bool Contains(string value, string filter)
            {
                return (value ?? string.Empty).IndexOf(filter, StringComparison.OrdinalIgnoreCase) >= 0;
            }
        }

