                BaseRarity = baseRarity;
                Rarity = rarity;
            }

            public bool Matches(string filter)
            {
                if (string.IsNullOrWhiteSpace(filter))
                    return true;

                return Contains(CarId.ToString(CultureInfo.InvariantCulture), filter) ||
                    Contains(Year, filter) ||
                    Contains(Make, filter) ||
                    Contains(Model, filter) ||
                    Contains(PerformanceIndex, filter) ||
                    Contains(ClassId, filter) ||
                    Contains(Copies, filter) ||
                    Contains(BaseRarity, filter) ||
                    Contains(Rarity, filter);
            }

            private static bool Contains(string value, string filter)
            {
                return (value ?? string.Empty).IndexOf(filter, StringComparison.OrdinalIgnoreCase) >= 0;
            }
        }

