        private static string EscapeIdentifierForSql(string name)
        {
            return "[" + name.Replace("]", "]]") + "]";
        }

        private static string ToSqlText(string value)
        {
            return "'" + (value ?? string.Empty).Replace("'", "''") + "'";
        }

        private static string BuildPerformanceClassExpression(RemoteDatabase db, string performanceIndexExpression, string fallbackExpression)
        {
            var fallback = string.IsNullOrWhiteSpace(fallbackExpression) ? "0" : fallbackExpression;
            if (db == null ||
                !db.TableExists("CarClasses") ||
                !db.ColumnExists("CarClasses", "Id") ||
                !db.ColumnExists("CarClasses", "MaxPerformanceIndex"))
            {
                return fallback;
            }

            var pi = string.IsNullOrWhiteSpace(performanceIndexExpression) ? "0" : performanceIndexExpression;
            var normalizedPi = "(CASE WHEN CAST((" + pi + ") AS REAL) > 10 THEN CAST((" + pi + ") AS REAL) / 1000.0 ELSE CAST((" + pi + ") AS REAL) END)";
            return "COALESCE(" +
                "(SELECT cc.[Id] FROM CarClasses cc WHERE " + normalizedPi + " <= CAST(cc.[MaxPerformanceIndex] AS REAL) ORDER BY CAST(cc.[MaxPerformanceIndex] AS REAL) ASC LIMIT 1), " +
                "(SELECT cc.[Id] FROM CarClasses cc ORDER BY CAST(cc.[MaxPerformanceIndex] AS REAL) DESC LIMIT 1), " +
                fallback +
                ", 0)";
        }

        private static string ResolveProfileTable(RemoteDatabase db, string primaryName, string fallbackName, params string[] requiredColumns)
        {
            if (HasRequiredColumns(db, primaryName, requiredColumns))
                return primaryName;
            if (HasRequiredColumns(db, fallbackName, requiredColumns))
                return fallbackName;
            throw new InvalidOperationException("Could not find " + primaryName + " or " + fallbackName + " with the expected columns.");
        }

        private static string ResolveActiveProfileTable(RemoteDatabase db, string primaryName, string fallbackName, params string[] requiredColumns)
        {
            var hasPrimary = HasRequiredColumns(db, primaryName, requiredColumns);
            var hasFallback = HasRequiredColumns(db, fallbackName, requiredColumns);
            if (hasPrimary && hasFallback)
            {
                var primaryRows = SafeTableRowCount(db, primaryName);
                var fallbackRows = SafeTableRowCount(db, fallbackName);
                if (primaryRows <= 0 && fallbackRows > 0)
                    return fallbackName;
                return primaryName;
            }
            if (hasPrimary)
                return primaryName;
            if (hasFallback)
                return fallbackName;
            throw new InvalidOperationException("Could not find " + primaryName + " or " + fallbackName + " with the expected columns.");
        }

        private static string ResolveOptionalProfileTable(RemoteDatabase db, string primaryName, string fallbackName, params string[] requiredColumns)
        {
            if (HasRequiredColumns(db, primaryName, requiredColumns))
                return primaryName;
            if (HasRequiredColumns(db, fallbackName, requiredColumns))
                return fallbackName;
            return string.Empty;
        }

        private static string ResolveProfileStatFieldTable(RemoteDatabase db, ProfileStatField field)
        {
            if (db == null || field == null || string.IsNullOrWhiteSpace(field.TableName))
                return string.Empty;

            var primaryName = field.TableName;
            var fallbackName = BuildProfileFallbackTableName(primaryName);
            if (string.Equals(primaryName, fallbackName, StringComparison.OrdinalIgnoreCase))
                return HasRequiredColumns(db, primaryName, field.ColumnName) ? primaryName : string.Empty;

            var hasPrimary = HasRequiredColumns(db, primaryName, field.ColumnName);
            var hasFallback = HasRequiredColumns(db, fallbackName, field.ColumnName);
            if (hasPrimary && hasFallback)
            {
                var primaryRows = SafeTableRowCount(db, primaryName);
                var fallbackRows = SafeTableRowCount(db, fallbackName);
                if (primaryRows <= 0 && fallbackRows > 0)
                    return fallbackName;
                return primaryName;
            }
            if (hasPrimary)
                return primaryName;
            return hasFallback ? fallbackName : string.Empty;
        }

        private static string BuildProfileFallbackTableName(string tableName)
        {
            return !string.IsNullOrWhiteSpace(tableName) && tableName.StartsWith("Profile0_", StringComparison.OrdinalIgnoreCase)
                ? "NewProfile_" + tableName.Substring("Profile0_".Length)
                : tableName;
        }

        private static long SafeTableRowCount(RemoteDatabase db, string tableName)
        {
            try
            {
                if (db == null || string.IsNullOrWhiteSpace(tableName) || !db.TableExists(tableName))
                    return 0;
                return db.QueryScalarLong("SELECT count(*) FROM " + EscapeIdentifierForSql(tableName)) ?? 0;
            }
            catch
            {
                return 0;
            }
        }

        private static string ResolveGarageTable(RemoteDatabase db)
        {
            return ResolveProfileTable(db, "Profile0_Career_Garage", "NewProfile_Career_Garage", "CarId");
        }

        private static string ResolveActiveGarageTable(RemoteDatabase db)
        {
            return ResolveActiveProfileTable(db, "Profile0_Career_Garage", "NewProfile_Career_Garage", "CarId");
        }

        private static string ResolveOptionalGarageTable(RemoteDatabase db)
        {
            return ResolveOptionalProfileTable(db, "Profile0_Career_Garage", "NewProfile_Career_Garage", "CarId");
        }

        private static string ResolveFreeCarsTable(RemoteDatabase db)
        {
            return ResolveProfileTable(db, "Profile0_FreeCars", "NewProfile_FreeCars", "CarId", "FreeCount");
        }

        private static string ResolveActiveFreeCarsTable(RemoteDatabase db)
        {
            return ResolveActiveProfileTable(db, "Profile0_FreeCars", "NewProfile_FreeCars", "CarId", "FreeCount");
        }

        private static string ResolveOptionalFreeCarsTable(RemoteDatabase db)
        {
            return ResolveOptionalProfileTable(db, "Profile0_FreeCars", "NewProfile_FreeCars", "CarId", "FreeCount");
        }

        private static string ResolveOptionalActiveFreeCarsTable(RemoteDatabase db)
        {
            if (HasRequiredColumns(db, "Profile0_FreeCars", "CarId", "FreeCount") &&
                HasRequiredColumns(db, "NewProfile_FreeCars", "CarId", "FreeCount"))
            {
                var primaryRows = SafeTableRowCount(db, "Profile0_FreeCars");
                var fallbackRows = SafeTableRowCount(db, "NewProfile_FreeCars");
                return primaryRows <= 0 && fallbackRows > 0 ? "NewProfile_FreeCars" : "Profile0_FreeCars";
            }
            return ResolveOptionalProfileTable(db, "Profile0_FreeCars", "NewProfile_FreeCars", "CarId", "FreeCount");
        }

        private static bool HasRequiredColumns(RemoteDatabase db, string tableName, params string[] requiredColumns)
        {
            if (db == null || string.IsNullOrWhiteSpace(tableName) || !db.TableExists(tableName))
                return false;

            foreach (var column in requiredColumns ?? new string[0])
            {
                if (!db.ColumnExists(tableName, column))
                    return false;
            }

            return true;
        }

        private static string BuildCarOfferIdExpression(RemoteDatabase db)
        {
            var visibilityFilter = db != null && db.ColumnExists("Data_Car", "NotAvailableInAutoshow")
                ? " AND COALESCE(DC.NotAvailableInAutoshow, 0)=0"
                : string.Empty;
            return "COALESCE((SELECT COM.OfferId FROM ContentOffersMapping COM JOIN Data_Car DC ON " + BuildContentMappingDataCarMatch(db, "COM", "DC") + " WHERE COM.ContentType=1" +
                visibilityFilter +
                " GROUP BY COM.OfferId ORDER BY COUNT(*) DESC LIMIT 1), (SELECT OfferId FROM ContentOffersMapping WHERE ContentType=1 GROUP BY OfferId ORDER BY COUNT(*) DESC LIMIT 1), 99)";
        }

        private static string BuildDataCarContentIdExpression(RemoteDatabase db, string alias)
        {
            var prefix = string.IsNullOrWhiteSpace(alias) ? string.Empty : alias + ".";
            var id = prefix + "[Id]";
            if (db != null && db.ColumnExists("Data_Car", "ContentId"))
            {
                var contentId = prefix + "[ContentId]";
                return "CASE WHEN " + contentId + " IS NOT NULL AND CAST(" + contentId + " AS INTEGER) > 0 THEN CAST(" + contentId + " AS INTEGER) ELSE " + id + " END";
            }
            return id;
        }

        private static string BuildContentMappingDataCarMatch(RemoteDatabase db, string mappingAlias, string carAlias)
        {
            var mappingPrefix = string.IsNullOrWhiteSpace(mappingAlias) ? string.Empty : mappingAlias + ".";
            return "CAST(" + mappingPrefix + "[ContentId] AS INTEGER) = " + BuildDataCarContentIdExpression(db, carAlias);
        }

        private static string BuildDataCarContentIdSubquery(RemoteDatabase db, string filterSql)
        {
            return "SELECT " + BuildDataCarContentIdExpression(db, "Data_Car") + " FROM Data_Car WHERE " + filterSql;
        }

        private static string BackupDataCarColumns(RemoteDatabase db, string backupName, params string[] columns)
        {
            if (db == null || !db.TableExists("Data_Car") || !db.ColumnExists("Data_Car", "Id"))
                return string.Empty;

            var supported = (columns ?? new string[0])
                .Where(column => db.ColumnExists("Data_Car", column))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
            if (supported.Count == 0)
                return string.Empty;

            return "CREATE TABLE IF NOT EXISTS " + EscapeIdentifierForSql(backupName) +
                " AS SELECT Id, " + string.Join(", ", supported.Select(EscapeIdentifierForSql).ToArray()) + " FROM Data_Car;";
        }

        private void ApplyAutoshowUnlock(RemoteDatabase db)
        {
            WriteSqlReference();

            var bucketTable = db.ResolveBucketTable();
            Log("Using FH6 bucket mapping table: " + bucketTable);

            Log("Stable mode: skipped runtime query text patching.");

            var stateBackupSql = BackupDataCarColumns(db, "_backup_AutoshowState", "NotAvailableInAutoshow", "BaseCost");
            if (stateBackupSql.Length > 0)
                ExecuteAutoshowSql(db, stateBackupSql);
            if (db.ColumnExists("Data_Car", "NotAvailableInAutoshow"))
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET NotAvailableInAutoshow = 0;");
            if (db.ColumnExists("Data_Car", "VisibleOnlyIfOwned"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_DataCarVisibleOnlyIfOwned AS SELECT Id, VisibleOnlyIfOwned FROM Data_Car;");
                ExecuteAutoshowSql(db, "UPDATE Data_Car SET VisibleOnlyIfOwned = 0;");
            }
            ApplyStableDataCarFlags(db);
            ApplyUnobtainableCarGate(db);
            ApplyCarDlcAndInstallSupport(db, false);
            ExecuteAutoshowSql(db, "DROP VIEW IF EXISTS Drivable_Data_Car;");
            ExecuteAutoshowSql(db, "CREATE VIEW Drivable_Data_Car AS SELECT * FROM Data_Car;");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_DataCarBuckets AS SELECT * FROM " + bucketTable + ";");
            ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO " + bucketTable + "(CarId) SELECT Id FROM Data_Car WHERE Id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM " + bucketTable + " buckets WHERE buckets.CarId = Data_Car.Id);");
            ExecuteAutoshowSql(db, "UPDATE " + bucketTable + " SET CarBucket=0, BucketHero=0 WHERE CarBucket IS NULL;");

            if (!string.Equals(bucketTable, "Data_Car_Buckets", StringComparison.OrdinalIgnoreCase) && !db.ObjectExists("Data_Car_Buckets"))
                ExecuteAutoshowSql(db, "CREATE VIEW IF NOT EXISTS Data_Car_Buckets AS SELECT * FROM " + bucketTable + ";");

            ApplyExpandedContentVisibility(db);
            LogAutoshowDiagnostics(db, bucketTable);
            Log("FH6 expanded Autoshow SQL applied: Data_Car visibility, Drivable_Data_Car view, " + bucketTable + " fill, offer visibility, and release gates.");
        }

        private void ApplyCarBucketSupport(RemoteDatabase db)
        {
            if (db == null || !db.TableExists("Data_Car"))
                return;

            string bucketTable;
            try
            {
                bucketTable = db.ResolveBucketTable();
            }
            catch (Exception ex)
            {
                Log("Car bucket support skipped: " + ex.Message);
                return;
            }

            var bucketSql = EscapeIdentifierForSql(bucketTable);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AddAllCars_CarBuckets AS SELECT * FROM " + bucketSql + ";");
            ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO " + bucketSql + "(CarId) SELECT Id FROM Data_Car WHERE Id IS NOT NULL AND Id > 0 AND Id <> 3300 AND NOT EXISTS (SELECT 1 FROM " + bucketSql + " buckets WHERE buckets.CarId = Data_Car.Id);");
            if (db.ColumnExists(bucketTable, "CarBucket") && db.ColumnExists(bucketTable, "BucketHero"))
                ExecuteAutoshowSql(db, "UPDATE " + bucketSql + " SET CarBucket=0, BucketHero=0 WHERE CarBucket IS NULL;");

            if (!string.Equals(bucketTable, "Data_Car_Buckets", StringComparison.OrdinalIgnoreCase) && !db.ObjectExists("Data_Car_Buckets"))
                ExecuteAutoshowSql(db, "CREATE VIEW IF NOT EXISTS Data_Car_Buckets AS SELECT * FROM " + bucketSql + ";");
        }

        private void ApplyAddAllCarsGrant(RemoteDatabase db)
        {
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("ContentOffersMapping"))
                throw new InvalidOperationException("ContentOffersMapping table was not found.");
            if (!db.TableExists("Profile0_FreeCars"))
                throw new InvalidOperationException("Profile0_FreeCars table was not found.");
            if (!db.ColumnExists("Profile0_FreeCars", "CarId") || !db.ColumnExists("Profile0_FreeCars", "FreeCount"))
                throw new InvalidOperationException("Profile0_FreeCars does not have the expected CarId/FreeCount columns.");
            if (!db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType"))
                throw new InvalidOperationException("ContentOffersMapping does not have the expected OfferId/ContentId/ContentType columns.");

            var hasGarage = db.TableExists("Profile0_Career_Garage") && db.ColumnExists("Profile0_Career_Garage", "CarId");
            var notOwnedFilter = hasGarage
                ? " AND Data_Car.Id NOT IN (SELECT CarId FROM Profile0_Career_Garage WHERE CarId IS NOT NULL)"
                : string.Empty;
            var targetFilter = "Data_Car.Id <> 3300" + notOwnedFilter;
            var targetSubquery = "SELECT Id FROM Data_Car WHERE " + targetFilter;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AddAllCars_FreeCars AS SELECT * FROM Profile0_FreeCars;");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AddAllCars_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");

            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "OfferId", "COALESCE((SELECT COM.OfferId FROM ContentOffersMapping COM JOIN Data_Car DC ON CAST(COM.ContentId AS INTEGER)=DC.Id WHERE COM.ContentType=1 AND DC.NotAvailableInAutoshow=0 GROUP BY COM.OfferId ORDER BY COUNT(*) DESC LIMIT 1), (SELECT OfferId FROM ContentOffersMapping WHERE ContentType=1 GROUP BY OfferId ORDER BY COUNT(*) DESC LIMIT 1), 99)");
            AddInsertColumn(columns, values, "ContentId", "CAST(Data_Car.Id AS TEXT)");
            AddInsertColumn(columns, values, "ContentType", "1");

            if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                AddInsertColumn(columns, values, "IsPromo", "0");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                AddInsertColumn(columns, values, "IsAutoRedeem", "1");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                AddInsertColumn(columns, values, "ReleaseDateUTC", "'1969-04-20 00:00'");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                AddInsertColumn(columns, values, "Quantity", "1");

            var insertMappings = "INSERT OR IGNORE INTO ContentOffersMapping (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE " + targetFilter + " AND NOT EXISTS (SELECT 1 FROM ContentOffersMapping WHERE CAST(ContentOffersMapping.ContentId AS INTEGER) = Data_Car.Id AND ContentOffersMapping.ContentType = 1);";
            ExecuteAutoshowSql(db, insertMappings);

            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 1 WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ");");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ") AND (Quantity IS NULL OR Quantity < 1);");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ") AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");

            ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO Profile0_FreeCars (CarId, FreeCount) SELECT Id, 1 FROM Data_Car WHERE " + targetFilter + " AND Id NOT IN (SELECT CarId FROM Profile0_FreeCars WHERE CarId IS NOT NULL);");
            ExecuteAutoshowSql(db, "UPDATE Profile0_FreeCars SET FreeCount = 1 WHERE CarId IN (" + targetSubquery + ") AND (FreeCount IS NULL OR FreeCount < 1);");

            if (hasGarage)
                LogCount(db, "Garage distinct cars currently owned", "SELECT count(DISTINCT CarId) FROM Profile0_Career_Garage WHERE CarId IS NOT NULL");
            LogCount(db, "Add All free-car grant rows", "SELECT count(*) FROM Profile0_FreeCars");
            LogCount(db, "Add All target cars still missing free grant", "SELECT count(*) FROM Data_Car WHERE " + targetFilter + " AND Id NOT IN (SELECT CarId FROM Profile0_FreeCars WHERE CarId IS NOT NULL)");
            LogCount(db, "Add All target cars still missing content mapping", "SELECT count(*) FROM Data_Car WHERE " + targetFilter + " AND Id NOT IN (SELECT CAST(ContentId AS INTEGER) FROM ContentOffersMapping WHERE ContentType = 1)");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                LogCount(db, "Add All auto-redeem car mappings", "SELECT count(DISTINCT ContentId) FROM ContentOffersMapping WHERE ContentType = 1 AND IsAutoRedeem = 1");
        }

        private int DirectInsertMissingGarageCars(RemoteDatabase db, string dataCarFilterSql)
        {
            if (db == null || !db.TableExists("Data_Car") || string.IsNullOrWhiteSpace(dataCarFilterSql))
                return 0;

            var added = 0;
            foreach (var row in db.Query("SELECT Id FROM Data_Car WHERE " + dataCarFilterSql + " ORDER BY Id;").Rows)
            {
                if (row.Count == 0)
                    continue;

                var carId = ToInt(row[0]);
                if (carId <= 0 || carId == 3300)
                    continue;

                if (TryInsertSingleGarageCar(db, carId))
                    added++;
            }

            return added;
        }

        private Dictionary<int, SelectedCarGrantResult> ApplyWheelspinCarsAddAllStyleGrant(RemoteDatabase db, List<CarTableGrantRequest> cars)
        {
            var selected = (cars ?? new List<CarTableGrantRequest>())
                .Where(car => car != null && car.CarId > 0)
                .GroupBy(car => car.CarId)
                .Select(group =>
                {
                    var first = group.First();
                    var quantity = group.Sum(item => Math.Max(1, item.Quantity));
                    return new CarTableGrantRequest(first.CarId, first.DisplayName, Math.Min(999, quantity));
                })
                .ToList();
            if (selected.Count == 0)
                throw new InvalidOperationException("No valid wheelspin cars were found.");

            foreach (var car in selected)
            {
                if (car.CarId == 3300)
                    throw new InvalidOperationException("That internal placeholder car cannot be granted.");
            }

            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("ContentOffersMapping"))
                throw new InvalidOperationException("ContentOffersMapping table was not found.");
            if (!db.TableExists("Profile0_FreeCars"))
                throw new InvalidOperationException("Profile0_FreeCars table was not found.");
            if (!db.ColumnExists("Profile0_FreeCars", "CarId") || !db.ColumnExists("Profile0_FreeCars", "FreeCount"))
                throw new InvalidOperationException("Profile0_FreeCars does not have the expected CarId/FreeCount columns.");
            if (!db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType"))
                throw new InvalidOperationException("ContentOffersMapping does not have the expected OfferId/ContentId/ContentType columns.");

