        private SelectedCarGrantResult ApplySelectedCarAddAllGrant(RemoteDatabase db, int carId, int quantity)
        {
            if (carId == 3300)
                throw new InvalidOperationException("That internal placeholder car cannot be granted.");
            if (!db.TableExists("Data_Car"))
                throw new InvalidOperationException("Data_Car table was not found.");
            if (!db.TableExists("ContentOffersMapping"))
                throw new InvalidOperationException("ContentOffersMapping table was not found.");
            if (!db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType"))
                throw new InvalidOperationException("ContentOffersMapping does not have the expected OfferId/ContentId/ContentType columns.");
            if (!db.TableExists("Profile0_FreeCars"))
                throw new InvalidOperationException("Profile0_FreeCars table was not found.");
            if (!db.ColumnExists("Profile0_FreeCars", "CarId") || !db.ColumnExists("Profile0_FreeCars", "FreeCount"))
                throw new InvalidOperationException("Profile0_FreeCars does not have the expected CarId/FreeCount columns.");

            var carIdSql = carId.ToString(CultureInfo.InvariantCulture);
            const string freeCarsSql = "Profile0_FreeCars";
            const string garageSql = "Profile0_Career_Garage";
            var hasGarage = db.TableExists(garageSql) && db.ColumnExists(garageSql, "CarId");
            var ownedBefore = hasGarage
                ? (db.QueryScalarLong("SELECT count(*) FROM " + garageSql + " WHERE CarId = " + carIdSql) ?? 0)
                : 0;
            var freeCountBefore = db.QueryScalarLong("SELECT COALESCE(MAX(FreeCount), 0) FROM " + freeCarsSql + " WHERE CarId = " + carIdSql) ?? 0;
            var requestedQuantity = Math.Max(1, Math.Min(999, quantity));
            var targetFreeCount = Math.Max(requestedQuantity, freeCountBefore + requestedQuantity);
            var targetFreeSql = targetFreeCount.ToString(CultureInfo.InvariantCulture);
            var requestedQuantitySql = requestedQuantity.ToString(CultureInfo.InvariantCulture);
            var targetFilter = "Data_Car.Id = " + carIdSql + " AND Data_Car.Id <> 3300";
            var targetSubquery = "SELECT Id FROM Data_Car WHERE " + targetFilter;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_Selected_FreeCars AS SELECT * FROM " + freeCarsSql + ";");
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_CarTable_Selected_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");

            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "OfferId", "COALESCE((SELECT COM.OfferId FROM ContentOffersMapping COM JOIN Data_Car DC ON CAST(COM.ContentId AS INTEGER)=DC.Id WHERE COM.ContentType=1 AND DC.NotAvailableInAutoshow=0 GROUP BY COM.OfferId ORDER BY COUNT(*) DESC LIMIT 1), (SELECT OfferId FROM ContentOffersMapping WHERE ContentType=1 GROUP BY OfferId ORDER BY COUNT(*) DESC LIMIT 1), 99)");
            AddInsertColumn(columns, values, "ContentId", "CAST(Data_Car.Id AS TEXT)");
            AddInsertColumn(columns, values, "ContentType", "1");

            if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                AddInsertColumn(columns, values, "IsPromo", "0");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                AddInsertColumn(columns, values, "IsAutoRedeem", "1");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                AddInsertColumn(columns, values, "ReleaseDateUTC", "'1969-04-20 00:00'");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                AddInsertColumn(columns, values, "Quantity", requestedQuantitySql);

            ExecuteAutoshowSql(db,
                "INSERT OR IGNORE INTO ContentOffersMapping (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE " + targetFilter + " AND NOT EXISTS (SELECT 1 FROM ContentOffersMapping WHERE CAST(ContentOffersMapping.ContentId AS INTEGER) = Data_Car.Id AND ContentOffersMapping.ContentType = 1);");

            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 1 WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ");");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = " + requestedQuantitySql + " WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ") AND (Quantity IS NULL OR Quantity < " + requestedQuantitySql + ");");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) IN (" + targetSubquery + ") AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");

            ExecuteAutoshowSql(db, "INSERT OR IGNORE INTO " + freeCarsSql + " (CarId, FreeCount) SELECT Id, " + targetFreeSql + " FROM Data_Car WHERE " + targetFilter + " AND NOT EXISTS (SELECT 1 FROM " + freeCarsSql + " free WHERE free.CarId = Data_Car.Id);");
            ExecuteAutoshowSql(db, "UPDATE " + freeCarsSql + " SET FreeCount = CASE WHEN FreeCount IS NULL OR FreeCount < " + targetFreeSql + " THEN " + targetFreeSql + " ELSE FreeCount END WHERE CarId = " + carIdSql + ";");

            var mappingsAfter = db.QueryScalarLong("SELECT count(*) FROM ContentOffersMapping WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) = " + carIdSql) ?? 0;
            var freeCountAfter = db.QueryScalarLong("SELECT COALESCE(MAX(FreeCount), 0) FROM " + freeCarsSql + " WHERE CarId = " + carIdSql) ?? 0;
            var autoRedeemMappings = db.ColumnExists("ContentOffersMapping", "IsAutoRedeem")
                ? (db.QueryScalarLong("SELECT count(*) FROM ContentOffersMapping WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) = " + carIdSql + " AND IsAutoRedeem = 1") ?? 0)
                : mappingsAfter;
            var offerQuantityAfter = db.ColumnExists("ContentOffersMapping", "Quantity")
                ? (db.QueryScalarLong("SELECT COALESCE(MAX(Quantity), 0) FROM ContentOffersMapping WHERE ContentType = 1 AND CAST(ContentId AS INTEGER) = " + carIdSql) ?? 0)
                : requestedQuantity;

            if (mappingsAfter <= 0)
                throw new InvalidOperationException("Selected car grant failed verification: no car content offer mapping was present after apply.");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem") && autoRedeemMappings <= 0)
                throw new InvalidOperationException("Selected car grant failed verification: the car offer was not marked auto-redeem.");
            if (freeCountAfter < targetFreeCount && offerQuantityAfter < requestedQuantity)
                Log("Selected car grant warning: FreeCount stayed at " + freeCountAfter.ToString(CultureInfo.InvariantCulture) +
                    " and offer quantity stayed at " + offerQuantityAfter.ToString(CultureInfo.InvariantCulture) +
                    ", but the car offer mapping is present and auto-redeem is armed.");
            if (freeCountAfter < targetFreeCount)
                Log("Selected car grant note: FreeCount stayed at " + freeCountAfter.ToString(CultureInfo.InvariantCulture) + ", but the auto-redeem offer quantity verified at " + offerQuantityAfter.ToString(CultureInfo.InvariantCulture) + ".");

            return new SelectedCarGrantResult(ownedBefore, freeCountBefore, freeCountAfter, autoRedeemMappings, offerQuantityAfter);
        }

        private void ApplyStableDataCarFlags(RemoteDatabase db)
        {
            BackupAndSetDataCarFlag(db, "IsInstalled", "_backup_DataCarIsInstalled", 1);
            BackupAndSetDataCarFlag(db, "IsPurchased", "_backup_DataCarIsPurchased", 1);
            BackupAndSetDataCarFlag(db, "IsDrivable", "_backup_DataCarIsDrivable", 1);
        }

        private void ApplyCarDlcAndInstallSupport(RemoteDatabase db, bool autoRedeemCarOffers)
        {
            if (db == null)
                return;

            if (db.TableExists("Data_Car"))
            {
                ApplyStableDataCarFlags(db);
                if (db.ColumnExists("Data_Car", "VisibleOnlyIfOwned"))
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_DataCarVisibleOnlyIfOwned AS SELECT Id, VisibleOnlyIfOwned FROM Data_Car;");
                    ExecuteAutoshowSql(db, "UPDATE Data_Car SET VisibleOnlyIfOwned = 0 WHERE VisibleOnlyIfOwned IS NULL OR VisibleOnlyIfOwned <> 0;");
                }
                if (db.ColumnExists("Data_Car", "NotAvailableInAutoshow"))
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_DataCarNotAvailableInAutoshow AS SELECT Id, NotAvailableInAutoshow FROM Data_Car;");
                    ExecuteAutoshowSql(db, "UPDATE Data_Car SET NotAvailableInAutoshow = 0 WHERE NotAvailableInAutoshow IS NULL OR NotAvailableInAutoshow <> 0;");
                }
            }

            if (db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentId") &&
                db.ColumnExists("ContentOffersMapping", "ContentType") &&
                db.TableExists("Data_Car"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AutoshowDlcInstall_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                InsertMissingContentOfferMappings(db);
            }

            var carOfferWhere = db.TableExists("ContentOffersMapping") &&
                db.ColumnExists("ContentOffersMapping", "OfferId") &&
                db.ColumnExists("ContentOffersMapping", "ContentType") &&
                db.TableExists("ContentOffers") &&
                db.ColumnExists("ContentOffers", "Id")
                ? " WHERE Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE ContentType = 1)"
                : string.Empty;

            if (db.TableExists("ContentOffers"))
            {
                var sets = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
                AddColumnSetIfExists(db, "ContentOffers", sets, "Visible", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsPurchased", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsFree", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "IsNew", "1");
                AddColumnSetIfExists(db, "ContentOffers", sets, "ShouldUpsell", "0");
                if (sets.Count > 0)
                {
                    ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AutoshowDlcInstall_ContentOffers AS SELECT * FROM ContentOffers;");
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET " + string.Join(", ", sets.Values.ToArray()) + carOfferWhere + ";");
                }
            }

            if (db.TableExists("ContentOffersMapping"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_AutoshowDlcInstall_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                var carMappingWhere = db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType = 1" : "1 = 1";
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC = '1969-04-20 00:00' WHERE " + carMappingWhere + " AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC = '' OR ReleaseDateUTC > '1969-04-20 00:00');");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE " + carMappingWhere + " AND (Quantity IS NULL OR Quantity < 1);");
                if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsPromo = 0 WHERE " + carMappingWhere + " AND (IsPromo IS NULL OR IsPromo <> 0);");
                if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                {
                    var desired = autoRedeemCarOffers ? "1" : "0";
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = " + desired + " WHERE " + carMappingWhere + " AND (IsAutoRedeem IS NULL OR IsAutoRedeem <> " + desired + ");");
                }
            }

            ApplyAllIeCarInstallFlags(db);
            ApplyOnDiscContentBridge(db);

            if (db.TableExists("ContentOffers") && db.TableExists("ContentOffersMapping"))
            {
                var checks = new List<string>();
                if (db.ColumnExists("ContentOffers", "Visible"))
                    checks.Add("Visible IS NULL OR Visible <> 1");
                if (db.ColumnExists("ContentOffers", "IsPurchased"))
                    checks.Add("IsPurchased IS NULL OR IsPurchased <> 1");
                if (db.ColumnExists("ContentOffers", "IsFree"))
                    checks.Add("IsFree IS NULL OR IsFree <> 1");
                if (checks.Count > 0)
                    LogCount(db, "Autoshow car DLC offers still gated", "SELECT count(*) FROM ContentOffers" + carOfferWhere + (carOfferWhere.Length == 0 ? " WHERE " : " AND ") + "(" + string.Join(" OR ", checks.ToArray()) + ")");
            }
        }

        private void LogRoutesStillLocked(RemoteDatabase db)
        {
            var flagColumns = new[] { "Active", "Renderable", "IsInstalled", "IsPurchased" };
            var supportedFlags = flagColumns.Where(column => db.ColumnExists("Tracks", column)).ToList();
            if (supportedFlags.Count == 0)
                return;

            LogCount(db, "Routes/tracks still locked", "SELECT count(*) FROM " + EscapeIdentifierForSql("Tracks") + " WHERE " + BuildNotOneWhere(supportedFlags));
        }

        private void ApplyUnobtainableCarGate(RemoteDatabase db)
        {
            if (!db.TableExists("UnobtainableCars") || !db.ColumnExists("UnobtainableCars", "Ordinal"))
                return;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_UnobtainableCars AS SELECT * FROM UnobtainableCars;");
            ExecuteAutoshowSql(db, "UPDATE UnobtainableCars SET Ordinal = -1000000000 - Ordinal WHERE Ordinal >= 0;");
            LogCount(db, "Unobtainable positive gates", "SELECT count(*) FROM UnobtainableCars WHERE Ordinal >= 0");
        }

        private void ApplySelectedUnobtainableGateIds(RemoteDatabase db, List<int> carIds)
        {
            if (db == null || !db.TableExists("UnobtainableCars") || !db.ColumnExists("UnobtainableCars", "Ordinal"))
                throw new InvalidOperationException("UnobtainableCars.Ordinal was not found.");

            var idsSql = BuildIntegerInList(carIds);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_Database_UnobtainableCars AS SELECT * FROM UnobtainableCars;");
            ExecuteAutoshowSql(db, "UPDATE UnobtainableCars SET Ordinal = -1000000000 - Ordinal WHERE Ordinal IN (" + idsSql + ") AND Ordinal >= 0;");
            LogCount(db, "Selected unobtainable gates still blocked", "SELECT count(*) FROM UnobtainableCars WHERE Ordinal IN (" + idsSql + ") AND Ordinal >= 0");
        }

        private void BackupAndSetDataCarFlag(RemoteDatabase db, string columnName, string backupName, int value)
        {
            if (!db.ColumnExists("Data_Car", columnName))
                return;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backupName + " AS SELECT Id, " + columnName + " FROM Data_Car;");
