        private static string BuildNotOneWhere(IEnumerable<string> columns)
        {
            return string.Join(" OR ", columns.Select(column => EscapeIdentifierForSql(column) + " IS NULL OR " + EscapeIdentifierForSql(column) + " <> 1").ToArray());
        }

        private static string BuildSetOneList(IEnumerable<string> columns)
        {
            return string.Join(", ", columns.Select(column => EscapeIdentifierForSql(column) + " = 1").ToArray());
        }

        private int ApplyDrivingColumnSet(RemoteDatabase db, string tableName, string backupName, List<DrivingEditorSqlInput> inputs, int carId)
        {
            if (!db.TableExists(tableName))
            {
                Log(tableName + " not found; skipping.");
                return 0;
            }

            var supported = inputs.Where(input => db.ColumnExists(tableName, input.Field.ColumnName)).ToList();
            if (supported.Count == 0)
            {
                Log(tableName + " has none of the requested Driving Editor columns; skipping.");
                return 0;
            }

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS " + backupSql + " AS SELECT rowid AS _rowid_, * FROM " + tableSql + ";");
            var carFilter = BuildDrivingCarFilterForQuery(db, tableName, tableSql, carId);
            if (string.IsNullOrEmpty(carFilter) &&
                (string.Equals(tableName, "Data_Car", StringComparison.OrdinalIgnoreCase) ||
                 string.Equals(tableName, "Profile0_Career_Garage", StringComparison.OrdinalIgnoreCase)))
            {
                Log(tableName + " cannot be safely filtered to the selected car; skipping.");
                return 0;
            }

            var applied = 0;
            foreach (var input in supported)
            {
                var column = input.Field.ColumnName;
                var columnSql = EscapeIdentifierForSql(column);
                if (input.Field.UseBaselineMultiplier)
                {
                    if (!db.ColumnExists(backupName, column) || !db.ColumnExists(backupName, "_rowid_"))
                    {
                        Log("Backup for " + input.Field.Path + " is missing baseline rows; skipping to avoid unsafe overwrite.");
                        continue;
                    }

                    ExecuteAutoshowSql(
                        db,
                        "UPDATE " + tableSql + " SET " + columnSql + " = " +
                        "(SELECT CASE WHEN " + backupSql + "." + columnSql + " IS NULL THEN " + tableSql + "." + columnSql + " ELSE CAST(" + backupSql + "." + columnSql + " AS REAL) * (" + input.SqlValue + ") END FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) " +
                        "WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) AND " + columnSql + " IS NOT NULL" + carFilter + ";");
                }
                else
                {
                    ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + columnSql + " = " + input.SqlValue + " WHERE (" + columnSql + " IS NULL OR CAST(" + columnSql + " AS TEXT) <> CAST((" + input.SqlValue + ") AS TEXT))" + carFilter + ";");
                }
                applied++;
            }

            return applied;
        }

        private int RestoreNumericColumnSet(RemoteDatabase db, string tableName, string backupName, IEnumerable<string> columns)
        {
            if (!db.TableExists(tableName) || !db.TableExists(backupName) || !db.ColumnExists(backupName, "_rowid_"))
                return 0;

            var tableSql = EscapeIdentifierForSql(tableName);
            var backupSql = EscapeIdentifierForSql(backupName);
            var restored = 0;

            foreach (var column in columns)
            {
                if (!db.ColumnExists(tableName, column) || !db.ColumnExists(backupName, column))
                    continue;

                var columnSql = EscapeIdentifierForSql(column);
                ExecuteAutoshowSql(db, "UPDATE " + tableSql + " SET " + columnSql + " = (SELECT " + backupSql + "." + columnSql + " FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid) WHERE EXISTS (SELECT 1 FROM " + backupSql + " WHERE " + backupSql + ".[_rowid_] = " + tableSql + ".rowid);");
                restored++;
            }

            if (restored > 0)
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS " + backupSql + ";");

            return restored;
        }

        private void ApplyExpandedContentVisibility(RemoteDatabase db)
        {
            var carOfferWhere = db.TableExists("ContentOffersMapping") && db.ColumnExists("ContentOffersMapping", "OfferId") && db.ColumnExists("ContentOffersMapping", "ContentType")
                ? " WHERE Id IN (SELECT DISTINCT OfferId FROM ContentOffersMapping WHERE ContentType = 1)"
                : string.Empty;
            if (db.TableExists("ContentOffers"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_ContentOffers AS SELECT * FROM ContentOffers;");
                if (db.ColumnExists("ContentOffers", "Visible"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET Visible = 1" + carOfferWhere + (carOfferWhere.Length == 0 ? " WHERE Visible <> 1" : " AND Visible <> 1") + ";");
                if (db.ColumnExists("ContentOffers", "IsNew"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET IsNew = 1" + carOfferWhere + (carOfferWhere.Length == 0 ? " WHERE IsNew <> 1" : " AND IsNew <> 1") + ";");
                if (db.ColumnExists("ContentOffers", "ShouldUpsell"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffers SET ShouldUpsell = 0" + carOfferWhere + (carOfferWhere.Length == 0 ? " WHERE ShouldUpsell <> 0" : " AND ShouldUpsell <> 0") + ";");
            }

            if (db.TableExists("ContentOffersMapping"))
            {
                ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;");
                var carContentWhere = db.ColumnExists("ContentOffersMapping", "ContentType") ? "ContentType=1 AND " : string.Empty;
                if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET ReleaseDateUTC='1969-04-20 00:00' WHERE " + carContentWhere + "(ReleaseDateUTC IS NULL OR ReleaseDateUTC='' OR ReleaseDateUTC > '1969-04-20 00:00');");
                if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET Quantity = 1 WHERE " + carContentWhere + "(Quantity IS NULL OR Quantity <> 1);");
                if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                    ExecuteAutoshowSql(db, "UPDATE ContentOffersMapping SET IsAutoRedeem = 0 WHERE " + carContentWhere + "IsAutoRedeem <> 0;");

                InsertMissingContentOfferMappings(db);
            }

            ApplyOnDiscContentBridge(db);
        }

        private void ApplyOnDiscContentBridge(RemoteDatabase db)
        {
            if (!db.TableExists("OnDiscContent") ||
                !db.ColumnExists("OnDiscContent", "ContentId") ||
                !db.ColumnExists("OnDiscContent", "ContentType"))
                return;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_OnDiscContent AS SELECT * FROM OnDiscContent;");

            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "ContentId", BuildDataCarContentIdExpression(db, "Data_Car"));
            AddInsertColumn(columns, values, "ContentType", "1");
            if (db.ColumnExists("OnDiscContent", "ReleaseOrder"))
                AddInsertColumn(columns, values, "ReleaseOrder", "COALESCE((SELECT MAX(ReleaseOrder) FROM OnDiscContent WHERE ContentType=1), 0)");

            var sql = "INSERT OR IGNORE INTO OnDiscContent (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE NOT EXISTS (SELECT 1 FROM OnDiscContent WHERE CAST(OnDiscContent.ContentId AS INTEGER) = " + BuildDataCarContentIdExpression(db, "Data_Car") + " AND OnDiscContent.ContentType = 1);";
            ExecuteAutoshowSql(db, sql);
        }

        private void ApplyOnDiscContentBridgeForOffers(RemoteDatabase db, string offerIdsSql)
        {
            if (string.IsNullOrWhiteSpace(offerIdsSql) ||
                !db.TableExists("OnDiscContent") ||
                !db.ColumnExists("OnDiscContent", "ContentId") ||
                !db.ColumnExists("OnDiscContent", "ContentType") ||
                !db.TableExists("ContentOffersMapping") ||
                !db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType"))
                return;

            ExecuteAutoshowSql(db, "CREATE TABLE IF NOT EXISTS _backup_OnDiscContent AS SELECT * FROM OnDiscContent;");

            var columns = new List<string>();
            var values = new List<string>();
            AddInsertColumn(columns, values, "ContentId", "CAST(ContentOffersMapping.[ContentId] AS INTEGER)");
            AddInsertColumn(columns, values, "ContentType", "ContentOffersMapping.[ContentType]");
            if (db.ColumnExists("OnDiscContent", "ReleaseOrder"))
                AddInsertColumn(columns, values, "ReleaseOrder", "COALESCE((SELECT MAX(ReleaseOrder) FROM OnDiscContent WHERE ContentType=ContentOffersMapping.[ContentType]), 0)");

            var sql = "INSERT OR IGNORE INTO OnDiscContent (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM ContentOffersMapping " +
                "WHERE ContentOffersMapping.OfferId IN (" + offerIdsSql + ") " +
                "AND CAST(ContentOffersMapping.[ContentId] AS INTEGER) > 0 " +
                "AND NOT EXISTS (SELECT 1 FROM OnDiscContent WHERE CAST(OnDiscContent.ContentId AS INTEGER) = CAST(ContentOffersMapping.[ContentId] AS INTEGER) AND OnDiscContent.ContentType = ContentOffersMapping.[ContentType]);";
            ExecuteAutoshowSql(db, sql);
        }

        private void InsertMissingContentOfferMappings(RemoteDatabase db)
        {
            if (!db.ColumnExists("ContentOffersMapping", "OfferId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentId") ||
                !db.ColumnExists("ContentOffersMapping", "ContentType"))
            {
                Log("ContentOffersMapping missing required OfferId/ContentId/ContentType columns; skipping missing offer bridge.");
                return;
            }

            var columns = new List<string>();
            var values = new List<string>();

            AddInsertColumn(columns, values, "OfferId", BuildCarOfferIdExpression(db));
            AddInsertColumn(columns, values, "ContentId", "CAST(" + BuildDataCarContentIdExpression(db, "Data_Car") + " AS TEXT)");
            AddInsertColumn(columns, values, "ContentType", "1");

            if (db.ColumnExists("ContentOffersMapping", "IsPromo"))
                AddInsertColumn(columns, values, "IsPromo", "0");
            if (db.ColumnExists("ContentOffersMapping", "IsAutoRedeem"))
                AddInsertColumn(columns, values, "IsAutoRedeem", "0");
            if (db.ColumnExists("ContentOffersMapping", "ReleaseDateUTC"))
                AddInsertColumn(columns, values, "ReleaseDateUTC", "'1969-04-20 00:00'");
            if (db.ColumnExists("ContentOffersMapping", "Quantity"))
                AddInsertColumn(columns, values, "Quantity", "1");

            var sql = "INSERT OR IGNORE INTO ContentOffersMapping (" + string.Join(", ", columns.ToArray()) + ") " +
                "SELECT " + string.Join(", ", values.ToArray()) + " FROM Data_Car " +
                "WHERE NOT EXISTS (SELECT 1 FROM ContentOffersMapping WHERE " + BuildContentMappingDataCarMatch(db, "ContentOffersMapping", "Data_Car") + " AND ContentOffersMapping.ContentType = 1);";
            ExecuteAutoshowSql(db, sql);
        }

        private static void AddInsertColumn(List<string> columns, List<string> values, string column, string value)
        {
            columns.Add(column);
            values.Add(value);
        }

        private void RestoreTableBackup(RemoteDatabase db, string tableName, string backupName)
        {
            if (!db.TableExists(backupName))
                return;

            ExecuteAutoshowSql(db, "DELETE FROM " + tableName + ";");
            ExecuteAutoshowSql(db, "INSERT INTO " + tableName + " SELECT * FROM " + backupName + ";");
            ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS " + backupName + ";");
        }

        private void RestoreBucketBackup(RemoteDatabase db, string bucketTable)
        {
            if (db.TableExists("_backup_DataCarBuckets"))
            {
                ExecuteAutoshowSql(db, "DELETE FROM " + bucketTable + ";");
                ExecuteAutoshowSql(db, "INSERT INTO " + bucketTable + " SELECT * FROM _backup_DataCarBuckets;");
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_DataCarBuckets;");
                return;
            }

            if (db.TableExists("_backup_CarBuckets") &&
                db.ColumnExists("_backup_CarBuckets", "CarId") &&
                db.ColumnExists("_backup_CarBuckets", "CarBucket") &&
                db.ColumnExists("_backup_CarBuckets", "BucketHero"))
            {
                ExecuteAutoshowSql(db, "DELETE FROM " + bucketTable + ";");
                ExecuteAutoshowSql(db, "INSERT INTO " + bucketTable + " SELECT * FROM _backup_CarBuckets;");
                ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS _backup_CarBuckets;");
                return;
            }

            if (db.TableExists("_backup_CarBuckets"))
                Log("Old _backup_CarBuckets does not match the car-bucket mapping schema; leaving " + bucketTable + " untouched.");
            else
                Log("No car-bucket mapping backup found; skipping " + bucketTable + " restore.");
        }

        private void RestoreDataCarColumnBackup(RemoteDatabase db, string columnName, string backupName)
        {
            if (!db.TableExists(backupName) || !db.ColumnExists("Data_Car", columnName))
                return;

            ExecuteAutoshowSql(db, "UPDATE Data_Car SET " + columnName + " = (SELECT " + columnName + " FROM " + backupName + " WHERE Data_Car.Id = " + backupName + ".Id) WHERE EXISTS (SELECT 1 FROM " + backupName + " WHERE Data_Car.Id = " + backupName + ".Id);");
            ExecuteAutoshowSql(db, "DROP TABLE IF EXISTS " + backupName + ";");
        }

        private void LogAutoshowDiagnostics(RemoteDatabase db, string bucketTable)
        {
            LogCount(db, "Coverage Data_Car rows", "SELECT count(*) FROM Data_Car");
            LogCount(db, "Coverage Drivable_Data_Car rows", "SELECT count(*) FROM Drivable_Data_Car");
            LogCount(db, "Coverage bucket mapping distinct CarId rows", "SELECT count(DISTINCT CarId) FROM " + bucketTable);
            LogCount(db, "Coverage cars still missing bucket rows", "SELECT count(*) FROM Data_Car WHERE Id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM " + bucketTable + " buckets WHERE buckets.CarId = Data_Car.Id)");
            if (db.ColumnExists("Data_Car", "NotAvailableInAutoshow"))
                LogCount(db, "Coverage cars still NotAvailableInAutoshow", "SELECT count(*) FROM Data_Car WHERE NotAvailableInAutoshow <> 0");

            if (db.ColumnExists("Data_Car", "VisibleOnlyIfOwned"))
                LogCount(db, "Coverage cars still VisibleOnlyIfOwned", "SELECT count(*) FROM Data_Car WHERE VisibleOnlyIfOwned <> 0");
            if (db.TableExists("ContentOffersMapping"))
            {
                LogCount(db, "Coverage mapped car content rows", "SELECT count(DISTINCT ContentId) FROM ContentOffersMapping WHERE ContentType=1");
                LogCount(db, "Coverage cars still missing content mapping", "SELECT count(*) FROM Data_Car WHERE NOT EXISTS (SELECT 1 FROM ContentOffersMapping map WHERE map.ContentType=1 AND CAST(map.ContentId AS INTEGER) = " + BuildDataCarContentIdExpression(db, "Data_Car") + ")");
            }
            if (db.TableExists("OnDiscContent"))
                LogCount(db, "Coverage cars still missing OnDiscContent rows", "SELECT count(*) FROM Data_Car WHERE NOT EXISTS (SELECT 1 FROM OnDiscContent disc WHERE disc.ContentType=1 AND CAST(disc.ContentId AS INTEGER) = " + BuildDataCarContentIdExpression(db, "Data_Car") + ")");
            if (db.TableExists("UnobtainableCars"))
                LogCount(db, "Coverage remaining unobtainable positive rows", "SELECT count(*) FROM UnobtainableCars WHERE Ordinal >= 0");
        }

        private void LogCount(RemoteDatabase db, string label, string sql)
        {
            try
            {
                var value = db.QueryScalarLong(sql);
                Log(label + ": " + (value.HasValue ? value.Value.ToString() : "?"));
            }
            catch (Exception ex)
            {
                Log(label + ": ? (" + ex.Message + ")");
            }
        }

        private static string GarageDuplicateExtraRowsSql()
        {
            return GarageDuplicateExtraRowsSql("Profile0_Career_Garage");
        }

        private static string GarageDuplicateExtraRowsSql(string tableName)
        {
            return "SELECT COALESCE(SUM(cnt - 1), 0) FROM (SELECT CarId, COUNT(*) AS cnt FROM " + EscapeIdentifierForSql(tableName) + " WHERE CarId IS NOT NULL GROUP BY CarId HAVING COUNT(*) > 1)";
        }

        private void ExecuteAutoshowSql(RemoteDatabase db, string sql)
        {
            try
            {
                db.Execute(sql);
            }
            catch (Exception ex)
            {
                Log("SQL step failed or was rejected: " + ex.Message);
                Log("SQL was: " + sql);
            }
        }

        private void UpdateAllCarsButton()
        {
            if (_allCars == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateAllCarsButton);
                return;
            }
            _allCars.Text = _allCarsOn ? "Show All Cars: ON" : "Show All Cars: OFF";
            MakeAccentButton(_allCars, _allCarsOn ? AccentGreen : AccentRed);
        }

        private void UpdateAddAllCarsButton()
        {
            if (_addAllCars == null)
                return;
            if (InvokeRequired)
            {
                BeginInvoke((Action)UpdateAddAllCarsButton);
                return;
            }
            switch (_addAllCarsState)
            {
                case 1:
                    _addAllCars.Text = "Add All Cars: RUNNING";
                    MakeAccentButton(_addAllCars, AccentOrange);
                    break;
                case 2:
                    _addAllCars.Text = "Add All Cars: COMPLETED";
                    MakeAccentButton(_addAllCars, AccentGreen);
                    break;
                default:
                    _addAllCars.Text = "Add All Cars: OFF";
                    MakeAccentButton(_addAllCars, AccentRed);
                    break;
            }
        }

        private void SetAddAllCarsState(int state)
        {
            _addAllCarsState = Math.Max(0, Math.Min(2, state));
            UpdateAddAllCarsButton();
        }

        private void CopyStaticDatabaseCandidate()
        {
            var candidate = Path.Combine(_gamePath.Text.Trim(), "media", "Stripped", "gamedbRC.slt");
            if (!File.Exists(candidate))
            {
                Log("Static DB candidate not found under the selected game folder.");
                return;
            }

            var stamp = DateTime.Now.ToString("yyyyMMdd_HHmmss");
            var outFile = Path.Combine(_dumpDir, "gamedbRC_static_" + stamp + ".slt");
            File.Copy(candidate, outFile, false);
            Log("Copied static gamedbRC.slt candidate to dumps: " + Path.GetFileName(outFile));
            Log("Note: gamedbRC.slt is packed/encrypted on disk, so the live dump is the useful database view.");
        }

        private void WriteSqlReference()
        {
            Directory.CreateDirectory(_reportDir);
            var path = Path.Combine(_reportDir, "sql_reference.sql");
            var text =
                "-- Forza Horizon 6 Luna SQL reference" + Environment.NewLine +
                "-- Stable All Cars Autoshow path" + Environment.NewLine +
                "-- Live FH6 schema correction: Data_Car_Buckets is the car-to-bucket mapping table." + Environment.NewLine +
                "-- Autoshow runtime query text patching is intentionally disabled; Features runtime hooks install only when Apply is pressed." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_AutoshowState AS SELECT Id, NotAvailableInAutoshow, BaseCost FROM Data_Car;" + Environment.NewLine +
                "UPDATE Data_Car SET NotAvailableInAutoshow = 0;" + Environment.NewLine +
                "DROP VIEW IF EXISTS Drivable_Data_Car;" + Environment.NewLine +
                "CREATE VIEW Drivable_Data_Car AS SELECT * FROM Data_Car;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_DataCarBuckets AS SELECT * FROM Data_Car_Buckets;" + Environment.NewLine +
                "INSERT OR IGNORE INTO Data_Car_Buckets(CarId) SELECT Id FROM Data_Car WHERE Id NOT IN (SELECT CarId FROM Data_Car_Buckets);" + Environment.NewLine +
                "UPDATE Data_Car_Buckets SET CarBucket=0, BucketHero=0 WHERE CarBucket IS NULL;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_DataCarVisibleOnlyIfOwned AS SELECT Id, VisibleOnlyIfOwned FROM Data_Car;" + Environment.NewLine +
                "UPDATE Data_Car SET VisibleOnlyIfOwned = 0;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_DataCarIsInstalled AS SELECT Id, IsInstalled FROM Data_Car;" + Environment.NewLine +
                "UPDATE Data_Car SET IsInstalled = 1 WHERE IsInstalled IS NULL OR IsInstalled <> 1;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_DataCarIsPurchased AS SELECT Id, IsPurchased FROM Data_Car;" + Environment.NewLine +
                "UPDATE Data_Car SET IsPurchased = 1 WHERE IsPurchased IS NULL OR IsPurchased <> 1;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_DataCarIsDrivable AS SELECT Id, IsDrivable FROM Data_Car;" + Environment.NewLine +
                "UPDATE Data_Car SET IsDrivable = 1 WHERE IsDrivable IS NULL OR IsDrivable <> 1;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_UnobtainableCars AS SELECT * FROM UnobtainableCars;" + Environment.NewLine +
                "UPDATE UnobtainableCars SET Ordinal = -1000000000 - Ordinal WHERE Ordinal >= 0;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_ContentOffers AS SELECT * FROM ContentOffers;" + Environment.NewLine +
                "UPDATE ContentOffers SET Visible = 1 WHERE Visible <> 1;" + Environment.NewLine +
                "UPDATE ContentOffers SET IsNew = 1 WHERE IsNew <> 1;" + Environment.NewLine +
                "UPDATE ContentOffers SET ShouldUpsell = 0 WHERE ShouldUpsell <> 0;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;" + Environment.NewLine +
                "UPDATE ContentOffersMapping SET ReleaseDateUTC='1969-04-20 00:00' WHERE ContentType=1 AND (ReleaseDateUTC IS NULL OR ReleaseDateUTC='' OR ReleaseDateUTC > '1969-04-20 00:00');" + Environment.NewLine +
                "UPDATE ContentOffersMapping SET Quantity = 1 WHERE ContentType=1 AND (Quantity IS NULL OR Quantity <> 1);" + Environment.NewLine +
                "UPDATE ContentOffersMapping SET IsAutoRedeem = 0 WHERE ContentType=1 AND IsAutoRedeem <> 0;" + Environment.NewLine +
                "-- The tool also inserts missing ContentOffersMapping rows for every Data_Car.Id using the best existing car OfferId." + Environment.NewLine +
                "-- The tool also inserts missing OnDiscContent rows for every Data_Car.Id with ContentType=1." + Environment.NewLine +
                Environment.NewLine +
                "-- Add All Cars grant path" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_AddAllCars_FreeCars AS SELECT * FROM Profile0_FreeCars;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_AddAllCars_ContentOffersMapping AS SELECT * FROM ContentOffersMapping;" + Environment.NewLine +
                "INSERT OR IGNORE INTO ContentOffersMapping (OfferId, ContentId, ContentType, IsPromo, IsAutoRedeem, ReleaseDateUTC, Quantity) SELECT 99, CAST(Id AS TEXT), 1, 0, 1, '1969-04-20 00:00', 1 FROM Data_Car WHERE Id <> 3300 AND Id NOT IN (SELECT CarId FROM Profile0_Career_Garage WHERE CarId IS NOT NULL);" + Environment.NewLine +
                "INSERT OR IGNORE INTO Profile0_FreeCars (CarId, FreeCount) SELECT Id, 1 FROM Data_Car WHERE Id <> 3300 AND Id NOT IN (SELECT CarId FROM Profile0_FreeCars WHERE CarId IS NOT NULL);" + Environment.NewLine +
                "UPDATE Profile0_FreeCars SET FreeCount = 1 WHERE FreeCount IS NULL OR FreeCount < 1;" + Environment.NewLine +
                "-- Autoshow car browser Add Selected asks for per-car quantities, then increases each selected car's queued FreeCount through this same grant path." + Environment.NewLine +
                Environment.NewLine +
                "-- Database tools" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_ProfileEditor_NewTags AS SELECT CarId, HasCurrentOwnerViewedCar FROM Profile0_Career_Garage;" + Environment.NewLine +
                "UPDATE Profile0_Career_Garage SET HasCurrentOwnerViewedCar = 1 WHERE HasCurrentOwnerViewedCar IS NULL OR HasCurrentOwnerViewedCar <> 1;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_ProfileEditor_Thumbnails AS SELECT CarId, Thumbnail FROM Profile0_Career_Garage;" + Environment.NewLine +
                "UPDATE Profile0_Career_Garage SET Thumbnail = (SELECT Data_Car.Thumbnail FROM Data_Car WHERE Data_Car.Id = Profile0_Career_Garage.CarId) WHERE EXISTS (SELECT 1 FROM Data_Car WHERE Data_Car.Id = Profile0_Career_Garage.CarId AND Data_Car.Thumbnail IS NOT NULL);" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_BarnFindUnlock_Profile0 AS SELECT * FROM Profile0_BarnFinds;" + Environment.NewLine +
                "INSERT OR IGNORE INTO Profile0_BarnFinds (CarOrdinal, State, VIN) SELECT CarId, 5, lower(printf('%08X-0000-4000-8000-%012X', CarId, CarId)) FROM BarnfindCars WHERE CarId IS NOT NULL;" + Environment.NewLine +
                "UPDATE Profile0_BarnFinds SET State = 5 WHERE State IS NULL OR State < 5;" + Environment.NewLine +
                "UPDATE Profile0_BarnFinds SET VIN = lower(printf('%08X-0000-4000-8000-%012X', CarOrdinal, CarOrdinal)) WHERE VIN IS NULL OR VIN = '' OR VIN = '00000000-0000-0000-0000-000000000000';" + Environment.NewLine +
                "-- Barn Finds also queues BarnfindCars through the stable selected-car grant path." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_StatsEditor_Garage AS SELECT rowid AS _rowid_, * FROM Profile0_Career_Garage;" + Environment.NewLine +
                "-- Stats Editor updates one selected garage row's OriginalOwner and supported owner/stat metadata at a time; Profile Editable Stats applies supported profile-wide table columns in bulk and mirrors NumRaces into CurOwnerNumRaces unless that row is edited separately." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_CarEditor_DataCar AS SELECT rowid AS _rowid_, * FROM Data_Car;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_CarEditor_Garage AS SELECT rowid AS _rowid_, * FROM Profile0_Career_Garage;" + Environment.NewLine +
                "-- Car Class Panel loads owned garage cars and edits only selected-car ClassID mirrors in Data_Car/Profile0_Career_Garage." + Environment.NewLine +
                "-- Driving Editor custom-value path" + Environment.NewLine +
                "-- The GUI creates these backups before applying user-entered values." + Environment.NewLine +
                "-- Risky physics fields are applied as multipliers against backup baselines so each car keeps its own handling balance." + Environment.NewLine +
                "-- After applying Driving Editor values, switch to another car and back so FH6 reloads active vehicle data; fast travel or entering a house is not enough." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_DataCarDrivingPack AS SELECT rowid AS _rowid_, * FROM Data_Car;" + Environment.NewLine +
                "-- Editable Data_Car multiplier columns: GameTorqueScale, GameDragScale, PuddleScale, TopSpeed-mph, SimTopSpeed, BodyAeroLongitudinalDrag." + Environment.NewLine +
                "-- Top Speed multiplier also backs up and scales Profile0_Career_Garage.TopSpeed plus List_DragWallSettingsOverride Min/Med/MaxSpeedForDragWall." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_DataCarSpeedPack AS SELECT rowid AS _rowid_, * FROM Data_Car;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_ProfileGarageSpeedPack AS SELECT rowid AS _rowid_, * FROM Profile0_Career_Garage;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_DragWallSpeedPack AS SELECT rowid AS _rowid_, * FROM List_DragWallSettingsOverride;" + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_ProfileEditor_UpgradePresetPackages AS SELECT * FROM UpgradePresetPackages;" + Environment.NewLine +
                "UPDATE UpgradePresetPackages SET Purchasable = 1 WHERE Purchasable IS NULL OR Purchasable <> 1;" + Environment.NewLine +
                "-- Remove Dupe Cars keeps the favorite/highest-distance/lowest-Id garage row for each CarId after creating this backup." + Environment.NewLine +
                "CREATE TABLE IF NOT EXISTS _backup_Database_RemoveDupeCars AS SELECT rowid AS _rowid_, * FROM Profile0_Career_Garage;" + Environment.NewLine +
            "-- Features Load Current captures Credits/Both Wheelspins/Skill Points through disabled runtime detours; Drift Score Multiplier uses Luna's live detour when applied." + Environment.NewLine +
                Environment.NewLine +
                "-- Restore button note" + Environment.NewLine +
                "-- Restore Autoshow intentionally shows restart instructions instead of running live restore SQL." + Environment.NewLine +
                Environment.NewLine +
                "-- Executor note" + Environment.NewLine +
                "-- Executor note: stable build resolves CDatabase with the FH6 AOB and calls ExecuteQuery vtable index 9." + Environment.NewLine;
            File.WriteAllText(path, text, Encoding.ASCII);
        }
    }

    internal sealed class LiveTuningReadback
    {
        public readonly string Key;
        public readonly ulong Address;
        public readonly float Value;
        public readonly string Status;

        public LiveTuningReadback(string key, ulong address, float value, string status)
        {
            Key = key ?? string.Empty;
            Address = address;
            Value = value;
            Status = status ?? string.Empty;
        }
    }

    internal sealed class LiveTuningScanReport
    {
        public readonly int SourcesResolved;
        public readonly string Summary;

        public LiveTuningScanReport(int sourcesResolved, string summary)
        {
            SourcesResolved = sourcesResolved;
            Summary = summary ?? string.Empty;
        }
    }

    internal struct Utf16DisplayString
    {
        public readonly int Offset;
        public readonly string Value;

        public Utf16DisplayString(int offset, string value)
        {
            Offset = offset;
            Value = value ?? string.Empty;
        }
    }

