        public bool IsAlive
        {
            get { return _process != null && !_process.HasExited && _handle != IntPtr.Zero; }
        }

        public RemoteDatabase(Process process, Action<string> log)
        {
            _process = process;
            _log = log;
        }

        public void Attach()
        {
            _handle = Native.OpenProcess(Native.ProcessRuntimeAccess, false, (uint)_process.Id);
            if (_handle == IntPtr.Zero)
                throw new InvalidOperationException("Could not open the selected FH6 process. Confirm Luna and FH6 use the same permission level, then try Attach again.");

            var main = _process.MainModule;
            var baseAddress = (ulong)main.BaseAddress.ToInt64();
            var moduleSize = main.ModuleMemorySize;
            _mainBase = baseAddress;
            _mainSize = moduleSize;
            _log("Scanning main module: " + main.ModuleName + " (" + moduleSize + " bytes)");

            var bytes = ReadBytes(baseAddress, moduleSize);
            if (bytes.Length == 0)
                throw new InvalidOperationException("Could not read main module memory.");

            var patterns = new[]
            {
                "48 8B 0D ? ? ? ? 48 8B 01 4C 8D 45 ? 48 8D 55 ? FF 50 48 90 48 8B 4D ? 48 85 C9",
                "48 8B 35 ? ? ? ? 48 85 F6 74",
                "48 8B 35 ? ? ? ? 48 85 F6 0F 84",
                "48 8B 35 ? ? ? ? 48 85 F6 0F 85"
            };

            var candidates = new List<DatabaseCandidate>();
            foreach (var p in patterns)
            {
                var parsed = Pattern.Parse(p);
                foreach (var offset in Pattern.FindAll(bytes, parsed, 64))
                {
                    var candidate = TryBuildCandidate(bytes, baseAddress, offset);
                    if (candidate.Valid && !candidates.Any(c => c.DatabaseObject == candidate.DatabaseObject && c.QueryFunction == candidate.QueryFunction))
                    {
                        candidates.Add(candidate);
                        _log("Candidate " + candidates.Count + " at 0x" + candidate.MatchAddress.ToString("X") +
                            " db=0x" + candidate.DatabaseObject.ToString("X") +
                            " fn=0x" + candidate.QueryFunction.ToString("X") + " via " + p);
                    }
                }
                if (candidates.Count > 0) break;
            }

            if (candidates.Count == 0)
                throw new InvalidOperationException("Database signature not found. If FH6 updated, the AOB pattern needs a refresh.");

            var best = candidates[0];
            _candidates.Clear();
            _candidates.AddRange(candidates);
            DatabaseObject = best.DatabaseObject;
            QueryFunction = best.QueryFunction;
        }

        public void RestoreMemoryPatches()
        {
            StopXpGainTrigger();
            StopTimeOfDayHold();
            RestoreTimeOfDayClockScale();
            StopTeleportToWaypointGuard();
            StopNoClipGuard();
            StopPhaseDashGuard();
            StopRewindGuard();
            StopGrapplingHookGuard();
            StopChargeJumpRuntime();
            StopWallClimberRuntime();
            StopSuperStrengthGuard();
            StopRolePlayGasRuntime();
            StopPhotoModeControls();
            ResetCameraEffects();
            RestoreValueEncryptionBypass();
            StopCrcTimer();
            RestoreRuntimeProfileHooks();
            RestoreFovTablePatches();
            RestorePhotoModeHookPatches();
            RestoreTimeAttackInfluencePatches();
            RestoreBestWheelspinOddsPatches();

            var restored = 0;
            for (var i = _memoryPatches.Count - 1; i >= 0; i--)
            {
                try
                {
                    WriteProtectedBytes(_memoryPatches[i].Address, _memoryPatches[i].Original);
                    restored++;
                }
                catch (Exception ex)
                {
                    _log("Could not restore runtime patch at 0x" + _memoryPatches[i].Address.ToString("X") + ": " + ex.Message);
                }
            }
            _memoryPatches.Clear();
            _log("Restored runtime query patches tracked by this process: " + restored + ".");
            RestoreCrcPointer();
        }

        internal LiveTuningScanReport ScanLiveTuningPointers(bool force)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (_mainBase == 0 || _mainSize <= 0)
                throw new InvalidOperationException("Main module was not captured during attach.");

            lock (_liveTuningLock)
            {
                return ScanLiveTuningPointersCore(force);
            }
        }

        internal LiveTuningReadback ReadLiveTuningFloat(string key, int source, uint offset, float saneMin, float saneMax)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            lock (_liveTuningLock)
            {
                if (_liveTuningSources.Count == 0)
                    ScanLiveTuningPointersCore(false);

                ulong address;
                if (!TryResolveLiveTuningAddress(source, offset, out address))
                    return new LiveTuningReadback(key, 0, 0F, "Not scanned");
                if (!IsReadableMemoryRange(address, 4))
                    return new LiveTuningReadback(key, address, 0F, "Unreadable");

                var value = ReadFloat(address);
                var status = IsFiniteFloat(value) && value >= saneMin && value <= saneMax ? "OK" : "Check";
                return new LiveTuningReadback(key, address, value, status);
            }
        }

        internal LiveTuningReadback WriteLiveTuningFloat(string key, int source, uint offset, float value, float saneMin, float saneMax, int mirrorSource, uint mirrorOffset)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (!IsFiniteFloat(value))
                throw new InvalidOperationException("Tuning value is not finite.");
            if (value < saneMin || value > saneMax)
                throw new InvalidOperationException("Tuning value is outside the safe range for this row.");

            lock (_liveTuningLock)
            {
                if (_liveTuningSources.Count == 0)
                    ScanLiveTuningPointersCore(false);

                ulong address;
                if (!TryResolveLiveTuningAddress(source, offset, out address))
                    throw new InvalidOperationException("Tuning row was not found yet. Keep Live Scan running, then try again.");
                if (!IsReadableMemoryRange(address, 4))
                    throw new InvalidOperationException("Tuning value target is not readable yet.");
                if (!IsWritableMemoryRange(address, 4))
                    throw new InvalidOperationException("Tuning value target is not writable yet.");

                var before = ReadFloat(address);
                if (!IsFiniteFloat(before) || before < saneMin || before > saneMax)
                    throw new InvalidOperationException("Tuning target changed or became stale. Run Live Scan again before applying.");

                SnapshotLiveTuningBytes(key, address);
                WriteFloat(address, value);

                if (mirrorSource >= 0)
                {
                    ulong mirrorAddress;
                    if (TryResolveLiveTuningAddress(mirrorSource, mirrorOffset, out mirrorAddress) && IsReadableMemoryRange(mirrorAddress, 4))
                    {
                        SnapshotLiveTuningBytes(key + ":mirror", mirrorAddress);
                        try
                        {
                            if (IsWritableMemoryRange(mirrorAddress, 4))
                                WriteFloat(mirrorAddress, value);
                            else
                                WriteProtectedBytes(mirrorAddress, BitConverter.GetBytes(value));
                        }
                        catch (Exception ex)
                        {
                            _log("Driving Tuning extra write skipped for " + key + ": " + ex.Message);
                        }
                    }
                }

                var readback = IsReadableMemoryRange(address, 4) ? ReadFloat(address) : value;
                var matched = Math.Abs(readback - value) <= Math.Max(0.0005F, Math.Abs(value) * 0.001F);
                return new LiveTuningReadback(key, address, readback, matched ? "Applied" : "Check");
            }
        }

        internal int RestoreLiveTuningSnapshots()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            lock (_liveTuningLock)
            {
                var restored = 0;
                foreach (var item in _liveTuningSnapshots.Values.ToList())
                {
                    if (item.Address == 0 || item.Original == null || item.Original.Length == 0)
                        continue;

                    try
                    {
                        if (IsWritableMemoryRange(item.Address, item.Original.Length))
                            WriteBytes(item.Address, item.Original);
                        else
                            WriteProtectedBytes(item.Address, item.Original);
                        restored++;
                    }
                    catch (Exception ex)
                    {
                        _log("Driving Tuning restore skipped: " + ex.Message);
                    }
                }

                _liveTuningSnapshots.Clear();
                return restored;
            }
        }

        private LiveTuningScanReport ScanLiveTuningPointersCore(bool force)
        {
            if (!force && _liveTuningSources.Count > 0)
                return new LiveTuningScanReport(_liveTuningSources.Count, BuildLiveTuningSourceSummary());

            _liveTuningSources.Clear();
            var module = ReadBytes(_mainBase, _mainSize);
            if (module.Length == 0)
                throw new InvalidOperationException("FH6 memory was not ready for Driving Tuning scan.");

            TryCaptureVehicleTuningSource();
            TryCaptureBase4Source(module);
            TryCaptureVehicleTuningLayoutAliases();

            if (_liveTuningSources.Count == 0)
                throw new InvalidOperationException("No Driving Tuning rows are ready yet.");

            var summary = BuildLiveTuningSourceSummary();
            return new LiveTuningScanReport(_liveTuningSources.Count, summary);
        }

        private void TryCaptureVehicleTuningSource()
        {
            try
            {
                var descriptor = GetVehicleControlDescriptor(RuntimeProfileFeature.Acceleration);
                var detour = EnsureRuntimeProfileHook(descriptor);
                var layout = GetVehicleControlLayout();
                var vehiclePointerSlot = detour.DetourAddress + (ulong)layout.VehiclePointerOffset;
                var watch = Stopwatch.StartNew();
                do
                {
                    var vehiclePointer = ReadUInt64(vehiclePointerSlot);
                    if (IsLikelyLiveTuningVehiclePointer(vehiclePointer))
                    {
                        _liveTuningSources[0] = vehiclePointer;
                        return;
                    }

                    Thread.Sleep(LiveTuningVehicleCapturePollMs);
                }
                while (watch.ElapsedMilliseconds < LiveTuningVehicleCaptureTimeoutMs && IsAlive);
            }
            catch (Exception ex)
            {
                if (ex is InvalidOperationException)
                    return;
            }
        }

        private void TryCaptureVehicleTuningLayoutAliases()
        {
            try
            {
                ulong vehiclePointer;
                if (!_liveTuningSources.TryGetValue(0, out vehiclePointer) || vehiclePointer == 0)
                    return;

                if (!IsLikelyVehicleTuningLayout(vehiclePointer))
                    return;

                _liveTuningSources[2] = vehiclePointer;
                _liveTuningSources[3] = vehiclePointer;
            }
            catch (Exception ex)
            {
                if (ex is InvalidOperationException)
                    return;
            }
        }

        private bool IsLikelyVehicleTuningLayout(ulong vehiclePointer)
        {
            if (vehiclePointer < 0x10000UL)
                return false;

            if (!IsReadableMemoryRange(vehiclePointer + 0x840UL, 4) ||
                !IsReadableMemoryRange(vehiclePointer + 0xA00UL, 4) ||
                !IsReadableMemoryRange(vehiclePointer + 0x7E4UL, 4))
                return false;

            var checks = new[]
            {
                new LiveTuningProbe(0x5AC, -25F, 25F),
                new LiveTuningProbe(0x5C0, -25F, 25F),
                new LiveTuningProbe(0x534, -100F, 100F),
                new LiveTuningProbe(0x538, -100F, 100F),
                new LiveTuningProbe(0x554, -100000F, 100000F),
                new LiveTuningProbe(0x5F0, -100000F, 100000F),
                new LiveTuningProbe(0x5F4, -100000F, 100000F),
                new LiveTuningProbe(0x6A8, -100000F, 100000F),
                new LiveTuningProbe(0x6AC, -100000F, 100000F),
                new LiveTuningProbe(0x828, -10000F, 10000F),
                new LiveTuningProbe(0x82C, -10000F, 10000F),
                new LiveTuningProbe(0x830, -10000F, 10000F),
                new LiveTuningProbe(0x7D8, -100F, 100F),
                new LiveTuningProbe(0x7DC, -100F, 100F),
                new LiveTuningProbe(0x7E0, -100F, 100F),
                new LiveTuningProbe(0x7E4, -100F, 100F)
            };

            var passed = 0;
            foreach (var probe in checks)
            {
                var address = vehiclePointer + probe.Offset;
                if (!IsReadableMemoryRange(address, 4))
                    continue;

                var value = ReadFloat(address);
                if (IsFiniteFloat(value) && value >= probe.Min && value <= probe.Max)
                    passed++;
            }

            return passed >= 11;
        }

        private void TryCaptureBase4Source(byte[] module)
        {
            const string signature = "3D ? ? ? ? 00 00 ? ? 00 00 5C 42";
            try
            {
                var parsed = Pattern.Parse(signature);
                foreach (var matchOffset in Pattern.FindAll(module, parsed, 16))
                {
                    var address = _mainBase + (ulong)matchOffset + 13UL;
                    if (address != 0 && IsReadableMemoryRange(address, 4))
                    {
                        _liveTuningSources[4] = address;
                        return;
                    }
                }
            }
            catch (Exception ex)
            {
                if (ex is InvalidOperationException)
                    return;
            }
        }

        private bool IsLikelyLiveTuningVehiclePointer(ulong vehiclePointer)
        {
            if (vehiclePointer < 0x10000UL)
                return false;

            if (!IsReadableMemoryRange(vehiclePointer + 0x20UL, 12))
                return false;

            if (!IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
                return false;

            return IsReadableMemoryRange(vehiclePointer + 0x660UL, 4) ||
                IsReadableMemoryRange(vehiclePointer + 0x108CUL, 4) ||
                IsReadableMemoryRange(vehiclePointer + 0x2D58UL, 4);
        }

        private bool TryResolveLiveTuningAddress(int source, uint offset, out ulong address)
        {
            address = 0;
            ulong baseAddress;
            if (!_liveTuningSources.TryGetValue(source, out baseAddress) || baseAddress == 0)
                return false;

            address = baseAddress + offset;
            return address >= baseAddress;
        }

        private void SnapshotLiveTuningBytes(string key, ulong address)
        {
            if (string.IsNullOrEmpty(key) || _liveTuningSnapshots.ContainsKey(key))
                return;

            var original = ReadBytes(address, 4);
            if (original.Length == 4)
                _liveTuningSnapshots[key] = new MemoryPatch { Address = address, Original = original };
        }

        private string BuildLiveTuningSourceSummary()
        {
            if (_liveTuningSources.Count == 0)
                return "No tuning groups found";

            var parts = new List<string>();
            if (_liveTuningSources.ContainsKey(0))
                parts.Add("tires and gears");
            if (_liveTuningSources.ContainsKey(2) || _liveTuningSources.ContainsKey(3))
                parts.Add("suspension, aero, steering, and body");
            if (_liveTuningSources.ContainsKey(4))
                parts.Add("alignment");

            if (parts.Count == 0)
                return "No tuning groups found";
            if (parts.Count == 3)
                return "All tuning groups found";

            return string.Join(", ", parts.ToArray());
        }

        public void ApplyProfileRuntimeHook(RuntimeProfileFeature feature, int value, bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            if (feature == RuntimeProfileFeature.TrailblazerMultiplier)
                throw new InvalidOperationException("Trailblazer Timer was removed from this build.");

            if (feature == RuntimeProfileFeature.Gravity)
            {
                ApplyGravityRuntimeHook(value, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.FovSlider)
            {
                ApplyFovTablePatch(value, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.NoWaterDrag && enabled)
                EnsureCrcBypass();

            if (feature == RuntimeProfileFeature.NoClip && enabled)
                EnsureCrcBypass();

            if (feature == RuntimeProfileFeature.NoClip)
            {
                if (enabled)
                {
                    var vehicleDescriptor = GetVehicleControlDescriptor(RuntimeProfileFeature.Jump);
                    var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
                    var cameraDescriptor = GetFlyCameraOffsetCaptureDescriptor();
                    var cameraDetour = EnsureRuntimeProfileHook(cameraDescriptor);
                    StartNoClipGuard(vehicleDetour, cameraDetour, cameraDescriptor, (int)Keys.V);
                }
                else
                {
                    StopNoClipGuard();
                }

                _log("No Clip " + (enabled ? "ON" : "OFF") + ".");
                return;
            }

            if (feature == RuntimeProfileFeature.WallClimber)
            {
                var strength = enabled ? BitConverter.ToSingle(BitConverter.GetBytes(value), 0) : 0F;
                SetWallJumperRuntimeHook(enabled, (int)Keys.J, strength);
                return;
            }

            var descriptor = GetProfileHookDescriptor(feature);
            RuntimeDetour detour;

            if (feature == RuntimeProfileFeature.Acceleration)
            {
                if (enabled)
                {
                    detour = EnsureRuntimeProfileHook(descriptor);
                }
                else
                {
                    lock (_runtimePatchLock)
                    {
                        if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                        {
                            _vehicleAccelerationEnabled = false;
                            _vehicleAccelerationValue = 0;
                            StopAccelerationGuard();
                            _log(descriptor.Name + " runtime hook is already OFF.");
                            return;
                        }
                    }
                }

                _vehicleAccelerationEnabled = enabled;
                _vehicleAccelerationValue = enabled ? value : 0;

                if (enabled)
                    StartAccelerationGuard(detour, descriptor);
                else
                    StopAccelerationGuard();
                _log("Acceleration " + (enabled ? "ON. Hold W or Up to apply it." : "OFF") + ".");
                return;
            }

            if (feature == RuntimeProfileFeature.SuperBrake)
            {
                _vehicleSuperBrakeEnabled = enabled;
                if (enabled)
                {
                    detour = EnsureRuntimeProfileHook(descriptor);
                    StartSuperBrakeGuard(detour, descriptor);
                    _log("Super Brake ON. Key=" + ((Keys)_brakeVirtualKey).ToString() + ". First second is instant stop, then reverse is allowed.");
                }
                else
                {
                    if (_vehicleAdaptiveBrakeEnabled)
                        ApplyVehicleControlLaneIfPresent(descriptor);
                    else
                        StopSuperBrakeGuard();
                    _log("Super Brake OFF.");
                }
                return;
            }

            if (feature == RuntimeProfileFeature.AdaptiveBrake)
            {
                _vehicleAdaptiveBrakeEnabled = enabled;
                _vehicleAdaptiveBrakeValue = enabled ? value : 0;
                if (enabled)
                {
                    detour = EnsureRuntimeProfileHook(descriptor);
                    StartSuperBrakeGuard(detour, descriptor);
                    _log("Adaptive Brake ON. Hold the selected keyboard brake key.");
                }
                else
                {
                    if (_vehicleSuperBrakeEnabled)
                        ApplyVehicleControlLaneIfPresent(descriptor);
                    else
                        StopSuperBrakeGuard();
                    _log("Adaptive Brake OFF.");
                }
                return;
            }

            if (feature == RuntimeProfileFeature.Hover)
            {
                if (enabled)
                {
                    var speed = BitConverter.ToSingle(BitConverter.GetBytes(value), 0);
                    if (float.IsNaN(speed) || float.IsInfinity(speed) || speed < 1F || speed > 250F)
                        throw new InvalidOperationException("Fly speed must be between 1 and 250.");
                    detour = EnsureRuntimeProfileHook(descriptor);
                    RuntimeDetour cameraDetour = null;
                    RuntimeProfileHookDescriptor cameraDescriptor = null;
                    try
                    {
                        cameraDescriptor = GetFlyCameraOffsetCaptureDescriptor();
                        cameraDetour = EnsureRuntimeProfileHook(cameraDescriptor);
                    }
                    catch (Exception ex)
                    {
                        _log("Fly heading alignment is waiting for FH6 camera data: " + ex.Message);
                    }

                    StartHoverGuard(detour, cameraDetour, cameraDescriptor, speed);
                    _log("Fly ON. W/S drives through the air, A/D steers movement and body yaw, Space or Jump rises, and Ctrl descends.");
                }
                else
                {
                    StopHoverGuard();
                    _log("Fly OFF.");
                }
                return;
            }

            if (feature == RuntimeProfileFeature.AirBrake)
            {
                var amount = enabled ? BitConverter.ToSingle(BitConverter.GetBytes(value), 0) : 0F;
                if (enabled)
                {
                    if (float.IsNaN(amount) || float.IsInfinity(amount))
                        throw new InvalidOperationException("Air Brake strength must be a valid number.");
                    detour = EnsureRuntimeProfileHook(descriptor);
                    StartAirBrakeGuard(detour, descriptor, amount);
                    _log("Air Brake ON. Hold S or Down while airborne to slow air travel.");
                }
                else
                {
                    StopAirBrakeGuard();
                    _log("Air Brake OFF.");
                }
                return;
            }

            if (feature == RuntimeProfileFeature.ForwardLaunch)
            {
                var force = enabled ? BitConverter.ToSingle(BitConverter.GetBytes(value), 0) : 0F;
                if (enabled)
                {
                    if (float.IsNaN(force) || float.IsInfinity(force))
                        throw new InvalidOperationException("Forward Launch strength must be a valid number.");
                    detour = EnsureRuntimeProfileHook(descriptor);
                    StartForwardLaunchGuard(detour, descriptor, force);
                    _log("Forward Launch ON. Forward input gets a straight 2 second launch boost.");
                }
                else
                {
                    StopForwardLaunchGuard();
                    _log("Forward Launch OFF.");
                }
                return;
            }

            if (feature == RuntimeProfileFeature.TimeOfDay)
            {
                ApplyTimeOfDayRuntimeHook(value, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.FastSlowTime)
            {
                ApplyProfileRuntimeHookGroup(feature, value, enabled);
                return;
            }

            if (feature == RuntimeProfileFeature.FreezeAI)
            {
                if (enabled)
                {
                    var vehicleDescriptor = GetVehicleControlDescriptor(RuntimeProfileFeature.Jump);
                    var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
                    detour = EnsureRuntimeProfileHook(descriptor);

                    if (descriptor.ObjectPointerOffset >= 0)
                    {
                        var vehiclePointerSlot = vehicleDetour.DetourAddress + (ulong)GetVehicleControlLayout().VehiclePointerOffset;
                        WriteUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset, vehiclePointerSlot);
                    }
                }
                else
                {
                    lock (_runtimePatchLock)
                    {
                        if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                        {
                            _log(descriptor.Name + " runtime hook is already OFF.");
                            return;
                        }
                    }
                }

                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, enabled ? (byte)1 : (byte)0);
                _log(descriptor.Name + " " + (enabled ? "ON" : "OFF") + ".");
                return;
            }

            if (feature == RuntimeProfileFeature.DisableCameraCollision)
            {
                if (enabled)
                {
                    detour = EnsureRuntimeProfileHook(descriptor);
                }
                else
                {
                    lock (_runtimePatchLock)
                    {
                        if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                        {
                            _log(descriptor.Name + " runtime hook is already OFF.");
                            return;
                        }
                    }
                }

                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, enabled ? (byte)1 : (byte)0);
                TryWriteCapturedCameraCollisionFlag(detour, descriptor, enabled ? (byte)0 : (byte)1);
                _log(descriptor.Name + " " + (enabled ? "ON" : "OFF") + ".");
                return;
            }

            if (enabled)
            {
                detour = EnsureRuntimeProfileHook(descriptor);
            }
            else
            {
                lock (_runtimePatchLock)
                {
                    if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                    {
                        _log(descriptor.Name + " runtime hook is already OFF.");
                        return;
                    }
                }
            }

            if (descriptor.ValueOffset >= 0)
                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, value);
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, enabled ? (byte)1 : (byte)0);
            if (feature == RuntimeProfileFeature.MissionTimerScale || feature == RuntimeProfileFeature.RaceTimerScale)
            {
                if (enabled)
                    StartTimerScaleGuard(feature, detour, descriptor, value);
                else
                    StopTimerScaleGuard(feature);
            }
            if (descriptor.ResetByteOffset >= 0 && enabled)
                WriteByte(detour.DetourAddress + (ulong)descriptor.ResetByteOffset, 0);
            if (enabled)
                TryWriteCapturedRuntimeObjectValue(feature, detour, descriptor, value);
            _log(descriptor.Name + " " + (enabled ? "ON" : "OFF") + ".");
        }

        public void SetXpGainRuntimeHook(bool enabled, int amount, int speedMs, bool whilePlaying)
        {
            SetXpGainRuntimeHook(enabled, amount, speedMs, whilePlaying, 0);
        }

        public void SetXpGainRuntimeHook(bool enabled, int amount, int speedMs, bool whilePlaying, int fireCount)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            if (!enabled)
            {
                StopXpGainTrigger();
                _log("XP Gain OFF.");
                return;
            }

            if (amount < 0)
                throw new InvalidOperationException("XP Gain needs a whole number greater than or equal to zero.");

            var descriptor = GetSpendCaptureDescriptor();
            var detour = EnsureRuntimeProfileHook(descriptor);

            _xpGainProfileDetour = detour;
            _xpGainSpendDescriptor = descriptor;
            _xpGainSpendFunctionAddress = detour.Address;
            _xpGainAmount = amount;
            _xpGainSpeedMs = Math.Max(100, Math.Min(10000, speedMs));
            _xpGainFireLimit = Math.Max(0, Math.Min(100000, fireCount));
            _xpGainFiresRemaining = _xpGainFireLimit;
            _xpGainWhilePlaying = whilePlaying;
            _xpGainPauseEdgeLast = false;
            _xpGainTriggerRunning = 0;
            _xpGainWaitingLogged = false;
            _xpGainCompleteLogged = false;

            var period = whilePlaying ? _xpGainSpeedMs : 60;
            if (_xpGainTriggerTimer == null)
                _xpGainTriggerTimer = new System.Threading.Timer(XpGainTriggerTick, null, 600, period);
            else
                _xpGainTriggerTimer.Change(600, period);

            _log("XP Gain ON: " + amount.ToString(CultureInfo.InvariantCulture) + " skill point(s) " +
                (whilePlaying ? "every " + _xpGainSpeedMs.ToString(CultureInfo.InvariantCulture) + " ms while playing" : "each time you pause/resume") +
                (_xpGainFireLimit > 0 ? ", " + _xpGainFireLimit.ToString(CultureInfo.InvariantCulture) + " fire(s)" : ", continuous") +
                ". Spend ONE skill point in the perk menu once to arm it, then it keeps applying until you turn it off.");
        }

        private void StopXpGainTrigger()
        {
            var timer = _xpGainTriggerTimer;
            _xpGainTriggerTimer = null;
            if (timer != null)
                timer.Dispose();

            _xpGainProfileDetour = null;
            _xpGainSpendDescriptor = null;
            _xpGainSpendFunctionAddress = 0;
            _xpGainAmount = 0;
            _xpGainFireLimit = 0;
            _xpGainFiresRemaining = 0;
            _xpGainTriggerRunning = 0;
            _xpGainWaitingLogged = false;
            _xpGainCompleteLogged = false;
        }

        private void XpGainTriggerTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _xpGainTriggerRunning, 1) == 1)
                return;

            try
            {
                var detour = _xpGainProfileDetour;
                var descriptor = _xpGainSpendDescriptor;
                var spendFunction = _xpGainSpendFunctionAddress;
                if (!IsAlive || detour == null || detour.DetourAddress == 0 || descriptor == null || !IsValidXpGainSpendTarget(spendFunction))
                    return;

                var ctx = ReadUInt64(detour.DetourAddress + (ulong)descriptor.CaptureOffset);
                if (ctx == 0)
                {
                    if (!_xpGainWaitingLogged)
                    {
                        _xpGainWaitingLogged = true;
                        _log("XP Gain armed - spend ONE skill point in the perk menu once so it can capture the reward path.");
                    }
                    return;
                }

                var fireAmount = _xpGainAmount > 0 ? _xpGainAmount : 1;
                if (_xpGainWhilePlaying)
                {
                    if (TryConsumeXpGainFireSlot())
                        FireSkillSpend(spendFunction, ctx, fireAmount);
                }
                else
                {
                    var pressed = IsXpGainPauseInputPressed();
                    if (pressed && !_xpGainPauseEdgeLast && TryConsumeXpGainFireSlot())
                        FireSkillSpend(spendFunction, ctx, fireAmount);
                    _xpGainPauseEdgeLast = pressed;
                }
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("XP Gain", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _xpGainTriggerRunning, 0);
            }
        }

        private bool TryConsumeXpGainFireSlot()
        {
            if (_xpGainFireLimit <= 0)
                return true;

            if (_xpGainFiresRemaining <= 0)
            {
                if (!_xpGainCompleteLogged)
                {
                    _xpGainCompleteLogged = true;
                    _log("XP Gain completed the configured fire count.");
                }
                return false;
            }

            _xpGainFiresRemaining--;
            if (_xpGainFiresRemaining == 0 && !_xpGainCompleteLogged)
            {
                _xpGainCompleteLogged = true;
                _log("XP Gain completed the configured fire count.");
            }
            return true;
        }

        private bool IsValidXpGainSpendTarget(ulong address)
        {
            if (address == 0 || _mainBase == 0 || _mainSize <= 0)
                return false;
            var end = _mainBase + (ulong)_mainSize;
            return address >= _mainBase && address < end && IsExecutableAddress(address);
        }

        private void FireSkillSpend(ulong target, ulong context, int amount)
        {
            if (context == 0 || !IsValidXpGainSpendTarget(target))
                return;

            var shell = new List<byte>();
            shell.AddRange(new byte[] { 0x48, 0x83, 0xEC, 0x28 });
            shell.AddRange(new byte[] { 0x48, 0xB9 }); shell.AddRange(BitConverter.GetBytes(context));
            shell.AddRange(new byte[] { 0xBA }); shell.AddRange(BitConverter.GetBytes(amount));
            shell.AddRange(new byte[] { 0x48, 0xB8 }); shell.AddRange(BitConverter.GetBytes(target));
            shell.AddRange(new byte[] { 0xFF, 0xD0 });
            shell.AddRange(new byte[] { 0x48, 0x83, 0xC4, 0x28 });
            shell.AddRange(new byte[] { 0xB8, 0x01, 0x00, 0x00, 0x00 });
            shell.Add(0xC3);
            ExecuteRemoteShellcode(shell.ToArray(), "XP Gain reward fire");
        }

        private static byte[] BuildSpendCaptureAsm(out int captureOffset, out int minimumSize)
        {
            var code = new List<byte>();
            var dataRefs = new List<ProfileAsmFixup>();

            EmitBytes(code, 0x48, 0x89, 0x0D);
            AddRelativeFixup(code, dataRefs, "ctx");
            EmitBytes(code, 0x89, 0x54, 0x24, 0x10);
            EmitBytes(code, 0x53);

            var ctxOffset = Align8(code.Count + 5);
            captureOffset = ctxOffset;
            minimumSize = ctxOffset + 0x10;

            var dataLabels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase) { { "ctx", ctxOffset } };
            PatchRelativeFixups(code, dataRefs, dataLabels);
            return code.ToArray();
        }

        private static RuntimeProfileHookDescriptor GetSpendCaptureDescriptor()
        {
            int captureOffset;
            int minimumSize;
            var asm = BuildSpendCaptureAsm(out captureOffset, out minimumSize);
            return new RuntimeProfileHookDescriptor
            {
                Key = "SkillSpendCapture",
                Name = "XP Gain",
                Signature = "89 54 24 10 53 55 56 57 41 56 48 83 EC 40 48 8B E9 33 F6 48 89 74 24 70 B9 28 00 00 00 E8",
                MatchOffset = 0,
                HookSize = 5,
                ExpectedOriginal = new byte[] { 0x89, 0x54, 0x24, 0x10, 0x53 },
                ToggleOffset = 0,
                ValueOffset = 0,
                CaptureOffset = captureOffset,
                MinimumSize = minimumSize,
                Asm = asm
            };
        }

        private static bool IsXpGainPauseInputPressed()
        {
            if (IsKeyDown((int)Keys.Escape))
                return true;

            return false;
        }

        private void StartTimerScaleGuard(RuntimeProfileFeature feature, RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int value)
        {
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return;

            if (feature == RuntimeProfileFeature.MissionTimerScale)
            {
                _missionTimerScaleGuardDetour = detour;
                _missionTimerScaleGuardDescriptor = descriptor;
                _missionTimerScaleGuardValue = value;
            }
            else if (feature == RuntimeProfileFeature.RaceTimerScale)
            {
                _raceTimerScaleGuardDetour = detour;
                _raceTimerScaleGuardDescriptor = descriptor;
                _raceTimerScaleGuardValue = value;
            }
            else
            {
                return;
            }

            if (_timerScaleGuardTimer == null)
                _timerScaleGuardTimer = new System.Threading.Timer(TimerScaleGuardTick, null, 0, TimerScaleGuardIntervalMs);
            else
                _timerScaleGuardTimer.Change(0, TimerScaleGuardIntervalMs);
        }

        private void StopTimerScaleGuard(RuntimeProfileFeature feature)
        {
            if (feature == RuntimeProfileFeature.MissionTimerScale)
            {
                ClearTimerScaleGuardSlot(_missionTimerScaleGuardDetour, _missionTimerScaleGuardDescriptor);
                _missionTimerScaleGuardDetour = null;
                _missionTimerScaleGuardDescriptor = null;
                _missionTimerScaleGuardValue = 0;
            }
            else if (feature == RuntimeProfileFeature.RaceTimerScale)
            {
                ClearTimerScaleGuardSlot(_raceTimerScaleGuardDetour, _raceTimerScaleGuardDescriptor);
                _raceTimerScaleGuardDetour = null;
                _raceTimerScaleGuardDescriptor = null;
                _raceTimerScaleGuardValue = 0;
            }

            if (_missionTimerScaleGuardDetour == null && _raceTimerScaleGuardDetour == null)
                StopTimerScaleGuardTimer();
        }

        private void StopTimerScaleGuardTimer()
        {
            var timer = _timerScaleGuardTimer;
            _timerScaleGuardTimer = null;
            if (timer != null)
                timer.Dispose();
            _missionTimerScaleGuardDetour = null;
            _missionTimerScaleGuardDescriptor = null;
            _missionTimerScaleGuardValue = 0;
            _raceTimerScaleGuardDetour = null;
            _raceTimerScaleGuardDescriptor = null;
            _raceTimerScaleGuardValue = 0;
        }

        private void TimerScaleGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _timerScaleGuardRunning, 1) == 1)
                return;

            try
            {
                ApplyTimerScaleGuardSlot(_missionTimerScaleGuardDetour, _missionTimerScaleGuardDescriptor, _missionTimerScaleGuardValue);
                ApplyTimerScaleGuardSlot(_raceTimerScaleGuardDetour, _raceTimerScaleGuardDescriptor, _raceTimerScaleGuardValue);
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Timer Scale", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _timerScaleGuardRunning, 0);
            }
        }

        private void ApplyTimerScaleGuardSlot(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int value)
        {
            if (!IsAlive || detour == null || descriptor == null || detour.DetourAddress == 0)
                return;

            if (descriptor.ValueOffset >= 0)
                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, value);
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
        }

        private void ClearTimerScaleGuardSlot(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor)
        {
            try
            {
                if (detour == null || descriptor == null || detour.DetourAddress == 0)
                    return;

                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                if (descriptor.ValueOffset >= 0)
                    WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0);
            }
            catch
            {
            }
        }

        public int ApplyTrailblazerTimerScale(float scale, bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            if (!enabled)
            {
                StopTrailblazerTimerGuard();
                _log("Trailblazer Timer OFF.");
                return 0;
            }

            if (float.IsNaN(scale) || float.IsInfinity(scale) || scale < -10F || scale > 10F)
                throw new InvalidOperationException("Trailblazer Timer expects a value from -10 to 10. Negative values slow the countdown; 1 is normal.");

            List<TrailblazerTimerCandidate> candidates;
            lock (_trailblazerTimerLock)
            {
                _trailblazerTimerScale = scale;
                candidates = LocateTrailblazerTimerCandidates();
                _trailblazerTimerCandidates = candidates;
                _trailblazerTimerLastRescanUtcTicks = DateTime.UtcNow.Ticks;
            }

            if (candidates.Count == 0)
                throw new InvalidOperationException("Trailblazer Timer could not find an active countdown. Start a Trailblazer event, then apply again.");

            StartTrailblazerTimerGuard();
            _log("Trailblazer Timer live guard armed with " + candidates.Count.ToString(CultureInfo.InvariantCulture) + " countdown field(s).");
            return candidates.Count;
        }

        private void StartTrailblazerTimerGuard()
        {
            if (_trailblazerTimerGuardTimer != null)
                return;
            _trailblazerTimerGuardTimer = new System.Threading.Timer(TrailblazerTimerGuardTick, null, TrailblazerTimerGuardIntervalMs, TrailblazerTimerGuardIntervalMs);
        }

        private void StopTrailblazerTimerGuard()
        {
            var timer = _trailblazerTimerGuardTimer;
            _trailblazerTimerGuardTimer = null;
            if (timer != null)
                timer.Dispose();
            lock (_trailblazerTimerLock)
            {
                _trailblazerTimerCandidates.Clear();
                _trailblazerTimerScale = 1F;
            }
        }

        private void TrailblazerTimerGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _trailblazerTimerGuardRunning, 1) == 1)
                return;

            try
            {
                if (_handle == IntPtr.Zero)
                    return;

                List<TrailblazerTimerCandidate> candidates;
                float scale;
                lock (_trailblazerTimerLock)
                {
                    scale = _trailblazerTimerScale;
                    candidates = _trailblazerTimerCandidates.ToList();
                }

                if (candidates.Count == 0)
                    return;

                var effectiveScale = NormalizeTrailblazerTimerScale(scale);
                var alive = 0;
                foreach (var candidate in candidates)
                {
                    if (!IsWritableMemoryRange(candidate.Address, candidate.Size))
                    {
                        candidate.Misses++;
                        continue;
                    }

                    var current = ReadTrailblazerTimerCandidateValue(candidate);
                    if (!IsTrailblazerTimerValue(current))
                    {
                        candidate.Misses++;
                        continue;
                    }

                    alive++;
                    if (current > candidate.LastValue + 2F || candidate.LastValue <= 0F)
                    {
                        candidate.LastValue = current;
                        candidate.Misses = 0;
                        continue;
                    }

                    if (Math.Abs(effectiveScale - 1F) < 0.0001F)
                    {
                        candidate.LastValue = current;
                        candidate.Misses = 0;
                        continue;
                    }

                    var drop = candidate.LastValue - current;
                    if (drop > 0.0001F && drop < 3F)
                    {
                        var desired = candidate.LastValue - (drop * effectiveScale);
                        if (desired < 0F)
                            desired = 0F;
                        if (desired > current + 1.25F)
                            desired = current + 1.25F;
                        if (desired > 300F)
                            desired = 300F;
                        if (Math.Abs(desired - current) > 0.0001F)
                            WriteTrailblazerTimerCandidateValue(candidate, desired);
                        candidate.LastValue = desired;
                    }
                    else if (drop >= 3F)
                    {
                        candidate.Misses++;
                        candidate.LastValue = current;
                        continue;
                    }
                    else
                    {
                        candidate.LastValue = current;
                    }
                    candidate.Misses = 0;
                }

                lock (_trailblazerTimerLock)
                {
                    _trailblazerTimerCandidates = candidates
                        .Where(candidate => candidate.Misses < 12 && IsReadableMemoryRange(candidate.Address, candidate.Size))
                        .GroupBy(candidate => candidate.Address)
                        .Select(group => group.First())
                        .OrderByDescending(candidate => candidate.Score)
                        .ThenBy(candidate => candidate.Address)
                        .Take(TrailblazerTimerMaxCandidates)
                        .ToList();
                }

                var now = DateTime.UtcNow.Ticks;
                if (alive == 0 ||
                    (alive < 2 && now - _trailblazerTimerLastRescanUtcTicks > TimeSpan.FromSeconds(6).Ticks))
                {
                    List<TrailblazerTimerCandidate> rescanned;
                    lock (_trailblazerTimerLock)
                    {
                        rescanned = LocateTrailblazerTimerCandidates();
                        if (rescanned.Count > 0)
                            _trailblazerTimerCandidates = rescanned
                                .OrderByDescending(candidate => candidate.Score)
                                .ThenBy(candidate => candidate.Address)
                                .Take(TrailblazerTimerMaxCandidates)
                                .ToList();
                        _trailblazerTimerLastRescanUtcTicks = now;
                    }
                    if (rescanned.Count > 0)
                        _log("Trailblazer Timer refreshed live countdown fields.");
                }
            }
            catch (Exception ex)
            {
                _log("Trailblazer Timer live control skipped a tick: " + ex.Message);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _trailblazerTimerGuardRunning, 0);
            }
        }

        private List<TrailblazerTimerCandidate> LocateTrailblazerTimerCandidates()
        {
            var candidates = new Dictionary<ulong, TrailblazerTimerCandidate>();
            foreach (var address in GetTrailblazerTimerSeedAddresses())
            {
                TrailblazerTimerCandidate candidate;
                if (TryValidateTrailblazerTimerAddress(address, 300, out candidate))
                    candidates[address] = candidate;
                if (candidates.Count >= 16)
                    break;
            }

            if (candidates.Count >= 2)
                return candidates.Values
                    .OrderByDescending(candidate => candidate.Score)
                    .ThenBy(candidate => candidate.Address)
                    .Take(TrailblazerTimerMaxCandidates)
                    .ToList();

            foreach (var candidate in ScanTrailblazerTimerCandidates(650))
            {
                if (!candidates.ContainsKey(candidate.Address))
                    candidates[candidate.Address] = candidate;
            }

            return candidates.Values
                .OrderByDescending(candidate => candidate.Score)
                .ThenBy(candidate => candidate.Address)
                .Take(TrailblazerTimerMaxCandidates)
                .ToList();
        }

        private IEnumerable<ulong> GetTrailblazerTimerSeedAddresses()
        {
            yield break;
        }

        private bool TryValidateTrailblazerTimerAddress(ulong address, int delayMs, out TrailblazerTimerCandidate candidate)
        {
            candidate = null;
            if (!IsReadableMemoryRange(address, 4) || !IsWritableMemoryRange(address, 4))
                return false;

            var first = ReadFloat(address);
            if (!IsTrailblazerTimerValue(first) || first < 1F)
                return false;

            Thread.Sleep(delayMs);
            var second = ReadFloat(address);
            if (!IsTrailblazerTimerValue(second))
                return false;

            var delta = first - second;
            if (!IsTrailblazerTimerDelta(delta, delayMs / 1000F))
                return false;

            candidate = new TrailblazerTimerCandidate
            {
                Address = address,
                Size = 4,
                LastValue = second,
                FrozenValue = second,
                Score = ScoreTrailblazerTimerCandidate(second, delta, delayMs / 1000F)
            };
            return true;
        }

        private IEnumerable<TrailblazerTimerCandidate> ScanTrailblazerTimerCandidates(int delayMs)
        {
            var snapshots = new List<Tuple<MemoryRegion, byte[]>>();
            var totalBytes = 0UL;
            const ulong MaxScanBytes = 768UL * 1024UL * 1024UL;
            const ulong MaxRegionBytes = 192UL * 1024UL * 1024UL;

            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.BaseAddress >= 0x10000000000UL &&
                                 region.BaseAddress < 0x700000000000UL &&
                                 region.RegionSize >= 1024UL * 1024UL &&
                                 region.RegionSize <= MaxRegionBytes)
                .OrderBy(region => TrailblazerTimerRegionPriority(region))
                .ThenByDescending(region => Math.Min(region.RegionSize, MaxRegionBytes))
                .ThenBy(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (totalBytes >= MaxScanBytes)
                    break;

                var length = (int)Math.Min(region.RegionSize, Math.Min(MaxRegionBytes, MaxScanBytes - totalBytes));
                var first = ReadBytes(region.BaseAddress, length);
                if (first.Length < 4)
                    continue;

                snapshots.Add(Tuple.Create(region, first));
                totalBytes += (ulong)first.Length;
            }

            if (snapshots.Count == 0)
                yield break;

            Thread.Sleep(delayMs);
            var elapsed = delayMs / 1000F;
            var emitted = 0;
            const int MaxEmitted = 512;
            foreach (var snapshot in snapshots)
            {
                var region = snapshot.Item1;
                var first = snapshot.Item2;
                var second = ReadBytes(region.BaseAddress, first.Length);
                var length = Math.Min(first.Length, second.Length) & ~3;
                var emittedForRegion = 0;
                for (var offset = 0; offset < length; offset += 4)
                {
                    var before = BitConverter.ToSingle(first, offset);
                    if (!IsTrailblazerTimerValue(before) || before < 2F)
                        continue;

                    var after = BitConverter.ToSingle(second, offset);
                    if (!IsTrailblazerTimerValue(after))
                        continue;

                    var delta = before - after;
                    if (!IsTrailblazerTimerDelta(delta, elapsed))
                        continue;

                    yield return new TrailblazerTimerCandidate
                    {
                        Address = region.BaseAddress + (ulong)offset,
                        Size = 4,
                        LastValue = after,
                        FrozenValue = after,
                        Score = ScoreTrailblazerTimerCandidate(after, delta, elapsed)
                    };

                    emitted++;
                    emittedForRegion++;
                    if (emitted >= MaxEmitted)
                        yield break;
                    if (emittedForRegion >= 96)
                        break;
                }
            }
        }

        private static float NormalizeTrailblazerTimerScale(float scale)
        {
            if (scale < 0F)
            {
                var slowed = 1F / (1F + Math.Abs(scale));
                return Math.Max(TrailblazerTimerMinimumSlowScale, slowed);
            }

            if (scale < 0.0001F)
                return TrailblazerTimerMinimumSlowScale;
            return Math.Min(10F, scale);
        }

        private float ReadTrailblazerTimerCandidateValue(TrailblazerTimerCandidate candidate)
        {
            if (candidate.Size == 8)
            {
                var bytes = ReadBytes(candidate.Address, 8);
                if (bytes.Length < 8)
                    return float.NaN;
                var value = BitConverter.ToDouble(bytes, 0);
                if (double.IsNaN(value) || double.IsInfinity(value) || value < float.MinValue || value > float.MaxValue)
                    return float.NaN;
                return (float)value;
            }

            return ReadFloat(candidate.Address);
        }

        private void WriteTrailblazerTimerCandidateValue(TrailblazerTimerCandidate candidate, float value)
        {
            if (candidate.Size == 8)
            {
                WriteBytes(candidate.Address, BitConverter.GetBytes((double)value));
                return;
            }

            WriteFloat(candidate.Address, value);
        }

        private static bool IsTrailblazerTimerValue(float value)
        {
            return !float.IsNaN(value) && !float.IsInfinity(value) && value >= 0F && value <= 300F;
        }

        private static int TrailblazerTimerRegionPriority(MemoryRegion region)
        {
            if (region.BaseAddress >= 0x1A000000000UL &&
                region.BaseAddress < 0x1C000000000UL &&
                region.RegionSize >= 16UL * 1024UL * 1024UL &&
                region.RegionSize <= 128UL * 1024UL * 1024UL)
                return 0;
            if (region.RegionSize >= 8UL * 1024UL * 1024UL &&
                region.RegionSize <= 192UL * 1024UL * 1024UL)
                return 1;
            return 2;
        }

        private static bool IsTrailblazerTimerDelta(float delta, float elapsed)
        {
            var min = Math.Max(0.15F, elapsed * 0.35F);
            var max = Math.Max(1.75F, elapsed * 2.2F);
            return delta >= min && delta <= max;
        }

        private static double ScoreTrailblazerTimerCandidate(float value, float delta, float elapsed)
        {
            var integerBonus = Math.Abs(value - (float)Math.Round(value)) < 0.02F ? 1.0 : 0.0;
            var speedScore = 6.0 - Math.Min(6.0, Math.Abs(delta - elapsed) * 2.0);
            var rangeScore = value >= 5F && value <= 180F ? 5.0 : (value >= 2F ? 1.0 : -8.0);
            var lowCounterPenalty = value < 3F ? 6.0 : 0.0;
            return integerBonus + speedScore + rangeScore - lowCounterPenalty;
        }

        private void ApplyProfileRuntimeHookGroup(RuntimeProfileFeature feature, int value, bool enabled)
        {
            var applied = 0;
            var failed = 0;
            string firstFailure = null;
            foreach (var descriptor in GetProfileHookDescriptors(feature))
            {
                try
                {
                    RuntimeDetour detour;
                    if (enabled)
                    {
                        detour = EnsureRuntimeProfileHook(descriptor);
                    }
                    else
                    {
                        lock (_runtimePatchLock)
                        {
                            if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                                continue;
                        }
                    }

                    if (descriptor.ValueOffset >= 0)
                        WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, value);
                    WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, enabled ? (byte)1 : (byte)0);
                    if (enabled)
                        TryWriteCapturedRuntimeObjectValue(feature, detour, descriptor, value);
                    applied++;
                }
                catch (Exception ex)
                {
                    failed++;
                    if (firstFailure == null)
                        firstFailure = descriptor.Key + ": " + ex.Message;
                }
            }

            var name = GetRuntimeFeatureName(feature);
            if (applied == 0)
            {
                if (enabled && firstFailure != null)
                    throw new InvalidOperationException(name + " hook could not be applied. " + firstFailure);
                _log(name + " runtime hook is already OFF.");
            }
            else
            {
                _log(name + " " + (enabled ? "ON" : "OFF") + (failed > 0 ? " (" + applied + " path(s), " + failed + " optional path(s) skipped)." : "."));
            }
        }

        private bool IsRuntimeDetourPatchActive(RuntimeDetour detour)
        {
            if (detour == null || detour.Patch == null || detour.Patch.Length == 0)
                return false;

            var current = ReadBytes(detour.Address, detour.Patch.Length);
            return current.Length == detour.Patch.Length && BytesStartWith(current, detour.Patch);
        }

        private bool TryWriteCapturedRuntimeObjectValue(RuntimeProfileFeature feature, RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int value)
        {
            if (detour == null || descriptor == null || descriptor.ObjectPointerOffset < 0)
                return false;

            var objectAddress = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
            if (objectAddress == 0)
                return false;

            if (feature == RuntimeProfileFeature.TimeOfDay)
            {
                if (descriptor.ObjectValueFieldOffset >= 0)
                    return TryWriteTimeOfDayObjectValue(objectAddress, value, descriptor.ObjectValueFieldOffset);
                return TryWriteTimeOfDayObjectValue(objectAddress, value);
            }

            if (descriptor.ObjectValueFieldOffset < 0)
                return false;

            var valueAddress = objectAddress + (ulong)descriptor.ObjectValueFieldOffset;
            if (!IsWritableMemoryRange(valueAddress, 4))
                return false;

            WriteInt32(valueAddress, value);
            return true;
        }

        private bool TryWriteCapturedCameraCollisionFlag(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, byte value)
        {
            if (detour == null || descriptor == null || descriptor.ObjectPointerOffset < 0)
                return false;

            var objectAddress = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
            if (objectAddress == 0)
                return false;

            var valueAddress = objectAddress + 0x10UL;
            if (!IsWritableMemoryRange(valueAddress, 1))
                return false;

            WriteByte(valueAddress, value);
            return true;
        }

        private bool TryWriteTimeOfDayObjectValue(ulong objectAddress, int value)
        {
            return TryWriteTimeOfDayObjectValue(objectAddress, value, 0x64);
        }

        private bool TryWriteTimeOfDayObjectValue(ulong objectAddress, int value, int valueFieldOffset)
        {
            var seconds = BitConverter.ToSingle(BitConverter.GetBytes(value), 0);
            if (!IsFiniteFloat(seconds))
                return false;

            if (seconds < 0F)
                seconds = 0F;
            while (seconds >= 86400F)
                seconds -= 86400F;

            var written = false;
            var valueAddress = objectAddress + (ulong)valueFieldOffset;
            if (IsWritableMemoryRange(valueAddress, 4))
            {
                WriteFloat(valueAddress, seconds);
                written = true;
            }

            if (valueFieldOffset == 0x64)
            {
                if (IsWritableMemoryRange(objectAddress + 0x78UL, 1))
                    WriteByte(objectAddress + 0x78UL, 1);
                if (IsWritableMemoryRange(objectAddress + 0x7AUL, 1))
                    WriteByte(objectAddress + 0x7AUL, 1);
            }
            else if (valueFieldOffset == 0x604)
            {
                var companionAddress = objectAddress + 0x600UL;
                if (IsWritableMemoryRange(companionAddress, 4))
                    WriteFloat(companionAddress, seconds);
            }

            return written;
        }

        private System.Threading.Thread _timeOfDayThread;
        private volatile bool _timeOfDayEnabled;
        private volatile int _timeOfDaySecondsBits;
        private ulong _timeOfDayGlobalAddress;
        private ulong _timeOfDayObjectCache;
        private readonly object _timeOfDayStateLock = new object();
        private ulong _timeOfDayScaleObject;
        private float _timeOfDayOriginalScale = 1F;
        private bool _timeOfDayScaleCaptured;

        private void ApplyTimeOfDayRuntimeHook(int value, bool enabled)
        {
            if (!enabled)
            {
                _timeOfDayEnabled = false;
                DisableTimeOfDayDescriptorHoldsIfPresent();
                StopTimeOfDayHold();
                RestoreTimeOfDayClockScale();
                _log("Time of Day OFF.");
                return;
            }

            var seconds = BitConverter.ToSingle(BitConverter.GetBytes(value), 0);
            if (!IsFiniteFloat(seconds))
                throw new InvalidOperationException("Time of Day value was not a valid number.");
            if (seconds < 0F) seconds = 0F;
            while (seconds >= 86400F) seconds -= 86400F;
            _timeOfDaySecondsBits = BitConverter.ToInt32(BitConverter.GetBytes(seconds), 0);
            DisableTimeOfDayDescriptorHoldsIfPresent();
            var s = (int)seconds;
            var label = (s / 3600).ToString("00", CultureInfo.InvariantCulture) + ":" + ((s % 3600) / 60).ToString("00", CultureInfo.InvariantCulture);

            if (_timeOfDayEnabled && _timeOfDayThread != null && _timeOfDayThread.IsAlive && _timeOfDayObjectCache > 0x10000UL)
            {
                PinTimeOfDayObject(_timeOfDayObjectCache, seconds);
                _log("Time of Day re-set to " + label + ".");
                return;
            }

            ulong obj;
            if (!TryResolveTimeOfDayObject(out obj))
                throw new InvalidOperationException("Could not locate the Time of Day clock in memory. Load into free-roam (out of menus/loading) and try again.");

            _timeOfDayObjectCache = obj;
            _timeOfDayEnabled = true;
            PinTimeOfDayObject(obj, seconds);
            EnsureTimeOfDayHold();

            _log("Time of Day ON: holding " + label + ".");
        }

        private void DisableTimeOfDayDescriptorHoldsIfPresent()
        {
            foreach (var descriptor in GetTimeOfDayRenderHookDescriptors())
            {
                try
                {
                    RuntimeDetour detour;
                    lock (_runtimePatchLock)
                    {
                        if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                            continue;
                    }
                    if (detour != null && detour.DetourAddress != 0)
                        WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                }
                catch
                {
                }
            }
        }

        private void EnsureTimeOfDayHold()
        {
            if (_timeOfDayThread != null && _timeOfDayThread.IsAlive)
                return;
            var thread = new System.Threading.Thread(TimeOfDayHoldLoop);
            thread.IsBackground = true;
            thread.Name = "LunaTimeOfDayHold";
            _timeOfDayThread = thread;
            thread.Start();
        }

        private void StopTimeOfDayHold()
        {
            _timeOfDayEnabled = false;
            var thread = _timeOfDayThread;
            _timeOfDayThread = null;
            if (thread != null)
            {
                try { thread.Join(200); }
                catch { }
            }
        }

        private void TimeOfDayHoldLoop()
        {
            while (_timeOfDayEnabled && IsAlive)
            {
                try
                {
                    var seconds = BitConverter.ToSingle(BitConverter.GetBytes(_timeOfDaySecondsBits), 0);
                    var obj = _timeOfDayObjectCache;
                    if (_timeOfDayGlobalAddress != 0)
                    {
                        var live = ReadUInt64(_timeOfDayGlobalAddress);
                        if (live > 0x10000UL && live < 0x00007FFFFFFFFFFFUL && IsReadableMemoryRange(live + 0x60UL, 12))
                        {
                            obj = live;
                            _timeOfDayObjectCache = live;
                        }
                    }
                    if (obj > 0x10000UL)
                    {
                        var current = ReadFloat(obj + 0x64UL);
                        var mirror = ReadFloat(obj + 0x60UL);
                        var scale = ReadFloat(obj + 0x68UL);
                        var objectChanged = obj != _timeOfDayScaleObject;
                        var drifted = !IsFiniteFloat(current) || !IsFiniteFloat(mirror) ||
                            Math.Abs(current - seconds) > 0.5F || Math.Abs(mirror - seconds) > 0.5F;
                        if (objectChanged || drifted || !IsFiniteFloat(scale) || Math.Abs(scale) > 0.0001F)
                            PinTimeOfDayObject(obj, seconds);
                    }
                }
                catch
                {
                }
                System.Threading.Thread.Sleep(50);
            }
        }

        private void PinTimeOfDayObject(ulong obj, float seconds)
        {
            if (obj <= 0x10000UL || !IsWritableMemoryRange(obj + 0x60UL, 12))
                return;

            lock (_timeOfDayStateLock)
            {
                if (_timeOfDayScaleObject != obj)
                {
                    RestoreTimeOfDayClockScaleLocked();
                    var originalScale = ReadFloat(obj + 0x68UL);
                    _timeOfDayOriginalScale = IsFiniteFloat(originalScale) && originalScale >= 0F && originalScale <= 20F
                        ? originalScale
                        : 1F;
                    _timeOfDayScaleObject = obj;
                    _timeOfDayScaleCaptured = true;
                }

                WriteTimeOfDayObject(obj, seconds);
                WriteFloat(obj + 0x68UL, 0F);
            }
        }

        private void RestoreTimeOfDayClockScale()
        {
            lock (_timeOfDayStateLock)
                RestoreTimeOfDayClockScaleLocked();
        }

        private void RestoreTimeOfDayClockScaleLocked()
        {
            if (_timeOfDayScaleCaptured && _timeOfDayScaleObject > 0x10000UL &&
                IsWritableMemoryRange(_timeOfDayScaleObject + 0x68UL, 4))
            {
                try { WriteFloat(_timeOfDayScaleObject + 0x68UL, _timeOfDayOriginalScale); }
                catch { }
            }
            _timeOfDayScaleCaptured = false;
            _timeOfDayScaleObject = 0;
            _timeOfDayOriginalScale = 1F;
        }

        private void WriteTimeOfDayObject(ulong obj, float seconds)
        {
            if (obj == 0)
                return;
            if (!IsWritableMemoryRange(obj + 0x60UL, 8))
                return;
            var sb = BitConverter.GetBytes(seconds);
            var pair = new byte[8];
            Buffer.BlockCopy(sb, 0, pair, 0, 4);
            Buffer.BlockCopy(sb, 0, pair, 4, 4);
            WriteBytes(obj + 0x60UL, pair);
        }

        private bool TryResolveTimeOfDayObject(out ulong obj)
        {
            obj = 0;
            if (!IsAlive || _mainBase == 0 || _mainSize <= 0)
                return false;

            if (_timeOfDayGlobalAddress != 0)
            {
                var cached = ReadUInt64(_timeOfDayGlobalAddress);
                if (IsTimeOfDayObject(cached))
                {
                    obj = cached;
                    return true;
                }
                _timeOfDayGlobalAddress = 0;
            }

            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            var regions = EnumerateReadableWritableRegions()
                .Where(r => r.BaseAddress < moduleEnd && r.BaseAddress + r.RegionSize > _mainBase && r.RegionSize <= 64UL * 1024UL * 1024UL)
                .OrderBy(r => r.BaseAddress)
                .ToList();

            var slots = new List<ulong>(64);
            var objects = new List<ulong>(64);
            var before = new List<float>(64);
            foreach (var region in regions)
            {
                var start = Math.Max(region.BaseAddress, _mainBase);
                var end = Math.Min(region.BaseAddress + region.RegionSize, moduleEnd);
                if (end <= start)
                    continue;
                var length = (int)Math.Min(end - start, 64UL * 1024UL * 1024UL);
                var data = ReadBytes(start, length);
                if (data.Length < 8)
                    continue;
                for (var off = 0; off + 8 <= data.Length; off += 8)
                {
                    var candidate = BitConverter.ToUInt64(data, off);
                    if (candidate <= 0x10000UL || candidate >= 0x00007FFFFFFFFFFFUL)
                        continue;
                    if (candidate >= _mainBase && candidate < moduleEnd)
                        continue;
                    if (!IsTimeOfDayObject(candidate))
                        continue;
                    slots.Add(start + (ulong)off);
                    objects.Add(candidate);
                    before.Add(ReadFloat(candidate + 0x64UL));
                    if (slots.Count >= 256)
                        break;
                }
                if (slots.Count >= 256)
                    break;
            }

            if (slots.Count == 0)
                return false;

            System.Threading.Thread.Sleep(160);
            for (var i = 0; i < slots.Count; i++)
            {
                var after = ReadFloat(objects[i] + 0x64UL);
                var delta = after - before[i];
                if (!IsFiniteFloat(after))
                    continue;
                if (delta > 0.0005F && delta < 600F)
                {
                    _timeOfDayGlobalAddress = slots[i];
                    obj = objects[i];
                    return true;
                }
            }
            return false;
        }

        private bool IsTimeOfDayObject(ulong obj)
        {
            if (obj <= 0x10000UL || obj >= 0x00007FFFFFFFFFFFUL)
                return false;
            var data = ReadBytes(obj + 0x60UL, 12);
            if (data.Length < 12)
                return false;
            var mirror = BitConverter.ToSingle(data, 0);
            var time = BitConverter.ToSingle(data, 4);
            var scale = BitConverter.ToSingle(data, 8);
            if (!IsFiniteFloat(mirror) || !IsFiniteFloat(time) || !IsFiniteFloat(scale))
                return false;
            if (time < 0F || time > 86400F || mirror < 0F || mirror > 86400F)
                return false;
            if (Math.Abs(time - mirror) > 180F)
                return false;
            if (scale < 0.5F || scale > 2F)
                return false;
            return true;
        }

        private void ApplyFovTablePatch(int value, bool enabled)
        {
            var degrees = BitConverter.ToSingle(BitConverter.GetBytes(value), 0);
            ApplyFovCameraTablePatch(true, degrees, degrees, degrees, degrees, degrees, degrees, enabled);
        }

        public void ApplyFovCameraTablePatch(
            bool controlAll,
            float allDegrees,
            float dashboardDegrees,
            float chaseDegrees,
            float farChaseDegrees,
            float hoodDegrees,
            float bumperDegrees,
            bool enabled)
        {
            lock (_fovTablePatchLock)
            {
                if (!enabled)
                {
                    RestoreFovTablePatches(true);
                    return;
                }

                EnsureCrcBypass();
                RestoreFovTablePatches(false);

                allDegrees = NormalizeFovPatchDegrees(allDegrees);
                dashboardDegrees = NormalizeFovPatchDegrees(dashboardDegrees);
                chaseDegrees = NormalizeFovPatchDegrees(chaseDegrees);
                farChaseDegrees = NormalizeFovPatchDegrees(farChaseDegrees);
                hoodDegrees = NormalizeFovPatchDegrees(hoodDegrees);
                bumperDegrees = NormalizeFovPatchDegrees(bumperDegrees);

                var targets = FindFovTableTargets();
                var applied = 0;
                foreach (var target in targets)
                {
                    var original = ReadBytes(target.Address, 4);
                    if (original.Length < 4)
                        continue;

                    var originalValue = BitConverter.ToSingle(original, 0);
                    if (float.IsNaN(originalValue) || float.IsInfinity(originalValue))
                        continue;

                    var degrees = controlAll ? allDegrees : GetFovDegreesForCamera(target.Camera, dashboardDegrees, chaseDegrees, farChaseDegrees, hoodDegrees, bumperDegrees);
                    var scale = degrees / DefaultFovDegrees;
                    var patchedValue = Math.Max(1F, Math.Min(360F, originalValue * scale));
                    WriteProtectedBytes(target.Address, BitConverter.GetBytes(patchedValue));
                    _fovTablePatches.Add(new MemoryPatch { Address = target.Address, Original = original });
                    applied++;
                }

                if (applied == 0)
                    throw new InvalidOperationException("FOV camera tables were found, but no writable FOV values were patched.");

                var summary = controlAll
                    ? "all cameras " + allDegrees.ToString("0.#", CultureInfo.InvariantCulture) + " degrees"
                    : "Dashboard " + dashboardDegrees.ToString("0.#", CultureInfo.InvariantCulture) +
                      ", Chase " + chaseDegrees.ToString("0.#", CultureInfo.InvariantCulture) +
                      ", Far Chase " + farChaseDegrees.ToString("0.#", CultureInfo.InvariantCulture) +
                      ", Hood " + hoodDegrees.ToString("0.#", CultureInfo.InvariantCulture) +
                      ", Bumper " + bumperDegrees.ToString("0.#", CultureInfo.InvariantCulture);
                _log("FOV Slider ON with " + summary + ". Camera table values patched: " + applied.ToString(CultureInfo.InvariantCulture) + ".");
            }
        }

        private static float NormalizeFovPatchDegrees(float degrees)
        {
            if (float.IsNaN(degrees) || float.IsInfinity(degrees))
                return DefaultFovDegrees;
            if (degrees < 1F)
                return 1F;
            if (degrees > 360F)
                return 360F;
            return degrees;
        }

        private static float GetFovDegreesForCamera(string camera, float dashboardDegrees, float chaseDegrees, float farChaseDegrees, float hoodDegrees, float bumperDegrees)
        {
            if (string.Equals(camera, "Dashboard", StringComparison.OrdinalIgnoreCase))
                return dashboardDegrees;
            if (string.Equals(camera, "Chase", StringComparison.OrdinalIgnoreCase))
                return chaseDegrees;
            if (string.Equals(camera, "Far Chase", StringComparison.OrdinalIgnoreCase))
                return farChaseDegrees;
            if (string.Equals(camera, "Hood", StringComparison.OrdinalIgnoreCase))
                return hoodDegrees;
            if (string.Equals(camera, "Bumper", StringComparison.OrdinalIgnoreCase))
                return bumperDegrees;
            return DefaultFovDegrees;
        }

        private void WriteDataOrProtectedBytes(ulong address, byte[] data)
        {
            if (IsWritableMemoryRange(address, data.Length))
            {
                WriteBytes(address, data);
                return;
            }

            WriteProtectedBytes(address, data);
        }

        private void RestoreFovTablePatches()
        {
            RestoreFovTablePatches(true);
        }

        private void RestoreFovTablePatches(bool log)
        {
            lock (_fovTablePatchLock)
            {
                var restored = 0;
                for (var i = _fovTablePatches.Count - 1; i >= 0; i--)
                {
                    try
                    {
                        WriteProtectedBytes(_fovTablePatches[i].Address, _fovTablePatches[i].Original);
                        restored++;
                    }
                    catch (Exception ex)
                    {
                        _log("Could not restore FOV value at 0x" + _fovTablePatches[i].Address.ToString("X") + ": " + ex.Message);
                    }
                }
                _fovTablePatches.Clear();
                if (log)
                    _log(restored > 0 ? "FOV Slider OFF. Restored " + restored.ToString(CultureInfo.InvariantCulture) + " camera table value(s)." : "FOV Slider is already OFF.");
            }
        }

        private List<FovTableTarget> FindFovTableTargets()
        {
            var module = ReadBytes(_mainBase, _mainSize);
            if (module.Length == 0)
                throw new InvalidOperationException("Could not read main module memory for FOV table scan.");

            var chaseMatches = Pattern.FindAll(module, Pattern.Parse("90 40 CD CC 8C 40 1F 85 2B 3F 00 00 00 40"), 4).ToList();
            var hoodDriverMatches = Pattern.FindAll(module, Pattern.Parse("CD CC 4C 3E 00 50 43 47 00 00 34 42 00 00 20"), 4).ToList();
            var bumperMatches = Pattern.FindAll(module, Pattern.Parse("00 CD CC 4C 3E ? ? ? 47 00 ? 54"), 4).ToList();
            if (chaseMatches.Count < 2 || hoodDriverMatches.Count < 2 || bumperMatches.Count < 1)
            {
                throw new InvalidOperationException("FOV table signatures did not match this FH6 build. Chase=" + chaseMatches.Count.ToString(CultureInfo.InvariantCulture) +
                    ", hood/driver=" + hoodDriverMatches.Count.ToString(CultureInfo.InvariantCulture) +
                    ", bumper=" + bumperMatches.Count.ToString(CultureInfo.InvariantCulture) + ".");
            }

            var targets = new List<FovTableTarget>();
            var seen = new HashSet<ulong>();
            var chase0 = _mainBase + (ulong)chaseMatches[0];
            var chase1 = _mainBase + (ulong)chaseMatches[chaseMatches.Count - 1];
            var hoodAnchor = _mainBase + (ulong)hoodDriverMatches[0];
            var dashboardAnchor = _mainBase + (ulong)hoodDriverMatches[hoodDriverMatches.Count - 1];
            var bumperAnchor = _mainBase + (ulong)bumperMatches[0];

            AddFovLimiterPair(targets, seen, "Chase", "Chase", chase0 - 10UL);
            AddFovLimiterPair(targets, seen, "Far Chase", "Far Chase", chase1 - 10UL);
            AddFovLimiterPair(targets, seen, "Dashboard", "Dashboard", dashboardAnchor - 0x24UL);
            AddFovLimiterPair(targets, seen, "Hood", "Hood", hoodAnchor - 0x24UL);
            AddFovLimiterPair(targets, seen, "Bumper", "Bumper", bumperAnchor - 0x23UL);

            if (targets.Count == 0)
                throw new InvalidOperationException("FOV table signatures matched, but no valid float targets were readable.");
            return targets;
        }

        public List<PhotoModeSettingRow> ScanPhotoModeSettings()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var baseAddress = ResolvePhotoModeModifierBase();
            var rows = new List<PhotoModeSettingRow>();

            lock (_photoModePatchLock)
            {
                _photoModeSettingCache.Clear();
                foreach (var definition in GetPhotoModeSettingDefinitions())
                {
                    var address = baseAddress + definition.Offset;
                    var row = new PhotoModeSettingRow
                    {
                        Key = definition.Key,
                        Name = definition.Name,
                        Address = address,
                        IsInteger = definition.IsInteger,
                        Description = definition.Description,
                        Found = IsReadableMemoryRange(address, 4) && IsWritableMemoryRange(address, 4),
                        Status = "Not Found"
                    };

                    if (row.Found)
                    {
                        if (definition.IsInteger)
                        {
                            var current = ReadInt32(address);
                            row.CurrentText = current.ToString(CultureInfo.InvariantCulture);
                            row.NewValueText = row.CurrentText;
                            row.DefaultText = row.CurrentText;
                        }
                        else
                        {
                            var current = ReadFloat(address);
                            row.CurrentText = FormatFloatInvariant(current);
                            row.NewValueText = row.CurrentText;
                            row.DefaultText = row.CurrentText;
                        }
                        row.Status = "Found";
                    }

                    rows.Add(row);
                    _photoModeSettingCache[row.Key] = row;
                }
            }

            _log("Photo Mode modifiers found at 0x" + baseAddress.ToString("X") + ".");
            return rows;
        }

        public string ApplyPhotoModeSettings(List<PhotoModeSettingInput> inputs)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (inputs == null || inputs.Count == 0)
                return "No Photo Mode rows selected.";

            if (_photoModeSettingCache.Count == 0)
                ScanPhotoModeSettings();

            var applied = 0;
            var skipped = 0;
            lock (_photoModePatchLock)
            {
                foreach (var input in inputs)
                {
                    PhotoModeSettingRow row;
                    if (!_photoModeSettingCache.TryGetValue(input.Key ?? string.Empty, out row) || row == null || !row.Found)
                    {
                        skipped++;
                        continue;
                    }

                    if (row.IsInteger)
                    {
                        int value;
                        if (!int.TryParse(input.ValueText, NumberStyles.Integer, CultureInfo.InvariantCulture, out value))
                            throw new InvalidOperationException(row.Name + " needs a whole number.");
                        WriteProtectedBytes(row.Address, BitConverter.GetBytes(value));
                    }
                    else
                    {
                        float value;
                        if (!float.TryParse(input.ValueText, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || !IsFiniteFloat(value))
                            throw new InvalidOperationException(row.Name + " needs a finite number.");
                        WriteProtectedBytes(row.Address, BitConverter.GetBytes(value));
                    }

                    applied++;
                }
            }

            return "Photo Mode applied " + applied.ToString(CultureInfo.InvariantCulture) +
                " row(s)" + (skipped > 0 ? ", skipped " + skipped.ToString(CultureInfo.InvariantCulture) : string.Empty) + ".";
        }

        public string RestorePhotoModeSettings()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (_photoModeSettingCache.Count == 0)
                return "Scan Photo Mode first.";

            var restored = 0;
            lock (_photoModePatchLock)
            {
                foreach (var row in _photoModeSettingCache.Values)
                {
                    if (row == null || !row.Found)
                        continue;

                    if (row.IsInteger)
                    {
                        int value;
                        if (!int.TryParse(row.DefaultText, NumberStyles.Integer, CultureInfo.InvariantCulture, out value))
                            continue;
                        WriteProtectedBytes(row.Address, BitConverter.GetBytes(value));
                    }
                    else
                    {
                        float value;
                        if (!float.TryParse(row.DefaultText, NumberStyles.Float, CultureInfo.InvariantCulture, out value) || !IsFiniteFloat(value))
                            continue;
                        WriteProtectedBytes(row.Address, BitConverter.GetBytes(value));
                    }

                    restored++;
                }
            }

            return "Photo Mode restored " + restored.ToString(CultureInfo.InvariantCulture) + " modifier(s).";
        }

        public void ApplyPhotoModeNoHeightLimit(bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var descriptor = GetPhotoModeHeightControlDescriptor();
            var detour = EnsureRuntimeProfileHook(descriptor);
            _photoModeCameraDetour = detour;
            _photoModeCameraDescriptor = descriptor;
            _photoModeHeightControlEnabled = enabled;
            if (!enabled)
            {
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0F);
                _photoModeHeightOffset = 0F;
                StopPhotoModeControlsIfIdle();
                _log("Photo Mode Height OFF.");
                return;
            }

            WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0F);
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
            StartPhotoModeControls();
            _log("Photo Mode Height ON. Hold Shift to move up and Ctrl to move down.");
        }

        public void ApplyPhotoModeIncreasedZoom(bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var descriptor = GetPhotoModeZoomControlDescriptor();
            var detour = EnsureRuntimeProfileHook(descriptor);
            _photoModeCameraDetour = detour;
            _photoModeCameraDescriptor = descriptor;
            _photoModeZoomControlEnabled = enabled;
            if (!enabled)
            {
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0F);
                Interlocked.Exchange(ref _photoModePendingWheelDelta, 0);
                _photoModeZoomOffset = 0F;
                StopPhotoModeControlsIfIdle();
                _log("Photo Mode Zoom OFF.");
                return;
            }

            WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, _photoModeZoomOffset);
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
            StartPhotoModeControls();
            _log("Photo Mode Zoom ON. Use the mouse wheel while FH6 is focused.");
        }

        public void ResetPhotoModeViewOffsets()
        {
            _photoModeZoomOffset = 0F;
            _photoModeHeightOffset = 0F;
            Interlocked.Exchange(ref _photoModePendingWheelDelta, 0);

            RuntimeDetour detour;
            var zoomDescriptor = GetPhotoModeZoomControlDescriptor();
            if (_runtimeProfileHooks.TryGetValue(zoomDescriptor.Key, out detour) && detour != null && detour.DetourAddress != 0)
                WriteFloat(detour.DetourAddress + (ulong)zoomDescriptor.ValueOffset, 0F);

            var heightDescriptor = GetPhotoModeHeightControlDescriptor();
            if (_runtimeProfileHooks.TryGetValue(heightDescriptor.Key, out detour) && detour != null && detour.DetourAddress != 0)
                WriteFloat(detour.DetourAddress + (ulong)heightDescriptor.ValueOffset, 0F);

            _log("Photo Mode view offsets reset.");
        }

        private void StartPhotoModeControls()
        {
            if (_photoModeControlTimer == null)
                _photoModeControlTimer = new System.Threading.Timer(PhotoModeControlTick, null, 0, 16);
            else
                _photoModeControlTimer.Change(0, 16);

            if (_photoModeZoomControlEnabled && _photoModeMouseHook == IntPtr.Zero)
            {
                _photoModeMouseProc = PhotoModeMouseHookCallback;
                _photoModeMouseHook = Native.SetWindowsHookEx(Native.WhMouseLl, _photoModeMouseProc, Native.GetModuleHandle(null), 0);
                if (_photoModeMouseHook == IntPtr.Zero)
                    _log("Photo Mode Zoom mouse wheel hook could not start. Use the modifier table or retry as administrator.");
            }
        }

        private void StopPhotoModeControlsIfIdle()
        {
            if (_photoModeZoomControlEnabled || _photoModeHeightControlEnabled)
                return;

            StopPhotoModeControls();
        }

        private void StopPhotoModeControls()
        {
            var timer = _photoModeControlTimer;
            _photoModeControlTimer = null;
            if (timer != null)
                timer.Dispose();

            if (_photoModeMouseHook != IntPtr.Zero)
            {
                Native.UnhookWindowsHookEx(_photoModeMouseHook);
                _photoModeMouseHook = IntPtr.Zero;
            }

            _photoModeMouseProc = null;
            _photoModeControlRunning = 0;
            _photoModeZoomControlEnabled = false;
            _photoModeHeightControlEnabled = false;
            _photoModeZoomOffset = 0F;
            _photoModeHeightOffset = 0F;
            Interlocked.Exchange(ref _photoModePendingWheelDelta, 0);
        }

        private void PhotoModeControlTick(object state)
        {
            if (Interlocked.Exchange(ref _photoModeControlRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive)
                    return;

                RuntimeDetour detour;
                if (_photoModeZoomControlEnabled)
                {
                    var descriptor = GetPhotoModeZoomControlDescriptor();
                    if (_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour) && detour != null && detour.DetourAddress != 0)
                    {
                        var wheel = Interlocked.Exchange(ref _photoModePendingWheelDelta, 0);
                        if (wheel != 0)
                        {
                            var notches = wheel / 120F;
                            _photoModeZoomOffset = ClampFloat(_photoModeZoomOffset + (notches * 0.06F), -4F, 4F);
                        }

                        WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, _photoModeZoomOffset);
                        WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
                    }
                }

                if (_photoModeHeightControlEnabled)
                {
                    var descriptor = GetPhotoModeHeightControlDescriptor();
                    if (_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour) && detour != null && detour.DetourAddress != 0)
                    {
                        var activeWindow = IsForzaForegroundForPhotoMode();
                        var up = activeWindow && (IsKeyDown((int)Keys.ShiftKey) || IsKeyDown((int)Keys.LShiftKey) || IsKeyDown((int)Keys.RShiftKey));
                        var down = activeWindow && (IsKeyDown((int)Keys.ControlKey) || IsKeyDown((int)Keys.LControlKey) || IsKeyDown((int)Keys.RControlKey));
                        if (up != down)
                        {
                            var delta = up ? 0.08F : -0.08F;
                            _photoModeHeightOffset = ClampFloat(_photoModeHeightOffset + delta, -80F, 80F);
                        }
                        WriteFloat(detour.DetourAddress + (ulong)descriptor.ValueOffset, _photoModeHeightOffset);
                        WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
                    }
                }
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Photo Mode controls", ex);
            }
            finally
            {
                Interlocked.Exchange(ref _photoModeControlRunning, 0);
            }
        }

        private IntPtr PhotoModeMouseHookCallback(int nCode, IntPtr wParam, IntPtr lParam)
        {
            if (nCode >= 0 && _photoModeZoomControlEnabled && wParam.ToInt32() == Native.WmMouseWheel && IsForzaForegroundForPhotoMode())
            {
                try
                {
                    var info = (Native.Msllhookstruct)Marshal.PtrToStructure(lParam, typeof(Native.Msllhookstruct));
                    var delta = unchecked((short)((info.mouseData >> 16) & 0xFFFF));
                    if (delta != 0)
                        Interlocked.Add(ref _photoModePendingWheelDelta, delta);
                }
                catch
                {
                }
            }

            return Native.CallNextHookEx(_photoModeMouseHook, nCode, wParam, lParam);
        }

        private bool IsForzaForegroundForPhotoMode()
        {
            try
            {
                int foregroundPid;
                Native.GetWindowThreadProcessId(Native.GetForegroundWindow(), out foregroundPid);
                return foregroundPid == _process.Id;
            }
            catch
            {
                return false;
            }
        }

        private static float ClampFloat(float value, float min, float max)
        {
            if (value < min)
                return min;
            if (value > max)
                return max;
            return value;
        }

        internal const int CameraEffectCount = 29;
        internal const int CamFxAperture = 2;
        internal const int CamFxSaturation = 3;
        internal const int CamFxExposure = 4;
        internal const int CamFxBrightness = 5;
        internal const int CamFxContrast = 6;
        internal const int CamFxSepia = 7;
        internal const int CamFxBlur = 8;
        internal const int CamFxVignettePower = 14;
        internal const int CamFxMotionBlur = 27;

        private readonly object _camFxLock = new object();
        private List<ulong> _camFxArrays = new List<ulong>();
        private readonly Dictionary<int, float> _camFxHeld = new Dictionary<int, float>();
        private System.Threading.Timer _camFxTimer;
        private int _camFxTimerRunning;

        private static readonly Dictionary<int, float> CameraEffectDefaults = new Dictionary<int, float>
        {
            { CamFxAperture, 1600f }, { CamFxSaturation, 1f }, { CamFxExposure, 0f }, { CamFxBrightness, 0f },
            { CamFxContrast, 1f }, { CamFxSepia, 0f }, { CamFxBlur, 0f }, { CamFxVignettePower, 1f }, { CamFxMotionBlur, 0f }
        };

        public int ScanCameraEffectArrays()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            var found = FindCameraEffectArrays(512);
            lock (_camFxLock) { _camFxArrays = found; }
            _log("Camera Effects: locked onto " + found.Count.ToString(CultureInfo.InvariantCulture) + " camera-effect block(s).");
            return found.Count;
        }

        public int EnsureCameraEffectScan()
        {
            lock (_camFxLock) { if (_camFxArrays.Count > 0) return _camFxArrays.Count; }
            return ScanCameraEffectArrays();
        }

        private List<ulong> FindCameraEffectArrays(int max)
        {
            var result = new List<ulong>();
            var watch = Stopwatch.StartNew();
            var infoSize = (UIntPtr)Marshal.SizeOf(typeof(Native.MemoryBasicInformation64));
            var address = 0UL;
            while (address < 0x00007FFFFFFFFFFFUL)
            {
                if (result.Count >= max || watch.Elapsed.TotalSeconds > 10)
                    break;
                Native.MemoryBasicInformation64 mbi;
                if (Native.VirtualQueryEx(_handle, new UIntPtr(address), out mbi, infoSize) == UIntPtr.Zero)
                    break;
                var next = mbi.BaseAddress + mbi.RegionSize;
                if (next <= address)
                    next = address + 0x1000UL;

                if (mbi.State == Native.MemCommit
                    && mbi.Type == 0x20000U
                    && (mbi.Protect & 0xFFU) == Native.PageReadWrite
                    && mbi.RegionSize >= (ulong)(CameraEffectCount * 4)
                    && mbi.RegionSize <= 0x400000UL)
                {
                    byte[] data = null;
                    try { data = ReadBytes(mbi.BaseAddress, (int)mbi.RegionSize); }
                    catch { data = null; }
                    if (data != null && data.Length >= CameraEffectCount * 4)
                    {
                        var limit = data.Length - CameraEffectCount * 4;
                        for (var off = 0; off <= limit; off += 4)
                        {
                            if (BitConverter.ToInt32(data, off + 1 * 4) != 0x45200000) continue;
                            if (BitConverter.ToInt32(data, off + 2 * 4) != 0x44C80000) continue;
                            if (!IsCameraEffectSignature(data, off)) continue;
                            result.Add(mbi.BaseAddress + (ulong)off);
                            if (result.Count >= max) break;
                            off += CameraEffectCount * 4;
                        }
                    }
                }
                address = next;
            }
            return result;
        }

        private static bool IsCameraEffectSignature(byte[] data, int off)
        {
            if (BitConverter.ToInt32(data, off + 3 * 4) != 0x3F800000) return false;
            if (BitConverter.ToInt32(data, off + 6 * 4) != 0x3F800000) return false;
            if (BitConverter.ToInt32(data, off + 4 * 4) != 0) return false;
            if (BitConverter.ToInt32(data, off + 5 * 4) != 0) return false;
            if (BitConverter.ToInt32(data, off + 7 * 4) != 0) return false;
            if (BitConverter.ToInt32(data, off + 8 * 4) != 0) return false;
            for (var i = 0; i < CameraEffectCount; i++)
            {
                var v = BitConverter.ToSingle(data, off + i * 4);
                if (float.IsNaN(v) || float.IsInfinity(v) || v < -1000f || v > 10000f) return false;
            }
            for (var i = 15; i <= 26; i++)
            {
                var v = BitConverter.ToSingle(data, off + i * 4);
                if (v < 0f || v > 1.5f) return false;
            }
            return true;
        }

        public void SetCameraEffect(int index, bool active, float value)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            lock (_camFxLock)
            {
                if (active) _camFxHeld[index] = value;
                else _camFxHeld.Remove(index);
            }
            if (active)
            {
                WriteCameraEffect(index, value);
                EnsureCameraEffectTimer();
            }
            else
            {
                float def;
                WriteCameraEffect(index, CameraEffectDefaults.TryGetValue(index, out def) ? def : 0f);
                StopCameraEffectTimerIfIdle();
            }
        }

        private void WriteCameraEffect(int index, float value)
        {
            List<ulong> arrays;
            lock (_camFxLock) { arrays = new List<ulong>(_camFxArrays); }
            foreach (var a in arrays)
            {
                try { WriteFloat(a + (ulong)(index * 4), value); }
                catch { }
            }
        }

        private void EnsureCameraEffectTimer()
        {
            if (_camFxTimer == null)
                _camFxTimer = new System.Threading.Timer(CameraEffectHoldTick, null, 0, 33);
            else
                _camFxTimer.Change(0, 33);
        }

        private void StopCameraEffectTimerIfIdle()
        {
            lock (_camFxLock) { if (_camFxHeld.Count > 0) return; }
            var timer = _camFxTimer;
            _camFxTimer = null;
            if (timer != null)
                timer.Dispose();
        }

        private void CameraEffectHoldTick(object state)
        {
            if (Interlocked.Exchange(ref _camFxTimerRunning, 1) == 1)
                return;
            try
            {
                if (!IsAlive)
                    return;
                KeyValuePair<int, float>[] held;
                ulong[] arrays;
                lock (_camFxLock)
                {
                    if (_camFxHeld.Count == 0 || _camFxArrays.Count == 0)
                        return;
                    held = new List<KeyValuePair<int, float>>(_camFxHeld).ToArray();
                    arrays = _camFxArrays.ToArray();
                }
                foreach (var a in arrays)
                    foreach (var kv in held)
                    {
                        try { WriteFloat(a + (ulong)(kv.Key * 4), kv.Value); }
                        catch { }
                    }
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Camera Effects", ex);
            }
            finally
            {
                Interlocked.Exchange(ref _camFxTimerRunning, 0);
            }
        }

        public void ResetCameraEffects()
        {
            int[] keys;
            lock (_camFxLock) { keys = new List<int>(_camFxHeld.Keys).ToArray(); _camFxHeld.Clear(); }
            foreach (var idx in keys)
            {
                float def;
                WriteCameraEffect(idx, CameraEffectDefaults.TryGetValue(idx, out def) ? def : 0f);
            }
            StopCameraEffectTimerIfIdle();
            _log("Camera Effects reset to default.");
        }

        private void StopCameraEffectHold()
        {
            lock (_camFxLock) { _camFxHeld.Clear(); _camFxArrays = new List<ulong>(); }
            var timer = _camFxTimer;
            _camFxTimer = null;
            if (timer != null)
                timer.Dispose();
        }

        private ulong ResolvePhotoModeModifierBase()
        {
            if (_photoModeModifierBase != 0 && IsReadableMemoryRange(_photoModeModifierBase, 0x50))
                return _photoModeModifierBase;

            var module = ReadBytes(_mainBase, _mainSize);
            if (module.Length == 0)
                throw new InvalidOperationException("Could not read main module for Photo Mode scan.");

            var matches = Pattern.FindAll(module, Pattern.Parse("3B 1D ? ? ? ? 0F 4E"), 4).ToList();
            if (matches.Count != 1)
                throw new InvalidOperationException("Photo Mode modifier signature expected 1 match, found " + matches.Count.ToString(CultureInfo.InvariantCulture) + ".");

            var matchAddress = _mainBase + (ulong)matches[0];
            var rel = BitConverter.ToInt32(module, matches[0] + 2);
            var baseAddress = (ulong)((long)matchAddress + 6 + rel);
            if (!IsReadableMemoryRange(baseAddress, 0x50))
                throw new InvalidOperationException("Photo Mode modifier table resolved to unreadable memory.");

            _photoModeModifierBase = baseAddress;
            return baseAddress;
        }

        private void ApplyPhotoModeHookPatch(string key, string name, string signature, int addressAdjustment, byte[] expectedPrefix, byte[] enabledBytes, bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            lock (_photoModePatchLock)
            {
                MemoryPatch existing;
                if (!enabled)
                {
                    if (_photoModeHookPatches.TryGetValue(key, out existing))
                    {
                        WriteProtectedBytes(existing.Address, existing.Original);
                        _photoModeHookPatches.Remove(key);
                    }
                    _log(name + " OFF.");
                    return;
                }

                if (_photoModeHookPatches.ContainsKey(key))
                {
                    _log(name + " already ON.");
                    return;
                }

                var module = ReadBytes(_mainBase, _mainSize);
                if (module.Length == 0)
                    throw new InvalidOperationException("Could not read main module for " + name + ".");

                var matches = Pattern.FindAll(module, Pattern.Parse(signature), 8).ToList();
                if (matches.Count != 1)
                    throw new InvalidOperationException(name + " signature is not validated in this FH6 build. Found " + matches.Count.ToString(CultureInfo.InvariantCulture) + " match(es).");

                var address = (ulong)((long)(_mainBase + (ulong)matches[0]) + addressAdjustment);
                var length = Math.Max(expectedPrefix.Length, enabledBytes.Length);
                var original = ReadBytes(address, length);
                if (original.Length < length)
                    throw new InvalidOperationException(name + " target bytes could not be read.");
                if (!BytesStartWith(original, expectedPrefix))
                    throw new InvalidOperationException(name + " target bytes did not match FH6 validation. Found: " + FormatBytes(original));

                var patch = new byte[length];
                Buffer.BlockCopy(original, 0, patch, 0, original.Length);
                Buffer.BlockCopy(enabledBytes, 0, patch, 0, enabledBytes.Length);
                WriteProtectedBytes(address, patch);
                _photoModeHookPatches[key] = new MemoryPatch { Address = address, Original = original };
                _log(name + " ON at 0x" + address.ToString("X") + ".");
            }
        }

        private void RestorePhotoModeHookPatches()
        {
            lock (_photoModePatchLock)
            {
                foreach (var patch in _photoModeHookPatches.Values.ToList())
                {
                    try
                    {
                        WriteProtectedBytes(patch.Address, patch.Original);
                    }
                    catch (Exception ex)
                    {
                        _log("Could not restore Photo Mode patch at 0x" + patch.Address.ToString("X") + ": " + ex.Message);
                    }
                }
                _photoModeHookPatches.Clear();
            }
        }

        private static PhotoModeSettingDefinition[] GetPhotoModeSettingDefinitions()
        {
            return new[]
            {
                new PhotoModeSettingDefinition("samples", "Samples", 0x00, true, "Controls the Photo Mode sample count used for rendering."),
                new PhotoModeSettingDefinition("sample_budget", "Sample Budget", 0x04, true, "Controls the larger live sample budget used by Photo Mode rendering."),
                new PhotoModeSettingDefinition("sample_limit", "Sample Limit", 0x08, true, "Upper clamp for Photo Mode samples."),
                new PhotoModeSettingDefinition("samples_multiplier", "Samples Multiplier", 0x0C, false, "Scales the Photo Mode sample count."),
                new PhotoModeSettingDefinition("preview_multiplier", "Preview Multiplier", 0x10, false, "Scales one live Photo Mode preview pass."),
                new PhotoModeSettingDefinition("render_blend_bias", "Render Blend Bias", 0x14, false, "Adjusts a live Photo Mode render blend value used by the current FH6 camera routine."),
                new PhotoModeSettingDefinition("focus_offset", "Focus Offset", 0x18, false, "Adjusts a live focus/distance offset in the FH6 Photo Mode table."),
                new PhotoModeSettingDefinition("focus_transition", "Focus Transition", 0x1C, false, "Controls a live Photo Mode focus transition/clamp value."),
                new PhotoModeSettingDefinition("aperture_scale", "Aperture Scale", 0x20, false, "Controls depth-of-field aperture strength."),
                new PhotoModeSettingDefinition("blur_balance_a", "Blur Balance A", 0x24, false, "Adjusts the first live blur balance value."),
                new PhotoModeSettingDefinition("blur_balance_b", "Blur Balance B", 0x28, false, "Adjusts the second live blur balance value."),
                new PhotoModeSettingDefinition("focus_strength", "Focus Strength", 0x2C, false, "Scales the live Photo Mode focus strength."),
                new PhotoModeSettingDefinition("car_in_focus", "Car In Focus", 0x30, false, "Controls how strongly Photo Mode keeps the car in focus."),
                new PhotoModeSettingDefinition("focus_blend", "Focus Blend", 0x34, false, "Controls a live focus blending value."),
                new PhotoModeSettingDefinition("time_slice", "Time Slice", 0x38, false, "Controls Photo Mode time slicing / temporal blend."),
                new PhotoModeSettingDefinition("time_slice_count", "Time Slice Count", 0x3C, false, "Controls a live time-slice count/scale value."),
                new PhotoModeSettingDefinition("camera_blend_min", "Camera Blend Min", 0x40, false, "Adjusts a live lower camera blend value."),
                new PhotoModeSettingDefinition("camera_blend_a", "Camera Blend A", 0x44, false, "Adjusts the first live camera blend value."),
                new PhotoModeSettingDefinition("camera_blend_b", "Camera Blend B", 0x48, false, "Adjusts the second live camera blend value."),
                new PhotoModeSettingDefinition("camera_blend_scale", "Camera Blend Scale", 0x4C, false, "Scales a live Photo Mode camera blend value.")
            };
        }

        private void AddFovLimiterPair(List<FovTableTarget> targets, HashSet<ulong> seen, string name, string camera, ulong minAddress)
        {
            AddFovTableTarget(targets, seen, name + " Min", camera, minAddress);
            AddFovTableTarget(targets, seen, name + " Max", camera, minAddress + 4UL);
        }

        private void AddFovTableTarget(List<FovTableTarget> targets, HashSet<ulong> seen, string name, string camera, ulong address)
        {
            if (seen.Contains(address))
                return;
            if (!IsReadableMemoryRange(address, 4))
                return;

            var value = ReadFloat(address);
            if (float.IsNaN(value) || float.IsInfinity(value) || value < 5F || value > 130F)
                return;

            seen.Add(address);
            targets.Add(new FovTableTarget { Name = name, Camera = camera, Address = address });
        }

        private static string GetRuntimeFeatureName(RuntimeProfileFeature feature)
        {
            if (feature == RuntimeProfileFeature.TimeOfDay)
                return "Time of Day";
            if (feature == RuntimeProfileFeature.SpeedZoneSpeed)
                return "Speed Zone Multiplier";
            if (feature == RuntimeProfileFeature.FovSlider)
                return "FOV Slider";
            if (feature == RuntimeProfileFeature.FreezeAI)
                return "Freeze AI";
            if (feature == RuntimeProfileFeature.NoClip)
                return "No Clip";
            if (feature == RuntimeProfileFeature.SuperStrength)
                return "Super Strength";
            if (feature == RuntimeProfileFeature.PhaseDash)
                return "Phase Dash";
            if (feature == RuntimeProfileFeature.FastSlowTime)
                return "Fast/Slow Time";
            return feature.ToString();
        }

        private void EnsureValueEncryptionBypass()
        {
            lock (_valueEncryptionPatchLock)
            {
                if (_valueEncryptionPatchAddress != 0)
                    return;

                EnsureCrcBypass();

                var module = ReadBytes(_mainBase, _mainSize);
                if (module.Length == 0)
                    throw new InvalidOperationException("Could not read main module memory for Value Encryption bypass scan.");

                const string signature = "48 8B ? 48 89 ? ? 48 89 ? ? 48 89 ? ? 55 41 ? 41 ? 48 8D ? ? 48 81 EC ? ? ? ? 48 8B ? ? ? ? ? 48 33 ? 48 89 ? ? 4C 8B ? 48 89";
                var parsed = Pattern.Parse(signature);
                var matches = Pattern.FindAll(module, parsed, 3).ToList();
                if (matches.Count == 0)
                    throw new InvalidOperationException("Value Encryption bypass signature was not found.");
                if (matches.Count > 1)
                    throw new InvalidOperationException("Value Encryption bypass signature was not unique.");

                var address = _mainBase + (ulong)matches[0];
                var current = ReadBytes(address, 3);
                if (current.Length < 3)
                    throw new InvalidOperationException("Could not read Value Encryption bytes.");

                _valueEncryptionPatchAddress = address;
                if (current[0] == 0xC3)
                {
                    _valueEncryptionPatchOriginal = null;
                    _valueEncryptionPatchOwned = false;
                    _log("XP Value save bypass is already active from another tool.");
                    return;
                }

                _valueEncryptionPatchOriginal = current;
                _valueEncryptionPatchOwned = true;
                WriteProtectedBytes(address, BuildValueEncryptionBypassPatch(_valueEncryptionPatchOriginal.Length));
                _log("XP Value save bypass ON.");
            }
        }

        private void RestoreValueEncryptionBypass()
        {
            lock (_valueEncryptionPatchLock)
            {
                if (_valueEncryptionPatchAddress == 0)
                    return;

                if (_valueEncryptionPatchOwned && _valueEncryptionPatchOriginal != null && _valueEncryptionPatchOriginal.Length > 0)
                {
                    try
                    {
                        WriteProtectedBytes(_valueEncryptionPatchAddress, _valueEncryptionPatchOriginal);
                        _log("XP Value save bypass OFF.");
                    }
                    catch (Exception ex)
                    {
                        _log("Could not restore XP Value save bypass: " + ex.Message);
                    }
                }

                _valueEncryptionPatchAddress = 0;
                _valueEncryptionPatchOriginal = null;
                _valueEncryptionPatchOwned = false;
            }
        }

        private static byte[] BuildValueEncryptionBypassPatch(int length)
        {
            var patch = new byte[Math.Max(1, length)];
            patch[0] = 0xC3;
            for (var i = 1; i < patch.Length; i++)
                patch[i] = 0x90;
            return patch;
        }

        private void RestoreValueEncryptionBypassForCleanWindow()
        {
            lock (_valueEncryptionPatchLock)
            {
                if (_valueEncryptionPatchAddress == 0 || !_valueEncryptionPatchOwned || _valueEncryptionPatchOriginal == null || _valueEncryptionPatchOriginal.Length == 0)
                    return;
                WriteProtectedBytes(_valueEncryptionPatchAddress, _valueEncryptionPatchOriginal);
            }
        }

        private void ReapplyValueEncryptionBypassForCleanWindow()
        {
            lock (_valueEncryptionPatchLock)
            {
                if (_valueEncryptionPatchAddress == 0 || !_valueEncryptionPatchOwned || _valueEncryptionPatchOriginal == null || _valueEncryptionPatchOriginal.Length == 0)
                    return;
                WriteProtectedBytes(_valueEncryptionPatchAddress, BuildValueEncryptionBypassPatch(_valueEncryptionPatchOriginal.Length));
            }
        }

