        public void VerifyRuntimeFeatureHook(RuntimeProfileFeature feature)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (_mainBase == 0 || _mainSize <= 0)
                throw new InvalidOperationException("Main module was not captured during attach.");

            if (feature == RuntimeProfileFeature.SuperStrength)
            {
                VerifyRuntimeHookDescriptor(GetVehicleControlDescriptor(RuntimeProfileFeature.Jump), "Super Strength vehicle lane");
                VerifyRuntimeHookDescriptor(GetFlyCameraOffsetCaptureDescriptor(), "Super Strength camera lane");
                return;
            }

            if (feature == RuntimeProfileFeature.PhaseDash)
            {
                VerifyRuntimeHookDescriptor(GetVehicleControlDescriptor(RuntimeProfileFeature.Jump), "Phase Dash vehicle lane");
                return;
            }

            if (feature == RuntimeProfileFeature.Rewind)
            {
                VerifyRuntimeHookDescriptor(GetVehicleControlDescriptor(RuntimeProfileFeature.Jump), "Rewind vehicle lane");
                return;
            }

            if (feature == RuntimeProfileFeature.GrapplingHook)
            {
                VerifyRuntimeHookDescriptor(GetVehicleControlDescriptor(RuntimeProfileFeature.Jump), "Grappling Hook vehicle lane");
                VerifyRuntimeHookDescriptor(GetFlyCameraOffsetCaptureDescriptor(), "Grappling Hook camera lane");
                return;
            }

            var descriptor = GetProfileHookDescriptor(feature);
            VerifyRuntimeHookDescriptor(descriptor, descriptor.Name);
        }

        private void VerifyRuntimeHookDescriptor(RuntimeProfileHookDescriptor descriptor, string label)
        {
            lock (_runtimePatchLock)
            {
                RuntimeDetour existing;
                if (_runtimeProfileHooks.TryGetValue(descriptor.Key, out existing) && existing != null && existing.DetourAddress != 0)
                {
                    _log(label + " hook is already installed at 0x" + existing.Address.ToString("X") + ", detour=0x" + existing.DetourAddress.ToString("X") + ".");
                    return;
                }
            }

            var module = ReadBytes(_mainBase, _mainSize);
            if (module.Length == 0)
                throw new InvalidOperationException("Could not read main module memory for runtime hook scan.");

            ulong hookAddress;
            byte[] current;
            FindProfileHookTarget(module, descriptor, out hookAddress, out current);
            _log(label + " hook verified at 0x" + hookAddress.ToString("X") + ". Bytes: " + FormatBytes(current) + ".");
        }

        public void VerifyVehicleControlRuntimeHook()
        {
            VerifyRuntimeFeatureHook(RuntimeProfileFeature.Acceleration);
        }

        private void ApplyGravityRuntimeHook(int encodedValue, bool enabled)
        {
            var gravityDescriptor = GetGravityDescriptor();

            if (!enabled)
            {
                DisableRuntimeHookLaneIfPresent(gravityDescriptor);
                DisableRuntimeHookLaneIfPresent(GetVehicleControlDescriptor(RuntimeProfileFeature.Gravity));
                _log("Gravity runtime hook OFF.");
                return;
            }

            var requestedScale = BitConverter.ToSingle(BitConverter.GetBytes(encodedValue), 0);
            if (float.IsNaN(requestedScale) || float.IsInfinity(requestedScale))
                throw new InvalidOperationException("Gravity value is not valid.");

            var physicsScale = GetStableGravityPhysicsScale(requestedScale);
            var vehicleForce = GetStableGravityVehicleForce(requestedScale);

            var gravityDetour = EnsureRuntimeProfileHook(gravityDescriptor);
            WriteByte(gravityDetour.DetourAddress + (ulong)gravityDescriptor.ToggleOffset, 1);
            WriteInt32(gravityDetour.DetourAddress + (ulong)gravityDescriptor.ValueOffset, BitConverter.ToInt32(BitConverter.GetBytes(physicsScale), 0));

            var vehicleDescriptor = GetVehicleControlDescriptor(RuntimeProfileFeature.Gravity);
            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
            WriteInt32(vehicleDetour.DetourAddress + (ulong)vehicleDescriptor.ValueOffset, BitConverter.ToInt32(BitConverter.GetBytes(vehicleForce), 0));
            WriteByte(vehicleDetour.DetourAddress + (ulong)vehicleDescriptor.ToggleOffset, Math.Abs(vehicleForce) > 0.0001F ? (byte)1 : (byte)0);

            _log("Gravity runtime hook enabled. requested=" + FormatFloatInvariant(requestedScale * 100F) + "%, physics=x" + FormatFloatInvariant(physicsScale) + ", vehicleForce=" + FormatFloatInvariant(vehicleForce) + ".");
        }

        private void DisableRuntimeHookLaneIfPresent(RuntimeProfileHookDescriptor descriptor)
        {
            RuntimeDetour detour;
            lock (_runtimePatchLock)
            {
                if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                    return;
            }

            if (detour == null || detour.DetourAddress == 0 || _handle == IntPtr.Zero)
                return;

            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
            if (descriptor.ValueOffset >= 0)
                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0);
        }

        private static float GetStableGravityPhysicsScale(float requestedScale)
        {
            if (requestedScale <= 0F)
                return 0F;
            if (requestedScale <= 1F)
                return requestedScale;
            return Math.Min(requestedScale, 2.0F);
        }

        private static float GetStableGravityVehicleForce(float requestedScale)
        {
            if (requestedScale > 1F)
                return Math.Min((requestedScale - 1F) * 0.32F, 2.5F);
            if (requestedScale < 0F)
                return Math.Max(requestedScale * 0.15F, -1.5F);
            return 0F;
        }

        public void SetJumpRuntimeHook(bool enabled, int virtualKey, float boost)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var descriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);

            if (!enabled)
            {
                StopJumpGuard();
                _log("Jump runtime hook OFF.");
                return;
            }

            if (virtualKey <= 0)
                throw new InvalidOperationException("Jump keybind is not valid.");
            if (float.IsNaN(boost) || float.IsInfinity(boost) || boost <= 0)
                throw new InvalidOperationException("Jump boost must be a positive number.");

            var detour = EnsureRuntimeProfileHook(descriptor);
            StartJumpGuard(detour, descriptor, virtualKey, boost);
            _log("Jump armed at detour 0x" + detour.DetourAddress.ToString("X") + ". Tap for the old hop height, or hold the selected key for repeated controlled hops.");
        }

        private static float NormalizeBoostForce(float requestedForce)
        {
            if (requestedForce <= DefaultBoostForce)
                return requestedForce;

            var softened = DefaultBoostForce + ((requestedForce - DefaultBoostForce) * BoostInputSoftScale);
            if (softened > MaxBoostRawForce)
                return MaxBoostRawForce;
            return softened;
        }

        public void SetBoostRuntimeHook(bool enabled, int virtualKey, float force)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var descriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Boost);

            if (!enabled)
            {
                StopBoostGuard();
                _log("Boost runtime hook OFF.");
                return;
            }

            if (virtualKey <= 0)
                throw new InvalidOperationException("Boost keybind is not valid.");
            if (float.IsNaN(force) || float.IsInfinity(force) || force < -0.95F || force > 20F)
                throw new InvalidOperationException("Boost amount must be between -0.95 and 20. Default is 0.02.");

            var effectiveMultiplier = 1F + NormalizeBoostForce(force);
            var detour = EnsureRuntimeProfileHook(descriptor);
            StartBoostGuard(detour, descriptor, virtualKey, effectiveMultiplier);
            _log("Boost armed. Hold key " + ((Keys)virtualKey).ToString() + " for nitro speed at multiplier x" + effectiveMultiplier.ToString("0.###", CultureInfo.InvariantCulture) + ".");
        }
