        public void SetSuperStrengthRuntimeConfig(
            float shoveSpeed,
            float minSpeed,
            float maxSpeed,
            float accelerationPerSecond,
            float verticalDamping,
            float verticalClamp)
        {
            if (!IsFiniteFloat(shoveSpeed) || shoveSpeed <= 0F || shoveSpeed > 500F)
                throw new InvalidOperationException("Super Strength shove speed must be between 1 and 500.");
            if (!IsFiniteFloat(minSpeed) || minSpeed <= 0F || minSpeed > 500F)
                throw new InvalidOperationException("Super Strength minimum speed must be between 1 and 500.");
            if (!IsFiniteFloat(maxSpeed) || maxSpeed <= 0F || maxSpeed > 500F)
                throw new InvalidOperationException("Super Strength maximum speed must be between 1 and 500.");
            if (!IsFiniteFloat(accelerationPerSecond) || accelerationPerSecond < 0F || accelerationPerSecond > 500F)
                throw new InvalidOperationException("Super Strength acceleration ramp must be between 0 and 500.");
            if (!IsFiniteFloat(verticalDamping) || verticalDamping < 0F || verticalDamping > 1F)
                throw new InvalidOperationException("Super Strength vertical damping must be between 0 and 1.");
            if (!IsFiniteFloat(verticalClamp) || verticalClamp < 0F || verticalClamp > 100F)
                throw new InvalidOperationException("Super Strength vertical clamp must be between 0 and 100.");

            var requiredMax = Math.Max(shoveSpeed, minSpeed);
            if (maxSpeed < requiredMax)
                throw new InvalidOperationException("Super Strength maximum speed must be at least the shove speed and minimum speed.");

            lock (_superStrengthConfigLock)
            {
                _superStrengthShoveSpeed = shoveSpeed;
                _superStrengthMinSpeed = minSpeed;
                _superStrengthMaxSpeed = maxSpeed;
                _superStrengthAccelerationPerSecond = accelerationPerSecond;
                _superStrengthVerticalDamping = verticalDamping;
                _superStrengthVerticalClamp = verticalClamp;
            }
        }

