            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
            StartAutoRaceDriveGuard(
                vehicleDetour,
                _teleportWaypointDetour,
                _teleportWaypointDescriptor,
                _teleportWaypointCopyDetours,
                _teleportWaypointCopyDescriptors,
                virtualKey);
            _log("Auto Race (Drive) armed. Get on the race route, then press key " + ((Keys)virtualKey).ToString() + " to start/stop auto-driving the line.");
        }

        private void InstallTeleportWaypointCaptureHooks(
            out RuntimeDetour waypointDetour,
            out RuntimeProfileHookDescriptor waypointDescriptor,
            out List<RuntimeDetour> waypointCaptureDetours,
            out List<RuntimeProfileHookDescriptor> waypointCaptureDescriptors)
        {
            waypointCaptureDetours = new List<RuntimeDetour>();
            waypointCaptureDescriptors = new List<RuntimeProfileHookDescriptor>();

            for (var i = 0; i < 5; i++)
            {
                try
                {
                    var mapDescriptor = GetMapFastTravelPositionCaptureDescriptor(i);
                    var mapDetour = EnsureRuntimeProfileHook(mapDescriptor);
                    waypointCaptureDescriptors.Add(mapDescriptor);
                    waypointCaptureDetours.Add(mapDetour);
                }
                catch (Exception ex)
                {
                    _log("Teleport map destination capture " + (i + 1).ToString(CultureInfo.InvariantCulture) + " not ready: " + ex.Message);
                }
            }

            for (var i = 0; i < 4; i++)
            {
                try
                {
                    var copyDescriptor = GetWaypointCopyDescriptor(i);
                    var copyDetour = EnsureRuntimeProfileHook(copyDescriptor);
                    waypointCaptureDescriptors.Add(copyDescriptor);
                    waypointCaptureDetours.Add(copyDetour);
                }
                catch (Exception ex)
                {
                    _log("Teleport waypoint copy capture " + (i + 1).ToString(CultureInfo.InvariantCulture) + " not ready: " + ex.Message);
                }
            }

            for (var i = 0; i < 4; i++)
            {
                try
                {
                    var captureDescriptor = GetWaypointDestinationCaptureDescriptor(i);
                    var captureDetour = EnsureRuntimeProfileHook(captureDescriptor);
                    waypointCaptureDescriptors.Add(captureDescriptor);
                    waypointCaptureDetours.Add(captureDetour);
                }
                catch (Exception ex)
                {
                    _log("Teleport waypoint destination capture " + (i + 1).ToString(CultureInfo.InvariantCulture) + " not ready: " + ex.Message);
                }
            }

            for (var i = 0; i < 3; i++)
            {
                try
                {
                    var captureDescriptor = GetWaypointRouteVectorDescriptor(i);
                    var captureDetour = EnsureRuntimeProfileHook(captureDescriptor);
                    waypointCaptureDescriptors.Add(captureDescriptor);
                    waypointCaptureDetours.Add(captureDetour);
                }
                catch (Exception ex)
                {
                    _log("Teleport route vector capture " + (i + 1).ToString(CultureInfo.InvariantCulture) + " not ready: " + ex.Message);
                }
            }

            for (var i = 0; i < 3; i++)
            {
                try
                {
                    var captureDescriptor = GetNavigationDestinationPointerDescriptor(i);
                    var captureDetour = EnsureRuntimeProfileHook(captureDescriptor);
                    waypointCaptureDescriptors.Add(captureDescriptor);
                    waypointCaptureDetours.Add(captureDetour);
                }
                catch (Exception ex)
                {
                    _log("Teleport navigation destination capture " + (i + 1).ToString(CultureInfo.InvariantCulture) + " not ready: " + ex.Message);
                }
            }

            try
            {
                var satNavDescriptor = GetSatNavRouteObjectDescriptor();
                var satNavDetour = EnsureRuntimeProfileHook(satNavDescriptor);
                waypointCaptureDescriptors.Add(satNavDescriptor);
                waypointCaptureDetours.Add(satNavDetour);
            }
            catch (Exception ex)
            {
                _log("Teleport SatNav object capture not ready: " + ex.Message);
            }

            waypointDescriptor = null;
            waypointDetour = null;
            try
            {
                waypointDescriptor = GetCurrentDestinationPointerDescriptor();
                waypointDetour = EnsureRuntimeProfileHook(waypointDescriptor);
            }
            catch (Exception ex)
            {
                _log("Teleport current destination pointer capture not ready: " + ex.Message);
            }

            if (waypointCaptureDetours.Count == 0 && waypointDetour == null)
            {
                ulong routeVectorAddress;
                if (!TryResolveFreshWaypointRouteHeader(out routeVectorAddress))
                    throw new InvalidOperationException("FH6 waypoint capture and active route data are not readable yet.");
            }
        }

        public byte[] ReadCurrentVehicleTeleportPosition()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var vehicleDescriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);
            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
            var vehiclePointer = ReadCurrentVehiclePointer(vehicleDetour);
            if (vehiclePointer == 0)
                throw new InvalidOperationException("Current vehicle was not captured yet. Sit in the car and move for a second, then try again.");

            var position = ReadBytes(vehiclePointer + 0x50UL, 16);
            if (!IsValidTeleportPosition(position))
                throw new InvalidOperationException("Current vehicle position did not look valid yet. Move the car a little and try again.");

            return BuildTeleportVehiclePosition(vehiclePointer, position);
        }

        public byte[] ReadCurrentWaypointTeleportPosition()
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var vehicleDescriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);
            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);

            var deadline = DateTime.UtcNow.AddMilliseconds(5000);
            byte[] position;
            do
            {
                var vehiclePointer = ReadCurrentVehiclePointer(vehicleDetour);
                if (TryReadBestWaypointPosition(vehiclePointer, out position))
                {
                    if (vehiclePointer != 0)
                        position = BuildTeleportVehiclePosition(vehiclePointer, position);

                    var source = string.IsNullOrWhiteSpace(_teleportLastSource) ? "waypoint" : _teleportLastSource;
                    _log("Teleport waypoint location captured from " + source + " at " + FormatTeleportPosition(position) + ".");
                    return position;
                }

                Thread.Sleep(50);
            }
            while (DateTime.UtcNow < deadline);

            throw new InvalidOperationException("Waypoint location was not captured yet. Set or refresh a map waypoint, then press Save Waypoint again.");
        }

        public void SetSavedLocationTeleportRuntimeHook(bool enabled, int virtualKey, byte[] position, string name)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            if (!enabled)
            {
                StopSavedLocationTeleportMode();
                _log("Saved Location Teleport runtime hook OFF.");
                return;
            }

            if (virtualKey <= 0)
                throw new InvalidOperationException("Teleport keybind is not valid.");
            if (!IsValidTeleportPosition(position))
                throw new InvalidOperationException("Saved teleport location is not valid.");

            var vehicleDescriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);
            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
            StartSavedLocationTeleportGuard(vehicleDetour, virtualKey, position, name);
            _log("Saved Location Teleport armed. Press key " + ((Keys)virtualKey).ToString() + " for " + (string.IsNullOrWhiteSpace(name) ? "selected spot" : name) + ".");
        }

        public void TeleportToSavedLocationNow(byte[] position, string name)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (!IsValidTeleportPosition(position))
                throw new InvalidOperationException("Saved teleport location is not valid.");

            var vehicleDescriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);
            var vehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
            TeleportVehicleToSavedLocation(vehicleDetour, position, name);
        }

        public void SetDriftModeRuntimeHook(bool enabled, int virtualKey, float amount)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            var descriptor = GetProfileHookDescriptor(RuntimeProfileFeature.DriftMode);

            if (!enabled)
            {
                StopDriftModeGuard();
                _log("Drift Mode runtime hook OFF.");
                return;
            }

            if (virtualKey <= 0)
                throw new InvalidOperationException("Drift Mode keybind is not valid.");
            if (float.IsNaN(amount) || float.IsInfinity(amount) || amount < 0F || amount > 1F)
                throw new InvalidOperationException("Drift Mode intensity must be between 0 and 1. Start around 0.5; higher slides harder.");

            var detour = EnsureRuntimeProfileHook(descriptor);
            StartDriftModeGuard(detour, descriptor, virtualKey, amount);
            _log("Drift Mode armed. Hold " + ((Keys)virtualKey).ToString() + " and steer (A/D, arrows, or stick) to drift; countersteer to hold or catch it.");
        }

