        private void ApplyVehicleControlLaneIfPresent(RuntimeProfileHookDescriptor descriptor)
        {
            RuntimeDetour detour;
            lock (_runtimePatchLock)
            {
                if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                    return;
            }

            ApplyVehicleControlLane(detour, descriptor);
        }

        private void ApplyVehicleControlLane(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor)
        {
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return;

            var inputBrakePressed = IsBrakeInputPressed();
            var brakePressed = (_vehicleSuperBrakeEnabled || _vehicleAdaptiveBrakeEnabled) && inputBrakePressed;
            var nowTicks = DateTime.UtcNow.Ticks;
            if (brakePressed)
            {
                if (!_superBrakeGuardLastState || _brakePressedSinceUtcTicks == 0)
                    _brakePressedSinceUtcTicks = nowTicks;
            }
            else
            {
                _brakePressedSinceUtcTicks = 0;
            }
            _superBrakeGuardLastState = brakePressed;

            int? speedValue = null;
            if (brakePressed)
            {
                var heldTicks = _brakePressedSinceUtcTicks == 0 ? 0 : nowTicks - _brakePressedSinceUtcTicks;
                if (_vehicleSuperBrakeEnabled && heldTicks < TimeSpan.TicksPerMillisecond * SuperBrakeInstantStopMilliseconds)
                    speedValue = 0;
                else if (_vehicleAdaptiveBrakeEnabled)
                    speedValue = _vehicleAdaptiveBrakeValue;
                else
                    speedValue = null;
            }
            else if (ShouldApplyAccelerationBoost(inputBrakePressed))
            {
                speedValue = _vehicleAccelerationValue;
            }

            if (!brakePressed && _vehicleBoostEnabled && _boostGuardVirtualKey > 0 && IsKeyDown(_boostGuardVirtualKey))
                speedValue = _vehicleBoostValue;

            if (speedValue.HasValue)
            {
                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, speedValue.Value);
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
                return;
            }

            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
            WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0);
        }

        private bool ShouldApplyAccelerationBoost(bool inputBrakePressed)
        {
            if (!_vehicleAccelerationEnabled || _vehicleAccelerationValue == 0)
                return false;

            if (inputBrakePressed)
                return false;

            return IsAccelerationInputPressed();
        }

        private void StartJumpGuard(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int virtualKey, float boost)
        {
            _jumpGuardDetour = detour;
            _jumpGuardDescriptor = descriptor;
            _jumpGuardVirtualKey = virtualKey;
            _jumpGuardLastState = false;
            _jumpGuardNextPulseUtcTicks = 0;

            WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, BitConverter.ToInt32(BitConverter.GetBytes(boost), 0));
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);

            if (_jumpGuardTimer == null)
                _jumpGuardTimer = new System.Threading.Timer(JumpGuardTick, null, 0, 16);
            else
                _jumpGuardTimer.Change(0, 16);
