        private void StopJumpGuard()
        {
            var timer = _jumpGuardTimer;
            _jumpGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            var detour = _jumpGuardDetour;
            var descriptor = _jumpGuardDescriptor;
            _jumpGuardDetour = null;
            _jumpGuardDescriptor = null;
            _jumpGuardLastState = false;
            _jumpGuardVirtualKey = 0;
            _jumpGuardNextPulseUtcTicks = 0;

            if (detour == null || descriptor == null || detour.DetourAddress == 0 || _handle == IntPtr.Zero)
                return;

            try
