        private void JumpGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _jumpGuardRunning, 1) == 1)
                return;

            try
            {
                var detour = _jumpGuardDetour;
                var descriptor = _jumpGuardDescriptor;
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || !IsAlive)
                    return;

                var pressed = IsKeyDown(_jumpGuardVirtualKey);
                var nowTicks = DateTime.UtcNow.Ticks;
                if (pressed && (!_jumpGuardLastState || nowTicks >= _jumpGuardNextPulseUtcTicks))
                {
                    WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 1);
                    _jumpGuardNextPulseUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * JumpPulseMilliseconds;
                }
                else
                {
                    WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                }
                _jumpGuardLastState = pressed;
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Jump", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _jumpGuardRunning, 0);
            }
        }

