        private void AirBrakeGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _airBrakeGuardRunning, 1) == 1)
                return;

            try
            {
                var detour = _airBrakeGuardDetour;
                var descriptor = _airBrakeGuardDescriptor;
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || !IsAlive)
                    return;

                var nowTicks = DateTime.UtcNow.Ticks;
                var active = IsAirBrakeInputPressed() && IsVehicleLikelyAirborne(detour, nowTicks);
                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, _airBrakeGuardValue);
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, active ? (byte)1 : (byte)0);
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Air Brake", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _airBrakeGuardRunning, 0);
            }
        }

        private bool IsVehicleLikelyAirborne(RuntimeDetour detour, long nowTicks)
        {
            if (detour == null || detour.DetourAddress == 0)
                return false;

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(detour.DetourAddress + (ulong)layout.VehiclePointerOffset);
            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x24UL, 4))
                return false;

            var verticalMotion = ReadFloat(vehiclePointer + 0x24UL);
            if (!IsFiniteFloat(verticalMotion))
                return false;

            if (Math.Abs(verticalMotion) > 0.10F)
                _airBrakeLastAirMotionUtcTicks = nowTicks;

            return _airBrakeLastAirMotionUtcTicks != 0 &&
                nowTicks - _airBrakeLastAirMotionUtcTicks <= TimeSpan.TicksPerMillisecond * AirBrakeAirMotionGraceMilliseconds;
        }

