        private void ForwardLaunchGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _forwardLaunchGuardRunning, 1) == 1)
                return;

            try
            {
                var detour = _forwardLaunchGuardDetour;
                var descriptor = _forwardLaunchGuardDescriptor;
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || !IsAlive)
                    return;

                var nowTicks = DateTime.UtcNow.Ticks;
                var forwardPressed = IsForwardInputPressed() && !IsAirBrakeInputPressed();
                if (forwardPressed && !_forwardLaunchForwardLastState)
                    _forwardLaunchStartedUtcTicks = nowTicks;
                else if (!forwardPressed)
                    _forwardLaunchStartedUtcTicks = 0;
                _forwardLaunchForwardLastState = forwardPressed;

                var active = forwardPressed &&
                    _forwardLaunchStartedUtcTicks != 0 &&
                    nowTicks - _forwardLaunchStartedUtcTicks <= TimeSpan.TicksPerMillisecond * ForwardLaunchDurationMilliseconds;

                WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, _forwardLaunchGuardValue);
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, active ? (byte)1 : (byte)0);
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Forward Launch", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _forwardLaunchGuardRunning, 0);
            }
        }

