        private void StartDriftModeGuard(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int virtualKey, float amount)
        {
            _driftModeGuardDetour = detour;
            _driftModeGuardDescriptor = descriptor;
            _driftModeGuardVirtualKey = virtualKey;
            _driftModeTargetForce = Math.Abs(amount);
            _driftModeCurrentForce = 0F;

            WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0);
            WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);

            if (_driftModeGuardTimer == null)
                _driftModeGuardTimer = new System.Threading.Timer(DriftModeGuardTick, null, 0, 16);
            else
                _driftModeGuardTimer.Change(0, 16);
        }

        private void StopDriftModeGuard()
        {
            var timer = _driftModeGuardTimer;
            _driftModeGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            var detour = _driftModeGuardDetour;
            var descriptor = _driftModeGuardDescriptor;
            _driftModeGuardDetour = null;
            _driftModeGuardDescriptor = null;
            _driftModeGuardVirtualKey = 0;
            _driftModeTargetForce = 0F;
            _driftModeCurrentForce = 0F;

            if (detour == null || descriptor == null || detour.DetourAddress == 0 || _handle == IntPtr.Zero)
                return;

            try
            {
                WriteByte(detour.DetourAddress + (ulong)descriptor.ToggleOffset, 0);
                if (descriptor.ValueOffset >= 0)
                    WriteInt32(detour.DetourAddress + (ulong)descriptor.ValueOffset, 0);
            }
            catch
            {
            }
        }

        private void DriftModeGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _driftModeGuardRunning, 1) == 1)
                return;

            try
            {
                var detour = _driftModeGuardDetour;
                var descriptor = _driftModeGuardDescriptor;
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || !IsAlive)
                    return;

                var engaged = _driftModeGuardVirtualKey > 0 && IsKeyDown(_driftModeGuardVirtualKey);

                var layout = GetVehicleControlLayout();
                var vp = ReadUInt64(detour.DetourAddress + (ulong)layout.VehiclePointerOffset);
                var nowTicks = DateTime.UtcNow.Ticks;
                if (vp == 0 || !IsAssistVehicleWriteSafe(vp, nowTicks) ||
                    !IsWritableMemoryRange(vp + 0x30UL, 16) || !IsReadableMemoryRange(vp + 0x20UL, 12))
                {
                    _driftModeCurrentForce = 0F;
                    return;
                }

                var target = 0F;
                if (engaged)
                {
                    var vel = ReadBytes(vp + 0x20UL, 12);
                    var dvx = BitConverter.ToSingle(vel, 0);
                    var dvz = BitConverter.ToSingle(vel, 8);
                    if (IsFiniteFloat(dvx) && IsFiniteFloat(dvz))
                    {
                        var speed = (float)Math.Sqrt((double)((dvx * dvx) + (dvz * dvz)));
                        var steer = ReadDriftSteeringAxis();
                        if (speed > DriftModeMinSpeed && Math.Abs(steer) > 0.02F)
                        {
                            var speedFactor = Math.Min(1F, speed / DriftModeFullSpeed);
                            target = steer * FlyBodyYawInputSign * _driftModeTargetForce * DriftModeMaxYawRate * speedFactor;
                        }
                    }
                }

                _driftModeCurrentForce = ApproachDriftForce(_driftModeCurrentForce, target);

                if (IsFiniteFloat(_driftModeCurrentForce) && Math.Abs(_driftModeCurrentForce) > DriftModeEngageEpsilon)
                {
                    WriteFloat(vp + 0x34UL, _driftModeCurrentForce);
                }
                else
                {
                    _driftModeCurrentForce = 0F;
                }
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Drift Mode", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _driftModeGuardRunning, 0);
            }
        }

        private static float ReadDriftSteeringAxis()
        {
            var steer = 0F;
            if (IsKeyDown((int)Keys.A) || IsKeyDown((int)Keys.Left))
                steer -= 1F;
            if (IsKeyDown((int)Keys.D) || IsKeyDown((int)Keys.Right))
                steer += 1F;

            return Math.Max(-1F, Math.Min(1F, steer));
        }

        private float ApproachDriftForce(float current, float target)
        {
            var maxStep = DriftModeMaxYawRate * DriftModeRampStepFraction;
            var delta = target - current;
            if (delta > maxStep)
                delta = maxStep;
            else if (delta < -maxStep)
                delta = -maxStep;
            return current + delta;
        }
        private void StartHoverGuard(
            RuntimeDetour detour,
            RuntimeDetour cameraDetour,
            RuntimeProfileHookDescriptor cameraDescriptor,
            float speed)
        {
            StopHoverGuard();

            _hoverGuardDetour = detour;
            _hoverCameraDetour = cameraDetour;
            _hoverCameraDescriptor = cameraDescriptor;
            _hoverLastVehiclePointer = 0;
            _hoverAnchorCaptured = false;
            _hoverHoldX = 0F;
            _hoverHoldY = 0F;
            _hoverHoldZ = 0F;
            _hoverForwardDirX = 0F;
            _hoverForwardDirZ = -1F;
            _hoverFacingDirX = 0F;
            _hoverFacingDirZ = -1F;
            _hoverDirectionCaptured = false;
            _hoverHorizontalSpeed = Math.Max(1F, Math.Min(250F, speed));
            _hoverVerticalSpeed = Math.Max(4F, _hoverHorizontalSpeed * HoverVerticalSpeedRatio);
            _hoverVelX = 0F;
            _hoverVelY = 0F;
            _hoverVelZ = 0F;
            _hoverLastTickUtcTicks = 0;
            _hoverVehicleForwardAxisSign = 0;
            _hoverPendingVehiclePointer = 0;
            _hoverPendingVehicleTicks = 0;
            _hoverHoldSeeded = false;

            ApplyHoverToCurrentVehicle();

            if (_hoverGuardTimer == null)
                _hoverGuardTimer = new System.Threading.Timer(HoverGuardTick, null, 0, 4);
            else
                _hoverGuardTimer.Change(0, 4);
        }

        private void StopHoverGuard()
        {
            var timer = _hoverGuardTimer;
            _hoverGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _hoverGuardDetour = null;
            _hoverCameraDetour = null;
            _hoverCameraDescriptor = null;
            _hoverLastVehiclePointer = 0;
            _hoverAnchorCaptured = false;
            _hoverHoldX = 0F;
            _hoverHoldY = 0F;
            _hoverHoldZ = 0F;
            _hoverForwardDirX = 0F;
            _hoverForwardDirZ = -1F;
            _hoverFacingDirX = 0F;
            _hoverFacingDirZ = -1F;
            _hoverDirectionCaptured = false;
            _hoverHorizontalSpeed = 0F;
            _hoverVerticalSpeed = 0F;
            _hoverVelX = 0F;
            _hoverVelY = 0F;
            _hoverVelZ = 0F;
            _hoverLastTickUtcTicks = 0;
            _hoverVehicleForwardAxisSign = 0;
            _hoverPendingVehiclePointer = 0;
            _hoverPendingVehicleTicks = 0;
            _hoverHoldSeeded = false;
        }

        private void HoverGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _hoverGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive || _hoverGuardDetour == null || _hoverGuardDetour.DetourAddress == 0)
                    return;

                ApplyHoverToCurrentVehicle();
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Fly", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _hoverGuardRunning, 0);
            }
        }

        private void PinFlyHoldDuringPointerFlicker()
        {
            var pointer = _hoverLastVehiclePointer;
            if (pointer == 0 || !_hoverHoldSeeded)
                return;
            if (!IsWritableMemoryRange(pointer + 0x20UL, 16) ||
                !IsWritableMemoryRange(pointer + 0x50UL, 12) ||
                !IsReadableMemoryRange(pointer + 0x40UL, 16))
                return;

            var quat = ReadBytes(pointer + 0x40UL, 16);
            if (quat.Length < 16)
                return;
            var qx = BitConverter.ToSingle(quat, 0);
            var qy = BitConverter.ToSingle(quat, 4);
            var qz = BitConverter.ToSingle(quat, 8);
            var qw = BitConverter.ToSingle(quat, 12);
            if (!IsFiniteFloat(qx) || !IsFiniteFloat(qy) || !IsFiniteFloat(qz) || !IsFiniteFloat(qw))
                return;
            var qLen = (float)Math.Sqrt((double)((qx * qx) + (qy * qy) + (qz * qz) + (qw * qw)));
            if (!IsFiniteFloat(qLen) || qLen < 0.25F || qLen > 4F)
                return;

            var position = ReadBytes(pointer + 0x50UL, 12);
            if (position.Length < 12)
                return;
            var px = BitConverter.ToSingle(position, 0);
            var py = BitConverter.ToSingle(position, 4);
            var pz = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(px) || !IsFiniteFloat(py) || !IsFiniteFloat(pz))
                return;
            var dx = px - _hoverHoldX;
            var dy = py - _hoverHoldY;
            var dz = pz - _hoverHoldZ;
            if (!IsFiniteFloat(dx) || !IsFiniteFloat(dy) || !IsFiniteFloat(dz) ||
                ((dx * dx) + (dy * dy) + (dz * dz)) > 500F * 500F)
                return;

            WriteFloat(pointer + 0x50UL, _hoverHoldX);
            WriteFloat(pointer + 0x54UL, _hoverHoldY);
            WriteFloat(pointer + 0x58UL, _hoverHoldZ);
            WriteFloat(pointer + 0x20UL, _hoverVelX);
            WriteFloat(pointer + 0x24UL, _hoverVelY);
            WriteFloat(pointer + 0x28UL, _hoverVelZ);
            WriteFloat(pointer + 0x2CUL, 0F);
        }

        private void ApplyHoverToCurrentVehicle()
        {
            var detour = _hoverGuardDetour;
            if (detour == null || detour.DetourAddress == 0)
                return;

            var vehiclePointer = ReadCurrentVehiclePointer(detour);
            if (vehiclePointer == 0)
                return;

            if (_hoverLastVehiclePointer != 0 && vehiclePointer != _hoverLastVehiclePointer)
            {
                if (vehiclePointer == _hoverPendingVehiclePointer)
                    _hoverPendingVehicleTicks++;
                else
                {
                    _hoverPendingVehiclePointer = vehiclePointer;
                    _hoverPendingVehicleTicks = 1;
                }

                if (_hoverPendingVehicleTicks < 5)
                {
                    PinFlyHoldDuringPointerFlicker();
                    return;
                }

                _hoverPendingVehiclePointer = 0;
                _hoverPendingVehicleTicks = 0;
            }
            else
            {
                _hoverPendingVehiclePointer = 0;
                _hoverPendingVehicleTicks = 0;
            }

            if (!IsWritableMemoryRange(vehiclePointer + 0x20UL, 16) || !IsWritableMemoryRange(vehiclePointer + 0x50UL, 12))
                return;

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
            var position = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (velocity.Length < 12 || position.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            var px = BitConverter.ToSingle(position, 0);
            var py = BitConverter.ToSingle(position, 4);
            var pz = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz) ||
                !IsFiniteFloat(px) || !IsFiniteFloat(py) || !IsFiniteFloat(pz))
                return;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            if (!IsFiniteFloat(speed))
                speed = 0F;

            if (vehiclePointer != _hoverLastVehiclePointer)
            {
                float preservedX = 0F;
                float preservedZ = -1F;
                var preserveHeading = _hoverDirectionCaptured &&
                    TryNormalizeFlyDirection(_hoverForwardDirX, _hoverForwardDirZ, out preservedX, out preservedZ);

                _hoverLastVehiclePointer = vehiclePointer;
                _hoverAnchorCaptured = false;
                _hoverForwardDirX = preserveHeading ? preservedX : 0F;
                _hoverForwardDirZ = preserveHeading ? preservedZ : -1F;
                _hoverFacingDirX = _hoverForwardDirX;
                _hoverFacingDirZ = _hoverForwardDirZ;
                _hoverDirectionCaptured = preserveHeading;
                if (!preserveHeading)
                {
                    _hoverVelX = 0F;
                    _hoverVelY = 0F;
                    _hoverVelZ = 0F;
                }
                _hoverLastTickUtcTicks = 0;
            }

            if (!_hoverAnchorCaptured)
            {
                if (!_hoverHoldSeeded)
                {
                    _hoverHoldX = px;
                    _hoverHoldY = py;
                    _hoverHoldZ = pz;
                    _hoverHoldSeeded = true;
                }

                float headingX;
                float headingZ;
                if (_hoverDirectionCaptured)
                {
                }
                else if ((speed > 2F &&
                     TryNormalizeFlyDirection(vx, vz, out headingX, out headingZ) &&
                     TryAcceptHoverDirection(headingX, headingZ, false, out headingX, out headingZ)) ||
                    (TryReadFlyCameraControlDirection(vehiclePointer, out headingX, out headingZ) &&
                      TryAcceptHoverDirection(headingX, headingZ, false, out headingX, out headingZ)) ||
                    (TryReadFlyVehicleNoseDirection(vehiclePointer, out headingX, out headingZ) &&
                     TryAcceptHoverDirection(headingX, headingZ, false, out headingX, out headingZ)))
                {
                    _hoverForwardDirX = headingX;
                    _hoverForwardDirZ = headingZ;
                    _hoverDirectionCaptured = true;
                }
                else if (!_hoverDirectionCaptured)
                {
                    _hoverForwardDirX = 0F;
                    _hoverForwardDirZ = -1F;
                    _hoverDirectionCaptured = true;
                }

                _hoverAnchorCaptured = true;
            }

            var nowTicks = DateTime.UtcNow.Ticks;
            var deltaSeconds = _hoverLastTickUtcTicks == 0
                ? 0.016F
                : Math.Max(0.004F, Math.Min(0.05F, (float)((nowTicks - _hoverLastTickUtcTicks) / (double)TimeSpan.TicksPerSecond)));
            _hoverLastTickUtcTicks = nowTicks;

            float side;
            float forward;
            float vertical;
            float yawAdjust;
            float nudgeSide;
            float nudgeForward;
            ReadHoverInput(out side, out forward, out vertical, out yawAdjust, out nudgeSide, out nudgeForward);

            var rawSteeringInput = (Math.Abs(yawAdjust) > 0.01F ? yawAdjust : side) * FlySteeringInputSign;
            var throttleMagnitude = Math.Min(1F, Math.Abs(forward));
            var steeringScale = throttleMagnitude > 0.01F ? FlyTurnWithThrottleScale : FlyTurnWithoutThrottleScale;
            var steeringInput = rawSteeringInput * steeringScale;
            var bodyYawInput = steeringInput;
            if (Math.Abs(steeringInput) > 0.01F)
            {
                RotateFlyDirection(
                    _hoverForwardDirX,
                    _hoverForwardDirZ,
                    steeringInput * FlyFacingTurnRadiansPerSecond * deltaSeconds,
                    out _hoverForwardDirX,
                    out _hoverForwardDirZ);
                _hoverDirectionCaptured = true;
            }
            else
            {
                float liveFacingX;
                float liveFacingZ;
                if (!_hoverDirectionCaptured &&
                    TryReadFlyVehicleNoseDirection(vehiclePointer, out liveFacingX, out liveFacingZ) &&
                    TryAcceptHoverDirection(liveFacingX, liveFacingZ, false, out liveFacingX, out liveFacingZ))
                {
                    _hoverForwardDirX = liveFacingX;
                    _hoverForwardDirZ = liveFacingZ;
                    _hoverDirectionCaptured = true;
                }
            }

            _hoverFacingDirX = _hoverForwardDirX;
            _hoverFacingDirZ = _hoverForwardDirZ;

            if (!ApplyFlyActivePhaseMovement(
                vehiclePointer,
                ref _hoverHoldX,
                ref _hoverHoldY,
                ref _hoverHoldZ,
                _hoverForwardDirX,
                _hoverForwardDirZ,
                _hoverFacingDirX,
                _hoverFacingDirZ,
                side,
                forward,
                vertical,
                _hoverHorizontalSpeed,
                _hoverVerticalSpeed,
                deltaSeconds,
                bodyYawInput,
                nudgeSide,
                nudgeForward))
            {
                return;
            }
        }

        private static float FlyApproachAlpha(float responsePerSecond, float deltaSeconds)
        {
            if (responsePerSecond <= 0F || deltaSeconds <= 0F)
                return 1F;

            var alpha = 1F - (float)Math.Exp((double)(-responsePerSecond * deltaSeconds));
            if (!IsFiniteFloat(alpha) || alpha > 1F)
                return 1F;
            if (alpha < 0F)
                return 0F;
            return alpha;
        }

        private bool ApplyFlyActivePhaseMovement(
            ulong vehiclePointer,
            ref float holdX,
            ref float holdY,
            ref float holdZ,
            float forwardDirX,
            float forwardDirZ,
            float facingDirX,
            float facingDirZ,
            float side,
            float forward,
            float vertical,
            float horizontalSpeed,
            float verticalSpeed,
            float deltaSeconds,
            float steeringInput,
            float nudgeSide,
            float nudgeForward)
        {
            if (!TryNormalizeFlyDirection(forwardDirX, forwardDirZ, out forwardDirX, out forwardDirZ))
            {
                if (_hoverDirectionCaptured &&
                    TryNormalizeFlyDirection(_hoverForwardDirX, _hoverForwardDirZ, out forwardDirX, out forwardDirZ))
                {
                }
                else if (!TryReadFlyVehicleNoseDirection(vehiclePointer, out forwardDirX, out forwardDirZ))
                {
                    forwardDirX = 0F;
                    forwardDirZ = -1F;
                }
            }
            if (!TryNormalizeFlyDirection(facingDirX, facingDirZ, out facingDirX, out facingDirZ))
            {
                facingDirX = forwardDirX;
                facingDirZ = forwardDirZ;
            }

            side = Math.Max(-1F, Math.Min(1F, side)) * FlySideInputSign;
            forward = Math.Max(-1F, Math.Min(1F, forward)) * FlyForwardInputSign;
            vertical = Math.Max(-1F, Math.Min(1F, vertical));
            horizontalSpeed = Math.Max(1F, horizontalSpeed);
            verticalSpeed = Math.Max(4F, verticalSpeed);

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
            var position = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (velocity.Length < 12 || position.Length < 12)
                return false;

            var liveVx = BitConverter.ToSingle(velocity, 0);
            var liveVz = BitConverter.ToSingle(velocity, 8);
            var liveX = BitConverter.ToSingle(position, 0);
            var liveZ = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(liveVx) || !IsFiniteFloat(liveVz) ||
                !IsFiniteFloat(liveX) || !IsFiniteFloat(liveZ))
                return false;

            var sideDirX = -forwardDirZ;
            var sideDirZ = forwardDirX;
            var sideInfluence = Math.Abs(forward) > 0.01F ? 0F : side * 0.35F;
            var driveX = (forwardDirX * forward) + (sideDirX * sideInfluence);
            var driveZ = (forwardDirZ * forward) + (sideDirZ * sideInfluence);
            var driveMag = (float)Math.Sqrt((double)((driveX * driveX) + (driveZ * driveZ)));
            if (driveMag > 1F)
            {
                driveX /= driveMag;
                driveZ /= driveMag;
                driveMag = 1F;
            }

            var targetVx = driveX * horizontalSpeed;
            var targetVz = driveZ * horizontalSpeed;
            var targetVy = vertical * verticalSpeed;
            var horizontalAlpha = FlyApproachAlpha(driveMag > 0.01F ? FlyDriveAccelResponse : FlyDriveCoastResponse, deltaSeconds);
            var verticalAlpha = FlyApproachAlpha(FlyDriveVerticalResponse, deltaSeconds);

            _hoverVelX += (targetVx - _hoverVelX) * horizontalAlpha;
            _hoverVelZ += (targetVz - _hoverVelZ) * horizontalAlpha;
            _hoverVelY += (targetVy - _hoverVelY) * verticalAlpha;

            if (!IsFiniteFloat(_hoverVelX) || !IsFiniteFloat(_hoverVelY) || !IsFiniteFloat(_hoverVelZ))
            {
                _hoverVelX = 0F;
                _hoverVelY = 0F;
                _hoverVelZ = 0F;
            }

            if (driveMag <= 0.01F && Math.Abs(_hoverVelX) < 0.05F && Math.Abs(_hoverVelZ) < 0.05F)
            {
                _hoverVelX = 0F;
                _hoverVelZ = 0F;
            }
            if (Math.Abs(vertical) <= 0.01F && Math.Abs(_hoverVelY) < 0.05F)
                _hoverVelY = 0F;

            nudgeSide = Math.Max(-1F, Math.Min(1F, nudgeSide));
            nudgeForward = Math.Max(-1F, Math.Min(1F, nudgeForward));
            var nudgeSpeed = Math.Max(6F, horizontalSpeed * 0.35F);
            var nudgeVx = ((sideDirX * nudgeSide) + (forwardDirX * nudgeForward)) * nudgeSpeed;
            var nudgeVz = ((sideDirZ * nudgeSide) + (forwardDirZ * nudgeForward)) * nudgeSpeed;
            if (!IsFiniteFloat(nudgeVx) || !IsFiniteFloat(nudgeVz))
            {
                nudgeVx = 0F;
                nudgeVz = 0F;
            }

            var moveVx = _hoverVelX + nudgeVx;
            var moveVz = _hoverVelZ + nudgeVz;

            holdX += moveVx * deltaSeconds;
            holdY += _hoverVelY * deltaSeconds;
            holdZ += moveVz * deltaSeconds;

            if (!IsFiniteFloat(holdX) || !IsFiniteFloat(holdY) || !IsFiniteFloat(holdZ))
                return false;

            ApplyFlyPhaseState(vehiclePointer, holdX, holdY, holdZ, moveVx, _hoverVelY, moveVz, facingDirX, facingDirZ, steeringInput, deltaSeconds);
            return true;
        }

        private void ApplyFlyPhaseState(
            ulong vehiclePointer,
            float positionX,
            float positionY,
            float positionZ,
            float velocityX,
            float velocityY,
            float velocityZ,
            float facingDirX,
            float facingDirZ,
            float steeringInput,
            float deltaSeconds)
        {
            if (vehiclePointer == 0)
                return;
            if (!IsWritableMemoryRange(vehiclePointer + 0x20UL, 16) || !IsWritableMemoryRange(vehiclePointer + 0x50UL, 12))
                return;
            if (!IsFiniteFloat(positionX) || !IsFiniteFloat(positionY) || !IsFiniteFloat(positionZ) ||
                !IsFiniteFloat(velocityX) || !IsFiniteFloat(velocityY) || !IsFiniteFloat(velocityZ))
                return;

            ApplyFlyAirDriveOrientation(vehiclePointer, steeringInput, deltaSeconds, facingDirX, facingDirZ);
            WriteFloat(vehiclePointer + 0x50UL, positionX);
            WriteFloat(vehiclePointer + 0x54UL, positionY);
            WriteFloat(vehiclePointer + 0x58UL, positionZ);
            WriteFloat(vehiclePointer + 0x20UL, velocityX);
            WriteFloat(vehiclePointer + 0x24UL, velocityY);
            WriteFloat(vehiclePointer + 0x28UL, velocityZ);
            WriteFloat(vehiclePointer + 0x2CUL, 0F);
            WriteFloat(vehiclePointer + 0x50UL, positionX);
            WriteFloat(vehiclePointer + 0x54UL, positionY);
            WriteFloat(vehiclePointer + 0x58UL, positionZ);
            WriteFloat(vehiclePointer + 0x20UL, velocityX);
            WriteFloat(vehiclePointer + 0x24UL, velocityY);
            WriteFloat(vehiclePointer + 0x28UL, velocityZ);
        }

        private bool TryReadFlyCameraDirection(out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            var detour = _hoverCameraDetour;
            var descriptor = _hoverCameraDescriptor;
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return false;

            if (descriptor.ObjectPointerOffset >= 0)
            {
                var cameraObject = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (cameraObject != 0 && IsReadableMemoryRange(cameraObject, 16))
                {
                    var live = ReadBytes(cameraObject, 16);
                    if (live.Length >= 12)
                    {
                        var liveX = BitConverter.ToSingle(live, 0);
                        var liveZ = BitConverter.ToSingle(live, 8);
                        if (TryNormalizeFlyDirection(-liveX, -liveZ, out dirX, out dirZ))
                            return true;
                    }
                }
            }

            if (descriptor.CaptureOffset >= 0 && !string.Equals(descriptor.Key, "FovSlider", StringComparison.OrdinalIgnoreCase))
            {
                var captureAddress = detour.DetourAddress + (ulong)descriptor.CaptureOffset;
                if (IsReadableMemoryRange(captureAddress, 16))
                {
                    var data = ReadBytes(captureAddress, 16);
                    if (data.Length >= 12)
                    {
                        var x = BitConverter.ToSingle(data, 0);
                        var z = BitConverter.ToSingle(data, 8);
                        if (TryNormalizeFlyDirection(-x, -z, out dirX, out dirZ))
                            return true;
                    }
                }
            }

            return false;
        }

        private bool TryReadFlyCameraPositionDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            var detour = _hoverCameraDetour;
            var descriptor = _hoverCameraDescriptor;
            if (detour == null || descriptor == null || detour.DetourAddress == 0 || descriptor.ObjectPointerOffset < 0)
                return false;

            var cameraObject = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
            if (cameraObject == 0)
                return false;

            if (!IsReadableMemoryRange(vehiclePointer + 0x50UL, 12))
                return false;

            var vehicle = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (vehicle.Length < 12)
                return false;

            var px = BitConverter.ToSingle(vehicle, 0);
            var pz = BitConverter.ToSingle(vehicle, 8);
            if (!IsFiniteFloat(px) || !IsFiniteFloat(pz))
                return false;

            var candidateOffsets = new ulong[] { 0x00UL, 0x10UL, 0x20UL, 0x30UL, 0x40UL, 0x50UL, 0x60UL, 0x70UL, 0x80UL };
            foreach (var offset in candidateOffsets)
            {
                var address = cameraObject + offset;
                if (!IsReadableMemoryRange(address, 12))
                    continue;

                var data = ReadBytes(address, 12);
                if (data.Length < 12)
                    continue;

                var cx = BitConverter.ToSingle(data, 0);
                var cz = BitConverter.ToSingle(data, 8);
                if (!IsFiniteFloat(cx) || !IsFiniteFloat(cz))
                    continue;

                var dx = px - cx;
                var dz = pz - cz;
                var distance = (float)Math.Sqrt((double)(dx * dx + dz * dz));
                if (distance >= 1F && distance <= 250F && TryNormalizeFlyDirection(dx, dz, out dirX, out dirZ))
                        return true;
            }

            return false;
        }

        private bool TryReadFlyCameraLook(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            if (TryReadFlyCameraPositionDirection(vehiclePointer, out dirX, out dirZ))
                return true;
            return TryReadFlyCameraDirection(out dirX, out dirZ);
        }

        private bool TryReadFlyCameraControlDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            if (TryReadFlyCameraDirection(out dirX, out dirZ))
                return true;
            return TryReadFlyCameraPositionDirection(vehiclePointer, out dirX, out dirZ);
        }

        private bool TryAcceptHoverDirection(float candidateX, float candidateZ, bool allowReverse, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (!TryNormalizeFlyDirection(candidateX, candidateZ, out candidateX, out candidateZ))
                return false;

            float currentX;
            float currentZ;
            if (!allowReverse &&
                _hoverDirectionCaptured &&
                TryNormalizeFlyDirection(_hoverForwardDirX, _hoverForwardDirZ, out currentX, out currentZ))
            {
                var dot = (candidateX * currentX) + (candidateZ * currentZ);
                if (IsFiniteFloat(dot) && dot < -0.25F)
                {
                    dirX = currentX;
                    dirZ = currentZ;
                    return true;
                }
            }

            dirX = candidateX;
            dirZ = candidateZ;
            return true;
        }

        private void ApplyFlyAirDriveOrientation(ulong vehiclePointer, float steeringInput, float deltaSeconds, float facingDirX, float facingDirZ)
        {
            if (vehiclePointer == 0 || !IsWritableMemoryRange(vehiclePointer + 0x30UL, 16))
                return;

            var yawRate = Math.Max(-1F, Math.Min(1F, steeringInput * FlyBodyYawInputSign)) * FlyBodyYawRadiansPerSecond;
            if (!IsFiniteFloat(yawRate))
                yawRate = 0F;

            var levelRateX = 0F;
            var levelRateZ = 0F;

            var quat = ReadBytes(vehiclePointer + 0x40UL, 16);
            if (quat.Length >= 16)
            {
                var qx = BitConverter.ToSingle(quat, 0);
                var qy = BitConverter.ToSingle(quat, 4);
                var qz = BitConverter.ToSingle(quat, 8);
                var qw = BitConverter.ToSingle(quat, 12);
                var lengthSq = (qx * qx) + (qy * qy) + (qz * qz) + (qw * qw);
                if (IsFiniteFloat(lengthSq) && lengthSq > 0.0625F && lengthSq < 16F)
                {
                    var inv = 1F / (float)Math.Sqrt((double)lengthSq);
                    qx *= inv;
                    qy *= inv;
                    qz *= inv;
                    qw *= inv;

                    var upX = 2F * ((qx * qy) - (qw * qz));
                    var upY = 1F - (2F * ((qx * qx) + (qz * qz)));
                    var upZ = 2F * ((qy * qz) + (qw * qx));

                    var yawError = 0F;
                    var hasYawError = false;
                    float noseX;
                    float noseZ;
                    var forwardX = 2F * ((qx * qz) + (qw * qy));
                    var forwardZ = 1F - (2F * ((qx * qx) + (qy * qy)));
                    if (TryNormalizeFlyDirection(forwardX, forwardZ, out noseX, out noseZ) &&
                        TryNormalizeFlyDirection(facingDirX, facingDirZ, out facingDirX, out facingDirZ))
                    {
                        var sign = ResolveFlyVehicleForwardAxisSign(vehiclePointer, noseX, noseZ);
                        noseX *= sign;
                        noseZ *= sign;
                        yawError = (float)Math.Atan2(
                            (double)((noseX * facingDirZ) - (noseZ * facingDirX)),
                            (double)((noseX * facingDirX) + (noseZ * facingDirZ)));
                        hasYawError = IsFiniteFloat(yawError);
                    }

                    var disturbed = upY < 0.85F || (hasYawError && Math.Abs(yawError) > 0.35F);
                    var levelGain = disturbed ? FlyLevelRatePerSecond * 3F : FlyLevelRatePerSecond;
                    var levelCap = disturbed ? 10F : FlyLevelMaxRadiansPerSecond;
                    var yawGain = disturbed ? FlyYawAlignRatePerSecond * 3F : FlyYawAlignRatePerSecond;
                    var yawCap = disturbed ? 7F : FlyYawAlignMaxRadiansPerSecond;

                    if (IsFiniteFloat(upX) && IsFiniteFloat(upY) && IsFiniteFloat(upZ) && upY > -0.9F)
                    {
                        levelRateX = Math.Max(-levelCap, Math.Min(levelCap, -upZ * levelGain));
                        levelRateZ = Math.Max(-levelCap, Math.Min(levelCap, upX * levelGain));
                    }

                    if (hasYawError)
                    {
                        var align = Math.Max(-yawCap, Math.Min(yawCap, yawError * yawGain));
                        yawRate += align * FlyBodyYawInputSign;
                    }
                }
            }

            WriteFloat(vehiclePointer + 0x30UL, levelRateX);
            WriteFloat(vehiclePointer + 0x34UL, yawRate);
            WriteFloat(vehiclePointer + 0x38UL, levelRateZ);
            WriteFloat(vehiclePointer + 0x3CUL, 0F);
        }

        private static bool TryNormalizeFlyDirection(float x, float z, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (!IsFiniteFloat(x) || !IsFiniteFloat(z))
                return false;

            var length = (float)Math.Sqrt((double)(x * x + z * z));
            if (length < 0.05F || length > 5000F)
                return false;

            dirX = x / length;
            dirZ = z / length;
            return IsFiniteFloat(dirX) && IsFiniteFloat(dirZ);
        }

        private bool TryReadFlyVehicleNoseDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            float rawX;
            float rawZ;
            if (!TryReadVehicleFacingDirection(vehiclePointer, out rawX, out rawZ))
                return false;

            var sign = ResolveFlyVehicleForwardAxisSign(vehiclePointer, rawX, rawZ);
            return TryNormalizeFlyDirection(rawX * sign, rawZ * sign, out dirX, out dirZ);
        }

        private float ResolveFlyVehicleForwardAxisSign(ulong vehiclePointer, float rawX, float rawZ)
        {
            if (_hoverVehicleForwardAxisSign != 0)
                return _hoverVehicleForwardAxisSign > 0 ? 1F : -1F;

            if (vehiclePointer != 0 && IsReadableMemoryRange(vehiclePointer + 0x20UL, 12))
            {
                var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
                if (velocity.Length >= 12)
                {
                    var vx = BitConverter.ToSingle(velocity, 0);
                    var vz = BitConverter.ToSingle(velocity, 8);
                    float velX;
                    float velZ;
                    if (TryNormalizeFlyDirection(vx, vz, out velX, out velZ) &&
                        TryNormalizeFlyDirection(rawX, rawZ, out rawX, out rawZ))
                    {
                        var dot = (rawX * velX) + (rawZ * velZ);
                        if (IsFiniteFloat(dot) && Math.Abs(dot) >= 0.35F)
                        {
                            _hoverVehicleForwardAxisSign = dot >= 0F ? 1 : -1;
                            return _hoverVehicleForwardAxisSign > 0 ? 1F : -1F;
                        }
                    }
                }
            }

            _hoverVehicleForwardAxisSign = -1;
            return -1F;
        }

        private bool TryReadVehicleFacingDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x40UL, 16))
                return false;

            var data = ReadBytes(vehiclePointer + 0x40UL, 16);
            if (data.Length < 16)
                return false;

            var qx = BitConverter.ToSingle(data, 0);
            var qy = BitConverter.ToSingle(data, 4);
            var qz = BitConverter.ToSingle(data, 8);
            var qw = BitConverter.ToSingle(data, 12);
            if (!IsFiniteFloat(qx) || !IsFiniteFloat(qy) || !IsFiniteFloat(qz) || !IsFiniteFloat(qw))
                return false;

            var length = (float)Math.Sqrt((double)((qx * qx) + (qy * qy) + (qz * qz) + (qw * qw)));
            if (IsFiniteFloat(length) && length >= 0.25F && length <= 4F)
            {
                var nx = qx / length;
                var ny = qy / length;
                var nz = qz / length;
                var nw = qw / length;

                var forwardX = 2F * ((nx * nz) + (nw * ny));
                var forwardZ = 1F - (2F * ((nx * nx) + (ny * ny)));
                if (TryNormalizeFlyDirection(forwardX, forwardZ, out dirX, out dirZ))
                    return true;
            }

            if (Math.Abs(qy) > 0.0001F || Math.Abs(qw) > 0.0001F)
            {
                var yaw = (float)(2.0 * Math.Atan2((double)qy, (double)qw));
                var yawX = (float)Math.Sin((double)yaw);
                var yawZ = (float)Math.Cos((double)yaw);
                if (TryNormalizeFlyDirection(yawX, yawZ, out dirX, out dirZ))
                    return true;
            }

            return TryNormalizeFlyDirection(qx, qz, out dirX, out dirZ);
        }

        private static float NormalizeFlyRadians(float value)
        {
            var twoPi = (float)(Math.PI * 2.0);
            while (value > Math.PI)
                value -= twoPi;
            while (value < -Math.PI)
                value += twoPi;
            return value;
        }

        private static void RotateFlyDirection(float dirX, float dirZ, float radians, out float rotatedX, out float rotatedZ)
        {
            var cos = (float)Math.Cos((double)radians);
            var sin = (float)Math.Sin((double)radians);
            rotatedX = dirX * cos - dirZ * sin;
            rotatedZ = dirX * sin + dirZ * cos;
            if (!TryNormalizeFlyDirection(rotatedX, rotatedZ, out rotatedX, out rotatedZ))
            {
                rotatedX = dirX;
                rotatedZ = dirZ;
            }
        }

        private void LockFlyVehicleFlat(ulong vehiclePointer, float dirX, float dirZ)
        {
            if (vehiclePointer == 0 || !IsWritableMemoryRange(vehiclePointer + 0x40UL, 16))
                return;

            var current = ReadBytes(vehiclePointer + 0x40UL, 16);
            if (current.Length < 16)
                return;

            var qx = BitConverter.ToSingle(current, 0);
            var qy = BitConverter.ToSingle(current, 4);
            var qz = BitConverter.ToSingle(current, 8);
            var qw = BitConverter.ToSingle(current, 12);
            if (!IsFiniteFloat(qx) || !IsFiniteFloat(qy) || !IsFiniteFloat(qz) || !IsFiniteFloat(qw))
                return;

            var length = (float)Math.Sqrt((double)(qx * qx + qy * qy + qz * qz + qw * qw));
            if (length < 0.5F || length > 1.5F)
                return;

            if (!TryNormalizeFlyDirection(dirX, dirZ, out dirX, out dirZ))
                return;

            var yaw = (float)Math.Atan2((double)dirX, (double)dirZ);
            var halfYaw = yaw * 0.5F;
            var flatY = (float)Math.Sin((double)halfYaw);
            var flatW = (float)Math.Cos((double)halfYaw);
            if (!IsFiniteFloat(flatY) || !IsFiniteFloat(flatW))
                return;

            WriteFloat(vehiclePointer + 0x40UL, 0F);
            WriteFloat(vehiclePointer + 0x44UL, flatY);
            WriteFloat(vehiclePointer + 0x48UL, 0F);
            WriteFloat(vehiclePointer + 0x4CUL, flatW);

            if (IsWritableMemoryRange(vehiclePointer + 0x30UL, 16))
            {
                WriteFloat(vehiclePointer + 0x30UL, 0F);
                WriteFloat(vehiclePointer + 0x34UL, 0F);
                WriteFloat(vehiclePointer + 0x38UL, 0F);
                WriteFloat(vehiclePointer + 0x3CUL, 0F);
            }
        }

        private void DampHoverSpin(ulong vehiclePointer)
        {
            if (!IsWritableMemoryRange(vehiclePointer + 0x30UL, 16))
                return;

            var data = ReadBytes(vehiclePointer + 0x30UL, 16);
            if (data.Length < 16)
                return;

            var x = BitConverter.ToSingle(data, 0);
            var y = BitConverter.ToSingle(data, 4);
            var z = BitConverter.ToSingle(data, 8);
            var w = BitConverter.ToSingle(data, 12);
            if (!IsFiniteFloat(x) || !IsFiniteFloat(y) || !IsFiniteFloat(z) || !IsFiniteFloat(w))
                return;

            var xyzLength = (float)Math.Sqrt((double)(x * x + y * y + z * z));
            var rowLength = (float)Math.Sqrt((double)(x * x + y * y + z * z + w * w));
            if (Math.Abs(w) < 0.05F && xyzLength > 0.01F && xyzLength < 250F)
            {
                WriteFloat(vehiclePointer + 0x30UL, 0F);
                WriteFloat(vehiclePointer + 0x34UL, 0F);
                WriteFloat(vehiclePointer + 0x38UL, 0F);
                WriteFloat(vehiclePointer + 0x3CUL, 0F);
                return;
            }
            if (rowLength > 0.75F && rowLength < 1.25F)
                return;
            if (xyzLength < 0.05F || xyzLength > 250F)
                return;

            WriteFloat(vehiclePointer + 0x30UL, 0F);
            WriteFloat(vehiclePointer + 0x34UL, 0F);
            WriteFloat(vehiclePointer + 0x38UL, 0F);
        }

        private void ReadHoverInput(out float side, out float forward, out float vertical, out float yawAdjust, out float nudgeSide, out float nudgeForward)
        {
            side = 0F;
            forward = 0F;
            yawAdjust = 0F;
            nudgeSide = 0F;
            nudgeForward = 0F;

            if (IsKeyDown((int)Keys.A))
                side -= 1F;
            if (IsKeyDown((int)Keys.D))
                side += 1F;
            if (IsKeyDown((int)Keys.W))
                forward += 1F;
            if (IsKeyDown((int)Keys.S) || IsKeyDown((int)Keys.B))
                forward -= 1F;

            if (IsKeyDown((int)Keys.Left))
                nudgeSide -= 1F;
            if (IsKeyDown((int)Keys.Right))
                nudgeSide += 1F;
            if (IsKeyDown((int)Keys.Up))
                nudgeForward += 1F;
            if (IsKeyDown((int)Keys.Down))
                nudgeForward -= 1F;

            side = Math.Max(-1F, Math.Min(1F, side));
            forward = Math.Max(-1F, Math.Min(1F, forward));
            yawAdjust = Math.Max(-1F, Math.Min(1F, yawAdjust));
            nudgeSide = Math.Max(-1F, Math.Min(1F, nudgeSide));
            nudgeForward = Math.Max(-1F, Math.Min(1F, nudgeForward));

            vertical = 0F;
            var rise = IsKeyDown((int)Keys.Space) ||
                (_jumpGuardVirtualKey > 0 && IsKeyDown(_jumpGuardVirtualKey));
            var sink = IsKeyDown((int)Keys.ControlKey) ||
                IsKeyDown((int)Keys.LControlKey) ||
                IsKeyDown((int)Keys.RControlKey);

            if (rise && !sink)
                vertical = 1F;
            else if (sink && !rise)
                vertical = -1F;
        }

        private void StartNoClipGuard(
            RuntimeDetour vehicleDetour,
            RuntimeDetour cameraDetour,
            RuntimeProfileHookDescriptor cameraDescriptor,
            int virtualKey)
        {
            StopNoClipGuard();

            _noClipGuardDetour = vehicleDetour;
            _noClipCameraDetour = cameraDetour;
            _noClipCameraDescriptor = cameraDescriptor;
            _noClipGuardVirtualKey = virtualKey;
            _noClipLastVehiclePointer = 0;
            _noClipLastDirX = 0F;
            _noClipLastDirZ = 0F;
            _noClipLastSpeed = 0F;
            _noClipLastPosX = 0F;
            _noClipLastPosZ = 0F;
            _noClipHoldX = 0F;
            _noClipHoldZ = 0F;
            _noClipLastDirectionTicks = 0;
            _noClipDirectionCaptured = false;
            _noClipPhaseActive = false;

            ApplyNoClipToCurrentVehicle();

            if (_noClipGuardTimer == null)
                _noClipGuardTimer = new System.Threading.Timer(NoClipGuardTick, null, 0, 16);
            else
                _noClipGuardTimer.Change(0, 16);
        }

        private void StopNoClipGuard()
        {
            var timer = _noClipGuardTimer;
            _noClipGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _noClipGuardDetour = null;
            _noClipCameraDetour = null;
            _noClipCameraDescriptor = null;
            _noClipGuardVirtualKey = 0;
            _noClipLastVehiclePointer = 0;
            _noClipLastDirX = 0F;
            _noClipLastDirZ = 0F;
            _noClipLastSpeed = 0F;
            _noClipLastPosX = 0F;
            _noClipLastPosZ = 0F;
            _noClipHoldX = 0F;
            _noClipHoldZ = 0F;
            _noClipLastDirectionTicks = 0;
            _noClipDirectionCaptured = false;
            _noClipPhaseActive = false;
        }

        private void NoClipGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _noClipGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive || _noClipGuardDetour == null || _noClipGuardDetour.DetourAddress == 0)
                    return;

                ApplyNoClipToCurrentVehicle();
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("No Clip", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _noClipGuardRunning, 0);
            }
        }

        private void ApplyNoClipToCurrentVehicle()
        {
            var detour = _noClipGuardDetour;
            if (detour == null || detour.DetourAddress == 0)
                return;

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(detour.DetourAddress + (ulong)layout.VehiclePointerOffset);
            if (vehiclePointer == 0)
                return;

            if (vehiclePointer != _noClipLastVehiclePointer)
            {
                _noClipLastVehiclePointer = vehiclePointer;
                _noClipDirectionCaptured = false;
                _noClipLastDirectionTicks = 0;
                _noClipPhaseActive = false;
            }

            if (!IsWritableMemoryRange(vehiclePointer + 0x20UL, 12) || !IsWritableMemoryRange(vehiclePointer + 0x50UL, 12))
                return;

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
            var position = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (velocity.Length < 12 || position.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vz = BitConverter.ToSingle(velocity, 8);
            var px = BitConverter.ToSingle(position, 0);
            var pz = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vz) || !IsFiniteFloat(px) || !IsFiniteFloat(pz))
                return;

            var speed = (float)Math.Sqrt((double)(vx * vx + vz * vz));
            if (_noClipGuardVirtualKey <= 0 || !IsKeyDown(_noClipGuardVirtualKey))
            {
                _noClipDirectionCaptured = false;
                _noClipLastDirX = 0F;
                _noClipLastDirZ = 0F;
                _noClipLastSpeed = 0F;
                _noClipLastDirectionTicks = 0;
                _noClipPhaseActive = false;
                _noClipLastPosX = px;
                _noClipLastPosZ = pz;
                return;
            }

            var nowTicks = DateTime.UtcNow.Ticks;
            var deltaSeconds = _noClipLastDirectionTicks == 0
                ? 0.016F
                : Math.Max(0.004F, Math.Min(0.05F, (float)((nowTicks - _noClipLastDirectionTicks) / (double)TimeSpan.TicksPerSecond)));

            float side;
            float forward;
            ReadNoClipMovementInput(out side, out forward);
            NormalizeAirControlDirection(ref side, ref forward);

            var hasInput = Math.Abs(side) > 0.01F || Math.Abs(forward) > 0.01F;

            float baseDirX;
            float baseDirZ;
            if (!TryReadNoClipCameraDirection(vehiclePointer, out baseDirX, out baseDirZ))
            {
                baseDirX = _noClipLastDirX;
                baseDirZ = _noClipLastDirZ;
                if (!_noClipDirectionCaptured && speed > 1.25F)
                    TryNormalizeFlyDirection(vx, vz, out baseDirX, out baseDirZ);
            }

            float phaseDirX;
            float phaseDirZ;
            if (!TryNormalizeFlyDirection(baseDirX, baseDirZ, out baseDirX, out baseDirZ))
            {
                baseDirX = 0F;
                baseDirZ = -1F;
            }

            if (hasInput)
            {
                var sideDirX = -baseDirZ;
                var sideDirZ = baseDirX;
                if (!TryNormalizeFlyDirection((baseDirX * forward) + (sideDirX * side), (baseDirZ * forward) + (sideDirZ * side), out phaseDirX, out phaseDirZ))
                    return;
            }
            else
            {
                phaseDirX = baseDirX;
                phaseDirZ = baseDirZ;
            }

            if (!_noClipPhaseActive)
            {
                _noClipHoldX = px;
                _noClipHoldZ = pz;
                _noClipPhaseActive = true;
            }

            var phaseSpeed = 42F;
            if (hasInput)
            {
                var step = Math.Max(0.18F, Math.Min(0.80F, phaseSpeed * deltaSeconds));
                _noClipHoldX += phaseDirX * step;
                _noClipHoldZ += phaseDirZ * step;
            }

            var newX = _noClipHoldX;
            var newZ = _noClipHoldZ;
            if (!IsFiniteFloat(newX) || !IsFiniteFloat(newZ))
            {
                _noClipPhaseActive = false;
                return;
            }

            WriteFloat(vehiclePointer + 0x50UL, newX);
            WriteFloat(vehiclePointer + 0x58UL, newZ);
            WriteFloat(vehiclePointer + 0x20UL, 0F);
            WriteFloat(vehiclePointer + 0x28UL, 0F);
            DampHoverSpin(vehiclePointer);
            LockFlyVehicleFlat(vehiclePointer, phaseDirX, phaseDirZ);

            _noClipLastDirX = phaseDirX;
            _noClipLastDirZ = phaseDirZ;
            _noClipLastSpeed = phaseSpeed;
            _noClipLastDirectionTicks = nowTicks;
            _noClipDirectionCaptured = true;
            _noClipLastPosX = newX;
            _noClipLastPosZ = newZ;
        }

        private bool TryReadNoClipCameraDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            var detour = _noClipCameraDetour;
            var descriptor = _noClipCameraDescriptor;
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return false;

            if (descriptor.ObjectPointerOffset >= 0)
            {
                var cameraObject = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (cameraObject != 0)
                {
                    if (TryReadCameraPositionDirection(cameraObject, vehiclePointer, out dirX, out dirZ))
                        return true;

                    if (IsReadableMemoryRange(cameraObject, 16))
                    {
                        var live = ReadBytes(cameraObject, 16);
                        if (live.Length >= 12)
                        {
                            var liveX = BitConverter.ToSingle(live, 0);
                            var liveZ = BitConverter.ToSingle(live, 8);
                            if (TryNormalizeFlyDirection(-liveX, -liveZ, out dirX, out dirZ))
                                return true;
                        }
                    }
                }
            }

            return false;
        }

        private bool TryReadCameraPositionDirection(ulong cameraObject, ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (cameraObject == 0 || vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x50UL, 12))
                return false;

            var vehicle = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (vehicle.Length < 12)
                return false;

            var px = BitConverter.ToSingle(vehicle, 0);
            var pz = BitConverter.ToSingle(vehicle, 8);
            if (!IsFiniteFloat(px) || !IsFiniteFloat(pz))
                return false;

            var candidateOffsets = new ulong[] { 0x00UL, 0x10UL, 0x20UL, 0x30UL, 0x40UL, 0x50UL, 0x60UL, 0x70UL, 0x80UL };
            foreach (var offset in candidateOffsets)
            {
                var address = cameraObject + offset;
                if (!IsReadableMemoryRange(address, 12))
                    continue;

                var data = ReadBytes(address, 12);
                if (data.Length < 12)
                    continue;

                var cx = BitConverter.ToSingle(data, 0);
                var cz = BitConverter.ToSingle(data, 8);
                if (!IsFiniteFloat(cx) || !IsFiniteFloat(cz))
                    continue;

                var dx = px - cx;
                var dz = pz - cz;
                var distance = (float)Math.Sqrt((double)(dx * dx + dz * dz));
                if (distance >= 1F && distance <= 250F && TryNormalizeFlyDirection(dx, dz, out dirX, out dirZ))
                    return true;
            }

            return false;
        }

        private static void ReadNoClipMovementInput(out float side, out float forward)
        {
            side = 0F;
            forward = 0F;

            if (IsKeyDown((int)Keys.A))
                side -= 1F;
            if (IsKeyDown((int)Keys.D))
                side += 1F;
            if (IsKeyDown((int)Keys.W))
                forward += 1F;
            if (IsKeyDown((int)Keys.S) || IsKeyDown((int)Keys.B))
                forward -= 1F;

            side = Math.Max(-1F, Math.Min(1F, side));
            forward = Math.Max(-1F, Math.Min(1F, forward));
        }

        private float GetPhaseDashDistanceMeters()
        {
            lock (_phaseDashConfigLock)
            {
                return _phaseDashDistanceMeters;
            }
        }

        private void StartPhaseDashGuard(RuntimeDetour vehicleDetour, int virtualKey)
        {
            StopPhaseDashGuard();

            _phaseDashGuardDetour = vehicleDetour;
            _phaseDashGuardVirtualKey = virtualKey;
            _phaseDashLastVehiclePointer = 0;
            _phaseDashKeyLastState = false;
            _phaseDashCooldownUntilUtcTicks = 0;
            _phaseDashDirX = 0F;
            _phaseDashDirZ = -1F;
            _phaseDashMomentumVehiclePointer = 0;
            _phaseDashMomentumVelocity = null;
            _phaseDashMomentumUntilUtcTicks = 0;

            try
            {
                _phaseDashGuardTimer = new System.Threading.Timer(PhaseDashGuardTick, null, 0, 16);
            }
            catch
            {
                StopPhaseDashGuard();
                throw;
            }
        }

        private void StopPhaseDashGuard()
        {
            var timer = _phaseDashGuardTimer;
            _phaseDashGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _phaseDashGuardDetour = null;
            _phaseDashGuardVirtualKey = 0;
            _phaseDashKeyLastState = false;
            _phaseDashCooldownUntilUtcTicks = 0;
            _phaseDashLastVehiclePointer = 0;
            _phaseDashDirX = 0F;
            _phaseDashDirZ = -1F;
            _phaseDashMomentumVehiclePointer = 0;
            _phaseDashMomentumVelocity = null;
            _phaseDashMomentumUntilUtcTicks = 0;
        }

        private void PhaseDashGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _phaseDashGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive || _phaseDashGuardDetour == null || _phaseDashGuardDetour.DetourAddress == 0)
                    return;

                var nowTicks = DateTime.UtcNow.Ticks;
                ApplyPendingPhaseDashMomentum(nowTicks);

                var pressed = _phaseDashGuardVirtualKey > 0 && IsKeyDown(_phaseDashGuardVirtualKey);
                if (!pressed)
                {
                    _phaseDashKeyLastState = false;
                    return;
                }

                if (_phaseDashKeyLastState)
                    return;

                _phaseDashKeyLastState = true;
                if (nowTicks < _phaseDashCooldownUntilUtcTicks)
                    return;

                if (ApplyPhaseDashToCurrentVehicle())
                    _phaseDashCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * PhaseDashCooldownMilliseconds;
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Phase Dash", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _phaseDashGuardRunning, 0);
            }
        }

        private bool ApplyPhaseDashToCurrentVehicle()
        {
            var detour = _phaseDashGuardDetour;
            if (detour == null || detour.DetourAddress == 0)
                return false;

            var vehiclePointer = ReadCurrentVehiclePointer(detour);
            if (vehiclePointer == 0)
                return false;

            if (!IsWritableMemoryRange(vehiclePointer + 0x50UL, 16))
                return false;

            var position = ReadBytes(vehiclePointer + 0x50UL, 16);
            if (position.Length < 16)
                return false;

            byte[] velocity = null;
            if (IsReadableMemoryRange(vehiclePointer + 0x20UL, 16))
            {
                velocity = ReadBytes(vehiclePointer + 0x20UL, 16);
                if (velocity.Length < 16 || !IsValidPhaseDashVelocity(velocity))
                    velocity = null;
            }

            var px = BitConverter.ToSingle(position, 0);
            var py = BitConverter.ToSingle(position, 4);
            var pz = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(px) || !IsFiniteFloat(py) || !IsFiniteFloat(pz))
                return false;

            if (vehiclePointer != _phaseDashLastVehiclePointer)
            {
                _phaseDashLastVehiclePointer = vehiclePointer;
                _phaseDashDirX = 0F;
                _phaseDashDirZ = -1F;
            }

            var dirX = 0F;
            var dirZ = -1F;
            var hasDirection = TryReadPhaseDashForwardDirection(vehiclePointer, velocity, out dirX, out dirZ);
            if (!hasDirection)
            {
                LogRuntimeGuardWaiting("Phase Dash", new InvalidOperationException("vehicle forward momentum direction is not ready yet"));
                return false;
            }

            var distance = GetPhaseDashDistanceMeters();
            var target = CopyTeleportPosition(position);
            Buffer.BlockCopy(BitConverter.GetBytes(px + dirX * distance), 0, target, 0, 4);
            Buffer.BlockCopy(BitConverter.GetBytes(py), 0, target, 4, 4);
            Buffer.BlockCopy(BitConverter.GetBytes(pz + dirZ * distance), 0, target, 8, 4);

            QueueVehicleControlTeleport(detour, target);
            WriteBytes(vehiclePointer + 0x50UL, target);
            SyncFlyHoldToTeleport(target, false);
            if (velocity != null && velocity.Length >= 16 && IsWritableMemoryRange(vehiclePointer + 0x20UL, 16))
            {
                WriteBytes(vehiclePointer + 0x20UL, velocity);
                _phaseDashMomentumVehiclePointer = vehiclePointer;
                _phaseDashMomentumVelocity = velocity;
                _phaseDashMomentumUntilUtcTicks = DateTime.UtcNow.Ticks + TimeSpan.TicksPerMillisecond * PhaseDashMomentumRestoreMilliseconds;
            }

            _phaseDashDirX = dirX;
            _phaseDashDirZ = dirZ;
            _log("Phase Dash moved forward " + FormatFloatInvariant(distance) + " m to " + FormatTeleportPosition(target) + ".");
            return true;
        }

        private bool TryReadPhaseDashForwardDirection(ulong vehiclePointer, byte[] velocity, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x40UL, 16))
                return false;

            var data = ReadBytes(vehiclePointer + 0x40UL, 16);
            if (data.Length < 16)
                return false;

            var qx = BitConverter.ToSingle(data, 0);
            var qy = BitConverter.ToSingle(data, 4);
            var qz = BitConverter.ToSingle(data, 8);
            var qw = BitConverter.ToSingle(data, 12);
            if (!IsFiniteFloat(qx) || !IsFiniteFloat(qy) || !IsFiniteFloat(qz) || !IsFiniteFloat(qw))
                return false;

            var candidateX = new float[4];
            var candidateZ = new float[4];
            var candidateCount = 0;

            var length = (float)Math.Sqrt((double)((qx * qx) + (qy * qy) + (qz * qz) + (qw * qw)));
            if (IsFiniteFloat(length) && length >= 0.25F && length <= 4F)
            {
                var nx = qx / length;
                var ny = qy / length;
                var nz = qz / length;
                var nw = qw / length;

                AddPhaseDashDirectionCandidate(2F * ((nx * nz) + (nw * ny)), 1F - (2F * ((nx * nx) + (ny * ny))), candidateX, candidateZ, ref candidateCount);
            }

            if (Math.Abs(qy) > 0.0001F || Math.Abs(qw) > 0.0001F)
            {
                var yaw = (float)(2.0 * Math.Atan2((double)qy, (double)qw));
                AddPhaseDashDirectionCandidate((float)Math.Sin((double)yaw), (float)Math.Cos((double)yaw), candidateX, candidateZ, ref candidateCount);
            }

            AddPhaseDashDirectionCandidate(qx, qz, candidateX, candidateZ, ref candidateCount);

            if (candidateCount <= 0)
                return false;

            float momentumX;
            float momentumZ;
            if (TryReadPhaseDashMomentumDirection(velocity, out momentumX, out momentumZ))
            {
                var bestX = candidateX[0];
                var bestZ = candidateZ[0];
                var bestDot = bestX * momentumX + bestZ * momentumZ;

                for (var i = 0; i < candidateCount; i++)
                {
                    var dot = candidateX[i] * momentumX + candidateZ[i] * momentumZ;
                    if (dot > bestDot)
                    {
                        bestDot = dot;
                        bestX = candidateX[i];
                        bestZ = candidateZ[i];
                    }

                    var flippedDot = -dot;
                    if (flippedDot > bestDot)
                    {
                        bestDot = flippedDot;
                        bestX = -candidateX[i];
                        bestZ = -candidateZ[i];
                    }
                }

                if (bestDot >= 0.35F && TryNormalizeFlyDirection(bestX, bestZ, out dirX, out dirZ))
                    return true;
            }

            dirX = candidateX[0];
            dirZ = candidateZ[0];
            return true;
        }

        private static void AddPhaseDashDirectionCandidate(float x, float z, float[] candidateX, float[] candidateZ, ref int candidateCount)
        {
            float dirX;
            float dirZ;
            if (candidateX == null || candidateZ == null || candidateCount >= candidateX.Length || !TryNormalizeFlyDirection(x, z, out dirX, out dirZ))
                return;

            for (var i = 0; i < candidateCount; i++)
            {
                var dot = (candidateX[i] * dirX) + (candidateZ[i] * dirZ);
                if (dot > 0.985F)
                    return;
            }

            candidateX[candidateCount] = dirX;
            candidateZ[candidateCount] = dirZ;
            candidateCount++;
        }

        private static bool TryReadPhaseDashMomentumDirection(byte[] velocity, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            if (velocity == null || velocity.Length < 12)
                return false;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vz))
                return false;

            var horizontalSpeed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            if (!IsFiniteFloat(horizontalSpeed) || horizontalSpeed < 1.5F)
                return false;

            return TryNormalizeFlyDirection(vx, vz, out dirX, out dirZ);
        }

        private void ApplyPendingPhaseDashMomentum(long nowTicks)
        {
            var velocity = _phaseDashMomentumVelocity;
            var vehiclePointer = _phaseDashMomentumVehiclePointer;
            if (velocity == null || velocity.Length < 16 || vehiclePointer == 0)
                return;

            if (nowTicks > _phaseDashMomentumUntilUtcTicks)
            {
                _phaseDashMomentumVehiclePointer = 0;
                _phaseDashMomentumVelocity = null;
                _phaseDashMomentumUntilUtcTicks = 0;
                return;
            }

            if (IsAlive && IsWritableMemoryRange(vehiclePointer + 0x20UL, 16))
                WriteBytes(vehiclePointer + 0x20UL, velocity);
        }

        private static bool IsValidPhaseDashVelocity(byte[] velocity)
        {
            if (velocity == null || velocity.Length < 12)
                return false;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return false;

            var speedSquared = (vx * vx) + (vy * vy) + (vz * vz);
            return IsFiniteFloat(speedSquared) && speedSquared < 25000000F;
        }

        private static bool IsValidFiniteVector3(byte[] data, float maxAbs)
        {
            if (data == null || data.Length < 12 || !IsFiniteFloat(maxAbs) || maxAbs <= 0F)
                return false;

            var x = BitConverter.ToSingle(data, 0);
            var y = BitConverter.ToSingle(data, 4);
            var z = BitConverter.ToSingle(data, 8);
            return IsFiniteFloat(x) && IsFiniteFloat(y) && IsFiniteFloat(z) &&
                   Math.Abs(x) <= maxAbs && Math.Abs(y) <= maxAbs && Math.Abs(z) <= maxAbs;
        }

        private static bool IsValidRewindPosition(byte[] position)
        {
            if (position == null || position.Length < 12)
                return false;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            return IsWorldPosition(x, y, z);
        }

        private float GetRewindBufferSeconds()
        {
            lock (_rewindConfigLock)
            {
                return _rewindBufferSeconds;
            }
        }

        private float GetRewindScrubSpeed()
        {
            lock (_rewindConfigLock)
            {
                return _rewindScrubSpeed;
            }
        }

        private void EnsureRewindBufferCapacity()
        {
            var seconds = GetRewindBufferSeconds();
            var capacity = (int)Math.Ceiling(seconds * 1000F / RewindGuardIntervalMilliseconds);
            capacity = Math.Max(128, Math.Min(RewindMaxSampleCount, capacity));

            lock (_rewindBufferLock)
            {
                if (_rewindSamples != null && _rewindSamples.Length == capacity)
                    return;

                _rewindSamples = new RewindVehicleSample[capacity];
                _rewindWriteIndex = 0;
                _rewindSampleCount = 0;
                _rewindActive = false;
                _rewindReadIndex = 0;
                _rewindRemainingSamples = 0;
                _rewindScrubAccumulator = 0F;
                _rewindResumeVehiclePointer = 0;
                _rewindResumeVelocity = null;
            }
        }

        private void StartRewindGuard(RuntimeDetour vehicleDetour, int virtualKey)
        {
            StopRewindGuard();

            _rewindGuardDetour = vehicleDetour;
            _rewindGuardVirtualKey = virtualKey;
            _rewindLastVehiclePointer = 0;
            _rewindLastStatusLogUtcTicks = 0;
            EnsureRewindBufferCapacity();

            try
            {
                _rewindGuardTimer = new System.Threading.Timer(RewindGuardTick, null, 0, RewindGuardIntervalMilliseconds);
            }
            catch
            {
                StopRewindGuard();
                throw;
            }
        }

        private void StopRewindGuard()
        {
            var timer = _rewindGuardTimer;
            _rewindGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _rewindGuardDetour = null;
            _rewindGuardVirtualKey = 0;
            _rewindLastVehiclePointer = 0;
            _rewindLastStatusLogUtcTicks = 0;
            lock (_rewindBufferLock)
            {
                _rewindSamples = new RewindVehicleSample[0];
                _rewindWriteIndex = 0;
                _rewindSampleCount = 0;
                _rewindActive = false;
                _rewindReadIndex = 0;
                _rewindRemainingSamples = 0;
                _rewindScrubAccumulator = 0F;
                _rewindResumeVehiclePointer = 0;
                _rewindResumeVelocity = null;
            }
        }

        private void RewindGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _rewindGuardRunning, 1) == 1)
                return;

            try
            {
                var detour = _rewindGuardDetour;
                if (!IsAlive || detour == null || detour.DetourAddress == 0)
                    return;

                var vehiclePointer = ReadCurrentVehiclePointer(detour);
                if (vehiclePointer == 0)
                    return;

                if (vehiclePointer != _rewindLastVehiclePointer)
                {
                    _rewindLastVehiclePointer = vehiclePointer;
                    lock (_rewindBufferLock)
                    {
                        _rewindWriteIndex = 0;
                        _rewindSampleCount = 0;
                        _rewindActive = false;
                        _rewindReadIndex = 0;
                        _rewindRemainingSamples = 0;
                        _rewindScrubAccumulator = 0F;
                        _rewindResumeVehiclePointer = 0;
                        _rewindResumeVelocity = null;
                    }
                }

                var pressed = _rewindGuardVirtualKey > 0 && IsKeyDown(_rewindGuardVirtualKey);
                if (pressed)
                    ApplyRewindScrub(vehiclePointer);
                else
                {
                    var restoreResume = false;
                    lock (_rewindBufferLock)
                    {
                        restoreResume = _rewindActive;
                        _rewindActive = false;
                        _rewindRemainingSamples = 0;
                        _rewindScrubAccumulator = 0F;
                    }

                    if (restoreResume)
                        RestoreRewindResumeVelocity(vehiclePointer);

                    RecordRewindSample(vehiclePointer);
                }
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Rewind", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _rewindGuardRunning, 0);
            }
        }

        private void RecordRewindSample(ulong vehiclePointer)
        {
            if (vehiclePointer == 0)
                return;
            if (!IsReadableMemoryRange(vehiclePointer + (ulong)VehiclePositionOffset, 12))
            {
                return;
            }

            var position = ReadBytes(vehiclePointer + (ulong)VehiclePositionOffset, 12);
            if (!IsValidRewindPosition(position))
                return;

            var velocity = new byte[16];
            if (IsReadableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 16))
            {
                var liveVelocity = ReadBytes(vehiclePointer + (ulong)VehicleVelocityOffset, 16);
                if (IsValidFiniteVector3(liveVelocity, 5000F))
                    Buffer.BlockCopy(liveVelocity, 0, velocity, 0, Math.Min(16, liveVelocity.Length));
            }

            var angular = new byte[16];
            if (IsReadableMemoryRange(vehiclePointer + (ulong)VehicleAngularVelocityOffset, 16))
            {
                var liveAngular = ReadBytes(vehiclePointer + (ulong)VehicleAngularVelocityOffset, 16);
                if (IsValidFiniteVector3(liveAngular, 5000F))
                    Buffer.BlockCopy(liveAngular, 0, angular, 0, Math.Min(16, liveAngular.Length));
            }

            byte[] rotation = null;
            if (IsReadableMemoryRange(vehiclePointer + 0x40UL, 16))
            {
                var liveRotation = ReadBytes(vehiclePointer + 0x40UL, 16);
                if (IsValidVehicleQuaternion(liveRotation))
                {
                    rotation = new byte[16];
                    Buffer.BlockCopy(liveRotation, 0, rotation, 0, Math.Min(16, liveRotation.Length));
                }
            }

            lock (_rewindBufferLock)
            {
                if (_rewindSamples.Length == 0)
                    return;

                _rewindSamples[_rewindWriteIndex] = new RewindVehicleSample(position, velocity, angular, rotation);
                _rewindWriteIndex = (_rewindWriteIndex + 1) % _rewindSamples.Length;
                if (_rewindSampleCount < _rewindSamples.Length)
                    _rewindSampleCount++;
            }
        }

        private void EnsureRewindBufferCapacityLocked()
        {
            var seconds = GetRewindBufferSeconds();
            var capacity = (int)Math.Ceiling(seconds * 1000F / RewindGuardIntervalMilliseconds);
            capacity = Math.Max(128, Math.Min(RewindMaxSampleCount, capacity));
            if (_rewindSamples != null && _rewindSamples.Length == capacity)
                return;

            _rewindSamples = new RewindVehicleSample[capacity];
            _rewindWriteIndex = 0;
            _rewindSampleCount = 0;
            _rewindActive = false;
            _rewindReadIndex = 0;
            _rewindRemainingSamples = 0;
            _rewindScrubAccumulator = 0F;
            _rewindResumeVehiclePointer = 0;
            _rewindResumeVelocity = null;
        }

        private void ApplyRewindScrub(ulong vehiclePointer)
        {
            RewindVehicleSample sample = null;
            lock (_rewindBufferLock)
            {
                if (_rewindSamples == null || _rewindSamples.Length == 0 || _rewindSampleCount <= 1)
                {
                    MaybeLogRewindStatus("Rewind is armed but waiting for movement samples. Drive for a moment, then hold the Rewind key.");
                    return;
                }

                if (!_rewindActive)
                {
                    _rewindActive = true;
                    _rewindReadIndex = (_rewindWriteIndex - 1 + _rewindSamples.Length) % _rewindSamples.Length;
                    _rewindRemainingSamples = _rewindSampleCount;
                    _rewindScrubAccumulator = 0F;
                    MaybeLogRewindStatus("Rewind scrubbing " + _rewindSampleCount.ToString(CultureInfo.InvariantCulture) + " recorded sample(s).");
                }

                var speed = Math.Max(0.25F, Math.Min(5F, GetRewindScrubSpeed()));
                _rewindScrubAccumulator += speed;
                var steps = (int)Math.Floor((double)_rewindScrubAccumulator);
                if (steps <= 0)
                    steps = 0;
                else
                    _rewindScrubAccumulator -= steps;

                while (steps-- > 0 && _rewindRemainingSamples > 1)
                {
                    _rewindReadIndex = (_rewindReadIndex - 1 + _rewindSamples.Length) % _rewindSamples.Length;
                    _rewindRemainingSamples--;
                }

                sample = _rewindSamples[_rewindReadIndex];
            }

            if (sample != null)
                ApplyRewindSample(vehiclePointer, sample);
        }

        private void ApplyRewindSample(ulong vehiclePointer, RewindVehicleSample sample)
        {
            if (vehiclePointer == 0 || sample == null)
                return;
            if (!IsWritableMemoryRange(vehiclePointer + (ulong)VehiclePositionOffset, 12))
            {
                return;
            }
            if (!IsValidRewindPosition(sample.Position))
                return;

            var x = BitConverter.ToSingle(sample.Position, 0);
            var y = BitConverter.ToSingle(sample.Position, 4);
            var z = BitConverter.ToSingle(sample.Position, 8);
            var zero = new byte[16];
            _rewindResumeVehiclePointer = vehiclePointer;
            _rewindResumeVelocity = CopyTeleportPosition(sample.Velocity);

            if (sample.Rotation != null && IsValidVehicleQuaternion(sample.Rotation) && IsWritableMemoryRange(vehiclePointer + 0x40UL, 16))
                WriteBytes(vehiclePointer + 0x40UL, sample.Rotation);
            if (IsWritableMemoryRange(vehiclePointer + (ulong)VehicleAngularVelocityOffset, 16))
                WriteBytes(vehiclePointer + (ulong)VehicleAngularVelocityOffset, zero);
            if (IsWritableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 16))
                WriteBytes(vehiclePointer + (ulong)VehicleVelocityOffset, zero);

            var queuedPosition = CopyTeleportPosition(sample.Position);
            var detour = _rewindGuardDetour;
            if (detour != null && detour.DetourAddress != 0)
                QueueVehicleControlTeleport(detour, queuedPosition);

            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset, x);
            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset + 4UL, y);
            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset + 8UL, z);
            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset, x);
            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset + 4UL, y);
            WriteFloat(vehiclePointer + (ulong)VehiclePositionOffset + 8UL, z);
            SyncFlyHoldToTeleport(sample.Position, false);
        }

        private void MaybeLogRewindStatus(string message)
        {
            var nowTicks = DateTime.UtcNow.Ticks;
            var lastTicks = _rewindLastStatusLogUtcTicks;
            if (lastTicks != 0 && nowTicks - lastTicks < TimeSpan.TicksPerSecond * 2)
                return;

            _rewindLastStatusLogUtcTicks = nowTicks;
            _log(message);
        }

        private void RestoreRewindResumeVelocity(ulong vehiclePointer)
        {
            var velocity = _rewindResumeVelocity;
            if (vehiclePointer == 0 ||
                _rewindResumeVehiclePointer != vehiclePointer ||
                velocity == null ||
                velocity.Length < 12 ||
                !IsValidFiniteVector3(velocity, 5000F) ||
                !IsWritableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 16))
            {
                _rewindResumeVehiclePointer = 0;
                _rewindResumeVelocity = null;
                return;
            }

            WriteBytes(vehiclePointer + (ulong)VehicleVelocityOffset, velocity);
            _rewindResumeVehiclePointer = 0;
            _rewindResumeVelocity = null;
        }

        private static bool IsValidVehicleQuaternion(byte[] rotation)
        {
            if (rotation == null || rotation.Length < 16)
                return false;

            var qx = BitConverter.ToSingle(rotation, 0);
            var qy = BitConverter.ToSingle(rotation, 4);
            var qz = BitConverter.ToSingle(rotation, 8);
            var qw = BitConverter.ToSingle(rotation, 12);
            if (!IsFiniteFloat(qx) || !IsFiniteFloat(qy) || !IsFiniteFloat(qz) || !IsFiniteFloat(qw))
                return false;

            var lengthSq = (qx * qx) + (qy * qy) + (qz * qz) + (qw * qw);
            return IsFiniteFloat(lengthSq) && lengthSq >= 0.16F && lengthSq <= 4F;
        }

        private void StartGrapplingHookGuard(
            RuntimeDetour vehicleDetour,
            RuntimeDetour cameraDetour,
            RuntimeProfileHookDescriptor cameraDescriptor,
            int virtualKey)
        {
            StopGrapplingHookGuard();

            _grapplingHookGuardDetour = vehicleDetour;
            _grapplingHookCameraDetour = cameraDetour;
            _grapplingHookCameraDescriptor = cameraDescriptor;
            _grapplingHookVirtualKey = virtualKey;
            _grapplingHookActive = false;
            _grapplingHookLastVehiclePointer = 0;
            _grapplingHookCurrentSpeed = 0F;
            _grapplingHookLastTickUtcTicks = 0;
            _grapplingHookDirX = 0F;
            _grapplingHookDirY = 0F;
            _grapplingHookDirZ = -1F;

            try
            {
                _grapplingHookGuardTimer = new System.Threading.Timer(GrapplingHookGuardTick, null, 0, GrapplingHookGuardIntervalMilliseconds);
            }
            catch
            {
                StopGrapplingHookGuard();
                throw;
            }
        }

        private void StopGrapplingHookGuard()
        {
            var timer = _grapplingHookGuardTimer;
            _grapplingHookGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _grapplingHookGuardDetour = null;
            _grapplingHookCameraDetour = null;
            _grapplingHookCameraDescriptor = null;
            _grapplingHookVirtualKey = 0;
            _grapplingHookActive = false;
            _grapplingHookLastVehiclePointer = 0;
            _grapplingHookCurrentSpeed = 0F;
            _grapplingHookLastTickUtcTicks = 0;
            _grapplingHookDirX = 0F;
            _grapplingHookDirY = 0F;
            _grapplingHookDirZ = -1F;
        }

        private void GrapplingHookGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _grapplingHookGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive || _grapplingHookGuardDetour == null || _grapplingHookGuardDetour.DetourAddress == 0)
                    return;

                ApplyGrapplingHookToCurrentVehicle();
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Grappling Hook", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _grapplingHookGuardRunning, 0);
            }
        }

        private void ApplyGrapplingHookToCurrentVehicle()
        {
            var detour = _grapplingHookGuardDetour;
            if (detour == null || detour.DetourAddress == 0)
                return;

            var vehiclePointer = ReadCurrentVehiclePointer(detour);
            if (vehiclePointer == 0)
                return;

            var pressed = _grapplingHookVirtualKey > 0 && IsKeyDown(_grapplingHookVirtualKey);
            if (!pressed)
            {
                _grapplingHookActive = false;
                _grapplingHookCurrentSpeed = 0F;
                _grapplingHookLastTickUtcTicks = 0;
                return;
            }

            if (!IsReadableMemoryRange(vehiclePointer + (ulong)VehiclePositionOffset, 16) ||
                !IsReadableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 16) ||
                !IsWritableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 16))
            {
                return;
            }

            var position = ReadBytes(vehiclePointer + (ulong)VehiclePositionOffset, 16);
            var currentVelocity = ReadBytes(vehiclePointer + (ulong)VehicleVelocityOffset, 16);
            if (position.Length < 12 || currentVelocity.Length < 12 || !IsValidTeleportPosition(position))
                return;

            var px = BitConverter.ToSingle(position, 0);
            var py = BitConverter.ToSingle(position, 4);
            var pz = BitConverter.ToSingle(position, 8);
            var currentVy = BitConverter.ToSingle(currentVelocity, 4);
            if (!IsFiniteFloat(currentVy))
                currentVy = 0F;

            float targetDistance;
            float minimumSpeed;
            float maximumSpeed;
            float rampPerSecond;
            float verticalScale;
            lock (_grapplingHookConfigLock)
            {
                targetDistance = _grapplingHookTargetDistance;
                minimumSpeed = _grapplingHookMinimumSpeed;
                maximumSpeed = _grapplingHookMaximumSpeed;
                rampPerSecond = _grapplingHookRampPerSecond;
                verticalScale = _grapplingHookVerticalScale;
            }

            var nowTicks = DateTime.UtcNow.Ticks;
            var deltaSeconds = _grapplingHookLastTickUtcTicks == 0
                ? 0.016F
                : Math.Max(0.004F, Math.Min(0.05F, (float)((nowTicks - _grapplingHookLastTickUtcTicks) / (double)TimeSpan.TicksPerSecond)));
            _grapplingHookLastTickUtcTicks = nowTicks;

            float side;
            float forward;
            float vertical;
            float yawAdjust;
            float nudgeSide;
            float nudgeForward;
            ReadHoverInput(out side, out forward, out vertical, out yawAdjust, out nudgeSide, out nudgeForward);

            side = Math.Max(-1F, Math.Min(1F, side)) * FlySideInputSign;
            forward = Math.Max(-1F, Math.Min(1F, forward)) * FlyForwardInputSign;
            vertical = Math.Max(-1F, Math.Min(1F, vertical));

            float cameraX;
            float cameraZ;
            var hasCameraDirection = TryReadGrapplingHookCameraDirection(vehiclePointer, out cameraX, out cameraZ);

            float noseX;
            float noseZ;
            var hasNoseDirection = TryReadFlyVehicleNoseDirection(vehiclePointer, out noseX, out noseZ);

            float baseX;
            float baseZ;
            var hasManualInput = Math.Abs(side) > 0.01F || Math.Abs(forward) > 0.01F || Math.Abs(yawAdjust) > 0.01F;
            if (_grapplingHookActive &&
                vehiclePointer == _grapplingHookLastVehiclePointer &&
                hasManualInput &&
                TryNormalizeFlyDirection(_grapplingHookDirX, _grapplingHookDirZ, out baseX, out baseZ))
            {
            }
            else if (hasManualInput && hasNoseDirection)
            {
                baseX = noseX;
                baseZ = noseZ;
            }
            else if (hasCameraDirection)
            {
                baseX = cameraX;
                baseZ = cameraZ;
            }
            else if (hasNoseDirection)
            {
                baseX = noseX;
                baseZ = noseZ;
            }
            else
            {
                baseX = 0F;
                baseZ = -1F;
            }

            var steeringInput = (Math.Abs(yawAdjust) > 0.01F ? yawAdjust : side) * FlySteeringInputSign;
            if (Math.Abs(steeringInput) > 0.01F && TryNormalizeFlyDirection(baseX, baseZ, out baseX, out baseZ))
            {
                RotateFlyDirection(
                    baseX,
                    baseZ,
                    steeringInput * FlyFacingTurnRadiansPerSecond * deltaSeconds,
                    out baseX,
                    out baseZ);
            }

            if (!TryNormalizeFlyDirection(baseX, baseZ, out baseX, out baseZ))
                return;

            var sideDirX = -baseZ;
            var sideDirZ = baseX;
            var forwardInput = Math.Abs(forward) > 0.01F ? forward : 1F;
            var sideInfluence = Math.Abs(forward) > 0.01F ? side * 0.65F : side;
            var driveX = (baseX * forwardInput) + (sideDirX * sideInfluence);
            var driveZ = (baseZ * forwardInput) + (sideDirZ * sideInfluence);
            var driveMag = (float)Math.Sqrt((double)((driveX * driveX) + (driveZ * driveZ)));
            if (!IsFiniteFloat(driveMag) || driveMag < 0.05F)
            {
                driveX = baseX;
                driveZ = baseZ;
            }
            else
            {
                driveX /= driveMag;
                driveZ /= driveMag;
                if (!IsFiniteFloat(driveX) || !IsFiniteFloat(driveZ))
                {
                    driveX = baseX;
                    driveZ = baseZ;
                }
            }

            var verticalStrength = Math.Max(0F, Math.Min(1.5F, verticalScale));
            var verticalAssist = (currentVy * 0.66F) + (vertical * Math.Min(44F, maximumSpeed * 0.28F) * Math.Max(0.25F, verticalStrength));
            if (Math.Abs(vertical) <= 0.01F)
                verticalAssist += verticalStrength * 2.5F;
            verticalAssist = Math.Max(-34F, Math.Min(42F, verticalAssist));

            _grapplingHookTargetX = px + (driveX * targetDistance);
            _grapplingHookTargetY = py + (verticalAssist * Math.Max(1F, targetDistance / Math.Max(1F, maximumSpeed)));
            _grapplingHookTargetZ = pz + (driveZ * targetDistance);
            _grapplingHookDirX = driveX;
            _grapplingHookDirY = verticalAssist;
            _grapplingHookDirZ = driveZ;

            if (!_grapplingHookActive || vehiclePointer != _grapplingHookLastVehiclePointer)
            {
                _grapplingHookLastVehiclePointer = vehiclePointer;
                _grapplingHookActive = true;
                _grapplingHookCurrentSpeed = Math.Max(minimumSpeed, ReadVehicleHorizontalSpeed(vehiclePointer));
            }
            else
            {
                _grapplingHookCurrentSpeed = Math.Max(_grapplingHookCurrentSpeed, ReadVehicleHorizontalSpeed(vehiclePointer));
            }

            _grapplingHookCurrentSpeed = Math.Min(maximumSpeed, Math.Max(minimumSpeed, _grapplingHookCurrentSpeed + (rampPerSecond * deltaSeconds)));
            var vx = driveX * _grapplingHookCurrentSpeed;
            var vy = verticalAssist;
            var vz = driveZ * _grapplingHookCurrentSpeed;
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return;

            ApplyFlyAirDriveOrientation(vehiclePointer, steeringInput, deltaSeconds, driveX, driveZ);
            WriteFloat(vehiclePointer + (ulong)VehicleVelocityOffset, vx);
            WriteFloat(vehiclePointer + (ulong)VehicleVelocityOffset + 4UL, vy);
            WriteFloat(vehiclePointer + (ulong)VehicleVelocityOffset + 8UL, vz);
            WriteFloat(vehiclePointer + (ulong)VehicleVelocityOffset + 12UL, 0F);
        }

        private float ReadVehicleHorizontalSpeed(ulong vehiclePointer)
        {
            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + (ulong)VehicleVelocityOffset, 12))
                return 0F;
            var velocity = ReadBytes(vehiclePointer + (ulong)VehicleVelocityOffset, 12);
            if (velocity.Length < 12)
                return 0F;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vz))
                return 0F;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            return IsFiniteFloat(speed) ? speed : 0F;
        }

        private bool TryReadGrapplingHookCameraDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            var detour = _grapplingHookCameraDetour;
            var descriptor = _grapplingHookCameraDescriptor;
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return false;

            if (descriptor.ObjectPointerOffset >= 0)
            {
                var cameraObject = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (cameraObject != 0 && IsReadableMemoryRange(cameraObject, 16))
                {
                    var live = ReadBytes(cameraObject, 16);
                    if (live.Length >= 12)
                    {
                        var liveX = BitConverter.ToSingle(live, 0);
                        var liveZ = BitConverter.ToSingle(live, 8);
                        if (TryNormalizeFlyDirection(-liveX, -liveZ, out dirX, out dirZ))
                            return true;
                    }

                    if (TryReadCameraPositionDirection(cameraObject, vehiclePointer, out dirX, out dirZ))
                        return true;
                }
            }

            if (descriptor.CaptureOffset >= 0 && !string.Equals(descriptor.Key, "FovSlider", StringComparison.OrdinalIgnoreCase))
            {
                var captureAddress = detour.DetourAddress + (ulong)descriptor.CaptureOffset;
                if (IsReadableMemoryRange(captureAddress, 16))
                {
                    var data = ReadBytes(captureAddress, 16);
                    if (data.Length >= 12)
                    {
                        var x = BitConverter.ToSingle(data, 0);
                        var z = BitConverter.ToSingle(data, 8);
                        if (TryNormalizeFlyDirection(-x, -z, out dirX, out dirZ))
                            return true;
                    }
                }
            }

            return TryReadFlyVehicleNoseDirection(vehiclePointer, out dirX, out dirZ);
        }

        private static bool TryNormalizeGrapplingHookDirection(float x, float y, float z, float verticalScale, out float dirX, out float dirY, out float dirZ)
        {
            dirX = 0F;
            dirY = 0.08F;
            dirZ = -1F;

            if (!IsFiniteFloat(x) || !IsFiniteFloat(y) || !IsFiniteFloat(z))
                return false;

            y *= Math.Max(0F, Math.Min(1.5F, verticalScale));
            y = Math.Max(-0.75F, Math.Min(0.85F, y));

            var length = (float)Math.Sqrt((double)((x * x) + (y * y) + (z * z)));
            if (!IsFiniteFloat(length) || length < 0.05F || length > 5000F)
                return false;

            dirX = x / length;
            dirY = y / length;
            dirZ = z / length;
            return IsFiniteFloat(dirX) && IsFiniteFloat(dirY) && IsFiniteFloat(dirZ);
        }

        private void StartSuperStrengthGuard(
            RuntimeDetour vehicleDetour,
            RuntimeDetour cameraDetour,
            RuntimeProfileHookDescriptor cameraDescriptor,
            int virtualKey)
        {
            StopSuperStrengthGuard();

            _superStrengthGuardDetour = vehicleDetour;
            _superStrengthCameraDetour = cameraDetour;
            _superStrengthCameraDescriptor = cameraDescriptor;
            _superStrengthGuardVirtualKey = virtualKey;
            _superStrengthLastVehiclePointer = 0;
            _superStrengthLastDirX = 0F;
            _superStrengthLastDirZ = -1F;
            _superStrengthLastSpeed = 0F;
            _superStrengthLastTickUtcTicks = 0;

            ApplySuperStrengthToCurrentVehicle();

            if (_superStrengthGuardTimer == null)
                _superStrengthGuardTimer = new System.Threading.Timer(SuperStrengthGuardTick, null, 0, 16);
            else
                _superStrengthGuardTimer.Change(0, 16);
        }

        private void StopSuperStrengthGuard()
        {
            var timer = _superStrengthGuardTimer;
            _superStrengthGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            _superStrengthGuardDetour = null;
            _superStrengthCameraDetour = null;
            _superStrengthCameraDescriptor = null;
            _superStrengthGuardVirtualKey = 0;
            _superStrengthLastVehiclePointer = 0;
            _superStrengthLastDirX = 0F;
            _superStrengthLastDirZ = -1F;
            _superStrengthLastSpeed = 0F;
            _superStrengthLastTickUtcTicks = 0;
        }

        private void SuperStrengthGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _superStrengthGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive || _superStrengthGuardDetour == null || _superStrengthGuardDetour.DetourAddress == 0)
                    return;

                ApplySuperStrengthToCurrentVehicle();
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting("Super Strength", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _superStrengthGuardRunning, 0);
            }
        }

        private void ApplySuperStrengthToCurrentVehicle()
        {
            var detour = _superStrengthGuardDetour;
            if (detour == null || detour.DetourAddress == 0)
                return;

            float shoveSpeed;
            float minSpeed;
            float maxSpeed;
            float accelerationPerSecond;
            float verticalDamping;
            float verticalClamp;
            lock (_superStrengthConfigLock)
            {
                shoveSpeed = _superStrengthShoveSpeed;
                minSpeed = _superStrengthMinSpeed;
                maxSpeed = _superStrengthMaxSpeed;
                accelerationPerSecond = _superStrengthAccelerationPerSecond;
                verticalDamping = _superStrengthVerticalDamping;
                verticalClamp = _superStrengthVerticalClamp;
            }

            var vehiclePointer = ReadCurrentVehiclePointer(detour);
            if (vehiclePointer == 0)
                return;

            if (!IsWritableMemoryRange(vehiclePointer + 0x20UL, 16))
                return;

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 16);
            if (velocity.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            if (!IsFiniteFloat(speed))
                speed = 0F;

            var nowTicks = DateTime.UtcNow.Ticks;
            if (vehiclePointer != _superStrengthLastVehiclePointer)
            {
                _superStrengthLastVehiclePointer = vehiclePointer;
                _superStrengthLastDirX = 0F;
                _superStrengthLastDirZ = -1F;
                _superStrengthLastSpeed = Math.Max(0F, speed);
                _superStrengthLastTickUtcTicks = nowTicks;
            }

            float idleDirX;
            float idleDirZ;
            if (speed > 2F && TryNormalizeFlyDirection(vx, vz, out idleDirX, out idleDirZ))
            {
                _superStrengthLastDirX = idleDirX;
                _superStrengthLastDirZ = idleDirZ;
            }

            if (_superStrengthGuardVirtualKey <= 0 || !IsKeyDown(_superStrengthGuardVirtualKey))
            {
                _superStrengthLastSpeed = Math.Max(0F, speed);
                _superStrengthLastTickUtcTicks = nowTicks;
                return;
            }

            var deltaSeconds = _superStrengthLastTickUtcTicks == 0
                ? 0.016F
                : Math.Max(0.004F, Math.Min(0.05F, (float)((nowTicks - _superStrengthLastTickUtcTicks) / (double)TimeSpan.TicksPerSecond)));

            float dirX;
            float dirZ;
            var hasDirection = TryReadSuperStrengthCameraDirection(vehiclePointer, out dirX, out dirZ);
            if (!hasDirection && speed > 1.25F)
                hasDirection = TryNormalizeFlyDirection(vx, vz, out dirX, out dirZ);
            if (!hasDirection && !TryNormalizeFlyDirection(_superStrengthLastDirX, _superStrengthLastDirZ, out dirX, out dirZ))
            {
                dirX = 0F;
                dirZ = -1F;
            }

            var baseSpeed = Math.Max(speed, _superStrengthLastSpeed);
            var targetSpeed = baseSpeed + (accelerationPerSecond * deltaSeconds);
            targetSpeed = Math.Max(minSpeed, targetSpeed);
            targetSpeed = Math.Max(shoveSpeed, targetSpeed);
            targetSpeed = Math.Min(maxSpeed, targetSpeed);

            var stableY = Math.Max(-verticalClamp, Math.Min(verticalClamp, vy * verticalDamping));
            WriteFloat(vehiclePointer + 0x20UL, dirX * targetSpeed);
            WriteFloat(vehiclePointer + 0x24UL, stableY);
            WriteFloat(vehiclePointer + 0x28UL, dirZ * targetSpeed);
            WriteFloat(vehiclePointer + 0x2CUL, 0F);
            DampHoverSpin(vehiclePointer);
            LockFlyVehicleFlat(vehiclePointer, dirX, dirZ);

            _superStrengthLastDirX = dirX;
            _superStrengthLastDirZ = dirZ;
            _superStrengthLastSpeed = targetSpeed;
            _superStrengthLastTickUtcTicks = nowTicks;
        }

        private bool TryReadSuperStrengthCameraDirection(ulong vehiclePointer, out float dirX, out float dirZ)
        {
            dirX = 0F;
            dirZ = -1F;

            var detour = _superStrengthCameraDetour;
            var descriptor = _superStrengthCameraDescriptor;
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return false;

            if (descriptor.ObjectPointerOffset >= 0)
            {
                var cameraObject = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (cameraObject != 0)
                {
                    if (TryReadCameraPositionDirection(cameraObject, vehiclePointer, out dirX, out dirZ))
                        return true;

                    if (IsReadableMemoryRange(cameraObject, 16))
                    {
                        var live = ReadBytes(cameraObject, 16);
                        if (live.Length >= 12)
                        {
                            var liveX = BitConverter.ToSingle(live, 0);
                            var liveZ = BitConverter.ToSingle(live, 8);
                            if (TryNormalizeFlyDirection(-liveX, -liveZ, out dirX, out dirZ))
                                return true;
                        }
                    }
                }
            }

            return false;
        }

        private static bool IsFiniteFloat(float value)
        {
            return !float.IsNaN(value) && !float.IsInfinity(value);
        }

        private void StartTeleportToWaypointGuard(
            RuntimeDetour vehicleDetour,
            RuntimeDetour waypointDetour,
            RuntimeProfileHookDescriptor waypointDescriptor,
            List<RuntimeDetour> waypointCopyDetours,
            List<RuntimeProfileHookDescriptor> waypointCopyDescriptors,
            int virtualKey)
        {
            _teleportVehicleDetour = vehicleDetour;
            if (!_teleportCheckpointEnabled && !_checkpointRecoveryEnabled && !_autoRaceDriveEnabled)
            {
                _teleportWaypointDetour = waypointDetour;
                _teleportWaypointDescriptor = waypointDescriptor;
                _teleportWaypointCopyDetours = waypointCopyDetours ?? new List<RuntimeDetour>();
                _teleportWaypointCopyDescriptors = waypointCopyDescriptors ?? new List<RuntimeProfileHookDescriptor>();
            }
            _teleportWaypointVirtualKey = virtualKey;
            _teleportWaypointEnabled = true;
            _teleportWaypointKeyLastState = false;
            _teleportWaypointCooldownUntilUtcTicks = 0;
            _teleportWaypointCaptureUntilUtcTicks = 0;
            _teleportRepeatPosition = null;
            _teleportRepeatUntilUtcTicks = 0;
            _teleportLastSource = string.Empty;
            ResetTeleportVehicleStability();
            if (!_teleportCheckpointEnabled && !_checkpointRecoveryEnabled && !_autoRaceDriveEnabled)
                ClearTeleportWaypointCaptures(_teleportWaypointCopyDetours, _teleportWaypointCopyDescriptors, _teleportWaypointDetour, _teleportWaypointDescriptor);
            EnsureTeleportGuardTimer();
            QueueTeleportWaypointDestinationPrewarmScan(ReadCurrentVehiclePointer(vehicleDetour));
        }

