        }

        private void EnsureTeleportGuardTimer()
        {
            if (_teleportToWaypointGuardTimer == null)
                _teleportToWaypointGuardTimer = new System.Threading.Timer(TeleportToWaypointGuardTick, null, 0, 16);
            else
                _teleportToWaypointGuardTimer.Change(0, 16);
        }

        private void ClearTeleportWaypointCaptures(
            List<RuntimeDetour> waypointCopyDetours,
            List<RuntimeProfileHookDescriptor> waypointCopyDescriptors,
            RuntimeDetour waypointDetour,
            RuntimeProfileHookDescriptor waypointDescriptor)
        {
            try
            {
                var count = Math.Min(waypointCopyDetours == null ? 0 : waypointCopyDetours.Count, waypointCopyDescriptors == null ? 0 : waypointCopyDescriptors.Count);
                for (var i = 0; i < count; i++)
                    ClearTeleportCapture(waypointCopyDetours[i], waypointCopyDescriptors[i]);
                ClearTeleportCapture(waypointDetour, waypointDescriptor);
            }
            catch
            {
            }
        }

        private void ClearTeleportCapture(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor)
        {
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return;

            if (descriptor.CaptureOffset >= 0)
                WriteBytes(detour.DetourAddress + (ulong)descriptor.CaptureOffset, new byte[16]);
            if (descriptor.ObjectPointerOffset >= 0)
                WriteUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset, 0);
        }

        private void StopTeleportToWaypointGuard()
        {
            var timer = _teleportToWaypointGuardTimer;
            _teleportToWaypointGuardTimer = null;
            if (timer != null)
                timer.Dispose();

            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour != null && vehicleDetour.DetourAddress != 0 && _handle != IntPtr.Zero)
            {
                try
                {
                    var layout = GetVehicleControlLayout();
                    WriteByte(vehicleDetour.DetourAddress + (ulong)layout.TeleportToggleOffset, 0);
                }
                catch
                {
                }
            }

            _teleportVehicleDetour = null;
            _teleportWaypointDetour = null;
            _teleportWaypointDescriptor = null;
            _teleportWaypointCopyDetours = new List<RuntimeDetour>();
            _teleportWaypointCopyDescriptors = new List<RuntimeProfileHookDescriptor>();
            _teleportWaypointVirtualKey = 0;
            _teleportCheckpointVirtualKey = 0;
            _checkpointRecoveryVirtualKey = 0;
            _teleportSavedVirtualKey = 0;
            _teleportWaypointEnabled = false;
            _teleportCheckpointEnabled = false;
            _checkpointRecoveryEnabled = false;
            _teleportWaypointKeyLastState = false;
            _teleportCheckpointKeyLastState = false;
            _checkpointRecoveryKeyLastState = false;
            _teleportSavedKeyLastState = false;
            _teleportWaypointCooldownUntilUtcTicks = 0;
            _teleportCheckpointCooldownUntilUtcTicks = 0;
            _checkpointRecoveryCooldownUntilUtcTicks = 0;
            _teleportSavedCooldownUntilUtcTicks = 0;
            _teleportWaypointCaptureUntilUtcTicks = 0;
            _teleportCheckpointCaptureUntilUtcTicks = 0;
            _teleportWaypointRouteAnchorPosition = null;
            _teleportWaypointRouteAnchorUntilUtcTicks = 0;
            _teleportCheckpointAutoOn = false;
            _teleportCheckpointAutoNextUtcTicks = 0;
            _teleportCheckpointRepeatPosition = null;
            _teleportCheckpointRepeatUntilUtcTicks = 0;
            ResetTeleportVehicleStability();
            _checkpointRecoveryRepeatPosition = null;
            _checkpointRecoveryRepeatUntilUtcTicks = 0;
            _autoRaceDriveEnabled = false;
