        private void StartAutoRaceDriveGuard(
            RuntimeDetour vehicleDetour,
            RuntimeDetour waypointDetour,
            RuntimeProfileHookDescriptor waypointDescriptor,
            List<RuntimeDetour> waypointCopyDetours,
            List<RuntimeProfileHookDescriptor> waypointCopyDescriptors,
            int virtualKey)
        {
            _teleportVehicleDetour = vehicleDetour;
            _teleportWaypointDetour = waypointDetour;
            _teleportWaypointDescriptor = waypointDescriptor;
            _teleportWaypointCopyDetours = waypointCopyDetours ?? new List<RuntimeDetour>();
            _teleportWaypointCopyDescriptors = waypointCopyDescriptors ?? new List<RuntimeProfileHookDescriptor>();
            _autoRaceDriveVirtualKey = virtualKey;
            System.Threading.Interlocked.Increment(ref _autoRaceDriveGeneration);
            _autoRaceDriveEnabled = true;
            _autoRaceDriveKeyLastState = false;
            _autoRaceDriveCooldownUntilUtcTicks = 0;
            _autoRaceDriveOn = false;
            _autoRaceDriveLastTickUtcTicks = 0;
            lock (_autoRaceDriveRouteLock)
            {
                _autoRaceDriveTarget = null;
                _autoRaceDriveLine = null;
                _autoRaceRouteDirectionHeader = 0;
                _autoRaceRouteDirection = 0;
            }
            _autoRaceDriveLastRecoveryUtcTicks = 0;
            _autoRaceDriveRecoverySuppressedUntilUtcTicks = 0;
            _autoRaceDriveHasLastPosition = false;
            _autoRaceDriveLastPositionX = 0F;
            _autoRaceDriveLastPositionZ = 0F;
            _autoRaceDriveOffRouteSinceUtcTicks = 0;
            _autoRaceDriveScanNextUtcTicks = 0;
            if (!_teleportWaypointEnabled && !_teleportCheckpointEnabled && !_checkpointRecoveryEnabled)
                ClearTeleportWaypointCaptures(_teleportWaypointCopyDetours, _teleportWaypointCopyDescriptors, _teleportWaypointDetour, _teleportWaypointDescriptor);
            EnsureTeleportGuardTimer();
        }

