        private void StopTeleportGuardTimerIfIdle()
        {
            if (_teleportWaypointEnabled || _teleportCheckpointEnabled || _checkpointRecoveryEnabled || _autoRaceDriveEnabled || _teleportSavedPosition != null ||
                _rolePlayGasEnabled ||
                _cruiseControlEnabled || _accelRampEnabled || _topSpeedCapEnabled ||
                _wallClimberEnabled || _chargeJumpEnabled)
                return;

            var timer = _teleportToWaypointGuardTimer;
            _teleportToWaypointGuardTimer = null;
            if (timer != null)
                timer.Dispose();
        }

        private bool _cruiseControlEnabled;
        private float _cruiseControlSpeedMps;
        private bool _accelRampEnabled;
        private float _accelRampRatePerSecond;
        private float _accelRampLastSpeed;
        private bool _accelRampHasLastSpeed;
        private bool _topSpeedCapEnabled;
        private float _topSpeedCapMps;
        private long _cruiseAccelLastTickUtcTicks;
        private bool _cruiseAccelHasPrev;
        private float _cruiseAccelPrevSpeed;
        private float _cruiseAccelPrevHeadingX;
        private float _cruiseAccelPrevHeadingZ;
        private bool _cruiseAccelHeadingFlipped;
        private long _cruiseAccelSuppressUntilTicks;
        private const float CruiseControlRampPerSecond = 45F;
        private const float CruiseAccelMaxSpeed = 250F;
        private ulong _assistVehiclePtr;
        private ulong _assistVehicleIdentity;
        private long _assistVehicleSettleUntilTicks;

        private bool IsAssistVehicleWriteSafe(ulong vp, long nowTicks)
        {
            if (vp == 0 || !IsReadableMemoryRange(vp, 8))
                return false;
            ulong identity;
            try { identity = ReadUInt64(vp); }
            catch { return false; }
            if (identity <= 0x10000UL || identity >= 0x00007FFFFFFFFFFFUL)
            {
                _assistVehiclePtr = 0;
                return false;
            }

            if (_assistVehiclePtr == 0)
            {
                _assistVehiclePtr = vp;
                _assistVehicleIdentity = identity;
                _assistVehicleSettleUntilTicks = 0;
                return true;
            }

            if (vp != _assistVehiclePtr || identity != _assistVehicleIdentity)
            {
                _assistVehiclePtr = vp;
                _assistVehicleIdentity = identity;
                _assistVehicleSettleUntilTicks = nowTicks + (TimeSpan.TicksPerMillisecond * 400);
                return false;
            }
            return nowTicks >= _assistVehicleSettleUntilTicks;
        }

        private void EnsureAssistVehicleDetour()
        {
            if (_teleportVehicleDetour != null && _teleportVehicleDetour.DetourAddress != 0)
                return;
            var vehicleDescriptor = GetProfileHookDescriptor(RuntimeProfileFeature.Jump);
            _teleportVehicleDetour = EnsureRuntimeProfileHook(vehicleDescriptor);
        }

        public void SetCruiseControlRuntimeHook(bool enabled, float speedKmh)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (!enabled)
            {
                _cruiseControlEnabled = false;
                StopTeleportGuardTimerIfIdle();
                _log("Cruise Control OFF.");
                return;
            }

            var mps = speedKmh / 3.6F;
            if (!IsFiniteFloat(mps) || mps < 0F)
                throw new InvalidOperationException("Cruise Control speed is not valid.");
            EnsureAssistVehicleDetour();
            _cruiseControlSpeedMps = mps;
            _cruiseAccelLastTickUtcTicks = 0;
            _cruiseControlEnabled = true;
            EnsureTeleportGuardTimer();
            _log("Cruise Control ON: holding " + ((int)Math.Round((double)speedKmh)).ToString(CultureInfo.InvariantCulture) + " km/h - you steer, it holds the speed.");
        }

        public void SetAccelerationRampRuntimeHook(bool enabled, float ratePerSecond)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (!enabled)
            {
                _accelRampEnabled = false;
                _accelRampHasLastSpeed = false;
                StopTeleportGuardTimerIfIdle();
                _log("Acceleration Ramp OFF.");
                return;
            }

            if (!IsFiniteFloat(ratePerSecond) || ratePerSecond <= 0F)
                throw new InvalidOperationException("Acceleration Ramp rate is not valid.");
            EnsureAssistVehicleDetour();
            _accelRampRatePerSecond = ratePerSecond;
            _accelRampHasLastSpeed = false;
            _cruiseAccelLastTickUtcTicks = 0;
            _cruiseAccelHasPrev = false;
            _cruiseAccelSuppressUntilTicks = 0;
            _accelRampEnabled = true;
            EnsureTeleportGuardTimer();
            _log("Acceleration Ramp ON: +" + ratePerSecond.ToString("0.##", CultureInfo.InvariantCulture) + " m/s^2 while accelerating.");
        }

        public void SetTopSpeedCapRuntimeHook(bool enabled, float speedKmh)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");
            if (!enabled)
            {
                _topSpeedCapEnabled = false;
                _topSpeedCapMps = 0F;
                StopTeleportGuardTimerIfIdle();
                _log("Top Speed OFF.");
                return;
            }

            var mps = speedKmh / 3.6F;
            if (!IsFiniteFloat(mps) || mps <= 0F)
                throw new InvalidOperationException("Top Speed cap is not valid.");
            EnsureAssistVehicleDetour();
            _topSpeedCapMps = mps;
            _cruiseAccelLastTickUtcTicks = 0;
            _topSpeedCapEnabled = true;
            EnsureTeleportGuardTimer();
            _log("Top Speed ON: hard cap " + ((int)Math.Round((double)speedKmh)).ToString(CultureInfo.InvariantCulture) + " km/h.");
        }

        private void ApplyCruiseAndAccelTick(long nowTicks)
        {
            var vp = ResolveAutoRaceDriveVehiclePointer();
            if (!IsAssistVehicleWriteSafe(vp, nowTicks))
            {
                _accelRampHasLastSpeed = false;
                _cruiseAccelHasPrev = false;
                return;
            }
            if (!IsWritableMemoryRange(vp + 0x20UL, 12))
                return;
            var vel = ReadBytes(vp + 0x20UL, 12);
            if (vel.Length < 12)
                return;
            var vx = BitConverter.ToSingle(vel, 0);
            var vy = BitConverter.ToSingle(vel, 4);
            var vz = BitConverter.ToSingle(vel, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return;
            if ((vx * vx) + (vz * vz) > (2000F * 2000F))
                return;

            var lastTicks = _cruiseAccelLastTickUtcTicks;
            _cruiseAccelLastTickUtcTicks = nowTicks;
            var dt = lastTicks == 0 ? 0.016 : (double)(nowTicks - lastTicks) / TimeSpan.TicksPerSecond;
            if (dt < 0.001) dt = 0.001;
            if (dt > 0.1) dt = 0.1;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            var throttleActive = IsAccelerationInputPressed() && !IsBrakeInputPressed();
            if (speed < 1.0F)
            {
                if (_cruiseAccelHasPrev && _cruiseAccelPrevSpeed > 3.0F)
                    _cruiseAccelSuppressUntilTicks = nowTicks + (TimeSpan.TicksPerMillisecond * 450);
                _accelRampHasLastSpeed = false;
                _cruiseAccelHasPrev = false;
                return;
            }
            var headingX = vx / speed;
            var headingZ = vz / speed;
            var newSpeed = speed;

            if (_cruiseAccelHasPrev)
            {
                var headingDot = (headingX * _cruiseAccelPrevHeadingX) + (headingZ * _cruiseAccelPrevHeadingZ);
                var impact = (_cruiseAccelPrevSpeed - speed) > 4.0F && speed < (_cruiseAccelPrevSpeed * 0.6F);
                var flipped = headingDot < 0.2F;
                if (impact || (flipped && _cruiseAccelHeadingFlipped))
                    _cruiseAccelSuppressUntilTicks = nowTicks + (TimeSpan.TicksPerMillisecond * 450);
                _cruiseAccelHeadingFlipped = flipped;
            }
            else
            {
                _cruiseAccelHeadingFlipped = false;
            }
            _cruiseAccelHasPrev = true;
            _cruiseAccelPrevSpeed = speed;
            _cruiseAccelPrevHeadingX = headingX;
            _cruiseAccelPrevHeadingZ = headingZ;

            if (nowTicks < _cruiseAccelSuppressUntilTicks)
            {
                _accelRampHasLastSpeed = false;
                return;
            }

            if (_accelRampEnabled)
            {
                if (throttleActive)
                {
                    var accelerating = _accelRampHasLastSpeed && speed >= _accelRampLastSpeed - 0.03F;
                    _accelRampLastSpeed = speed;
                    _accelRampHasLastSpeed = true;
                    if (accelerating)
                        newSpeed = Math.Min(newSpeed + (_accelRampRatePerSecond * (float)dt), CruiseAccelMaxSpeed);
                }
                else
                {
                    _accelRampHasLastSpeed = false;
                }
            }

            if (_cruiseControlEnabled && !IsBrakeInputPressed())
            {
                var target = Math.Min(_cruiseControlSpeedMps, CruiseAccelMaxSpeed);
                var step = CruiseControlRampPerSecond * (float)dt;
                if (newSpeed < target)
                    newSpeed = Math.Min(newSpeed + step, target);
                else if (newSpeed > target)
                    newSpeed = Math.Max(newSpeed - step, target);
            }

            if (_topSpeedCapEnabled && _topSpeedCapMps > 0F && newSpeed > _topSpeedCapMps)
                newSpeed = _topSpeedCapMps;

            if (Math.Abs(newSpeed - speed) < 0.0005F)
                return;
            var newVx = headingX * newSpeed;
            var newVz = headingZ * newSpeed;
            if (!IsFiniteFloat(newVx) || !IsFiniteFloat(newVz))
                return;
            Buffer.BlockCopy(BitConverter.GetBytes(newVx), 0, vel, 0, 4);
            Buffer.BlockCopy(BitConverter.GetBytes(newVz), 0, vel, 8, 4);
            WriteBytes(vp + 0x20UL, vel);
        }

        private void ApplyWallClimberTick(long nowTicks)
        {
            var pressed = _wallJumperVirtualKey > 0 && IsKeyDown(_wallJumperVirtualKey);
            if (!pressed)
            {
                _wallJumperKeyWasPressed = false;
                return;
            }

            if (_wallJumperKeyWasPressed)
                return;
            _wallJumperKeyWasPressed = true;

            var vp = ResolveAutoRaceDriveVehiclePointer();
            if (!IsAssistVehicleWriteSafe(vp, nowTicks))
                return;
            if (!IsReadableMemoryRange(vp + (ulong)VehicleVelocityOffset, 16) ||
                !IsWritableMemoryRange(vp + (ulong)VehicleVelocityOffset, 16))
                return;

            var velocity = ReadBytes(vp + (ulong)VehicleVelocityOffset, 16);
            if (velocity.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            float dirX;
            float dirZ;
            if (!TryReadSuperStrengthCameraDirection(vp, out dirX, out dirZ) &&
                !TryNormalizeFlyDirection(vx, vz, out dirX, out dirZ) &&
                !TryNormalizeFlyDirection(_superStrengthLastDirX, _superStrengthLastDirZ, out dirX, out dirZ))
            {
                dirX = 0F;
                dirZ = -1F;
            }

            var strength = Math.Max(0.1F, Math.Min(10F, _wallClimberStrength));
            var forwardBoost = Math.Min(500F, WallClimberForwardAssistMps * 3F * strength);
            var lift = Math.Min(300F, WallClimberBaseLiftMps * 2.5F * strength);
            var targetVy = Math.Max(0F, vy) + lift;

            WriteFloat(vp + (ulong)VehicleVelocityOffset, vx + (dirX * Math.Max(forwardBoost, Math.Min(140F, speed))));
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 4UL, targetVy);
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 8UL, vz + (dirZ * Math.Max(forwardBoost, Math.Min(140F, speed))));
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 12UL, 0F);
            DampHoverSpin(vp);
        }

        private void ApplyChargeJumpTick(long nowTicks)
        {
            var pressed = _chargeJumpVirtualKey > 0 && IsKeyDown(_chargeJumpVirtualKey);
            if (pressed)
            {
                if (!_chargeJumpWasPressed)
                {
                    _chargeJumpWasPressed = true;
                    _chargeJumpPressedUtcTicks = nowTicks;
                }

                float maxSeconds;
                lock (_chargeJumpConfigLock)
                    maxSeconds = _chargeJumpMaxSeconds;
                if (!IsFiniteFloat(maxSeconds) || maxSeconds <= 0F)
                    maxSeconds = DefaultRuntimeChargeJumpMaxSeconds;
                var heldSeconds = (float)Math.Max(0.0, (nowTicks - _chargeJumpPressedUtcTicks) / (double)TimeSpan.TicksPerSecond);
                NotifyChargeJumpPercent(Math.Min(100F, (heldSeconds / maxSeconds) * 100F));
                return;
            }

            if (!_chargeJumpWasPressed)
            {
                NotifyChargeJumpPercent(0F);
                return;
            }

            var chargeTicks = Math.Max(0L, nowTicks - _chargeJumpPressedUtcTicks);
            _chargeJumpWasPressed = false;
            _chargeJumpPressedUtcTicks = 0;

            float maxChargeSeconds;
            float verticalForce;
            float forwardForce;
            lock (_chargeJumpConfigLock)
            {
                maxChargeSeconds = _chargeJumpMaxSeconds;
                verticalForce = _chargeJumpVerticalForce;
                forwardForce = _chargeJumpForwardForce;
            }
            if (!IsFiniteFloat(maxChargeSeconds) || maxChargeSeconds <= 0F)
                maxChargeSeconds = DefaultRuntimeChargeJumpMaxSeconds;
            if (!IsFiniteFloat(verticalForce) || verticalForce <= 0F)
                verticalForce = DefaultRuntimeChargeJumpVerticalForce;
            if (!IsFiniteFloat(forwardForce) || forwardForce < 0F)
                forwardForce = DefaultRuntimeChargeJumpForwardForce;

            var charge = (float)Math.Min(1.0, Math.Max(0.0, (chargeTicks / (double)TimeSpan.TicksPerSecond) / maxChargeSeconds));
            NotifyChargeJumpPercent(0F);
            if (charge < 0.03F)
                return;

            var vp = ResolveAutoRaceDriveVehiclePointer();
            if (!IsAssistVehicleWriteSafe(vp, nowTicks))
                return;
            if (!IsReadableMemoryRange(vp + (ulong)VehicleVelocityOffset, 16) ||
                !IsWritableMemoryRange(vp + (ulong)VehicleVelocityOffset, 16))
                return;

            var velocity = ReadBytes(vp + (ulong)VehicleVelocityOffset, 16);
            if (velocity.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz))
                return;

            float dirX;
            float dirZ;
            if (!TryReadSuperStrengthCameraDirection(vp, out dirX, out dirZ) &&
                !TryNormalizeFlyDirection(vx, vz, out dirX, out dirZ))
            {
                dirX = 0F;
                dirZ = -1F;
            }

            var forwardBoost = forwardForce * charge;
            var upwardBoost = verticalForce * (0.15F + (0.85F * charge));
            WriteFloat(vp + (ulong)VehicleVelocityOffset, vx + (dirX * forwardBoost));
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 4UL, Math.Max(0F, vy) + upwardBoost);
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 8UL, vz + (dirZ * forwardBoost));
            WriteFloat(vp + (ulong)VehicleVelocityOffset + 12UL, 0F);
        }

        private void NotifyChargeJumpPercent(float percent)
        {
            var callback = _chargeJumpStatusCallback;
            if (callback == null)
                return;
            try
            {
                callback(percent);
            }
            catch
            {
            }
        }

        private int GetAutoRaceIntervalMs()
        {
            return Math.Max(100, Math.Min(5000, AutoRaceIntervalMs));
        }

        private void TeleportToWaypointGuardTick(object state)
        {
            if (System.Threading.Interlocked.Exchange(ref _teleportToWaypointGuardRunning, 1) == 1)
                return;

            try
            {
                if (!IsAlive)
                    return;

                var nowTicks = DateTime.UtcNow.Ticks;
                if (_teleportWaypointEnabled || _teleportCheckpointEnabled || _checkpointRecoveryEnabled)
                    IsTeleportVehicleWriteReady(ResolveAutoRaceDriveVehiclePointer(), nowTicks);
                var savedPressed = _teleportSavedVirtualKey > 0 && IsKeyDown(_teleportSavedVirtualKey);
                if (savedPressed && !_teleportSavedKeyLastState && nowTicks >= _teleportSavedCooldownUntilUtcTicks && _teleportSavedPosition != null)
                {
                    TeleportVehicleToSavedLocation(_teleportVehicleDetour, _teleportSavedPosition, _teleportSavedName);
                    _teleportSavedCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 650;
                }

                var waypointPressed = _teleportWaypointEnabled && _teleportWaypointVirtualKey > 0 && IsKeyDown(_teleportWaypointVirtualKey);
                if (_teleportWaypointEnabled)
                    QueueTeleportWaypointDestinationPrewarmScan(ReadCurrentVehiclePointer(_teleportVehicleDetour));
                if (waypointPressed && !_teleportWaypointKeyLastState && nowTicks >= _teleportWaypointCooldownUntilUtcTicks)
                {
                    _teleportRepeatPosition = null;
                    _teleportRepeatUntilUtcTicks = 0;
                    CaptureTeleportWaypointRouteAnchor(nowTicks);
                    _teleportWaypointCaptureUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 1500;
                    _teleportLastSource = string.Empty;
                }

                if (_teleportWaypointEnabled && _teleportWaypointCaptureUntilUtcTicks != 0)
                {
                    if (TryTeleportVehicleToWaypoint())
                    {
                        _teleportWaypointCaptureUntilUtcTicks = 0;
                        _teleportWaypointCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 650;
                    }
                    else if (nowTicks > _teleportWaypointCaptureUntilUtcTicks)
                    {
                        _teleportWaypointCaptureUntilUtcTicks = 0;
                        _log("Teleport To Waypoint waiting for a fresh FH6 waypoint. Set or refresh a map waypoint, then press the key again.");
                    }
                }

                var checkpointPressed = _teleportCheckpointEnabled && _teleportCheckpointVirtualKey > 0 && IsKeyDown(_teleportCheckpointVirtualKey);
                if (checkpointPressed && !_teleportCheckpointKeyLastState && nowTicks >= _teleportCheckpointCooldownUntilUtcTicks)
                {
                    _teleportCheckpointCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 350;
                    _teleportCheckpointAutoOn = !_teleportCheckpointAutoOn;
                    if (_teleportCheckpointAutoOn)
                    {
                        _teleportCheckpointRepeatPosition = null;
                        _teleportCheckpointRepeatUntilUtcTicks = 0;
                        ResetTeleportVehicleStability();
                        var routeVehicle = ResolveAutoRaceDriveVehiclePointer();
                        lock (_autoRaceDriveRouteLock)
                        {
                            _autoRaceRouteDirectionHeader = 0;
                            _autoRaceRouteDirection = 0;
                            _autoRaceDriveTarget = null;
                            _autoRaceDriveLine = null;
                        }

                        ulong directRouteHeader;
                        if (TryResolveFreshWaypointRouteHeader(out directRouteHeader))
                        {
                            _teleportCheckpointRouteHeaderAddress = directRouteHeader;
                            if (routeVehicle != 0)
                                TryRefreshAutoRaceDriveLineFromCachedHeader(routeVehicle, false);
                        }

                        _teleportCheckpointAutoNextUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 75;
                        QueueAutoRaceDriveRouteScan(routeVehicle);
                        _log("Auto Race ON: following the active route every " +
                            (GetAutoRaceIntervalMs() / 1000.0).ToString("0.##", CultureInfo.InvariantCulture) + "s. Press " + ((Keys)_teleportCheckpointVirtualKey) + " again to stop.");
                    }
                    else
                    {
                        _teleportCheckpointRepeatPosition = null;
                        _teleportCheckpointRepeatUntilUtcTicks = 0;
                        _log("Auto Race OFF.");
                    }
                }

                if (_teleportCheckpointEnabled && _teleportCheckpointAutoOn && nowTicks >= _teleportCheckpointAutoNextUtcTicks)
                {
                    _teleportCheckpointRepeatPosition = null;
                    _teleportCheckpointRepeatUntilUtcTicks = 0;
                    _teleportCheckpointAutoNextUtcTicks = nowTicks +
                        TimeSpan.TicksPerMillisecond * GetAutoRaceIntervalMs();
                    try
                    {
                        TryTeleportVehicleToCheckpoint();
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Auto Race", ex);
                    }
                }

                if (_checkpointRecoveryEnabled)
                {
                    try
                    {
                        var vp = ResolveAutoRaceDriveVehiclePointer();
                        if (vp != 0)
                            QueueAutoRaceDriveRouteScan(vp);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Recovery Path", ex);
                    }
                }

                var recoveryPressed = _checkpointRecoveryEnabled && _checkpointRecoveryVirtualKey > 0 && IsKeyDown(_checkpointRecoveryVirtualKey);
                if (recoveryPressed && !_checkpointRecoveryKeyLastState && nowTicks >= _checkpointRecoveryCooldownUntilUtcTicks)
                {
                    _checkpointRecoveryCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 450;
                    try
                    {
                        if (!TryTeleportVehicleToCheckpointRecovery())
                            _log("Recovery Path waiting for active FH6 route data. Drive near or enter a checkpoint, then press the key again.");
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Recovery Path", ex);
                    }
                }

                var drivePressed = _autoRaceDriveEnabled && _autoRaceDriveVirtualKey > 0 && IsKeyDown(_autoRaceDriveVirtualKey);
                if (drivePressed && !_autoRaceDriveKeyLastState && nowTicks >= _autoRaceDriveCooldownUntilUtcTicks)
                {
                    _autoRaceDriveCooldownUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 350;
                    _autoRaceDriveOn = !_autoRaceDriveOn;
                    _autoRaceDriveLastTickUtcTicks = nowTicks;
                    _autoRaceDriveScanNextUtcTicks = 0;
                    if (_autoRaceDriveOn)
                    {
                        lock (_autoRaceDriveRouteLock)
                        {
                            _autoRaceRouteDirectionHeader = 0;
                            _autoRaceRouteDirection = 0;
                            _autoRaceDriveTarget = null;
                            _autoRaceDriveLine = null;
                        }

                        _autoRaceDriveHasLastPosition = false;
                        _autoRaceDriveOffRouteSinceUtcTicks = 0;
                        _autoRaceDriveRecoverySuppressedUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 250;

                        var routeVehicle = ResolveAutoRaceDriveVehiclePointer();
                        ulong directRouteHeader;
                        if (TryResolveFreshWaypointRouteHeader(out directRouteHeader))
                        {
                            _teleportCheckpointRouteHeaderAddress = directRouteHeader;
                            if (routeVehicle != 0)
                                TryRefreshAutoRaceDriveLineFromCachedHeader(routeVehicle, false);
                        }

                        if (routeVehicle != 0)
                            QueueAutoRaceDriveRouteScan(routeVehicle);
                    }
                    _log(_autoRaceDriveOn
                        ? "Auto Race (Drive) ON: auto-driving the route. Press " + ((Keys)_autoRaceDriveVirtualKey) + " again to stop."
                        : "Auto Race (Drive) OFF.");
                }

                if (_autoRaceDriveEnabled && _autoRaceDriveOn)
                {
                    try
                    {
                        ApplyAutoRaceDriveTick(nowTicks);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Auto Race (Drive)", ex);
                    }
                }
                else if (_autoRaceDriveEnabled)
                {
                    try
                    {
                        var vp = ResolveAutoRaceDriveVehiclePointer();
                        if (vp != 0)
                            QueueAutoRaceDriveRouteScan(vp);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Auto Race (Drive)", ex);
                    }
                }

                if (!(_autoRaceDriveEnabled && _autoRaceDriveOn) &&
                    (_cruiseControlEnabled || _accelRampEnabled || _topSpeedCapEnabled))
                {
                    try
                    {
                        ApplyCruiseAndAccelTick(nowTicks);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Speed Assist", ex);
                    }
                }

                if (_wallClimberEnabled)
                {
                    try
                    {
                        ApplyWallClimberTick(nowTicks);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Wall Jumper", ex);
                    }
                }

                if (_chargeJumpEnabled)
                {
                    try
                    {
                        ApplyChargeJumpTick(nowTicks);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Charge Jump", ex);
                    }
                }

                if (_rolePlayGasEnabled)
                {
                    try
                    {
                        ApplyRolePlayGasTick(nowTicks);
                    }
                    catch (Exception ex)
                    {
                        LogRuntimeGuardWaiting("Role Play Gas", ex);
                    }
                }

                ApplyPendingTeleport(nowTicks);
                _teleportSavedKeyLastState = savedPressed;
                _teleportWaypointKeyLastState = waypointPressed;
                _teleportCheckpointKeyLastState = checkpointPressed;
                _checkpointRecoveryKeyLastState = recoveryPressed;
                _autoRaceDriveKeyLastState = drivePressed;
            }
            catch (Exception ex)
            {
                LogRuntimeGuardWaiting(_teleportCheckpointCaptureUntilUtcTicks != 0 ? "Auto Race" : _teleportWaypointCaptureUntilUtcTicks != 0 ? "Teleport To Waypoint" : "Saved Teleport", ex);
            }
            finally
            {
                System.Threading.Interlocked.Exchange(ref _teleportToWaypointGuardRunning, 0);
            }
        }

        private void LogRuntimeGuardWaiting(string guardName, Exception ex)
        {
            var name = string.IsNullOrWhiteSpace(guardName) ? "Runtime" : guardName.Trim();
            var message = ex == null || string.IsNullOrWhiteSpace(ex.Message) ? "waiting for FH6 to refresh" : ex.Message.Trim();
            var nowTicks = DateTime.UtcNow.Ticks;

            lock (_runtimeGuardLogLock)
            {
                string lastMessage;
                long lastTicks;
                var sameMessage = _runtimeGuardLastErrors.TryGetValue(name, out lastMessage) &&
                    string.Equals(lastMessage, message, StringComparison.OrdinalIgnoreCase);
                var recentlyLogged = _runtimeGuardLastErrorTicks.TryGetValue(name, out lastTicks) &&
                    nowTicks - lastTicks < TimeSpan.TicksPerSecond * 5;
                if (sameMessage && recentlyLogged)
                    return;

                _runtimeGuardLastErrors[name] = message;
                _runtimeGuardLastErrorTicks[name] = nowTicks;
            }

            _log(name + " waiting: " + message);
        }

        private void TeleportVehicleToWaypoint()
        {
            if (!TryTeleportVehicleToWaypoint())
                _log("Teleport To Waypoint waiting for a fresh FH6 waypoint. Set or refresh a map waypoint, then press the key again.");
        }

        private void TeleportVehicleToCheckpoint()
        {
            if (!TryTeleportVehicleToCheckpoint())
                _log("Auto Race waiting for active FH6 route data. Drive near or enter a checkpoint, then press the key again.");
        }

        private bool TryTeleportVehicleToWaypoint()
        {
            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour == null)
                throw new InvalidOperationException("Teleport hook is not ready yet.");

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);
            if (!IsTeleportVehicleWriteReady(vehiclePointer, DateTime.UtcNow.Ticks))
                return false;

            byte[] position;
            if (!TryReadBestWaypointPosition(vehiclePointer, out position))
                return false;

            if (vehiclePointer != 0)
                position = BuildTeleportVehiclePosition(vehiclePointer, position);
            ApplyTeleportPosition(vehiclePointer, position, true);
            _teleportRepeatPosition = position;
            _teleportRepeatUntilUtcTicks = DateTime.UtcNow.Ticks + TimeSpan.TicksPerMillisecond * 650;
            var source = string.IsNullOrEmpty(_teleportLastSource) ? "unknown" : _teleportLastSource;
            _log("Teleport To Waypoint fired from " + source + " to " + FormatTeleportPosition(position) + ".");
            return true;
        }

        private bool TryTeleportVehicleToCheckpoint()
        {
            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour == null)
                throw new InvalidOperationException("Teleport hook is not ready yet.");

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);

            if (!IsTeleportVehicleWriteReady(vehiclePointer, DateTime.UtcNow.Ticks))
                return false;

            byte[] position;
            if (!TryReadAutoRacePathPosition(vehiclePointer, out position))
                return false;

            if (vehiclePointer != 0)
                position = BuildTeleportVehiclePosition(vehiclePointer, position);
            ApplyTeleportPosition(vehiclePointer, position, AutoRaceResetSpeed);
            _teleportCheckpointRepeatPosition = position;
            var intervalMs = GetAutoRaceIntervalMs();
            var holdMs = Math.Max(50, Math.Min(Math.Min(300, AutoRaceHoldMs), intervalMs / 2));
            _teleportCheckpointRepeatUntilUtcTicks = DateTime.UtcNow.Ticks + TimeSpan.TicksPerMillisecond * holdMs;
            var nowLogTicks = DateTime.UtcNow.Ticks;
            if (nowLogTicks - _teleportCheckpointLastLogUtcTicks > TimeSpan.TicksPerMillisecond * 2500)
            {
                _teleportCheckpointLastLogUtcTicks = nowLogTicks;
                var source = string.IsNullOrEmpty(_teleportLastSource) ? "route" : _teleportLastSource;
                _log("Auto Race firing from " + source + " to " + FormatTeleportPosition(position) + ".");
            }
            return true;
        }

        private bool TryTeleportVehicleToCheckpointRecovery()
        {
            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour == null)
                throw new InvalidOperationException("Teleport hook is not ready yet.");

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);
            if (!IsTeleportVehicleWriteReady(vehiclePointer, DateTime.UtcNow.Ticks))
                return false;

            byte[] position;
            if (!TryReadBestCheckpointPosition(vehiclePointer, out position))
                return false;

            if (vehiclePointer != 0)
            {
                position = BuildTeleportVehiclePosition(vehiclePointer, position);
                position = AddTeleportVerticalLift(position, CheckpointRecoveryLiftMeters);
            }
            QueueVehicleControlTeleport(vehicleDetour, position);
            if (vehiclePointer != 0)
            {
                byte[] velocity = null;
                if (IsReadableMemoryRange(vehiclePointer + 0x20UL, 16))
                {
                    velocity = ReadBytes(vehiclePointer + 0x20UL, 16);
                    Buffer.BlockCopy(BitConverter.GetBytes(0F), 0, velocity, 4, 4);
                }

                ApplyTeleportPosition(vehiclePointer, position, false);
                if (velocity != null && velocity.Length >= 16 && IsWritableMemoryRange(vehiclePointer + 0x20UL, 16))
                    WriteBytes(vehiclePointer + 0x20UL, velocity);

                _checkpointRecoveryRepeatPosition = position;
                _checkpointRecoveryRepeatUntilUtcTicks = DateTime.UtcNow.Ticks + TimeSpan.TicksPerMillisecond * CheckpointRecoveryHoldMs;
            }

            var source = string.IsNullOrEmpty(_teleportLastSource) ? "route" : _teleportLastSource;
            _log("Recovery Path fired from " + source + " to " + FormatTeleportPosition(position) + ".");
            return true;
        }

        private ulong ResolveAutoRaceDriveVehiclePointer()
        {
            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour == null || vehicleDetour.DetourAddress == 0)
                return 0;
            var layout = GetVehicleControlLayout();
            return ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);
        }

        private bool ShouldAutoRaceDriveYieldToMovementFeature(long nowTicks)
        {
            if (_hoverGuardTimer != null || _noClipPhaseActive || _rewindActive || _grapplingHookActive)
                return true;
            if (_phaseDashMomentumUntilUtcTicks > nowTicks)
                return true;
            if (_superStrengthGuardVirtualKey > 0 && IsKeyDown(_superStrengthGuardVirtualKey))
                return true;
            if (_wallClimberEnabled && _wallJumperVirtualKey > 0 && IsKeyDown(_wallJumperVirtualKey))
                return true;
            if (_chargeJumpEnabled && _chargeJumpVirtualKey > 0 && IsKeyDown(_chargeJumpVirtualKey))
                return true;
            return false;
        }

        private void ApplyAutoRaceDriveTick(long nowTicks)
        {
            if (ShouldAutoRaceDriveYieldToMovementFeature(nowTicks))
                return;

            var vehiclePointer = ResolveAutoRaceDriveVehiclePointer();
            if (vehiclePointer == 0)
                return;
            if (!IsAssistVehicleWriteSafe(vehiclePointer, nowTicks))
                return;

            var lastTicks = _autoRaceDriveLastTickUtcTicks;
            _autoRaceDriveLastTickUtcTicks = nowTicks;
            var deltaSeconds = lastTicks == 0 ? 0.016 : (double)(nowTicks - lastTicks) / TimeSpan.TicksPerSecond;
            if (deltaSeconds < 0.001) deltaSeconds = 0.001;
            if (deltaSeconds > 0.1) deltaSeconds = 0.1;

            TryRefreshAutoRaceDriveLineFromCachedHeader(vehiclePointer, false);
            QueueAutoRaceDriveRouteScan(vehiclePointer);

            if (!IsWritableMemoryRange(vehiclePointer + 0x20UL, 12) || !IsReadableMemoryRange(vehiclePointer + 0x50UL, 12))
                return;

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
            var position = ReadBytes(vehiclePointer + 0x50UL, 12);
            if (velocity.Length < 12 || position.Length < 12)
                return;

            var vx = BitConverter.ToSingle(velocity, 0);
            var vy = BitConverter.ToSingle(velocity, 4);
            var vz = BitConverter.ToSingle(velocity, 8);
            var px = BitConverter.ToSingle(position, 0);
            var py = BitConverter.ToSingle(position, 4);
            var pz = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vy) || !IsFiniteFloat(vz) ||
                !IsFiniteFloat(px) || !IsFiniteFloat(py) || !IsFiniteFloat(pz))
                return;

            if (HandleAutoRaceDriveRespawnReset(nowTicks, vehiclePointer, px, pz))
                return;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            float tx, tz, cornerSpeedLimit, pathX, pathY, pathZ, routeError;
            if (!TryResolveAutoRaceDriveTargetXZ(px, pz, speed, out tx, out tz, out cornerSpeedLimit, out pathX, out pathY, out pathZ, out routeError))
                return;

            if (ShouldAutoRaceDriveRecover(nowTicks, routeError, speed) &&
                IsFiniteFloat(pathX) && IsFiniteFloat(pathY) && IsFiniteFloat(pathZ) &&
                Math.Abs(pathY - py) <= 18F &&
                IsWritableMemoryRange(vehiclePointer + 0x50UL, 16))
            {
                var snap = new byte[16];
                Buffer.BlockCopy(position, 0, snap, 0, Math.Min(position.Length, 16));
                Buffer.BlockCopy(BitConverter.GetBytes(pathX), 0, snap, 0, 4);
                Buffer.BlockCopy(BitConverter.GetBytes(pathY + AutoRaceDriveRecoverLiftMeters), 0, snap, 4, 4);
                Buffer.BlockCopy(BitConverter.GetBytes(pathZ), 0, snap, 8, 4);
                ApplyTeleportPosition(vehiclePointer, snap, false);
                _autoRaceDriveLastRecoveryUtcTicks = nowTicks;
                _autoRaceDriveOffRouteSinceUtcTicks = 0;
                px = pathX;
                pz = pathZ;
                RememberAutoRaceDrivePosition(px, pz);
            }

            var desiredX = tx - px;
            var desiredZ = tz - pz;
            var desiredLen = (float)Math.Sqrt((double)((desiredX * desiredX) + (desiredZ * desiredZ)));
            if (desiredLen < 0.5F)
                return;
            desiredX /= desiredLen;
            desiredZ /= desiredLen;

            var ramped = Math.Max(speed, AutoRaceDriveMinSpeed) + (AutoRaceDriveAccelPerSecond * (float)deltaSeconds);
            var driveSpeed = Math.Min(ramped, AutoRaceDriveCruiseSpeed);
            driveSpeed = Math.Max(driveSpeed, speed);
            driveSpeed = Math.Min(driveSpeed, AutoRaceDriveMaxSpeed);

            if (cornerSpeedLimit < driveSpeed)
                driveSpeed = Math.Max(cornerSpeedLimit, AutoRaceDriveCornerMinSpeed);

            float headingX, headingZ;
            if (speed > 0.75F)
            {
                headingX = vx / speed;
                headingZ = vz / speed;
            }
            else
            {
                headingX = desiredX;
                headingZ = desiredZ;
            }

            var headingDot = (headingX * desiredX) + (headingZ * desiredZ);
            if (speed > 0.75F && headingDot < AutoRaceDriveBehindDot)
            {
                desiredX = headingX;
                desiredZ = headingZ;
                headingDot = 1F;
            }

            var turnBoost = headingDot < 0.15F ? 1.65F : headingDot < 0.55F ? 1.25F : 1F;
            var maxTurn = AutoRaceDriveTurnRate * turnBoost * (float)deltaSeconds;
            RotateHeadingTowards(ref headingX, ref headingZ, desiredX, desiredZ, maxTurn);

            var newVx = headingX * driveSpeed;
            var newVz = headingZ * driveSpeed;
            if (!IsFiniteFloat(newVx) || !IsFiniteFloat(newVz))
                return;

            Buffer.BlockCopy(BitConverter.GetBytes(newVx), 0, velocity, 0, 4);
            Buffer.BlockCopy(BitConverter.GetBytes(newVz), 0, velocity, 8, 4);
            WriteBytes(vehiclePointer + 0x20UL, velocity);
            RememberAutoRaceDrivePosition(px, pz);

            if (nowTicks - _autoRaceDriveLastLogUtcTicks > TimeSpan.TicksPerMillisecond * 3000)
            {
                _autoRaceDriveLastLogUtcTicks = nowTicks;
                var source = string.IsNullOrEmpty(_teleportLastSource) ? "route" : _teleportLastSource;
                _log("Auto Race (Drive) following " + source + " at ~" + ((int)(driveSpeed * 3.6F)).ToString(CultureInfo.InvariantCulture) + " km/h.");
            }
        }

        private void RememberAutoRaceDrivePosition(float px, float pz)
        {
            if (!IsFiniteFloat(px) || !IsFiniteFloat(pz))
                return;

            _autoRaceDriveHasLastPosition = true;
            _autoRaceDriveLastPositionX = px;
            _autoRaceDriveLastPositionZ = pz;
        }

        private bool ShouldAutoRaceDriveRecover(long nowTicks, float routeError, float speed)
        {
            if (nowTicks < _autoRaceDriveRecoverySuppressedUntilUtcTicks ||
                nowTicks - _autoRaceDriveLastRecoveryUtcTicks <= TimeSpan.TicksPerMillisecond * 650)
            {
                _autoRaceDriveOffRouteSinceUtcTicks = 0;
                return false;
            }

            var speedKmh = Math.Max(0F, speed * 3.6F);
            var threshold = AutoRaceDriveRecoverMeters + Math.Min(24F, speedKmh * 0.035F);
            if (routeError < threshold)
            {
                _autoRaceDriveOffRouteSinceUtcTicks = 0;
                return false;
            }

            if (_autoRaceDriveOffRouteSinceUtcTicks == 0)
            {
                _autoRaceDriveOffRouteSinceUtcTicks = nowTicks;
                return false;
            }

            var holdTicks = TimeSpan.TicksPerMillisecond * AutoRaceDriveRecoverHoldMs;
            return nowTicks - _autoRaceDriveOffRouteSinceUtcTicks >= holdTicks;
        }

        private bool HandleAutoRaceDriveRespawnReset(long nowTicks, ulong vehiclePointer, float px, float pz)
        {
            if (!_autoRaceDriveHasLastPosition)
            {
                RememberAutoRaceDrivePosition(px, pz);
                return false;
            }

            var dx = px - _autoRaceDriveLastPositionX;
            var dz = pz - _autoRaceDriveLastPositionZ;
            var jumpSquared = (dx * dx) + (dz * dz);
            if (jumpSquared < AutoRaceDriveRespawnJumpMeters * AutoRaceDriveRespawnJumpMeters)
            {
                RememberAutoRaceDrivePosition(px, pz);
                return false;
            }

            if (nowTicks - _autoRaceDriveLastRecoveryUtcTicks < TimeSpan.TicksPerMillisecond * 900)
            {
                RememberAutoRaceDrivePosition(px, pz);
                return false;
            }

            lock (_autoRaceDriveRouteLock)
            {
                _autoRaceDriveTarget = null;
                _autoRaceDriveLine = null;
                _autoRaceRouteDirectionHeader = 0;
                _autoRaceRouteDirection = 0;
            }
            _teleportCheckpointRouteHeaderAddress = 0;
            _autoRaceDriveScanNextUtcTicks = 0;
            _autoRaceDriveRecoverySuppressedUntilUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * 1800;
            _autoRaceDriveOffRouteSinceUtcTicks = 0;
            _teleportCheckpointRepeatPosition = null;
            _teleportCheckpointRepeatUntilUtcTicks = 0;
            RememberAutoRaceDrivePosition(px, pz);
            QueueAutoRaceDriveRouteScan(vehiclePointer);

            if (nowTicks - _autoRaceDriveLastLogUtcTicks > TimeSpan.TicksPerMillisecond * 1500)
            {
                _autoRaceDriveLastLogUtcTicks = nowTicks;
                _log("Auto Race (Drive) detected a checkpoint respawn and reset the route from the current checkpoint.");
            }
            return true;
        }

        private void QueueAutoRaceDriveRouteScan(ulong vehiclePointer)
        {
            if (!IsAlive || vehiclePointer == 0 ||
                !(_autoRaceDriveEnabled || _checkpointRecoveryEnabled || _teleportCheckpointEnabled))
                return;

            var nowTicks = DateTime.UtcNow.Ticks;
            if (nowTicks < _autoRaceDriveScanNextUtcTicks)
                return;
            if (System.Threading.Interlocked.CompareExchange(ref _autoRaceDriveScanRunning, 1, 0) != 0)
                return;

            var interval = Math.Max(16, Math.Min(2000, AutoRaceDriveScanIntervalMs));
            _autoRaceDriveScanNextUtcTicks = nowTicks + TimeSpan.TicksPerMillisecond * interval;
            var generation = System.Threading.Volatile.Read(ref _autoRaceDriveGeneration);
            System.Threading.ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    if (!IsAlive ||
                        !(_autoRaceDriveEnabled || _checkpointRecoveryEnabled || _teleportCheckpointEnabled) ||
                        generation != System.Threading.Volatile.Read(ref _autoRaceDriveGeneration))
                        return;
                    if (ResolveAutoRaceDriveVehiclePointer() != vehiclePointer)
                        return;
                    if (TryRefreshAutoRaceDriveLineFromCachedHeader(vehiclePointer, true))
                        return;

                    byte[] target;
                    if ((_autoRaceDriveEnabled || _checkpointRecoveryEnabled || _teleportCheckpointEnabled) &&
                        TryReadCheckpointPositionFromModuleRouteVector(vehiclePointer, out target) &&
                        target != null && target.Length >= 12 &&
                        _teleportLastSource != null &&
                        _teleportLastSource.IndexOf("nextCheckpoint", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        var line = BuildAutoRaceDriveLineFromHeader(_teleportCheckpointRouteHeaderAddress, vehiclePointer);
                        if (line != null && line.Count >= 2 &&
                            _autoRaceDriveEnabled &&
                            generation == System.Threading.Volatile.Read(ref _autoRaceDriveGeneration) &&
                            ResolveAutoRaceDriveVehiclePointer() == vehiclePointer)
                        {
                            lock (_autoRaceDriveRouteLock)
                            {
                                _autoRaceDriveTarget = CopyTeleportPosition(target);
                                _autoRaceDriveLine = line;
                            }
                        }
                    }
                }
                catch
                {
                }
                finally
                {
                    System.Threading.Interlocked.Exchange(ref _autoRaceDriveScanRunning, 0);
                }
            });
        }

        private bool TryRefreshAutoRaceDriveLineFromCachedHeader(ulong vehiclePointer, bool clearBadHeader)
        {
            var headerAddress = _teleportCheckpointRouteHeaderAddress;
            if (headerAddress == 0 || vehiclePointer == 0)
                return false;

            var anchor = GetLiveVehicleRouteAnchor(vehiclePointer);
            if (!IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var ranges = new List<TeleportRouteRangeCandidate>();
            CollectModuleRouteVectorAtHeader(headerAddress, ranges);

            byte[] target;
            List<byte[]> line;
            string source;
            if (!TrySelectAutoRaceDriveRoute(ranges, anchor, vehiclePointer, out target, out line, out source))
            {
                if (clearBadHeader)
                    _teleportCheckpointRouteHeaderAddress = 0;
                return false;
            }

            lock (_autoRaceDriveRouteLock)
            {
                _autoRaceDriveTarget = CopyTeleportPosition(target);
                _autoRaceDriveLine = line;
            }
            _teleportLastSource = source;
            return true;
        }

        private List<byte[]> BuildAutoRaceDriveLineFromHeader(ulong headerAddress, ulong vehiclePointer)
        {
            if (headerAddress == 0)
                return null;
            var anchor = GetLiveVehicleRouteAnchor(vehiclePointer);
            if (!IsPlausibleWorldTeleportPosition(anchor))
                return null;

            var ranges = new List<TeleportRouteRangeCandidate>();
            CollectModuleRouteVectorAtHeader(headerAddress, ranges);
            byte[] target;
            List<byte[]> line;
            string source;
            return TrySelectAutoRaceDriveRoute(ranges, anchor, vehiclePointer, out target, out line, out source) ? line : null;
        }

        private bool TryReadRouteTravelHeading(ulong vehiclePointer, out float headingX, out float headingZ)
        {
            headingX = 0F;
            headingZ = 0F;
            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x20UL, 12))
                return false;

            var velocity = ReadBytes(vehiclePointer + 0x20UL, 12);
            if (velocity.Length < 12)
                return false;
            var vx = BitConverter.ToSingle(velocity, 0);
            var vz = BitConverter.ToSingle(velocity, 8);
            if (!IsFiniteFloat(vx) || !IsFiniteFloat(vz))
                return false;

            var speed = (float)Math.Sqrt((double)((vx * vx) + (vz * vz)));
            if (speed >= 1.5F)
            {
                headingX = vx / speed;
                headingZ = vz / speed;
                return IsFiniteFloat(headingX) && IsFiniteFloat(headingZ);
            }

            return TryReadFlyVehicleNoseDirection(vehiclePointer, out headingX, out headingZ);
        }

        private int GetRememberedAutoRaceRouteDirection(ulong headerAddress)
        {
            if (headerAddress == 0)
                return 0;
            lock (_autoRaceDriveRouteLock)
                return _autoRaceRouteDirectionHeader == headerAddress ? _autoRaceRouteDirection : 0;
        }

        private void RememberAutoRaceRouteDirection(ulong headerAddress, int direction)
        {
            if (headerAddress == 0 || (direction != 1 && direction != -1))
                return;
            lock (_autoRaceDriveRouteLock)
            {
                _autoRaceRouteDirectionHeader = headerAddress;
                _autoRaceRouteDirection = direction;
            }
        }

        private bool TrySelectAutoRaceDriveRoute(
            List<TeleportRouteRangeCandidate> ranges,
            byte[] anchor,
            ulong vehiclePointer,
            out byte[] target,
            out List<byte[]> line,
            out string source)
        {
            target = null;
            line = null;
            source = string.Empty;
            if (ranges == null || ranges.Count == 0 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            float headingX;
            float headingZ;
            var hasHeading = TryReadRouteTravelHeading(vehiclePointer, out headingX, out headingZ);
            _teleportRouteWinningHeaderAddress = 0;
            var bestScore = double.MinValue;
            var bestDirection = 0;
            for (var i = 0; i < ranges.Count; i++)
            {
                var routeRange = ranges[i];
                if (routeRange == null || routeRange.Positions == null || routeRange.Positions.Count < 2)
                    continue;

                byte[] checkpoint;
                int nearestIndex;
                int checkpointIndex;
                int routeDirection;
                double nearestDistance;
                double checkpointDistance;
                var preferredDirection = GetRememberedAutoRaceRouteDirection(routeRange.HeaderAddress);
                if (!TryChooseNextCheckpointFromRoute(
                    routeRange.Positions,
                    anchor,
                    preferredDirection,
                    hasHeading,
                    headingX,
                    headingZ,
                    out checkpoint,
                    out nearestIndex,
                    out checkpointIndex,
                    out routeDirection,
                    out nearestDistance,
                    out checkpointDistance))
                    continue;
                if (nearestDistance > AutoRaceDriveOnRouteMaxSquared)
                    continue;

                var routeLine = BuildForwardRouteLine(routeRange.Positions, nearestIndex, routeDirection);
                if (routeLine == null || routeLine.Count < 2)
                    continue;

                var indexAdvance = Math.Abs(checkpointIndex - nearestIndex);
                var score = routeRange.Priority +
                            (250000.0 - Math.Min(nearestDistance, 250000.0)) +
                            (640000.0 - Math.Min(checkpointDistance, 640000.0)) +
                            (double)Math.Min(indexAdvance, 128) * 2500.0 +
                            (double)Math.Min(routeRange.Positions.Count, 64) * 500.0 -
                            (double)Math.Min(routeRange.ByteLength, 0x20000UL) * 0.25;
                if (score <= bestScore)
                    continue;

                bestScore = score;
                target = CopyTeleportPosition(checkpoint);
                line = routeLine;
                source = routeRange.Source + ".nextCheckpoint";
                _teleportRouteWinningHeaderAddress = routeRange.HeaderAddress;
                bestDirection = routeDirection;
            }

            if (target != null && _teleportRouteWinningHeaderAddress != 0 && bestDirection != 0)
                RememberAutoRaceRouteDirection(_teleportRouteWinningHeaderAddress, bestDirection);
            return target != null && line != null && line.Count >= 2;
        }

        private static List<byte[]> BuildForwardRouteLine(List<byte[]> positions, int startIndex, int direction)
        {
            if (positions == null || startIndex < 0 || startIndex >= positions.Count || (direction != 1 && direction != -1))
                return null;
            var line = new List<byte[]>(AutoRaceDriveLineMaxPoints);
            byte[] prev = null;
            for (var i = startIndex; i >= 0 && i < positions.Count && line.Count < AutoRaceDriveLineMaxPoints; i += direction)
            {
                var p = positions[i];
                if (!IsPlausibleRouteOrMarkerPosition(p))
                    continue;
                if (prev != null && TeleportHorizontalDistanceSquared(prev, p) > TeleportRouteSegmentBreakDistanceSquared)
                    break;
                line.Add(CopyTeleportPosition(p));
                prev = p;
            }
            return line.Count >= 2 ? line : null;
        }

        private static bool TryFindNearestAutoRaceDriveSegment(
            List<byte[]> line,
            float px,
            float pz,
            out int segmentIndex,
            out float pointX,
            out float pointY,
            out float pointZ,
            out double distanceSquared)
        {
            segmentIndex = -1;
            pointX = 0F;
            pointY = 0F;
            pointZ = 0F;
            distanceSquared = double.MaxValue;
            if (line == null || line.Count < 2)
                return false;

            for (var i = 0; i + 1 < line.Count; i++)
            {
                var a = line[i];
                var b = line[i + 1];
                if (a == null || b == null || a.Length < 12 || b.Length < 12)
                    continue;

                var ax = BitConverter.ToSingle(a, 0);
                var ay = BitConverter.ToSingle(a, 4);
                var az = BitConverter.ToSingle(a, 8);
                var bx = BitConverter.ToSingle(b, 0);
                var by = BitConverter.ToSingle(b, 4);
                var bz = BitConverter.ToSingle(b, 8);
                var sx = bx - ax;
                var sz = bz - az;
                var lenSq = (sx * sx) + (sz * sz);
                if (lenSq < 1e-4F)
                    continue;

                var t = (((px - ax) * sx) + ((pz - az) * sz)) / lenSq;
                if (t < 0F) t = 0F;
                else if (t > 1F) t = 1F;

                var qx = ax + (sx * t);
                var qy = ay + ((by - ay) * t);
                var qz = az + (sz * t);
                var dx = qx - px;
                var dz = qz - pz;
                var d = ((double)dx * dx) + ((double)dz * dz);
                if (d >= distanceSquared)
                    continue;

                distanceSquared = d;
                segmentIndex = i;
                pointX = qx;
                pointY = qy;
                pointZ = qz;
            }

            return segmentIndex >= 0 && IsFiniteFloat(pointX) && IsFiniteFloat(pointY) && IsFiniteFloat(pointZ);
        }

        private bool TryResolveAutoRaceDriveTargetXZ(
            float px,
            float pz,
            float speed,
            out float tx,
            out float tz,
            out float cornerSpeedLimit,
            out float pathX,
            out float pathY,
            out float pathZ,
            out float routeError)
        {
            tx = 0F;
            tz = 0F;
            cornerSpeedLimit = AutoRaceDriveMaxSpeed;
            pathX = 0F;
            pathY = 0F;
            pathZ = 0F;
            routeError = 0F;
            List<byte[]> line;
            byte[] target;
            lock (_autoRaceDriveRouteLock)
            {
                line = _autoRaceDriveLine;
                target = _autoRaceDriveTarget;
            }
            if (line != null && line.Count >= 2)
            {
                int nearest;
                float baseX;
                float baseY;
                float baseZ;
                double nearestDistance;
                if (!TryFindNearestAutoRaceDriveSegment(line, px, pz, out nearest, out baseX, out baseY, out baseZ, out nearestDistance))
                    return false;

                pathX = baseX;
                pathY = baseY;
                pathZ = baseZ;
                cornerSpeedLimit = ComputeAutoRaceDriveCornerLimit(line, nearest);
                routeError = (float)Math.Sqrt(Math.Max(0.0, nearestDistance));
                var dynamicLookahead = AutoRaceDrivePursuitLookahead +
                                       Math.Min(10F, Math.Max(0F, speed) * AutoRaceDriveSpeedLookaheadSeconds);
                if (routeError > 22F)
                {
                    dynamicLookahead = AutoRaceDriveMinLookahead;
                }
                else if (routeError > 10F)
                {
                    dynamicLookahead = Math.Min(dynamicLookahead, 10F);
                }
                dynamicLookahead = Math.Max(AutoRaceDriveMinLookahead, Math.Min(AutoRaceDriveMaxLookahead, dynamicLookahead));
                var bendMinLookahead = Math.Max(AutoRaceDriveMinLookahead, Math.Min(14F, dynamicLookahead * 0.5F));

                var chosenIndex = Math.Min(nearest + 1, line.Count - 1);
                var chosenX = baseX;
                var chosenZ = baseZ;
                var travelled = 0.0;
                var firstDirSet = false;
                var firstDirX = 0F;
                var firstDirZ = 0F;
                var prevX = baseX;
                var prevZ = baseZ;
                for (var i = nearest + 1; i < line.Count; i++)
                {
                    var p = line[i];
                    if (p == null || p.Length < 12)
                        continue;
                    var cx = BitConverter.ToSingle(p, 0);
                    var cz = BitConverter.ToSingle(p, 8);
                    var segX = cx - prevX;
                    var segZ = cz - prevZ;
                    var segLen = (float)Math.Sqrt((double)((segX * segX) + (segZ * segZ)));
                    if (segLen > 1e-3F)
                    {
                        var dirX = segX / segLen;
                        var dirZ = segZ / segLen;
                        if (!firstDirSet)
                        {
                            firstDirX = dirX;
                            firstDirZ = dirZ;
                            firstDirSet = true;
                        }
                        else if (travelled >= bendMinLookahead &&
                                 ((firstDirX * dirX) + (firstDirZ * dirZ)) < AutoRaceDriveBendCos)
                        {
                            chosenIndex = Math.Max(nearest + 1, i - 1);
                            chosenX = prevX;
                            chosenZ = prevZ;
                            break;
                        }
                    }
                    if (travelled + segLen >= dynamicLookahead && segLen > 1e-3F)
                    {
                        var t = (float)((dynamicLookahead - travelled) / segLen);
                        if (t < 0F) t = 0F;
                        else if (t > 1F) t = 1F;
                        chosenIndex = i;
                        chosenX = prevX + (segX * t);
                        chosenZ = prevZ + (segZ * t);
                        break;
                    }
                    travelled += segLen;
                    prevX = cx;
                    prevZ = cz;
                    chosenIndex = i;
                    chosenX = cx;
                    chosenZ = cz;
                }
                tx = chosenX;
                tz = chosenZ;

                var offset = AutoRaceDriveOffWaypointMeters;
                if (offset > 0.01F && chosenIndex > nearest && chosenIndex + 1 < line.Count)
                {
                    var before = line[chosenIndex - 1];
                    var after = line[chosenIndex + 1];
                    if (before != null && before.Length >= 12 && after != null && after.Length >= 12)
                    {
                        var inX = tx - BitConverter.ToSingle(before, 0);
                        var inZ = tz - BitConverter.ToSingle(before, 8);
                        var outX = BitConverter.ToSingle(after, 0) - tx;
                        var outZ = BitConverter.ToSingle(after, 8) - tz;
                        var inLen = (float)Math.Sqrt((double)((inX * inX) + (inZ * inZ)));
                        var outLen = (float)Math.Sqrt((double)((outX * outX) + (outZ * outZ)));
                        if (inLen > 1e-3F && outLen > 1e-3F)
                        {
                            inX /= inLen; inZ /= inLen;
                            outX /= outLen; outZ /= outLen;
                            var outsideX = inX - outX;
                            var outsideZ = inZ - outZ;
                            var sharp = (float)Math.Sqrt((double)((outsideX * outsideX) + (outsideZ * outsideZ)));
                            if (sharp > 1e-3F)
                            {
                                outsideX /= sharp;
                                outsideZ /= sharp;
                                var mag = offset * Math.Min(1F, sharp / 0.5F);
                                var ox = tx + (outsideX * mag);
                                var oz = tz + (outsideZ * mag);
                                if (IsFiniteFloat(ox) && IsFiniteFloat(oz))
                                {
                                    tx = ox;
                                    tz = oz;
                                }
                            }
                        }
                    }
                }
                return IsFiniteFloat(tx) && IsFiniteFloat(tz);
            }

            if (target != null && target.Length >= 12)
            {
                tx = BitConverter.ToSingle(target, 0);
                tz = BitConverter.ToSingle(target, 8);
                pathX = tx;
                pathY = target.Length >= 8 ? BitConverter.ToSingle(target, 4) : 0F;
                pathZ = tz;
                return IsFiniteFloat(tx) && IsFiniteFloat(tz);
            }
            return false;
        }

        private float ComputeAutoRaceDriveCornerLimit(List<byte[]> line, int nearest)
        {
            var limit = AutoRaceDriveMaxSpeed;
            if (line == null || nearest < 0 || nearest >= line.Count)
                return limit;

            var turnRate = Math.Max(0.1F, AutoRaceDriveTurnRate);
            var pdist = 0.0;
            var bx = BitConverter.ToSingle(line[nearest], 0);
            var bz = BitConverter.ToSingle(line[nearest], 8);
            for (var i = nearest + 1; i + 1 < line.Count; i++)
            {
                var cur = line[i];
                var nxt = line[i + 1];
                if (cur == null || cur.Length < 12 || nxt == null || nxt.Length < 12)
                    continue;
                var cx = BitConverter.ToSingle(cur, 0);
                var cz = BitConverter.ToSingle(cur, 8);
                var nx = BitConverter.ToSingle(nxt, 0);
                var nz = BitConverter.ToSingle(nxt, 8);

                var s1x = cx - bx;
                var s1z = cz - bz;
                var s2x = nx - cx;
                var s2z = nz - cz;
                var l1 = (float)Math.Sqrt((double)((s1x * s1x) + (s1z * s1z)));
                var l2 = (float)Math.Sqrt((double)((s2x * s2x) + (s2z * s2z)));
                pdist += l1;

                if (l1 > 1e-3F && l2 > 1e-3F)
                {
                    var cosA = Math.Max(-1F, Math.Min(1F, ((s1x * s2x) + (s1z * s2z)) / (l1 * l2)));
                    var theta = (float)Math.Acos((double)cosA);
                    if (theta > 0.04F)
                    {
                        var radius = ((l1 + l2) * 0.5F) / theta;
                        var vmaxAtBend = turnRate * radius * AutoRaceDriveCornerSafety;
                        var allowedNow = (float)Math.Sqrt((double)((vmaxAtBend * vmaxAtBend) + (2.0 * AutoRaceDriveCornerDecel * pdist)));
                        if (allowedNow < limit)
                            limit = allowedNow;
                    }
                }

                bx = cx;
                bz = cz;
                if (pdist >= AutoRaceDriveCornerPreviewMeters)
                    break;
            }
            return Math.Max(AutoRaceDriveCornerMinSpeed, limit);
        }

        private static void RotateHeadingTowards(ref float curX, ref float curZ, float targetX, float targetZ, float maxRadians)
        {
            var curLen = (float)Math.Sqrt((double)((curX * curX) + (curZ * curZ)));
            if (curLen < 1e-4F)
            {
                curX = targetX;
                curZ = targetZ;
                return;
            }
            curX /= curLen;
            curZ /= curLen;

            var dot = Math.Max(-1F, Math.Min(1F, (curX * targetX) + (curZ * targetZ)));
            var angle = (float)Math.Acos(dot);
            if (angle <= maxRadians || angle < 1e-4F)
            {
                curX = targetX;
                curZ = targetZ;
                return;
            }

            var cross = (curX * targetZ) - (curZ * targetX);
            var signed = cross >= 0F ? maxRadians : -maxRadians;
            var ca = (float)Math.Cos(signed);
            var sa = (float)Math.Sin(signed);
            var rx = (curX * ca) - (curZ * sa);
            var rz = (curX * sa) + (curZ * ca);
            curX = rx;
            curZ = rz;
        }

        private void TeleportVehicleToSavedLocation(RuntimeDetour vehicleDetour, byte[] savedPosition, string name)
        {
            if (vehicleDetour == null)
                throw new InvalidOperationException("Teleport hook is not ready yet.");
            if (!IsValidTeleportPosition(savedPosition))
                throw new InvalidOperationException("Saved teleport location is not valid.");

            var vehiclePointer = ReadCurrentVehiclePointer(vehicleDetour);
            if (!IsTeleportVehicleWriteReady(vehiclePointer, DateTime.UtcNow.Ticks))
                throw new InvalidOperationException("Current vehicle is still settling. Try the teleport again in a moment.");
            var position = vehiclePointer == 0 ? CopyTeleportPosition(savedPosition) : BuildTeleportVehiclePosition(vehiclePointer, savedPosition);
            if (!QueueVehicleControlTeleport(vehicleDetour, position))
                throw new InvalidOperationException("A previous teleport is still being applied. Try again in a moment.");
            _teleportRepeatPosition = position;
            _teleportRepeatUntilUtcTicks = DateTime.UtcNow.Ticks + TimeSpan.TicksPerMillisecond * 650;

            _log("Saved Location Teleport fired to " + (string.IsNullOrWhiteSpace(name) ? "saved spot" : name) + " at " + FormatTeleportPosition(position) + ".");
        }

        private ulong ReadCurrentVehiclePointer(RuntimeDetour vehicleDetour)
        {
            if (vehicleDetour == null || vehicleDetour.DetourAddress == 0)
                return 0;

            var layout = GetVehicleControlLayout();
            return ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);
        }

        private void ResetTeleportVehicleStability()
        {
            _assistVehiclePtr = 0;
            _assistVehicleIdentity = 0;
            _assistVehicleSettleUntilTicks = 0;
        }

        private bool IsTeleportVehicleWriteReady(ulong vehiclePointer, long nowTicks)
        {
            if (!IsAssistVehicleWriteSafe(vehiclePointer, nowTicks) ||
                !IsReadableMemoryRange(vehiclePointer + 0x50UL, 16) ||
                !IsWritableMemoryRange(vehiclePointer + 0x20UL, 16) ||
                !IsWritableMemoryRange(vehiclePointer + 0x50UL, 16))
                return false;

            byte[] position;
            try
            {
                position = ReadBytes(vehiclePointer + 0x50UL, 16);
            }
            catch
            {
                return false;
            }
            return IsValidTeleportPosition(position);
        }

        private static byte[] CopyTeleportPosition(byte[] position)
        {
            var copy = new byte[16];
            if (position != null)
                Buffer.BlockCopy(position, 0, copy, 0, Math.Min(16, position.Length));
            return copy;
        }

        private bool QueueVehicleControlTeleport(RuntimeDetour vehicleDetour, byte[] position)
        {
            if (vehicleDetour == null || vehicleDetour.DetourAddress == 0 || position == null || position.Length < 16)
                return false;

            var layout = GetVehicleControlLayout();
            var toggleAddress = vehicleDetour.DetourAddress + (ulong)layout.TeleportToggleOffset;
            lock (_runtimeMemoryWriteLock)
            {
                if (ReadByte(toggleAddress) != 0)
                    return false;
                WriteBytes(vehicleDetour.DetourAddress + (ulong)layout.TeleportPositionOffset, position);
                WriteByte(toggleAddress, 1);
            }
            return true;
        }

        private byte[] BuildTeleportVehiclePosition(ulong vehiclePointer, byte[] position)
        {
            var target = new byte[16];
            var current = vehiclePointer == 0 ? null : ReadBytes(vehiclePointer + 0x50UL, 16);
            if (current != null && current.Length >= 16)
                Buffer.BlockCopy(current, 0, target, 0, 16);
            else if (position != null && position.Length >= 16)
                Buffer.BlockCopy(position, 0, target, 0, 16);

            if (position != null && position.Length >= 12)
            {
                Buffer.BlockCopy(position, 0, target, 0, 12);
                if (IsFlatTeleportMapMarker(position))
                {
                    if (current != null && current.Length >= 8 && IsValidTeleportPosition(current))
                        Buffer.BlockCopy(current, 4, target, 4, 4);
                    else
                    {
                        var safeHeight = 120F;
                        Buffer.BlockCopy(BitConverter.GetBytes(safeHeight), 0, target, 4, 4);
                    }
                }
            }
            return target;
        }

        private static byte[] AddTeleportVerticalLift(byte[] position, float liftMeters)
        {
            var target = CopyTeleportPosition(position);
            if (target.Length >= 8 && !float.IsNaN(liftMeters) && !float.IsInfinity(liftMeters))
            {
                var y = BitConverter.ToSingle(target, 4);
                if (!float.IsNaN(y) && !float.IsInfinity(y))
                    Buffer.BlockCopy(BitConverter.GetBytes(y + liftMeters), 0, target, 4, 4);
            }
            return target;
        }

        private void ApplyPendingTeleport(long nowTicks)
        {
            ApplyPendingTeleportSlot(nowTicks, ref _teleportRepeatPosition, ref _teleportRepeatUntilUtcTicks, true);
            ApplyPendingTeleportSlot(nowTicks, ref _teleportCheckpointRepeatPosition, ref _teleportCheckpointRepeatUntilUtcTicks, AutoRaceResetSpeed);
            ApplyPendingTeleportSlot(nowTicks, ref _checkpointRecoveryRepeatPosition, ref _checkpointRecoveryRepeatUntilUtcTicks, false);
        }

        private void ApplyPendingTeleportSlot(long nowTicks, ref byte[] repeatPosition, ref long repeatUntilUtcTicks, bool zeroVelocity)
        {
            var position = repeatPosition;
            if (position == null)
                return;
            if (nowTicks > repeatUntilUtcTicks)
            {
                repeatPosition = null;
                repeatUntilUtcTicks = 0;
                return;
            }

            var vehicleDetour = _teleportVehicleDetour;
            if (vehicleDetour == null || vehicleDetour.DetourAddress == 0)
                return;

            var layout = GetVehicleControlLayout();
            var vehiclePointer = ReadUInt64(vehicleDetour.DetourAddress + (ulong)layout.VehiclePointerOffset);
            if (!IsTeleportVehicleWriteReady(vehiclePointer, nowTicks))
                return;

            ApplyTeleportPosition(vehiclePointer, position, zeroVelocity);
        }

        private void ApplyTeleportPosition(ulong vehiclePointer, byte[] position)
        {
            ApplyTeleportPosition(vehiclePointer, position, true);
        }

        private void ApplyTeleportPosition(ulong vehiclePointer, byte[] position, bool zeroVelocity)
        {
            if (position == null || position.Length < 16)
                return;

            WriteBytes(vehiclePointer + 0x50UL, position);
            if (zeroVelocity)
                WriteBytes(vehiclePointer + 0x20UL, new byte[16]);
            SyncFlyHoldToTeleport(position, zeroVelocity);
        }

        private void SyncFlyHoldToTeleport(byte[] position, bool zeroVelocity)
        {
            if (_hoverGuardTimer == null || position == null || position.Length < 12)
                return;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            if (!IsFiniteFloat(x) || !IsFiniteFloat(y) || !IsFiniteFloat(z))
                return;

            _hoverHoldX = x;
            _hoverHoldY = y;
            _hoverHoldZ = z;
            _hoverHoldSeeded = true;
            if (zeroVelocity)
            {
                _hoverVelX = 0F;
                _hoverVelY = 0F;
                _hoverVelZ = 0F;
            }
        }

        private bool TryReadBestWaypointPosition(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;

            var current = GetLiveVehicleRouteAnchor(vehiclePointer);
            if (IsPlausibleWorldTeleportPosition(current) &&
                TryReadCurrentDestinationWaypoint(
                    _teleportWaypointDetour,
                    _teleportWaypointDescriptor,
                    _teleportWaypointCopyDetours,
                    _teleportWaypointCopyDescriptors,
                    current,
                    out position))
                return true;

            return TryReadWaypointPositionFromModuleRouteVectorMemoryScan(vehiclePointer, out position);
        }

        private void CaptureTeleportWaypointRouteAnchor(long nowTicks)
        {
            var vehiclePointer = ReadCurrentVehiclePointer(_teleportVehicleDetour);
            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
                return;

            var current = ReadBytes(vehiclePointer + 0x50UL, 16);
            if (!IsPlausibleWorldTeleportPosition(current))
                return;

            _teleportWaypointRouteAnchorPosition = CopyTeleportPosition(current);
            _teleportWaypointRouteAnchorUntilUtcTicks = nowTicks + TimeSpan.TicksPerSecond * 2;
        }

        private byte[] GetTeleportWaypointRouteAnchor(ulong vehiclePointer)
        {
            if (vehiclePointer != 0 && IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
            {
                var current = ReadBytes(vehiclePointer + 0x50UL, 16);
                if (IsPlausibleWorldTeleportPosition(current))
                    return current;
            }

            var nowTicks = DateTime.UtcNow.Ticks;
            if (_teleportWaypointRouteAnchorPosition != null &&
                nowTicks < _teleportWaypointRouteAnchorUntilUtcTicks &&
                IsPlausibleWorldTeleportPosition(_teleportWaypointRouteAnchorPosition))
                return CopyTeleportPosition(_teleportWaypointRouteAnchorPosition);
            return null;
        }

        private byte[] GetLiveVehicleRouteAnchor(ulong vehiclePointer)
        {
            if (vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
                return null;
            var current = ReadBytes(vehiclePointer + 0x50UL, 16);
            return IsPlausibleWorldTeleportPosition(current) ? current : null;
        }

        private bool TryReadBestCheckpointPosition(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;

            if (TryReadCheckpointPositionFromModuleRouteVector(vehiclePointer, out position))
                return true;

            if (TryReadCheckpointPositionFromCapturedRouteObjects(vehiclePointer, out position))
                return true;

            if (TryReadCheckpointPositionFromRouteMemoryScan(vehiclePointer, out position))
                return true;

            return false;
        }

        private bool TryReadAutoRacePathPosition(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            var anchor = GetLiveVehicleRouteAnchor(vehiclePointer);
            if (!IsPlausibleWorldTeleportPosition(anchor))
                return false;

            List<byte[]> readyLine = null;
            lock (_autoRaceDriveRouteLock)
            {
                if (_autoRaceDriveLine != null && _autoRaceDriveLine.Count >= 2)
                    readyLine = _autoRaceDriveLine.Select(CopyTeleportPosition).ToList();
            }
            if (readyLine != null &&
                TrySelectAutoRaceTeleportPathPoint(readyLine, anchor, AutoRaceTeleportPathStepMeters, out position))
            {
                _teleportLastSource = "validatedRouteSnapshot.path";
                return true;
            }

            if (_teleportCheckpointRouteHeaderAddress == 0)
            {
                byte[] ignoredCheckpoint;
                if (!TryReadCheckpointPositionFromModuleRouteVector(vehiclePointer, out ignoredCheckpoint))
                    return false;
            }

            var ranges = new List<TeleportRouteRangeCandidate>();
            CollectModuleRouteVectorAtHeader(_teleportCheckpointRouteHeaderAddress, ranges);
            byte[] checkpoint;
            List<byte[]> line;
            string source;
            if (!TrySelectAutoRaceDriveRoute(ranges, anchor, vehiclePointer, out checkpoint, out line, out source) ||
                line == null || line.Count < 2)
            {
                _teleportCheckpointRouteHeaderAddress = 0;
                return false;
            }

            if (!TrySelectAutoRaceTeleportPathPoint(line, anchor, AutoRaceTeleportPathStepMeters, out position))
                return false;

            lock (_autoRaceDriveRouteLock)
            {
                _autoRaceDriveTarget = CopyTeleportPosition(checkpoint);
                _autoRaceDriveLine = line;
            }
            _teleportLastSource = source + ".path";
            return true;
        }

        private static bool TrySelectAutoRaceTeleportPathPoint(
            List<byte[]> line,
            byte[] anchor,
            float distanceAhead,
            out byte[] position)
        {
            position = null;
            if (line == null || line.Count < 2 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var px = BitConverter.ToSingle(anchor, 0);
            var pz = BitConverter.ToSingle(anchor, 8);
            int segmentIndex;
            float baseX;
            float baseY;
            float baseZ;
            double routeDistance;
            if (!TryFindNearestAutoRaceDriveSegment(
                line, px, pz, out segmentIndex, out baseX, out baseY, out baseZ, out routeDistance))
                return false;
            if (routeDistance > AutoRaceDriveOnRouteMaxSquared)
                return false;

            var remaining = Math.Max(4F, distanceAhead);
            var previousX = baseX;
            var previousY = baseY;
            var previousZ = baseZ;
            for (var i = segmentIndex + 1; i < line.Count; i++)
            {
                var next = line[i];
                if (next == null || next.Length < 12)
                    continue;
                var nextX = BitConverter.ToSingle(next, 0);
                var nextY = BitConverter.ToSingle(next, 4);
                var nextZ = BitConverter.ToSingle(next, 8);
                var dx = nextX - previousX;
                var dz = nextZ - previousZ;
                var length = (float)Math.Sqrt((double)((dx * dx) + (dz * dz)));
                if (length <= 0.001F)
                    continue;

                if (remaining <= length)
                {
                    var t = Math.Max(0F, Math.Min(1F, remaining / length));
                    position = CopyTeleportPosition(next);
                    Buffer.BlockCopy(BitConverter.GetBytes(previousX + (dx * t)), 0, position, 0, 4);
                    Buffer.BlockCopy(BitConverter.GetBytes(previousY + ((nextY - previousY) * t)), 0, position, 4, 4);
                    Buffer.BlockCopy(BitConverter.GetBytes(previousZ + (dz * t)), 0, position, 8, 4);
                    return IsPlausibleWorldTeleportPosition(position) &&
                        TeleportHorizontalDistanceSquared(position, anchor) >= 4.0;
                }

                remaining -= length;
                previousX = nextX;
                previousY = nextY;
                previousZ = nextZ;
            }

            var endpoint = line[line.Count - 1];
            if (!IsPlausibleWorldTeleportPosition(endpoint) ||
                TeleportHorizontalDistanceSquared(endpoint, anchor) < 4.0)
                return false;
            position = CopyTeleportPosition(endpoint);
            return true;
        }

        private bool TryReadCheckpointPositionFromModuleRouteVector(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var current = GetLiveVehicleRouteAnchor(vehiclePointer);
            if (!IsPlausibleWorldTeleportPosition(current))
                return false;

            ulong directHeader;
            if (!TryResolveFreshWaypointRouteHeader(out directHeader))
                return false;

            _teleportCheckpointRouteHeaderAddress = directHeader;
            var routeRanges = new List<TeleportRouteRangeCandidate>();
            CollectModuleRouteVectorAtHeader(directHeader, routeRanges);
            string source;
            if (!TrySelectTeleportCheckpointRoute(routeRanges, current, vehiclePointer, out position, out source))
                return false;

            _teleportLastSource = source;
            return true;
        }

        private bool TryReadWaypointPositionFromModuleRouteVectorMemoryScan(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var current = GetTeleportWaypointRouteAnchor(vehiclePointer);
            if (!IsPlausibleWorldTeleportPosition(current))
                return false;

            ulong resolvedHeader;
            if (!TryResolveFreshWaypointRouteHeader(out resolvedHeader))
                return false;

            var routeRanges = new List<TeleportRouteRangeCandidate>();
            CollectModuleRouteVectorAtHeader(resolvedHeader, routeRanges);
            string source;
            if (!TrySelectFreshWaypointRouteDestination(routeRanges, current, vehiclePointer, out position, out source))
                return false;

            _teleportLastSource = source;
            return true;
        }

        private bool TryResolveFreshWaypointRouteHeader(out ulong headerAddress)
        {
            headerAddress = 0;
            if (_teleportRouteHeaderAddress != 0 && IsLiveTeleportRouteVectorHeader(_teleportRouteHeaderAddress))
            {
                headerAddress = _teleportRouteHeaderAddress;
                return true;
            }

            _teleportRouteHeaderAddress = 0;
            ulong signatureAddress;
            if (!TryFindTeleportRouteSignature(out signatureAddress))
                return false;

            var displacementBytes = ReadBytes(signatureAddress + 5UL, 4);
            if (displacementBytes == null || displacementBytes.Length != 4)
                return false;
            var displacement = BitConverter.ToInt32(displacementBytes, 0);
            var resolved = (long)signatureAddress + 9L + displacement;
            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            if (resolved <= 0 || (ulong)resolved < _mainBase || (ulong)resolved + 16UL > moduleEnd)
                return false;
            if (!IsLiveTeleportRouteVectorHeader((ulong)resolved))
                return false;

            _teleportRouteHeaderAddress = (ulong)resolved;
            headerAddress = _teleportRouteHeaderAddress;
            return true;
        }

        private bool TryFindTeleportRouteSignature(out ulong signatureAddress)
        {
            signatureAddress = 0;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var pattern = Pattern.Parse(TeleportWaypointRouteVectorSignature);
            var preferredOffset = (int)Math.Min((ulong)_mainSize, TeleportWaypointRouteSignaturePreferredSearchRva);
            var preferredLength = Math.Min(
                TeleportWaypointRouteSignaturePreferredSearchBytes,
                Math.Max(0, _mainSize - preferredOffset));
            if (preferredLength > 0)
            {
                var preferred = ReadBytes(_mainBase + (ulong)preferredOffset, preferredLength);
                var preferredMatches = Pattern.FindAll(preferred, pattern, 2).ToList();
                if (preferredMatches.Count == 1)
                {
                    signatureAddress = _mainBase + (ulong)preferredOffset + (ulong)preferredMatches[0];
                    return true;
                }
            }

            var overlap = Math.Max(32, TeleportWaypointRouteVectorSignature.Split(' ').Length + 8);
            var uniqueMatches = new HashSet<ulong>();
            var moduleEnd = _mainBase + (ulong)_mainSize;
            var moduleRegions = EnumerateReadableRegions()
                .Where(region => region.BaseAddress < moduleEnd && region.BaseAddress + region.RegionSize > _mainBase)
                .OrderBy(region => region.BaseAddress)
                .ToList();
            foreach (var region in moduleRegions)
            {
                var regionStart = Math.Max(region.BaseAddress, _mainBase);
                var regionEnd = Math.Min(region.BaseAddress + region.RegionSize, moduleEnd);
                byte[] carry = null;
                for (var address = regionStart; address < regionEnd; address += (ulong)TeleportWaypointRouteSignatureScanChunkBytes)
                {
                    var length = (int)Math.Min(
                        (ulong)TeleportWaypointRouteSignatureScanChunkBytes,
                        regionEnd - address);
                    var current = ReadBytes(address, length);
                    if (current == null || current.Length == 0)
                    {
                        carry = null;
                        continue;
                    }

                    byte[] scan;
                    ulong scanAddress;
                    if (carry != null && carry.Length > 0)
                    {
                        scan = new byte[carry.Length + current.Length];
                        Buffer.BlockCopy(carry, 0, scan, 0, carry.Length);
                        Buffer.BlockCopy(current, 0, scan, carry.Length, current.Length);
                        scanAddress = address - (ulong)carry.Length;
                    }
                    else
                    {
                        scan = current;
                        scanAddress = address;
                    }

                    foreach (var match in Pattern.FindAll(scan, pattern, 2))
                    {
                        uniqueMatches.Add(scanAddress + (ulong)match);
                        if (uniqueMatches.Count > 1)
                            return false;
                    }

                    var carryLength = Math.Min(overlap, current.Length);
                    carry = new byte[carryLength];
                    Buffer.BlockCopy(current, current.Length - carryLength, carry, 0, carryLength);
                }
            }

            if (uniqueMatches.Count != 1)
                return false;

            signatureAddress = uniqueMatches.First();
            return true;
        }

        private bool IsLiveTeleportRouteVectorHeader(ulong headerAddress)
        {
            if (!IsReadableMemoryRange(headerAddress, 16))
                return false;

            var header = ReadBytes(headerAddress, 16);
            if (header == null || header.Length != 16)
                return false;

            var begin = BitConverter.ToUInt64(header, 0);
            var end = BitConverter.ToUInt64(header, 8);
            if (begin < 0x10000UL || end <= begin)
                return false;

            var byteLength = end - begin;
            if (byteLength < 160UL || byteLength > 0x100000UL || (byteLength & 15UL) != 0)
                return false;
            if (!IsReadableMemoryRange(begin, (int)Math.Min(byteLength, 320UL)))
                return false;

            var probe = ReadBytes(begin, (int)Math.Min(byteLength, 320UL));
            if (probe == null || probe.Length < 32)
                return false;

            var plausible = 0;
            var slots = probe.Length / 16;
            for (var offset = 0; offset + 12 <= probe.Length; offset += 16)
            {
                var candidate = new byte[16];
                Buffer.BlockCopy(probe, offset, candidate, 0, Math.Min(16, probe.Length - offset));
                if (IsPlausibleWorldTeleportPosition(candidate))
                    plausible++;
            }

            return slots > 0 && plausible * 4 >= slots * 3;
        }

        private bool TrySelectFreshWaypointRouteDestination(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            ulong vehiclePointer,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            _teleportRouteWinningHeaderAddress = 0;
            if (routeRanges == null || routeRanges.Count == 0 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var bestScore = double.MinValue;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var route = routeRanges[i];
                if (route == null || route.Positions == null || route.Positions.Count < 8 || route.ByteLength < 128UL)
                    continue;

                var slots = Math.Max(1, (int)(route.ByteLength / 16UL));
                if (route.Positions.Count * 4 < slots * 3)
                    continue;

                var runStart = 0;
                while (runStart < route.Positions.Count - 1)
                {
                    var runEnd = runStart;
                    while (runEnd + 1 < route.Positions.Count &&
                        TeleportHorizontalDistanceSquared(route.Positions[runEnd], route.Positions[runEnd + 1]) <=
                            TeleportRouteSegmentBreakDistanceSquared)
                        runEnd++;

                    if (runEnd - runStart >= 3)
                    {
                        byte[] marker;
                        string markerSide;
                        if (TryGetTerminalRouteMarker(route.Positions, runStart, runEnd, out marker, out markerSide) &&
                            IsPlausibleModuleWaypointEndpoint(marker))
                        {
                            var markerDistance = TeleportHorizontalDistanceSquared(marker, anchor);
                            if (markerDistance >= 25.0)
                            {
                                var origin = string.Equals(markerSide, "start", StringComparison.OrdinalIgnoreCase)
                                    ? route.Positions[runEnd]
                                    : route.Positions[runStart];
                                var originDistance = TeleportHorizontalDistanceSquared(origin, anchor);
                                var nearestDistance = double.MaxValue;
                                var pathLength = 0.0;
                                for (var p = runStart; p <= runEnd; p++)
                                {
                                    nearestDistance = Math.Min(
                                        nearestDistance,
                                        TeleportHorizontalDistanceSquared(route.Positions[p], anchor));
                                    if (p > runStart)
                                        pathLength += Math.Sqrt(Math.Max(
                                            0.0,
                                            TeleportHorizontalDistanceSquared(route.Positions[p - 1], route.Positions[p])));
                                }

                                if (nearestDistance <= AutoRaceDriveOnRouteMaxSquared && pathLength >= 10.0)
                                {
                                    var originBonus = Math.Max(0.0, 250000.0 - Math.Min(originDistance, 250000.0));
                                    var proximityBonus = Math.Max(0.0, AutoRaceDriveOnRouteMaxSquared - nearestDistance);
                                    var score = route.Priority +
                                        (originBonus * 1000000000.0) +
                                        (proximityBonus * 1000000.0) +
                                        (Math.Min(pathLength, 100000.0) * 10000.0) +
                                        Math.Min(markerDistance, 100000000.0);
                                    if (score > bestScore)
                                    {
                                        bestScore = score;
                                        position = CopyTeleportPosition(marker);
                                        source = route.Source + ".selectedWaypoint.marker." + markerSide;
                                        _teleportRouteWinningHeaderAddress = route.HeaderAddress;
                                    }
                                }
                            }
                        }
                    }

                    runStart = Math.Max(runStart + 1, runEnd + 1);
                }
            }

            return position != null;
        }

        private void CollectModuleRouteVectorAtHeader(ulong headerAddress, List<TeleportRouteRangeCandidate> routeRanges)
        {
            if (headerAddress == 0 || routeRanges == null || !IsReadableMemoryRange(headerAddress, 16))
                return;

            var data = ReadBytes(headerAddress, 16);
            if (data.Length < 16)
                return;

            byte[] inferredCurrent = null;
            var inferredCurrentSpread = double.MaxValue;
            CollectTeleportMemoryRouteRange(
                data,
                0,
                headerAddress,
                0UL,
                8UL,
                1.0e12,
                "moduleRouteVector",
                routeRanges,
                ref inferredCurrent,
                ref inferredCurrentSpread);
        }

        private bool TryReadCurrentDestinationWaypoint(
            RuntimeDetour waypointDetour,
            RuntimeProfileHookDescriptor waypointDescriptor,
            List<RuntimeDetour> copyDetours,
            List<RuntimeProfileHookDescriptor> copyDescriptors,
            byte[] currentVehiclePosition,
            out byte[] position)
        {
            position = null;

            string source;
            if (TryReadCapturedWaypointDescriptor(waypointDetour, waypointDescriptor, currentVehiclePosition, out position, out source))
            {
                _teleportLastSource = source;
                return true;
            }

            var count = Math.Min(copyDetours == null ? 0 : copyDetours.Count, copyDescriptors == null ? 0 : copyDescriptors.Count);
            for (var i = 0; i < count; i++)
            {
                var detour = copyDetours[i];
                var descriptor = copyDescriptors[i];
                if (TryReadCapturedWaypointDescriptor(detour, descriptor, currentVehiclePosition, out position, out source))
                {
                    _teleportLastSource = source;
                    return true;
                }
            }

            return false;
        }

        private bool TryReadCapturedWaypointDescriptor(
            RuntimeDetour detour,
            RuntimeProfileHookDescriptor descriptor,
            byte[] currentVehiclePosition,
            out byte[] position,
            out string source)
        {
            position = null;
            source = string.Empty;
            if (detour == null || descriptor == null || detour.DetourAddress == 0)
                return false;

            ulong objectPointer = 0;
            if (descriptor.ObjectPointerOffset >= 0)
                objectPointer = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);

            if (IsCurrentDestinationCaptureSource(descriptor))
            {
                byte[] candidate;
                bool hasDestinationFlag;
                if (objectPointer != 0 &&
                    TryReadCurrentDestinationObject(objectPointer, out candidate, out hasDestinationFlag) &&
                    IsValidTeleportPosition(candidate) &&
                    !IsWaypointCandidateVehiclePosition(candidate, currentVehiclePosition))
                {
                    position = CopyTeleportPosition(candidate);
                    source = descriptor.Key + ".currentObject" + (hasDestinationFlag ? ".flag" : string.Empty);
                    return true;
                }

                if (descriptor.CaptureOffset >= 0)
                {
                    candidate = ReadBytes(detour.DetourAddress + (ulong)descriptor.CaptureOffset, 16);
                    if (IsPlausibleRouteOrMarkerPosition(candidate) &&
                        !IsWaypointCandidateVehiclePosition(candidate, currentVehiclePosition))
                    {
                        position = CopyTeleportPosition(candidate);
                        source = descriptor.Key + ".capture";
                        return true;
                    }
                }

                return false;
            }

            if (!IsNavigationDestinationCaptureSource(descriptor))
                return false;

            if (objectPointer != 0)
            {
                byte[] candidate;
                var layout = TeleportWaypointDestinationLayoutPrimary;
                if (!TryReadNavigationDestinationObjectLayout(objectPointer, layout, out candidate))
                {
                    layout = TeleportWaypointDestinationLayoutMirror;
                    if (!TryReadNavigationDestinationObjectLayout(objectPointer, layout, out candidate))
                        candidate = null;
                }

                if (IsValidTeleportPosition(candidate) &&
                    !IsWaypointCandidateVehiclePosition(candidate, currentVehiclePosition))
                {
                    position = CopyTeleportPosition(candidate);
                    source = descriptor.Key + ".object";
                    RememberTeleportWaypointDestinationObject(objectPointer, layout, source);
                    return true;
                }
            }

            if (descriptor.CaptureOffset >= 0)
            {
                var candidate = ReadBytes(detour.DetourAddress + (ulong)descriptor.CaptureOffset, 16);
                if (IsPlausibleRouteOrMarkerPosition(candidate) &&
                    !IsWaypointCandidateVehiclePosition(candidate, currentVehiclePosition))
                {
                    position = CopyTeleportPosition(candidate);
                    source = descriptor.Key + ".capture";
                    return true;
                }
            }

            return false;
        }

        private bool TryReadNavigationDestinationObject(ulong objectPointer, out byte[] position)
        {
            position = null;
            if (!IsLikelyTeleportPointer(objectPointer) || !IsReadableMemoryRange(objectPointer, 0x5B0))
                return false;

            var vtable = ReadUInt64(objectPointer);
            if (!IsKnownNavigationDestinationVtable(vtable))
                return false;

            byte[] primary;
            double spread;
            if (TryReadDestinationOffsetGroup(objectPointer, TeleportNavigationDestinationPrimaryOffsets, out primary, out spread))
            {
                position = primary;
                return true;
            }

            if (TryReadDestinationOffsetGroup(objectPointer, TeleportNavigationDestinationMirrorOffsets, out primary, out spread))
            {
                position = primary;
                return true;
            }

            return false;
        }

        private bool TryReadCachedWaypointDestination(byte[] currentVehiclePosition, out byte[] position)
        {
            return TryReadCachedWaypointDestination(currentVehiclePosition, out position, false);
        }

        private bool TryReadCachedWaypointDestination(byte[] currentVehiclePosition, out byte[] position, bool routeEndpointOnly)
        {
            position = null;

            ulong objectPointer;
            int layout;
            string source;
            lock (_teleportWaypointDestinationCacheLock)
            {
                objectPointer = _teleportWaypointDestinationObject;
                layout = _teleportWaypointDestinationLayout;
                source = _teleportWaypointDestinationSource;
            }

            if (objectPointer == 0)
                return false;
            if (routeEndpointOnly && layout != TeleportWaypointDestinationLayoutRouteEndpoint)
                return false;

            if (!TryReadNavigationDestinationObjectLayout(objectPointer, layout, out position))
            {
                ClearTeleportWaypointDestinationCache();
                return false;
            }
            if (layout != TeleportWaypointDestinationLayoutRouteEndpoint &&
                IsWaypointCandidateVehiclePosition(position, currentVehiclePosition))
            {
                ClearTeleportWaypointDestinationCache();
                position = null;
                return false;
            }

            _teleportLastSource = string.IsNullOrWhiteSpace(source) ? "navigationDestination.cache" : source + ".cache";
            return true;
        }

        private void QueueTeleportWaypointDestinationPrewarmScan(ulong vehiclePointer)
        {
            if (!IsAlive)
                return;

            var nowTicks = DateTime.UtcNow.Ticks;
            if (nowTicks < _teleportWaypointDestinationScanNextUtcTicks)
                return;
            if (System.Threading.Interlocked.CompareExchange(ref _teleportWaypointDestinationScanRunning, 1, 0) != 0)
                return;

            _teleportWaypointDestinationScanNextUtcTicks = nowTicks + TimeSpan.TicksPerSecond * 3;
            ThreadPool.QueueUserWorkItem(_ =>
            {
                try
                {
                    ulong ignoredHeader;
                    TryResolveFreshWaypointRouteHeader(out ignoredHeader);
                }
                catch (Exception ex)
                {
                    LogRuntimeGuardWaiting("Teleport To Waypoint", ex);
                }
                finally
                {
                    System.Threading.Interlocked.Exchange(ref _teleportWaypointDestinationScanRunning, 0);
                }
            });
        }

        private bool TryReadNavigationDestinationObjectLayout(ulong objectPointer, int layout, out byte[] position)
        {
            position = null;
            var requiredBytes = layout == TeleportWaypointDestinationLayoutMarker
                ? 0x790
                : layout == TeleportWaypointDestinationLayoutRouteEndpoint
                ? 0x170
                : 0x5B0;
            if (!IsLikelyTeleportPointer(objectPointer) || !IsReadableMemoryRange(objectPointer, requiredBytes))
                return false;

            var vtable = ReadUInt64(objectPointer);
            if (layout == TeleportWaypointDestinationLayoutMarker)
            {
                if (!IsKnownWaypointMarkerVtable(vtable))
                    return false;
            }
            else if (layout == TeleportWaypointDestinationLayoutRouteEndpoint)
            {
                if (!IsKnownRouteEndpointDestinationVtable(vtable))
                    return false;
            }
            else if (!IsKnownNavigationDestinationVtable(vtable))
            {
                return false;
            }

            double spread;
            var offsets = layout == TeleportWaypointDestinationLayoutMarker
                ? TeleportWaypointMarkerDestinationOffsets
                : layout == TeleportWaypointDestinationLayoutRouteEndpoint
                ? TeleportRouteEndpointDestinationOffsets
                : layout == TeleportWaypointDestinationLayoutMirror
                ? TeleportNavigationDestinationMirrorOffsets
                : TeleportNavigationDestinationPrimaryOffsets;
            return TryReadDestinationOffsetGroup(objectPointer, offsets, out position, out spread);
        }

        private void RememberTeleportWaypointDestinationObject(ulong objectPointer, int layout, string source)
        {
            if (objectPointer == 0)
                return;

            lock (_teleportWaypointDestinationCacheLock)
            {
                _teleportWaypointDestinationObject = objectPointer;
                _teleportWaypointDestinationLayout = layout;
                _teleportWaypointDestinationSource = string.IsNullOrWhiteSpace(source) ? "navigationDestination" : source;
            }
        }

        private void ClearTeleportWaypointDestinationCache()
        {
            lock (_teleportWaypointDestinationCacheLock)
            {
                _teleportWaypointDestinationObject = 0;
                _teleportWaypointDestinationLayout = TeleportWaypointDestinationLayoutPrimary;
                _teleportWaypointDestinationSource = string.Empty;
                _teleportWaypointDestinationScanNextUtcTicks = 0;
            }
        }

        private bool TryReadDestinationOffsetGroup(ulong objectPointer, ulong[] offsets, out byte[] position, out double maxSpread)
        {
            position = null;
            maxSpread = 0.0;
            if (offsets == null || offsets.Length < 2)
                return false;

            var agreeingCopies = 0;
            for (var i = 0; i < offsets.Length; i++)
            {
                var address = objectPointer + offsets[i];
                if (!IsReadableMemoryRange(address, 16))
                    continue;

                var candidate = ReadBytes(address, 16);
                if (!IsPlausibleWorldTeleportPosition(candidate))
                    continue;

                if (position == null)
                {
                    position = candidate;
                    agreeingCopies = 1;
                    continue;
                }

                var spread = TeleportHorizontalDistanceSquared(candidate, position);
                if (spread >= 25.0)
                    continue;

                agreeingCopies++;
                if (spread > maxSpread)
                    maxSpread = spread;
            }

            return position != null && agreeingCopies >= 2;
        }

        private static bool IsWaypointCandidateVehiclePosition(byte[] candidate, byte[] currentVehiclePosition)
        {
            if (candidate == null || currentVehiclePosition == null || candidate.Length < 12 || currentVehiclePosition.Length < 12)
                return false;

            return TeleportDistanceSquared(candidate, currentVehiclePosition) < 9.0;
        }

        private bool TryReadWaypointPositionFromRouteNodeMemoryScan(byte[] currentVehiclePosition, out byte[] position)
        {
            position = null;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var routeNodeVtable = _mainBase + TeleportWaypointRouteNodeVtableRva;
            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            if (routeNodeVtable < _mainBase || routeNodeVtable >= moduleEnd)
                return false;

            var needle = BitConverter.GetBytes(routeNodeVtable);
            var scanWatch = Stopwatch.StartNew();
            byte[] best = null;
            var bestScore = double.MinValue;
            var bestCount = 0;
            var bestSource = string.Empty;

            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.RegionSize >= 0x10000UL)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderBy(GetTeleportWaypointRouteNodeRegionPriority)
                .ThenBy(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                    break;

                var current = region.BaseAddress;
                var remaining = region.RegionSize;
                var carry = new byte[0];

                while (remaining > 0)
                {
                    if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                        break;

                    var take = (int)Math.Min(TeleportWaypointRouteNodeMaxChunkBytes, remaining);
                    if (take < (int)(TeleportWaypointRouteNodePositionOffset + 16UL))
                        break;

                    var read = ReadBytes(current, take);
                    if (read.Length >= (int)(TeleportWaypointRouteNodePositionOffset + 16UL))
                    {
                        var data = new byte[carry.Length + read.Length];
                        if (carry.Length > 0)
                            Buffer.BlockCopy(carry, 0, data, 0, carry.Length);
                        Buffer.BlockCopy(read, 0, data, carry.Length, read.Length);
                        var dataBase = current - (ulong)carry.Length;

                        ScanWaypointRouteNodeBuffer(data, dataBase, needle, currentVehiclePosition, ref best, ref bestScore, ref bestCount, ref bestSource);
                        if (best != null && bestCount >= TeleportWaypointRouteNodeStrongRun)
                        {
                            position = best;
                            _teleportLastSource = bestSource;
                            ClearTeleportWaypointDestinationCache();
                            return true;
                        }

                        var keep = Math.Min(data.Length, TeleportWaypointRouteNodeCarryBytes);
                        carry = new byte[keep];
                        Buffer.BlockCopy(data, data.Length - keep, carry, 0, keep);
                    }
                    else
                    {
                        carry = new byte[0];
                    }

                    current += (ulong)take;
                    remaining -= (ulong)take;
                }
            }

            if (best == null)
                return false;

            position = best;
            _teleportLastSource = bestSource;
            ClearTeleportWaypointDestinationCache();
            return true;
        }

        private bool TryReadWaypointPositionFromEndpointObjectScan(byte[] currentVehiclePosition, out byte[] position)
        {
            position = null;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            ulong routeAllocationBase;
            if (!TryFindTeleportWaypointRouteAllocationBase(out routeAllocationBase) || routeAllocationBase == 0)
                return false;

            var scanWatch = Stopwatch.StartNew();
            var clusters = new Dictionary<Tuple<int, int, int>, TeleportRawWaypointCluster>();
            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.AllocationBase == routeAllocationBase)
                .OrderByDescending(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, TeleportWaypointEndpointObjectMaxRegionBytes);
                if (length < 0x1000)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < 0x1000)
                    continue;

                ScanWaypointEndpointObjectBuffer(data, region.BaseAddress, currentVehiclePosition, clusters);

            }

            TeleportRawWaypointCluster bestCluster;
            if (!TrySelectEndpointObjectCluster(clusters, currentVehiclePosition, TeleportWaypointEndpointObjectMinimumCopies, out bestCluster) ||
                !bestCluster.TryGetAveragePosition(out position))
            {
                position = null;
                return false;
            }

            _teleportLastSource = "endpointObject.scan count " + bestCluster.Count.ToString(CultureInfo.InvariantCulture);
            ClearTeleportWaypointDestinationCache();
            return true;
        }

        private bool TryFindTeleportWaypointRouteAllocationBase(out ulong allocationBase)
        {
            allocationBase = 0;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var routeNodeVtable = _mainBase + TeleportWaypointRouteNodeVtableRva;
            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            if (routeNodeVtable < _mainBase || routeNodeVtable >= moduleEnd)
                return false;

            var needle = BitConverter.GetBytes(routeNodeVtable);
            var scanWatch = Stopwatch.StartNew();
            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.RegionSize >= 0x10000UL && region.RegionSize <= TeleportWaypointRouteNodeMaxChunkBytes)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderBy(GetTeleportWaypointRouteAllocationRegionPriority)
                .ThenByDescending(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, TeleportWaypointRouteNodeMaxChunkBytes);
                if (length < 0x1000)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < needle.Length)
                    continue;
                if (IndexOf(data, needle, 0) < 0)
                    continue;

                allocationBase = region.AllocationBase != 0 ? region.AllocationBase : region.BaseAddress;
                return true;
            }

            return false;
        }

        private void ScanWaypointEndpointObjectBuffer(
            byte[] data,
            ulong dataBase,
            byte[] currentVehiclePosition,
            Dictionary<Tuple<int, int, int>, TeleportRawWaypointCluster> clusters)
        {
            if (data == null || data.Length < 0x100 || clusters == null)
                return;

            for (var i = 0; i < TeleportWaypointEndpointObjectVtableRvas.Length; i++)
            {
                var vtable = _mainBase + TeleportWaypointEndpointObjectVtableRvas[i];
                var needle = BitConverter.GetBytes(vtable);
                var offsets = TeleportWaypointEndpointObjectVtableRvas[i] == 0x6F33280UL
                    ? TeleportWaypointEndpointMarkerVectorOffsets
                    : TeleportWaypointEndpointObjectVectorOffsets;

                for (var hit = IndexOf(data, needle, 0); hit >= 0; hit = IndexOf(data, needle, hit + 8))
                {
                    for (var offsetIndex = 0; offsetIndex < offsets.Length; offsetIndex++)
                    {
                        var vectorOffset = hit + checked((int)offsets[offsetIndex]);
                        if (vectorOffset < 0 || vectorOffset + 12 > data.Length)
                            continue;

                        var x = BitConverter.ToSingle(data, vectorOffset);
                        var y = BitConverter.ToSingle(data, vectorOffset + 4);
                        var z = BitConverter.ToSingle(data, vectorOffset + 8);
                        if (!IsPlausibleWaypointEndpointObjectPosition(x, y, z, currentVehiclePosition))
                            continue;

                        var key = Tuple.Create(
                            (int)Math.Round(x * 10F),
                            (int)Math.Round(y * 10F),
                            (int)Math.Round(z * 10F));

                        TeleportRawWaypointCluster cluster;
                        if (!clusters.TryGetValue(key, out cluster))
                        {
                            cluster = new TeleportRawWaypointCluster();
                            clusters[key] = cluster;
                        }
                        cluster.Add(x, y, z, TeleportWaypointEndpointObjectVtableRvas[i] == 0x6F33280UL);
                    }
                }
            }
        }

        private static bool TrySelectEndpointObjectCluster(
            Dictionary<Tuple<int, int, int>, TeleportRawWaypointCluster> clusters,
            byte[] currentVehiclePosition,
            int minimumCopies,
            out TeleportRawWaypointCluster bestCluster)
        {
            bestCluster = null;
            if (clusters == null || clusters.Count == 0)
                return false;

            foreach (var cluster in clusters.Values)
            {
                if (cluster == null || cluster.Count < minimumCopies)
                    continue;
                byte[] candidate;
                if (!cluster.TryGetAveragePosition(out candidate))
                    continue;
                if (!IsPlausibleWaypointEndpointObjectPosition(
                    BitConverter.ToSingle(candidate, 0),
                    BitConverter.ToSingle(candidate, 4),
                    BitConverter.ToSingle(candidate, 8),
                    currentVehiclePosition))
                    continue;

                if (bestCluster == null ||
                    cluster.Count > bestCluster.Count ||
                    (cluster.Count == bestCluster.Count && cluster.MarkerCopies > bestCluster.MarkerCopies))
                    bestCluster = cluster;
            }

            return bestCluster != null;
        }

        private static bool IsPlausibleWaypointEndpointObjectPosition(float x, float y, float z, byte[] currentVehiclePosition)
        {
            if (!IsFiniteFloat(x) || !IsFiniteFloat(y) || !IsFiniteFloat(z))
                return false;
            if (Math.Abs(x) > 10000F || Math.Abs(z) > 10000F || y < 8F || y > 900F)
                return false;
            if (Math.Abs(x) < 128F || Math.Abs(z) < 128F)
                return false;
            if (currentVehiclePosition != null && currentVehiclePosition.Length >= 12)
            {
                var dx = x - BitConverter.ToSingle(currentVehiclePosition, 0);
                var dz = z - BitConverter.ToSingle(currentVehiclePosition, 8);
                if ((double)dx * dx + (double)dz * dz < TeleportWaypointEndpointObjectMinimumDistanceSquared)
                    return false;
            }

            return true;
        }

        private bool TryReadWaypointPositionFromRawDestinationClusterScan(byte[] currentVehiclePosition, out byte[] position)
        {
            position = null;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            var scanWatch = Stopwatch.StartNew();
            TeleportRawWaypointCluster bestCluster = null;
            var bestScore = double.MinValue;

            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.RegionSize >= 0x10000UL && region.RegionSize <= TeleportWaypointRawClusterMaxRegionBytes)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderByDescending(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, TeleportWaypointRawClusterMaxRegionBytes);
                if (length < 0x1000)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < 0x1000)
                    continue;

                var clusters = new Dictionary<long, TeleportRawWaypointCluster>();
                for (var offset = 0; offset + 12 <= data.Length; offset += 8)
                {
                    var x = BitConverter.ToSingle(data, offset);
                    var y = BitConverter.ToSingle(data, offset + 4);
                    var z = BitConverter.ToSingle(data, offset + 8);
                    if (!IsPlausibleRawWaypointClusterPosition(x, y, z, currentVehiclePosition))
                        continue;

                    var binX = (int)Math.Floor(x / TeleportWaypointRawClusterBinSize);
                    var binZ = (int)Math.Floor(z / TeleportWaypointRawClusterBinSize);
                    var key = PackTeleportRawClusterKey(binX, binZ);

                    TeleportRawWaypointCluster cluster;
                    if (!clusters.TryGetValue(key, out cluster))
                    {
                        cluster = new TeleportRawWaypointCluster();
                        clusters[key] = cluster;
                    }
                    cluster.Add(x, y, z);
                }

                foreach (var cluster in clusters.Values)
                {
                    if (cluster.Count < TeleportWaypointRawClusterMinimumCount)
                        continue;
                    if (!cluster.TryGetAveragePosition(out position))
                        continue;
                    if (IsLikelyRawWaypointClusterArtifact(cluster, position, currentVehiclePosition))
                        continue;

                    var variance = cluster.HorizontalVariance();
                    var distanceBonus = 0.0;
                    if (currentVehiclePosition != null && currentVehiclePosition.Length >= 12)
                        distanceBonus = Math.Min(Math.Sqrt(TeleportHorizontalDistanceSquared(position, currentVehiclePosition)), 8000.0);

                    var score = (double)cluster.Count * 1000000.0 + distanceBonus - variance * 1000.0;
                    if (score <= bestScore)
                        continue;

                    bestScore = score;
                    bestCluster = cluster;
                }
            }

            if (bestCluster == null || !bestCluster.TryGetAveragePosition(out position))
            {
                position = null;
                return false;
            }

            _teleportLastSource = "rawDestinationCluster.scan count " + bestCluster.Count.ToString(CultureInfo.InvariantCulture);
            ClearTeleportWaypointDestinationCache();
            return true;
        }

        private static long PackTeleportRawClusterKey(int x, int z)
        {
            return ((long)x << 32) ^ (uint)z;
        }

        private static bool IsPlausibleRawWaypointClusterPosition(float x, float y, float z, byte[] currentVehiclePosition)
        {
            if (!IsFiniteFloat(x) || !IsFiniteFloat(y) || !IsFiniteFloat(z))
                return false;
            if (Math.Abs(x) > 10000F || Math.Abs(z) > 10000F || y < 8F || y > 900F)
                return false;
            if (Math.Abs(x) < 128F || Math.Abs(z) < 128F)
                return false;
            if (currentVehiclePosition != null && currentVehiclePosition.Length >= 12)
            {
                var dx = x - BitConverter.ToSingle(currentVehiclePosition, 0);
                var dz = z - BitConverter.ToSingle(currentVehiclePosition, 8);
                if ((double)dx * dx + (double)dz * dz < 625.0)
                    return false;
            }

            return true;
        }

        private static bool IsLikelyRawWaypointClusterArtifact(TeleportRawWaypointCluster cluster, byte[] position, byte[] currentVehiclePosition)
        {
            if (cluster == null || position == null || position.Length < 12)
                return true;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            if (!IsPlausibleRawWaypointClusterPosition(x, y, z, currentVehiclePosition))
                return true;
            if (cluster.Count > 100000)
                return true;

            if (Math.Abs(x - z) < 12F && Math.Abs(x) < 1500F && Math.Abs(z) < 1500F)
                return true;
            if (cluster.HorizontalVariance() > 200.0)
                return true;

            return false;
        }

        private static ulong GetTeleportWaypointRouteNodeRegionPriority(MemoryRegion region)
        {
            var size = region.RegionSize;
            var preferred = TeleportWaypointRouteNodePreferredRegionSize;
            var delta = size > preferred ? size - preferred : preferred - size;
            if (size >= 4UL * 1024UL * 1024UL && size <= 32UL * 1024UL * 1024UL)
                return delta;

            return delta + 0x100000000UL;
        }

        private static ulong GetTeleportWaypointRouteAllocationRegionPriority(MemoryRegion region)
        {
            var size = region.RegionSize;
            var preferred = TeleportWaypointRouteAllocationPreferredRegionSize;
            var delta = size > preferred ? size - preferred : preferred - size;
            if (size >= 4UL * 1024UL * 1024UL && size <= 32UL * 1024UL * 1024UL)
                return delta;

            return delta + 0x100000000UL;
        }

        private void ScanWaypointRouteNodeBuffer(
            byte[] data,
            ulong dataBase,
            byte[] needle,
            byte[] currentVehiclePosition,
            ref byte[] best,
            ref double bestScore,
            ref int bestCount,
            ref string bestSource)
        {
            if (data == null || needle == null || needle.Length != 8 ||
                data.Length < (int)(TeleportWaypointRouteNodePositionOffset + 16UL))
                return;

            var hit = IndexOf(data, needle, 0);
            var runCount = 0;
            var runLastObject = 0UL;
            byte[] runFirstPosition = null;
            byte[] runLastPosition = null;

            while (hit >= 0)
            {
                if (hit + (int)(TeleportWaypointRouteNodePositionOffset + 16UL) <= data.Length)
                {
                    var objectAddress = dataBase + (ulong)hit;
                    if ((objectAddress & 0x7UL) == 0)
                    {
                        var positionOffset = hit + (int)TeleportWaypointRouteNodePositionOffset;
                        var candidate = new byte[16];
                        Buffer.BlockCopy(data, positionOffset, candidate, 0, 16);

                        if (IsPlausibleRouteTeleportPosition(candidate))
                        {
                            if (runCount > 0 && objectAddress == runLastObject + TeleportWaypointRouteNodeStride)
                            {
                                runCount++;
                                runLastObject = objectAddress;
                                runLastPosition = candidate;
                            }
                            else
                            {
                                ConsiderWaypointRouteNodeRun(runCount, runLastObject, runFirstPosition, runLastPosition, currentVehiclePosition, ref best, ref bestScore, ref bestCount, ref bestSource);
                                runCount = 1;
                                runLastObject = objectAddress;
                                runFirstPosition = candidate;
                                runLastPosition = candidate;
                            }
                        }
                        else
                        {
                            ConsiderWaypointRouteNodeRun(runCount, runLastObject, runFirstPosition, runLastPosition, currentVehiclePosition, ref best, ref bestScore, ref bestCount, ref bestSource);
                            runCount = 0;
                            runLastObject = 0;
                            runFirstPosition = null;
                            runLastPosition = null;
                        }
                    }
                }

                hit = IndexOf(data, needle, hit + 8);
            }

            ConsiderWaypointRouteNodeRun(runCount, runLastObject, runFirstPosition, runLastPosition, currentVehiclePosition, ref best, ref bestScore, ref bestCount, ref bestSource);
        }

        private static void ConsiderWaypointRouteNodeRun(
            int runCount,
            ulong runLastObject,
            byte[] runFirstPosition,
            byte[] runLastPosition,
            byte[] currentVehiclePosition,
            ref byte[] best,
            ref double bestScore,
            ref int bestCount,
            ref string bestSource)
        {
            if (runCount < TeleportWaypointRouteNodeMinimumRun || runLastPosition == null)
                return;

            var runSpan = runFirstPosition == null ? 0.0 : TeleportHorizontalDistanceSquared(runFirstPosition, runLastPosition);
            if (runSpan < 4.0)
                return;

            var anchorScore = 0.0;
            if (IsPlausibleWorldTeleportPosition(currentVehiclePosition))
                anchorScore = Math.Min(TeleportHorizontalDistanceSquared(runLastPosition, currentVehiclePosition), 1000000.0);

            var score = (double)runCount * 1000000000.0 + Math.Min(runSpan, 1000000.0) + anchorScore;
            if (score <= bestScore)
                return;

            best = CopyTeleportPosition(runLastPosition);
            bestScore = score;
            bestCount = runCount;
            bestSource = "routeNode.scan+0xC0 count " + runCount.ToString(CultureInfo.InvariantCulture) +
                " object 0x" + runLastObject.ToString("X", CultureInfo.InvariantCulture);
        }

        private bool TryReadWaypointPositionFromDestinationMemoryScan(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            if (_mainBase == 0 || _mainSize <= 0 || _handle == IntPtr.Zero)
                return false;

            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);
            var scanWatch = Stopwatch.StartNew();
            var maxLayoutBytes = (int)(TeleportNavigationDestinationMirrorOffsets[TeleportNavigationDestinationMirrorOffsets.Length - 1] + 16UL);
            byte[] best = null;
            var bestScore = double.MinValue;
            var bestSource = string.Empty;
            var bestObject = 0UL;
            var bestLayout = TeleportWaypointDestinationLayoutPrimary;
            var currentVehiclePosition = vehiclePointer == 0 || !IsReadableMemoryRange(vehiclePointer + 0x50UL, 16)
                ? null
                : ReadBytes(vehiclePointer + 0x50UL, 16);
            if (!IsPlausibleWorldTeleportPosition(currentVehiclePosition))
                currentVehiclePosition = null;

            var regions = EnumerateReadableWritableRegions()
                .Where(region => region.RegionSize > 0x1000UL)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderBy(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                    break;

                var current = region.BaseAddress;
                var remaining = region.RegionSize;
                var carry = new byte[0];

                while (remaining > 0)
                {
                    if (scanWatch.ElapsedMilliseconds >= TeleportWaypointDestinationScanTimeoutMs)
                        break;

                    var take = (int)Math.Min(TeleportWaypointDestinationMaxScanRegionBytes, remaining);
                    if (take < maxLayoutBytes)
                        break;

                    var read = ReadBytes(current, take);
                    if (read.Length >= maxLayoutBytes)
                    {
                        var data = new byte[carry.Length + read.Length];
                        if (carry.Length > 0)
                            Buffer.BlockCopy(carry, 0, data, 0, carry.Length);
                        Buffer.BlockCopy(read, 0, data, carry.Length, read.Length);
                        var dataBase = current - (ulong)carry.Length;

                        ScanWaypointDestinationBuffer(data, dataBase, moduleEnd, currentVehiclePosition, ref best, ref bestScore, ref bestSource, ref bestObject, ref bestLayout);
                        if (bestObject != 0 &&
                            (bestLayout == TeleportWaypointDestinationLayoutRouteEndpoint ||
                             bestLayout == TeleportWaypointDestinationLayoutPrimary ||
                             bestLayout == TeleportWaypointDestinationLayoutMarker))
                        {
                            position = best;
                            _teleportLastSource = bestSource;
                            RememberTeleportWaypointDestinationObject(bestObject, bestLayout, bestSource);
                            return true;
                        }

                        var keep = Math.Min(data.Length, maxLayoutBytes + 8);
                        carry = new byte[keep];
                        Buffer.BlockCopy(data, data.Length - keep, carry, 0, keep);
                    }
                    else
                    {
                        carry = new byte[0];
                    }

                    current += (ulong)take;
                    remaining -= (ulong)take;
                }
            }

            if (best == null)
                return false;

            position = best;
            _teleportLastSource = bestSource;
            RememberTeleportWaypointDestinationObject(bestObject, bestLayout, bestSource);
            return true;
        }

        private void ScanWaypointDestinationBuffer(byte[] data, ulong dataBase, ulong moduleEnd, byte[] currentVehiclePosition, ref byte[] best, ref double bestScore, ref string bestSource, ref ulong bestObject, ref int bestLayout)
        {
            var maxLayoutBytes = (int)(TeleportNavigationDestinationMirrorOffsets[TeleportNavigationDestinationMirrorOffsets.Length - 1] + 16UL);
            if (data == null || data.Length < maxLayoutBytes)
                return;

            for (var vtableIndex = 0; vtableIndex < TeleportRouteEndpointDestinationKnownVtableRvas.Length; vtableIndex++)
            {
                var vtable = _mainBase + TeleportRouteEndpointDestinationKnownVtableRvas[vtableIndex];
                if (vtable < _mainBase || vtable >= moduleEnd || (vtable & 0x7UL) != 0)
                    continue;

                var needle = BitConverter.GetBytes(vtable);
                for (var offset = IndexOf(data, needle, 0); offset >= 0; offset = IndexOf(data, needle, offset + 8))
                {
                    if (offset + 0x170 > data.Length)
                        continue;

                    var objectAddress = dataBase + (ulong)offset;
                    if ((objectAddress & 0x7UL) != 0)
                        continue;

                    ConsiderWaypointDestinationLayout(data, offset, objectAddress, vtable, TeleportRouteEndpointDestinationOffsets, TeleportWaypointDestinationLayoutRouteEndpoint, "routeEndpointDestination.scan+0x108", 4.0e15, currentVehiclePosition, ref best, ref bestScore, ref bestSource, ref bestObject, ref bestLayout);
                }
            }

            for (var vtableIndex = 0; vtableIndex < TeleportNavigationDestinationKnownVtableRvas.Length; vtableIndex++)
            {
                var vtable = _mainBase + TeleportNavigationDestinationKnownVtableRvas[vtableIndex];
                if (vtable < _mainBase || vtable >= moduleEnd || (vtable & 0x7UL) != 0)
                    continue;

                var needle = BitConverter.GetBytes(vtable);
                for (var offset = IndexOf(data, needle, 0); offset >= 0; offset = IndexOf(data, needle, offset + 8))
                {
                    if (offset + maxLayoutBytes > data.Length)
                        continue;

                    var objectAddress = dataBase + (ulong)offset;
                    if ((objectAddress & 0x7UL) != 0)
                        continue;

                    ConsiderWaypointDestinationLayout(data, offset, objectAddress, vtable, TeleportNavigationDestinationPrimaryOffsets, TeleportWaypointDestinationLayoutPrimary, "navigationDestination.scan+0x210", 2.0e15, currentVehiclePosition, ref best, ref bestScore, ref bestSource, ref bestObject, ref bestLayout);
                    ConsiderWaypointDestinationLayout(data, offset, objectAddress, vtable, TeleportNavigationDestinationMirrorOffsets, TeleportWaypointDestinationLayoutMirror, "navigationDestination.scan+0x590", 1.9e15, currentVehiclePosition, ref best, ref bestScore, ref bestSource, ref bestObject, ref bestLayout);
                }
            }

            for (var vtableIndex = 0; vtableIndex < TeleportWaypointMarkerKnownVtableRvas.Length; vtableIndex++)
            {
                var vtable = _mainBase + TeleportWaypointMarkerKnownVtableRvas[vtableIndex];
                if (vtable < _mainBase || vtable >= moduleEnd || (vtable & 0x7UL) != 0)
                    continue;

                var needle = BitConverter.GetBytes(vtable);
                for (var offset = IndexOf(data, needle, 0); offset >= 0; offset = IndexOf(data, needle, offset + 8))
                {
                    if (offset + 0x790 > data.Length)
                        continue;

                    var objectAddress = dataBase + (ulong)offset;
                    if ((objectAddress & 0x7UL) != 0)
                        continue;

                    ConsiderWaypointDestinationLayout(data, offset, objectAddress, vtable, TeleportWaypointMarkerDestinationOffsets, TeleportWaypointDestinationLayoutMarker, "waypointMarker.scan+0x750", 2.6e15, currentVehiclePosition, ref best, ref bestScore, ref bestSource, ref bestObject, ref bestLayout);
                }
            }
        }

        private void ConsiderWaypointDestinationLayout(
            byte[] data,
            int objectOffset,
            ulong objectAddress,
            ulong vtable,
            ulong[] offsets,
            int layout,
            string source,
            double baseScore,
            byte[] currentVehiclePosition,
            ref byte[] best,
            ref double bestScore,
            ref string bestSource,
            ref ulong bestObject,
            ref int bestLayout)
        {
            if (offsets == null || offsets.Length < 2)
                return;

            byte[] primary = null;
            var agreeingCopies = 0;
            var maxSpread = 0.0;
            for (var i = 0; i < offsets.Length; i++)
            {
                var vectorOffset = objectOffset + checked((int)offsets[i]);
                if (vectorOffset < 0 || vectorOffset + 16 > data.Length)
                    continue;

                var candidate = new byte[16];
                Buffer.BlockCopy(data, vectorOffset, candidate, 0, 16);
                if (!IsPlausibleWorldTeleportPosition(candidate))
                    continue;

                if (primary == null)
                {
                    primary = candidate;
                    agreeingCopies = 1;
                    continue;
                }

                var spread = TeleportHorizontalDistanceSquared(candidate, primary);
                if (spread >= 25.0)
                    continue;

                agreeingCopies++;
                if (spread > maxSpread)
                    maxSpread = spread;
            }

            if (primary == null || agreeingCopies < 2)
                return;
            if (layout != TeleportWaypointDestinationLayoutRouteEndpoint &&
                IsWaypointCandidateVehiclePosition(primary, currentVehiclePosition))
                return;

            var score = baseScore + (double)agreeingCopies * 1000000.0 - maxSpread;
            if (score <= bestScore)
                return;

            best = CopyTeleportPosition(primary);
            bestScore = score;
            bestSource = source;
            bestObject = objectAddress;
            bestLayout = layout;
        }

        private static bool IsCurrentDestinationCaptureSource(RuntimeProfileHookDescriptor descriptor)
        {
            return descriptor != null &&
                   !string.IsNullOrEmpty(descriptor.Key) &&
                   descriptor.Key.IndexOf("CurrentDestination", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static bool IsNavigationDestinationCaptureSource(RuntimeProfileHookDescriptor descriptor)
        {
            return descriptor != null &&
                   !string.IsNullOrEmpty(descriptor.Key) &&
                   descriptor.Key.IndexOf("NavigationDestinationPointer", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private bool IsKnownNavigationDestinationVtable(ulong vtable)
        {
            if (vtable < _mainBase || vtable >= _mainBase + (ulong)Math.Max(0, _mainSize) || (vtable & 0x7UL) != 0)
                return false;

            var rva = vtable - _mainBase;
            for (var i = 0; i < TeleportNavigationDestinationKnownVtableRvas.Length; i++)
            {
                var known = TeleportNavigationDestinationKnownVtableRvas[i];
                var min = known > TeleportNavigationDestinationKnownVtableTolerance
                    ? known - TeleportNavigationDestinationKnownVtableTolerance
                    : 0UL;
                var max = known + TeleportNavigationDestinationKnownVtableTolerance;
                if (rva >= min && rva <= max)
                    return true;
            }

            return false;
        }

        private bool IsKnownWaypointMarkerVtable(ulong vtable)
        {
            if (vtable < _mainBase || vtable >= _mainBase + (ulong)Math.Max(0, _mainSize) || (vtable & 0x7UL) != 0)
                return false;

            var rva = vtable - _mainBase;
            for (var i = 0; i < TeleportWaypointMarkerKnownVtableRvas.Length; i++)
            {
                var known = TeleportWaypointMarkerKnownVtableRvas[i];
                var min = known > TeleportWaypointMarkerKnownVtableTolerance
                    ? known - TeleportWaypointMarkerKnownVtableTolerance
                    : 0UL;
                var max = known + TeleportWaypointMarkerKnownVtableTolerance;
                if (rva >= min && rva <= max)
                    return true;
            }

            return false;
        }

        private bool IsKnownRouteEndpointDestinationVtable(ulong vtable)
        {
            if (vtable < _mainBase || vtable >= _mainBase + (ulong)Math.Max(0, _mainSize) || (vtable & 0x7UL) != 0)
                return false;

            var rva = vtable - _mainBase;
            for (var i = 0; i < TeleportRouteEndpointDestinationKnownVtableRvas.Length; i++)
            {
                var known = TeleportRouteEndpointDestinationKnownVtableRvas[i];
                var min = known > TeleportRouteEndpointDestinationKnownVtableTolerance
                    ? known - TeleportRouteEndpointDestinationKnownVtableTolerance
                    : 0UL;
                var max = known + TeleportRouteEndpointDestinationKnownVtableTolerance;
                if (rva >= min && rva <= max)
                    return true;
            }

            return false;
        }

        private bool TryReadCurrentDestinationObject(ulong objectPointer, out byte[] position, out bool hasDestinationFlag)
        {
            position = null;
            hasDestinationFlag = false;
            if (!IsLikelyTeleportPointer(objectPointer) || !IsReadableMemoryRange(objectPointer, 0x790))
                return false;

            byte[] primary = null;
            var agreeingCopies = 0;
            for (var i = 0; i < TeleportCurrentDestinationOffsets.Length; i++)
            {
                var address = objectPointer + TeleportCurrentDestinationOffsets[i];
                if (!IsReadableMemoryRange(address, 16))
                    continue;
                var candidate = ReadBytes(address, 16);
                if (!IsPlausibleWorldTeleportPosition(candidate))
                    continue;
                if (primary == null)
                {
                    primary = candidate;
                    agreeingCopies = 1;
                }
                else if (TeleportHorizontalDistanceSquared(candidate, primary) < 16.0)
                {
                    agreeingCopies++;
                }
            }
            if (primary == null)
                return false;

            if (IsReadableMemoryRange(objectPointer + TeleportCurrentDestinationFlagOffset, 4))
            {
                var flag = ReadFloat(objectPointer + TeleportCurrentDestinationFlagOffset);
                hasDestinationFlag = Math.Abs(flag - 1.0F) < 0.0001F;
            }

            var structural = hasDestinationFlag && agreeingCopies >= 2;
            if (!structural && !IsTeleportCurrentDestinationObject(objectPointer))
                return false;

            position = primary;
            return true;
        }

        private bool IsTeleportCurrentDestinationObject(ulong objectPointer)
        {
            if (!IsReadableMemoryRange(objectPointer, 8))
                return false;

            var vtable = ReadUInt64(objectPointer);
            if (vtable < _mainBase || vtable >= _mainBase + (ulong)Math.Max(0, _mainSize))
                return false;

            var rva = vtable - _mainBase;
            var min = TeleportCurrentDestinationVtableRva > TeleportCurrentDestinationVtableTolerance
                ? TeleportCurrentDestinationVtableRva - TeleportCurrentDestinationVtableTolerance
                : 0UL;
            var max = TeleportCurrentDestinationVtableRva + TeleportCurrentDestinationVtableTolerance;
            return rva >= min && rva <= max;
        }

        private bool TryReadCheckpointPositionFromCapturedRouteObjects(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            byte[] current = null;
            if (vehiclePointer != 0 && IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
            {
                current = ReadBytes(vehiclePointer + 0x50UL, 16);
                if (!IsPlausibleWorldTeleportPosition(current))
                    current = null;
            }

            var routeRanges = new List<TeleportRouteRangeCandidate>();
            var count = Math.Min(_teleportWaypointCopyDetours == null ? 0 : _teleportWaypointCopyDetours.Count, _teleportWaypointCopyDescriptors == null ? 0 : _teleportWaypointCopyDescriptors.Count);
            for (var i = 0; i < count; i++)
            {
                var detour = _teleportWaypointCopyDetours[i];
                var descriptor = _teleportWaypointCopyDescriptors[i];
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || descriptor.ObjectPointerOffset < 0)
                    continue;

                var objectPointer = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (objectPointer == 0)
                    continue;

                CollectTeleportRouteObjectRanges(objectPointer, GetTeleportObjectBasePriority(descriptor), descriptor.Key, routeRanges, 25.0);
            }

            string bestSource;
            if (!TrySelectTeleportCheckpointRoute(routeRanges, current, vehiclePointer, out position, out bestSource))
                return false;

            _teleportLastSource = bestSource;
            return true;
        }

        private void ConsiderTeleportCaptureSources(byte[] current, ref byte[] position, ref double bestScore, bool routeVectorFallbackOnly)
        {
            ConsiderTeleportCaptureSources(_teleportWaypointCopyDetours, _teleportWaypointCopyDescriptors, current, ref position, ref bestScore, routeVectorFallbackOnly);
        }

        private void ConsiderTeleportCaptureObjects(
            List<RuntimeDetour> copyDetours,
            List<RuntimeProfileHookDescriptor> copyDescriptors,
            byte[] current,
            ref byte[] position,
            ref double bestScore)
        {
            var count = Math.Min(copyDetours == null ? 0 : copyDetours.Count, copyDescriptors == null ? 0 : copyDescriptors.Count);
            for (var i = 0; i < count; i++)
            {
                var detour = copyDetours[i];
                var descriptor = copyDescriptors[i];
                if (detour == null || descriptor == null || detour.DetourAddress == 0 || descriptor.ObjectPointerOffset < 0)
                    continue;

                var objectPointer = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (objectPointer != 0)
                    ConsiderTeleportDestinationObject(objectPointer, current, ref position, ref bestScore, GetTeleportObjectBasePriority(descriptor), descriptor.Key);
            }
        }

        private void ConsiderTeleportCaptureSources(
            List<RuntimeDetour> copyDetours,
            List<RuntimeProfileHookDescriptor> copyDescriptors,
            byte[] current,
            ref byte[] position,
            ref double bestScore,
            bool routeVectorFallbackOnly)
        {
            var count = Math.Min(copyDetours == null ? 0 : copyDetours.Count, copyDescriptors == null ? 0 : copyDescriptors.Count);
            for (var i = 0; i < count; i++)
            {
                var detour = copyDetours[i];
                var descriptor = copyDescriptors[i];
                if (detour == null || descriptor == null || detour.DetourAddress == 0)
                    continue;

                var isRouteVector = IsRawRouteVectorTeleportSource(descriptor);
                if (routeVectorFallbackOnly != isRouteVector)
                    continue;

                if (!isRouteVector && descriptor.CaptureOffset >= 0)
                {
                    if (IsStaleWaypointHudCaptureSource(descriptor))
                        continue;

                    var candidate = ReadBytes(detour.DetourAddress + (ulong)descriptor.CaptureOffset, 16);
                    ConsiderTeleportPosition(candidate, current, ref position, ref bestScore, GetTeleportCapturePriority(descriptor), descriptor.Key + ".capture");
                }

                if (descriptor.ObjectPointerOffset >= 0)
                {
                    var objectPointer = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                    ConsiderTeleportDestinationObject(objectPointer, current, ref position, ref bestScore, GetTeleportObjectBasePriority(descriptor), descriptor.Key);
                }
            }
        }

        private static bool IsRawRouteVectorTeleportSource(RuntimeProfileHookDescriptor descriptor)
        {
            return descriptor != null &&
                   !string.IsNullOrEmpty(descriptor.Key) &&
                   descriptor.Key.IndexOf("RouteVector", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static bool IsWaypointCopyTeleportSource(RuntimeProfileHookDescriptor descriptor)
        {
            return descriptor != null &&
                   !string.IsNullOrEmpty(descriptor.Key) &&
                   descriptor.Key.IndexOf("WaypointCopy", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private static bool IsStaleWaypointHudCaptureSource(RuntimeProfileHookDescriptor descriptor)
        {
            if (descriptor == null || string.IsNullOrEmpty(descriptor.Key))
                return false;

            return descriptor.Key.IndexOf("WaypointPointer", StringComparison.OrdinalIgnoreCase) >= 0 ||
                   descriptor.Key.IndexOf("WaypointCopy", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private void ConsiderTeleportDestinationObject(ulong objectPointer, byte[] current, ref byte[] best, ref double bestScore)
        {
            ConsiderTeleportDestinationObject(objectPointer, current, ref best, ref bestScore, 0.0, "object");
        }

        private void ConsiderTeleportDestinationObject(ulong objectPointer, byte[] current, ref byte[] best, ref double bestScore, double basePriority, string source)
        {
            if (!IsLikelyTeleportPointer(objectPointer) || !IsReadableMemoryRange(objectPointer, 0x100))
                return;

            if (!string.IsNullOrEmpty(source) && source.IndexOf("RouteVector", StringComparison.OrdinalIgnoreCase) >= 0)
            {
                ConsiderTeleportRouteVectorObjectEndpoint(objectPointer, current, ref best, ref bestScore, basePriority, source);
                return;
            }

            if (!string.IsNullOrEmpty(source) && source.IndexOf("SatNavRouteObject", StringComparison.OrdinalIgnoreCase) >= 0)
                ConsiderTeleportSatNavRouteObject(objectPointer, current, ref best, ref bestScore, basePriority, source);

            var offsets = GetTeleportObjectOffsetsForSource(source);
            if (offsets == null || offsets.Length == 0)
                return;

            var objectPriority = basePriority;
            if (IsTeleportNavigationDestinationSource(source) && IsTeleportNavigationDestinationObject(objectPointer))
                objectPriority += 9.0e12;

            for (var i = 0; i < offsets.Length; i++)
            {
                var address = objectPointer + offsets[i];
                if (!IsReadableMemoryRange(address, 16))
                    continue;
                var candidate = ReadBytes(address, 16);
                ConsiderTeleportPosition(candidate, current, ref best, ref bestScore, objectPriority + GetTeleportObjectOffsetPriority(offsets[i]), source + "+0x" + offsets[i].ToString("X", CultureInfo.InvariantCulture));
            }
        }

        private static ulong[] GetTeleportObjectOffsetsForSource(string source)
        {
            if (string.IsNullOrEmpty(source))
                return new ulong[] { 0x230UL };

            if (source.IndexOf("WaypointPointer", StringComparison.OrdinalIgnoreCase) >= 0)
                return new ulong[0];
            if (source.IndexOf("WaypointCopy", StringComparison.OrdinalIgnoreCase) >= 0)
                return new ulong[0];
            if (source.IndexOf("CurrentDestination", StringComparison.OrdinalIgnoreCase) >= 0)
                return new ulong[] { 0x760UL, 0x770UL, 0x780UL, 0x750UL };
            if (source.IndexOf("NavigationDestination", StringComparison.OrdinalIgnoreCase) >= 0)
                return new ulong[] { 0x210UL, 0x220UL, 0x590UL, 0x5A0UL, 0x90UL };
            if (source.IndexOf("DestinationSetter", StringComparison.OrdinalIgnoreCase) >= 0)
                return source.IndexOf("Navigation", StringComparison.OrdinalIgnoreCase) >= 0
                    ? new ulong[] { 0x210UL, 0x220UL, 0x590UL, 0x5A0UL, 0x90UL }
                    : new ulong[] { 0x760UL, 0x770UL, 0x780UL, 0x750UL };

            return new ulong[] { 0x230UL };
        }

        private bool IsTeleportNavigationDestinationObject(ulong objectPointer)
        {
            if (!IsReadableMemoryRange(objectPointer, 8))
                return false;

            var vtable = ReadUInt64(objectPointer);
            if (vtable < _mainBase || vtable >= _mainBase + (ulong)Math.Max(0, _mainSize))
                return false;

            var rva = vtable - _mainBase;
            var min = TeleportNavigationDestinationVtableRva > TeleportNavigationDestinationVtableTolerance
                ? TeleportNavigationDestinationVtableRva - TeleportNavigationDestinationVtableTolerance
                : 0UL;
            var max = TeleportNavigationDestinationVtableRva + TeleportNavigationDestinationVtableTolerance;
            return rva >= min && rva <= max;
        }

        private static bool IsTeleportNavigationDestinationSource(string source)
        {
            return !string.IsNullOrEmpty(source) &&
                   (source.IndexOf("NavigationDestination", StringComparison.OrdinalIgnoreCase) >= 0 ||
                    source.IndexOf("NavigationDestinationPointer", StringComparison.OrdinalIgnoreCase) >= 0 ||
                    source.IndexOf("TeleportNavigation", StringComparison.OrdinalIgnoreCase) >= 0);
        }

        private void ConsiderTeleportRouteVectorObjectEndpoint(ulong objectPointer, byte[] current, ref byte[] best, ref double bestScore, double basePriority, string source)
        {
            ConsiderTeleportRouteVectorObjectEndpointRange(objectPointer, 0xA0UL, 0xA8UL, current, ref best, ref bestScore, basePriority + 4.0e12, source + ".routeA");
            ConsiderTeleportRouteVectorObjectEndpointRange(objectPointer, 0xB8UL, 0xC0UL, current, ref best, ref bestScore, basePriority + 3.0e12, source + ".routeB");
            ConsiderTeleportRouteVectorObjectEndpointRange(objectPointer, 0xE8UL, 0xF0UL, current, ref best, ref bestScore, basePriority + 2.0e12, source + ".routeC");
            ConsiderTeleportRouteVectorObjectEndpointRange(objectPointer, 0x1A0UL, 0x1A8UL, current, ref best, ref bestScore, basePriority + 1.0e12, source + ".routeD");
        }

        private void ConsiderTeleportRouteVectorObjectEndpointRange(ulong objectPointer, ulong beginOffset, ulong endOffset, byte[] current, ref byte[] best, ref double bestScore, double priority, string source)
        {
            if (!IsReadableMemoryRange(objectPointer + beginOffset, 16))
                return;

            var begin = ReadUInt64(objectPointer + beginOffset);
            var end = ReadUInt64(objectPointer + endOffset);
            if (!IsLikelyTeleportPointer(begin) || !IsLikelyTeleportPointer(end) || end <= begin)
                return;

            var bytes = end - begin;
            if (bytes < 32UL || bytes > 0x20000UL || (bytes % 16UL) != 0UL)
                return;
            if (!IsWritableMemoryRange(begin, (int)Math.Min(bytes, 0x1000UL)) || !IsReadableMemoryRange(begin, (int)bytes))
                return;

            var routeData = ReadBytes(begin, (int)bytes);
            byte[] first = null;
            byte[] last = null;
            var positions = new List<byte[]>();
            var valid = 0;
            for (var offset = 0; offset + 16 <= routeData.Length; offset += 16)
            {
                var candidate = new byte[16];
                Buffer.BlockCopy(routeData, offset, candidate, 0, 16);
                if (!IsPlausibleRouteOrMarkerPosition(candidate))
                    continue;

                valid++;
                positions.Add(candidate);
                if (first == null)
                    first = CopyTeleportPosition(candidate);
                last = CopyTeleportPosition(candidate);
            }

            var totalSlots = Math.Max(1, routeData.Length / 16);
            if (valid < 2 || (totalSlots > 8 && valid * 3 < totalSlots))
                return;

            byte[] destination;
            double nearestDistance;
            double destinationDistance;
            if (!TryChooseActiveRouteDestination(positions, current, out destination, out nearestDistance, out destinationDistance))
                return;

            ConsiderTeleportPosition(
                destination,
                current,
                ref best,
                ref bestScore,
                priority + destinationDistance * 1000.0 + (double)valid * 1000.0 + (double)Math.Min(bytes, 0x20000UL),
                source + ".destination");
        }

        private void ConsiderTeleportSatNavRouteObject(ulong objectPointer, byte[] current, ref byte[] best, ref double bestScore, double basePriority, string source)
        {
            var routeCount = ReadInt32(objectPointer + 0x90UL);
            if (routeCount <= 0 || routeCount > 4096)
                return;

            ConsiderTeleportVectorRange(objectPointer, 0xA0UL, 0xA8UL, current, ref best, ref bestScore, basePriority + 5.0e14, source + ".routeA");
            ConsiderTeleportVectorRange(objectPointer, 0xB8UL, 0xC0UL, current, ref best, ref bestScore, basePriority + 4.0e14, source + ".routeB");
            ConsiderTeleportVectorRange(objectPointer, 0xE8UL, 0xF0UL, current, ref best, ref bestScore, basePriority + 3.0e14, source + ".routeC");
            ConsiderTeleportVectorRange(objectPointer, 0x1A0UL, 0x1A8UL, current, ref best, ref bestScore, basePriority + 2.0e14, source + ".routeD");
        }

        private void ConsiderTeleportVectorRange(ulong objectPointer, ulong beginOffset, ulong endOffset, byte[] current, ref byte[] best, ref double bestScore, double priority, string source)
        {
            if (!IsReadableMemoryRange(objectPointer + beginOffset, 16))
                return;

            var begin = ReadUInt64(objectPointer + beginOffset);
            var end = ReadUInt64(objectPointer + endOffset);
            if (!IsLikelyTeleportPointer(begin) || !IsLikelyTeleportPointer(end) || end <= begin)
                return;

            var bytes = end - begin;
            if (bytes < 16UL || bytes > 0x20000UL)
                return;

            var tail = end - 16UL;
            if (IsReadableMemoryRange(tail, 16))
                ConsiderTeleportPosition(ReadBytes(tail, 16), current, ref best, ref bestScore, priority, source + ".last");

            var stride = bytes % 16UL == 0UL ? 16UL : 4UL;
            var scanStart = bytes > 0x400UL ? end - 0x400UL : begin;
            for (var address = scanStart; address + 16UL <= end; address += stride)
            {
                if (!IsReadableMemoryRange(address, 16))
                    continue;
                ConsiderTeleportPosition(ReadBytes(address, 16), current, ref best, ref bestScore, priority - (double)(end - address), source + "+0x" + (address - begin).ToString("X", CultureInfo.InvariantCulture));
            }
        }

        private bool TryReadWaypointPositionFromRouteMemoryScan(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;

            byte[] current = null;
            if (vehiclePointer != 0 && IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
            {
                current = ReadBytes(vehiclePointer + 0x50UL, 16);
                if (!IsPlausibleWorldTeleportPosition(current))
                    current = null;
            }

            var routeRanges = new List<TeleportRouteRangeCandidate>();
            byte[] inferredCurrent = null;
            var inferredCurrentSpread = double.MaxValue;
            var scanWatch = Stopwatch.StartNew();
            string bestSource;

            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);

            routeRanges.Clear();
            inferredCurrent = null;
            inferredCurrentSpread = double.MaxValue;
            ulong resolvedRouteHeader;
            if (TryResolveFreshWaypointRouteHeader(out resolvedRouteHeader))
                CollectModuleRouteVectorAtHeader(resolvedRouteHeader, routeRanges);
            if (TrySelectActiveRouteWaypointMarker(routeRanges, current, out position, out bestSource) ||
                TrySelectTeleportMemoryRoute(routeRanges, current, false, out position, out bestSource))
            {
                _teleportLastSource = bestSource;
                return true;
            }

            var allRegions = EnumerateReadableWritableRegions();
            routeRanges.Clear();
            inferredCurrent = null;
            inferredCurrentSpread = double.MaxValue;
            scanWatch.Restart();
            var regions = allRegions
                .Where(region => region.RegionSize <= 4UL * 1024UL * 1024UL)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderByDescending(region => region.BaseAddress)
                .ToList();
            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointMemoryScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, 64UL * 1024UL * 1024UL);
                if (length < 0x400)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < 0x400)
                    continue;

                for (var offset = 0x200; offset + 0x1B0 < data.Length; offset += 8)
                {
                    var objectAddress = region.BaseAddress + (ulong)offset;
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xA0UL, 0xA8UL, 4.0e12, "routeA", routeRanges, ref inferredCurrent, ref inferredCurrentSpread);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xB8UL, 0xC0UL, 3.0e12, "routeB", routeRanges, ref inferredCurrent, ref inferredCurrentSpread);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xE8UL, 0xF0UL, 2.0e12, "routeC", routeRanges, ref inferredCurrent, ref inferredCurrentSpread);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0x1A0UL, 0x1A8UL, 1.0e12, "routeD", routeRanges, ref inferredCurrent, ref inferredCurrentSpread);
                }
            }

            if (TrySelectTeleportMemoryRoute(routeRanges, current ?? inferredCurrent, false, out position, out bestSource))
            {
                _teleportLastSource = bestSource;
                return true;
            }

            routeRanges.Clear();
            inferredCurrent = null;
            inferredCurrentSpread = double.MaxValue;
            scanWatch.Restart();
            var moduleRegions = allRegions
                .Where(region =>
                    IsPlausibleWorldTeleportPosition(current) &&
                    region.BaseAddress < moduleEnd &&
                    region.BaseAddress + region.RegionSize > _mainBase &&
                    region.RegionSize <= 64UL * 1024UL * 1024UL)
                .OrderByDescending(region => region.BaseAddress)
                .ToList();
            foreach (var region in moduleRegions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointMemoryScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, 64UL * 1024UL * 1024UL);
                if (length < 0x20)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < 0x20)
                    continue;

                for (var offset = 0; offset + 16 <= data.Length; offset += 8)
                {
                    CollectTeleportMemoryRouteRange(
                        data,
                        offset,
                        region.BaseAddress + (ulong)offset,
                        0UL,
                        8UL,
                        1.0e12,
                        "moduleRouteVector",
                        routeRanges,
                        ref inferredCurrent,
                        ref inferredCurrentSpread);
                }
            }

            if (!TrySelectTeleportMemoryRoute(routeRanges, current, false, out position, out bestSource))
                return false;

            _teleportLastSource = bestSource;
            return true;
        }

        private bool TryReadCheckpointPositionFromRouteMemoryScan(ulong vehiclePointer, out byte[] position)
        {
            position = null;
            _teleportLastSource = string.Empty;

            byte[] current = null;
            if (vehiclePointer != 0 && IsReadableMemoryRange(vehiclePointer + 0x50UL, 16))
            {
                current = ReadBytes(vehiclePointer + 0x50UL, 16);
                if (!IsPlausibleWorldTeleportPosition(current))
                    current = null;
            }

            var routeRanges = new List<TeleportRouteRangeCandidate>();
            byte[] inferredCurrent = null;
            var inferredCurrentSpread = double.MaxValue;
            var scanWatch = Stopwatch.StartNew();
            string bestSource;

            var moduleEnd = _mainBase + (ulong)Math.Max(0, _mainSize);

            ulong resolvedRouteHeader;
            if (TryResolveFreshWaypointRouteHeader(out resolvedRouteHeader))
                CollectModuleRouteVectorAtHeader(resolvedRouteHeader, routeRanges);

            if (TrySelectTeleportCheckpointRoute(routeRanges, current, vehiclePointer, out position, out bestSource))
            {
                _teleportLastSource = bestSource;
                return true;
            }

            var allRegions = EnumerateReadableWritableRegions();
            routeRanges.Clear();
            inferredCurrent = null;
            inferredCurrentSpread = double.MaxValue;
            var regions = allRegions
                .Where(region => region.RegionSize <= 4UL * 1024UL * 1024UL)
                .Where(region => region.BaseAddress >= moduleEnd || region.BaseAddress + region.RegionSize <= _mainBase)
                .OrderByDescending(region => region.BaseAddress)
                .ToList();

            foreach (var region in regions)
            {
                if (scanWatch.ElapsedMilliseconds >= TeleportWaypointMemoryScanTimeoutMs)
                    break;

                var length = (int)Math.Min(region.RegionSize, 64UL * 1024UL * 1024UL);
                if (length < 0x400)
                    continue;

                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length < 0x400)
                    continue;

                for (var offset = 0x200; offset + 0x1B0 < data.Length; offset += 8)
                {
                    var objectAddress = region.BaseAddress + (ulong)offset;
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xA0UL, 0xA8UL, 4.0e12, "checkpointRouteA", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, 25.0);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xB8UL, 0xC0UL, 3.0e12, "checkpointRouteB", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, 25.0);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0xE8UL, 0xF0UL, 2.0e12, "checkpointRouteC", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, 25.0);
                    CollectTeleportMemoryRouteRange(data, offset, objectAddress, 0x1A0UL, 0x1A8UL, 1.0e12, "checkpointRouteD", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, 25.0);
                }
            }

            if (!TrySelectTeleportCheckpointRoute(routeRanges, current ?? inferredCurrent, vehiclePointer, out position, out bestSource))
                return false;

            _teleportLastSource = bestSource;
            return true;
        }

        private void CollectTeleportRouteObjectRanges(ulong objectPointer, double priority, string source, List<TeleportRouteRangeCandidate> routeRanges, double minimumSpread)
        {
            if (!IsLikelyTeleportPointer(objectPointer) || !IsReadableMemoryRange(objectPointer, 0x1B0) || routeRanges == null)
                return;

            var data = ReadBytes(objectPointer, 0x1B0);
            if (data.Length < 0x1B0)
                return;

            byte[] inferredCurrent = null;
            var inferredCurrentSpread = double.MaxValue;
            var name = string.IsNullOrWhiteSpace(source) ? "checkpointObject" : source;
            CollectTeleportMemoryRouteRange(data, 0, objectPointer, 0xA0UL, 0xA8UL, priority + 4.0e12, name + ".routeA", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, minimumSpread);
            CollectTeleportMemoryRouteRange(data, 0, objectPointer, 0xB8UL, 0xC0UL, priority + 3.0e12, name + ".routeB", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, minimumSpread);
            CollectTeleportMemoryRouteRange(data, 0, objectPointer, 0xE8UL, 0xF0UL, priority + 2.0e12, name + ".routeC", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, minimumSpread);
            CollectTeleportMemoryRouteRange(data, 0, objectPointer, 0x1A0UL, 0x1A8UL, priority + 1.0e12, name + ".routeD", routeRanges, ref inferredCurrent, ref inferredCurrentSpread, minimumSpread);
        }

        private void CollectTeleportMemoryRouteObjectAtAddress(
            ulong objectAddress,
            double priority,
            string routeName,
            List<TeleportRouteRangeCandidate> routeRanges,
            ref byte[] inferredCurrent,
            ref double inferredCurrentSpread,
            double minimumSpread)
        {
            if (objectAddress == 0 || !IsReadableMemoryRange(objectAddress, 0x1B0))
                return;

            var data = ReadBytes(objectAddress, 0x1B0);
            if (data.Length < 0x1B0)
                return;

            var routeObjectPointer = objectAddress;
            if (IsLikelyTeleportPointer(routeObjectPointer))
            {
                CollectTeleportRouteObjectRanges(routeObjectPointer, priority, routeName, routeRanges, minimumSpread);
                return;
            }

            CollectTeleportRouteObjectRanges(objectAddress, priority, routeName, routeRanges, minimumSpread);
        }

        private void CollectTeleportMemoryRouteVectorAtAddress(
            ulong vectorAddress,
            double priority,
            string routeName,
            List<TeleportRouteRangeCandidate> routeRanges,
            ref byte[] inferredCurrent,
            ref double inferredCurrentSpread,
            double minimumSpread)
        {
            if (vectorAddress == 0 || !IsReadableMemoryRange(vectorAddress, 16))
                return;

            var data = ReadBytes(vectorAddress, 16);
            if (data.Length < 16)
                return;

            CollectTeleportMemoryRouteRange(
                data,
                0,
                vectorAddress,
                0UL,
                8UL,
                priority,
                routeName,
                routeRanges,
                ref inferredCurrent,
                ref inferredCurrentSpread,
                minimumSpread);
        }

        private static void CollectTeleportRawRouteRanges(
            byte[] data,
            ulong baseAddress,
            double priority,
            List<TeleportRouteRangeCandidate> routeRanges)
        {
            if (data == null || data.Length < 0x400 || routeRanges == null)
                return;

            var offset = 0;
            while (offset + 16 <= data.Length)
            {
                if (!IsPlausibleRouteOrMarkerPositionAt(data, offset))
                {
                    offset += 16;
                    continue;
                }

                var start = offset;
                var positions = new List<byte[]>();
                while (offset + 16 <= data.Length && IsPlausibleRouteOrMarkerPositionAt(data, offset))
                {
                    var candidate = new byte[16];
                    Buffer.BlockCopy(data, offset, candidate, 0, 16);
                    positions.Add(candidate);
                    offset += 16;
                }

                var bytes = (ulong)(offset - start);
                if (positions.Count < 24 || bytes > 0x20000UL)
                    continue;

                var spread = GetMaxTeleportDistanceSquared(positions, positions[positions.Count - 1]);
                if (spread < 900.0)
                    continue;

                routeRanges.Add(new TeleportRouteRangeCandidate
                {
                    Source = "0x" + (baseAddress + (ulong)start).ToString("X", CultureInfo.InvariantCulture) + ".rawRoute",
                    Priority = priority + Math.Min(bytes, 0x20000UL),
                    ByteLength = bytes,
                    Positions = positions,
                    FirstPosition = CopyTeleportPosition(positions[0]),
                    LastPosition = CopyTeleportPosition(positions[positions.Count - 1])
                });
            }
        }

        private static bool IsPlausibleRouteTeleportPositionAt(byte[] data, int offset)
        {
            return IsPlausibleRouteOrMarkerPositionAt(data, offset) &&
                BitConverter.ToSingle(data, offset + 4) > 5F;
        }

        private static bool IsPlausibleRouteOrMarkerPositionAt(byte[] data, int offset)
        {
            if (data == null || offset < 0 || offset + 12 > data.Length)
                return false;

            var x = BitConverter.ToSingle(data, offset);
            var y = BitConverter.ToSingle(data, offset + 4);
            var z = BitConverter.ToSingle(data, offset + 8);
            if (float.IsNaN(x) || float.IsNaN(y) || float.IsNaN(z) ||
                float.IsInfinity(x) || float.IsInfinity(y) || float.IsInfinity(z))
                return false;

            if (Math.Abs(x) < 5F || Math.Abs(z) < 5F)
                return false;
            if (Math.Abs(x) > 10000F || Math.Abs(z) > 10000F || y < -10F || y > 700F)
                return false;

            return true;
        }

        private bool TrySelectTeleportMemoryRoute(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            bool allowOrderedRouteAnchor,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            var bestScore = double.MinValue;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                var localAnchor = IsPlausibleWorldTeleportPosition(anchor)
                    ? anchor
                    : allowOrderedRouteAnchor
                        ? routeRange.FirstPosition
                        : null;

                byte[] endpoint;
                double nearestDistance;
                double endpointDistance;
                if (!IsPlausibleWorldTeleportPosition(localAnchor) ||
                    !TryChooseActiveRouteDestination(routeRange.Positions, localAnchor, out endpoint, out nearestDistance, out endpointDistance))
                    continue;

                var score = routeRange.Priority +
                            endpointDistance * 1000.0 +
                            (160000.0 - Math.Min(nearestDistance, 160000.0)) +
                            (double)routeRange.Positions.Count * 1000.0 +
                            (double)Math.Min(routeRange.ByteLength, 0x20000UL);
                if (score <= bestScore)
                    continue;

                bestScore = score;
                position = CopyTeleportPosition(endpoint);
                source = routeRange.Source + ".memory";
            }

            return position != null;
        }

        private bool TrySelectStrictModuleWaypointRoute(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            if (routeRanges == null || routeRanges.Count == 0 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var bestScore = double.MinValue;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                if (routeRange == null ||
                    routeRange.Positions == null ||
                    routeRange.Positions.Count < 2 ||
                    string.IsNullOrWhiteSpace(routeRange.Source) ||
                    routeRange.Source.IndexOf("moduleRouteVector", StringComparison.OrdinalIgnoreCase) < 0)
                    continue;

                byte[] endpoint;
                double nearestDistance;
                double endpointDistance;
                if (!TryChooseActiveRouteDestination(routeRange.Positions, anchor, out endpoint, out nearestDistance, out endpointDistance))
                    continue;

                if (nearestDistance > TeleportWaypointModuleRouteNearestMaxSquared)
                    continue;
                if (!IsPlausibleModuleWaypointEndpoint(endpoint))
                    continue;

                var nearestBonus = (TeleportWaypointModuleRouteNearestMaxSquared - nearestDistance) * 1000000.0;
                var endpointBonus = endpointDistance * 100.0;
                var countBonus = (double)Math.Min(routeRange.Positions.Count, 2048) * 1000.0;
                var sizePenalty = (double)Math.Min(routeRange.ByteLength, 0x20000UL) * 0.1;
                var score = routeRange.Priority + nearestBonus + endpointBonus + countBonus - sizePenalty;
                if (score <= bestScore)
                    continue;

                bestScore = score;
                position = CopyTeleportPosition(endpoint);
                source = routeRange.Source + ".memory";
            }

            return position != null;
        }

        private bool TrySelectActiveRouteWaypointDestination(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            _teleportRouteWinningHeaderAddress = 0;
            if (routeRanges == null || routeRanges.Count == 0 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            const double carStartMaxSquared = 22500.0;
            var bestStart = double.MaxValue;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                if (routeRange == null || routeRange.Positions == null || routeRange.Positions.Count < 2)
                    continue;

                var positions = routeRange.Positions;
                var runStart = 0;
                for (var p = 1; p <= positions.Count; p++)
                {
                    var endsRun = p == positions.Count ||
                        TeleportHorizontalDistanceSquared(positions[p - 1], positions[p]) > TeleportRouteSegmentBreakDistanceSquared;
                    if (!endsRun)
                        continue;

                    var runEnd = p - 1;
                    if (runEnd > runStart)
                    {
                        var firstPoint = positions[runStart];
                        var lastPoint = positions[runEnd];
                        var firstDistance = TeleportHorizontalDistanceSquared(firstPoint, anchor);
                        var lastDistance = TeleportHorizontalDistanceSquared(lastPoint, anchor);

                        if (firstDistance <= carStartMaxSquared &&
                            lastDistance >= 900.0 &&
                            IsPlausibleModuleWaypointEndpoint(lastPoint) &&
                            firstDistance < bestStart)
                        {
                            bestStart = firstDistance;
                            position = CopyTeleportPosition(lastPoint);
                            source = routeRange.Source + ".dest.end";
                            _teleportRouteWinningHeaderAddress = routeRange.HeaderAddress;
                        }
                    }

                    runStart = p;
                }
            }

            return position != null;
        }

        private static bool IsPlausibleModuleWaypointEndpoint(byte[] endpoint)
        {
            if (!IsPlausibleRouteOrMarkerPosition(endpoint))
                return false;

            var y = BitConverter.ToSingle(endpoint, 4);
            return y >= -10F && y <= TeleportWaypointModuleRouteMaxEndpointY;
        }

        private bool TrySelectTeleportCheckpointRoute(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            ulong vehiclePointer,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            _teleportRouteWinningHeaderAddress = 0;
            if (routeRanges == null || routeRanges.Count == 0 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            float headingX;
            float headingZ;
            var hasHeading = TryReadRouteTravelHeading(vehiclePointer, out headingX, out headingZ);
            var bestScore = double.MinValue;
            var bestDirection = 0;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                if (routeRange == null || routeRange.Positions == null || routeRange.Positions.Count < 2)
                    continue;

                byte[] checkpoint;
                int nearestIndex;
                int checkpointIndex;
                int routeDirection;
                double nearestDistance;
                double checkpointDistance;
                var preferredDirection = GetRememberedAutoRaceRouteDirection(routeRange.HeaderAddress);
                if (!TryChooseNextCheckpointFromRoute(
                    routeRange.Positions,
                    anchor,
                    preferredDirection,
                    hasHeading,
                    headingX,
                    headingZ,
                    out checkpoint,
                    out nearestIndex,
                    out checkpointIndex,
                    out routeDirection,
                    out nearestDistance,
                    out checkpointDistance))
                    continue;

                var indexAdvance = Math.Abs(checkpointIndex - nearestIndex);
                var score = routeRange.Priority +
                            (250000.0 - Math.Min(nearestDistance, 250000.0)) +
                            (640000.0 - Math.Min(checkpointDistance, 640000.0)) +
                            (double)Math.Min(indexAdvance, 128) * 2500.0 +
                            (double)Math.Min(routeRange.Positions.Count, 64) * 500.0 -
                            (double)Math.Min(routeRange.ByteLength, 0x20000UL) * 0.25;
                if (score <= bestScore)
                    continue;

                bestScore = score;
                position = CopyTeleportPosition(checkpoint);
                source = routeRange.Source + ".nextCheckpoint";
                _teleportRouteWinningHeaderAddress = routeRange.HeaderAddress;
                bestDirection = routeDirection;
            }

            if (position != null && _teleportRouteWinningHeaderAddress != 0 && bestDirection != 0)
                RememberAutoRaceRouteDirection(_teleportRouteWinningHeaderAddress, bestDirection);
            return position != null;
        }

        private static bool TryChooseNextCheckpointFromRoute(
            List<byte[]> positions,
            byte[] anchor,
            int preferredDirection,
            bool hasHeading,
            float headingX,
            float headingZ,
            out byte[] checkpoint,
            out int nearestIndex,
            out int checkpointIndex,
            out int selectedDirection,
            out double nearestDistance,
            out double checkpointDistance)
        {
            checkpoint = null;
            nearestIndex = -1;
            checkpointIndex = -1;
            selectedDirection = 0;
            nearestDistance = double.MaxValue;
            checkpointDistance = double.MaxValue;
            if (positions == null || positions.Count < 2 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var gridAligned = 0;
            var valid = new List<int>();
            for (var i = 0; i < positions.Count; i++)
            {
                var candidate = positions[i];
                if (!IsPlausibleRouteOrMarkerPosition(candidate))
                    continue;

                valid.Add(i);
                var x = BitConverter.ToSingle(candidate, 0);
                var z = BitConverter.ToSingle(candidate, 8);
                if (Math.Abs(x / 512F - (float)Math.Round(x / 512F)) < 0.001F ||
                    Math.Abs(z / 512F - (float)Math.Round(z / 512F)) < 0.001F)
                    gridAligned++;

                var distance = TeleportHorizontalDistanceSquared(candidate, anchor);
                if (distance < nearestDistance)
                {
                    nearestDistance = distance;
                    nearestIndex = i;
                }
            }

            if (valid.Count < 2 || nearestIndex < 0)
                return false;
            if (gridAligned * 4 > valid.Count)
                return false;
            if (nearestDistance > 250000.0)
                return false;

            if (hasHeading)
            {
                var headingLength = (float)Math.Sqrt((double)((headingX * headingX) + (headingZ * headingZ)));
                if (headingLength > 0.001F)
                {
                    headingX /= headingLength;
                    headingZ /= headingLength;
                }
                else
                {
                    hasHeading = false;
                }
            }

            int positiveIndex;
            int negativeIndex;
            double positiveDistance;
            double negativeDistance;
            double positiveSpan;
            double negativeSpan;
            int positiveCount;
            int negativeCount;
            float positiveDirX;
            float positiveDirZ;
            float negativeDirX;
            float negativeDirZ;
            bool positiveMarker;
            bool negativeMarker;
            var positive = SelectCheckpointCandidateInDirection(
                positions, anchor, nearestIndex, 1,
                out positiveIndex, out positiveDistance, out positiveSpan, out positiveCount,
                out positiveDirX, out positiveDirZ, out positiveMarker);
            var negative = SelectCheckpointCandidateInDirection(
                positions, anchor, nearestIndex, -1,
                out negativeIndex, out negativeDistance, out negativeSpan, out negativeCount,
                out negativeDirX, out negativeDirZ, out negativeMarker);

            var positiveScore = ScoreRouteDirectionCandidate(
                positive, 1, preferredDirection, hasHeading, headingX, headingZ,
                positiveDirX, positiveDirZ, positiveSpan, positiveCount, positiveMarker);
            var negativeScore = ScoreRouteDirectionCandidate(
                negative, -1, preferredDirection, hasHeading, headingX, headingZ,
                negativeDirX, negativeDirZ, negativeSpan, negativeCount, negativeMarker);

            if (double.IsNegativeInfinity(positiveScore) && double.IsNegativeInfinity(negativeScore))
                return false;

            if (positiveScore >= negativeScore)
            {
                checkpoint = CopyTeleportPosition(positive);
                checkpointIndex = positiveIndex;
                checkpointDistance = positiveDistance;
                selectedDirection = 1;
            }
            else
            {
                checkpoint = CopyTeleportPosition(negative);
                checkpointIndex = negativeIndex;
                checkpointDistance = negativeDistance;
                selectedDirection = -1;
            }
            return checkpoint != null;
        }

        private static double ScoreRouteDirectionCandidate(
            byte[] candidate,
            int direction,
            int preferredDirection,
            bool hasHeading,
            float headingX,
            float headingZ,
            float routeDirX,
            float routeDirZ,
            double pathSpan,
            int pathCount,
            bool checkpointMarker)
        {
            if (candidate == null)
                return double.NegativeInfinity;

            var score = (Math.Min(pathSpan, 5000.0) * 1000.0) + (Math.Min(pathCount, 512) * 500.0);
            if (checkpointMarker)
                score += 500000.0;
            if (preferredDirection == direction)
                score += 6000000000.0;

            if (hasHeading)
            {
                var dot = (headingX * routeDirX) + (headingZ * routeDirZ);
                score += dot * 2000000000.0;
                if (dot < -0.15F)
                    score -= 3000000000.0;
            }
            return score;
        }

        private static byte[] SelectCheckpointCandidateInDirection(
            List<byte[]> positions,
            byte[] anchor,
            int nearestIndex,
            int step,
            out int selectedIndex,
            out double selectedDistance,
            out double pathSpan,
            out int pathCount,
            out float routeDirectionX,
            out float routeDirectionZ,
            out bool checkpointMarker)
        {
            selectedIndex = -1;
            selectedDistance = double.MaxValue;
            pathSpan = 0.0;
            pathCount = 0;
            routeDirectionX = 0F;
            routeDirectionZ = 0F;
            checkpointMarker = false;
            if (positions == null || anchor == null || nearestIndex < 0 || nearestIndex >= positions.Count || step == 0)
                return null;

            byte[] previous = positions[nearestIndex];
            byte[] endpoint = null;
            var endpointIndex = -1;
            var endpointDistance = double.MaxValue;
            for (var i = nearestIndex + step; i >= 0 && i < positions.Count; i += step)
            {
                var candidate = positions[i];
                if (!IsPlausibleRouteOrMarkerPosition(candidate))
                    continue;

                var segment = TeleportHorizontalDistanceSquared(previous, candidate);
                if (segment > TeleportRouteSegmentBreakDistanceSquared)
                    break;

                var segmentLength = Math.Sqrt(Math.Max(0.0, segment));
                if (segmentLength > 0.001)
                {
                    if (pathCount == 0)
                    {
                        routeDirectionX = (BitConverter.ToSingle(candidate, 0) - BitConverter.ToSingle(previous, 0)) / (float)segmentLength;
                        routeDirectionZ = (BitConverter.ToSingle(candidate, 8) - BitConverter.ToSingle(previous, 8)) / (float)segmentLength;
                    }
                    pathSpan += segmentLength;
                    pathCount++;
                }

                previous = candidate;

                var distance = TeleportHorizontalDistanceSquared(candidate, anchor);
                if (distance < 64.0)
                    continue;

                var distanceMeters = Math.Sqrt(Math.Max(0.0, distance));
                endpoint = candidate;
                endpointIndex = i;
                endpointDistance = distance;

                if (IsLikelyCheckpointRouteMarker(positions, i, step) && distanceMeters >= 10.0)
                {
                    selectedIndex = i;
                    selectedDistance = distance;
                    checkpointMarker = true;
                    return CopyTeleportPosition(candidate);
                }
            }

            if (endpoint == null)
                return null;

            selectedIndex = endpointIndex;
            selectedDistance = endpointDistance;
            return CopyTeleportPosition(endpoint);
        }

        private static bool IsLikelyCheckpointRouteMarker(List<byte[]> positions, int index, int step)
        {
            if (positions == null || index < 0 || index >= positions.Count || step == 0)
                return false;

            var same = 1;
            var marker = positions[index];
            for (var i = index + step; i >= 0 && i < positions.Count; i += step)
            {
                if (TeleportHorizontalDistanceSquared(marker, positions[i]) > 4.0)
                    break;
                same++;
                if (same >= 2)
                    return true;
            }

            return false;
        }

        private static bool TrySelectActiveRouteWaypointMarker(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            if (routeRanges == null || routeRanges.Count == 0)
                return false;

            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                if (routeRange == null ||
                    routeRange.Positions == null ||
                    routeRange.Positions.Count < 2 ||
                    string.IsNullOrEmpty(routeRange.Source) ||
                    (routeRange.Source.IndexOf("activeRouteVector", StringComparison.OrdinalIgnoreCase) < 0 &&
                     routeRange.Source.IndexOf("activeRouteObject", StringComparison.OrdinalIgnoreCase) < 0))
                    continue;

                int runStart;
                int runEnd;
                if (!TryGetFirstContinuousRouteRun(routeRange.Positions, out runStart, out runEnd))
                    continue;

                byte[] marker;
                string markerSide;
                if (!TryGetTerminalRouteMarker(routeRange.Positions, runStart, runEnd, out marker, out markerSide))
                    marker = CopyTeleportPosition(routeRange.Positions[runEnd]);
                else if (!string.IsNullOrEmpty(markerSide))
                    markerSide = "." + markerSide;

                if (!IsPlausibleRouteOrMarkerPosition(marker))
                    continue;

                position = CopyTeleportPosition(marker);
                source = routeRange.Source + ".marker" + (markerSide ?? string.Empty);
                return true;
            }

            return false;
        }

        private static bool TryGetFirstContinuousRouteRun(List<byte[]> positions, out int runStart, out int runEnd)
        {
            runStart = -1;
            runEnd = -1;
            if (positions == null || positions.Count < 2)
                return false;

            runStart = 0;
            runEnd = 0;
            for (var i = 1; i < positions.Count; i++)
            {
                if (TeleportHorizontalDistanceSquared(positions[i - 1], positions[i]) > TeleportRouteSegmentBreakDistanceSquared)
                    break;
                runEnd = i;
            }

            return runEnd > runStart;
        }

        private static bool TryGetTerminalRouteMarker(
            List<byte[]> positions,
            int runStart,
            int runEnd,
            out byte[] marker,
            out string side)
        {
            marker = null;
            side = null;
            if (positions == null || runStart < 0 || runEnd <= runStart || runEnd >= positions.Count)
                return false;

            var startCount = CountMatchingRouteTerminal(positions, runStart, runEnd, 1);
            var endCount = CountMatchingRouteTerminal(positions, runEnd, runStart, -1);
            if (startCount < 2 && endCount < 2)
                return false;

            if (endCount >= startCount)
            {
                marker = CopyTeleportPosition(positions[runEnd]);
                side = "end";
            }
            else
            {
                marker = CopyTeleportPosition(positions[runStart]);
                side = "start";
            }

            return marker != null;
        }

        private static int CountMatchingRouteTerminal(List<byte[]> positions, int start, int stop, int step)
        {
            if (positions == null || start < 0 || start >= positions.Count || step == 0)
                return 0;

            var count = 1;
            var marker = positions[start];
            for (var i = start + step; step > 0 ? i <= stop : i >= stop; i += step)
            {
                if (i < 0 || i >= positions.Count || TeleportHorizontalDistanceSquared(marker, positions[i]) > 4.0)
                    break;
                count++;
            }

            return count;
        }

        private static bool TrySelectOrderedTeleportRouteEndpoint(
            List<TeleportRouteRangeCandidate> routeRanges,
            byte[] anchor,
            bool allowOrderedRouteAnchor,
            out byte[] position,
            out string source)
        {
            position = null;
            source = null;
            if (routeRanges == null || routeRanges.Count == 0)
                return false;

            var bestScore = double.MinValue;
            for (var i = 0; i < routeRanges.Count; i++)
            {
                var routeRange = routeRanges[i];
                if (routeRange == null || routeRange.Positions == null || routeRange.Positions.Count < 2)
                    continue;

                var localAnchor = IsPlausibleWorldTeleportPosition(anchor)
                    ? anchor
                    : allowOrderedRouteAnchor
                        ? routeRange.FirstPosition
                        : null;
                if (!IsPlausibleWorldTeleportPosition(localAnchor))
                    continue;

                double nearestDistance;
                byte[] endpoint;
                if (!TryGetContinuousRouteEndpoint(routeRange.Positions, localAnchor, out endpoint, out nearestDistance))
                    continue;

                var endpointDistance = TeleportHorizontalDistanceSquared(endpoint, localAnchor);
                if (nearestDistance > 250000.0 || endpointDistance < 25.0)
                    continue;

                var score = routeRange.Priority +
                            endpointDistance +
                            (160000.0 - Math.Min(nearestDistance, 160000.0)) +
                            (double)routeRange.Positions.Count * 1000.0 +
                            (double)Math.Min(routeRange.ByteLength, 0x20000UL);
                if (score <= bestScore)
                    continue;

                bestScore = score;
                position = CopyTeleportPosition(endpoint);
                source = routeRange.Source + ".continuousEnd";
            }

            return position != null;
        }

        private static bool TryGetContinuousRouteEndpoint(
            List<byte[]> positions,
            byte[] anchor,
            out byte[] endpoint,
            out double nearestDistance)
        {
            endpoint = null;
            nearestDistance = double.MaxValue;
            if (positions == null || positions.Count < 2)
                return false;

            var hasAnchor = IsPlausibleWorldTeleportPosition(anchor);
            var bestRunStart = -1;
            var bestRunEnd = -1;
            var bestRunNearest = double.MaxValue;
            var bestRunCount = 0;
            var runStart = 0;

            for (var i = 1; i <= positions.Count; i++)
            {
                var endsRun = i == positions.Count ||
                    TeleportHorizontalDistanceSquared(positions[i - 1], positions[i]) > TeleportRouteSegmentBreakDistanceSquared;
                if (!endsRun)
                    continue;

                var runEnd = i - 1;
                var runCount = runEnd - runStart + 1;
                if (runCount >= 2)
                {
                    var runNearest = double.MaxValue;
                    if (hasAnchor)
                    {
                        for (var pointIndex = runStart; pointIndex <= runEnd; pointIndex++)
                            runNearest = Math.Min(runNearest, TeleportHorizontalDistanceSquared(positions[pointIndex], anchor));
                    }

                    var betterRun = hasAnchor
                        ? runNearest < bestRunNearest
                        : runCount > bestRunCount;
                    if (betterRun)
                    {
                        bestRunStart = runStart;
                        bestRunEnd = runEnd;
                        bestRunNearest = runNearest;
                        bestRunCount = runCount;
                    }
                }

                runStart = i;
            }

            if (bestRunStart < 0 || bestRunEnd < bestRunStart)
                return false;

            var gridAligned = 0;
            for (var i = bestRunStart; i <= bestRunEnd; i++)
            {
                var candidate = positions[i];
                if (!IsPlausibleRouteOrMarkerPosition(candidate))
                    continue;

                var x = BitConverter.ToSingle(candidate, 0);
                var z = BitConverter.ToSingle(candidate, 8);
                if (Math.Abs(x / 512F - (float)Math.Round(x / 512F)) < 0.001F ||
                    Math.Abs(z / 512F - (float)Math.Round(z / 512F)) < 0.001F)
                    gridAligned++;

                if (hasAnchor)
                    nearestDistance = Math.Min(nearestDistance, TeleportHorizontalDistanceSquared(candidate, anchor));
            }

            if (!hasAnchor)
                nearestDistance = 0.0;
            if (gridAligned * 4 > bestRunCount)
                return false;

            endpoint = CopyTeleportPosition(positions[bestRunEnd]);
            return endpoint != null;
        }

        private void CollectTeleportMemoryRouteRange(
            byte[] objectData,
            int objectOffset,
            ulong objectAddress,
            ulong beginOffset,
            ulong endOffset,
            double priority,
            string routeName,
            List<TeleportRouteRangeCandidate> routeRanges,
            ref byte[] inferredCurrent,
            ref double inferredCurrentSpread,
            double minimumSpread = 900.0)
        {
            var beginIndex = objectOffset + (int)beginOffset;
            var endIndex = objectOffset + (int)endOffset;
            if (beginIndex < 0 || endIndex < 0 || beginIndex + 8 > objectData.Length || endIndex + 8 > objectData.Length)
                return;

            var begin = BitConverter.ToUInt64(objectData, beginIndex);
            var end = BitConverter.ToUInt64(objectData, endIndex);
            if (!IsLikelyTeleportPointer(begin) || !IsLikelyTeleportPointer(end) || end <= begin)
                return;

            var bytes = end - begin;
            if (bytes < 32UL || bytes > 0x100000UL || (bytes % 16UL) != 0UL)
                return;
            if (!IsWritableMemoryRange(begin, (int)Math.Min(bytes, 0x1000UL)))
                return;
            if (!IsReadableMemoryRange(begin, (int)bytes))
                return;

            var rangeData = ReadBytes(begin, (int)bytes);
            if (rangeData.Length < 32)
                return;

            var positions = new List<byte[]>();
            for (var offset = 0; offset + 16 <= rangeData.Length; offset += 16)
            {
                var candidate = new byte[16];
                Buffer.BlockCopy(rangeData, offset, candidate, 0, 16);
                if (IsPlausibleRouteOrMarkerPosition(candidate))
                    positions.Add(candidate);
            }

            if (positions.Count < 2)
                return;

            var totalSlots = Math.Max(1, rangeData.Length / 16);
            if (totalSlots > 8 && positions.Count * 3 < totalSlots)
                return;

            var last = positions[positions.Count - 1];
            var spread = GetMaxTeleportDistanceSquared(positions, last);
            if (spread < inferredCurrentSpread && spread < 225.0)
            {
                inferredCurrentSpread = spread;
                inferredCurrent = CopyTeleportPosition(last);
            }

            if (spread < minimumSpread)
                return;

            routeRanges.Add(new TeleportRouteRangeCandidate
            {
                Source = "0x" + objectAddress.ToString("X", CultureInfo.InvariantCulture) + "." + routeName,
                Priority = priority,
                ByteLength = bytes,
                Positions = positions,
                FirstPosition = CopyTeleportPosition(positions[0]),
                LastPosition = CopyTeleportPosition(last),
                HeaderAddress = objectAddress
            });
        }

        private static double GetMaxTeleportDistanceSquared(List<byte[]> positions, byte[] anchor)
        {
            if (positions == null || anchor == null || anchor.Length < 12)
                return 0.0;

            var best = 0.0;
            for (var i = 0; i < positions.Count; i++)
                best = Math.Max(best, TeleportHorizontalDistanceSquared(positions[i], anchor));
            return best;
        }

        private static bool TryChooseActiveRouteDestination(
            List<byte[]> positions,
            byte[] anchor,
            out byte[] destination,
            out double nearestDistance,
            out double destinationDistance)
        {
            destination = null;
            nearestDistance = double.MaxValue;
            destinationDistance = 0.0;
            if (positions == null || positions.Count < 2 || !IsPlausibleWorldTeleportPosition(anchor))
                return false;

            var gridAligned = 0;
            for (var i = 0; i < positions.Count; i++)
            {
                var candidate = positions[i];
                var x = BitConverter.ToSingle(candidate, 0);
                var z = BitConverter.ToSingle(candidate, 8);
                if (Math.Abs(x / 512F - (float)Math.Round(x / 512F)) < 0.001F ||
                    Math.Abs(z / 512F - (float)Math.Round(z / 512F)) < 0.001F)
                    gridAligned++;
            }

            if (gridAligned * 4 > positions.Count)
                return false;

            byte[] farthest = null;
            nearestDistance = double.MaxValue;
            destinationDistance = 0.0;
            for (var i = 0; i < positions.Count; i++)
            {
                var candidate = positions[i];
                if (!IsPlausibleRouteOrMarkerPosition(candidate))
                    continue;

                var distance = TeleportHorizontalDistanceSquared(candidate, anchor);
                if (distance < nearestDistance)
                    nearestDistance = distance;
                if (distance <= destinationDistance)
                    continue;

                destinationDistance = distance;
                farthest = candidate;
            }

            if (farthest == null || nearestDistance > 250000.0 || destinationDistance < 900.0)
                return false;

            destination = CopyTeleportPosition(farthest);
            return true;
        }

        private static double TeleportDistanceSquared(byte[] left, byte[] right)
        {
            if (left == null || right == null || left.Length < 12 || right.Length < 12)
                return 0.0;

            var dx = BitConverter.ToSingle(left, 0) - BitConverter.ToSingle(right, 0);
            var dy = BitConverter.ToSingle(left, 4) - BitConverter.ToSingle(right, 4);
            var dz = BitConverter.ToSingle(left, 8) - BitConverter.ToSingle(right, 8);
            return (double)dx * dx + (double)dy * dy + (double)dz * dz;
        }

        private static double TeleportHorizontalDistanceSquared(byte[] left, byte[] right)
        {
            if (left == null || right == null || left.Length < 12 || right.Length < 12)
                return 0.0;

            var dx = BitConverter.ToSingle(left, 0) - BitConverter.ToSingle(right, 0);
            var dz = BitConverter.ToSingle(left, 8) - BitConverter.ToSingle(right, 8);
            return (double)dx * dx + (double)dz * dz;
        }

        private static byte[] ChooseRouteEndpoint(byte[] first, byte[] last, byte[] anchor)
        {
            if (first == null || first.Length < 12)
                return CopyTeleportPosition(last);
            if (last == null || last.Length < 12)
                return CopyTeleportPosition(first);
            if (anchor == null || anchor.Length < 12)
                return CopyTeleportPosition(last);

            return TeleportHorizontalDistanceSquared(first, anchor) > TeleportHorizontalDistanceSquared(last, anchor)
                ? CopyTeleportPosition(first)
                : CopyTeleportPosition(last);
        }

        private static bool IsPlausibleWorldTeleportPosition(byte[] position)
        {
            if (position == null || position.Length < 12 || !IsValidTeleportPosition(position))
                return false;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            if (Math.Abs(x) < 5F || Math.Abs(z) < 5F)
                return false;
            if (Math.Abs(x) > 10000F || Math.Abs(z) > 10000F || y < -1000F || y > 2500F)
                return false;

            return true;
        }

        private static bool IsPlausibleRouteTeleportPosition(byte[] position)
        {
            if (!IsPlausibleRouteOrMarkerPosition(position))
                return false;

            var y = BitConverter.ToSingle(position, 4);
            return y > 5F;
        }

        private static bool IsPlausibleRouteOrMarkerPosition(byte[] position)
        {
            if (position == null || position.Length < 12 || !IsValidTeleportPosition(position))
                return false;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            if (Math.Abs(x) < 5F || Math.Abs(z) < 5F)
                return false;
            if (Math.Abs(x) > 10000F || Math.Abs(z) > 10000F || y < -10F || y > 2500F)
                return false;

            return true;
        }

        private static bool IsFlatTeleportMapMarker(byte[] position)
        {
            if (position == null || position.Length < 12)
                return false;

            var y = BitConverter.ToSingle(position, 4);
            return Math.Abs(y) <= 0.25F;
        }

        private static double GetTeleportCapturePriority(RuntimeProfileHookDescriptor descriptor)
        {
            if (descriptor == null || string.IsNullOrEmpty(descriptor.Key))
                return 0.0;
            if (descriptor.Key.IndexOf("NativeFastTravelPosition", StringComparison.OrdinalIgnoreCase) >= 0)
                return 9.0e14;
            if (descriptor.Key.IndexOf("MapFastTravelPosition", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.5e14;
            if (descriptor.Key.IndexOf("DestinationSetter", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.8e14;
            if (descriptor.Key.IndexOf("WaypointPointer", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.0e14;
            if (descriptor.Key.IndexOf("WaypointCopy", StringComparison.OrdinalIgnoreCase) >= 0)
                return 7.0e14;
            if (descriptor.Key.IndexOf("SatNav", StringComparison.OrdinalIgnoreCase) >= 0)
                return 0.0;
            if (descriptor.Key.IndexOf("RouteVectorB", StringComparison.OrdinalIgnoreCase) >= 0)
                return 0.0;
            if (descriptor.Key.IndexOf("RouteVector", StringComparison.OrdinalIgnoreCase) >= 0)
                return 0.0;
            return 0.0;
        }

        private static double GetTeleportObjectBasePriority(RuntimeProfileHookDescriptor descriptor)
        {
            if (descriptor == null || string.IsNullOrEmpty(descriptor.Key))
                return 0.0;
            if (descriptor.Key.IndexOf("NativeFastTravelPosition", StringComparison.OrdinalIgnoreCase) >= 0)
                return 9.0e14;
            if (descriptor.Key.IndexOf("MapFastTravelPosition", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.5e14;
            if (descriptor.Key.IndexOf("NavigationDestinationPointer", StringComparison.OrdinalIgnoreCase) >= 0 ||
                descriptor.Key.IndexOf("CurrentDestinationPointer", StringComparison.OrdinalIgnoreCase) >= 0 ||
                descriptor.Key.IndexOf("DestinationSetter", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.8e14;
            if (descriptor.Key.IndexOf("WaypointPointer", StringComparison.OrdinalIgnoreCase) >= 0)
                return 8.0e14;
            if (descriptor.Key.IndexOf("WaypointCopy", StringComparison.OrdinalIgnoreCase) >= 0)
                return 7.0e14;
            if (descriptor.Key.IndexOf("SatNavRouteObject", StringComparison.OrdinalIgnoreCase) >= 0)
                return 0.0;
            if (descriptor.Key.IndexOf("SatNav", StringComparison.OrdinalIgnoreCase) >= 0)
                return 0.0;
            if (descriptor.Key.IndexOf("RouteVector", StringComparison.OrdinalIgnoreCase) >= 0)
                return 3.0e14;
            return 0.0;
        }

        private static double GetTeleportObjectOffsetPriority(ulong offset)
        {
            if (offset == 0x210UL)
                return 8.0e12;
            if (offset == 0x220UL)
                return 7.0e12;
            if (offset == 0x590UL)
                return 6.0e12;
            if (offset == 0x5A0UL)
                return 5.0e12;
            if (offset == 0x230UL)
                return 4.0e12;
            if (offset == 0x90UL)
                return 1.0e12;
            if (offset == 0x760UL)
                return 2.0e12;
            if (offset == 0xA0UL)
                return 1.0e12;
            if (offset == 0x80UL)
                return 5.0e11;
            return 0.0;
        }

        private void ConsiderTeleportPosition(byte[] candidate, byte[] current, ref byte[] best, ref double bestScore, double priority, string source)
        {
            if (candidate == null || candidate.Length < 12 || !IsPlausibleRouteOrMarkerPosition(candidate))
                return;

            var score = 1.0;
            if (current != null && current.Length >= 12 && IsValidTeleportPosition(current))
            {
                var dx = BitConverter.ToSingle(candidate, 0) - BitConverter.ToSingle(current, 0);
                var dz = BitConverter.ToSingle(candidate, 8) - BitConverter.ToSingle(current, 8);
                score = (double)dx * dx + (double)dz * dz;
                if (score < 9.0)
                    return;
            }

            score += priority;
            if (score <= bestScore)
                return;

            bestScore = score;
            best = candidate;
            _teleportLastSource = source ?? string.Empty;
        }

        private static bool IsValidTeleportPosition(byte[] position)
        {
            if (position == null || position.Length < 12)
                return false;

            var x = BitConverter.ToSingle(position, 0);
            var y = BitConverter.ToSingle(position, 4);
            var z = BitConverter.ToSingle(position, 8);
            if (!IsValidTeleportCoordinate(x) ||
                !IsValidTeleportCoordinate(y) ||
                !IsValidTeleportCoordinate(z) ||
                LooksLikePointerBackedVector(position) ||
                (Math.Abs(x) < 0.001F && Math.Abs(y) < 0.001F && Math.Abs(z) < 0.001F))
                return false;

            var maxAbs = Math.Max(Math.Abs(x), Math.Max(Math.Abs(y), Math.Abs(z)));
            if (maxAbs > 250000F)
            {
                var meaningful = 0;
                if (Math.Abs(x) > 1000F) meaningful++;
                if (Math.Abs(y) > 1000F) meaningful++;
                if (Math.Abs(z) > 1000F) meaningful++;
                if (meaningful < 2)
                    return false;
            }

            return true;
        }

        private static string FormatTeleportPosition(byte[] position)
        {
            if (position == null || position.Length < 12)
                return "unknown";

            return "X " + BitConverter.ToSingle(position, 0).ToString("0.0", CultureInfo.InvariantCulture) +
                   ", Y " + BitConverter.ToSingle(position, 4).ToString("0.0", CultureInfo.InvariantCulture) +
                   ", Z " + BitConverter.ToSingle(position, 8).ToString("0.0", CultureInfo.InvariantCulture);
        }

        private static bool IsValidTeleportCoordinate(float value)
        {
            return !float.IsNaN(value) && !float.IsInfinity(value) && Math.Abs(value) < 10000000F;
        }

        private static bool LooksLikePointerBackedVector(byte[] position)
        {
            if (position == null || position.Length < 16)
                return false;

            return LooksLikeProcessPointer(BitConverter.ToUInt64(position, 0)) ||
                   LooksLikeProcessPointer(BitConverter.ToUInt64(position, 8));
        }

        private static bool IsLikelyTeleportPointer(ulong pointer)
        {
            return LooksLikeProcessPointer(pointer);
        }

        private static bool LooksLikeProcessPointer(ulong value)
        {
            if (value < 0x100000000UL || value > 0x00007FFFFFFFFFFFUL)
                return false;
            return (value >> 32) < 0x10000UL;
        }

        private static void NormalizeAirControlDirection(ref float side, ref float forward)
        {
            var sideAbs = Math.Abs(side);
            var forwardAbs = Math.Abs(forward);
            if (sideAbs <= 0.01F && forwardAbs <= 0.01F)
            {
                side = 0F;
                forward = 0F;
                return;
            }

            if (forwardAbs >= sideAbs)
            {
                forward = forward < 0F ? -1F : 1F;
                side = 0F;
            }
            else
            {
                side = side < 0F ? -1F : 1F;
                forward = 0F;
            }
        }
        private bool IsBrakeInputPressed()
        {
            return IsKeyDown(_brakeVirtualKey);
        }

        private bool IsAirBrakeInputPressed()
        {
            return IsKeyDown((int)Keys.S) || IsKeyDown((int)Keys.Down) || IsKeyDown(_brakeVirtualKey);
        }

        private static bool IsAccelerationInputPressed()
        {
            return IsForwardInputPressed();
        }

        private static bool IsForwardInputPressed()
        {
            return IsKeyDown((int)Keys.W) || IsKeyDown((int)Keys.Up);
        }

        private static bool IsKeyDown(int virtualKey)
        {
            return (Native.GetAsyncKeyState(virtualKey) & unchecked((short)0x8000)) != 0;
        }

        public void SetBestWheelspinOddsRuntime(bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            lock (_bestWheelspinPatchLock)
            {
                if (!enabled)
                {
                    var restored = RestoreBestWheelspinOddsPatches();
                    _log("Best Spins runtime hook disabled. Restored " + restored.ToString(CultureInfo.InvariantCulture) + " Tombola patch(es).");
                    return;
                }

                EnsureCrcBypass();
                RestoreBestWheelspinOddsPatches();

                var module = ReadBytes(_mainBase, _mainSize);
                if (module.Length == 0)
                    throw new InvalidOperationException("Could not read main module memory for Best Spins hook scan.");

                var patched = PatchBestWheelspinSpinValueMetadataHooks(module);
                if (patched <= 0)
                    throw new InvalidOperationException("Best Spins runtime hook was not armed because the Tombola SpinValue rarity metadata was not found.");

                _log("Best Spins runtime hook enabled. Tombola SpinValue rarity conversions are forced to FH6's rarest tier value (3) while Luna stays attached.");
            }
        }

        private int PatchBestWheelspinSpinValueMetadataHooks(byte[] module)
        {
            var enumReadByValue = _mainBase + 0x2E88580UL;
            var detours = new Dictionary<ulong, ulong>();
            var patched = 0;

            patched += PatchBestWheelspinSpinValueBlock(module, "SpinValue", 0x90, enumReadByValue, detours);
            patched += PatchBestWheelspinSpinValueBlock(module, "TombolaRemainingSpinItem", 0x80, enumReadByValue, detours);

            return patched;
        }

        private int PatchBestWheelspinSpinValueBlock(byte[] module, string label, int scanBytes, ulong enumReadByValue, Dictionary<ulong, ulong> detours)
        {
            var needle = Encoding.ASCII.GetBytes(label + "\0");
            var patched = 0;

            foreach (var labelOffset in Pattern.FindBytes(module, needle, 8))
            {
                for (var relative = 8; relative <= scanBytes; relative += 8)
                {
                    var pointerAddress = _mainBase + (ulong)labelOffset + (ulong)relative;
                    var originalTarget = ReadUInt64(pointerAddress);
                    if (originalTarget != enumReadByValue)
                        continue;

                    var current = ReadBytes(pointerAddress, 8);
                    if (current.Length != 8)
                        continue;

                    ulong detour;
                    if (!detours.TryGetValue(originalTarget, out detour))
                    {
                        detour = CreateBestWheelspinSpinValueDetour(originalTarget);
                        detours.Add(originalTarget, detour);
                    }

                    WriteProtectedBytes(pointerAddress, BitConverter.GetBytes(detour));
                    _bestWheelspinOddsPatches.Add(new MemoryPatch { Address = pointerAddress, Original = current });
                    patched++;
                    _log("Best Spins patched " + label + " SpinValue converter pointer at 0x" + pointerAddress.ToString("X") +
                        " from 0x" + originalTarget.ToString("X") + " to detour 0x" + detour.ToString("X") + ".");
                }
            }

            return patched;
        }

        private ulong CreateBestWheelspinSpinValueDetour(ulong originalTarget)
        {
            var code = new List<byte>();
            EmitBytes(code, 0x48, 0x89, 0x5C, 0x24, 0x08);
            EmitBytes(code, 0x48, 0x89, 0x6C, 0x24, 0x10);
            EmitBytes(code, 0x56);
            EmitBytes(code, 0x57);
            EmitBytes(code, 0x41, 0x56);
            EmitBytes(code, 0x48, 0x83, 0xEC, 0x30);
            EmitBytes(code, 0x48, 0x8B, 0xFA);
            EmitBytes(code, 0x48, 0x8B, 0xF1);
            EmitBytes(code, 0x4D, 0x85, 0xC9);
            EmitBytes(code, 0x75, 0x0F);
            EmitBytes(code, 0x4C, 0x89, 0x0A);
            EmitBytes(code, 0x48, 0xB8);
            code.AddRange(BitConverter.GetBytes(originalTarget + 0x62UL));
            EmitBytes(code, 0xFF, 0xE0);
            EmitBytes(code, 0xBD, 0x03, 0x00, 0x00, 0x00);
            EmitBytes(code, 0x48, 0xB8);
            code.AddRange(BitConverter.GetBytes(originalTarget + 0x26UL));
            EmitBytes(code, 0xFF, 0xE0);

            var remote = Native.VirtualAllocEx(_handle, IntPtr.Zero, (UIntPtr)Math.Max(0x1000, code.Count), Native.MemCommitReserve, Native.PageExecuteReadWrite);
            if (remote == IntPtr.Zero)
                throw new InvalidOperationException("VirtualAllocEx failed while creating Best Spins detour.");

            var address = (ulong)remote.ToInt64();
            WriteBytes(address, code.ToArray());
            _bestWheelspinOddsDetours.Add(address);
            return address;
        }

        private int RestoreBestWheelspinOddsPatches()
        {
            lock (_bestWheelspinPatchLock)
            {
                var restored = 0;
                for (var i = _bestWheelspinOddsPatches.Count - 1; i >= 0; i--)
                {
                    try
                    {
                        WriteProtectedBytes(_bestWheelspinOddsPatches[i].Address, _bestWheelspinOddsPatches[i].Original);
                        restored++;
                    }
                    catch (Exception ex)
                    {
                        _log("Could not restore Best Spins patch at 0x" + _bestWheelspinOddsPatches[i].Address.ToString("X") + ": " + ex.Message);
                    }
                }
                _bestWheelspinOddsPatches.Clear();
                for (var i = _bestWheelspinOddsDetours.Count - 1; i >= 0; i--)
                {
                    try
                    {
                        Native.VirtualFreeEx(_handle, new IntPtr((long)_bestWheelspinOddsDetours[i]), UIntPtr.Zero, Native.MemRelease);
                    }
                    catch
                    {
                    }
                }
                _bestWheelspinOddsDetours.Clear();
                return restored;
            }
        }

        private void ApplyTimeAttackInfluenceMultiplier(float multiplier, bool enabled)
        {
            if (!enabled)
            {
                var restored = RestoreTimeAttackInfluencePatches();
                _log("Time Attack XP Multiplier disabled. Restored " + restored.ToString(CultureInfo.InvariantCulture) + " patched bonus float(s).");
                return;
            }

            if (float.IsNaN(multiplier) || float.IsInfinity(multiplier) || multiplier < 1F)
                throw new InvalidOperationException("Time Attack XP Multiplier must be 1 or higher.");
            if (multiplier > 1000000F)
                throw new InvalidOperationException("Time Attack XP Multiplier must be 1000000 or lower for this guarded patch path.");

            lock (_timeAttackPatchLock)
            {
                RestoreTimeAttackInfluencePatches();
                var scanWatch = Stopwatch.StartNew();
                bool scanTimedOut;
                var candidates = FindTimeAttackInfluenceRecordFloatCandidates(scanWatch, out scanTimedOut);
                var patched = 0;
                foreach (var candidate in candidates)
                {
                    if (!IsLiveTimeAttackCandidate(candidate))
                        continue;

                    var current = ReadBytes(candidate.Address, 4);
                    if (current.Length < 4)
                        continue;
                    var currentValue = BitConverter.ToSingle(current, 0);
                    if (!IsTimeAttackRuntimeBonusValue(currentValue))
                        continue;

                    try
                    {
                        var targetValue = GetTimeAttackPatchValue(multiplier, candidate.PatchMode);
                        WriteTimeAttackBytes(candidate.Address, BitConverter.GetBytes(targetValue));
                        _timeAttackInfluencePatches.Add(new MemoryPatch { Address = candidate.Address, Original = current });
                        patched++;
                        _log("Time Attack XP candidate patched at 0x" + candidate.Address.ToString("X") +
                            " from x" + FormatFloatInvariant(currentValue) +
                            " to raw x" + FormatFloatInvariant(targetValue) +
                            " for requested x" + FormatFloatInvariant(multiplier) +
                            " near 0x" + candidate.Anchor.ToString("X") + ".");
                    }
                    catch (Exception ex)
                    {
                        _log("Skipped volatile Time Attack XP candidate at 0x" + candidate.Address.ToString("X") + ": " + ex.Message);
                    }
                }

                if (patched == 0)
                {
                    var scanState = scanTimedOut ? "stopped at the " + TimeAttackRecordScanTimeoutMs.ToString(CultureInfo.InvariantCulture) + "ms safety limit" : "finished";
                    _log("Time Attack XP Multiplier ID-record scan " + scanState + ". No TimeAttackInfluence runtime record bonus slots were patched.");
                    throw new InvalidOperationException("Time Attack XP Multiplier was not armed because the TimeAttackInfluence runtime record was not found in the current live scan.");
                }

                _log("Time Attack XP Multiplier enabled. Patched " + patched.ToString(CultureInfo.InvariantCulture) +
                    " TimeAttackInfluence bonus float(s). Bonus-delta slots use requested multiplier minus 1. Run a Time Attack XP drop while Luna stays attached.");
            }
        }

        public bool TryReadCurrentTimeAttackXpMultiplier(out float value)
        {
            value = 0F;
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            lock (_timeAttackPatchLock)
            {
                bool timedOut;
                var candidates = FindTimeAttackInfluenceRecordFloatCandidates(Stopwatch.StartNew(), out timedOut);
                if (candidates.Count == 0)
                {
                    _log("Time Attack XP Multiplier Load Current did not find live ID-record slots" + (timedOut ? " before the safety timeout." : "."));
                    return false;
                }

                value = GetTimeAttackDisplayMultiplier(candidates);
                _log("Time Attack XP Multiplier Load Current cached " + candidates.Count.ToString(CultureInfo.InvariantCulture) +
                    " live bonus slot(s). Current value: x" + FormatFloatInvariant(value) + ".");
                return true;
            }
        }

        private int RestoreTimeAttackInfluencePatches()
        {
            lock (_timeAttackPatchLock)
            {
                var restored = 0;
                for (var i = _timeAttackInfluencePatches.Count - 1; i >= 0; i--)
                {
                    try
                    {
                        WriteTimeAttackBytes(_timeAttackInfluencePatches[i].Address, _timeAttackInfluencePatches[i].Original);
                        restored++;
                    }
                    catch (Exception ex)
                    {
                        _log("Could not restore Time Attack XP patch at 0x" + _timeAttackInfluencePatches[i].Address.ToString("X") + ": " + ex.Message);
                    }
                }
                _timeAttackInfluencePatches.Clear();
                return restored;
            }
        }

        private List<TimeAttackFloatCandidate> FindTimeAttackInfluenceRecordFloatCandidates(Stopwatch scanWatch, out bool timedOut)
        {
            var cached = ValidateTimeAttackInfluenceCachedCandidates();
            if (cached.Count > 0)
            {
                timedOut = false;
                return cached;
            }

            var scanned = ScanTimeAttackInfluenceRecordFloatCandidates(scanWatch, out timedOut);
            if (scanned.Count == 0 && !IsTimeAttackRecordScanExpired(scanWatch))
            {
                var anchorTimedOut = RefreshTimeAttackInfluenceAnchors(scanWatch);
                var fallback = FindTimeAttackInfluenceFloatCandidates();
                if (fallback.Count > 0)
                {
                    scanned = fallback;
                    timedOut = anchorTimedOut;
                }
            }

            if (scanned.Count > 0)
            {
                _timeAttackInfluenceCachedCandidates.Clear();
                _timeAttackInfluenceCachedCandidates.AddRange(scanned);
            }

            return scanned;
        }

        private List<TimeAttackFloatCandidate> ValidateTimeAttackInfluenceCachedCandidates()
        {
            var candidates = new List<TimeAttackFloatCandidate>();
            var seen = new HashSet<ulong>();
            foreach (var candidate in _timeAttackInfluenceCachedCandidates)
            {
                if (candidate.Anchor < 16UL)
                    continue;

                var recordData = ReadBytes(candidate.Anchor - 16UL, 160);
                if (recordData.Length < 128 || !LooksLikeTimeAttackInfluenceRecord(recordData, 16))
                    continue;

                var current = ReadBytes(candidate.Address, 4);
                if (current.Length < 4)
                    continue;

                var value = BitConverter.ToSingle(current, 0);
                if (!IsTimeAttackRuntimeBonusValue(value) || !seen.Add(candidate.Address))
                    continue;

                candidates.Add(new TimeAttackFloatCandidate
                {
                    Address = candidate.Address,
                    Anchor = candidate.Anchor,
                    Value = value,
                    PatchMode = candidate.PatchMode
                });
                if (candidates.Count >= TimeAttackMaxBonusSlots)
                    break;
            }

            if (candidates.Count == 0)
                _timeAttackInfluenceCachedCandidates.Clear();
            return candidates;
        }

        private List<TimeAttackFloatCandidate> ScanTimeAttackInfluenceRecordFloatCandidates(Stopwatch scanWatch, out bool timedOut)
        {
            timedOut = false;
            var candidates = new List<TimeAttackFloatCandidate>();
            var seen = new HashSet<ulong>();
            var gate = new object();
            var timedOutFlag = 0;
            var foundEnough = 0;
            var regions = EnumerateTimeAttackRecordRegions();

            var options = new ParallelOptions
            {
                MaxDegreeOfParallelism = Math.Max(1, Math.Min(Environment.ProcessorCount, 6))
            };

            Parallel.ForEach(regions, options, (region, state) =>
            {
                if (Volatile.Read(ref foundEnough) != 0)
                {
                    state.Stop();
                    return;
                }

                var offset = 0UL;
                while (offset < region.RegionSize && Volatile.Read(ref foundEnough) == 0)
                {
                    if (IsTimeAttackRecordScanExpired(scanWatch))
                    {
                        Interlocked.Exchange(ref timedOutFlag, 1);
                        state.Stop();
                        return;
                    }

                    var length = (int)Math.Min((4UL * 1024UL * 1024UL) + 256UL, region.RegionSize - offset);
                    var data = ReadBytes(region.BaseAddress + offset, length);
                    if (data.Length == 0)
                        break;

                    ScanTimeAttackRecordChunk(region.BaseAddress + offset, data, candidates, seen, gate);
                    lock (gate)
                    {
                        if (candidates.Count >= TimeAttackMaxBonusSlots)
                        {
                            Interlocked.Exchange(ref foundEnough, 1);
                            state.Stop();
                            return;
                        }
                    }

                    if (data.Length <= 256)
                        offset += (ulong)data.Length;
                    else
                        offset += (ulong)(data.Length - 256);
                }
            });

            timedOut = Volatile.Read(ref timedOutFlag) != 0;
            return candidates;
        }

        private void ScanTimeAttackRecordChunk(ulong baseAddress, byte[] data, List<TimeAttackFloatCandidate> candidates, HashSet<ulong> seen, object gate)
        {
            foreach (var needleOffset in Pattern.FindBytes(data, TimeAttackRecordNeedle, 256))
            {
                var recordOffset = needleOffset + 16;
                if (!LooksLikeTimeAttackInfluenceRecord(data, recordOffset))
                    continue;

                lock (gate)
                {
                    if (candidates.Count >= TimeAttackMaxBonusSlots)
                        return;
            AddTimeAttackRecordFloatCandidate(baseAddress + (ulong)recordOffset + 80UL, baseAddress + (ulong)recordOffset, data, recordOffset + 80, candidates, seen);
                    if (candidates.Count >= TimeAttackMaxBonusSlots)
                        return;
            AddTimeAttackRecordFloatCandidate(baseAddress + (ulong)recordOffset + 92UL, baseAddress + (ulong)recordOffset, data, recordOffset + 92, candidates, seen);
                }
            }
        }

        private void AddTimeAttackRecordFloatCandidate(ulong address, ulong recordAddress, byte[] data, int offset, List<TimeAttackFloatCandidate> candidates, HashSet<ulong> seen)
        {
            if (candidates.Count >= TimeAttackMaxBonusSlots)
                return;
            if (offset < 0 || offset + 4 > data.Length)
                return;

            var value = BitConverter.ToSingle(data, offset);
            if (!IsTimeAttackRuntimeBonusValue(value) || !seen.Add(address))
                return;

            candidates.Add(new TimeAttackFloatCandidate
            {
                Address = address,
                Value = value,
                Anchor = recordAddress,
                PatchMode = TimeAttackPatchModeBonusDelta
            });
        }

        private bool IsLiveTimeAttackCandidate(TimeAttackFloatCandidate candidate)
        {
            if (candidate.Anchor < 16UL)
                return false;

            try
            {
                var recordData = ReadBytes(candidate.Anchor - 16UL, 160);
                return recordData.Length >= 128 && LooksLikeTimeAttackInfluenceRecord(recordData, 16);
            }
            catch
            {
                return false;
            }
        }

        private List<MemoryRegion> EnumerateTimeAttackRecordRegions()
        {
            var regions = new List<MemoryRegion>();
            var address = 0UL;
            var size = (UIntPtr)Marshal.SizeOf(typeof(Native.MemoryBasicInformation64));
            while (address < 0x00007FFFFFFFFFFFUL)
            {
                Native.MemoryBasicInformation64 mbi;
                var queried = Native.VirtualQueryEx(_handle, new UIntPtr(address), out mbi, size);
                if (queried == UIntPtr.Zero)
                    break;

                var next = mbi.BaseAddress + mbi.RegionSize;
                if (next <= address)
                    next = address + 0x1000UL;

                if (mbi.State == Native.MemCommit &&
                    IsTimeAttackRecordRegion(mbi.Protect, mbi.BaseAddress, mbi.RegionSize))
                {
                    regions.Add(new MemoryRegion { BaseAddress = mbi.BaseAddress, RegionSize = mbi.RegionSize });
                }

                address = next;
            }

            regions.Sort(CompareTimeAttackRecordRegions);
            return regions;
        }

        private static int CompareTimeAttackRecordRegions(MemoryRegion left, MemoryRegion right)
        {
            var rightScore = TimeAttackRecordRegionScore(right);
            var leftScore = TimeAttackRecordRegionScore(left);
            var scoreCompare = rightScore.CompareTo(leftScore);
            if (scoreCompare != 0)
                return scoreCompare;
            return right.BaseAddress.CompareTo(left.BaseAddress);
        }

        private static int TimeAttackRecordRegionScore(MemoryRegion region)
        {
            var score = 0;
            if (region.RegionSize >= 16UL * 1024UL * 1024UL && region.RegionSize <= 64UL * 1024UL * 1024UL)
                score += 4;
            if (region.RegionSize == 32UL * 1024UL * 1024UL)
                score += 2;
            if (region.BaseAddress >= 0x12000000000UL && region.BaseAddress <= 0x14000000000UL)
                score += 1;
            return score;
        }

        private static bool IsTimeAttackRecordRegion(uint protect, ulong baseAddress, ulong regionSize)
        {
            if ((protect & Native.PageGuard) != 0) return false;
            if ((protect & Native.PageNoAccess) != 0) return false;
            if ((protect & 0xFFU) != Native.PageReadWrite) return false;
            if ((protect & PageNoCache) == 0) return false;
            if (baseAddress <= 0x10000000000UL || baseAddress >= 0x700000000000UL) return false;
            return regionSize > 0x1000UL && regionSize <= 64UL * 1024UL * 1024UL;
        }

        private static bool LooksLikeTimeAttackInfluenceRecord(byte[] data, int offset)
        {
            if (offset < 16 || offset + 108 >= data.Length)
                return false;

            return ReadInt32Local(data, offset) == 87 &&
                   ReadInt32Local(data, offset + 24) == 88 &&
                   ReadInt32Local(data, offset - 16) == 6 &&
                   ReadInt32Local(data, offset - 12) == 2 &&
                   ReadInt32Local(data, offset - 8) == 6 &&
                   ReadInt32Local(data, offset - 4) == 2 &&
                   IsBetween(ReadInt32Local(data, offset + 8), 140, 160) &&
                   IsBetween(ReadInt32Local(data, offset + 12), 140, 160) &&
                   IsFloatNear(data, offset + 56, 1F) &&
                   IsFloatNear(data, offset + 60, 1F) &&
                   IsFloatNear(data, offset + 68, 0.5F) &&
                   IsFloatNear(data, offset + 76, 2F) &&
                   IsTimeAttackRuntimeBonusAt(data, offset + 80) &&
                   IsFloatNear(data, offset + 84, 2F) &&
                   IsFloatNear(data, offset + 88, 1F) &&
                   IsTimeAttackRuntimeBonusAt(data, offset + 92) &&
                   IsFloatNear(data, offset + 96, 0.4F);
        }

        private static int ReadInt32Local(byte[] data, int offset)
        {
            return BitConverter.ToInt32(data, offset);
        }

        private static bool IsBetween(int value, int min, int max)
        {
            return value >= min && value <= max;
        }

        private static bool IsFloatNear(byte[] data, int offset, float expected)
        {
            return offset >= 0 && offset + 4 <= data.Length && Math.Abs(BitConverter.ToSingle(data, offset) - expected) < 0.0005F;
        }

        private static bool IsTimeAttackRuntimeBonusAt(byte[] data, int offset)
        {
            return offset >= 0 && offset + 4 <= data.Length && IsTimeAttackRuntimeBonusValue(BitConverter.ToSingle(data, offset));
        }

        private bool RefreshTimeAttackInfluenceAnchors(Stopwatch scanWatch)
        {
            _timeAttackInfluenceStringAddresses.Clear();
            _timeAttackInfluenceReferenceAddresses.Clear();
            var timedOut = false;

            var names = new[]
            {
                Encoding.ASCII.GetBytes("TimeAttackInfluence"),
                Encoding.ASCII.GetBytes("TimeAttackInfluenceConsumable")
            };

            foreach (var region in EnumerateReadableRegions())
            {
                if (IsTimeAttackScanExpired(scanWatch))
                {
                    timedOut = true;
                    break;
                }

                var length = (int)Math.Min(region.RegionSize, TimeAttackInfluenceMaxRegionRead);
                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length == 0)
                    continue;

                foreach (var name in names)
                {
                    foreach (var offset in Pattern.FindBytes(data, name, 32))
                    {
                        var address = region.BaseAddress + (ulong)offset;
                        if (!_timeAttackInfluenceStringAddresses.Contains(address))
                            _timeAttackInfluenceStringAddresses.Add(address);
                        if (_timeAttackInfluenceStringAddresses.Count >= TimeAttackInfluenceMaxAnchors)
                            break;
                    }
                    if (_timeAttackInfluenceStringAddresses.Count >= TimeAttackInfluenceMaxAnchors)
                        break;
                }
                if (_timeAttackInfluenceStringAddresses.Count >= TimeAttackInfluenceMaxAnchors)
                    break;
            }

            if (_timeAttackInfluenceStringAddresses.Count == 0)
                return timedOut || IsTimeAttackScanExpired(scanWatch);

            var needles = _timeAttackInfluenceStringAddresses.Select(address => BitConverter.GetBytes(address)).ToList();
            foreach (var region in EnumerateReadableRegions())
            {
                if (IsTimeAttackScanExpired(scanWatch))
                {
                    timedOut = true;
                    break;
                }

                var length = (int)Math.Min(region.RegionSize, TimeAttackInfluenceMaxRegionRead);
                var data = ReadBytes(region.BaseAddress, length);
                if (data.Length == 0)
                    continue;

                foreach (var needle in needles)
                {
                    foreach (var offset in Pattern.FindBytes(data, needle, 64))
                    {
                        var address = region.BaseAddress + (ulong)offset;
                        if (!_timeAttackInfluenceReferenceAddresses.Contains(address))
                            _timeAttackInfluenceReferenceAddresses.Add(address);
                        if (_timeAttackInfluenceReferenceAddresses.Count >= TimeAttackInfluenceMaxReferences)
                            break;
                    }
                    if (_timeAttackInfluenceReferenceAddresses.Count >= TimeAttackInfluenceMaxReferences)
                        break;
                }
                if (_timeAttackInfluenceReferenceAddresses.Count >= TimeAttackInfluenceMaxReferences)
                    break;
            }

            return timedOut || IsTimeAttackScanExpired(scanWatch);
        }

        private List<TimeAttackFloatCandidate> FindTimeAttackInfluenceFloatCandidates()
        {
            var candidates = new List<TimeAttackFloatCandidate>();
            var seen = new HashSet<ulong>();
            foreach (var anchor in _timeAttackInfluenceStringAddresses)
                AddTimeAttackFloatCandidates(anchor, 0x4000, candidates, seen);
            foreach (var anchor in _timeAttackInfluenceReferenceAddresses)
                AddTimeAttackFloatCandidates(anchor, 0x4000, candidates, seen);
            return candidates;
        }

        private void AddTimeAttackFloatCandidates(ulong anchor, int radius, List<TimeAttackFloatCandidate> candidates, HashSet<ulong> seen)
        {
            Native.MemoryBasicInformation64 mbi;
            var size = (UIntPtr)Marshal.SizeOf(typeof(Native.MemoryBasicInformation64));
            var queried = Native.VirtualQueryEx(_handle, new UIntPtr(anchor), out mbi, size);
            if (queried == UIntPtr.Zero || mbi.State != Native.MemCommit || !Native.IsReadable(mbi.Protect))
                return;

            var regionStart = mbi.BaseAddress;
            var regionEnd = mbi.BaseAddress + mbi.RegionSize;
            var start = anchor > (ulong)radius ? anchor - (ulong)radius : regionStart;
            if (start < regionStart) start = regionStart;
            var end = anchor + (ulong)radius;
            if (end > regionEnd) end = regionEnd;
            if (end <= start || end - start > 128UL * 1024UL)
                return;

            var data = ReadBytes(start, (int)(end - start));
            if (data.Length < 4)
                return;

            var first = (int)((4UL - (start & 3UL)) & 3UL);
            for (var offset = first; offset + 4 <= data.Length; offset += 4)
            {
                var value = BitConverter.ToSingle(data, offset);
                if (!IsTimeAttackBonusFloat(value))
                    continue;

                var address = start + (ulong)offset;
                if (!seen.Add(address))
                    continue;

                candidates.Add(new TimeAttackFloatCandidate
                {
                    Address = address,
                    Value = value,
                    Anchor = anchor,
                    PatchMode = Math.Abs(value - 0.2F) < 0.0005F ? TimeAttackPatchModeBonusDelta : TimeAttackPatchModeDirectMultiplier
                });
            }
        }

        private static float GetTimeAttackPatchValue(float requestedMultiplier, int patchMode)
        {
            if (patchMode == TimeAttackPatchModeBonusDelta)
                return Math.Max(0F, requestedMultiplier - 1F);
            return requestedMultiplier;
        }

        private static float GetTimeAttackDisplayMultiplier(IEnumerable<TimeAttackFloatCandidate> candidates)
        {
            var values = new List<float>();
            foreach (var candidate in candidates)
            {
                var display = candidate.PatchMode == TimeAttackPatchModeBonusDelta
                    ? candidate.Value + 1F
                    : candidate.Value;
                if (!float.IsNaN(display) && !float.IsInfinity(display) && display > 0F)
                    values.Add(display);
            }

            if (values.Count == 0)
                return 1F;
            values.Sort();
            return values[values.Count / 2];
        }

        private List<MemoryRegion> EnumerateReadableRegions()
        {
            var regions = new List<MemoryRegion>();
            var address = 0UL;
            var size = (UIntPtr)Marshal.SizeOf(typeof(Native.MemoryBasicInformation64));
            while (address < 0x00007FFFFFFFFFFFUL)
            {
                Native.MemoryBasicInformation64 mbi;
                var queried = Native.VirtualQueryEx(_handle, new UIntPtr(address), out mbi, size);
                if (queried == UIntPtr.Zero)
                    break;

                var next = mbi.BaseAddress + mbi.RegionSize;
                if (next <= address)
                    next = address + 0x1000UL;

                if (mbi.State == Native.MemCommit && Native.IsReadable(mbi.Protect) && mbi.RegionSize > 0x1000UL && mbi.RegionSize <= 128UL * 1024UL * 1024UL)
                    regions.Add(new MemoryRegion { BaseAddress = mbi.BaseAddress, RegionSize = mbi.RegionSize });

                address = next;
            }

            return regions;
        }

        private static bool IsTimeAttackBonusFloat(float value)
        {
            return Math.Abs(value - 1.2F) < 0.0005F || Math.Abs(value - 0.2F) < 0.0005F;
        }

        private static bool IsTimeAttackRuntimeBonusValue(float value)
        {
            return !float.IsNaN(value) && !float.IsInfinity(value) && value >= 0F && value <= 1000000F;
        }

        private static bool IsTimeAttackScanExpired(Stopwatch scanWatch)
        {
            return scanWatch != null && scanWatch.ElapsedMilliseconds >= TimeAttackInfluenceScanTimeoutMs;
        }

        private static bool IsTimeAttackRecordScanExpired(Stopwatch scanWatch)
        {
            return scanWatch != null && scanWatch.ElapsedMilliseconds >= TimeAttackRecordScanTimeoutMs;
        }

        private static string FormatFloatInvariant(float value)
        {
            return value.ToString("0.###", CultureInfo.InvariantCulture);
        }

        private static int XpFieldPriority(string key)
        {
            if (key.Equals("XP", StringComparison.OrdinalIgnoreCase)) return 0;
            if (key.Equals("TotalSkills", StringComparison.OrdinalIgnoreCase)) return 1;
            if (key.Equals("WristbandLevel", StringComparison.OrdinalIgnoreCase)) return 2;
            if (key.Equals("TotalXP", StringComparison.OrdinalIgnoreCase)) return 3;
            if (key.Equals("Main/TotalXP", StringComparison.OrdinalIgnoreCase)) return 4;
            if (key.Equals("Level", StringComparison.OrdinalIgnoreCase)) return 52;
            return 100;
        }

        private List<LiveProfileIntegerMatch> FindLiveProfileIntegerMatches(string[] keys, int maxCandidates)
        {
            var matches = new List<LiveProfileIntegerMatch>();
            foreach (var candidate in FindLiveProfileCandidates(maxCandidates))
            {
                var match = LocateProfileIntegerField(candidate.Data, keys, 0, int.MaxValue);
                if (match.Offset < 0)
                    continue;

                match.BaseAddress = candidate.BaseAddress;
                match.Address = candidate.BaseAddress + (ulong)match.Offset;
                match.BufferLength = candidate.Data.Length;
                matches.Add(match);
            }

            return matches;
        }

        private List<LiveProfileCandidate> FindLiveProfileCandidates(int maxCandidates)
        {
            var results = new List<LiveProfileCandidate>();
            var regions = EnumerateReadableWritableRegions();
            regions.Sort((a, b) => b.BaseAddress.CompareTo(a.BaseAddress));
            var preferredRegions = regions.Where(IsLikelyLiveProfileRegion).ToList();
            var marker = Encoding.ASCII.GetBytes("MouseControlOptions");
            var scanWatch = Stopwatch.StartNew();

            AddLiveProfileCandidatesFromRegions(results, preferredRegions, marker, scanWatch, maxCandidates);
            if (results.Count < maxCandidates)
                AddProfileHeaderCandidatesFromRegions(results, preferredRegions, scanWatch, maxCandidates);
            if (results.Count > 0)
                return results;

            AddLiveProfileCandidatesFromRegions(results, regions, marker, scanWatch, maxCandidates);
            if (results.Count < maxCandidates)
            {
                AddProfileHeaderCandidatesFromRegions(results, regions, scanWatch, maxCandidates);
            }

            return results;
        }

        private static bool IsLikelyLiveProfileRegion(MemoryRegion region)
        {
            return region.RegionSize >= 0x10000UL && region.RegionSize <= 0x1000000UL;
        }

        private void AddLiveProfileCandidatesFromRegions(List<LiveProfileCandidate> results, IEnumerable<MemoryRegion> regions, byte[] marker, Stopwatch scanWatch, int maxCandidates)
        {
            foreach (var region in regions)
            {
                if (IsXpProfileCandidateScanExpired(scanWatch))
                    break;

                foreach (var candidate in ScanRegionForLiveProfiles(region, marker, scanWatch))
                {
                    if (results.Any(c => c.BaseAddress == candidate.BaseAddress))
                        continue;
                    results.Add(candidate);
                    if (results.Count >= maxCandidates)
                        return;
                }
            }
        }

        private void AddProfileHeaderCandidatesFromRegions(List<LiveProfileCandidate> results, IEnumerable<MemoryRegion> regions, Stopwatch scanWatch, int maxCandidates)
        {
            foreach (var region in regions)
            {
                if (IsXpProfileCandidateScanExpired(scanWatch))
                    break;

                foreach (var candidate in ScanRegionForProfileHeaders(region, scanWatch))
                {
                    if (results.Any(c => c.BaseAddress == candidate.BaseAddress))
                        continue;
                    results.Add(candidate);
                    if (results.Count >= maxCandidates)
                        return;
                }
            }
        }

        private IEnumerable<LiveProfileCandidate> ScanRegionForLiveProfiles(MemoryRegion region, byte[] marker, Stopwatch scanWatch)
        {
            const int ChunkSize = 4 * 1024 * 1024;
            ulong current = region.BaseAddress;
            ulong remaining = region.RegionSize;
            var carry = new byte[0];

            while (remaining > 0)
            {
                if (IsXpProfileCandidateScanExpired(scanWatch))
                    yield break;

                var chunkSize = (int)Math.Min((ulong)ChunkSize, remaining);
                var read = ReadBytes(current, chunkSize);
                if (read.Length > 0)
                {
                    var data = new byte[carry.Length + read.Length];
                    Buffer.BlockCopy(carry, 0, data, 0, carry.Length);
                    Buffer.BlockCopy(read, 0, data, carry.Length, read.Length);
                    var dataBase = current - (ulong)carry.Length;

                    for (var at = IndexOf(data, marker, 0); at >= 0; at = IndexOf(data, marker, at + 1))
                    {
                        var profileOffset = at - 0x15;
                        if (profileOffset < 0 || profileOffset + 12 >= data.Length)
                            continue;
                        if (BitConverter.ToUInt32(data, profileOffset) != ForzaProfileHash("profile"))
                            continue;

                        var baseAddress = dataBase + (ulong)profileOffset;
                        var candidate = TryReadLiveProfileCandidate(baseAddress, BitConverter.ToUInt32(data, profileOffset + 4));
                        if (candidate == null)
                            continue;

                        yield return candidate;
                    }

                    var keep = Math.Min(0x9000, data.Length);
                    carry = new byte[keep];
                    Buffer.BlockCopy(data, data.Length - keep, carry, 0, keep);
                }

                current += (ulong)chunkSize;
                remaining -= (ulong)chunkSize;
            }
        }

        private IEnumerable<LiveProfileCandidate> ScanRegionForProfileHeaders(MemoryRegion region, Stopwatch scanWatch)
        {
            const int ChunkSize = 4 * 1024 * 1024;
            var profileHash = BitConverter.GetBytes(ForzaProfileHash("profile"));
            ulong current = region.BaseAddress;
            ulong remaining = region.RegionSize;
            var carry = new byte[0];

            while (remaining > 0)
            {
                if (IsXpProfileCandidateScanExpired(scanWatch))
                    yield break;

                var chunkSize = (int)Math.Min((ulong)ChunkSize, remaining);
                var read = ReadBytes(current, chunkSize);
                if (read.Length > 0)
                {
                    var data = new byte[carry.Length + read.Length];
                    Buffer.BlockCopy(carry, 0, data, 0, carry.Length);
                    Buffer.BlockCopy(read, 0, data, carry.Length, read.Length);
                    var dataBase = current - (ulong)carry.Length;

                    for (var at = IndexOf(data, profileHash, 0); at >= 0; at = IndexOf(data, profileHash, at + 1))
                    {
                        if (at < 0 || at + 8 > data.Length)
                            continue;

                        var profileSize = BitConverter.ToUInt32(data, at + 4);
                        var baseAddress = dataBase + (ulong)at;
                        var candidate = TryReadLiveProfileCandidate(baseAddress, profileSize);
                        if (candidate == null)
                            continue;

                        yield return candidate;
                    }

                    var keep = Math.Min(16, data.Length);
                    carry = new byte[keep];
                    Buffer.BlockCopy(data, data.Length - keep, carry, 0, keep);
                }
                else
                {
                    carry = new byte[0];
                }

                current += (ulong)chunkSize;
                remaining -= (ulong)chunkSize;
            }
        }

        private LiveProfileCandidate TryReadLiveProfileCandidate(ulong baseAddress, uint profileSize)
        {
            if (profileSize < 0x1000 || profileSize > 0x200000)
                return null;

            var totalLength = GuessLiveProfileBufferLength(baseAddress, profileSize);
            if (totalLength <= 0)
                return null;

            var full = ReadBytes(baseAddress, totalLength);
            if (full.Length != totalLength)
                return null;
            if (LocateProfileIntegerField(full, new[] { "Credits" }, 0, int.MaxValue).Offset < 0)
                return null;
            if (LocateProfileIntegerField(full, new[] { "TotalXP", "XP", "TotalSkills", "WristbandLevel" }, 0, int.MaxValue).Offset < 0)
                return null;

            return new LiveProfileCandidate { BaseAddress = baseAddress, Data = full };
        }

        private static bool IsXpProfileCandidateScanExpired(Stopwatch scanWatch)
        {
            return scanWatch != null && scanWatch.ElapsedMilliseconds >= XpProfileCandidateScanTimeoutMs;
        }

        private int GuessLiveProfileBufferLength(ulong baseAddress, uint firstSectionSize)
        {
            var initial = checked((int)Math.Min(0x400000U, firstSectionSize + 0x1000U));
            var probe = ReadBytes(baseAddress, Math.Max(initial, 0x40000));
            if (probe.Length < 8)
                return 0;

            var pos = 0;
            for (var i = 0; i < 8 && pos + 8 <= probe.Length; i++)
            {
                var hash = BitConverter.ToUInt32(probe, pos);
                var size = BitConverter.ToUInt32(probe, pos + 4);
                if (hash == 0U && size == 0U)
                    break;
                if (size > 0x300000U)
                    break;

                var next = pos + 8L + size;
                if (next > probe.Length)
                {
                    var larger = ReadBytes(baseAddress, checked((int)Math.Min(0x400000L, next + 0x1000L)));
                    if (next > larger.Length)
                        break;
                    probe = larger;
                }

                pos = checked((int)next);
            }

            return pos > 0 ? pos : checked((int)(8 + firstSectionSize));
        }

        private List<MemoryRegion> EnumerateReadableWritableRegions()
        {
            var regions = new List<MemoryRegion>();
            var address = 0UL;
            var size = (UIntPtr)Marshal.SizeOf(typeof(Native.MemoryBasicInformation64));
            while (address < 0x00007FFFFFFFFFFFUL)
            {
                Native.MemoryBasicInformation64 mbi;
                var queried = Native.VirtualQueryEx(_handle, new UIntPtr(address), out mbi, size);
                if (queried == UIntPtr.Zero)
                    break;

                var next = mbi.BaseAddress + mbi.RegionSize;
                if (next <= address)
                    next = address + 0x1000UL;

                if (mbi.State == Native.MemCommit && IsReadableWritable(mbi.Protect) && mbi.RegionSize > 0x1000UL)
                    regions.Add(new MemoryRegion { BaseAddress = mbi.BaseAddress, AllocationBase = mbi.AllocationBase, RegionSize = mbi.RegionSize });

                address = next;
            }

            return regions;
        }

        private static bool IsReadableWritable(uint protect)
        {
            if ((protect & Native.PageGuard) != 0) return false;
            if ((protect & Native.PageNoAccess) != 0) return false;
            var basic = protect & 0xFFU;
            return basic == Native.PageReadWrite || basic == Native.PageWriteCopy || basic == Native.PageExecuteReadWrite;
        }

        private const int VehicleVelocityOffset = 0x20;
        private const int VehicleAngularVelocityOffset = 0x30;
        private const int VehiclePositionOffset = 0x50;
        private const float TrafficPlayerExcludeRadius = 6.0f;
        private System.Threading.Timer _trafficFreezeTimer;
        private int _trafficFreezeRunning;
        private int _trafficFreezeScanning;
        private ulong _trafficFreezeSlot;
        private ulong _trafficFreezeVtable;
        private int _trafficFreezeScanCountdown;
        private readonly object _trafficFreezeVehiclesLock = new object();
        private List<ulong> _trafficFreezeVehicles = new List<ulong>();

        internal void SetTrafficFreezeEnabled(bool enabled)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            if (!enabled)
            {
                StopTrafficFreeze();
                _log("Freeze AI Traffic OFF. Civilian traffic moves normally again.");
                return;
            }

            var vehicleDetour = EnsureRuntimeProfileHook(GetVehicleControlDescriptor(RuntimeProfileFeature.Jump));
            var vehiclePointerSlot = vehicleDetour.DetourAddress + (ulong)GetVehicleControlLayout().VehiclePointerOffset;
            StartTrafficFreeze(vehiclePointerSlot);
            _log("Freeze AI Traffic ON. Drive your car for a second so Luna learns it, then nearby civilian traffic holds at zero speed. Your own car stays free.");
        }

        private void StartTrafficFreeze(ulong vehiclePointerSlot)
        {
            _trafficFreezeSlot = vehiclePointerSlot;
            _trafficFreezeVtable = 0;
            _trafficFreezeScanCountdown = 0;
            lock (_trafficFreezeVehiclesLock)
                _trafficFreezeVehicles = new List<ulong>();
            StopTrafficFreezeTimer();
            _trafficFreezeTimer = new System.Threading.Timer(TrafficFreezeTick, null, 80, 25);
        }

        private void StopTrafficFreeze()
        {
            StopTrafficFreezeTimer();
            _trafficFreezeVtable = 0;
            lock (_trafficFreezeVehiclesLock)
                _trafficFreezeVehicles = new List<ulong>();
        }

        private void StopTrafficFreezeTimer()
        {
            var timer = _trafficFreezeTimer;
            _trafficFreezeTimer = null;
            if (timer != null)
            {
                try { timer.Dispose(); } catch { }
            }
            Interlocked.Exchange(ref _trafficFreezeRunning, 0);
        }

        private void TrafficFreezeTick(object state)
        {
            if (!IsAlive || _trafficFreezeTimer == null)
            {
                StopTrafficFreezeTimer();
                return;
            }
            if (Interlocked.Exchange(ref _trafficFreezeRunning, 1) != 0)
                return;

            try
            {
                ulong playerVehicle = 0;
                float px = 0f, py = 0f, pz = 0f;
                bool havePlayer = false;
                ulong vtable = _trafficFreezeVtable;
                try
                {
                    ulong slotPointer = ReadUInt64(_trafficFreezeSlot);
                    if (slotPointer != 0)
                    {
                        playerVehicle = ReadUInt64(slotPointer);
                        if (playerVehicle != 0)
                        {
                            havePlayer = TryReadWorldVec3(playerVehicle + (ulong)VehiclePositionOffset, out px, out py, out pz);
                            if (vtable == 0)
                            {
                                ulong candidate = ReadUInt64(playerVehicle);
                                if (candidate > 0x10000UL && candidate < 0x00007FFFFFFFFFFFUL)
                                {
                                    vtable = candidate;
                                    _trafficFreezeVtable = candidate;
                                }
                            }
                        }
                    }
                }
                catch { }

                if (playerVehicle == 0 || vtable == 0 || !havePlayer)
                    return;

                if (_trafficFreezeScanCountdown <= 0)
                {
                    _trafficFreezeScanCountdown = 320;
                    QueueTrafficVehicleScan(vtable, playerVehicle);
                }
                _trafficFreezeScanCountdown--;

                List<ulong> vehicles;
                lock (_trafficFreezeVehiclesLock)
                    vehicles = _trafficFreezeVehicles;

                byte[] zero = new byte[16];
                for (int i = 0; i < vehicles.Count; i++)
                {
                    ulong obj = vehicles[i];
                    if (obj == playerVehicle)
                        continue;
                    ulong vt;
                    try { vt = ReadUInt64(obj); }
                    catch { vt = 0; }
                    if (vt != vtable)
                        continue;
                    float lx, ly, lz;
                    if (TryReadWorldVec3(obj + (ulong)VehiclePositionOffset, out lx, out ly, out lz) &&
                        IsWithin(lx, lz, px, pz, TrafficPlayerExcludeRadius))
                        continue;
                    try
                    {
                        if (IsWritableMemoryRange(obj + (ulong)VehicleVelocityOffset, 16))
                            WriteBytes(obj + (ulong)VehicleVelocityOffset, zero);
                        if (IsWritableMemoryRange(obj + (ulong)VehicleAngularVelocityOffset, 16))
                            WriteBytes(obj + (ulong)VehicleAngularVelocityOffset, zero);
                    }
                    catch { }
                }
            }
            catch (Exception ex)
            {
                _log("Traffic freeze warning: " + ex.Message);
            }
            finally
            {
                Interlocked.Exchange(ref _trafficFreezeRunning, 0);
            }
        }

        private void QueueTrafficVehicleScan(ulong vtable, ulong playerVehicle)
        {
            if (Interlocked.Exchange(ref _trafficFreezeScanning, 1) != 0)
                return;
            System.Threading.ThreadPool.QueueUserWorkItem(delegate
            {
                try
                {
                    ScanTrafficVehicles(vtable, playerVehicle);
                }
                catch { }
                finally
                {
                    Interlocked.Exchange(ref _trafficFreezeScanning, 0);
                }
            });
        }

        private void ScanTrafficVehicles(ulong vtable, ulong playerVehicle)
        {
            byte[] needle = BitConverter.GetBytes(vtable);
            var found = new List<ulong>();
            ulong scannedBytes = 0;
            const ulong scanBudget = 1400UL * 1024UL * 1024UL;
            const int perRegionCap = 24 * 1024 * 1024;
            foreach (var region in EnumerateReadableWritableRegions())
            {
                if (!IsAlive || _trafficFreezeTimer == null)
                    return;
                if (scannedBytes >= scanBudget || found.Count >= 4096)
                    break;
                if (region.RegionSize > 0x8000000UL)
                    continue;
                int take = (int)Math.Min(region.RegionSize, (ulong)perRegionCap);
                byte[] data = ReadBytes(region.BaseAddress, take);
                if (data == null || data.Length == 0)
                    continue;
                scannedBytes += (ulong)data.Length;
                int limit = data.Length - (VehiclePositionOffset + 12);
                for (int i = 0; i + 8 <= data.Length && i <= limit; i += 8)
                {
                    if (data[i] != needle[0] || data[i + 1] != needle[1] || data[i + 2] != needle[2] || data[i + 7] != needle[7])
                        continue;
                    bool match = true;
                    for (int b = 0; b < 8; b++)
                        if (data[i + b] != needle[b]) { match = false; break; }
                    if (!match)
                        continue;

                    ulong obj = region.BaseAddress + (ulong)i;
                    if (obj == playerVehicle)
                        continue;
                    float x = BitConverter.ToSingle(data, i + VehiclePositionOffset);
                    float y = BitConverter.ToSingle(data, i + VehiclePositionOffset + 4);
                    float z = BitConverter.ToSingle(data, i + VehiclePositionOffset + 8);
                    if (!IsWorldPosition(x, y, z))
                        continue;
                    found.Add(obj);
                    if (found.Count >= 4096)
                        break;
                }
            }
            lock (_trafficFreezeVehiclesLock)
                _trafficFreezeVehicles = found;
        }

        private bool TryReadWorldVec3(ulong address, out float x, out float y, out float z)
        {
            x = 0f; y = 0f; z = 0f;
            var data = ReadBytes(address, 12);
            if (data == null || data.Length < 12)
                return false;
            x = BitConverter.ToSingle(data, 0);
            y = BitConverter.ToSingle(data, 4);
            z = BitConverter.ToSingle(data, 8);
            return IsWorldPosition(x, y, z);
        }

        private static bool IsWorldPosition(float x, float y, float z)
        {
            if (float.IsNaN(x) || float.IsInfinity(x) || float.IsNaN(y) || float.IsInfinity(y) || float.IsNaN(z) || float.IsInfinity(z))
                return false;
            if (Math.Abs(x) > 1000000f || Math.Abs(y) > 1000000f || Math.Abs(z) > 1000000f)
                return false;
            return Math.Abs(x) >= 1f || Math.Abs(z) >= 1f;
        }

        private static bool IsWithin(float x, float z, float px, float pz, float radius)
        {
            float dx = x - px;
            float dz = z - pz;
            return (dx * dx + dz * dz) <= (radius * radius);
        }

        private static LiveProfileIntegerMatch LocateProfileIntegerField(byte[] data, string[] keys, int minValue, int maxValue)
        {
            var best = new LiveProfileIntegerMatch { Offset = -1, Score = int.MaxValue, Size = 4 };
            foreach (var match in LocateProfileIntegerFields(data, keys, minValue, maxValue))
            {
                var score = XpFieldPriority(match.Key) * 1000000 + match.Offset;
                if (score < best.Score)
                {
                    match.Score = score;
                    best = match;
                }
            }

            return best;
        }

        private static List<LiveProfileIntegerMatch> LocateProfileIntegerFields(byte[] data, string[] keys, int minValue, int maxValue)
        {
            var matches = new List<LiveProfileIntegerMatch>();
            for (var keyIndex = 0; keyIndex < keys.Length; keyIndex++)
            {
                var key = keys[keyIndex];
                if (string.IsNullOrWhiteSpace(key) || key.Length < 2)
                    continue;

                var needle = Encoding.ASCII.GetBytes(key);
                for (var at = IndexOf(data, needle, 0); at >= 0; at = IndexOf(data, needle, at + 1))
                {
                    if (at < 8 || at + needle.Length + 8 > data.Length)
                        continue;

                    var flags = BitConverter.ToUInt32(data, at - 8);
                    var nameLength = BitConverter.ToUInt32(data, at - 4);
                    if (nameLength != needle.Length || (flags != 0x20U && flags != 0x21U && flags != 0x10020U))
                        continue;

                    var type = BitConverter.ToUInt32(data, at + needle.Length);
                    var valueOffset = at + needle.Length + 4;
                    int size;
                    long value;
                    if (!TryReadProfileInteger(data, valueOffset, type, out value, out size))
                        continue;
                    if (value < minValue || value > maxValue)
                        continue;

                    matches.Add(new LiveProfileIntegerMatch
                    {
                        Offset = valueOffset,
                        Value = (int)value,
                        Key = key,
                        Score = keyIndex * 1000000 + at,
                        Size = size
                    });
                }
            }

            return matches;
        }

        private static bool TryReadProfileInteger(byte[] data, int valueOffset, uint type, out long value, out int size)
        {
            value = 0;
            size = 4;
            if (valueOffset < 0 || valueOffset + 4 > data.Length)
                return false;

            if (type == 4U)
            {
                if (valueOffset + 8 > data.Length)
                    return false;
                value = BitConverter.ToInt64(data, valueOffset);
                size = 8;
                return true;
            }

            if (type == 3U || type == 17U || type == 1U || type == 0U)
            {
                value = BitConverter.ToInt32(data, valueOffset);
                size = 4;
                return true;
            }

            return false;
        }

        private static int IndexOf(byte[] data, byte[] needle, int start)
        {
            if (needle.Length == 0 || start > data.Length - needle.Length)
                return -1;

            var first = needle[0];
            var limit = data.Length - needle.Length;
            var i = start;
            while (i <= limit)
            {
                i = Array.IndexOf(data, first, i, limit - i + 1);
                if (i < 0)
                    return -1;

                var match = true;
                for (var j = 0; j < needle.Length; j++)
                {
                    if (data[i + j] != needle[j])
                    {
                        match = false;
                        break;
                    }
                }
                if (match) return i;
                i++;
            }

            return -1;
        }

        private static uint ForzaProfileHash(string text)
        {
            uint hash = 0x1505;
            for (var pass = 0; pass < 2; pass++)
            {
                for (var i = 0; i < text.Length; i++)
                    hash ^= (uint)text[i] + (hash >> 2) + 32U * hash;
            }
            return hash;
        }

        public List<RuntimeProfileFeature> ArmProfileRuntimeValueCapture(IEnumerable<RuntimeProfileFeature> features)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            const int Sentinel = int.MinValue;
            var armed = new List<RuntimeProfileFeature>();

            foreach (var feature in features)
            {
                var featureArmed = false;
                foreach (var descriptor in GetProfileHookDescriptors(feature))
                {
                    try
                    {
                        if (descriptor.CaptureOffset < 0)
                            continue;

                        var detour = EnsureRuntimeProfileHook(descriptor);
                        WriteInt32(detour.DetourAddress + (ulong)descriptor.CaptureOffset, Sentinel);
                        featureArmed = true;
                    }
                    catch (Exception ex)
                    {
                        _log("Current " + feature + " capture could not be armed: " + ex.Message);
                    }
                }
                if (featureArmed)
                    armed.Add(feature);
            }

            if (armed.Count > 0)
                _log("Current runtime capture armed for " + armed.Count + " value(s).");
            return armed;
        }

        public Dictionary<RuntimeProfileFeature, int> ReadProfileRuntimeCaptureValues(IEnumerable<RuntimeProfileFeature> features, bool logMisses)
        {
            if (!IsAlive)
                throw new InvalidOperationException("Not attached.");

            const int Sentinel = int.MinValue;
            var captured = new Dictionary<RuntimeProfileFeature, int>();

            foreach (var feature in features)
            {
                foreach (var descriptor in GetProfileHookDescriptors(feature))
                {
                    try
                    {
                        if (descriptor.CaptureOffset < 0)
                            continue;

                        RuntimeDetour detour;
                        lock (_runtimePatchLock)
                        {
                            if (!_runtimeProfileHooks.TryGetValue(descriptor.Key, out detour))
                                continue;
                        }

                        int current;
                        if (TryReadRuntimeCaptureValue(detour, descriptor, Sentinel, out current))
                        {
                            captured[feature] = current;
                            break;
                        }
                    }
                    catch (Exception ex)
                    {
                        if (logMisses)
                            _log("Current " + feature + " capture could not be read: " + ex.Message);
                    }
                }
            }

            if (logMisses)
                _log("Current runtime capture read " + captured.Count + " value(s).");
            return captured;
        }

        private bool TryReadRuntimeCaptureValue(RuntimeDetour detour, RuntimeProfileHookDescriptor descriptor, int sentinel, out int value)
        {
            value = 0;
            var current = ReadInt32(detour.DetourAddress + (ulong)descriptor.CaptureOffset);
            if (current != sentinel)
            {
                value = current;
                return true;
            }

            if (descriptor.ObjectPointerOffset >= 0 && descriptor.ObjectValueFieldOffset >= 0)
            {
                var objectAddress = ReadUInt64(detour.DetourAddress + (ulong)descriptor.ObjectPointerOffset);
                if (objectAddress != 0)
                {
                    var valueAddress = objectAddress + (ulong)descriptor.ObjectValueFieldOffset;
                    if (IsReadableMemoryRange(valueAddress, 4))
                    {
                        value = ReadInt32(valueAddress);
                        return true;
                    }
                }
            }

            return false;
        }

        private RuntimeDetour EnsureRuntimeProfileHook(RuntimeProfileHookDescriptor descriptor)
        {
            lock (_runtimePatchLock)
            {
                RuntimeDetour existing;
                if (_runtimeProfileHooks.TryGetValue(descriptor.Key, out existing))
                    return existing;

                EnsureCrcBypass();

                var module = ReadBytes(_mainBase, _mainSize);
                if (module.Length == 0)
                    throw new InvalidOperationException("Could not read main module memory for " + descriptor.Name + " hook scan.");

                byte[] current;
                ulong hookAddress;
                FindProfileHookTarget(module, descriptor, out hookAddress, out current);

                var detour = CreateRuntimeDetour(descriptor, hookAddress);
                if (string.Equals(descriptor.Key, "ProfileIntFields", StringComparison.OrdinalIgnoreCase))
                {
                    ProfileIntegerHookLayout layout = GetProfileIntegerFieldsLayout();
                    WriteInt32(detour.DetourAddress + (ulong)layout.XpCaptureOffset, int.MinValue);
                }
                _runtimeProfileHooks.Add(descriptor.Key, detour);
                _log(descriptor.Name + " runtime detour installed. target=0x" + hookAddress.ToString("X") + ", detour=0x" + detour.DetourAddress.ToString("X"));
                return detour;
            }
        }

        private void FindProfileHookTarget(byte[] module, RuntimeProfileHookDescriptor descriptor, out ulong hookAddress, out byte[] current)
        {
            hookAddress = 0;
            current = null;

            if (!string.IsNullOrEmpty(descriptor.MetadataName))
            {
                var metadataOffset = FindAsciiOffset(module, descriptor.MetadataName + "\0");
                if (metadataOffset < 0)
                    throw new InvalidOperationException(descriptor.Name + " metadata name was not found: " + descriptor.MetadataName);

                var pointerAddress = _mainBase + (ulong)metadataOffset + (ulong)descriptor.MetadataPointerOffset;
                var candidateAddress = ReadUInt64(pointerAddress);
                if (candidateAddress == 0)
                    throw new InvalidOperationException(descriptor.Name + " metadata pointer was empty at 0x" + pointerAddress.ToString("X") + ".");

                var candidateBytes = ReadBytes(candidateAddress, descriptor.HookSize);
                if (candidateBytes.Length < descriptor.HookSize)
                    throw new InvalidOperationException(descriptor.Name + " metadata target could not be read at 0x" + candidateAddress.ToString("X") + ".");
                if (!BytesStartWith(candidateBytes, descriptor.ExpectedOriginal))
                    throw new InvalidOperationException(descriptor.Name + " metadata target bytes did not match the expected FH6 sequence. Found: " + FormatBytes(candidateBytes));

                hookAddress = candidateAddress;
                current = candidateBytes;
                return;
            }

            var parsed = Pattern.Parse(descriptor.Signature);
            var foundSignature = false;
            var foundPatchedTarget = false;
            var firstMismatch = string.Empty;

            foreach (var matchOffset in Pattern.FindAll(module, parsed, 128))
            {
                foundSignature = true;
                ulong candidateAddress;
                if (descriptor.ResolveCallTarget)
                {
                    var callAddress = _mainBase + (ulong)matchOffset;
                    var call = ReadBytes(callAddress, 5);
                    if (call.Length < 5 || call[0] != 0xE8)
                        continue;

                    var rel = BitConverter.ToInt32(call, 1);
                    candidateAddress = (ulong)((long)callAddress + 5 + rel + descriptor.CallTargetOffset);
                }
                else
                {
                    candidateAddress = _mainBase + (ulong)matchOffset + (ulong)descriptor.MatchOffset;
                }

                var candidateBytes = ReadBytes(candidateAddress, descriptor.HookSize);
                if (candidateBytes.Length < descriptor.HookSize)
                    continue;

                if (BytesStartWith(candidateBytes, descriptor.ExpectedOriginal))
                {
                    hookAddress = candidateAddress;
                    current = candidateBytes;
                    return;
                }

                if (candidateBytes.Length > 0 && candidateBytes[0] == 0xE9)
                    foundPatchedTarget = true;
                if (string.IsNullOrEmpty(firstMismatch))
                    firstMismatch = FormatBytes(candidateBytes);
            }

            if (!foundSignature)
                throw new InvalidOperationException(descriptor.Name + " hook signature was not found. Signature: " + descriptor.Signature);
            if (foundPatchedTarget)
                throw new InvalidOperationException(descriptor.Name + " hook target already appears patched by another tool.");

            throw new InvalidOperationException(descriptor.Name + " hook target bytes did not match the expected FH5/FH6 sequence. Found: " + firstMismatch);
        }

        private static readonly ProfileIntegerHookLayout ProfileIntegerFieldsLayout = BuildProfileIntegerFieldsLayout();
        private static readonly SkillPointHookLayout SkillPointFieldsLayout = BuildSkillPointHookLayout();

        private static ProfileIntegerHookLayout GetProfileIntegerFieldsLayout()
        {
            return ProfileIntegerFieldsLayout;
        }

        private static SkillPointHookLayout GetSkillPointHookLayout()
        {
            return SkillPointFieldsLayout;
        }

        private static SkillPointHookLayout BuildSkillPointHookLayout()
        {
            var code = new List<byte>();
            var labels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            var jumps = new List<ProfileAsmFixup>();
            var dataRefs = new List<ProfileAsmFixup>();
            Action<string> mark = delegate(string label) { labels[label] = code.Count; };

            EmitBytes(code, 0x50);
            EmitBytes(code, 0x8B, 0x47, 0x40);
            EmitRipStoreEax(code, dataRefs, "capture");
            EmitBytes(code, 0x58);

            EmitRipCmpByteImm(code, dataRefs, "transactionPending", 0x01);
            EmitJne(code, jumps, "constantCheck");
            EmitBytes(code, 0x83, 0xC3, 0x01);
            EmitJno(code, jumps, "transactionReady");
            EmitBytes(code, 0xBB, 0xFF, 0xFF, 0xFF, 0x7F);
            mark("transactionReady");
            EmitRipStoreByteImmediate(code, dataRefs, "transactionPending", 0x00);

            mark("constantCheck");
            EmitRipCmpByteImm(code, dataRefs, "toggle", 0x01);
            EmitJne(code, jumps, "done");
            EmitRipLoadEbx(code, dataRefs, "value");

            mark("done");
            EmitBytes(code, 0x33, 0xD2, 0x89, 0x5F, 0x40);

            var dataOffset = Align4(code.Count + 5);
            var toggleOffset = dataOffset++;
            var valueOffset = Align4(dataOffset);
            dataOffset = valueOffset + 4;
            var captureOffset = dataOffset;
            dataOffset += 4;
            var transactionPendingOffset = dataOffset++;

            var dataLabels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            {
                { "toggle", toggleOffset },
                { "value", valueOffset },
                { "capture", captureOffset },
                { "transactionPending", transactionPendingOffset }
            };

            PatchRelativeFixups(code, jumps, labels);
            PatchRelativeFixups(code, dataRefs, dataLabels);

            return new SkillPointHookLayout
            {
                Asm = code.ToArray(),
                ToggleOffset = toggleOffset,
                ValueOffset = valueOffset,
                CaptureOffset = captureOffset,
                TransactionPendingOffset = transactionPendingOffset,
                MinimumSize = dataOffset
            };
        }

        private static ProfileIntegerHookLayout BuildProfileIntegerFieldsLayout()
        {
            var code = new List<byte>();
            var labels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            var jumps = new List<ProfileAsmFixup>();
            var dataRefs = new List<ProfileAsmFixup>();

            Action<string> mark = delegate(string label) { labels[label] = code.Count; };

            EmitBytes(code, 0x48, 0x8B, 0x4F, 0x08);
            EmitBytes(code, 0x50);
            EmitBytes(code, 0x48, 0x8B, 0x54, 0x24, 0x28);

            EmitMovRaxAscii8(code, "Credits");
            EmitBytes(code, 0x48, 0x39, 0x42, 0xB4);
            EmitJne(code, jumps, "checkXpShort");
            EmitBytes(code, 0x8B, 0x07);
            EmitRipStoreEax(code, dataRefs, "creditsCapture");
            EmitRipCmpByteImm(code, dataRefs, "creditsToggle", 0x01);
            EmitJne(code, jumps, "done");
            EmitRipLoadEdx(code, dataRefs, "creditsValue");
            EmitBytes(code, 0x89, 0x17);
            EmitJmp(code, jumps, "done");

            mark("checkXpShort");
            EmitMovRaxAscii8(code, "TotalXP");
            EmitCmpRdxOffsetRax(code, 0xB4);
            EmitJne(code, jumps, "checkXpMain");
            EmitJmp(code, jumps, "xpTotalMatch");

            mark("checkXpMain");
            EmitMovRaxAscii8(code, "Main/Tot");
            EmitCmpRdxOffsetRax(code, 0xB4);
            EmitJne(code, jumps, "checkWristbandLevel");
            EmitBytes(code, 0x81, 0x7A, 0xBC, 0x61, 0x6C, 0x58, 0x50);
            EmitJne(code, jumps, "checkWristbandLevel");
            EmitJmp(code, jumps, "xpTotalMatch");

            mark("checkWristbandLevel");
            EmitMovRaxAscii8(code, "Wristban");
            EmitCmpRdxOffsetRax(code, 0xB4);
            EmitJne(code, jumps, "checkXpExact");
            EmitBytes(code, 0x81, 0x7A, 0xBC, 0x64, 0x4C, 0x65, 0x76);
            EmitJne(code, jumps, "checkXpExact");
            EmitBytes(code, 0x66, 0x81, 0x7A, 0xC0, 0x65, 0x6C);
            EmitJne(code, jumps, "checkXpExact");
            EmitBytes(code, 0x80, 0x7A, 0xC2, 0x00);
            EmitJne(code, jumps, "checkXpExact");
            EmitJmp(code, jumps, "wbMatch");

            mark("checkXpExact");
            EmitBytes(code, 0x66, 0x81, 0x7A, 0xB4, 0x58, 0x50);
            EmitJne(code, jumps, "done");
            EmitBytes(code, 0x80, 0x7A, 0xB6, 0x00);
            EmitJne(code, jumps, "done");
            EmitJmp(code, jumps, "xpTotalMatch");

            mark("xpTotalMatch");
            EmitBytes(code, 0x8B, 0x07);
            EmitRipStoreEax(code, dataRefs, "xpCapture");
            EmitRipCmpByteImm(code, dataRefs, "xpTriggerToggle", 0x01);
            EmitJne(code, jumps, "xpConstantCheck");
            EmitRipCmpByteImm(code, dataRefs, "xpTriggerPending", 0x01);
            EmitJne(code, jumps, "xpConstantCheck");
            EmitRipAddEax(code, dataRefs, "xpTriggerValue");
            EmitJno(code, jumps, "xpTriggerStore");
            EmitBytes(code, 0xB8, 0xFF, 0xFF, 0xFF, 0x7F);
            mark("xpTriggerStore");
            EmitBytes(code, 0x89, 0x07);
            EmitRipStoreEax(code, dataRefs, "xpCapture");
            EmitRipStoreByteImmediate(code, dataRefs, "xpTriggerPending", 0x00);
            EmitJmp(code, jumps, "done");

            mark("xpConstantCheck");
            EmitRipCmpByteImm(code, dataRefs, "xpToggle", 0x01);
            EmitJne(code, jumps, "done");
            EmitRipLoadEdx(code, dataRefs, "xpValue");
            EmitBytes(code, 0x89, 0x17);
            EmitJmp(code, jumps, "done");

            mark("wbMatch");
            EmitBytes(code, 0x8B, 0x07);
            EmitRipStoreEax(code, dataRefs, "wbCapture");
            EmitRipCmpByteImm(code, dataRefs, "wbToggle", 0x01);
            EmitJne(code, jumps, "done");
            EmitRipLoadEdx(code, dataRefs, "wbValue");
            EmitBytes(code, 0x89, 0x17);
            EmitJmp(code, jumps, "done");

            mark("done");
            EmitBytes(code, 0x58);
            EmitBytes(code, 0x31, 0xD2);

            var dataOffset = Align4(code.Count + 5);
            var creditsToggle = dataOffset++;
            var creditsValue = dataOffset;
            dataOffset += 4;
            var creditsCapture = dataOffset;
            dataOffset += 4;
            var xpToggle = dataOffset++;
            var xpValue = dataOffset;
            dataOffset += 4;
            var xpCapture = dataOffset;
            dataOffset += 4;
            var wbToggle = dataOffset++;
            var wbValue = dataOffset;
            dataOffset += 4;
            var wbCapture = dataOffset;
            dataOffset += 4;
            var xpTriggerToggle = dataOffset++;
            var xpTriggerValue = Align4(dataOffset);
            dataOffset = xpTriggerValue + 4;
            var xpTriggerPending = dataOffset++;

            var dataLabels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            {
                { "creditsToggle", creditsToggle },
                { "creditsValue", creditsValue },
                { "creditsCapture", creditsCapture },
                { "xpToggle", xpToggle },
                { "xpValue", xpValue },
                { "xpCapture", xpCapture },
                { "wbToggle", wbToggle },
                { "wbValue", wbValue },
                { "wbCapture", wbCapture },
                { "xpTriggerToggle", xpTriggerToggle },
                { "xpTriggerValue", xpTriggerValue },
                { "xpTriggerPending", xpTriggerPending }
            };

            PatchRelativeFixups(code, jumps, labels);
            PatchRelativeFixups(code, dataRefs, dataLabels);

            return new ProfileIntegerHookLayout
            {
                Asm = code.ToArray(),
                CreditsToggleOffset = creditsToggle,
                CreditsValueOffset = creditsValue,
                CreditsCaptureOffset = creditsCapture,
                XpToggleOffset = xpToggle,
                XpValueOffset = xpValue,
                XpCaptureOffset = xpCapture,
                WbToggleOffset = wbToggle,
                WbValueOffset = wbValue,
                WbCaptureOffset = wbCapture,
                XpTriggerToggleOffset = xpTriggerToggle,
                XpTriggerValueOffset = xpTriggerValue,
                XpTriggerPendingOffset = xpTriggerPending,
                MinimumSize = dataOffset
            };
        }

        private static void EmitBytes(List<byte> code, params byte[] bytes)
        {
            code.AddRange(bytes);
        }

        private static void EmitMovRaxAscii8(List<byte> code, string text)
        {
            var bytes = new byte[8];
            var source = Encoding.ASCII.GetBytes(text);
            Buffer.BlockCopy(source, 0, bytes, 0, Math.Min(source.Length, bytes.Length));
            code.Add(0x48);
            code.Add(0xB8);
            code.AddRange(bytes);
        }

