        private static void AddRelativeFixup(List<byte> code, List<ProfileAsmFixup> fixups, string label)
        {
            var offset = ReserveRelativeFixup(code);
            fixups.Add(new ProfileAsmFixup { Offset = offset, InstructionEnd = code.Count, Label = label });
        }

        private static int ReserveRelativeFixup(List<byte> code)
        {
            var offset = code.Count;
            code.Add(0x00);
            code.Add(0x00);
            code.Add(0x00);
            code.Add(0x00);
            return offset;
        }

        private static void PatchRelativeFixups(List<byte> code, IEnumerable<ProfileAsmFixup> fixups, Dictionary<string, int> labels)
        {
            foreach (var fixup in fixups)
            {
                int target;
                if (!labels.TryGetValue(fixup.Label, out target))
                    throw new InvalidOperationException("Missing profile hook label: " + fixup.Label);
                var rel = target - fixup.InstructionEnd;
                var bytes = BitConverter.GetBytes(rel);
                for (var i = 0; i < 4; i++)
                    code[fixup.Offset + i] = bytes[i];
            }
        }

        private static int Align4(int value)
        {
            return (value + 3) & ~3;
        }

        private static int Align8(int value)
        {
            return (value + 7) & ~7;
        }

        private static RuntimeProfileHookDescriptor GetProfileHookDescriptor(RuntimeProfileFeature feature)
        {
            var profileIntegerLayout = GetProfileIntegerFieldsLayout();
            switch (feature)
            {
                case RuntimeProfileFeature.Credits:
                    return new RuntimeProfileHookDescriptor
                    {
                        Key = "ProfileIntFields",
                        Name = "Credits",
                        Signature = "E8 ? ? ? ? 89 84 ? ? ? ? ? 4C 8D ? ? ? ? ? 48 8B",
                        ResolveCallTarget = true,
                        CallTargetOffset = 24,
                        HookSize = 6,
                        ExpectedOriginal = new byte[] { 0x48, 0x8B, 0x4F, 0x08, 0x33, 0xD2 },
                        ToggleOffset = profileIntegerLayout.CreditsToggleOffset,
                        ValueOffset = profileIntegerLayout.CreditsValueOffset,
                        CaptureOffset = profileIntegerLayout.CreditsCaptureOffset,
                        MinimumSize = profileIntegerLayout.MinimumSize,
                        Asm = profileIntegerLayout.Asm
                    };

                case RuntimeProfileFeature.FestivalWristband:
                    return new RuntimeProfileHookDescriptor
                    {
                        Key = "ProfileIntFields",
                        Name = "Festival Wristband",
                        Signature = "E8 ? ? ? ? 89 84 ? ? ? ? ? 4C 8D ? ? ? ? ? 48 8B",
                        ResolveCallTarget = true,
                        CallTargetOffset = 24,
                        HookSize = 6,
                        ExpectedOriginal = new byte[] { 0x48, 0x8B, 0x4F, 0x08, 0x33, 0xD2 },
                        ToggleOffset = profileIntegerLayout.WbToggleOffset,
                        ValueOffset = profileIntegerLayout.WbValueOffset,
                        CaptureOffset = profileIntegerLayout.WbCaptureOffset,
                        MinimumSize = profileIntegerLayout.MinimumSize,
                        Asm = profileIntegerLayout.Asm
                    };

                case RuntimeProfileFeature.Wheelspins:
                    return new RuntimeProfileHookDescriptor
                    {
                        Key = "Wheelspins",
                        Name = "Wheelspins",
                        Signature = "48 89 5C 24 08 57 48 83 EC 20 48 8B FA 33 D2 48 8B 4F 10",
                        MatchOffset = 28,
                        HookSize = 5,
                        ExpectedOriginal = new byte[] { 0x33, 0xD2, 0x8B, 0x5F, 0x08 },
                        ToggleOffset = 0x27,
                        ValueOffset = 0x28,
                        CaptureOffset = 0x2C,
                        Asm = new byte[]
                        {
