        private static RuntimeProfileHookDescriptor[] GetProfileHookDescriptors(RuntimeProfileFeature feature)
        {
            if (feature == RuntimeProfileFeature.TimeOfDay)
            {
                return new[]
                {
                    GetTimeOfDaySkyStateDescriptor(),
                    GetTimeOfDaySkyInterpolationDescriptor(),
                    GetTimeOfDaySkyReturnDescriptor(),
                    GetTimeOfDayEnvironmentBlendDescriptor(),
                    GetTimeOfDayDescriptor(),
                    GetTimeOfDaySetterDescriptor(),
                    GetTimeOfDayGetterDescriptor()
                };
            }

            if (feature == RuntimeProfileFeature.FastSlowTime)
            {
                return new[]
                {
                    GetFastSlowTimeFrameDeltaDescriptor()
                };
            }

            return new[] { GetProfileHookDescriptor(feature) };
        }

