                MatchOffset = 0,
                HookSize = 11,
                ExpectedOriginal = new byte[] { 0xF3, 0x0F, 0x5E, 0xB5, 0x88, 0x00, 0x00, 0x00, 0x0F, 0x28, 0xC6 },
