        private static byte[] BuildScalarXmmMultiplierAsm(int xmmRegister, byte[] originalBytes, out int toggleOffset, out int valueOffset, out int captureOffset, out int minimumSize)
        {
            var code = new List<byte>();
            var labels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            var jumps = new List<ProfileAsmFixup>();
            var dataRefs = new List<ProfileAsmFixup>();

            EmitRipStoreXmmByRegister(code, dataRefs, xmmRegister, "capture");
            EmitRipCmpByteImm(code, dataRefs, "toggle", 0x01);
            EmitJne(code, jumps, "done");
            EmitRipMulXmmByRegister(code, dataRefs, xmmRegister, "value");
            labels["done"] = code.Count;
            EmitBytes(code, originalBytes);

            var dataOffset = Align4(code.Count + 5);
            toggleOffset = dataOffset++;
            valueOffset = Align4(dataOffset);
            dataOffset = valueOffset + 4;
            captureOffset = dataOffset;
            dataOffset += 4;
            minimumSize = dataOffset;
            var dataLabels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            {
                { "toggle", toggleOffset },
                { "value", valueOffset },
                { "capture", captureOffset }
            };

            PatchRelativeFixups(code, jumps, labels);
            PatchRelativeFixups(code, dataRefs, dataLabels);
            return code.ToArray();
        }

