        private static GravityHookLayout BuildGravityAllAxesLayout()
        {
            var code = new List<byte>();
            var labels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            var jumps = new List<ProfileAsmFixup>();
            var dataRefs = new List<ProfileAsmFixup>();

            EmitGravityScaleBlock(code, labels, jumps, dataRefs, "scalePairA", 0x08, 0x04, 0x04, 0x08, false);
            EmitGravityScaleBlock(code, labels, jumps, dataRefs, "scalePairB", 0x10, 0x14, 0x10, 0x14, false);
            EmitGravityScaleBlock(code, labels, jumps, dataRefs, "scalePairC", 0x1C, 0x20, 0x1C, 0x20, true);
            EmitGravityScaleBlock(code, labels, jumps, dataRefs, "scalePairD", 0x28, 0x2C, 0x28, 0x2C, false);

            var dataOffset = Align4(code.Count + 5);
            var toggleOffset = dataOffset++;
            var valueOffset = dataOffset;
            dataOffset += 4;
            var captureOffset = dataOffset;
            dataOffset += 4;

            var dataLabels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase)
            {
                { "toggle", toggleOffset },
                { "value", valueOffset },
                { "capture", captureOffset }
            };

            PatchRelativeFixups(code, jumps, labels);
            PatchRelativeFixups(code, dataRefs, dataLabels);

            return new GravityHookLayout
            {
                Asm = code.ToArray(),
                ToggleOffset = toggleOffset,
                ValueOffset = valueOffset,
                CaptureOffset = captureOffset,
                MinimumSize = dataOffset
            };
        }

        private static void EmitGravityScaleBlock(List<byte> code, Dictionary<string, int> labels, List<ProfileAsmFixup> jumps, List<ProfileAsmFixup> dataRefs, string noScaleLabel, byte firstMulOffset, byte secondMulOffset, byte firstStoreOffset, byte secondStoreOffset, bool useXmm2)
        {
            if (useXmm2)
            {
                EmitBytes(code, 0xF3, 0x0F, 0x10, 0x57, 0x04);
                EmitRipCmpByteImm(code, dataRefs, "toggle", 0x01);
                EmitJne(code, jumps, noScaleLabel);
                EmitRipMulXmm2(code, dataRefs, "value");
            }
            else
            {
                EmitBytes(code, 0xF3, 0x0F, 0x10, 0x4F, 0x04);
                if (firstMulOffset == 0x08)
                    EmitRipStoreXmm1(code, dataRefs, "capture");
                EmitRipCmpByteImm(code, dataRefs, "toggle", 0x01);
                EmitJne(code, jumps, noScaleLabel);
                EmitRipMulXmm1(code, dataRefs, "value");
            }

            labels[noScaleLabel] = code.Count;

            if (useXmm2)
            {
                EmitBytes(code, 0x0F, 0x28, 0xC2);
                EmitBytes(code, 0xF3, 0x0F, 0x59, 0x53, firstMulOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x59, 0x43, secondMulOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x11, 0x53, firstStoreOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x11, 0x43, secondStoreOffset);
            }
            else
            {
                EmitBytes(code, 0x0F, 0x28, 0xC1);
                EmitBytes(code, 0xF3, 0x0F, 0x59, 0x4B, firstMulOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x59, 0x43, secondMulOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x11, 0x4B, firstStoreOffset);
                EmitBytes(code, 0xF3, 0x0F, 0x11, 0x43, secondStoreOffset);
            }
        }

