        private static VehicleControlHookLayout BuildVehicleControlLayout()
        {
            var code = new List<byte>();
            var labels = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            var jumps = new List<ProfileAsmFixup>();
            var dataRefs = new List<ProfileAsmFixup>();
            Action<string> mark = delegate(string label) { labels[label] = code.Count; };

            EmitRipStoreRdi(code, dataRefs, "vehiclePointer");

            EmitRipCmpByteImm(code, dataRefs, "teleportToggle", 0x01);
            EmitJne(code, jumps, "teleportDone");
            EmitRipLoadXmm0Vector(code, dataRefs, "teleportPosition");
            EmitBytes(code, 0x0F, 0x11, 0x47, 0x50);
            EmitBytes(code, 0x0F, 0x57, 0xC0);
            EmitBytes(code, 0x0F, 0x11, 0x47, 0x20);
            EmitRipStoreByteImm(code, dataRefs, "teleportToggle", 0x00);
            mark("teleportDone");

            EmitRipCmpByteImm(code, dataRefs, "speedToggle", 0x01);
            EmitJne(code, jumps, "speedDone");
            EmitBytes(code, 0xF3, 0x0F, 0x10, 0x47, 0x20);
            EmitRipMulXmm0(code, dataRefs, "speedValue");
            EmitBytes(code, 0xF3, 0x0F, 0x11, 0x47, 0x20);
            EmitBytes(code, 0xF3, 0x0F, 0x10, 0x47, 0x28);
            EmitRipMulXmm0(code, dataRefs, "speedValue");
            EmitBytes(code, 0xF3, 0x0F, 0x11, 0x47, 0x28);
            mark("speedDone");

            EmitRipCmpByteImm(code, dataRefs, "jumpToggle", 0x01);
            EmitJne(code, jumps, "jumpDone");
            EmitBytes(code, 0xF3, 0x0F, 0x10, 0x4F, 0x24);
            EmitRipAddXmm1(code, dataRefs, "jumpValue");
            EmitBytes(code, 0xF3, 0x0F, 0x11, 0x4F, 0x24);
            mark("jumpDone");

            EmitRipCmpByteImm(code, dataRefs, "boostToggle", 0x01);
            EmitJne(code, jumps, "boostDone");
            EmitBytes(code, 0xF3, 0x0F, 0x10, 0x47, 0x20);
            EmitRipMulXmm0(code, dataRefs, "boostValue");
            EmitBytes(code, 0xF3, 0x0F, 0x11, 0x47, 0x20);
