            mark("bounceCushionDone");

            EmitRipCmpByteImm(code, dataRefs, "momentumToggle", 0x01);
            EmitJne(code, jumps, "momentumDone");
            EmitBytes(code, 0xF3, 0x0F, 0x10, 0x47, 0x20);
            EmitRipMulXmm0(code, dataRefs, "momentumValue");
