        {
            if (_handle != IntPtr.Zero)
            {
                StopXpGainTrigger();
                StopTimeOfDayHold();
                RestoreTimeOfDayClockScale();
                StopAccelerationGuard();
                StopSuperBrakeGuard();
                StopJumpGuard();
                StopBoostGuard();
                StopAirBrakeGuard();
                StopForwardLaunchGuard();
                StopDriftModeGuard();
