                StopNoClipGuard();
                StopPhaseDashGuard();
                StopRewindGuard();
                StopGrapplingHookGuard();
                StopChargeJumpRuntime();
                StopWallClimberRuntime();
                StopSuperStrengthGuard();
                StopRolePlayGasRuntime();
                StopTimerScaleGuardTimer();
                StopTrailblazerTimerGuard();
                StopTrafficGuard();
                StopTrafficFreeze();
                StopPhotoModeControls();
                StopCameraEffectHold();
                RestoreValueEncryptionBypass();
                StopCrcTimer();
                RestoreRuntimeProfileHooks();
                RestoreFovTablePatches();
                RestorePhotoModeHookPatches();
                RestoreTimeAttackInfluencePatches();
                RestoreBestWheelspinOddsPatches();
                RestoreCrcPointer();
                Native.CloseHandle(_handle);
                _handle = IntPtr.Zero;
            }
        }

