        private sealed class TeleportRawWaypointCluster
        {
            public int Count;
            public int MarkerCopies;
            public double SumX;
            public double SumY;
            public double SumZ;
            public double SumX2;
            public double SumZ2;

            public void Add(float x, float y, float z)
            {
                Add(x, y, z, false);
            }

            public void Add(float x, float y, float z, bool markerCopy)
            {
                Count++;
                if (markerCopy)
                    MarkerCopies++;
                SumX += x;
                SumY += y;
                SumZ += z;
                SumX2 += (double)x * x;
                SumZ2 += (double)z * z;
            }

            public bool TryGetAveragePosition(out byte[] position)
            {
                position = null;
                if (Count <= 0)
                    return false;

                var x = (float)(SumX / Count);
                var y = (float)(SumY / Count);
                var z = (float)(SumZ / Count);
                position = new byte[16];
                Buffer.BlockCopy(BitConverter.GetBytes(x), 0, position, 0, 4);
                Buffer.BlockCopy(BitConverter.GetBytes(y), 0, position, 4, 4);
                Buffer.BlockCopy(BitConverter.GetBytes(z), 0, position, 8, 4);
                return true;
            }

            public double HorizontalVariance()
            {
                if (Count <= 0)
                    return double.MaxValue;

                var meanX = SumX / Count;
                var meanZ = SumZ / Count;
                var varianceX = SumX2 / Count - meanX * meanX;
                var varianceZ = SumZ2 / Count - meanZ * meanZ;
                if (varianceX < 0.0)
                    varianceX = 0.0;
                if (varianceZ < 0.0)
                    varianceZ = 0.0;
                return varianceX + varianceZ;
            }
        }

