        {
            DoubleBuffered = true;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
            _animationClock = Stopwatch.StartNew();
            _animationTimer = new System.Windows.Forms.Timer();
            _animationTimer.Interval = 15;
            _animationTimer.Tick += delegate
            {
                if (Visible)
                    Invalidate();
            };
            _animationTimer.Start();
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
                _animationTimer.Dispose();
            base.Dispose(disposing);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.InterpolationMode = InterpolationMode.HighQualityBicubic;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            e.Graphics.TextRenderingHint = System.Drawing.Text.TextRenderingHint.ClearTypeGridFit;

            var outer = new Rectangle(0, 0, Math.Max(1, Width - 1), Math.Max(1, Height - 1));
            using (var card = RoundedRectangle(outer, 12))
            using (var fill = new SolidBrush(Color.FromArgb(25, 31, 42)))
            using (var border = new Pen(Color.FromArgb(70, 82, 104)))
            {
                e.Graphics.FillPath(fill, card);
                e.Graphics.DrawPath(border, card);
            }

            var imageRect = new Rectangle(2, 2, Math.Max(1, Width - 4), Math.Max(1, Height - 4));
            using (var clip = RoundedRectangle(imageRect, 11))
            {
                var state = e.Graphics.Save();
                e.Graphics.SetClip(clip);
                if (Banner != null)
                    DrawCover(e.Graphics, Banner, imageRect);
                else
                    DrawFallback(e.Graphics, imageRect);

                using (var leftShade = new LinearGradientBrush(imageRect, Color.FromArgb(142, 4, 8, 15), Color.FromArgb(10, 4, 8, 15), LinearGradientMode.Horizontal))
                    e.Graphics.FillRectangle(leftShade, imageRect);
                using (var bottomShade = new LinearGradientBrush(imageRect, Color.FromArgb(0, 0, 0, 0), Color.FromArgb(90, 0, 0, 0), LinearGradientMode.Vertical))
                    e.Graphics.FillRectangle(bottomShade, imageRect);

                DrawOverlayText(e.Graphics, imageRect);
                e.Graphics.Restore(state);
            }
        }

        private void DrawOverlayText(Graphics graphics, Rectangle bounds)
        {
            var textWidth = Math.Max(280, Math.Min(540, (int)(bounds.Width * 0.42F)));
            var titleHeight = Math.Max(38, Math.Min(56, bounds.Height / 3));
            var subtitleHeight = 24;
            var x = bounds.X + Math.Max(28, (int)(bounds.Width * 0.055F));
            var y = bounds.Y + Math.Max(22, (bounds.Height - titleHeight - subtitleHeight) / 2);
            var titleRect = new Rectangle(x - 4, y, textWidth, titleHeight);
            var subtitleRect = new Rectangle(x + 6, titleRect.Bottom - 1, textWidth, subtitleHeight);

            using (var titleFont = new Font("Segoe UI Semibold", Math.Max(24F, Math.Min(34F, bounds.Height * 0.185F)), FontStyle.Bold, GraphicsUnit.Pixel))
            using (var subtitleFont = new Font("Segoe UI Semibold", Math.Max(13F, Math.Min(17F, bounds.Height * 0.08F)), FontStyle.Regular, GraphicsUnit.Pixel))
            using (var titlePath = new GraphicsPath())
            using (var subtitleBrush = new SolidBrush(Color.FromArgb(238, 255, 255, 255)))
            using (var shadowBrush = new SolidBrush(Color.FromArgb(150, 0, 0, 0)))
            using (var stringFormat = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center, Trimming = StringTrimming.EllipsisCharacter })
            {
                titlePath.AddString(
                    "Welcome to Luna",
                    titleFont.FontFamily,
                    (int)titleFont.Style,
                    titleFont.Size,
                    titleRect,
                    stringFormat);

                using (var matrix = new Matrix())
                {
                    matrix.Translate(2F, 2F);
                    using (var shadowPath = (GraphicsPath)titlePath.Clone())
                    {
                        shadowPath.Transform(matrix);
                        graphics.FillPath(shadowBrush, shadowPath);
                    }
                }

                var phase = (float)((_animationClock.Elapsed.TotalSeconds / 11.5D) % 1D);
                var gradientPeriod = Math.Max(2F, bounds.Width * 0.55F);
                var gradientRect = new RectangleF(titleRect.X, titleRect.Y, gradientPeriod, Math.Max(1, titleRect.Height));
                var colors = new[]
                {
                    Color.FromArgb(34, 211, 238),
                    Color.FromArgb(59, 130, 246),
                    Color.FromArgb(168, 85, 247),
                    Color.FromArgb(236, 72, 153),
                    Color.FromArgb(34, 211, 238)
                };
                using (var gradient = new LinearGradientBrush(gradientRect, colors[0], colors[colors.Length - 1], LinearGradientMode.Horizontal))
                {
                    gradient.GammaCorrection = true;
                    gradient.WrapMode = WrapMode.Tile;
                    gradient.InterpolationColors = new ColorBlend
                    {
                        Colors = colors,
                        Positions = new[] { 0F, 0.24F, 0.5F, 0.76F, 1F }
                    };
                    gradient.TranslateTransform(-gradientPeriod * phase, 0F);
                    graphics.FillPath(gradient, titlePath);
                }

                var shadowRect = subtitleRect;
                shadowRect.Offset(1, 1);
                graphics.DrawString("Unleash the Horizon.", subtitleFont, shadowBrush, shadowRect, stringFormat);
                graphics.DrawString("Unleash the Horizon.", subtitleFont, subtitleBrush, subtitleRect, stringFormat);
            }
        }

        private static void DrawCover(Graphics graphics, Image image, Rectangle target)
        {
            var scale = Math.Max(target.Width / (float)Math.Max(1, image.Width), target.Height / (float)Math.Max(1, image.Height));
            var width = image.Width * scale;
            var height = image.Height * scale;
            var x = target.X + (target.Width - width) / 2F;
            var topOverflow = Math.Max(0F, (height - target.Height) / 2F);
            var down = Math.Min(height * 0.105F, topOverflow);
            var y = target.Y + (target.Height - height) / 2F + down;
            graphics.DrawImage(image, x, y, width, height);
        }

        private static void DrawFallback(Graphics graphics, Rectangle target)
        {
            using (var fill = new LinearGradientBrush(target, Color.FromArgb(0, 222, 255), Color.FromArgb(255, 83, 157), LinearGradientMode.Horizontal))
            using (var font = new Font("Bahnschrift SemiBold Condensed", 42F, FontStyle.Bold, GraphicsUnit.Pixel))
            using (var format = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center })
                graphics.DrawString("LUNA", font, fill, target, format);
        }

        private static Image LoadBanner()
        {
            try
            {
                using (var stream = typeof(Program).Assembly.GetManifestResourceStream("luna-banner.jpeg"))
                {
                    if (stream == null)
                        return null;
                    using (var image = Image.FromStream(stream))
                        return new Bitmap(image);
                }
            }
            catch
            {
                return null;
            }
        }

        private static GraphicsPath RoundedRectangle(Rectangle bounds, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(bounds.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = bounds.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = bounds.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = bounds.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

