    internal sealed class HubUpdateCallout : Control
    {
        private readonly Action<string> _openUrl;
        private readonly System.Windows.Forms.Timer _animationTimer;
        private readonly Stopwatch _animationClock;
        private LunaUpdateInfo _info;

        public HubUpdateCallout(Action<string> openUrl)
        {
            _openUrl = openUrl;
            DoubleBuffered = true;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
            _animationClock = Stopwatch.StartNew();
            _animationTimer = new System.Windows.Forms.Timer();
            _animationTimer.Interval = 18;
            _animationTimer.Tick += delegate
            {
                if (Visible)
                    Invalidate();
            };
            _animationTimer.Start();
            Cursor = Cursors.Default;
        }

        public void SetUpdate(LunaUpdateInfo info)
        {
            _info = info;
            Cursor = info != null && !string.IsNullOrWhiteSpace(info.DownloadUrl) ? Cursors.Hand : Cursors.Default;
            Invalidate();
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
                _animationTimer.Dispose();
            base.Dispose(disposing);
        }

        protected override void OnClick(EventArgs e)
        {
            base.OnClick(e);
            if (_info != null && !string.IsNullOrWhiteSpace(_info.DownloadUrl) && _openUrl != null)
                _openUrl(_info.DownloadUrl);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var parentBack = Parent != null ? Parent.BackColor : Color.FromArgb(9, 9, 11);
            var lightMode = ((parentBack.R * 299) + (parentBack.G * 587) + (parentBack.B * 114)) > 150000;
            e.Graphics.Clear(parentBack);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            e.Graphics.TextRenderingHint = System.Drawing.Text.TextRenderingHint.ClearTypeGridFit;

            if (_info == null)
                return;

            var bounds = new Rectangle(0, 0, Math.Max(1, Width - 1), Math.Max(1, Height - 1));
            using (var path = RoundedRectangle(bounds, 16))
            using (var fill = new LinearGradientBrush(bounds, Color.FromArgb(30, 24, 24, 27), Color.FromArgb(38, 16, 25, 39), LinearGradientMode.Horizontal))
            using (var border = new Pen(Color.FromArgb(82, 93, 118), 1.1F))
            {
                e.Graphics.FillPath(fill, path);
                e.Graphics.DrawPath(border, path);
            }

            var title = string.IsNullOrWhiteSpace(_info.Title) ? "New Update Available" : _info.Title.Trim();
            var message = string.IsNullOrWhiteSpace(_info.Message) ? "A new Luna build is available." : _info.Message.Trim();
            var hasLink = !string.IsNullOrWhiteSpace(_info.DownloadUrl);

            var textArea = bounds;
            textArea.Inflate(-28, -12);
            if (hasLink)
                textArea.Width -= 74;

            var titleRect = new Rectangle(textArea.X, textArea.Y + 2, textArea.Width, 34);
            var messageRect = new Rectangle(textArea.X, titleRect.Bottom + 3, textArea.Width, Math.Max(24, textArea.Bottom - titleRect.Bottom - 4));

            using (var titleFont = new Font("Segoe UI Semibold", 22F, FontStyle.Bold, GraphicsUnit.Pixel))
            using (var messageFont = new Font("Segoe UI Semibold", 12.5F, FontStyle.Regular, GraphicsUnit.Pixel))
            using (var textFormat = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center, Trimming = StringTrimming.EllipsisCharacter })
            using (var titlePath = new GraphicsPath())
            using (var shadow = new SolidBrush(Color.FromArgb(lightMode ? 60 : 132, 0, 0, 0)))
            using (var messageBrush = new SolidBrush(lightMode ? Color.FromArgb(235, 60, 66, 78) : Color.FromArgb(222, 226, 232, 244)))
            {
                titlePath.AddString(title, titleFont.FontFamily, (int)titleFont.Style, titleFont.Size, titleRect, textFormat);
                using (var shadowPath = (GraphicsPath)titlePath.Clone())
                using (var matrix = new Matrix())
                {
                    matrix.Translate(1.5F, 1.5F);
                    shadowPath.Transform(matrix);
                    e.Graphics.FillPath(shadow, shadowPath);
                }

                var phase = (float)((_animationClock.Elapsed.TotalSeconds / 7.5D) % 1D);
                var gradientPeriod = Math.Max(240F, Width * 0.48F);
                var gradientRect = new RectangleF(titleRect.X, titleRect.Y, gradientPeriod, Math.Max(1, titleRect.Height));
                var colors = new[]
                {
                    Color.FromArgb(34, 211, 238),
                    Color.FromArgb(96, 165, 250),
                    Color.FromArgb(168, 85, 247),
                    Color.FromArgb(244, 114, 182),
                    Color.FromArgb(34, 211, 238)
                };
                using (var gradient = new LinearGradientBrush(gradientRect, colors[0], colors[colors.Length - 1], LinearGradientMode.Horizontal))
                {
                    gradient.GammaCorrection = true;
                    gradient.WrapMode = WrapMode.Tile;
                    gradient.InterpolationColors = new ColorBlend
                    {
                        Colors = colors,
                        Positions = new[] { 0F, 0.24F, 0.5F, 0.76F, 1F }
                    };
                    gradient.TranslateTransform(-gradientPeriod * phase, 0F);
                    e.Graphics.FillPath(gradient, titlePath);
                }

                e.Graphics.DrawString(message, messageFont, messageBrush, messageRect, textFormat);
            }

            if (hasLink)
            {
                const int linkSize = 40;
                var linkRect = new Rectangle(bounds.Right - 26 - linkSize, bounds.Y + ((bounds.Height - linkSize) / 2), linkSize, linkSize);
                using (var pill = RoundedRectangle(linkRect, 11))
                using (var fill = new LinearGradientBrush(linkRect, Color.FromArgb(59, 130, 246), Color.FromArgb(34, 211, 238), LinearGradientMode.Horizontal))
                using (var linkFont = new Font("Segoe UI Symbol", 17F, FontStyle.Bold, GraphicsUnit.Pixel))
                using (var linkBrush = new SolidBrush(Color.White))
                using (var linkFormat = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center })
                {
                    e.Graphics.FillPath(fill, pill);
                    e.Graphics.DrawString("\u2197", linkFont, linkBrush, linkRect, linkFormat);
                }
            }
        }

        private static GraphicsPath RoundedRectangle(Rectangle bounds, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(bounds.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = bounds.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = bounds.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = bounds.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

