    internal sealed class LunaWordmark : Control
    {
        public LunaWordmark()
        {
            DoubleBuffered = true;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            using (var textPath = CreateTextPath())
            {
                using (var shadowPath = (GraphicsPath)textPath.Clone())
                using (var shadowMove = new Matrix())
                using (var shadow = new SolidBrush(Color.FromArgb(120, 0, 0, 0)))
                {
                    shadowMove.Translate(1.5F, 2F);
                    shadowPath.Transform(shadowMove);
                    e.Graphics.FillPath(shadow, shadowPath);
                }

                using (var fill = new SolidBrush(Color.FromArgb(0, 222, 255)))
                using (var edge = new Pen(Color.FromArgb(90, 255, 255, 255), 1F))
                {
                    e.Graphics.FillPath(fill, textPath);
                    e.Graphics.DrawPath(edge, textPath);
                }
            }
        }

        private GraphicsPath CreateTextPath()
        {
            var path = new GraphicsPath();
            using (var font = new Font("Bahnschrift SemiBold Condensed", 42F, FontStyle.Bold, GraphicsUnit.Pixel))
            using (var format = (StringFormat)StringFormat.GenericTypographic.Clone())
            {
                format.Alignment = StringAlignment.Near;
                format.LineAlignment = StringAlignment.Near;
                path.AddString("LUNA", font.FontFamily, (int)FontStyle.Bold, font.Size, Point.Empty, format);
            }

            var bounds = path.GetBounds();
            var maxWidth = Math.Max(1F, Width - 18F);
            var maxHeight = Math.Max(1F, Height - 18F);
            var scale = Math.Min(maxWidth / Math.Max(1F, bounds.Width), maxHeight / Math.Max(1F, bounds.Height));
            var scaledWidth = bounds.Width * scale;
            var scaledHeight = bounds.Height * scale;
            var x = (Width - scaledWidth) / 2F;
            var y = (Height - scaledHeight) / 2F - 1F;

            using (var transform = new Matrix())
            {
                transform.Translate(-bounds.X, -bounds.Y);
                transform.Scale(scale, scale, MatrixOrder.Append);
                transform.Translate(x, y, MatrixOrder.Append);
                path.Transform(transform);
            }

            return path;
        }
    }

    internal static class ThemePaint
    {
        public static Color Lighten(Color color, float amount)
        {
            return Mix(color, Color.White, amount);
        }

        public static Color Darken(Color color, float amount)
        {
            return Mix(color, Color.Black, amount);
        }

        public static Color Mix(Color baseColor, Color target, float amount)
        {
            if (amount <= 0F)
                return baseColor;
            if (amount >= 1F)
                return Color.FromArgb(baseColor.A, target.R, target.G, target.B);

            var r = (int)Math.Round(baseColor.R + (target.R - baseColor.R) * amount);
            var g = (int)Math.Round(baseColor.G + (target.G - baseColor.G) * amount);
            var b = (int)Math.Round(baseColor.B + (target.B - baseColor.B) * amount);
            return Color.FromArgb(baseColor.A, Clamp(r), Clamp(g), Clamp(b));
        }

        private static int Clamp(int value)
        {
            if (value < 0)
                return 0;
            return value > 255 ? 255 : value;
        }
    }

