    internal sealed class LunaDialogCloseButton : Control
    {
        private bool _hovered;
        private bool _pressed;

        public Color FillColor { get; set; }
        public Color HoverColor { get; set; }
        public Color PressedColor { get; set; }
        public Color GlyphColor { get; set; }

        public LunaDialogCloseButton()
        {
            FillColor = Color.FromArgb(239, 68, 68);
            HoverColor = Color.FromArgb(200, 42, 42);
            PressedColor = Color.FromArgb(170, 32, 32);
            GlyphColor = Color.White;
            Cursor = Cursors.Hand;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            _pressed = false;
            Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                _pressed = true;
                Invalidate();
            }
            base.OnMouseDown(e);
        }

        protected override void OnMouseUp(MouseEventArgs e)
        {
            _pressed = false;
            Invalidate();
            base.OnMouseUp(e);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent == null ? BackColor : Parent.BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            var color = _pressed ? PressedColor : _hovered ? HoverColor : FillColor;
            var rect = new Rectangle(0, 0, Math.Max(1, Width - 1), Math.Max(1, Height - 1));
            using (var path = CreateRoundPath(rect, 8))
            using (var fill = new SolidBrush(color))
            using (var pen = new Pen(GlyphColor, 2F))
            {
                e.Graphics.FillPath(fill, path);
                var inset = Math.Max(9, Math.Min(Width, Height) / 3);
                e.Graphics.DrawLine(pen, inset, inset, Width - inset - 1, Height - inset - 1);
                e.Graphics.DrawLine(pen, Width - inset - 1, inset, inset, Height - inset - 1);
            }
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(2, radius * 2);
            var arc = new Rectangle(rect.Left, rect.Top, diameter, diameter);
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class PageInfoIcon : Control
    {
        private Color _glyphColor;

        public Color GlyphColor
        {
            get { return _glyphColor; }
            set
            {
                _glyphColor = value;
                Invalidate();
            }
        }

        public PageInfoIcon()
        {
            _glyphColor = Color.FromArgb(161, 161, 170);
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent == null ? BackColor : Parent.BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            var size = Math.Min(18, Math.Min(Width - 4, Height - 4));
            var left = (Width - size) / 2;
            var top = (Height - size) / 2;
            var rect = new Rectangle(left, top, size, size);

            using (var pen = new Pen(_glyphColor, 1.6F))
            using (var brush = new SolidBrush(_glyphColor))
            {
                e.Graphics.DrawEllipse(pen, rect);
                var centerX = rect.Left + (rect.Width / 2F);
                e.Graphics.FillEllipse(brush, centerX - 1.25F, rect.Top + 4F, 2.5F, 2.5F);
                e.Graphics.DrawLine(pen, centerX, rect.Top + 8.5F, centerX, rect.Bottom - 4F);
            }
        }
    }

    internal sealed class ModernPanel : Panel
    {
        private Color _fillColor;
        private Color _borderColor;
        private int _cornerRadius;

        public Color FillColor
        {
            get { return _fillColor; }
            set
            {
                _fillColor = value;
                BackColor = value;
                Invalidate();
            }
        }

        public Color BorderColor
        {
            get { return _borderColor; }
            set
            {
                _borderColor = value;
                Invalidate();
            }
        }

        public int CornerRadius
        {
            get { return _cornerRadius; }
            set
            {
                _cornerRadius = Math.Max(0, value);
                UpdateRegion();
                Invalidate();
            }
        }
        public float BorderWidth { get; set; }
        public bool UseGradientFill { get; set; }

        public ModernPanel()
        {
            _fillColor = Color.FromArgb(25, 31, 42);
            _borderColor = Color.FromArgb(48, 57, 73);
            BackColor = _fillColor;
            _cornerRadius = 14;
            BorderWidth = 1F;
            UseGradientFill = false;
            DoubleBuffered = true;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
        }

        protected override void OnSizeChanged(EventArgs e)
        {
            base.OnSizeChanged(e);
            UpdateRegion();
        }

        protected override void OnBackColorChanged(EventArgs e)
        {
            base.OnBackColorChanged(e);
            Invalidate();
        }

        private void UpdateRegion()
        {
            if (Width <= 0 || Height <= 0)
                return;

            var rect = new Rectangle(0, 0, Math.Max(1, Width - 1), Math.Max(1, Height - 1));
            using (var path = CreateRoundPath(rect, CornerRadius))
            {
                Region = new Region(path);
            }
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            var rect = new Rectangle(1, 1, Math.Max(1, Width - 3), Math.Max(1, Height - 3));
            using (var path = CreateRoundPath(rect, CornerRadius))
            using (var border = new Pen(_borderColor, Math.Max(1F, BorderWidth)))
            {
                border.Alignment = PenAlignment.Inset;
                if (UseGradientFill)
                {
                    using (var fill = new LinearGradientBrush(
                        rect,
                        ThemePaint.Lighten(_fillColor, 0.035F),
                        ThemePaint.Darken(_fillColor, 0.025F),
                        LinearGradientMode.Vertical))
                        e.Graphics.FillPath(fill, path);
                }
                else
                {
                    using (var fill = new SolidBrush(_fillColor))
                        e.Graphics.FillPath(fill, path);
                }
                e.Graphics.DrawPath(border, path);
            }
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(1, radius * 2);
            radius = Math.Min(radius, Math.Min(rect.Width, rect.Height) / 2);
            diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(rect.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class ModernGridScrollBar : Control
    {
        private readonly DataGridView _grid;
        private bool _dragging;
        private bool _hovered;
        private int _dragOffset;

        public Color TrackColor { get; set; }
        public Color ThumbColor { get; set; }
        public Color HoverColor { get; set; }

        public ModernGridScrollBar(DataGridView grid)
        {
            _grid = grid;
            TrackColor = Color.FromArgb(45, 45, 52);
            ThumbColor = Color.FromArgb(90, 104, 132);
            HoverColor = Color.FromArgb(82, 158, 246);
            Cursor = Cursors.Hand;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;

            if (_grid != null)
            {
                _grid.Scroll += delegate { RefreshMetrics(); };
                _grid.RowsAdded += delegate { RefreshMetrics(); };
                _grid.RowsRemoved += delegate { RefreshMetrics(); };
                _grid.SizeChanged += delegate { RefreshMetrics(); };
                _grid.ColumnHeadersHeightChanged += delegate { RefreshMetrics(); };
                _grid.DataBindingComplete += delegate { RefreshMetrics(); };
            }
        }

        public void RefreshMetrics()
        {
            if (_grid == null || _grid.IsDisposed)
                return;

            var top = Math.Max(3, _grid.ColumnHeadersHeight + 5);
            SetBounds(
                Math.Max(0, _grid.ClientSize.Width - Width - 4),
                top,
                Width,
                Math.Max(20, _grid.ClientSize.Height - top - 5));
            var visibleRows = GetVisibleRowCount();
            Visible = _grid.RowCount > visibleRows && visibleRows > 0;
            Invalidate();
            BringToFront();
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            if (!_dragging)
                Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                var thumb = GetThumbRectangle();
                if (thumb.Contains(e.Location))
                    _dragOffset = e.Y - thumb.Top;
                else
                {
                    _dragOffset = thumb.Height / 2;
                    SetScrollFromThumbTop(e.Y - _dragOffset);
                }
                _dragging = true;
                Capture = true;
                Invalidate();
            }
            base.OnMouseDown(e);
        }

        protected override void OnMouseMove(MouseEventArgs e)
        {
            if (_dragging)
                SetScrollFromThumbTop(e.Y - _dragOffset);
            base.OnMouseMove(e);
        }

        protected override void OnMouseUp(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                _dragging = false;
                Capture = false;
                Invalidate();
            }
            base.OnMouseUp(e);
        }

        protected override void OnMouseWheel(MouseEventArgs e)
        {
            if (_grid != null && _grid.RowCount > 0)
            {
                var visibleRows = GetVisibleRowCount();
                var maxFirst = Math.Max(0, _grid.RowCount - visibleRows);
                var first = GetFirstDisplayedRow();
                var step = Math.Max(1, Math.Min(4, Math.Abs(e.Delta) / 120 * 3));
                var target = e.Delta > 0
                    ? Math.Max(0, first - step)
                    : Math.Min(maxFirst, first + step);
                try
                {
                    _grid.FirstDisplayedScrollingRowIndex = target;
                }
                catch
                {
                }
                RefreshMetrics();
            }
            base.OnMouseWheel(e);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent == null ? BackColor : Parent.BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            var trackRect = new Rectangle(3, 2, Math.Max(3, Width - 6), Math.Max(4, Height - 4));
            using (var trackPath = CreateRoundPath(trackRect, trackRect.Width / 2))
            using (var track = new SolidBrush(TrackColor))
                e.Graphics.FillPath(track, trackPath);

            var thumbRect = GetThumbRectangle();
            var color = _dragging || _hovered ? HoverColor : ThumbColor;
            using (var thumbPath = CreateRoundPath(thumbRect, thumbRect.Width / 2))
            using (var thumb = new SolidBrush(color))
                e.Graphics.FillPath(thumb, thumbPath);
        }

        private Rectangle GetThumbRectangle()
        {
            var trackTop = 3;
            var trackHeight = Math.Max(1, Height - 6);
            var visibleRows = GetVisibleRowCount();
            var totalRows = Math.Max(1, _grid == null ? 1 : _grid.RowCount);
            var thumbHeight = Math.Max(30, (int)Math.Round(trackHeight * Math.Min(1D, visibleRows / (double)totalRows)));
            thumbHeight = Math.Min(trackHeight, thumbHeight);
            var maxFirst = Math.Max(0, totalRows - visibleRows);
            var first = GetFirstDisplayedRow();
            var travel = Math.Max(0, trackHeight - thumbHeight);
            var top = trackTop + (maxFirst == 0 ? 0 : (int)Math.Round(travel * (first / (double)maxFirst)));
            return new Rectangle(2, top, Math.Max(4, Width - 4), thumbHeight);
        }

        private int GetVisibleRowCount()
        {
            if (_grid == null || _grid.RowCount == 0)
                return 0;
            try
            {
                return Math.Max(1, _grid.DisplayedRowCount(false));
            }
            catch
            {
                return Math.Max(1, _grid.ClientSize.Height / Math.Max(1, _grid.RowTemplate.Height));
            }
        }

        private int GetFirstDisplayedRow()
        {
            if (_grid == null || _grid.RowCount == 0)
                return 0;
            try
            {
                return Math.Max(0, _grid.FirstDisplayedScrollingRowIndex);
            }
            catch
            {
                return 0;
            }
        }

        private void SetScrollFromThumbTop(int thumbTop)
        {
            if (_grid == null || _grid.RowCount == 0)
                return;

            var visibleRows = GetVisibleRowCount();
            var maxFirst = Math.Max(0, _grid.RowCount - visibleRows);
            if (maxFirst == 0)
                return;

            var thumb = GetThumbRectangle();
            var trackTop = 3;
            var travel = Math.Max(1, Height - 6 - thumb.Height);
            var ratio = Math.Max(0D, Math.Min(1D, (thumbTop - trackTop) / (double)travel));
            var target = Math.Max(0, Math.Min(maxFirst, (int)Math.Round(maxFirst * ratio)));
            try
            {
                _grid.FirstDisplayedScrollingRowIndex = target;
            }
            catch
            {
            }
            Invalidate();
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            radius = Math.Max(1, Math.Min(radius, Math.Min(rect.Width, rect.Height) / 2));
            var diameter = radius * 2;
            var arc = new Rectangle(rect.Left, rect.Top, diameter, diameter);
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class AnimatedGradientLabel : Label
    {
        private readonly System.Windows.Forms.Timer _animationTimer;
        private readonly Stopwatch _animationClock;

        public AnimatedGradientLabel()
        {
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
            _animationClock = Stopwatch.StartNew();
            _animationTimer = new System.Windows.Forms.Timer();
            _animationTimer.Interval = 15;
            _animationTimer.Tick += delegate
            {
                if (Visible)
                    Invalidate();
            };
            _animationTimer.Start();
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
                _animationTimer.Dispose();
            base.Dispose(disposing);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent == null ? BackColor : Parent.BackColor;
            e.Graphics.Clear(background);
            if (string.IsNullOrEmpty(Text) || Width <= 0 || Height <= 0)
                return;

            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.CompositingQuality = CompositingQuality.HighQuality;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            e.Graphics.TextRenderingHint = System.Drawing.Text.TextRenderingHint.AntiAliasGridFit;
            using (var path = new GraphicsPath())
            using (var format = CreateStringFormat())
            {
                var emSize = e.Graphics.DpiY * Font.Size / 72F;
                path.AddString(
                    Text,
                    Font.FontFamily,
                    (int)Font.Style,
                    emSize,
                    new RectangleF(0, 0, Width, Height),
                    format);

                var lightBackground = background.GetBrightness() > 0.62F;
                using (var glow = new Pen(
                    lightBackground
                        ? Color.FromArgb(34, 37, 99, 235)
                        : Color.FromArgb(48, 96, 165, 250),
                    2.2F))
                    e.Graphics.DrawPath(glow, path);

                var phase = (float)((_animationClock.Elapsed.TotalSeconds / 11.5D) % 1D);
                var gradientPeriod = Math.Max(2F, Width * 1.45F);
                var gradientRect = new RectangleF(0, 0, gradientPeriod, Math.Max(1, Height));
                var colors = lightBackground
                    ? new[]
                    {
                        Color.FromArgb(8, 145, 178),
                        Color.FromArgb(37, 99, 235),
                        Color.FromArgb(126, 34, 206),
                        Color.FromArgb(190, 24, 93),
                        Color.FromArgb(8, 145, 178)
                    }
                    : new[]
                    {
                        Color.FromArgb(34, 211, 238),
                        Color.FromArgb(59, 130, 246),
                        Color.FromArgb(168, 85, 247),
                        Color.FromArgb(236, 72, 153),
                        Color.FromArgb(34, 211, 238)
                    };
                using (var brush = new LinearGradientBrush(
                    gradientRect,
                    colors[0],
                    colors[colors.Length - 1],
                    LinearGradientMode.Horizontal))
                {
                    brush.GammaCorrection = true;
                    brush.WrapMode = WrapMode.Tile;
                    brush.InterpolationColors = new ColorBlend
                    {
                        Colors = colors,
                        Positions = new[] { 0F, 0.24F, 0.5F, 0.76F, 1F }
                    };
                    brush.TranslateTransform(-gradientPeriod * phase, 0F);
                    e.Graphics.FillPath(brush, path);
                }
            }
        }

        private StringFormat CreateStringFormat()
        {
            var format = new StringFormat(StringFormatFlags.NoWrap);
            format.Trimming = StringTrimming.EllipsisCharacter;
            format.Alignment = TextAlign == ContentAlignment.TopCenter ||
                               TextAlign == ContentAlignment.MiddleCenter ||
                               TextAlign == ContentAlignment.BottomCenter
                ? StringAlignment.Center
                : TextAlign == ContentAlignment.TopRight ||
                  TextAlign == ContentAlignment.MiddleRight ||
                  TextAlign == ContentAlignment.BottomRight
                    ? StringAlignment.Far
                    : StringAlignment.Near;
            format.LineAlignment = TextAlign == ContentAlignment.MiddleLeft ||
                                   TextAlign == ContentAlignment.MiddleCenter ||
                                   TextAlign == ContentAlignment.MiddleRight
                ? StringAlignment.Center
                : TextAlign == ContentAlignment.BottomLeft ||
                  TextAlign == ContentAlignment.BottomCenter ||
                  TextAlign == ContentAlignment.BottomRight
                    ? StringAlignment.Far
                    : StringAlignment.Near;
            return format;
        }
    }

    internal sealed class ThemeIconButton : Control
    {
        private readonly Image _moonImage;
        private readonly Image _sunImage;
        private readonly System.Windows.Forms.Timer _transitionTimer;
        private readonly Stopwatch _transitionClock;
        private bool _displayLightMode;
        private bool _startLightMode;
        private bool _targetLightMode;
        private bool _animating;

        public ThemeIconButton(Image moonImage, Image sunImage)
        {
            _moonImage = moonImage;
            _sunImage = sunImage;
            Cursor = Cursors.Hand;
            TabStop = false;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;

            _transitionClock = new Stopwatch();
            _transitionTimer = new System.Windows.Forms.Timer();
            _transitionTimer.Interval = 15;
            _transitionTimer.Tick += delegate
            {
                if (_transitionClock.ElapsedMilliseconds >= 240)
                {
                    _displayLightMode = _targetLightMode;
                    _animating = false;
                    _transitionTimer.Stop();
                }
                Invalidate();
            };
        }

        public void SetLightMode(bool lightMode, bool animate)
        {
            if (!animate)
            {
                _displayLightMode = lightMode;
                _targetLightMode = lightMode;
                _animating = false;
                _transitionTimer.Stop();
                Invalidate();
                return;
            }

            if (_animating)
                _displayLightMode = GetTransitionProgress() >= 0.5F ? _targetLightMode : _startLightMode;
            if (!_animating && _displayLightMode == lightMode)
                return;

            _startLightMode = _displayLightMode;
            _targetLightMode = lightMode;
            _animating = true;
            _transitionClock.Restart();
            _transitionTimer.Start();
            Invalidate();
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _transitionTimer.Dispose();
                _transitionClock.Stop();
                if (_moonImage != null)
                    _moonImage.Dispose();
                if (_sunImage != null)
                    _sunImage.Dispose();
            }
            base.Dispose(disposing);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            base.OnPaint(e);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.CompositingQuality = CompositingQuality.HighQuality;
            e.Graphics.InterpolationMode = InterpolationMode.HighQualityBicubic;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            if (!_animating)
            {
                DrawIcon(e.Graphics, _displayLightMode ? _sunImage : _moonImage, 1F, 1F, 0F);
                return;
            }

            var progress = EaseInOutCubic(GetTransitionProgress());
            var outgoing = _startLightMode ? _sunImage : _moonImage;
            var incoming = _targetLightMode ? _sunImage : _moonImage;
            DrawIcon(e.Graphics, outgoing, 1F - progress, 1F - (0.18F * progress), -18F * progress);
            DrawIcon(e.Graphics, incoming, progress, 0.82F + (0.18F * progress), 18F * (1F - progress));
        }

        private float GetTransitionProgress()
        {
            return Math.Max(0F, Math.Min(1F, (float)(_transitionClock.Elapsed.TotalMilliseconds / 240D)));
        }

        private void DrawIcon(Graphics graphics, Image image, float opacity, float scale, float rotation)
        {
            if (image == null || opacity <= 0F)
                return;

            var side = Math.Max(1F, Math.Min(ClientSize.Width, ClientSize.Height) - 2F);
            var drawSide = side * scale;
            var state = graphics.Save();
            graphics.TranslateTransform(ClientSize.Width / 2F, ClientSize.Height / 2F);
            graphics.RotateTransform(rotation);

            using (var attributes = new ImageAttributes())
            {
                var colorMatrix = new ColorMatrix();
                colorMatrix.Matrix33 = Math.Max(0F, Math.Min(1F, opacity));
                attributes.SetColorMatrix(colorMatrix, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
                graphics.DrawImage(
                    image,
                    Rectangle.Round(new RectangleF(-drawSide / 2F, -drawSide / 2F, drawSide, drawSide)),
                    0,
                    0,
                    image.Width,
                    image.Height,
                    GraphicsUnit.Pixel,
                    attributes);
            }
            graphics.Restore(state);
        }

        private static float EaseInOutCubic(float value)
        {
            return value < 0.5F
                ? 4F * value * value * value
                : 1F - ((float)Math.Pow(-2F * value + 2F, 3D) / 2F);
        }
    }

    internal sealed class SocialLinkIconButton : Control
    {
        private readonly Image _image;
        private readonly Color _accentColor;
        private readonly bool _forceAccentTint;
        private bool _hovered;
        private bool _pressed;

        public SocialLinkIconButton(Image image, Color accentColor, bool forceAccentTint)
        {
            _image = image;
            _accentColor = accentColor;
            _forceAccentTint = forceAccentTint;
            Cursor = Cursors.Hand;
            TabStop = false;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing && _image != null)
                _image.Dispose();
            base.Dispose(disposing);
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            _pressed = false;
            Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                _pressed = true;
                Invalidate();
            }
            base.OnMouseDown(e);
        }

        protected override void OnMouseUp(MouseEventArgs e)
        {
            if (_pressed)
            {
                _pressed = false;
                Invalidate();
            }
            base.OnMouseUp(e);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            base.OnPaint(e);
            var parentBack = Parent == null ? Color.FromArgb(8, 9, 12) : Parent.BackColor;
            e.Graphics.Clear(parentBack);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.CompositingQuality = CompositingQuality.HighQuality;
            e.Graphics.InterpolationMode = InterpolationMode.HighQualityBicubic;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            var bounds = new Rectangle(1, 1, Math.Max(1, Width - 2), Math.Max(1, Height - 2));
            if (_hovered || _pressed)
            {
                var light = parentBack.GetBrightness() > 0.62F;
                var fillColor = _pressed
                    ? Color.FromArgb(light ? 42 : 56, _accentColor)
                    : Color.FromArgb(light ? 24 : 38, _accentColor);
                var borderColor = Color.FromArgb(light ? 100 : 125, _accentColor);
                using (var path = CreateRoundPath(bounds, Math.Max(8, bounds.Height / 2)))
                using (var fill = new SolidBrush(fillColor))
                using (var border = new Pen(borderColor, 1F))
                {
                    e.Graphics.FillPath(fill, path);
                    e.Graphics.DrawPath(border, path);
                }
            }

            if (_image == null)
                return;

            var iconInset = _pressed ? 8 : 7;
            var iconRect = Rectangle.Inflate(bounds, -iconInset, -iconInset);
            if (_forceAccentTint)
                DrawTintedImage(e.Graphics, _image, iconRect, _accentColor);
            else
                e.Graphics.DrawImage(_image, iconRect);
        }

        private static void DrawTintedImage(Graphics graphics, Image image, Rectangle target, Color tint)
        {
            using (var attributes = new ImageAttributes())
            {
                var matrix = new ColorMatrix
                {
                    Matrix00 = 0F,
                    Matrix11 = 0F,
                    Matrix22 = 0F,
                    Matrix33 = 1F,
                    Matrix40 = tint.R / 255F,
                    Matrix41 = tint.G / 255F,
                    Matrix42 = tint.B / 255F
                };
                attributes.SetColorMatrix(matrix, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
                graphics.DrawImage(
                    image,
                    target,
                    0,
                    0,
                    image.Width,
                    image.Height,
                    GraphicsUnit.Pixel,
                    attributes);
            }
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var d = Math.Max(1, Math.Min(radius * 2, Math.Min(rect.Width, rect.Height)));
            path.AddArc(rect.X, rect.Y, d, d, 180, 90);
            path.AddArc(rect.Right - d, rect.Y, d, d, 270, 90);
            path.AddArc(rect.Right - d, rect.Bottom - d, d, d, 0, 90);
            path.AddArc(rect.X, rect.Bottom - d, d, d, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class ModernSlider : Control
    {
        private int _minimum;
        private int _maximum = 100;
        private int _value;
        private bool _dragging;
        private bool _hovered;

        public event EventHandler ValueChanged;

        public int Minimum
        {
            get { return _minimum; }
            set
            {
                _minimum = value;
                if (_maximum <= _minimum)
                    _maximum = _minimum + 1;
                Value = _value;
                Invalidate();
            }
        }

        public int Maximum
        {
            get { return _maximum; }
            set
            {
                _maximum = Math.Max(_minimum + 1, value);
                Value = _value;
                Invalidate();
            }
        }

        public int Value
        {
            get { return _value; }
            set
            {
                var next = Math.Max(_minimum, Math.Min(_maximum, value));
                if (_value == next)
                    return;
                _value = next;
                Invalidate();
                var handler = ValueChanged;
                if (handler != null)
                    handler(this, EventArgs.Empty);
            }
        }

        public Color TrackColor { get; set; }
        public Color FillColor { get; set; }
        public Color ThumbColor { get; set; }
        public Color ThumbBorderColor { get; set; }

        public ModernSlider()
        {
            TrackColor = Color.FromArgb(63, 63, 70);
            FillColor = Color.FromArgb(82, 158, 246);
            ThumbColor = Color.White;
            ThumbBorderColor = Color.FromArgb(138, 190, 250);
            Cursor = Cursors.Hand;
            TabStop = true;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.Selectable |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            if (!_dragging)
                Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                Focus();
                _dragging = true;
                Capture = true;
                SetValueFromMouse(e.X);
            }
            base.OnMouseDown(e);
        }

        protected override void OnMouseMove(MouseEventArgs e)
        {
            if (_dragging)
                SetValueFromMouse(e.X);
            base.OnMouseMove(e);
        }

        protected override void OnMouseUp(MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                _dragging = false;
                Capture = false;
                SetValueFromMouse(e.X);
                Invalidate();
            }
            base.OnMouseUp(e);
        }

        protected override void OnKeyDown(KeyEventArgs e)
        {
            if (e.KeyCode == Keys.Left || e.KeyCode == Keys.Down)
            {
                Value -= Math.Max(1, (_maximum - _minimum) / 100);
                e.Handled = true;
            }
            else if (e.KeyCode == Keys.Right || e.KeyCode == Keys.Up)
            {
                Value += Math.Max(1, (_maximum - _minimum) / 100);
                e.Handled = true;
            }
            else if (e.KeyCode == Keys.Home)
            {
                Value = _minimum;
                e.Handled = true;
            }
            else if (e.KeyCode == Keys.End)
            {
                Value = _maximum;
                e.Handled = true;
            }
            base.OnKeyDown(e);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent == null ? BackColor : Parent.BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            const int horizontalPadding = 10;
            var trackHeight = Math.Max(4, Math.Min(7, Height / 4));
            var trackY = (Height - trackHeight) / 2;
            var trackWidth = Math.Max(1, Width - (horizontalPadding * 2));
            var ratio = (_value - _minimum) / (double)Math.Max(1, _maximum - _minimum);
            var thumbCenterX = horizontalPadding + (int)Math.Round(trackWidth * ratio);
            var filledWidth = Math.Max(0, thumbCenterX - horizontalPadding);
            var trackRect = new Rectangle(horizontalPadding, trackY, trackWidth, trackHeight);
            var fillRect = new Rectangle(horizontalPadding, trackY, filledWidth, trackHeight);

            using (var trackPath = CreateRoundPath(trackRect, trackHeight / 2))
            using (var trackBrush = new SolidBrush(Enabled ? TrackColor : Color.FromArgb(72, 72, 78)))
                e.Graphics.FillPath(trackBrush, trackPath);

            if (fillRect.Width > 0)
            {
                using (var fillPath = CreateRoundPath(fillRect, trackHeight / 2))
                using (var fillBrush = new SolidBrush(Enabled ? FillColor : Color.FromArgb(100, 116, 139)))
                    e.Graphics.FillPath(fillBrush, fillPath);
            }

            var thumbSize = _dragging ? 18 : _hovered || Focused ? 17 : 16;
            var thumbRect = new Rectangle(
                thumbCenterX - (thumbSize / 2),
                (Height - thumbSize) / 2,
                thumbSize,
                thumbSize);
            using (var shadow = new SolidBrush(Color.FromArgb(55, 0, 0, 0)))
                e.Graphics.FillEllipse(shadow, thumbRect.X + 1, thumbRect.Y + 2, thumbRect.Width, thumbRect.Height);
            using (var thumb = new SolidBrush(Enabled ? ThumbColor : Color.FromArgb(180, 180, 184)))
            using (var border = new Pen(Enabled ? ThumbBorderColor : Color.FromArgb(120, 120, 128), 1.5F))
            {
                e.Graphics.FillEllipse(thumb, thumbRect);
                e.Graphics.DrawEllipse(border, thumbRect);
            }
        }

        private void SetValueFromMouse(int mouseX)
        {
            const int horizontalPadding = 10;
            var width = Math.Max(1, Width - (horizontalPadding * 2));
            var ratio = Math.Max(0D, Math.Min(1D, (mouseX - horizontalPadding) / (double)width));
            Value = _minimum + (int)Math.Round((_maximum - _minimum) * ratio);
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            if (rect.Width <= 0 || rect.Height <= 0)
                return path;
            radius = Math.Max(1, Math.Min(radius, Math.Min(rect.Width, rect.Height) / 2));
            var diameter = radius * 2;
            var arc = new Rectangle(rect.Left, rect.Top, diameter, diameter);
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class ModernCheckBox : CheckBox
    {
        private bool _hovered;

        public Color CheckedColor { get; set; }
        public Color UncheckedColor { get; set; }

        public ModernCheckBox()
        {
            Text = string.Empty;
            Cursor = Cursors.Hand;
            CheckedColor = Color.FromArgb(34, 197, 94);
            UncheckedColor = Color.FromArgb(239, 68, 68);
            BackColor = Color.Transparent;
            FlatStyle = FlatStyle.Flat;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.SupportsTransparentBackColor | ControlStyles.UserPaint, true);
        }

        protected override void OnMouseEnter(EventArgs e) { _hovered = true; Invalidate(); base.OnMouseEnter(e); }
        protected override void OnMouseLeave(EventArgs e) { _hovered = false; Invalidate(); base.OnMouseLeave(e); }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            var box = Math.Max(12, Math.Min(Width, Height) - 2);
            var rect = new Rectangle((Width - box) / 2, (Height - box) / 2, box, box);

            var fill = !Enabled ? Color.FromArgb(70, 70, 78) : (Checked ? CheckedColor : UncheckedColor);
            if (_hovered && Enabled)
                fill = ThemePaint.Lighten(fill, 0.08F);

            using (var path = RoundRect(rect, Math.Max(4, box / 4)))
            using (var brush = new SolidBrush(fill))
                e.Graphics.FillPath(brush, path);

            var glyph = Enabled ? Color.White : Color.FromArgb(180, 180, 186);
            using (var pen = new Pen(glyph, Math.Max(2F, box / 10F)))
            {
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;
                pen.LineJoin = LineJoin.Round;
                float x = rect.X, y = rect.Y, s = rect.Width;
                if (Checked)
                {
                    e.Graphics.DrawLines(pen, new[]
                    {
                        new PointF(x + (s * 0.26F), y + (s * 0.52F)),
                        new PointF(x + (s * 0.44F), y + (s * 0.70F)),
                        new PointF(x + (s * 0.76F), y + (s * 0.30F))
                    });
                }
                else
                {
                    e.Graphics.DrawLine(pen, x + (s * 0.30F), y + (s * 0.30F), x + (s * 0.70F), y + (s * 0.70F));
                    e.Graphics.DrawLine(pen, x + (s * 0.70F), y + (s * 0.30F), x + (s * 0.30F), y + (s * 0.70F));
                }
            }
        }

        private static GraphicsPath RoundRect(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var d = Math.Max(1, radius * 2);
            path.AddArc(rect.X, rect.Y, d, d, 180, 90);
            path.AddArc(rect.Right - d, rect.Y, d, d, 270, 90);
            path.AddArc(rect.Right - d, rect.Bottom - d, d, d, 0, 90);
            path.AddArc(rect.X, rect.Bottom - d, d, d, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class StatusDotToggle : CheckBox
    {
        private bool _hovered;
        private bool _pressed;

        public StatusDotToggle()
        {
            Text = string.Empty;
            Cursor = Cursors.Hand;
            BackColor = Color.FromArgb(25, 31, 42);
            FlatStyle = FlatStyle.Flat;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            _pressed = false;
            Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs mevent)
        {
            if (mevent.Button == MouseButtons.Left)
            {
                _pressed = true;
                Invalidate();
            }
            base.OnMouseDown(mevent);
        }

        protected override void OnMouseUp(MouseEventArgs mevent)
        {
            _pressed = false;
            Invalidate();
            base.OnMouseUp(mevent);
        }

        protected override void OnCheckedChanged(EventArgs e)
        {
            Invalidate();
            base.OnCheckedChanged(e);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            var trackHeight = Math.Max(14, Math.Min(Height - 2, (int)Math.Round(Math.Min(Height, Width) * 0.70F)));
            var trackWidth = Math.Max(trackHeight + 7, Width - 6);
            var trackX = (Width - trackWidth) / 2;
            var trackY = (Height - trackHeight) / 2;

            var lightParent = background.GetBrightness() > 0.62F;
            var trackColor = Checked
                ? Color.FromArgb(34, 197, 94)
                : lightParent
                    ? Color.FromArgb(239, 90, 90)
                    : Color.FromArgb(185, 48, 58);
            if (!Enabled)
                trackColor = lightParent ? Color.FromArgb(226, 174, 178) : Color.FromArgb(112, 62, 68);
            else if (_pressed)
                trackColor = ControlPaint.Dark(trackColor, 0.08F);
            else if (_hovered)
                trackColor = ControlPaint.Light(trackColor, 0.06F);

            using (var fill = new SolidBrush(trackColor))
            {
                e.Graphics.FillEllipse(fill, trackX, trackY, trackHeight, trackHeight);
                e.Graphics.FillEllipse(fill, trackX + trackWidth - trackHeight, trackY, trackHeight, trackHeight);
                e.Graphics.FillRectangle(fill, trackX + trackHeight / 2, trackY, trackWidth - trackHeight, trackHeight);
            }

            var knobMargin = 2;
            var knobSize = trackHeight - (knobMargin * 2);
            var knobX = Checked ? trackX + trackWidth - knobSize - knobMargin : trackX + knobMargin;
            var knobY = trackY + knobMargin;
            using (var knob = new SolidBrush(Color.White))
                e.Graphics.FillEllipse(knob, knobX, knobY, knobSize, knobSize);
        }
    }

    internal sealed class BetaBadge : Control
    {
        public BetaBadge()
        {
            Text = "BETA";
            Font = new Font("Segoe UI Semibold", 7.5F);
            ForeColor = Color.FromArgb(255, 228, 228);
            BackColor = Color.FromArgb(25, 31, 42);
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : Color.FromArgb(25, 31, 42);
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            var rect = new Rectangle(0, 0, Width - 1, Height - 1);
            using (var path = CreateRoundPath(rect, Height / 2))
            using (var fill = new SolidBrush(Color.FromArgb(98, 36, 46)))
            using (var border = new Pen(Color.FromArgb(240, 88, 100)))
            {
                e.Graphics.FillPath(fill, path);
                e.Graphics.DrawPath(border, path);
            }

            TextRenderer.DrawText(
                e.Graphics,
                Text,
                Font,
                ClientRectangle,
                ForeColor,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(rect.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal sealed class CircularPictureBox : PictureBox
    {
        public Color BorderColor { get; set; }
        public float BorderWidth { get; set; }

        public CircularPictureBox()
        {
            BorderColor = Color.FromArgb(79, 156, 249);
            BorderWidth = 2F;
            SetStyle(
                ControlStyles.AllPaintingInWmPaint |
                ControlStyles.OptimizedDoubleBuffer |
                ControlStyles.ResizeRedraw |
                ControlStyles.SupportsTransparentBackColor |
                ControlStyles.UserPaint,
                true);
            BackColor = Color.Transparent;
        }

        protected override void OnResize(EventArgs e)
        {
            base.OnResize(e);
            UpdateCircularRegion();
        }

        protected override void OnPaint(PaintEventArgs pe)
        {
            pe.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            pe.Graphics.InterpolationMode = InterpolationMode.HighQualityBicubic;
            pe.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            var state = pe.Graphics.Save();
            using (var clipPath = new GraphicsPath())
            {
                clipPath.AddEllipse(0, 0, Math.Max(1, Width - 1), Math.Max(1, Height - 1));
                pe.Graphics.SetClip(clipPath);
                base.OnPaint(pe);
            }
            pe.Graphics.Restore(state);

            if (BorderWidth <= 0F)
                return;
            var inset = BorderWidth / 2F;
            using (var pen = new Pen(BorderColor, BorderWidth))
                pe.Graphics.DrawEllipse(
                    pen,
                    inset,
                    inset,
                    Math.Max(1F, Width - BorderWidth - 1F),
                    Math.Max(1F, Height - BorderWidth - 1F));
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing && Region != null)
            {
                Region.Dispose();
                Region = null;
            }
            base.Dispose(disposing);
        }

        private void UpdateCircularRegion()
        {
            if (Width <= 0 || Height <= 0)
                return;
            using (var path = new GraphicsPath())
            {
                path.AddEllipse(0, 0, Width, Height);
                var previous = Region;
                Region = new Region(path);
                if (previous != null)
                    previous.Dispose();
            }
        }
    }

    internal sealed class NoteBadge : Control
    {
