        }
    }

    internal sealed class ModernButton : Button
    {
        private bool _hovered;
        private bool _pressed;
        private bool _selected;

        public Color FillColor { get; set; }
        public Color HoverColor { get; set; }
        public Color PressedColor { get; set; }
        public Color BorderColor { get; set; }
        public Color SelectedFillColor { get; set; }
        public Color SelectedBorderColor { get; set; }
        public int CornerRadius { get; set; }
        public string Glyph { get; set; }
        public Image IconImage { get; set; }
        public Color GlyphColor { get; set; }
        public bool CenterContent { get; set; }
        public bool TracksTheme = true;

        public bool Selected
        {
            get { return _selected; }
            set
            {
                if (_selected == value)
                    return;
                _selected = value;
                Invalidate();
            }
        }

        public ModernButton()
        {
            FillColor = Color.FromArgb(35, 35, 39);
            HoverColor = Color.FromArgb(45, 45, 50);
            PressedColor = Color.FromArgb(55, 55, 60);
            BorderColor = Color.FromArgb(24, 24, 27);
            SelectedFillColor = Color.FromArgb(30, 58, 96);
            SelectedBorderColor = Color.FromArgb(59, 130, 246);
            CornerRadius = 8;
            Glyph = string.Empty;
            IconImage = null;
            GlyphColor = Color.FromArgb(59, 130, 246);
            CenterContent = false;
            BackColor = FillColor;
            FlatStyle = FlatStyle.Flat;
            FlatAppearance.BorderSize = 0;
            UseVisualStyleBackColor = false;
            SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.ResizeRedraw | ControlStyles.UserPaint, true);
        }

        protected override void OnMouseEnter(EventArgs e)
        {
            _hovered = true;
            Invalidate();
            base.OnMouseEnter(e);
        }

        protected override void OnMouseLeave(EventArgs e)
        {
            _hovered = false;
            _pressed = false;
            Invalidate();
            base.OnMouseLeave(e);
        }

        protected override void OnMouseDown(MouseEventArgs mevent)
        {
            if (mevent.Button == MouseButtons.Left)
            {
                _pressed = true;
                Invalidate();
            }
            base.OnMouseDown(mevent);
        }

        protected override void OnMouseUp(MouseEventArgs mevent)
        {
            _pressed = false;
            Invalidate();
            base.OnMouseUp(mevent);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            var background = Parent != null ? Parent.BackColor : BackColor;
            e.Graphics.Clear(background);
            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;
            var rect = new Rectangle(0, 0, Width - 1, Height - 1);
            var fillColor = FillColor;
            var borderColor = BorderColor;
            var textColor = ForeColor;

            if (!Enabled)
            {
                fillColor = Color.FromArgb(27, 32, 42);
                borderColor = Color.FromArgb(42, 49, 62);
                textColor = Color.FromArgb(103, 113, 128);
            }
            else if (_pressed)
            {
                fillColor = PressedColor;
            }
            else if (_selected)
            {
                fillColor = SelectedFillColor;
                borderColor = SelectedBorderColor;
            }
            else if (_hovered)
            {
                fillColor = HoverColor;
            }

            var topFill = ThemePaint.Lighten(fillColor, 0.06F);
            var bottomFill = ThemePaint.Darken(fillColor, 0.06F);
            var fillBounds = new Rectangle(0, 0, Math.Max(1, Width), Math.Max(1, Height + 1));
            using (var path = CreateRoundPath(rect, CornerRadius))
            using (var fill = new LinearGradientBrush(fillBounds, topFill, bottomFill, LinearGradientMode.Vertical))
            using (var border = new Pen(borderColor))
            {
                e.Graphics.FillPath(fill, path);
                if (borderColor.A > 0)
                    e.Graphics.DrawPath(border, path);
            }

            if (IconImage != null && CenterContent)
            {
                var iconSize = Math.Min(30, Math.Max(20, Height - 14));
                var textSize = TextRenderer.MeasureText(e.Graphics, Text, Font, new Size(Math.Max(1, Width - 20), Height), TextFormatFlags.SingleLine | TextFormatFlags.NoPadding);
                var gap = 8;
                var totalWidth = Math.Min(Width - 16, iconSize + gap + textSize.Width + 8);
                var startX = Math.Max(8, (Width - totalWidth) / 2);
                var iconRect = new Rectangle(startX, (Height - iconSize) / 2, iconSize, iconSize);
                e.Graphics.DrawImage(IconImage, iconRect);
                var centeredTextRect = new Rectangle(iconRect.Right + gap, 0, Math.Max(1, Width - iconRect.Right - gap - startX + 8), Height);
                TextRenderer.DrawText(e.Graphics, Text, Font, centeredTextRect, textColor, TextFormatFlags.Left | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
                return;
            }

            if (!string.IsNullOrEmpty(Glyph) && CenterContent)
            {
                using (var glyphFont = new Font("Segoe UI Symbol", 12F, FontStyle.Bold))
                {
                    var glyphSize = TextRenderer.MeasureText(e.Graphics, Glyph, glyphFont, new Size(100, Height), TextFormatFlags.SingleLine | TextFormatFlags.NoPadding);
                    var textSize = TextRenderer.MeasureText(e.Graphics, Text, Font, new Size(Math.Max(1, Width - 20), Height), TextFormatFlags.SingleLine | TextFormatFlags.NoPadding);
                    var gap = 8;
                    var totalWidth = Math.Min(Width - 16, Math.Max(24, glyphSize.Width) + gap + textSize.Width + 8);
                    var startX = Math.Max(8, (Width - totalWidth) / 2);
                    var glyphRect = new Rectangle(startX, 0, Math.Max(24, glyphSize.Width), Height);
                    TextRenderer.DrawText(e.Graphics, Glyph, glyphFont, glyphRect, Enabled ? GlyphColor : Color.FromArgb(103, 113, 128), TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
                    var centeredTextRect = new Rectangle(glyphRect.Right + gap, 0, Math.Max(1, Width - glyphRect.Right - gap - startX + 8), Height);
                    TextRenderer.DrawText(e.Graphics, Text, Font, centeredTextRect, textColor, TextFormatFlags.Left | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
                }
                return;
            }

            if (IconImage != null)
            {
                var iconSize = Math.Min(22, Math.Max(18, Height - 12));
                var iconRect = new Rectangle(15, (Height - iconSize) / 2, iconSize, iconSize);
                e.Graphics.DrawImage(IconImage, iconRect);
            }
            else if (!string.IsNullOrEmpty(Glyph))
            {
                var glyphRect = new Rectangle(14, 0, 24, Height);
                using (var glyphFont = new Font("Segoe UI Symbol", 12F, FontStyle.Bold))
                    TextRenderer.DrawText(e.Graphics, Glyph, glyphFont, glyphRect, Enabled ? GlyphColor : Color.FromArgb(103, 113, 128), TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine);
            }

            var textRect = string.IsNullOrEmpty(Glyph) && IconImage == null
                ? ClientRectangle
                : new Rectangle(52, 0, Math.Max(1, Width - 60), Height);
            if (string.IsNullOrEmpty(Glyph) && IconImage == null)
                textRect.Inflate(-Padding.Horizontal / 2 - 8, -1);
            var flags = TextFormatFlags.VerticalCenter | TextFormatFlags.EndEllipsis | TextFormatFlags.SingleLine;
            if (TextAlign == ContentAlignment.MiddleLeft)
                flags |= TextFormatFlags.Left;
            else if (TextAlign == ContentAlignment.MiddleRight)
                flags |= TextFormatFlags.Right;
            else
                flags |= TextFormatFlags.HorizontalCenter;
            TextRenderer.DrawText(e.Graphics, Text, Font, textRect, textColor, flags);
        }

        private static GraphicsPath CreateRoundPath(Rectangle rect, int radius)
        {
            var path = new GraphicsPath();
            var diameter = Math.Max(1, radius * 2);
            var arc = new Rectangle(rect.Location, new Size(diameter, diameter));
            path.AddArc(arc, 180, 90);
            arc.X = rect.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = rect.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = rect.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();
            return path;
        }
    }

    internal static class Pattern
    {
        public static int[] Parse(string pattern)
        {
            var parts = pattern.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            var result = new int[parts.Length];
            for (var i = 0; i < parts.Length; i++)
                result[i] = parts[i] == "?" || parts[i] == "??" ? -1 : Convert.ToInt32(parts[i], 16);
            return result;
        }

        public static IEnumerable<int> FindAll(byte[] data, int[] pattern, int max)
        {
            var found = 0;
            for (var i = 0; i <= data.Length - pattern.Length; i++)
            {
                var match = true;
                for (var j = 0; j < pattern.Length; j++)
                {
                    if (pattern[j] >= 0 && data[i + j] != pattern[j])
                    {
                        match = false;
                        break;
                    }
                }
                if (match)
                {
                    yield return i;
                    found++;
                    if (found >= max) yield break;
                }
            }
        }

        public static IEnumerable<int> FindBytes(byte[] data, byte[] needle, int max)
        {
            var found = 0;
            for (var i = 0; i <= data.Length - needle.Length; i++)
            {
                var match = true;
                for (var j = 0; j < needle.Length; j++)
                {
                    if (data[i + j] != needle[j])
                    {
                        match = false;
                        break;
                    }
                }
                if (match)
                {
                    yield return i;
                    found++;
                    if (found >= max) yield break;
                }
            }
        }
    }

