        public static bool IsReadable(uint protect)
        {
            if ((protect & PageGuard) != 0) return false;
            if ((protect & PageNoAccess) != 0) return false;
            return protect != 0;
        }

        public static bool IsExecutable(uint protect)
        {
            if ((protect & PageGuard) != 0) return false;
            if ((protect & PageNoAccess) != 0) return false;
            var baseProtect = protect & 0xFF;
            return baseProtect == PageExecute ||
                   baseProtect == PageExecuteRead ||
                   baseProtect == PageExecuteReadWrite ||
                   baseProtect == PageExecuteWriteCopy;
        }

        public static bool IsAdministrator()
        {
            try
            {
                var identity = WindowsIdentity.GetCurrent();
                var principal = new WindowsPrincipal(identity);
                return principal.IsInRole(WindowsBuiltInRole.Administrator);
            }
            catch
            {
                return false;
            }
        }

        public static void ApplySystemTitleBarColor(IntPtr handle)
        {
            if (handle == IntPtr.Zero)
                return;

            uint argb;
            bool opaque;
            if (DwmGetColorizationColor(out argb, out opaque) != 0)
                return;

            var r = (byte)((argb >> 16) & 0xFF);
            var g = (byte)((argb >> 8) & 0xFF);
            var b = (byte)(argb & 0xFF);
            var caption = ToColorRef(r, g, b);
            var text = GetReadableTitleTextColor(r, g, b);

            const int dwmwaBorderColor = 34;
            const int dwmwaCaptionColor = 35;
            const int dwmwaTextColor = 36;
            DwmSetWindowAttribute(handle, dwmwaCaptionColor, ref caption, sizeof(int));
            DwmSetWindowAttribute(handle, dwmwaBorderColor, ref caption, sizeof(int));
            DwmSetWindowAttribute(handle, dwmwaTextColor, ref text, sizeof(int));
        }

        public static void ApplySystemTitleBarColor(IntPtr handle, Color frame, Color text)
        {
            if (handle == IntPtr.Zero)
                return;

            var caption = ToColorRef(frame.R, frame.G, frame.B);
            var captionText = ToColorRef(text.R, text.G, text.B);

            const int dwmwaBorderColor = 34;
            const int dwmwaCaptionColor = 35;
            const int dwmwaTextColor = 36;
            DwmSetWindowAttribute(handle, dwmwaCaptionColor, ref caption, sizeof(int));
            DwmSetWindowAttribute(handle, dwmwaBorderColor, ref caption, sizeof(int));
            DwmSetWindowAttribute(handle, dwmwaTextColor, ref captionText, sizeof(int));
        }

        public static bool TryPlayMp3File(string path, out string error)
        {
            error = string.Empty;
            if (string.IsNullOrWhiteSpace(path))
            {
                error = "Audio path was empty.";
                return false;
            }

            var alias = "lunaTeleportSaved" + Environment.TickCount.ToString("X", CultureInfo.InvariantCulture);
            var opened = false;
            try
            {
                var result = mciSendString("open \"" + path + "\" type mpegvideo alias " + alias, null, 0, IntPtr.Zero);
                if (result != 0)
                {
                    error = GetMciError(result);
                    return false;
                }

                opened = true;
                result = mciSendString("play " + alias + " wait", null, 0, IntPtr.Zero);
                if (result != 0)
                {
                    error = GetMciError(result);
                    return false;
                }

                return true;
            }
            finally
            {
                if (opened)
                    mciSendString("close " + alias, null, 0, IntPtr.Zero);
            }
        }

        private static string GetMciError(int code)
        {
            var text = new StringBuilder(256);
            if (mciGetErrorString(code, text, text.Capacity))
                return text.ToString();
            return "MCI error " + code.ToString(CultureInfo.InvariantCulture);
        }

        private static int ToColorRef(byte r, byte g, byte b)
        {
            return r | (g << 8) | (b << 16);
        }

        private static int GetReadableTitleTextColor(byte r, byte g, byte b)
        {
            var luminance = (0.2126 * r) + (0.7152 * g) + (0.0722 * b);
            return luminance < 140.0 ? 0x00FFFFFF : 0x00000000;
        }

        public static void EnableDebugPrivilege()
        {
            try
            {
                const int tokenAdjustPrivileges = 0x20;
                const int tokenQuery = 0x8;
                const int sePrivilegeEnabled = 0x2;
                IntPtr token = IntPtr.Zero;
                if (!OpenProcessToken(GetCurrentProcess(), tokenAdjustPrivileges | tokenQuery, ref token))
                    return;

                long luid = 0;
                if (!LookupPrivilegeValue(null, "SeDebugPrivilege", ref luid))
                    return;

                var tp = new TokPriv1Luid();
                tp.Count = 1;
                tp.Luid = luid;
                tp.Attr = sePrivilegeEnabled;
                AdjustTokenPrivileges(token, false, ref tp, 0, IntPtr.Zero, IntPtr.Zero);
                CloseHandle(token);
            }
            catch
            {
            }
        }

        public static void SendKeyboardKey(ushort virtualKey)
        {
            var mapped = MapVirtualKey(virtualKey, MapvkVkToVscEx);
            if (mapped != 0)
            {
                var scanCode = (ushort)(mapped & 0xFF);
                var flags = KeyEventFScancode;
                if ((mapped & 0xFF00) != 0 || IsExtendedVirtualKey(virtualKey))
                    flags |= KeyEventFExtendedKey;

                var scanInputs = new[]
                {
                    new Input
                    {
                        type = InputKeyboard,
                        u = new InputUnion
                        {
                            ki = new KeyboardInput { wVk = 0, wScan = scanCode, dwFlags = flags, time = 0, dwExtraInfo = IntPtr.Zero }
                        }
                    },
                    new Input
                    {
                        type = InputKeyboard,
                        u = new InputUnion
                        {
                            ki = new KeyboardInput { wVk = 0, wScan = scanCode, dwFlags = flags | KeyEventFKeyUp, time = 0, dwExtraInfo = IntPtr.Zero }
                        }
                    }
                };

                SendInput((uint)scanInputs.Length, scanInputs, Marshal.SizeOf(typeof(Input)));
                return;
            }

            var inputs = new[]
            {
                new Input
                {
                    type = InputKeyboard,
                    u = new InputUnion
                    {
                        ki = new KeyboardInput { wVk = virtualKey, wScan = 0, dwFlags = 0, time = 0, dwExtraInfo = IntPtr.Zero }
                    }
                },
                new Input
                {
                    type = InputKeyboard,
                    u = new InputUnion
                    {
                        ki = new KeyboardInput { wVk = virtualKey, wScan = 0, dwFlags = KeyEventFKeyUp, time = 0, dwExtraInfo = IntPtr.Zero }
                    }
                }
            };

            SendInput((uint)inputs.Length, inputs, Marshal.SizeOf(typeof(Input)));
        }

        public static void SendMouseLeftClick(int x, int y)
        {
            SetCursorPos(x, y);
            Thread.Sleep(35);
            var inputs = new[]
            {
                new Input
                {
                    type = InputMouse,
                    u = new InputUnion
                    {
                        mi = new MouseInput { dx = 0, dy = 0, mouseData = 0, dwFlags = MouseEventFLeftDown, time = 0, dwExtraInfo = IntPtr.Zero }
                    }
                },
                new Input
                {
                    type = InputMouse,
                    u = new InputUnion
                    {
                        mi = new MouseInput { dx = 0, dy = 0, mouseData = 0, dwFlags = MouseEventFLeftUp, time = 0, dwExtraInfo = IntPtr.Zero }
                    }
                }
            };

            SendInput((uint)inputs.Length, inputs, Marshal.SizeOf(typeof(Input)));
        }

        private static bool IsExtendedVirtualKey(ushort virtualKey)
        {
            switch ((Keys)virtualKey)
            {
                case Keys.Insert:
                case Keys.Delete:
                case Keys.Home:
                case Keys.End:
                case Keys.PageUp:
                case Keys.PageDown:
                case Keys.Left:
                case Keys.Right:
                case Keys.Up:
                case Keys.Down:
                case Keys.RControlKey:
                case Keys.RMenu:
                    return true;
                default:
                    return false;
            }
        }
    }
